/****** Object:  StoredProcedure [dbo].[GetIssuedBusiness]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE   PROCEDURE [dbo].[GetIssuedBusiness]
AS
/*
Original MI script from Issues Production Scan.sql

*/

BEGIN
	SET NOCOUNT ON; 

	TRUNCATE TABLE dbo.IssuedBusiness;

	DECLARE @StartDate VARCHAR(30),@EndDate VARCHAR(30), @inc1 INT, @inc2 INT, @excldate VARCHAR(30)

	-- Exclude incorrect mortgage cases up to 01-01-2020 ------------------------------------------------------------
	SET @excldate =  CONVERT(DATETIME, '2020-01-01 00:00:00',102)
	-----------------------------------------------------------------------------------------------------------------
	---dates for daily scans -----------------------------------------------------------------------------------------
	SET @StartDate =  DATEADD(yy, DATEDIFF(yy, 0, GETDATE()) - 2, 0) --CONVERT(DATETIME, '2014-01-01 00:00:00',102) --DATEADD(yy, DATEDIFF(yy, 0, GETDATE()) - 2, 0)  --DATEADD(yy, DATEDIFF(yy, 0, GETDATE())-1, 0) --CONVERT(DATETIME, '2014-11-01 00:00:00',102)
	SET @EndDate = DATEADD(day,datediff(day,0,GETDATE()),0); --CONVERT(DATETIME, '2017-06-01 00:00:00',102) 
	-----------------------------------------------------------------------------------------------------------------
	--------------------------------------------------OWL ISSUED BUSINESS -------------------------------------------------------------------------------------------
	----- Manager Promotion Dates -----------------------------------------------------------------------------------

	WITH Manager_Prom AS (
	SELECT DISTINCT
	ud.Usr_login
	,UPS_Jobtitle
	,max(UPS_Createddate) PromotionDate
	,ups_userid	
	FROM
	sa_insight_UserDetails ud LEFT JOIN
	sa_insight_UserPositionHistory uph ON uph.ups_userid = ud.Usr_id LEFT JOIN
	mi_insight_UserHierarchy uh ON uh.useruid = ud.Usr_login
	WHERE 
	UPS_Jobtitle = 54 
	AND UserJobTitleCodeSalesMgr = 54	
	GROUP BY 
	ud.Usr_login,UPS_Jobtitle,ups_userid),	

	------END MANAGER PROMOTION DATES

	------ L&G COMMISSIOSN MONTH ----------------------------------------------------------------------------------------

	Comm_Month AS(
	SELECT
	commissionmonth
	,policyreference
	FROM
	owt_OwlDirectPayments
	WHERE 
	source LIKE 'L&G'
	AND (Transactiontype LIKE 'Endorse%' OR Transactiontype LIKE 'New%Business')
	GROUP BY
	commissionmonth
	,policyreference
	HAVING 
	SUM(CASE WHEN SIGN(grosspremium)<>SIGN(openworkcommissionamt) 
		THEN grosspremium*-1 
		ELSE grosspremium 
		END) =0
	),

	------ END L&G COMMISSIOSN MONTH ----------------------------------------------------------------------------------------

	---------------------------------- STANDARD OWL ISSUED SCAN -------------------------------------------------------------

	------ TEMP TABLES FOR FINDING FIRST ISSUED DATE -------------------------------------------------------------------------

	First_Issued_Date AS (
	SELECT
	min(transactionid) as transactionid
	, po.policyref
	, po.cont_num
	, co.productcode
	FROM		 
	dbo.mstt_Commissions co INNER JOIN
	dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
	dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID INNER JOIN
		(SELECT DISTINCT 
			useruid 
		FROM 
			mi_insight_userhierarchyallusers 
		WHERE 
			aduid = '4005013') t ON t.UserUID = pt.AGENTCODE
	WHERE
	co.poltrantranstype <> 39
	and co.agent_code NOT IN ('10002','1011542','10004')	
	and po.policyref NOT LIKE '800%'
	AND co.commissiontype = 1
	GROUP BY
	po.policyref
	, po.cont_num
	, co.productcode),

	------ END TEMP TABLES FOR FINDING FIRST ISSUED DATE ----------------------------------------------------------------------

	------ POL REF COUNT --------------------------------------------------------------------------

	Pol_Ref_Count AS (
	SELECT
	min(id) as transactionid
	, policyreference
	, Commissionmonth
	, count(policyreference) as lines
	FROM 
	dbo.owt_OwlDirectPayments	 
	WHERE
	Grosspremium >=0 
	GROUP BY
	policyreference
	, Commissionmonth),

	------ END POL REF COUNT --------------------------------------------------------------------------


	------ ISSUED SWIFT ---------------------------------------------------------------------------------------------------------------------------------------------------

	Owl_Issued_Swift AS (
	SELECT 
	'Issued' AS "Type"
	, pt.AGENTCODE AS PriAdviser
	, CASE WHEN ((ph.productgroupname <> 'Mortgage' AND coalesce(co.adminmethod,co2.adminmethod,'A') NOT IN ('A','G'))) 
	  THEN 'Non Advised' 
	  ELSE 'Advised' 
	  END AS 'Adminmethod'
	, ph.productgroupname AS ProductGroupName
	, CASE WHEN ISNULL(co.productcode,ag.tranproduct) LIKE '%AVIP OWL%' 
	  THEN 'AVIVA OWL' 
	  ELSE ISNULL(co.productcode,ag.tranproduct) 
	  END AS productsubgroup
	, CASE WHEN ph.productProvidercode LIKE 'METLIFE%' AND ph.productsubgroupname LIKE 'Term %' THEN 'A&HMETLIFE' ELSE
			 CASE WHEN ph.productsubgroupname LIKE 'Income %' THEN 'IP'
				  WHEN ph.productsubgroupname LIKE 'Term %' OR ph.productsubgroupname LIKE 'Whole o%' THEN 'LP'
				  ELSE ph.productsubgroupname 
				  END + ph.Reportingproductprovidercode
	   END AS productsubtype
	 , CASE WHEN ph.productProvidercode LIKE 'METLIFE%' AND ph.productsubgroupname LIKE 'Term %' THEN 'A&H '
	   WHEN ph.productsubgroupname LIKE 'Income %' THEN 'IP '
	   WHEN ph.productsubgroupname LIKE 'Term %'  THEN 'LP '
	   WHEN ph.productsubgroupname LIKE 'Whole o%' THEN 'WOL '
	   ELSE ph.productsubgroupname 
	   END  +
		CASE WHEN ph.productProvidercode LIKE '%OWL%' 
		THEN 'OWL' 
		ELSE 'PANEL' 
		END	AS daily_category
	, CAST(ag.createdatetime AS DATE) AS Date
	, DAY(ag.createdatetime) AS Day
	, MONTH(ag.createdatetime) AS Month
	, YEAR(ag.createdatetime) AS Year
	, SUM(CASE WHEN ag.commissiontypedesc LIKE '%claw%' 
		  THEN 0 
		  ELSE COALESCE(cs.ape,co2.turnover,0) 
		  end) AS PREMIUM
	, SUM(CASE WHEN ag.commissiontypedesc LIKE '%claw%' 
		  THEN 0 
		  ELSE COALESCE(cs.ape,co2.turnover,0) 
		  end) AS APE
	, SUM(CASE WHEN ag.commissiontypedesc LIKE '%claw%' THEN 0
			 WHEN b.transactionid IS NULL THEN 0
			 WHEN cs.ape < 0 AND ag.transactionid = b.transactionid THEN -ag.derivedagentsplit/100
			 WHEN cs.ape = 0 THEN 0
			 WHEN cs.ape > 0 AND ag.transactionid = b.transactionid THEN ag.derivedagentsplit/100
			 WHEN ag.transactionid = b.transactionid THEN ag.derivedagentsplit/100 
			 ELSE 0 
			 END) AS NewPolicies
	, SUM(CASE WHEN (ag.commissiontype IN ('1','17') AND cs.oastatus = 'valid') 
		  THEN (cs.inissued + ((ROUND((cs.inissued/ag.amount),0) *ag.derivedmarginamount))) 
		  ELSE (ag.amount + isnull(derivedmarginamount,0)) 
		  END) AS DA
	-- GROSS MARGIN INITIAL
	, SUM(CASE WHEN (ag.commissiontype in ('1','17') and cs.oastatus = 'valid')
		  THEN (round(cs.INIssued / ag.AMOUNT,0) * ag.DerivedMarginAmount)
	-- GROSS MARGIN POT ACCOUNT/SERVICING
		  WHEN ((cs.oastatus <> 'valid' OR cs.oastatus IS NULL)
				 AND ag.agent_code IN ('1011543','1006886','1011587','1011623')
				 AND ag.commissiontype NOT IN ('0','2','3','7','8','14','15','16','20','21'))
		  THEN (ag.amount + ISNULL(derivedmarginamount,0)) 
	-- INCORRECT OWL MARGIN POT ACCOUNTS
		  WHEN ((cs.oastatus <> 'valid' OR cs.oastatus IS NULL) AND ag.agent_code IN ('1011629','1011630','1011631','1011632','1011633','1011634','1011635')
				 AND ag.commissiontype NOT IN ('0','2','3','7','8','14','15','16','20','21'))
		  THEN (ISNULL(derivedmarginamount,0))
		  ELSE 0 
		  end) 
	-- Adjusting Margin to remove the hierarchy payments (hierarchy not included in mstt_paymentspending)
				- SUM(ISNULL(HEvo.Amount,0)) AS Margin
	,ah.agentstartdate AS startdate
	, CONVERT(DATE,pt.proposaldate) AS writdate
	, pr.Promotiondate

	FROM mstt_paymentspending ag LEFT OUTER JOIN
	msit_commissionstatement cs ON cs.PendingPaymentID = ag.id LEFT OUTER JOIN
	msit_openworkadviserlisting oa ON oa.sourceid = cs.id AND oa.Source = 'Openwork 2006' LEFT OUTER JOIN
	mstt_commissions co ON cs.commissionsid = co.id LEFT OUTER JOIN
	mstt_Commissions co2 ON co2.transactionid = ag.transactionid 
												AND co2.agent_code = ag.agent_code 
												AND co2.commissiontype = CASE WHEN ag.commissiontype in (1,2,17) THEN 1 
																		 WHEN ag.commissiontype in (4,15,18) THEN 4 
																		 WHEN ag.commissiontype in (10,16,19) THEN 10 
																		 END LEFT OUTER JOIN
	mstt_PolicyTransactions pt ON pt.ID = ag.TransactionID LEFT OUTER JOIN
	mstt_ProductHierarchy ph ON ag.tranproduct = ph.ProductCode LEFT OUTER JOIN
	msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode LEFT OUTER JOIN
	msit_CodeCommissionShape ccs ON ccs.id = pt.codecommissionshapeid LEFT OUTER JOIN
	cscv_AgentsHierarchy ah ON ah.agentcode = pt.AgentCode LEFT OUTER JOIN
	First_Issued_Date b ON b.transactionid = ag.transactionid LEFT JOIN
	Manager_Prom pr ON pr.Usr_login = pt.AGENTCODE INNER JOIN
			(SELECT DISTINCT 
				useruid 
			 FROM 
				mi_insight_userhierarchyallusers 
			 WHERE aduid = '4005013') t ON t.UserUID = pt.AGENTCODE LEFT JOIN
			(SELECT 
				SUM(Roleamount) AS Amount, AGMID 
			 FROM 
				OwlEvolution.sa_SwiftLogging_PaymentToHierarchy 
			 WHERE Paymentstage <>'Deferred' GROUP BY AGMID) HEvo ON HEvo.agmid = ag.id
	WHERE
	(ag.createdatetime) >= @StartDate
	AND (ag.createdatetime) <= @EndDate
	AND NOT (ag.createdatetime <= @excldate AND ph.ProductGroupName = 'Mortgage') -- excluding incorrect mortgage cases for OWL advisers (RB 04/09/2019)
	AND (ag.agent_code <> '10002')
	AND ag.amount <> 0
	AND ag.commissiontype in ('1','4','10','17','18','19')
	AND (co2.id NOT IN ('17797514','17797515') or co2.id IS NULL)
	AND (cs.oastatus = 'valid' OR cs.oastatus IS NULL)
	AND (rtrim(ah.ASDName) = 'Pat Mckenna' OR ag.agent_code IN ('1011623','1011629','1011630','1011631','1011632','1011633','1011634','1011635'))---OWL POT ACCOUNT NOT COUNTED
	AND (CASE WHEN (cs.oastatus = 'valid' AND ag.commissiontype IN ('4','10','15','16','18','19') 
										  AND ag.tranproduct NOT LIKE '%INCOME%' 
										  AND ag.tranproduct NOT LIKE '%PRUFUND%' 
										  AND ag.tranproduct NOT LIKE '%FIA%' 
										  AND ag.tranproduct NOT LIKE 'OW%' 
										  AND ag.tranproduct NOT LIKE 'OF%' 
										  AND ag.tranproduct NOT LIKE 'OZ%') 
		  THEN 'NonTrail' 
		  ELSE 'Other' 
		  END) <> 'NonTrail' 
	AND case WHEN ag.commissiontypedesc like '%claw%' THEN 0
			 WHEN b.transactionid IS NULL THEN 0
			 WHEN cs.ape < 0 AND ag.transactionid = b.transactionid THEN -ag.derivedagentsplit/100
			 WHEN cs.ape = 0 THEN 0
			 WHEN cs.ape > 0 AND ag.transactionid = b.transactionid THEN ag.derivedagentsplit/100
			 WHEN ag.transactionid = b.transactionid THEN ag.derivedagentsplit/100 
			 ELSE 0 end IS NOT NULL
	AND CASE WHEN (ag.commissiontype in ('1','17') AND cs.oastatus = 'valid')
		THEN (round(cs.INIssued / ag.AMOUNT,0) * ag.DerivedMarginAmount)
	-- GROSS MARGIN POT ACCOUNT/SERVICING
		When ((cs.oastatus <> 'valid' OR cs.oastatus IS NULL)
			   AND ag.agent_code IN ('1011543','1006886','1011587','1011623')
			   AND ag.commissiontype NOT IN ('0','2','3','7','8','14','15','16','20','21'))
		THEN (ag.amount + isnull(derivedmarginamount,0)) 
	-- INCORRECT OWL MARGIN POT ACCOUNTS
		WHEN ((cs.oastatus <> 'valid' OR cs.oastatus IS NULL) AND ag.agent_code IN ('1011629','1011630','1011631','1011632','1011633','1011634','1011635')
			   AND ag.commissiontype NOT IN ('0','2','3','7','8','14','15','16','20','21'))
		THEN (isnull(derivedmarginamount,0))
		ELSE 0 
		END <> 0
	AND NOT (ag.commissiontype IN (3,17,18,19) AND ag.createdatetime >='2018-11-01' AND ag.comp_code LIKE '%zurich%') -- Ignore all adj from 01/11/18 onwards JB 13/02/19

	---- Fix for dodgy cases causing huge DA/margin JB 22/09/17

	AND ag.id NOT IN ('39478718','39475072')

	GROUP BY
	CAST(ag.createdatetime AS DATE)
	, pt.AgentCode
	, DAY(ag.createdatetime)
	, MONTH(ag.createdatetime)
	, YEAR(ag.createdatetime)
	, CASE WHEN ISNULL(co.productcode,ag.tranproduct) LIKE '%AVIP OWL%' 
	  THEN 'AVIVA OWL' 
	  ELSE ISNULL(co.productcode,ag.tranproduct) 
	  END
	, CASE WHEN ((ph.productgroupname <> 'Mortgage' AND COALESCE(co.adminmethod,co2.adminmethod,'A') NOT IN ('A','G'))) 
	  THEN 'Non Advised' 
	  ELSE 'Advised' 
	  END
	, ph.productgroupname
	, ah.agentstartdate
	, CONVERT(DATE,pt.proposaldate)
	, pr.Promotiondate
	, CASE WHEN ph.productProvidercode LIKE 'METLIFE%' AND ph.productsubgroupname LIKE 'Term %' 
	  THEN 'A&HMETLIFE' 
	  ELSE
			CASE WHEN ph.productsubgroupname LIKE 'Income %' THEN 'IP'
				 WHEN ph.productsubgroupname LIKE 'Term %' OR ph.productsubgroupname LIKE 'Whole o%' THEN 'LP'
				 ELSE ph.productsubgroupname 
				 END  + ph.Reportingproductprovidercode
	  END
	, CASE WHEN ph.productProvidercode LIKE 'METLIFE%' AND ph.productsubgroupname LIKE 'Term %' THEN 'A&H '
		   WHEN ph.productsubgroupname LIKE 'Income %' THEN 'IP '
		   WHEN ph.productsubgroupname LIKE 'Term %'  THEN 'LP '
		   WHEN ph.productsubgroupname LIKE 'Whole o%' THEN 'WOL '
		   ELSE ph.productsubgroupname END  +
				CASE WHEN ph.productProvidercode LIKE '%OWL%' 
				THEN 'OWL' 
				ELSE 'PANEL' 
				END			  
	-- (Excluding non-owl cases before panel)
	HAVING
	NOT (MIN(co.ProductCode) NOT LIKE '%owl%' AND CONVERT(DATE,pt.proposaldate) <= '2018-12-01')

	UNION ALL

	--------------------------------------------------------------------------L&G ASU Product Added 18/05/17

	select
	'Issued' as 'Type',
	case when dp.adviserUID = '1012011' then '1012002' else dp.adviserUID end UID,
	'Advised' as adminmethod,
	'Protection' as productgroupname,
	'L&GASU OWL' as ProductSubGroup,
	'LPL&G' Productsubtype,
	'LP OWL' Daily_Category,
	dateadd(mm,1,dp.Commissionmonth) as date,
	day(dateadd(mm,1,dp.Commissionmonth)) as day,
	month(dateadd(mm,1,dp.Commissionmonth)) as month,
	year(dateadd(mm,1,dp.Commissionmonth)) as year,
	sum((dp.GrossPremium)) as premium,
	sum((dp.GrossPremium)) as APE,
	sum((case when e.transactionID = dp.ID then 1 else 0 end)) as Newpolicies,
	sum((dp.GrossPremium*0.35)) as DA,
	sum((dp.OpenworkActualMarginamt)) as Margin,
	ah.agentstartdate as startdate,
	dp.CommissionAuthorisationDate,
	pr.Promotiondate

	from dbo.owt_OwlDirectPayments dp
		 left join Pol_Ref_Count e on e.transactionID = dp.ID
		 left join cscv_AgentsHierarchy ah on ah.Agentcode = dp.adviserUID
		 left join Manager_Prom pr on pr.Usr_login = dp.adviserUID
		 left join Comm_Month p on p.policyreference = dp.policyreference

	where
		Transactiontype like '%New%Business%'
		and dp.source like 'L&G'
		and Grosspremium >=0 and Grosspremium is not null
		and e.policyreference = dp.policyreference
		and (dp.Commissionmonth) >= @StartDate
		and (dp.Commissionmonth) <= @EndDate
		and p.policyreference is null

	group by
	dp.adviserUID,
	dp.Commissionmonth,
	day(dp.Commissionmonth),
	month(dp.Commissionmonth),
	year(dp.Commissionmonth),
	ah.agentstartdate,
	dp.CommissionAuthorisationDate,
	pr.Promotiondate

	UNION ALL

	select
	'Issued' as 'Type',
	case when dp.adviserUID = '1012011' then '1012002' else dp.adviserUID end UID,
	'Advised' as adminmethod,
	'Protection' as productgroupname,
	'L&GASU OWL' as ProductSubGroup,
	'LPL&G' Productsubtype,
	'LP OWL' Daily_Category,
	dateadd(mm,1,dp.Commissionmonth) as date,
	day(dateadd(mm,1,dp.Commissionmonth)) as day,
	month(dateadd(mm,1,dp.Commissionmonth)) as month,
	year(dateadd(mm,1,dp.Commissionmonth)) as year,
	sum((dp.GrossPremium)) as premium,
	sum((dp.GrossPremium)) as APE,
	sum(0) as Newpolicies,
	sum((dp.GrossPremium*0.35)) as DA,
	sum((dp.OpenworkActualMarginamt)) as Margin,
	ah.agentstartdate as startdate,
	dp.CommissionAuthorisationDate,
	pr.Promotiondate

	from dbo.owt_OwlDirectPayments dp
		 left join Pol_Ref_Count e on e.transactionID = dp.ID
		 left join cscv_AgentsHierarchy ah on ah.Agentcode = dp.adviserUID
		 left join Manager_Prom pr on pr.Usr_login = dp.adviserUID
		 left join Comm_Month p on p.policyreference = dp.policyreference
	where
		Transactiontype like 'Endorse%'
		and dp.source like 'L&G'
		and (dp.Commissionmonth) >= @StartDate
		and (dp.Commissionmonth) <= @EndDate
		and p.policyreference is null
	
	group by
	dp.adviserUID,
	dp.Commissionmonth,
	day(dp.Commissionmonth),
	month(dp.Commissionmonth),
	year(dp.Commissionmonth),
	ah.agentstartdate,
	dp.CommissionAuthorisationDate,
	pr.Promotiondate

	------------------------------------------------------------------------L&G ASU Product End

	----GI

	--------------------------------------------------------------------------GI Start
	UNION ALL

	select
	'Issued' Type,
	oal.sellercode,
	'Advised',
	'GI',case when oal.remarks like  '%Renewal%' then 'GI-REN' else 'GI-NB' end,
	'GIPAYMENTSHIELD',
	case when oal.remarks like  '%Renewal%' then 'GI-REN' else 'GI-NB' end,
	 convert(date,dateadd(m,1,oal.paymentdate)) Date, --offset for reporting
	 day(convert(date,dateadd(m,1,oal.paymentdate))),
	 Month(convert(date,dateadd(m,1,oal.paymentdate))),
	 year(convert(date,dateadd(m,1,oal.paymentdate))),
	 sum(oal.premium) Premium,
	 sum(oal.APE) as APE,
	 sum(Case when (oal.remarks like '%New Business%' and oal.CommRate >12) or oal.remarks like '%Renewal%'  then 1 else 0 end) as NewPolicies,
	 sum(oal.APE) as DA, -----  GI DA = APE
	 sum(oal.APE - oal.TotalPayment)  as Margin,
	 ah.agentstartdate,
	 oal.paymentdate,
	 pr.Promotiondate
 
	from msit_OpenworkAdviserListing oal
		 inner join owt_PaymentshieldCommissionPayments pcp on pcp.ID = oal.SourceID and oal.Source = 'Payshield'
		 left join cscv_AgentsHierarchy ah on ah.Agentcode = oal.sellercode
		 left join Manager_Prom pr on pr.Usr_login = oal.sellercode

	where oal.Source = 'Payshield'
	and oal.MONTH > CAST(DATEADD(yy, DATEDIFF(yy, 0, GETDATE()) - 2, 0) AS DATE)
	and oal.Provider in ('Payment Shield Owl ASM','Payment Shield Owl')
	and oal.remarks not like 'CANCELLATION' 

	group by
	oal.sellercode,
	case when oal.remarks like  '%Renewal%' then 'GI-REN' else 'GI-NB' end,
	 convert(date,dateadd(m,1,oal.paymentdate)),
	 day(convert(date,dateadd(m,1,oal.paymentdate))),
	 Month(convert(date,dateadd(m,1,oal.paymentdate))),
	 year(convert(date,dateadd(m,1,oal.paymentdate))),
	 ah.agentstartdate,
	 oal.paymentdate,
	 pr.Promotiondate),


	--------------------------------------------------------------------------GI End


	------adding hierarchy and duplicate APE (for incentives)
	Hieracrhy_1 AS (
	select h.Type,h.PriAdviser,h.Adminmethod,h.ProductGroupName,h.daily_category,h.productsubgroup,h.productsubtype,h.Date,h.Day,h.Month,h.Year,h.Premium,h.Newpolicies,h.DA,h.Margin,h.startdate
	,h.writdate,h.promotiondate

	,h.APE AS APE

	,hier.owlasmuid1 asm1
	,hier.owlasmuid2 asm2
	,hier.owlasmuid3 asm3
	,hier.owlasmuid4 asm4
	,hier.owlasmuid5 asm5
	,hier.owlasmuid6 asm6
	,case when h.promotiondate is null or h.writdate <= convert(date, h.promotiondate) then 'Adviser' 
		  when h.writdate > convert(date, h.promotiondate) then 'Manager'
		  end PriStatus

	--into #itemp
	from Owl_Issued_Swift h left join
	mi_insight_UserHierarchyAllUsers hier on convert(varchar,hier.UserUID) = h.Priadviser
					 and convert(date,h.writdate) >= hier.effectivestartdate and convert(date,h.writdate) <= hier.effectiveenddate

	union all

	-- duplicate ape for new managers in incentive period
	----
	select h.Type,h.PriAdviser,h.Adminmethod,h.ProductGroupName,h.daily_category,h.productsubgroup,h.productsubtype,h.Date,h.Day,h.Month,h.Year,h.Premium,h.Newpolicies,h.DA,h.Margin,h.startdate
	,h.writdate,h.promotiondate

	,h.APE AS APE
 
	,hier.owlasmuid1 asm1
	,hier.owlasmuid2 asm2
	,hier.owlasmuid3 asm3
	,hier.owlasmuid4 asm4
	,hier.owlasmuid5 asm5
	,hier.owlasmuid6 asm6

	,case when h.promotiondate is null or h.writdate <= convert(date, h.promotiondate) then 'Manager' 
		  when h.writdate > convert(date, h.promotiondate) then 'Adviser'
		  end PriStatus
	from Owl_Issued_Swift h left join
	mi_insight_UserHierarchyAllUsers hier on convert(varchar,hier.UserUID) = h.Priadviser
					 and convert(date,h.writdate) >= hier.effectivestartdate and convert(date,h.writdate) <= hier.effectiveenddate

	------------------DON'T UNDERSTAND THIS BIT ------------------------------------------------------------------------------
	where  h.promotiondate >= DATEADD(yy, DATEDIFF(yy, 0, @startdate)-2, 0)
		  and (@inc2 = 1 or @inc1 = 1)),	
	--------------------------------------------------------------------------------------------------------------------------

	----
	-----Final summary table with full hierarchy


	Final_Summary AS (
	select Type
	,cast(case when Priadviser = '4007583' then '4007584' when Priadviser= '1012011' then '1012002' else Priadviser end as int) PriAdviser
	,Adminmethod,Productgroupname,Productsubgroup,productsubtype,daily_category
	,Date,Day,Month,Year
	,Premium,APE,Newpolicies,DA,Margin,Startdate,   	
	--,dupe,
	-- Reporting hierarchy
	case when  asm1 is null and asm2 is null and asm3 is null and asm4 is null and asm5 is null and asm6 is null and Pristatus <> 'Adviser' then Priadviser
		 when  asm2 is null and asm3 is null and asm4 is null and asm5 is null and asm6 is null then asm1
		 when  asm3 is null and asm4 is null and asm5 is null and asm6 is null then asm2
		 when  asm4 is null and asm5 is null and asm6 is null then asm3
		 when  asm5 is null and asm6 is null then asm4
		 when  asm6 is null then asm5
	end L0,

	case when  asm2 is null and asm3 is null and asm4 is null and asm5 is null and asm6 is null and Pristatus <> 'Adviser' then Priadviser
		 when  asm2 is null and asm3 is null and asm4 is null and asm5 is null and asm6 is null then asm1
		 when  asm3 is null and asm4 is null and asm5 is null and asm6 is null then asm1
		 when  asm4 is null and asm5 is null and asm6 is null then asm2
		 when  asm5 is null and asm6 is null then asm3
		 when  asm6 is null then asm4
	end L1,

	case when  asm3 is null and asm4 is null and asm5 is null and asm6 is null and Pristatus <> 'Adviser' then Priadviser
		 when  asm3 is null and asm4 is null and asm5 is null and asm6 is null then asm1
		 when  asm4 is null and asm5 is null and asm6 is null then asm1
		 when  asm5 is null and asm6 is null then asm2
		 when  asm6 is null then asm3
	end L2,

	case when  asm4 is null and asm5 is null and asm6 is null and Pristatus <> 'Adviser' then Priadviser
		 when  asm4 is null and asm5 is null and asm6 is null then asm1
		 when  asm5 is null and asm6 is null then asm1
		 when  asm6 is null then asm2
	end L3,

	case when  asm5 is null and asm6 is null and Pristatus <> 'Adviser' then Priadviser
		 when  asm5 is null and asm6 is null then asm1
		 when  asm6 is null then asm1
	end L4
	--into #gtemp

	from Hieracrhy_1),


	Owl_Issued_Business AS (

	SELECT
	Type
	,Date
	,Day
	,Month
	,Year
	,SUM(Premium) AS Premium
	,SUM(APE) AS APE
	,SUM(Newpolicies) AS NewPolicies
	,SUM(DA) AS DA
	,SUM(Margin) AS Margin
	,ProductGroupName
	,ProductsubGroup
	,Adminmethod
	,'Owl' AS Channel

	FROM Final_Summary

	Group BY 
	Type
	,Adminmethod
	,Productgroupname
	,Date
	,Day
	,ProductSubGroup
	,Month
	,Year),

	--------------------------------------------------END OWL ISSUED BUSINESS -------------------------------------------------------------------------------------------

	--------------------------------------------------OPENWORK ISSUED BUSINESS ------------------------------------------------------------------------------------------
	 First_Query AS (

	select
	min(transactionid) as transactionid, po.policyref, po.cont_num, co.productcode

	FROM          dbo.mstt_Commissions co INNER JOIN
				  dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
				  dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
				  dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
				  dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
				  dbo.msit_CodeReportingProductCode wr ON wr.Code = ph.ReportingProductCode LEFT OUTER JOIN
				  dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
				  cscv_AgentsHierarchy ah ON co.firm = ah.agentcode

	where co.poltrantranstype <> 39
	and co.agent_code not in ('10002','1011542','10004')	
	and co.commissiontype = 1
	and((left(ltrim(po.policyref),4) <> '8000' or left(ltrim(po.policyref),4) is null) or ph.productgroupname not like 'Protection')
	and pt.writtendate is not null -- Zurich Cases Fix JB 05/10/18
	group by po.policyref, po.cont_num, co.productcode

	union all

	select
	min(transactionid) as transactionid, '', '','L&G' provider

	FROM				  dbo.mstt_Commissions co INNER JOIN
						  dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
						  dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
						  dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
						  dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
						  dbo.msit_CodeReportingProductCode wr ON wr.Code = ph.ReportingProductCode LEFT OUTER JOIN
						  dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
						  cscv_AgentsHierarchy ah ON co.firm = ah.agentcode
	where
	co.agent_code not in ('10002','1011542','10004')
	and co.commissiontype = 1
	and co.poltrantranstype = 39
	and (ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
	and (left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
	and (left(ccs.description,2) <> 'UA' or ccs.description is NULL)
	and (co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)
	and((left(ltrim(po.policyref),4) = '8000' or left(ltrim(po.policyref),4) is null) and ph.productgroupname like 'Protection')
	and pt.writtendate is not null -- Zurich Cases Fix JB 05/10/18
	group by co.CLIENT_NUM,po.comp_code,case po.plan_code when 'IPP' then 'IPP' else 'OTHER' end),

	Second_Query AS(
	select transactionid,policyref,cont_num 
	from First_Query 
	where left(cont_num,2) <> 'ZR' or cont_num is null

	union all
	select case when left(cont_num,2) = 'ZR' then min(transactionid) end transactionid, policyref, cont_num
	from First_Query
	where left(cont_num,2) = 'ZR'
	group by  policyref, cont_num),

	-----------------------CORRECT APE LV
	Correct_LV_APE AS (
	Select distinct 
	edic.PolicyNumber, 
	edic.PremiumAmount, 
	edic.AmountReceived,  
	edic.CommissionType, 
	edih.LifeOfficeCode, 
	edih.DateReceived,
	potr.Amount, 
	potr.CommInitialPeriod, 
	potr.Amount/potr.CommInitialPeriod as CorrectPremium,
	(potr.Amount/potr.CommInitialPeriod)*12 as CorrectAPE,
	potr.Amount*12 as IncorrectAPE,
	pp.AGENT_CODE,
	pp.AGENT_PERC,
	pp.BACSDate,
	pp.FranchiseAgentCode,
	agt.DESCN,
	pp.TransactionID AS TransID
	from sa_swift_EDIFACTCommissionStatementContents edic
	join sa_swift_EDIFACTCommissionStatementHeader edih on edih.ID = edic.StatementHeaderID
	join sa_swift_S_PACC pacc on pacc.ID = edic.Pacc_ID
	join sa_swift_PolicyTransactions potr on potr.ID = pacc.TransactionID
	join mstt_PaymentsPending pp on pp.PACC_ID = pacc.ID
	join sa_swift_S_AGENTS agt on agt.code = pp.FranchiseAgentCode
	where edih.LifeOfficeCode = '24225G' and edih.DateReceived <= '10-Apr-2017' 
	and pp.BACSDate > '11-Jan-2016' 
	and edic.CommissionType = 'Y'
	and edic.PremiumAmount = potr.Amount
	and pp.AGENT_CODE != '10002'
	),

	OwlAROngoingFee as
	(Select distinct pacc_id
	 from mstt_PaymentsPending
	 where TranProduct in (select productcode from mstt_ProductHierarchy where RDRType is not null)
	 and CommissionType in (10,16,19)
	 and (Manager2Code = '4010386' OR Firm = '2016789')),

	-- ISSUED SWIFT
	Issued_Swift AS(
	select
	'Issued' as "Type",
	CAST(ag.createdatetime AS DATE) as Date, 
	day(ag.createdatetime) as "Day", month(ag.createdatetime) as "Month", year(ag.createdatetime) as "Year",

	-- PREMIUM FIX FOR CROSS CHARGE ASSUMING DA IS 2.5% OF PREMIUM
	sum(Case when (ag.commissiontype in ('1','17') and left(ccs.description,3) = 'IMP') then (cs.inissued + ((round((cs.inissued/ag.amount),0) *ag.derivedmarginamount))) / 0.025 else
	(Case when (case when pt.frequencydescription = 'Single' Then 'Single' ELSE 'Regular' end) = 'Single' then ((case when  (ag.commissiontype = 2 AND ph.productgroupname = 'Mortgage') then (coalesce(cs.ape,co2.turnover,0)) when ag.commissiontypedesc like '%claw%' then 0 else coalesce(cs.ape,co2.turnover,0) end) *10) else (case when ag.commissiontypedesc like '%claw%' then 0 else coalesce(cs.ape,co2.turnover,0) end)
	end) end) as "Premium",

	-- APE FIX FOR CROSS CHARGE ASSUMING DA IS 2.5% OF PREMIUM / 10 FOR APE
	sum(Case when (c.PolicyNumber = ag.providerRef AND ag.createdatetime < '10-Jul-2017') then c.CorrectAPE else
	((case when (ag.commissiontype in ('1','17') and left(ccs.description,3) = 'IMP') then ((cs.inissued + ((round((cs.inissued/ag.amount),0) *ag.derivedmarginamount))) / 0.025 / 10) else
	
	-- ENSURE MORTGAGES APE IS THE SAME AS DA
	(case when 
	ph.productgroupname = 'mortgage'
	then (case when (
	ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') then (ag.Amount+ag.derivedmarginamount)
	-- GROSS DA SERVICING
	when (cs.oastatus = 'valid' and left(tranproduct,2) in ('OW','OF','OZ') and ag.commissiontype in ('4','10','18','19')) then (ag.amount + isnull(derivedmarginamount,0))
	-- GROSS DA TRAIL
	when (cs.oastatus = 'valid' and tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','19')) then (ag.amount / (8.0/10))
	-- GROSS DA POT ACCOUNT
	when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and ag.agent_code in ('1011543','1006886','1011587') and ag.commissiontype not in ('0','2','3','7','8','14','15','16','20','21')) then (ag.amount + isnull(derivedmarginamount,0)) else 0 end)
	else (case when ag.commissiontypedesc like '%claw%' then 0 else coalesce(cs.ape,co2.turnover,0) end) end) END))End) as "APE", 


	sum(CASE WHEN b.policyref = 0 then 0 else (case when ag.commissiontypedesc like '%claw%' then 0 when b.transactionid is null then 0 when (ag.caseid is NULL AND ph.productgroupname = 'Protection' AND ag.agent_code <> '1000312') then 0 when ((coalesce(co.businessreason,co2.businessreason) = ('I')) and coalesce(co.adminmethoddescription,co2.adminmethoddescription,'Advisory Tracked') <> 'Not Sold By This Office' and coalesce(co.adminmethoddescription,co2.adminmethoddescription,'Advisory Tracked') <> 'Execution Only Increase') then 0 when cs.ape < 0 and ag.transactionid = b.transactionid then -ag.derivedagentsplit/100 when cs.ape = 0 then 0 when cs.ape > 0 and ag.transactionid = b.transactionid then ag.derivedagentsplit/100 else 0 end)END) as "NewPolicies",


	sum(
	case when (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid' AND ph.ProductGroupName = 'Mortgage') then (ag.Amount+ag.derivedmarginamount) ElSE

	(Case when (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') then (cs.inissued + ((round((cs.inissued/ag.amount),0) *ag.derivedmarginamount)))
	-- GROSS DA SERVICING
	when (cs.oastatus = 'valid' and left(tranproduct,2) in ('OW','OF','OZ') and ag.commissiontype in ('4','10','18','19')) then (ag.amount + isnull(derivedmarginamount,0))
	-- GROSS DA TRAIL
	when (cs.oastatus = 'valid' and tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','19')) then (ag.amount / (8.0/10))
	-- GROSS DA POT ACCOUNT
	when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and ag.agent_code in ('1011543','1006886','1011587') and ag.commissiontype not in ('0','2','3','7','8','14','15','16','20','21')) then 
		(ag.amount + isnull(derivedmarginamount,0)) else 0 END)END) as 'DA',

	-- GROSS MARGIN INITIAL
	sum(CASE when (ag.firm <> 1010904 AND RTRIM(ah.ASDName) = 'GHL' and (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') and left((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),3) <> '005') THEN (round(cs.INIssued / ag.AMOUNT,0) * ag.DerivedMarginAmount) - ((round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) * 0.7) 
		when (ag.firm <> 1010904 AND RTRIM(ah.ASDName) = 'GHL' and (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') and ph.productgroupname = 'Protection' and left((replace((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),'do not use - ','')),3) = '005') THEN (round(cs.INIssued / ag.AMOUNT,0) * ag.DerivedMarginAmount) - ((round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) * 0.6) 
		WHEN (RTRIM(ah.ASDName) = 'First Affinity' and (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') and left((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),3) <> '005') THEN (round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) - ((((cs.INIssued)*10.0)/9) - (cs.INIssued)) 
		when (RTRIM(ah.ASDName) = 'First Affinity' and (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') and ph.productgroupname = 'Protection' and left((replace((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),'do not use - ','')),3) = '005') THEN ((round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) - (cs.INIssued * 0.1655)) 
	
	
		when (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid' AND ph.productgroupname = 'Mortgage') then 
		(CASE when (ag.firm <> 1010904 AND RTRIM(ah.ASDName) = 'GHL' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and left((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),3) <> '005') THEN (round(cs.INIssued / ag.AMOUNT,0) * ag.DerivedMarginAmount) - ((round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) * 0.7) 
			 when (ag.firm <> 1010904 AND RTRIM(ah.ASDName) = 'GHL' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and ph.productgroupname = 'Protection' and left((replace((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),'do not use - ','')),3) = '005') THEN (round(cs.INIssued / ag.AMOUNT,0) * ag.DerivedMarginAmount) - ((round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) * 0.6) 
			 WHEN (RTRIM(ah.ASDName) = 'First Affinity' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and left((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),3) <> '005' ) THEN (round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) - ((((cs.INIssued)*10.0)/9) - (cs.INIssued)) 
			 when (RTRIM(ah.ASDName) = 'First Affinity' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and ph.productgroupname = 'Protection' and left((replace((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),'do not use - ','')),3) = '005') THEN ((round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) - (cs.INIssued * 0.1655)) ELSE (ag.derivedmarginamount) END)
	
		when (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') then (round(cs.INIssued / ag.AMOUNT,0) * ag.DerivedMarginAmount)
	-- GROSS MARGIN TRAIL
	when (cs.oastatus = 'valid' and tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','19')) then ((ag.amount / (8.0/10)) - ag.amount) 
	-- GROSS MARGIN POT ACCOUNT/SERVICING
	when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and ag.agent_code in ('1011543','1006886','1011587') and ag.commissiontype not in ('0','2','3','7','8','14','15','16','20','21')) then (ag.amount + isnull(derivedmarginamount,0)) else 0 end) as 'Margin',
	----------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
	case when ag.commissiontype in ('1','2','17') then (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' when ((left(ag.tranproduct,2) in ('OW','OZ') AND ag.tranproduct NOT IN ('OWADHOC','OWADVICE')) or ag.tranproduct = 'OFHBSIPP' or isnull(co.productprovidercode,ag.comp_code) = 'Zurich PLT' or isnull(co.productprovidercode,ag.comp_code) = 'Pru PLT') then 'COB Platform' when ph.productgroupname in ('Pensions','Investment') then 'COB Off Platform' when ph.productgroupname = 'Other' then 'COB Off Platform' else ph.productgroupname end) when (ag.commissiontype in ('4','10','15','16','18','19') and ag.agent_code <> '1011587' and ((left(ag.tranproduct,2) in ('OW','OF','OZ')) or ag.agent_code = '1011543')) then 'Recurring Income' when ag.agent_code = '1011587' then 'Recurring Income' when ag.commissiontype in ('10','16','19') then 'Recurring Income' else 'Recurring Income' end as ProductGroupName,

	case when (case when ag.commissiontype in ('1','2','17') then (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' when (left(isnull(co.productcode,ag.tranproduct),2) in ('OW','OZ') AND ag.tranproduct NOT IN ('OWADHOC','OWADVICE')) then 'COB Platform' when ph.productgroupname in ('Pensions','Investment') then 'COB Off Platform' else ph.productgroupname end) when (ag.commissiontype in ('4','10','15','16','18','19') and ((left(tranproduct,2) in ('OW','OF','OZ')) or ag.agent_code = '1011543')) then 'Recurring Income' when ag.commissiontype in ('10','16','19') then 'Recurring Income' else 'Recurring Income' end) in ('Trail Income','Renewal Income','Servicing Fee') then 'Recurring Income'

	--Protection
	when (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) = 'Protection' then (case when isnull(co.productprovidercode,ag.comp_code) in ('Zurich New','Zurich Leg','Zurich PNL') then 'Zurich' when isnull(co.productprovidercode,ag.comp_code) = 'Scot Eq' then 'Aegon' when isnull(co.productprovidercode,ag.comp_code) = 'Axa' then 'Friends Life' else isnull(co.productprovidercode,ag.comp_code) end) 
	-- Pensions
	when ((left(isnull(co.productcode,ag.tranproduct),2) in ('OW') AND ag.tranproduct NOT IN ('OWADHOC','OWADVICE')) or isnull(co.productcode,ag.tranproduct) = 'OFHBSIPP' or isnull(co.productprovidercode,ag.comp_code) = 'Pru PLT') then 'IFDL'
	when ((left(isnull(co.productcode,ag.tranproduct),2) in ('OZ') AND ag.tranproduct NOT IN ('OWADHOC','OWADVICE')) or isnull(co.productprovidercode,ag.comp_code) = 'Zurich PLT') then 'ZIP'
	when (isnull(co.productprovidercode,ag.comp_code) = 'MetLife' and (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) = 'Pensions') then 'MetLife'
	when (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) = 'Pensions' then isnull(co.productprovidercode,ag.comp_code)

	-- Annuities
	when (isnull(co.productprovidercode,ag.comp_code) = 'PTSP') then 'Partnership' when isnull(co.productprovidercode,ag.comp_code) = 'MGMA' then 'MGMA'
	when (isnull(co.productprovidercode,ag.comp_code) = 'PRU' and (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) = 'COB Off Platform') then 'Pru Ann'
	when (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) = 'COB Off Platform' then isnull(co.productprovidercode,ag.comp_code)

	-- Investments
	when (isnull(co.productprovidercode,ag.comp_code) = 'PRU' and (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) = 'Investment') then 'Pru'
	when (isnull(co.productprovidercode,ag.comp_code) = 'Scot EqInt' and (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) = 'Investment') then 'Aegon'
	when (ph.productgroupname = 'Investment' and ph.productsubgroupname like '%Guaranteed Account%') then 'Structured'
	when (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) = 'Investment' then isnull(co.productprovidercode,ag.comp_code)

	when ph.productgroupname = 'Mortgage' then 
	(case when rp.reportingproductname like '%Leeds & Holbeck Mortgages%' then 'Leeds Building Society' when rp.reportingproductname like '%Nationwide Mortgages%' then 'Nationwide Building Society' when rp.reportingproductname like '%Natwest Mortgages%' then 'Natwest' when rp.reportingproductname like '%Progressive Mortgages%' then 'Progressive Building Society' when rp.reportingproductname like '%Abbey Mortgages%' then 'Santander for Intermediaries' when rp.reportingproductname like '%Santander%' then 'Santander for Intermediaries' when rp.reportingproductname like '%Skipton Mortgages%' then 'Skipton Building Society' when rp.reportingproductname like '%Skipton (Buildstore)%' then 'Skipton Building Society' when rp.reportingproductname like '%Northern Rock%' then 'Virgin Money' when rp.reportingproductname like '%Platform%' then 'Platform (Co-op Bank)' when rp.reportingproductname like '%BM Solutions%' then 'BM Solutions (LBG)' when rp.reportingproductname like '%The Mortgage Works%' then 'The Mortgage Works (NBS)' when rp.reportingproductname like '%Godiva%' then 'Coventry' when rp.reportingproductname like '%Principality%' then 'Principality' when rp.reportingproductname like '%lloyds TSB%' then 'TSB' when rp.reportingproductname like '%Precise%' then 'Precise' when rp.reportingproductname like '%Newcastle%' then 'Newcastle Building Society' when rp.reportingproductname = 'BOI' THEN 'Bank of Ireland' when rp.reportingproductname like '%Woolwich%' then 'Barclays' else replace(replace(rp.reportingproductname,' Mortgages',''),' (TBMC)','') end)
	else (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) end as "ProductSubGroup",

	case when (case when ag.commissiontype in ('1','2','17') then (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' when ph.productgroupname = 'Other' then 'Pensions' else ph.productgroupname end) when (ag.commissiontype in ('4','10','15','16','18','19') and ((left(tranproduct,2) in ('OW','OF','OZ')) or ag.agent_code = '1011543')) then 'Servicing Fee' when ag.commissiontype in ('10','16','19') then 'Trail Income' else 'Renewal Income' end) in ('Trail Income','Renewal Income','Servicing Fee') then 'Advised' when 
	((ph.productgroupname <> 'Mortgage' and coalesce(co.adminmethod,co2.adminmethod,'A') NOT IN ('A','G')) or ph.productsubgroupname like '%Guaranteed Account%' or rp.reportingproductname = 'Zurich Bank Structured Product' or ph.productsubgroupname like '%Group Pension%' or isnull(co.productprovidercode,ag.comp_code) = 'Zurich Leg' or isnull(co.productcode,ag.tranproduct) = 'ZGUA' or isnull(co.productprovidercode,ag.comp_code) = 'Close' or isnull(co.productprovidercode,ag.comp_code) = 'MSQ') then 'Non Advised' else 'Advised' end as "Adminmethod"

	,CASE WHEN (ah.ASDCode = '4019902' OR ag.Firm = '2016789' or oof.PACC_ID is not null) THEN 'Owl AR' ELSE 'Openwork' END AS Channel

	from mstt_paymentspending ag LEFT OUTER JOIN
	msit_commissionstatement cs ON cs.PendingPaymentID = ag.id LEFT OUTER JOIN
	msit_openworkadviserlisting oa ON oa.sourceid = cs.id AND oa.Source = 'Openwork 2006' LEFT OUTER JOIN
	mstt_commissions co ON cs.commissionsid = co.id LEFT OUTER JOIN
	mstt_Commissions co2 on co2.transactionid = ag.transactionid 
	and co2.agent_code = ag.agent_code 
	and co2.commissiontype = case when ag.commissiontype in (1,2,17) then 1 
	when ag.commissiontype in (4,15,18) then 4 
	when ag.commissiontype in (10,16,19) then 10 end LEFT OUTER JOIN
	mstt_PolicyTransactions pt ON pt.ID = ag.TransactionID LEFT OUTER JOIN
	mstt_Commissions co3 on co3.transactionid = ag.transactionid 
	and co3.agent_code = pt.agentcode
	and co3.commissiontype = ag.commissiontype 
	and co3.firm <> '1011543' LEFT OUTER JOIN
	mstt_ProductHierarchy ph ON ag.tranproduct = ph.ProductCode LEFT OUTER JOIN
	msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode LEFT OUTER JOIN
	msit_CodeCommissionShape ccs ON ccs.id = pt.codecommissionshapeid LEFT OUTER JOIN
	cscv_AgentsHierarchy ah ON ag.firm = ah.agentcode LEFT OUTER JOIN
	Second_Query b on b.transactionid = ag.transactionid
	LEFT OUTER JOIN Correct_LV_APE c on (c.PolicyNumber = ag.providerref) AND (c.TransID = ag.TransactionID) 
	LEFT OUTER JOIN OwlAROngoingFee oof on oof.PACC_ID = ag.PACC_ID
	where 
	(ag.createdatetime) >= DATEADD(yy, DATEDIFF(yy, 0, GETDATE()) - 2, 0)
	and (ag.agent_code <> '10002' or ag.agent_code <> '1011623')
	--and ag.Firm = '2016789'
	--and ag.PACC_ID = 121001684
	and ag.amount <> 0
	and (co2.id not in ('17797514','17797515') or co2.id is NULL)
	and (co3.id not in ('17797514','17797515') or co3.id is NULL)
	and (cs.oastatus = 'valid' or cs.oastatus is NULL)
	and isnull(ag.Manager2Code,'1111') <> '1011671' -- EXCLUDES OWL ADVISERS
	--ENSURE NO TRAIL WHERE OPENWORK DO NOT TAKE A MARGIN IS INCLUDED
	and (case when (cs.oastatus = 'valid' and ag.commissiontype in ('4','10','15','16','18','19') and ag.tranproduct not like '%INCOME%' and ag.tranproduct not like '%PRUFUND%' and ag.tranproduct not like '%FIA%' and ag.tranproduct not like 'OW%' and ag.tranproduct not like 'OF%' and ag.tranproduct not like 'OZ%') then 'NonTrail' else 'Other' end) <> 'NonTrail' 

	--ENSURE NO ZERO DA TRANSACTIONS ARE INCLUDED AS UNNEEDED
	and (case when (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') then (ag.Amount+ag.derivedmarginamount)
	-- NET DA SERVICING
	when (cs.oastatus = 'valid' and left(tranproduct,2) in ('OW','OF','OZ') and ag.commissiontype in ('4','10','15','16','18','19')) then (ag.amount + isnull(derivedmarginamount,0))
	-- NET DA TRAIL
	when (cs.oastatus = 'valid' and tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','16','19')) then (ag.amount / (8.0/10))
	-- NET DA POT ACCOUNT
	when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and ag.agent_code in ('1011543','1006886','1011587') and ag.commissiontype not in ('0','3','7','8','14','20','21')) then (ag.amount + isnull(derivedmarginamount,0)) else 0 end) <> 0
	----------EXCLUDE ALL GROUP PENSION BUSINESS---------------------------
	and (case when ph.productsubgroupname NOT IN ('Group Pension') then 1 when (ph.productsubgroupname = 'Group Pension'and year(ag.createdatetime) <2016) then 1 else 0 end) = 1
	-----------------------------------------------------------------------
	group by
	CAST(ag.createdatetime AS DATE), 
	day(ag.createdatetime), month(ag.createdatetime), year(ag.createdatetime),

	CASE WHEN (ah.ASDCode = '4019902' OR ag.Firm = '2016789' or oof.PACC_ID is not null) THEN 'Owl AR' ELSE 'Openwork' END,

	case when ag.commissiontype in ('1','2','17') then (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' when ((left(ag.tranproduct,2) in ('OW','OZ') AND ag.tranproduct NOT IN ('OWADHOC','OWADVICE')) or ag.tranproduct = 'OFHBSIPP' or isnull(co.productprovidercode,ag.comp_code) = 'Zurich PLT' or isnull(co.productprovidercode,ag.comp_code) = 'Pru PLT') then 'COB Platform' when ph.productgroupname in ('Pensions','Investment') then 'COB Off Platform' when ph.productgroupname = 'Other' then 'COB Off Platform' else ph.productgroupname end) when (ag.commissiontype in ('4','10','15','16','18','19') and ag.agent_code <> '1011587' and ((left(ag.tranproduct,2) in ('OW','OF','OZ')) or ag.agent_code = '1011543')) then 'Recurring Income' when ag.agent_code = '1011587' then 'Recurring Income' when ag.commissiontype in ('10','16','19') then 'Recurring Income' else 'Recurring Income' end,
	case when (case when ag.commissiontype in ('1','2','17') then (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' when (left(isnull(co.productcode,ag.tranproduct),2) in ('OW','OZ') AND ag.tranproduct NOT IN ('OWADHOC','OWADVICE')) then 'COB Platform' when ph.productgroupname in ('Pensions','Investment') then 'COB Off Platform' else ph.productgroupname end) when (ag.commissiontype in ('4','10','15','16','18','19') and ((left(tranproduct,2) in ('OW','OF','OZ')) or ag.agent_code = '1011543')) then 'Recurring Income' when ag.commissiontype in ('10','16','19') then 'Recurring Income' else 'Recurring Income' end) in ('Trail Income','Renewal Income','Servicing Fee') then 'Recurring Income'

	--Protection
	when (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) = 'Protection' then (case when isnull(co.productprovidercode,ag.comp_code) in ('Zurich New','Zurich Leg','Zurich PNL') then 'Zurich' when isnull(co.productprovidercode,ag.comp_code) = 'Scot Eq' then 'Aegon' when isnull(co.productprovidercode,ag.comp_code) = 'Axa' then 'Friends Life' else isnull(co.productprovidercode,ag.comp_code) end) 
	-- Pensions
	when ((left(isnull(co.productcode,ag.tranproduct),2) in ('OW') AND ag.tranproduct NOT IN ('OWADHOC','OWADVICE')) or isnull(co.productcode,ag.tranproduct) = 'OFHBSIPP' or isnull(co.productprovidercode,ag.comp_code) = 'Pru PLT') then 'IFDL'
	when ((left(isnull(co.productcode,ag.tranproduct),2) in ('OZ') AND ag.tranproduct NOT IN ('OWADHOC','OWADVICE')) or isnull(co.productprovidercode,ag.comp_code) = 'Zurich PLT') then 'ZIP'
	when (isnull(co.productprovidercode,ag.comp_code) = 'MetLife' and (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) = 'Pensions') then 'MetLife'
	when (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) = 'Pensions' then isnull(co.productprovidercode,ag.comp_code)

	-- Annuities
	when (isnull(co.productprovidercode,ag.comp_code) = 'PTSP') then 'Partnership' when isnull(co.productprovidercode,ag.comp_code) = 'MGMA' then 'MGMA'
	when (isnull(co.productprovidercode,ag.comp_code) = 'PRU' and (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) = 'COB Off Platform') then 'Pru Ann'
	when (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) = 'COB Off Platform' then isnull(co.productprovidercode,ag.comp_code)

	-- Investments
	when (isnull(co.productprovidercode,ag.comp_code) = 'PRU' and (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) = 'Investment') then 'Pru'
	when (isnull(co.productprovidercode,ag.comp_code) = 'Scot EqInt' and (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) = 'Investment') then 'Aegon'
	when (ph.productgroupname = 'Investment' and ph.productsubgroupname like '%Guaranteed Account%') then 'Structured'
	when (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) = 'Investment' then isnull(co.productprovidercode,ag.comp_code)

	when ph.productgroupname = 'Mortgage' then 
	(case when rp.reportingproductname like '%Leeds & Holbeck Mortgages%' then 'Leeds Building Society' when rp.reportingproductname like '%Nationwide Mortgages%' then 'Nationwide Building Society' when rp.reportingproductname like '%Natwest Mortgages%' then 'Natwest' when rp.reportingproductname like '%Progressive Mortgages%' then 'Progressive Building Society' when rp.reportingproductname like '%Abbey Mortgages%' then 'Santander for Intermediaries' when rp.reportingproductname like '%Santander%' then 'Santander for Intermediaries' when rp.reportingproductname like '%Skipton Mortgages%' then 'Skipton Building Society' when rp.reportingproductname like '%Skipton (Buildstore)%' then 'Skipton Building Society' when rp.reportingproductname like '%Northern Rock%' then 'Virgin Money' when rp.reportingproductname like '%Platform%' then 'Platform (Co-op Bank)' when rp.reportingproductname like '%BM Solutions%' then 'BM Solutions (LBG)' when rp.reportingproductname like '%The Mortgage Works%' then 'The Mortgage Works (NBS)' when rp.reportingproductname like '%Godiva%' then 'Coventry' when rp.reportingproductname like '%Principality%' then 'Principality' when rp.reportingproductname like '%lloyds TSB%' then 'TSB' when rp.reportingproductname like '%Precise%' then 'Precise' when rp.reportingproductname like '%Newcastle%' then 'Newcastle Building Society' when rp.reportingproductname = 'BOI' THEN 'Bank of Ireland' when rp.reportingproductname like '%Woolwich%' then 'Barclays' else replace(replace(rp.reportingproductname,' Mortgages',''),' (TBMC)','') end)else (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) end,

	case when (case when ag.commissiontype in ('1','2','17') then (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' when ph.productgroupname = 'Other' then 'Pensions' else ph.productgroupname end) when (ag.commissiontype in ('4','10','15','16','18','19') and ((left(tranproduct,2) in ('OW','OF','OZ')) or ag.agent_code = '1011543')) then 'Servicing Fee' when ag.commissiontype in ('10','16','19') then 'Trail Income' else 'Renewal Income' end) in ('Trail Income','Renewal Income','Servicing Fee') then 'Advised' when 
	((ph.productgroupname <> 'Mortgage' and coalesce(co.adminmethod,co2.adminmethod,'A') NOT IN ('A','G')) or ph.productsubgroupname like '%Guaranteed Account%' or rp.reportingproductname = 'Zurich Bank Structured Product' or ph.productsubgroupname like '%Group Pension%' or isnull(co.productprovidercode,ag.comp_code) = 'Zurich Leg' or isnull(co.productcode,ag.tranproduct) = 'ZGUA' or isnull(co.productprovidercode,ag.comp_code) = 'Close' or isnull(co.productprovidercode,ag.comp_code) = 'MSQ') then 'Non Advised' else 'Advised' end

	UNION ALL

	---INSERT ZERO UPFRONT APE

	select
	'Issued' as "Type",
	CAST(pt.createdatetime AS DATE) as Date, 
	day(pt.createdatetime) as "Day", month(pt.createdatetime) as "Month", year(pt.createdatetime) as "Year",
	sum(case when pt.frequencydescription = 'Single' Then (co.ape * 10) ELSE (co.ape) end) as "Premium",
	sum(co.ape),

	sum(case when b.transactionid is null then 0 when (co.businessreason = 'I' and co.adminmethoddescription <> 'Not Sold By This Office' and co.adminmethoddescription <> 'Execution Only Increase') then 0 when co.ape = 0 then 0 when co.ape > 0 and co.transactionid = b.transactionid then co.agent_perc/100 else 0 end) as "NewPolicies",

	DA = 0,
	Margin = 0,
	case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' when ((left(co.productcode,2) in ('OW','OZ') AND ph.ProductCode NOT IN ('OWADHOC', 'OWADVICE')) or co.productcode = 'OFHBSIPP' or co.productprovidercode = 'Zurich PLT' or co.productprovidercode = 'Pru PLT') then 'COB Platform' when ph.productgroupname in ('Pensions','Investment') then 'COB Off Platform' else ph.productgroupname end as "Productgroupname",

	--Protection
	case when (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) = 'Protection' then (case when po.comp_code in ('Zurich New','Zurich Leg') then 'Zurich' when po.comp_code = 'Scot Eq' then 'Aegon' when po.comp_code = 'Axa' then 'Friends Life' else po.comp_code end) 
	-- Pensions
	when ((left(co.productcode,2) in ('OW') AND ph.ProductCode NOT IN ('OWADHOC', 'OWADVICE')) or co.productcode = 'OFHBSIPP' or po.comp_code = 'Pru PLT') then 'IFDL'
	when ((left(co.productcode,2) in ('OZ') AND ph.ProductCode NOT IN ('OWADHOC', 'OWADVICE')) or po.comp_code = 'Zurich PLT') then 'ZIP'
	when (po.comp_code = 'MetLife' and (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) = 'Pensions') then 'MetLife'
	when (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) = 'Pensions' then po.comp_code

	-- Annuities
	when (po.comp_code = 'PTSP') then 'Partnership' when po.comp_code = 'MGMA' then 'MGMA'
	when (po.comp_code = 'PRU' and (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) = 'COB Off Platform') then 'Pru'
	when (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) = 'COB Off Platform' then po.comp_code

	-- Investments
	when (po.comp_code = 'PRU' and (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) = 'Investment') then 'Pru'
	when (po.comp_code = 'Scot EqInt' and (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) = 'Investment') then 'Aegon'
	when (ph.productgroupname = 'Investment' and ph.productsubgroupname like '%Guaranteed Account%') then 'Structured'
	when (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) = 'Investment' then po.comp_code

	when ph.productgroupname = 'Mortgage' then 
	(case when rp.reportingproductname like '%Leeds & Holbeck Mortgages%' then 'Leeds Building Society' when rp.reportingproductname like '%Nationwide Mortgages%' then 'Nationwide Building Society' when rp.reportingproductname like '%Natwest Mortgages%' then 'Natwest' when rp.reportingproductname like '%Progressive Mortgages%' then 'Progressive Building Society' when rp.reportingproductname like '%Abbey Mortgages%' then 'Santander for Intermediaries' when rp.reportingproductname like '%Skipton Mortgages%' then 'Skipton Building Society' when rp.reportingproductname like '%Northern Rock%' then 'Virgin Money' when rp.reportingproductname like '%Platform%' then 'Platform (Co-op Bank)' when rp.reportingproductname like '%BM Solutions%' then 'BM Solutions (LBG)' when rp.reportingproductname like '%The Mortgage Works%' then 'The Mortgage Works (NBS)' when rp.reportingproductname like '%Godiva%' then 'Coventry' when rp.reportingproductname like '%Kensington%' then 'Investec' when rp.reportingproductname like '%Principality%' then 'Principality' else replace(replace(rp.reportingproductname,' Mortgages',''),' (TBMC)','') end)
	else (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) end as "ProductSubGroup",

	(case when ((ph.productgroupname <> 'Mortgage' and co.adminmethod NOT IN ('A','G')) or ph.productsubgroupname like '%Guaranteed Account%' or rp.reportingproductname = 'Zurich Bank Structured Product' or ph.productsubgroupname like '%Group Pension%' or po.comp_code = 'Zurich Leg' or co.productcode = 'ZGUA' or po.comp_code = 'Close' or po.comp_code = 'MSQ') then 'Non Advised' else 'Advised' end) as "Adminmethod"

	,CASE WHEN (ah.ASDCode = '4019902' OR co.Firm = '2016789') THEN 'Owl AR' ELSE 'Openwork' END AS Channel

	from 
	mstt_Commissions co LEFT OUTER JOIN
	mstt_Policytransactions pt on co.transactionid = pt.id LEFT OUTER JOIN
	mstt_Policies po on pt.policyid = po.pol_num LEFT OUTER JOIN
	mstt_ProductHierarchy ph ON co.ProductCode = ph.productcode LEFT OUTER JOIN
	msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode LEFT OUTER JOIN
	msit_CodeCommissionShape ccs ON ccs.id = pt.codecommissionshapeid LEFT OUTER JOIN
	cscv_AgentsHierarchy ah ON co.firm = ah.agentcode LEFT OUTER JOIN
	Second_Query b on b.transactionid = co.transactionid


	where
	co.agent_code <> '10002'
	and (pt.createdatetime) >= DATEADD(yy, DATEDIFF(yy, 0, GETDATE()) - 2, 0)
	and co.commissiontype = 1
	and ph.rdrtype is not null
	and pt.comminitialamount <= 0 and pt.amount > 0
	and co.poltrantranstype = 17
	and (rtrim(ah.ASDName) <> 'Pat Mckenna' or ah.ASDName is Null)
	----------------------------EXCLUDE ALL GROUP PENSION BUSINESS--------------------------------
	and (case when ph.productsubgroupname NOT IN ('Group Pension') then 1 when (ph.productsubgroupname = 'Group Pension'and year(pt.createdatetime) <2016) then 1 else 0 end) = 1
	----------------------------------------------------------------------------------------------

	group by

	CAST (pt.createdatetime AS DATE) , 
	day(pt.createdatetime), month(pt.createdatetime), year(pt.createdatetime),
	case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' when ((left(co.productcode,2) in ('OW','OZ') AND ph.ProductCode NOT IN ('OWADHOC', 'OWADVICE')) or co.productcode = 'OFHBSIPP' or co.productprovidercode = 'Zurich PLT' or co.productprovidercode = 'Pru PLT') then 'COB Platform' when ph.productgroupname in ('Pensions','Investment') then 'COB Off Platform' else ph.productgroupname end,

	CASE WHEN (ah.ASDCode = '4019902' OR co.Firm = '2016789') THEN 'Owl AR' ELSE 'Openwork' END,

	--Protection
	case when (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) = 'Protection' then (case when po.comp_code in ('Zurich New','Zurich Leg') then 'Zurich' when po.comp_code = 'Scot Eq' then 'Aegon' when po.comp_code = 'Axa' then 'Friends Life' else po.comp_code end) 
	-- Pensions
	when ((left(co.productcode,2) in ('OW') AND ph.ProductCode NOT IN ('OWADHOC', 'OWADVICE')) or co.productcode = 'OFHBSIPP' or po.comp_code = 'Pru PLT') then 'IFDL'
	when ((left(co.productcode,2) in ('OZ') AND ph.ProductCode NOT IN ('OWADHOC', 'OWADVICE')) or po.comp_code = 'Zurich PLT') then 'ZIP'
	when (po.comp_code = 'MetLife' and (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) = 'Pensions') then 'MetLife'
	when (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) = 'Pensions' then po.comp_code

	-- Annuities
	when (po.comp_code = 'PTSP') then 'Partnership' when po.comp_code = 'MGMA' then 'MGMA'
	when (po.comp_code = 'PRU' and (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) = 'COB Off Platform') then 'Pru'
	when (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) = 'COB Off Platform' then po.comp_code

	-- Investments
	when (po.comp_code = 'PRU' and (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) = 'Investment') then 'Pru'
	when (po.comp_code = 'Scot EqInt' and (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) = 'Investment') then 'Aegon'
	when (ph.productgroupname = 'Investment' and ph.productsubgroupname like '%Guaranteed Account%') then 'Structured'
	when (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) = 'Investment' then po.comp_code

	when ph.productgroupname = 'Mortgage' then 
	(case when rp.reportingproductname like '%Leeds & Holbeck Mortgages%' then 'Leeds Building Society' when rp.reportingproductname like '%Nationwide Mortgages%' then 'Nationwide Building Society' when rp.reportingproductname like '%Natwest Mortgages%' then 'Natwest' when rp.reportingproductname like '%Progressive Mortgages%' then 'Progressive Building Society' when rp.reportingproductname like '%Abbey Mortgages%' then 'Santander for Intermediaries' when rp.reportingproductname like '%Skipton Mortgages%' then 'Skipton Building Society' when rp.reportingproductname like '%Northern Rock%' then 'Virgin Money' when rp.reportingproductname like '%Platform%' then 'Platform (Co-op Bank)' when rp.reportingproductname like '%BM Solutions%' then 'BM Solutions (LBG)' when rp.reportingproductname like '%The Mortgage Works%' then 'The Mortgage Works (NBS)' when rp.reportingproductname like '%Godiva%' then 'Coventry' when rp.reportingproductname like '%Kensington%' then 'Investec' when rp.reportingproductname like '%Principality%' then 'Principality' else replace(replace(rp.reportingproductname,' Mortgages',''),' (TBMC)','') end)
	else (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) end,

	(case when ((ph.productgroupname <> 'Mortgage' and co.adminmethod NOT IN ('A','G')) or ph.productsubgroupname like '%Guaranteed Account%' or rp.reportingproductname = 'Zurich Bank Structured Product' or ph.productsubgroupname like '%Group Pension%' or po.comp_code = 'Zurich Leg' or co.productcode = 'ZGUA' or po.comp_code = 'Close' or po.comp_code = 'MSQ') then 'Non Advised' else 'Advised' end)

	UNION ALL
	---LEGACY

	select 
	'Issued' as "Type",
	CAST(oa.month AS DATE) as Date, 
	'1' as "Day", month(oa.month) as "Month", year(oa.month) as "Year",


	sum(oa.ape) as "Premium",
	sum(oa.ape) as "APE",
	"NewPolicies" = 0,
	sum(case when ph.productgroupname = 'Mortgage' then oa.ape else oa.totdue_enhd/0.8163 end) as "DA",

	sum(case when ph.productgroupname = 'Mortgage' then oa.ape - oa.totdue_enhd else ((oa.totdue_enhd/0.8163) - oa.totdue_enhd) end) as "Margin",

	case when oa.provider='General Insurance' then 'GI' when oa.provider='SIML' then 'COB Off Platform' when oa.provider='Sterling' then 'COB Off Platform' when oa.provider='Scottish Equitable' then 'COB Off Platform' when oa.prodtype = 'PE' then 'COB Off Platform' when ph.productgroupname in ('Pensions','Investment') then 'COB Off Platform' else isNull(ph.productgroupname,'Protection') end as productgroupname,

	'Legacy ' + case when oa.provider='General Insurance' then 'GI' when oa.provider='SIML' then 'COB Off Platform' when oa.provider='Sterling' then 'COB Off Platform' when oa.provider='Scottish Equitable' then 'COB Off Platform' when oa.prodtype = 'PE' then 'COB Off Platform' else (case when isNull(ph.productgroupname,'Protection') = 'Protection' then 'Zurich' else isNull(ph.productgroupname,'Protection') end) end as productsubgroupname,

	'Non Advised' as "AdminMethod"

	,CASE WHEN (ah.ASDCode = '4019902' OR oa.businesscode = '2016789') THEN 'Owl AR' ELSE 'Openwork' END AS Channel

	from msit_openworkadviserlisting oa left outer join 
	msit_feesNonSwiftFeeListing fnsfl on fnsfl.ID = oa.sourceID left outer join
	mstt_producthierarchy ph on 'NBI_'+ fnsfl.productCode = ph.productCode left outer join
	cscv_AgentsHierarchy ah ON oa.businesscode = ah.agentcode left outer join
	cscv_AgentsHierarchy ah1 ON oa.sellercode = ah1.agentcode

	where
	(oa.month) >= DATEADD(yy, DATEDIFF(yy, 0, GETDATE()) - 2, 0)
	and oa.feetype <> 'RC'
	and oa.feetype <> 'Trail'
	and oa.feetype <> 'TF'
	and oa.source = 'openwork 2005'
	and oa.providercode <> 'GI'
	and ((ape + totdue_enhd) <> 0)
	and (fnsfl.id <> '27617494' or fnsfl.id is NULL)
	----------------------------EXCLUDE ALL GROUP PENSION BUSINESS--------------------------------
	and (case when ph.productsubgroupname NOT IN ('Group Pension') then 1 when (ph.productsubgroupname = 'Group Pension'and year(oa.month) <2016) then 1 else 0 end) = 1
	----------------------------------------------------------------------------------------------
	group by

	CAST (oa.month AS DATE), 
	month(oa.month), year(oa.month),
	CASE WHEN (ah.ASDCode = '4019902' OR oa.businesscode = '2016789') THEN 'Owl AR' ELSE 'Openwork' END,
	case when oa.provider='General Insurance' then 'GI' when oa.provider='SIML' then 'COB Off Platform' when oa.provider='Sterling' then 'COB Off Platform' when oa.provider='Scottish Equitable' then 'COB Off Platform' when oa.prodtype = 'PE' then 'COB Off Platform' when ph.productgroupname in ('Pensions','Investment') then 'COB Off Platform' else isNull(ph.productgroupname,'Protection') end,

	'Legacy ' + case when oa.provider='General Insurance' then 'GI' when oa.provider='SIML' then 'COB Off Platform' when oa.provider='Sterling' then 'COB Off Platform' when oa.provider='Scottish Equitable' then 'COB Off Platform' when oa.prodtype = 'PE' then 'COB Off Platform' else (case when isNull(ph.productgroupname,'Protection') = 'Protection' then 'Zurich' else isNull(ph.productgroupname,'Protection') end) end

	UNION ALL

	---- GI

	select
	'Issued' as "Type",
	CAST((case when providercode in ('Payment shield', 'PYMTSHLD') then month - 27 else month end)AS DATE) as Date, 
	'1' as Day,
	month(case when providercode in ('Payment shield', 'PYMTSHLD') then month - 27 else month end) as month, 
	year(case when providercode in ('Payment shield', 'PYMTSHLD') then month - 27 else month end) as year,
	sum(case when providercode = 'GI' then ((totdue_base/27.5)*35) else ape end) as "Premium",
	sum(case when providercode = 'GI' then ((totdue_base/27.5)*35) else ape end) as "APE",
	sum(case when providercode = 'GI' then ((totdue_base/27.5)*35) else ape end / 121) as "NewPolicies",
	sum(case when providercode = 'GI' then ((totdue_base/27.5)*35) else ape end) as "DA",
	sum(case when (businesscode <> '1010904' AND rtrim(ah.asdname) = 'GHL') then (case when oa.providercode = 'GI' then ((totdue_base/27.5)*35) else (ape) end- (totdue_enhd))-((case when oa.providercode = 'GI' then ((totdue_base/27.5)*35) else (ape) end - (totdue_enhd)) *0.7) when rtrim(ah.asdname) = 'First Affinity' then (case when oa.providercode = 'GI' then ((totdue_base/27.5)*35) else (ape) end - (totdue_enhd)) -((totdue_enhd)*(10.0/9) - (totdue_enhd)) else case when oa.providercode = 'GI' then ((totdue_base/27.5)*35) else (ape) end - (totdue_enhd) end) as "Margin", 
	'GI' as ProductGroupName,
	providercode as ProductSubGroupName,
	'Advised' as AdminMethod
	,CASE WHEN (ah.ASDCode = '4019902' OR oa.businesscode = '2016789') THEN 'Owl AR' ELSE 'Openwork' END AS Channel

	-- paymentshield month - 31 as paymentshield in open access has been pushed forward
	from msit_openworkadviserlisting oa LEFT OUTER JOIN
	cscv_AgentsHierarchy ah ON oa.businesscode = ah.agentcode
	where 
	(case when providercode in ('Payment shield', 'PYMTSHLD') then month - 27 else month end) >= DATEADD(yy, DATEDIFF(yy, 0, GETDATE()) - 2, 0)
	and providercode in ('GI', 'Payment shield', 'PYMTSHLD')
	and feetype <> 'RC'
	and feetype <> 'Trail'
	and feetype <> 'TF'
	and APE <> 0
	and (rtrim(ah.ASDName) <> 'Pat Mckenna' or oa.sellercode <> '1011623' or ah.ASDName is Null)
	group by 
	CAST((case when providercode in ('Payment shield', 'PYMTSHLD') then month - 27 else month end)AS DATE), 
	month(case when providercode in ('Payment shield', 'PYMTSHLD') then month - 27 else month end), 
	year(case when providercode in ('Payment shield', 'PYMTSHLD') then month - 27 else month end),
	providercode,
	CASE WHEN (ah.ASDCode = '4019902' OR oa.businesscode = '2016789') THEN 'Owl AR' ELSE 'Openwork' END

	UNION ALL

	-----Mortgage Broker Fee

	Select 
	'Issued' as "Type", 
	CAST(MBF.PaymentMatchedDate AS DATE) as "Date", 
	Day(MBF.PaymentMatchedDate) as "Day", 
	Month(MBF.PaymentMatchedDate) as "Month", 
	Year(MBF.PaymentMatchedDate) as "Year",
	' ' as Premium, 
	SUM(MBF.APE) as "APE", 
	SUM(MBF.AgentSplit)/100 as "New Policies",
	SUM(MBF.APE) as "DA", 
	Sum(MBF.DeductionAmount*-1) as "Margin", 
	'Mortgage Broker Fee' as productgroupname,
	'MBF' as ProductSubGroupName,
	'Advised' as "AdminMethod"
	,CASE WHEN (ah.ASDCode = '4019902' OR MBF.FirmUID = '2016789') THEN 'Owl AR' ELSE 'Openwork' END AS Channel

	FROM dbo.owt_MortgageBrokerFees MBF JOIN
	cscv_AgentsHierarchy ah ON MBF.FirmUID = ah.agentcode

	where
	(MBF.PaymentMatchedDate) >= DATEADD(yy, DATEDIFF(yy, 0, GETDATE()) - 2, 0)
	and MBF.AdviceFeeCharged = 'Yes'
	and transactionID = (select max(TransactionID)
									from dbo.owt_MortgageBrokerFees MBF2
									where MBF2.policyID = MBF.PolicyID)

	Group by CAST(MBF.PaymentMatchedDate AS DATE), Day(MBF.PaymentMatchedDate), Month(MBF.PaymentMatchedDate), Year(MBF.PaymentMatchedDate), CASE WHEN (ah.ASDCode = '4019902' OR MBF.FirmUID = '2016789') THEN 'Owl AR' ELSE 'Openwork' END)

	--------------------------------------------------END OPENWORK ISSUED BUSINESS ------------------------------------------------------------------------------------------

	INSERT dbo.IssuedBusiness
		SELECT * FROM Issued_Swift
		UNION ALL
		SELECT * FROM Owl_Issued_Business
		OPTION ( USE HINT ( 'FORCE_LEGACY_CARDINALITY_ESTIMATION' ) );
END
GO
/****** Object:  StoredProcedure [dbo].[GetReportEmailRecipient]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[GetReportEmailRecipient] 
 @ReportName VARCHAR(200)
,@RecipientType VARCHAR(3) = 'TO'
,@ReportEmailRecipient VARCHAR(MAX) OUTPUT
AS
BEGIN
	SET NOCOUNT ON;

	SET @ReportEmailRecipient = STUFF((
								SELECT ';' + er.EmailRecipientName 
								FROM	dbo.Report r
								JOIN	dbo.ReportEmailRecipient rer ON rer.ReportID = r.ReportID
								JOIN	dbo.EmailRecipient er ON er.EmailRecipientID = rer.EmailRecipientID
								WHERE	rer.Active = 1
								AND		rer.RecipientType = @RecipientType
								AND		r.ReportName = @ReportName
								FOR XML PATH('')
								),1,1,'');

	SET @ReportEmailRecipient = REPLACE( @ReportEmailRecipient, '&amp;', '&' );
END
GO
/****** Object:  StoredProcedure [dbo].[GetWrittenBusiness]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE   PROCEDURE [dbo].[GetWrittenBusiness]
AS
/*
Original MI script from Written Business.sql

*/

BEGIN

	SET NOCOUNT ON; 

	TRUNCATE TABLE dbo.WrittenBusiness;

	----------------------QUERY NAME - OPENWORK WRITTEN BUSINESS EXCLUDING OWL AR BUSINESS-----------------------------------------------------------------------

	DECLARE @StartDate DATETIME,@EndDate DATETIME;

	SET DATEFIRST 1;
	SET DATEFORMAT DMY;
	SET @StartDate = DATEADD(yy, DATEDIFF(yy, 0, GETDATE()) - 2, 0)
	SET @EndDate = (DATEADD(day,datediff(day,0,GETDATE()),0));


	WITH All_Trans AS(

	SELECT
	MIN(transactionid) AS transactionid, 
	po.policyref, 
	po.cont_num, 
	co.productcode,
	ph.productgroupname,
	COMP_CODE

	FROM          dbo.mstt_Commissions co INNER JOIN
				  dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
				  dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
				  dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
				  dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
				  dbo.msit_CodeReportingProductCode wr ON wr.Code = ph.ReportingProductCode LEFT OUTER JOIN
				  dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
				  cscv_AgentsHierarchy ah ON co.firm = ah.agentcode
	WHERE
	co.agent_code not in ('10002','1011542','10004')
	and co.commissiontype = 1
	and co.poltrantranstype = 39
	and (ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
	and (left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
	and (left(ccs.description,2) <> 'UA' or ccs.description is NULL)
	and (co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)
	and((left(ltrim(po.policyref),4) <> '8000' or left(ltrim(po.policyref),4) is null) or ph.productgroupname not like 'Protection')

	GROUP BY po.policyref, po.cont_num, co.productcode, ph.productgroupname,COMP_CODE

	UNION ALL

	SELECT
	min(transactionid) AS transactionid, 
	'' t1, 
	'' t2,
	'' t3,
	ph.productgroupname,
	COMP_CODE

	FROM          dbo.mstt_Commissions co INNER JOIN
						  dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
						  dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
						  dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
						  dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
						  dbo.msit_CodeReportingProductCode wr ON wr.Code = ph.ReportingProductCode LEFT OUTER JOIN
						  dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
						  cscv_AgentsHierarchy ah ON co.firm = ah.agentcode
	WHERE
	co.agent_code not in ('10002','1011542','10004')
	and co.commissiontype = 1
	and co.poltrantranstype = 39
	and (ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
	and (left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
	and (left(ccs.description,2) <> 'UA' or ccs.description is NULL)
	and (co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)
	and((left(ltrim(po.policyref),4) = '8000' or left(ltrim(po.policyref),4) is null) and ph.productgroupname like 'Protection')
	and pt.writtendate is not null -- Zurich Cases Fix JB 05/10/18
	GROUP BY co.CLIENT_NUM,po.comp_code,
	CASE po.plan_code WHEN 'IPP' THEN 'IPP' ELSE 'OTHER' END,
	ph.productgroupname,
	COMP_CODE),



	------------ MAIN OPENWORK WRITTEN BUSINESS SCAN ---------------------------------------------------------

	-------------WRITTEN BUSINESS EXCLUDING MORTGAGE BROKER FEE ----------------------------------------------
	OW_Prod AS (

	SELECT 'Written' AS "Type", 
	CAST(wr.writtendate AS DATE) AS Date,
	DAY(wr.writtendate) AS "Day",
	MONTH(wr.writtendate) AS "Month", 
	YEAR(wr.writtendate) AS "Year", 
	SUM(CASE WHEN wr.frequency = 'Single' THEN wr.ape * 10 ELSE wr.ape END) AS Premium,
	SUM(wr.ape) AS APE, 
	SUM(wr.NBcases) AS NewPolicies,
	SUM(wr.distributionallowance) AS DA,
	SUM(wr.margin) AS Margin,
	CASE WHEN wr.productsubgroupname LIKE '%Annuity' THEN 'COB Off Platform' WHEN ((LEFT(wr.productcode,2) IN ('OW','OZ')) OR wr.productcode = 'OFHBSIPP' OR wr.provider = 'Zurich PLT' OR wr.provider = 'Pru PLT') THEN 'COB Platform' WHEN wr.productgroupname IN ('Pensions','Investment') THEN 'COB Off Platform' ELSE wr.productgroupname END AS 'ProductGroupName',

	-------------------------PRODUCT SUB GROUP DEFINITIONS ---------------------------------------------------------------------------------------------------------------------
	CASE WHEN wr.productgroupname = 'Protection' THEN (CASE WHEN wr.provider in ('Zurich New','Zurich Leg','Zurich PNL') THEN 'Zurich' WHEN wr.provider = 'Scot Eq' THEN 'Aegon' 
													   WHEN wr.provider = 'Axa' THEN 'Friends Life' 
													   ELSE wr.provider 
													   END) 
	-- Platform
	WHEN ((LEFT(wr.productcode,2) IN ('OW') AND LEFT(wr.productsubgroupname,3) <> 'FEE') OR wr.productcode = 'OFHBSIPP' OR wr.provider = 'Pru PLT' OR wr.provider = 'IFDL') THEN 'IFDL'
	WHEN ((LEFT(wr.productcode,2) IN ('OZ') AND LEFT(wr.productsubgroupname,3) <> 'FEE') OR wr.provider = 'Zurich PLT') THEN 'ZIP'

	-- Annuities
	WHEN (wr.provider = 'PTSP') THEN 'Partnership' 
	WHEN (wr.provider = 'MGMA') THEN 'MGMA'
	WHEN (wr.provider = 'PRU' AND (CASE WHEN wr.productsubgroupname LIKE '%Annuity' THEN 'Annuities' 
								   ELSE wr.productgroupname 
								   END) = 'Annuities') THEN 'Pru Ann'
	WHEN (CASE WHEN wr.productsubgroupname LIKE '%Annuity' THEN 'Annuities' 
		  ELSE wr.productgroupname 
		  END) = 'Annuities' THEN wr.provider

	-- Off Platform
	WHEN wr.provider = 'MetLife' THEN 'MetLife'
	WHEN wr.provider = 'PRU' THEN 'Pru'
	WHEN wr.provider = 'Octopus' THEN 'Octopus'
	WHEN (wr.productgroupname = 'Investment' AND wr.productsubgroupname LIKE '%Guaranteed Account%') THEN 'Structured'
	WHEN (LEFT(wr.productsubgroupname,3)) = 'FEE' THEN 'Other Fee'
	WHEN wr.productgroupname IN ('Pensions','Investment') THEN 'Other Comm'

	-- Mortgages
	WHEN wr.productgroupname = 'Mortgage' THEN 
	(CASE WHEN wr.reportingproductname LIKE '%Leeds & Holbeck Mortgages%' THEN 'Leeds Building Society' 
	 WHEN wr.reportingproductname LIKE '%Nationwide Mortgages%' THEN 'Nationwide Building Society' 
	 WHEN wr.reportingproductname LIKE '%Natwest Mortgages%' THEN 'Natwest' 
	 WHEN wr.reportingproductname LIKE '%Progressive Mortgages%' THEN 'Progressive Building Society' 
	 WHEN wr.reportingproductname LIKE '%Abbey Mortgages%' THEN 'Santander for Intermediaries' 
	 WHEN wr.reportingproductname LIKE '%Santander%' THEN 'Santander for Intermediaries' 
	 WHEN wr.reportingproductname LIKE '%Skipton Mortgages%' THEN 'Skipton Building Society' 
	 WHEN wr.reportingproductname LIKE '%Skipton (Buildstore)%' THEN 'Skipton Building Society'  
	 WHEN wr.reportingproductname LIKE '%Northern Rock%' THEN 'Virgin Money' 
	 WHEN wr.reportingproductname LIKE '%Platform%' THEN 'Platform (Co-op Bank)' 
	 WHEN wr.reportingproductname LIKE '%BM Solutions%' THEN 'BM Solutions (LBG)' 
	 WHEN wr.reportingproductname LIKE '%The Mortgage Works%' THEN 'The Mortgage Works (NBS)' 
	 WHEN wr.reportingproductname LIKE '%Godiva%' THEN 'Coventry' 
	 WHEN wr.reportingproductname LIKE '%Principality%' THEN 'Principality' 
	 WHEN wr.reportingproductname LIKE '%lloyds TSB%' THEN 'TSB' 
	 WHEN wr.reportingproductname LIKE '%Precise%' THEN 'Precise' 
	 WHEN wr.reportingproductname LIKE '%Newcastle%' THEN 'Newcastle Building Society' 
	 WHEN wr.reportingproductname = 'BOI' THEN 'Bank of Ireland' 
	 WHEN wr.reportingproductname LIKE '%Woolwich%' THEN 'Barclays' 
	 ELSE REPLACE(REPLACE(wr.reportingproductname,' Mortgages',''),' (TBMC)','') 
	 END)
	ELSE (CASE WHEN wr.productsubgroupname LIKE '%Annuity' THEN 'Annuities' ELSE wr.productgroupname END) END AS "ProductSubGroup",
	----------------------END OF PRODUCT SUB GROUP DEFINITIONS ------------------------------------------------------------------------
	wr.adminmethod,
	--SUM(wr.mortgageloanamount) AS MortgageLoanAmount, 
	--CASE WHEN wr.frequency = 'Single' THEN 'Single' ELSE 'Regular' END AS 'Frequency',

	--CASE WHEN sacrifice = 100 THEN 'Zero Fee' ELSE 'Fee' END AS UpfrontFee,
	--CASE WHEN wr.MortgageCategory = 'BTL' THEN wr.MortgageCategory WHEN wr.MortgageCategory = 'CBTL' THEN 'BTL' WHEN wr.MortgageType IN ('First Time Purchase', 'Second or Subsequent Purchase', 'Purchase', 'First Time Buyer') THEN 'New' WHEN  wr.productgroupname Not IN('Mortgage') THEN '' WHEN wr.MortgageType = 'Product transfer' THEN 'Product transfer' ELSE 'Remo' END AS MortgageCategory,
	--wr.MortgageCategory AS MortgageTransaction,
	wr.Channel

	FROM
	(SELECT
	CAST(co.AGENT_CODE AS int) AS Adviser,
	MIN(COALESCE(co.firm,co.agent_code)) AS Firm,
	MIN(co.transactionid) AS transactionid, 
	MIN(pt.writtendate) AS writtendate,
	DATEPART(WEEK,(pt.writtendate)) AS writtenweek, 
	YEAR(pt.writtendate) AS writtenyear,

	ROUND((CASE WHEN (ph.productgroupname = 'Mortgage' AND ccs.description IS NULL) THEN ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) ELSE co.Turnover END),2) AS APE,

	ROUND(MIN(CASE WHEN (ph.productgroupname = 'Protection' AND ccs.description IS NULL) THEN co.turnover * 2.2 
	WHEN (ph.productgroupname = 'Mortgage' AND ccs.description IS NULL) THEN ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) ELSE co.distributionallowance END),2) AS distributionallowance,

	ROUND(MIN(CASE WHEN (ph.productgroupname = 'Protection' AND ccs.description IS NULL) THEN ((co.turnover * 2.2) *0.7) 
	WHEN (ph.productgroupname = 'Mortgage' AND ccs.description IS NULL) THEN (((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) * 0.9) ELSE (co.baseamount + co.upliftamount) END),2) AS NBI,

	ROUND(MIN(CASE WHEN (ph.productgroupname = 'Protection' AND ccs.description IS NULL) THEN ((co.turnover * 2.2) *0.3) 
	WHEN (ph.productgroupname = 'Mortgage' AND ccs.description IS NULL) THEN (((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) * 0.1) ELSE (co.salesmargin) END),2) AS Margin,

	MIN(po.PolicyRef) AS minpolref,
	co.agent_perc tst2,
	CASE WHEN MIN(c.policyref) = 0 THEN 0 ELSE (CASE WHEN (MIN(po.PolicyRef) IS NULL AND ph.productgroupname = 'Protection' AND co.agent_code <> '1000312') THEN 0 ELSE MAX(CASE WHEN co.transactionid = c.transactionid AND (spt.CommNotes NOT LIKE '%IFDL to Zurich Transfer%' OR spt.CommNotes IS NULL) THEN (co.agent_perc/100) ELSE 0 END)End)END AS "NBCases", 
	CASE WHEN MIN(c.policyref) = 0 THEN 0 ELSE (CASE WHEN (min(po.PolicyRef) IS NULL AND ph.productgroupname = 'Protection' AND co.agent_code <> '1000312') OR (((LEFT(LTRIM(po.policyref),4) = '8000' or LEFT(LTRIM(po.policyref),4) IS NULL) AND ph.productgroupname like 'Protection')) THEN 0 ELSE MAX((co.agent_perc/100))End)END AS "AllCases", 
	MIN(pt.FrequencyDescription) AS frequency, 
	MIN(po.PolicyRef) AS CaseID, 
	po.CONT_NUM AS Policy, 
	MIN(co.BusinessReason) AS businessreason,
	MIN(co.AdminMethodDescription) AS adminmethoddescription, 
	MIN(co.ProductCode) AS productcode, 
	MIN(po.COMP_CODE) AS Provider, 
	MIN(rp.ReportingProductName) AS reportingproductname, 
	MIN(ph.ProductSubGroupName) AS productsubgroupname, 
	MIN(CASE WHEN ph.productgroupname = 'Other' THEN 'Pensions' ELSE ph.productgroupname END) AS "ProductGroupName",
	MIN(po.originatingsource) AS originatingsource, 
	MIN(CASE WHEN ((ph.productgroupname <> 'Mortgage' AND co.adminmethod NOT IN ('A','G')) OR ph.productsubgroupname LIKE '%Guaranteed Account%' OR rp.reportingproductname = 'Zurich Bank Structured Product' OR ph.productsubgroupname LIKE '%Group Pension%' OR po.comp_code = 'Zurich Leg' OR co.productcode = 'ZGUA' OR po.comp_code = 'Close' OR po.comp_code = 'MSQ') THEN 'Non Advised' ELSE 'Advised' END) AS "Adminmethod", 
	MIN(ccs.calculationcode) AS calculationcode, 
	MIN(ccs.description) AS description, 
	MIN(RTRIM(ah.asdname)) AS ASD,
	MIN(pt.mortgageamount) AS MortgageLoanAmount,
	MIN(pt.commtrialbalancegiveuppercent) AS Sacrifice,
	invtrans.ValueName AS MortgageType,
	invtrans2.ValueName AS MortgageCategory,
	CASE WHEN (ah.ASDCode = '4019902' OR MIN(COALESCE(co.firm,co.agent_code)) = '2016789') THEN 'Owl AR' ELSE 'Openwork' END AS Channel


	FROM          dbo.mstt_Commissions co INNER JOIN
				  dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
				  dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
				  dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
				  dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
				  dbo.msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode LEFT OUTER JOIN
				  dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
				  All_Trans c ON c.transactionid = co.transactionid LEFT OUTER JOIN
				  cscv_AgentsHierarchy ah ON co.firm = ah.agentcode LEFT JOIN 
				  sa_swift_PolicyTransactions spt ON spt.PolicyID = po.Pol_Num LEFT OUTER JOIN
				  dbo.sa_ows_policies opol ON opol.PolicyID = po.policyref LEFT OUTER JOIN
				  Policy.sa_ows_MortgageProduct mo ON mo.InternalProductID = opol.InternalProductID LEFT OUTER JOIN
				  vw_ows_MortgageProductSummary mps ON mps.PolicyID = po.policyref LEFT JOIN 
				  policy.sa_ows_MortgageRecommendedSolution mrs ON mrs.PolicyID = mps.PolicyID LEFT JOIN 
				  policyonelink.sa_ows_MortgageProductSummary olmps ON olmps.PolicyId = mps.PolicyID LEFT JOIN 
				  policy.sa_ows_MortgageProductSummary pmps ON pmps.PolicyID = mps.PolicyID LEFT JOIN 
				  StaticData.sa_ows_InputValues invTrans ON invtrans.InputID = CASE WHEN olmps.PolicyId IS NULL THEN mrs.TransactionTypeID ELSE olmps.TransactionTypeId END LEFT JOIN 
				  StaticData.sa_ows_InputValues invTrans2 ON invtrans2.InputID = mps.mortgagecategoryID

	WHERE  
	co.agent_code NOT IN ('10002','1011542','10004','1011623')
	AND co.commissiontype = 1
	AND co.poltrantranstype = 39
	AND (co.adminmethoddescription <> 'Indexation' OR co.adminmethoddescription IS NULL)
	AND (ph.productgroupname <> 'GI' OR ph.productgroupname IS NULL)
	AND (left(ccs.description,3) <> 'IMP' OR ccs.description IS NULL)
	AND (left(ccs.description,2) <> 'UA' OR ccs.description IS NULL)
	AND (co.productcode NOT IN ('OWADVICE','OWADHOC') or co.productcode IS NULL)
	AND po.COMP_CODE NOT LIKE '%Owl%'
	AND (RTRIM(ah.ASDName) <> 'Pat Mckenna' or ah.ASDName IS NULL)
	----------EXCLUDE ALL GROUP PENSION BUSINESS---------------------------
	AND (CASE WHEN ph.productsubgroupname NOT IN ('Group Pension') THEN 1 WHEN (ph.productsubgroupname = 'Group Pension'AND YEAR(pt.writtendate) <2016) THEN 1 ELSE 0 END) = 1
	-----------------------------------------------------------------------
	AND (pt.writtendate) >= @StartDate 
	AND (pt.writtendate) <= @EndDate

	GROUP BY
	CAST(co.AGENT_CODE AS INT), 
	ROUND((CASE WHEN (ph.productgroupname = 'Mortgage' AND ccs.description IS NULL) THEN ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) ELSE co.Turnover END),2), 
	po.policyref, 
	po.cont_num, 
	DATEPART(WEEK,(pt.writtendate)), 
	YEAR(pt.writtendate), 
	ph.productgroupname,
	ph.productgroupname,
	co.agent_code, 
	ah.ASDCode, 
	co.firm,
	co.agent_perc, 
	invtrans.ValueName,
	invtrans2.ValueName

	) wr

	WHERE
	(wr.caseid NOT IN ('500020430','500020431') OR wr.caseid IS NULL)


	GROUP BY
	CAST (wr.writtendate AS DATE),
	DAY(wr.writtendate), 
	MONTH(wr.writtendate), 
	YEAR(wr.writtendate),
	CASE WHEN wr.productsubgroupname LIKE'%Annuity' THEN 'COB Off Platform' WHEN ((LEFT(wr.productcode,2) IN ('OW','OZ')) OR wr.productcode = 'OFHBSIPP' OR wr.provider = 'Zurich PLT' OR wr.provider = 'Pru PLT') THEN 'COB Platform' WHEN wr.productgroupname IN ('Pensions','Investment') THEN 'COB Off Platform' ELSE wr.productgroupname END,
	wr.adminmethod, 
	--wr.Frequency,
	--CASE WHEN sacrifice = 100 THEN 'Zero Fee' ELSE 'Fee' END,
	--CASE WHEN wr.MortgageCategory = 'BTL' THEN wr.MortgageCategory WHEN wr.MortgageCategory = 'CBTL' THEN 'BTL' WHEN wr.MortgageType IN ('First Time Purchase', 'Second or Subsequent Purchase', 'Purchase', 'First Time Buyer') THEN 'New' WHEN  wr.productgroupname NOT IN ('Mortgage') THEN '' WHEN wr.MortgageType = 'Product transfer' THEN 'Product transfer' ELSE 'Remo' END,
	--wr.MortgageCategory, 
	wr.Channel,
	-------------------------PRODUCT SUB GROUP DEFINITIONS ---------------------------------------------------------------------------------------------------------------------
	CASE WHEN wr.productgroupname = 'Protection' THEN (CASE WHEN wr.provider in ('Zurich New','Zurich Leg','Zurich PNL') THEN 'Zurich' WHEN wr.provider = 'Scot Eq' THEN 'Aegon' 
													   WHEN wr.provider = 'Axa' THEN 'Friends Life' 
													   ELSE wr.provider 
													   END) 
	-- Platform
	WHEN ((LEFT(wr.productcode,2) IN ('OW') AND LEFT(wr.productsubgroupname,3) <> 'FEE') OR wr.productcode = 'OFHBSIPP' OR wr.provider = 'Pru PLT' OR wr.provider = 'IFDL') THEN 'IFDL'
	WHEN ((LEFT(wr.productcode,2) IN ('OZ') AND LEFT(wr.productsubgroupname,3) <> 'FEE') OR wr.provider = 'Zurich PLT') THEN 'ZIP'

	-- Annuities
	WHEN (wr.provider = 'PTSP') THEN 'Partnership' 
	WHEN (wr.provider = 'MGMA') THEN 'MGMA'
	WHEN (wr.provider = 'PRU' AND (CASE WHEN wr.productsubgroupname LIKE '%Annuity' THEN 'Annuities' 
								   ELSE wr.productgroupname 
								   END) = 'Annuities') THEN 'Pru Ann'
	WHEN (CASE WHEN wr.productsubgroupname LIKE '%Annuity' THEN 'Annuities' 
		  ELSE wr.productgroupname 
		  END) = 'Annuities' THEN wr.provider

	-- Off Platform
	WHEN wr.provider = 'MetLife' THEN 'MetLife'
	WHEN wr.provider = 'PRU' THEN 'Pru'
	WHEN wr.provider = 'Octopus' THEN 'Octopus'
	WHEN (wr.productgroupname = 'Investment' AND wr.productsubgroupname LIKE '%Guaranteed Account%') THEN 'Structured'
	WHEN (LEFT(wr.productsubgroupname,3)) = 'FEE' THEN 'Other Fee'
	WHEN wr.productgroupname IN ('Pensions','Investment') THEN 'Other Comm'

	-- Mortgages
	WHEN wr.productgroupname = 'Mortgage' THEN 
	(CASE WHEN wr.reportingproductname LIKE '%Leeds & Holbeck Mortgages%' THEN 'Leeds Building Society' 
	 WHEN wr.reportingproductname LIKE '%Nationwide Mortgages%' THEN 'Nationwide Building Society' 
	 WHEN wr.reportingproductname LIKE '%Natwest Mortgages%' THEN 'Natwest' 
	 WHEN wr.reportingproductname LIKE '%Progressive Mortgages%' THEN 'Progressive Building Society' 
	 WHEN wr.reportingproductname LIKE '%Abbey Mortgages%' THEN 'Santander for Intermediaries' 
	 WHEN wr.reportingproductname LIKE '%Santander%' THEN 'Santander for Intermediaries' 
	 WHEN wr.reportingproductname LIKE '%Skipton Mortgages%' THEN 'Skipton Building Society' 
	 WHEN wr.reportingproductname LIKE '%Skipton (Buildstore)%' THEN 'Skipton Building Society'  
	 WHEN wr.reportingproductname LIKE '%Northern Rock%' THEN 'Virgin Money' 
	 WHEN wr.reportingproductname LIKE '%Platform%' THEN 'Platform (Co-op Bank)' 
	 WHEN wr.reportingproductname LIKE '%BM Solutions%' THEN 'BM Solutions (LBG)' 
	 WHEN wr.reportingproductname LIKE '%The Mortgage Works%' THEN 'The Mortgage Works (NBS)' 
	 WHEN wr.reportingproductname LIKE '%Godiva%' THEN 'Coventry' 
	 WHEN wr.reportingproductname LIKE '%Principality%' THEN 'Principality' 
	 WHEN wr.reportingproductname LIKE '%lloyds TSB%' THEN 'TSB' 
	 WHEN wr.reportingproductname LIKE '%Precise%' THEN 'Precise' 
	 WHEN wr.reportingproductname LIKE '%Newcastle%' THEN 'Newcastle Building Society' 
	 WHEN wr.reportingproductname = 'BOI' THEN 'Bank of Ireland' 
	 WHEN wr.reportingproductname LIKE '%Woolwich%' THEN 'Barclays' 
	 ELSE REPLACE(REPLACE(wr.reportingproductname,' Mortgages',''),' (TBMC)','') 
	 END)
	ELSE (CASE WHEN wr.productsubgroupname LIKE '%Annuity' THEN 'Annuities' ELSE wr.productgroupname END) END
	-------------------------END OF PRODUCT SUB GROUP DEFINITIONS ------------------------------------------------

	-------------END OF WRITTEN BUSINESS EXCLUDING MORTGAGE BROKER FEE ----------------------------------------------
	UNION ALL

	------------- MORTGAGE BROKER FEES ------------------------
	SELECT
	'Written' AS Type,
	CAST (sale.datesubmitted AS DATE) AS DATE,
	DAY(sale.datesubmitted) AS Day,
	MONTH(sale.datesubmitted) AS Month,
	YEAR(sale.datesubmitted) AS Year,
	' ' AS Premium,
	SUM(mdaf.brokerfeeamount*AGENT_PERC/100) AS APE,
	COUNT(DISTINCT mdaf.policyID) AS Policies,
	SUM(mdaf.brokerfeeamount*AGENT_PERC/100) AS DA,
	SUM(CASE WHEN ah.ASDName in ('First Affinity','GHL') THEN ((mdaf.brokerfeeamount*AGENT_PERC/100)*0.05) ELSE (((mdaf.brokerfeeamount*AGENT_PERC/100) * (100 - (FranchiseUpliftPercent - (CASE WHEN sale.businessUID = '2005309' THEN 22.79 ELSE 20 END)))/100)) END) AS Margin,
	'Mortgage Broker Fee' AS ProductGroupName,
	mp.DisplayName,
	'Advised' AS AdminMethod,
	--0,
	--'Single' AS 'Frequency',

	--'Fee',
	--'' v1,
	--'' v2,
	CASE WHEN (ah.ASDCode = '4019902' OR ah.AgentCode = '2016789') THEN 'Owl AR' ELSE 'Openwork' END AS Channel

	FROM sa_swift_S_POLMAI polm
	join sa_swift_PolicyTransactions potr ON potr.PolicyID = polm.POL_NUM
	join sa_swift_S_AGTCOM agtc ON agtc.TransactionID = potr.ID
	join PolicyOneLink.sa_ows_MortgageDisclosureAndFee mdaf ON mdaf.PolicyId = polm.PolicyRef 
	join sa_ows_Sale sale ON sale.SaleID = mdaf.saleid
	join sa_ows_Policies pol ON pol.PolicyID = mdaf.PolicyId
	join policy.sa_ows_MortgageProvider mp ON mp.InternalProviderID = pol.InternalProviderID
	LEFT JOIN cscv_AgentsHierarchy ah ON ah.AgentCode = Sale.businessUID

	WHERE 
	1=1 
	AND potr.ID = (SELECT MIN(potr1.ID)
					FROM sa_swift_S_POLMAI polm1
					JOIN sa_swift_PolicyTransactions potr1 ON potr1.PolicyID = polm1.POL_NUM
					WHERE polm.PolicyRef = polm1.PolicyRef)
	AND AGENT_CODE != '10002' AND agtc.CommissionType = 1
	AND mdaf.HasBrokerFeeCharged = 19
	AND (sale.datesubmitted) >= @StartDate
	AND (sale.datesubmitted) <= @EndDate

	GROUP BY
	DAY(datesubmitted), 
	MONTH(datesubmitted), 
	YEAR(datesubmitted),
	CAST (sale.datesubmitted AS DATE),
	CASE WHEN (ah.ASDCode = '4019902' OR ah.AgentCode = '2016789') THEN 'Owl AR' ELSE 'Openwork' END,
	mp.DisplayName
 
	------------- END OF MORTGAGE BROKER FEES ------------------------

	),

	------------------------- END OF MAIN OPENWORK WRITTEN BUSINESS SCAN --------------------------------------------------------------------------

	---------------------PANEL MARGIN ADJUSTMENTS ------------------------------------------------------------------------------
	PMargin AS (

	SELECT
	comm.TransactionID,
	FixedAmount*((cr.UpfrontASM+cr.UpfrontESM+cr.UpfrontIntro+cr.DeferredASM+cr.DeferredESM+cr.DeferredIntro)/100) AS AdditionalPayaway

	FROM dbo.mstt_Commissions comm
	JOIN mstt_transagentsplithierarchyhistory tashh ON tashh.TransactionID = comm.TransactionID AND tashh.AgentCode = comm.AGENT_CODE AND comm.CommissionType = tashh.CommissionType
	JOIN
			(SELECT DISTINCT [EnterpriseUID],Panel FROM [prod_zurich_openwork_datawarehouse].[BI].[OwlEvoSwiftUpliftRates]) ol
			 ON ol.EnterpriseUID = tashh.FranchiseAgentCode
	JOIN OwlEvolution.ConfigRates cr ON cr.Panel = ol.Panel AND cr.UpliftRate = franchiseupliftpercent AND cr.ProductOrganization != 'Accruals'

	WHERE comm.Commissiontype = 1 
	AND poltrantranstype IN (39) 
	AND comm.ProductProviderCode NOT LIKE '%Owl'),

	---------------------END OF PANEL MARGIN ADJUSTMENTS ------------------------------------------------------------------------------

	C AS (

	SELECT
	MIN(transactionid) AS transactionid, 
	po.policyref, 
	po.cont_num, 
	co.productcode

	FROM        dbo.mstt_Commissions co INNER JOIN
				dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
				dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
				dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
				dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
				dbo.msit_CodeReportingProductCode wr ON wr.Code = ph.ReportingProductCode LEFT OUTER JOIN
				dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
				mstt_agents ag ON pt.agentcode = ag.code

	WHERE
	co.agent_code NOT IN ('10002','1011542','10004')
	AND co.commissiontype = 1
	AND co.poltrantranstype = 39
	AND (ph.productgroupname <> 'GI' OR ph.productgroupname IS NULL)
	AND (left(ccs.description,3) <> 'IMP' OR ccs.description IS NULL)
	AND (left(ccs.description,2) <> 'UA' OR ccs.description IS NULL)
	AND po.policyref NOT LIKE '800%' -- ignoring split multi-protect cases

	GROUP BY 
	po.policyref, 
	po.cont_num, 
	co.productcode),

	--------------- OWL MANAGER PROMOTION DATES -----------------------------
	Prom AS (

	SELECT DISTINCT ud.Usr_login
		   ,UPS_Jobtitle
		   ,MAX(UPS_Createddate) PromotionDate
		   ,ups_userid	
	FROM  sa_insight_UserDetails ud LEFT JOIN
		  sa_insight_UserPositionHistory uph ON uph.ups_userid = ud.Usr_id LEFT JOIN
		  mi_insight_UserHierarchy uh ON uh.useruid = ud.Usr_login

	WHERE
	UPS_Jobtitle = 54 
	AND UserJobTitleCodeSalesMgr = 54	

	GROUP BY 
	ud.Usr_login,
	UPS_Jobtitle,
	ups_userid	

	HAVING 
	MAX(UPS_Createddate) < @startdate),

	--------------- END OF OWL MANAGER PROMOTION DATES -----------------------------

	---------------- STANDARD OWL WRITTEN SCAN -------------------------------------------------------------------------

	Owl_Prod_Initial AS(

	SELECT 'Written' AS "Type", 
	wr.PriAdviser,
	wr.adminmethod,
	wr.productgroupname AS 'ProductGroupName',
	CASE WHEN wr.productcode LIKE '%AVIP OWL%' THEN 'AVIVA OWL' ELSE wr.productcode END AS 'Productsubgroup',
	wr.writtendate AS Date,
	DAY(wr.writtendate) AS "Day", 
	MONTH(wr.writtendate) AS "Month", 
	YEAR(wr.writtendate) AS "Year",
	SUM(CASE WHEN wr.frequency = 'Single' THEN wr.ape * 10 ELSE wr.ape END) AS Premium, 
	SUM(wr.ape) AS APE, 
	SUM(wr.NBcases) AS NewPolicies,
	SUM(wr.distributionallowance) AS DA, 
	SUM(wr.margin) AS Margin,
	CASE WHEN YEAR(wr.writtendate) = YEAR(GETDATE()) THEN 'Curr YTD' WHEN
		wr.writtendate BETWEEN DATEADD(YEAR, -1, DATEADD(YEAR, DATEDIFF(YEAR, 0, GETDATE()), 0)) AND DATEADD(YEAR, -1, DATEADD(DAY, DATEDIFF(DAY, 0, GETDATE()), 0)) THEN 'Prior YTD' ELSE
		'Not YTD' 
	END AS YTD,
	wr.startdate,
	pr.PromotionDate,
	wr.frequency

	FROM

	(
	SELECT 
	cast(co.AGENT_CODE AS INT) AS Adviser,
	 cast(pt.AGENTCODE AS INT) AS PriAdviser,
	CAST(MIN(ISNULL(s.DateSubmitted,pt.writtendate)) AS DATE) AS writtendate,
	ROUND((CASE WHEN (ph.productgroupname = 'Mortgage' AND ccs.description IS NULL) THEN ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) ELSE co.Turnover END),2) AS APE,
	ROUND(MIN(CASE WHEN (ph.productgroupname = 'Protection' AND ccs.description IS NULL) THEN co.turnover * 2.2 
				   WHEN (ph.productgroupname = 'Mortgage' AND ccs.description IS NULL) THEN ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) 
				   ELSE co.distributionallowance 
			   END),2) AS distributionallowance, 
	ROUND(MIN(CASE WHEN (ph.productgroupname = 'Protection' AND ccs.description IS NULL) THEN ((co.turnover * 2.2) *0.3) 
				   WHEN (ph.productgroupname = 'Mortgage' AND ccs.description IS NULL) THEN (((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) * 0.1) 
				   ELSE (co.salesmargin) END),2) - ISNULL(SUM(pm.additionalpayaway),0)	as Margin,
	MAX(CASE WHEN co.transactionid = c.transactionid THEN (co.agent_perc/100) ELSE 0 END) AS "NBCases", 
	MAX((co.agent_perc/100)) AS "AllCases",
	MIN(pt.FrequencyDescription) AS frequency,
	MIN(co.AdminMethodDescription) AS adminmethoddescription,
	MIN(co.ProductCode) AS productcode,
	MIN(ph.ProductSubGroupName) AS productsubgroupname, 
	MIN(ph.productgroupname) AS "ProductGroupName",
	MIN(CASE WHEN ((ph.productgroupname <> 'Mortgage' AND co.adminmethod NOT IN ('A','G'))) THEN 'Non Advised' ELSE 'Advised' END) AS "Adminmethod",
	ah.agentstartdate AS startdate

	FROM                   dbo.mstt_Commissions co INNER JOIN
						   dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
						   dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT JOIN             
						   dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT JOIN               
						   dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT JOIN
						   dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT JOIN
						   c ON c.transactionid = co.transactionid LEFT JOIN
						   cscv_AgentsHierarchy ah ON ah.agentcode = pt.AgentCode LEFT JOIN
						   sa_ows_Policies p ON p.PolicyID = po.PolicyRef LEFT JOIN
						   sa_ows_Sale s ON s.SaleID = p.SaleID LEFT JOIN
						   mi_insight_userhierarchyallusers uh2 ON uh2.useruid = pt.agentcode AND pt.writtendate BETWEEN uh2.effectivestartdate AND uh2.effectiveenddate LEFT JOIN
						   PMargin pm ON pm.transactionid = pt.id

	WHERE  
	co.agent_code NOT IN ('10002','1011542','10004')
	AND co.commissiontype = 1
	AND co.poltrantranstype = 39
	AND (co.adminmethoddescription <> 'Indexation' or co.adminmethoddescription IS NULL)
	AND (LEFT(ccs.description,3) <> 'IMP' or ccs.description IS NULL)
	AND (LEFT(ccs.description,2) <> 'UA' or ccs.description IS NULL)
	AND ((RTRIM(uh2.ADName) = 'Pat Mckenna' OR rtrim(ah.ASDName) = 'Pat Mckenna') OR co.agent_code IN ('1011623','1011629','1011630','1011631','1011632','1011633','1011634','1011635'))---OWL POT ACCOUNT NOT COUNTED
	AND (po.PolicyRef NOT IN ('500020430','500020431') OR po.PolicyRef IS NULL)
	AND ISNULL(s.DateSubmitted,pt.writtendate) >= CONVERT(DATETIME, @startdate,103)
	AND ISNULL(s.DateSubmitted,pt.writtendate) <= CONVERT(DATETIME, @enddate,103)

	GROUP BY
	CAST(co.AGENT_CODE AS INT),
	CAST(pt.AGENTCODE AS INT),
	ROUND((CASE WHEN (ph.productgroupname = 'Mortgage' AND ccs.description IS NULL) THEN ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) ELSE co.Turnover END),2),
	po.policyref,
	po.cont_num,
	ah.agentstartdate

	HAVING
	NOT (MIN(co.ProductCode) NOT LIKE '%owl%' AND MIN(ISNULL(s.DateSubmitted,pt.writtendate)) <= '2018-12-01')
	) wr


	LEFT JOIN prom pr ON pr.Usr_login = wr.PriAdviser 

	WHERE
	(wr.writtendate) >=  @startdate 
	AND (wr.writtendate) <= @enddate


	GROUP BY
	wr.writtendate, 
	DAY(wr.writtendate), 
	MONTH(wr.writtendate), 
	YEAR(wr.writtendate),
	wr.PriAdviser,
	wr.productgroupname,
	CASE WHEN wr.productcode LIKE '%AVIP OWL%' THEN 'AVIVA OWL' ELSE wr.productcode END,
	wr.adminmethod,
	wr.startdate,
	pr.Promotiondate,
	wr.frequency,
	CASE WHEN YEAR(wr.writtendate) = YEAR(GETDATE()) THEN 'Curr YTD' 
		 WHEN wr.writtendate BETWEEN DATEADD(YEAR, -1, DATEADD(YEAR, DATEDIFF(YEAR, 0, GETDATE()), 0)) AND DATEADD(YEAR, -1, DATEADD(DAY, DATEDIFF(DAY, 0, GETDATE()), 0)) THEN 'Prior YTD' 
		 ELSE 'Not YTD'
	END

	---------------- END OF STANDARD OWL WRITTEN SCAN ---------------------------------------------------------------------------------------------------------------------------------------

	UNION all

	----------------- OWS L&G ASU Product Added 20/03/17 ------------------------------------------------------------------

	SELECT 
	'Written' AS Type,
	sale.AdviserUID AS priadviser,
	'Advised' AS adminmethod,
	'Protection' AS ProductGroupName,
	'L&GASU OWL' AS ProductSubGroup,
	CAST(pol.ApplicationDate AS DATE) AS Date,
	DAY(pol.ApplicationDate) AS Day,
	MONTH(pol.ApplicationDate) AS Month,
	YEAR(pol.ApplicationDate) AS Year,
	SUM(pps.PremiumAmount*12) AS Premium,
	SUM(pps.PremiumAmount*12) AS APE,
	SUM(1) AS NewPolicies,
	SUM(pps.PremiumAmount*12*0.35) AS DA,
	SUM(pps.PremiumAmount*12*0.10) AS Margin,
	CASE WHEN YEAR(pol.ApplicationDate) = YEAR(GETDATE()) THEN 'Curr YTD' WHEN
		pol.ApplicationDate BETWEEN DATEADD(YEAR, -1, DATEADD(YEAR, DATEDIFF(YEAR, 0, GETDATE()), 0)) AND DATEADD(YEAR, -1, DATEADD(DAY, DATEDIFF(DAY, 0, GETDATE()), 0)) THEN 'Prior YTD' 
		ELSE 'Not YTD' 
	END AS YTD,
	ah.agentstartdate AS startdate,
	pr.Promotiondate,
	pt.FrequencyDescription

	FROM sa_ows_Policies  pol 
	JOIN policy.sa_ows_ProtectionProductSummary pps ON pps.PolicyID = pol.PolicyID
	JOIN sa_ows_sale sale ON sale.SaleID = pol.SaleID
	JOIN mi_insight_UserHierarchy uh ON uh.UserUID = sale.AdviserUID
	JOIN cscv_AgentsHierarchy ah ON agentcode = sale.adviseruid
	LEFT JOIN prom pr ON pr.Usr_login = sale.adviseruid 
	LEFT JOIN dbo.mstt_Policies po ON po.PolicyRef = pol.PolicyID 
	LEFT JOIN dbo.mstt_Commissions co ON co.PolicyID = po.POL_NUM 
	LEFT JOIN dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID

	WHERE
	InternalProductID = 10000063
	AND SaleStatusID = 2 AND pol.Status = 2
	AND sale.adviserUID <> '4006226' -- Excluding the test UID
	AND pol.ApplicationDate >=	CONVERT(DATE, @startdate,103)
	AND pol.ApplicationDate <= CONVERT(DATE, @enddate,103)

	GROUP BY 
	pol.ApplicationDate,
	DAY(pol.ApplicationDate),
	MONTH(pol.ApplicationDate),
	YEAR(pol.ApplicationDate),
	sale.AdviserUID,
	ah.agentstartdate,
	pr.Promotiondate,
	pt.FrequencyDescription,
	CASE WHEN YEAR(pol.ApplicationDate) = YEAR(GETDATE()) THEN 'Curr YTD' WHEN
		pol.ApplicationDate BETWEEN DATEADD(YEAR, -1, DATEADD(YEAR, DATEDIFF(YEAR, 0, GETDATE()), 0)) AND DATEADD(YEAR, -1, DATEADD(DAY, DATEDIFF(DAY, 0, GETDATE()), 0)) THEN 'Prior YTD' 
		ELSE 'Not YTD' 
	END),
	-------------- END OF OWS L&G ASU Product Added 20/03/17 ------------------------------------------------------------------------------------------------------------------------------

	-------------- ADDING HIERARCHY AND DUPLICATE APE (FOR INCENTIVES)----------------------------------------------------------

	i AS (

	SELECT h.* 
	,hier.owlasmuid1 asm1
	,hier.owlasmuid2 asm2
	,hier.owlasmuid3 asm3
	,hier.owlasmuid4 asm4
	,hier.owlasmuid5 asm5
	,hier.owlasmuid6 asm6
	,CASE WHEN h.promotiondate IS NULL or h.date <= CONVERT(DATE, h.promotiondate) THEN 'Adviser' 
		  WHEN h.date > CONVERT(DATE, h.promotiondate) THEN 'Manager'
		  END PriStatus
	,0 dupe

	FROM Owl_Prod_Initial h LEFT JOIN
	mi_insight_UserHierarchyAllUsers hier ON CONVERT(VARCHAR,hier.UserUID) = CONVERT(VARCHAR,h.Priadviser)
																			 AND ((CONVERT(DATE,h.date) >= hier.effectivestartdate 
																			 AND CONVERT(DATE,h.date) <= hier.effectiveenddate ))

	-------------- END OF ADDING HIERARCHY AND DUPLICATE APE (FOR INCENTIVES) -------------------------------------------------------
				 		 
	UNION ALL

	-------------- DUPLICATE APE FOR NEW MANAGERS IN INCENTIVE PERIOD ------------------------------

	SELECT h.*
	,hier.owlasmuid1 asm1
	,hier.owlasmuid2 asm2
	,hier.owlasmuid3 asm3
	,hier.owlasmuid4 asm4
	,hier.owlasmuid5 asm5
	,hier.owlasmuid6 asm6

	,CASE WHEN h.promotiondate IS NULL or h.date <= CONVERT(DATE, h.promotiondate) THEN 'Manager' 
		  WHEN h.date > CONVERT(DATE, h.promotiondate) THEN 'Adviser'
		  END PriStatus
	,1 dupe

	FROM Owl_Prod_Initial h LEFT JOIN
	mi_insight_UserHierarchyAllUsers hier ON CONVERT(VARCHAR,hier.UserUID) = CONVERT(VARCHAR,h.Priadviser)
																			 AND ((CONVERT(DATE,h.date) >= hier.effectivestartdate 
																			 AND CONVERT(DATE,h.date) <= hier.effectiveenddate))
				 		 
	WHERE  h.promotiondate BETWEEN @startdate AND @enddate),
	-------------- END DUPLICATE APE FOR NEW MANAGERS IN INCENTIVE PERIOD ------------------------------
	
	-------------- FINAL OWL SUMMARY TABLE -------------------------------------------------
	Owl_Prod AS (

	SELECT 
	Type
	--,CONVERT(VARCHAR(10), DATE, 103) AS Date
	,Date
	,Day
	,Month
	,Year 
	,SUM(Premium) AS Premium
	,SUM(APE) AS APE
	,SUM(Newpolicies) AS Newpolicies
	,SUM (DA) AS DA
	,SUM(Margin) AS Margin
	,Productgroupname
	,ProductSubGroup
	,Adminmethod
	--,0 AS 'Mortgage Loan Amount'
	--,Frequency

	--,'' AS 'UpfrontFee'
	--,'' AS 'MortgageCat'
	--,'' AS 'MortgageTrans'
	,'Owl' AS Channel

	FROM i LEFT JOIN 
		(SELECT UserUID UID FROM  mi_insight_userhierarchyallusers WHERE userjobtitlecodeseller = 61 AND effectiveenddate > GETDATE()) Panel	
		ON panel.UID = CASE WHEN i.Priadviser = '4007583' THEN '4007584' ELSE i.Priadviser END
		
	GROUP BY 
	Type
	,Adminmethod
	,Productgroupname
	,Date
	,Day
	,ProductSubGroup
	,Month
	,Year 
	,YTD)
	--,Frequency)
	-------------- END OF FINAL OWL SUMMARY TABLE -------------------------------------------------

	-------------- FINAL WRITTEN BUSINESS OUTPUT CREATION ------------------------------
	INSERT dbo.WrittenBusiness
		SELECT * FROM OW_Prod
		UNION ALL
		SELECT * FROM Owl_Prod;
END
GO
/****** Object:  StoredProcedure [dbo].[Insert_DWH_Standing_Order]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[Insert_DWH_Standing_Order]
/****** CREATED:  Stephen Lancaster June 2025 ******/

--Utilities
--STORED procedure to insert new Standing Order Description (used on reports)
--run in Utilities on DWH
--TO EXECUTE THIS RUN exec [Insert_DWH_Standing_Order] 'TEST_TICKET','1234','BSC rebated',2,0 -- last field is 0 for rollback or 1 for commit


-----To be added by user
	@TicketNo varchar(50),
	@SwiftCode int,
	@SwiftDescription varchar(150),
	@ReportingClassCode int,
	@RunLive bit --- Run Live

as
-----Set as same for each insert
declare @SwiftField nvarchar(20),
	@ReportingClassDescription varchar(10),
	@Section16 varchar(5),
	@S16Type nvarchar(10),
	@S16TypeDesc nvarchar(10)

	set @SwiftField = 'StandingOrderCode'
	set	@ReportingClassDescription = 'Charge'
	set	@Section16 = 'N'
	set	@S16Type = NULL
	set	@S16TypeDesc = NULL

---Log
declare @Phase nvarchar(4000),
	@theUser nvarchar(150),
	@DateLastUpdated DateTime,
	@alreadyExists bit,
	@alreadyExistsSwiftCode bit

set @theUser = (SELECT CURRENT_USER)
set @DateLastUpdated = Getdate()
set @alreadyExists = 0
set @alreadyExistsSwiftCode = 0

Begin Try

/*Rollback if set to 0*/

--Check if description already in table
IF exists (Select top 1 * from [dbo].[msit_CommissionReportingClassCodes] where SwiftDescription = @SwiftDescription) BEGIN
	set @alreadyExists = 1
END
--Check if swift code already in table
IF exists (Select top 1 * from [dbo].[msit_CommissionReportingClassCodes] where SwiftField = @SwiftField and SwiftCode = @SwiftCode) BEGIN
	set @alreadyExistsSwiftCode = 1
END

--Insert into table
BEGIN TRAN
	Insert into [dbo].[msit_CommissionReportingClassCodes]
	values
	(@SwiftField, @SwiftCode, @SwiftDescription, @ReportingClassCode, @ReportingClassDescription, @Section16, @S16Type, @S16TypeDesc)

--Check if live 
IF @RunLive = 1 BEGIN
	select 'RUNNING LIVE RUN'	

	--Inform user if description already exists (show data if insert had happened)
	IF @alreadyExists = 1 BEGIN
		Select 'ROLLBACK RUN - SwiftDescription already in msit_CommissionReportingClassCodes'

		select 'ROWS THAT WOULD EXISTS AFTER INSERT', SwiftField, SwiftCode, SwiftDescription, ReportingClassCode, ReportingClassDescription, Section16, S16Type, S16TypeDesc From [dbo].[msit_CommissionReportingClassCodes]
		where SwiftDescription = @SwiftDescription

	END 

	--Inform user if swift code already exists (show data if insert had happened)
	IF @alreadyExistsSwiftCode = 1 BEGIN
		Select 'ROLLBACK RUN - SwiftCode already in msit_CommissionReportingClassCodes'

		select 'ROWS THAT WOULD EXISTS AFTER INSERT', SwiftField, SwiftCode, SwiftDescription, ReportingClassCode, ReportingClassDescription, Section16, S16Type, S16TypeDesc From [dbo].[msit_CommissionReportingClassCodes]
		where SwiftField = @SwiftField and SwiftCode = @SwiftCode
	END

	--Rollback insert if description or swift code already exists
	IF @alreadyExists = 1 or @alreadyExistsSwiftCode = 1 BEGIN
		ROLLBACK TRAN
	--Inform user of inserted rows
	END ELSE BEGIN
		select 'LIVE INSERT', SwiftField, SwiftCode, SwiftDescription, ReportingClassCode, ReportingClassDescription, Section16, S16Type, S16TypeDesc From [dbo].[msit_CommissionReportingClassCodes]
		where SwiftField = @SwiftField and SwiftCode = @SwiftCode and SwiftDescription = @SwiftDescription

		COMMIT TRAN
	END

--check if rollback mode
END ELSE BEGIN
	select 'RUNNING IN ROLLBACK MODE'

	ROLLBACK TRAN
	--If desciption exists inform user
	IF exists (Select * from [dbo].[msit_CommissionReportingClassCodes] where SwiftDescription = @SwiftDescription) BEGIN
		select 'SwiftDescription already in msit_CommissionReportingClassCodes', SwiftField, SwiftCode, SwiftDescription, ReportingClassCode, ReportingClassDescription, Section16, S16Type, S16TypeDesc From [dbo].[msit_CommissionReportingClassCodes]
		where SwiftDescription = @SwiftDescription
	END
	--If swift code exists inform user
	IF exists (Select * from [dbo].[msit_CommissionReportingClassCodes] where SwiftField = @SwiftField and SwiftCode = @SwiftCode) BEGIN
		select 'SwiftCode already in msit_CommissionReportingClassCodes', SwiftField, SwiftCode, SwiftDescription, ReportingClassCode, ReportingClassDescription, Section16, S16Type, S16TypeDesc From [dbo].[msit_CommissionReportingClassCodes]
		where SwiftField = @SwiftField and SwiftCode = @SwiftCode
	END
	--If not in table safe to continue
	IF NOT exists (Select * from [dbo].[msit_CommissionReportingClassCodes] where SwiftDescription = @SwiftDescription) and 
		NOT exists (Select * from [dbo].[msit_CommissionReportingClassCodes] where SwiftField = @SwiftField and SwiftCode = @SwiftCode) BEGIN
		select 'Not already in table, you can continue'
	END
END
	
--If in run live mode and description and swift code do not exist
IF @RunLive = 1 and @alreadyExists = 0 and @alreadyExistsSwiftCode = 0 BEGIN

	/*Write to log*/
	Set @Phase = 'COMPLETED INSERT'

	Insert into [dbo].[appman_DWH_Standing_Order_Log]
	values
	(@TicketNo, @DateLastUpdated, @Phase, @theUser, @SwiftField, @SwiftCode, @SwiftDescription, @ReportingClassCode, @ReportingClassDescription, @Section16, @S16Type, @S16TypeDesc)
END
	Select 'Check exists in live Swift', 'Select distinct [Description] from CommAgentStandingOrders where Description like ''' + '%' + cast(@SwiftDescription as nvarchar(150)) + '%' + '''' 'Run on POTSQL02 - Swift Database'

END TRY
BEGIN CATCH
	IF @@TRANCOUNT <> 0
	ROLLBACK TRAN

	/*Write to log*/
	SELECT @Phase = 'CATCH: ' + ERROR_MESSAGE()
	Insert into [dbo].[appman_DWH_Standing_Order_Log]
	values
	(@TicketNo, @DateLastUpdated, @Phase, @theUser, @SwiftField, @SwiftCode, @SwiftDescription, @ReportingClassCode, @ReportingClassDescription, @Section16, @S16Type, @S16TypeDesc)

END CATCH
GO
