CREATE PROCEDURE [dbo].[mscp_AdvisersInQualitySpan] 


WITH RECOMPILE --,ENCRYPTION
  /* Param List */
AS

/******************************************************************************

Copyright (C) Moore Stephens Consulting Limited 2005

Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
          
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>

*******************************************************************************/

begin
 

declare @ReportMonth datetime
set @ReportMonth = (Select max(ReportMonth) 
      from mstt_AgentQualityAggregation
      where KPILevel = 'ADVISERKPI')
      
      
select  distinct
  ReportMonth,
  HierarchyTypeCode,
  SummaryPeriod,
  SalesQualityPSLevelCode,
  SalesQualitySQMLevelCode,
  SalesQualityRSMLevelCode,
  SalesQualityASDLevelCode,
  PracticeCode,
  AgentCode  
into #AQABaseValues
from msv_AgentQualityAggregation
where KPILevel = 'BASEVALUES'
and ReportMonth between dateadd(mm, -6, @ReportMonth) and @ReportMonth 
order by 1,2,3,4,5,6,7,8,9

--create index IX_TempAQA on #AQABaseValues (ReportMonth,HierarchyTypeCode,SummaryPeriod,SalesQualitySQMLevelCode, AgentCode)
--create index IX2_TempAQA on #AQABaseValues (ReportMonth,HierarchyTypeCode,SummaryPeriod,SalesQualityRSMLevelCode, AgentCode)
create index IX3_TempAQA on #AQABaseValues (ReportMonth)
create index IX4_TempAQA on #AQABaseValues (HierarchyTypeCode)
create index IX5_TempAQA on #AQABaseValues (SummaryPeriod)
create index IX6_TempAQA on #AQABaseValues (SalesQualitySQMLevelCode)
create index IX7_TempAQA on #AQABaseValues (AgentCode)
create index IX8_TempAQA on #AQABaseValues (SalesQualityRSMLevelCode)     


select * 
into #CurrentHierarchy
from mstt_AgentQualityHierarchy
where dateadd(mm, 1, @ReportMonth) - 1 between AgentHierarchyStartDate and AgentHierarchyEndDate

--Create a temp table to hold values
select  'CURRENT' as HierarchyTypeCode,
  6 as SummaryPeriod,
  AgentCode, 
  cast('' as varchar(255)) as Agent,
  SalesQualityPSLevelCode, 
  cast('' as varchar(255)) as PracticeSupervisor,
  SalesQualitySQMLevelCode,
  cast('' as varchar(255)) as SalesQualityManager,
  SalesQualityRSMLevelCode, 
  cast('' as varchar(255)) as RegionalSalesManager,
  SalesQualityASDLevelCode, 
  cast('' as varchar(255)) as AreaSalesDirector,
  PracticeCode,
  cast('' as varchar(255)) as Practice,
  iu.Name as DomainLogin,
  iu.AssociatedAgent as UserAgentCode
into  #QualityAdvisers  
from 
  msit_IntUsers iu,
  mstt_AgentQualityAggregation aqa
where 1=0

insert into #QualityAdvisers
--6MonthSpan
--Get Agents under an ASD
select distinct 
  'KPI' as HierarchyTypeCode,
  6 as SummaryPeriod,
  AgentCode, 
  cast('' as varchar(255)) as Agent,
  SalesQualityPSLevelCode, 
  cast('' as varchar(255)) as PracticeSupervisor,
  SalesQualitySQMLevelCode,
  cast('' as varchar(255)) as SalesQualityManager,
  SalesQualityRSMLevelCode, 
  cast('' as varchar(255)) as RegionalSalesManager,
  SalesQualityASDLevelCode, 
  cast('' as varchar(255)) as AreaSalesDirector,
  PracticeCode,
  cast('' as varchar(255)) as Practice,
  iu.Name as DomainLogin,
  iu.AssociatedAgent as UserAgentCode
from 
  msit_IntUsers iu,
  #AQABaseValues aqa
where 
  iu.AssociatedAgent = aqa.SalesQualityASDLevelCode
--AND ReportMonth between dateadd(mm, -6, @ReportMonth) and @ReportMonth 
--AND KPILevel = 'BaseValues'

exec msp_ProcessLog 'SPAN', 'AgentsUnderASD6', null, 'AQH', 'Openwork'


insert into #QualityAdvisers
--Get Agents under an RSM
select distinct 
  'KPI' as HierarchyTypeCode,
  6 as SummaryPeriod,
  AgentCode, 
  cast('' as varchar(255)) as Agent,
  SalesQualityPSLevelCode, 
  cast('' as varchar(255)) as PracticeSupervisor,
  SalesQualitySQMLevelCode,
  cast('' as varchar(255)) as SalesQualityManager,
  SalesQualityRSMLevelCode, 
  cast('' as varchar(255)) as RegionalSalesManager,
  SalesQualityASDLevelCode, 
  cast('' as varchar(255)) as AreaSalesDirector,
  PracticeCode,
  cast('' as varchar(255)) as Practice,
  iu.Name as DomainLogin,
  iu.AssociatedAgent as UserAgentCode
from 
  msit_IntUsers iu,
  #AQABaseValues aqa
where 
  iu.AssociatedAgent = aqa.SalesQualityRSMLevelCode
--AND ReportMonth between dateadd(mm, -6, @ReportMonth) and @ReportMonth 
--AND KPILevel = 'BaseValues'

exec msp_ProcessLog 'SPAN', 'AgentsUnderRSM6', null, 'AQH', 'Openwork'


insert into #QualityAdvisers
--Get Agents under an SQM (Includes ASQMs)
select distinct 
  'KPI' as HierarchyTypeCode,
  6 as SummaryPeriod,
  aqa.AgentCode, 
  cast('' as varchar(255)) as Agent,
  aqa.SalesQualityPSLevelCode, 
  cast('' as varchar(255)) as PracticeSupervisor,
  aqa.SalesQualitySQMLevelCode,
  cast('' as varchar(255)) as SalesQualityManager,
  aqa.SalesQualityRSMLevelCode, 
  cast('' as varchar(255)) as RegionalSalesManager,
  --If the Agent's ASD Level Code is null get it from other Agent records where this Agent is the SQM or RSM
  isnull(aqa.SalesQualityASDLevelCode, isnull(asd.SalesQualityASDLevelCode, asd2.SalesQualityASDLevelCode)) as SalesQualityASDLevelCode,
  cast('' as varchar(255)) as AreaSalesDirector,
  aqa.PracticeCode,
  cast('' as varchar(255)) as Practice,
  iu.Name as DomainLogin,
  iu.AssociatedAgent as UserAgentCode
from 
  msit_IntUsers iu,
  #AQABaseValues aqa 
 --Find ASQM's ASD via the SQM
  LEFT JOIN #AQABaseValues asd
    ON asd.[ReportMonth] = aqa.[ReportMonth] 
    AND asd.[HierarchyTypeCode] = aqa.[HierarchyTypeCode] 
    AND asd.[SummaryPeriod] = aqa.[SummaryPeriod]
    AND asd.[SalesQualitySQMLevelCode] = aqa.[AgentCode]
    --AND asd.[KPILevel] = aqa.[KPILevel]
 --Find ASQM's ASD via the RSM
  LEFT JOIN #AQABaseValues asd2
    ON asd2.[ReportMonth] = aqa.[ReportMonth] 
    AND asd2.[HierarchyTypeCode] = aqa.[HierarchyTypeCode] 
    AND asd2.[SummaryPeriod] = aqa.[SummaryPeriod]
    AND asd2.[SalesQualityRSMLevelCode] = aqa.[AgentCode]
    --AND asd2.[KPILevel] = aqa.[KPILevel]
where 
  iu.AssociatedAgent = aqa.SalesQualitySQMLevelCode
--AND aqa.ReportMonth between dateadd(mm, -6, @ReportMonth) and @ReportMonth 
--AND aqa.KPILevel = 'BaseValues'

exec msp_ProcessLog 'SPAN', 'AgentsUnderSQM6', null, 'AQH', 'Openwork'

insert into #QualityAdvisers
--Get Agents under an PS
select distinct 
  'KPI' as HierarchyTypeCode,
  6 as SummaryPeriod,
  AgentCode, 
  cast('' as varchar(255)) as Agent,
  SalesQualityPSLevelCode, 
  cast('' as varchar(255)) as PracticeSupervisor,
  SalesQualitySQMLevelCode,
  cast('' as varchar(255)) as SalesQualityManager,
  SalesQualityRSMLevelCode, 
  cast('' as varchar(255)) as RegionalSalesManager,
  SalesQualityASDLevelCode, 
  cast('' as varchar(255)) as AreaSalesDirector,
  PracticeCode,
  cast('' as varchar(255)) as Practice,
  iu.Name as DomainLogin,
  iu.AssociatedAgent as UserAgentCode
from 
  msit_IntUsers iu,
  #AQABaseValues aqa
where 
  iu.AssociatedAgent = aqa.SalesQualityPSLevelCode
--AND ReportMonth between dateadd(mm, -6, @ReportMonth) and @ReportMonth 
--AND KPILevel = 'BaseValues'

exec msp_ProcessLog 'SPAN', 'AgentsUnderPS6', null, 'AQH', 'Openwork'

insert into #QualityAdvisers
--Get Agents themselves
select distinct 
  'KPI' as HierarchyTypeCode,
  6 as SummaryPeriod,
  aqa.AgentCode, 
  cast('' as varchar(255)) as Agent,
  aqa.SalesQualityPSLevelCode, 
  cast('' as varchar(255)) as PracticeSupervisor,
  aqa.SalesQualitySQMLevelCode,
  cast('' as varchar(255)) as SalesQualityManager,
  aqa.SalesQualityRSMLevelCode, 
  cast('' as varchar(255)) as RegionalSalesManager,
  --If the Agent's ASD Level Code is null get it from other Agent records where this Agent is the SQM or RSM
  isnull(aqa.SalesQualityASDLevelCode, isnull(asd.SalesQualityASDLevelCode, asd2.SalesQualityASDLevelCode)) as SalesQualityASDLevelCode,
  cast('' as varchar(255)) as AreaSalesDirector,
  aqa.PracticeCode,
  cast('' as varchar(255)) as Practice,
  iu.Name as DomainLogin,
  iu.AssociatedAgent as UserAgentCode
from 
  msit_IntUsers iu,
  #AQABaseValues aqa
 --Find ASQM's ASD via the SQM
  LEFT JOIN #AQABaseValues asd
    ON asd.[ReportMonth] = aqa.[ReportMonth] 
    AND asd.[HierarchyTypeCode] = aqa.[HierarchyTypeCode] 
    AND asd.[SummaryPeriod] = aqa.[SummaryPeriod]
    AND asd.[SalesQualitySQMLevelCode] = aqa.[AgentCode]
    --AND asd.[KPILevel] = aqa.[KPILevel]
 --Find ASQM's ASD via the RSM
  LEFT JOIN #AQABaseValues asd2
    ON asd2.[ReportMonth] = aqa.[ReportMonth] 
    AND asd2.[HierarchyTypeCode] = aqa.[HierarchyTypeCode] 
    AND asd2.[SummaryPeriod] = aqa.[SummaryPeriod]
    AND asd2.[SalesQualityRSMLevelCode] = aqa.[AgentCode]
    --AND asd2.[KPILevel] = aqa.[KPILevel]
where 
  iu.AssociatedAgent = aqa.AgentCode
--AND aqa.ReportMonth between dateadd(mm, -6, @ReportMonth) and @ReportMonth 
--AND aqa.KPILevel = 'BaseValues'

exec msp_ProcessLog 'SPAN', 'Agents6', null, 'AQH', 'Openwork'

select  distinct
  HierarchyTypeCode,
  SummaryPeriod,
  SalesQualityPSLevelCode,
  SalesQualitySQMLevelCode,
  SalesQualityRSMLevelCode,
  SalesQualityASDLevelCode,
  PracticeCode,
  AgentCode  
into #AQABaseValues_OneMonth
from msv_AgentQualityAggregation
where KPILevel = 'BASEVALUES'
AND ReportMonth = @ReportMonth 
order by 1,2,3,4,5,6,7,8



--create index IX_TempAQAa on #AQABaseValues (ReportMonth,HierarchyTypeCode,SummaryPeriod,SalesQualitySQMLevelCode, AgentCode)
--create index IX2_TempAQAa on #AQABaseValues (ReportMonth,HierarchyTypeCode,SummaryPeriod,SalesQualityRSMLevelCode, AgentCode)
create index IX4_TempAQA on #AQABaseValues_OneMonth (HierarchyTypeCode)
create index IX5_TempAQA on #AQABaseValues_OneMonth (SummaryPeriod)
create index IX6_TempAQA on #AQABaseValues_OneMonth (SalesQualitySQMLevelCode)
create index IX7_TempAQA on #AQABaseValues_OneMonth (AgentCode)
create index IX8_TempAQA on #AQABaseValues_OneMonth (SalesQualityRSMLevelCode)




