/****** Object:  StoredProcedure [dbo].[mscp_CheckUserVerseFranchiseCode]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER OFF
GO



CREATE PROCEDURE [dbo].[mscp_CheckUserVerseFranchiseCode] -- WITH RECOMPILE,ENCRYPTION
@UserId NVARCHAR (50),
@Franchise NVARCHAR(7)
AS


exec msp_ProcessLog 'Start', 'mscp_CheckUserVerseFranchiseCode', null, null, 'Openwork'

DECLARE @ErrorMsg NVARCHAR(150)
SELECT @ErrorMsg = 'This user is not authorised to view the report using the parameters provided (' + @UserId + ' and ' + @Franchise + ')'


  

IF (@Franchise NOT IN (SELECT  DISTINCT a.FranchiseCode
FROM  msdt_Adviser a 
  INNER JOIN msct_UserAccessControl uac 
    ON a.AdviserID = uac.AdviserID
WHERE @UserId = uac.DomainLogin))
BEGIN
  RAISERROR ('@ErrorMsg',16, 1)
END
exec msp_ProcessLog 'End', 'mscp_CheckUserVerseFranchiseCode', null, null, 'Openwork'





