/********************************************************************************/
--PipelineAge

--ONE OFF LOAD to populate from 0 days to 1000 days

begin

print 'truncate table msdt_PipelineAge'
truncate table msdt_Pipelineage

declare @MinDay int, @MaxDay int, @DayCounter int

set @MinDay = 0
set @MaxDay = 1000

set @DayCounter = @MinDay

while @DayCounter <= @MaxDay  
  begin

  insert into msdt_Pipelineage (AgeBanding,Age)
  select 
   case 
    when @DayCounter >= 0    and @DayCounter<= 5    then '0 to 05'
    when @DayCounter >= 6    and @DayCounter<= 10   then '06 to 10'
    when @DayCounter >= 11   and @DayCounter<= 20   then '11 to 20'
    when @DayCounter >= 21   and @DayCounter<= 30   then '21 to 30'
    when @DayCounter >= 31   and @DayCounter<= 40   then '31 to 40'
    when @DayCounter >= 41   and @DayCounter<= 50   then '41 to 50'
    when @DayCounter >= 51   and @DayCounter<= 60   then '51 to 60'
    when @DayCounter >= 61   and @DayCounter<= 70   then '61 to 70'
    when @DayCounter >= 71   and @DayCounter<= 80   then '71 to 80'
    when @DayCounter >= 81   and @DayCounter<= 100  then '81 to 100'
    when @DayCounter >= 101           then 'Above 101'
   end,
   @DayCounter
   
   set @DayCounter = @DayCounter + 1
  
  end -- while @DayCounter <= @MaxDay 



--Force a record for Unknown with -99 id

SET IDENTITY_INSERT msdt_PipelineAge ON

