print 'truncating table msdt_FranchiseSize'
truncate table msdt_FranchiseSize

declare @MinSize int, @MaxSize int, @SizeCounter int

set @MinSize = 0
set @MaxSize = 1000

set @SizeCounter = @MinSize

while @SizeCounter <= @MaxSize  
  begin

  insert into msdt_FranchiseSize (FranchiseSizeType,FranchiseSize)
  select 
   case 
    when @SizeCounter <= 1              then 'Sole Trader' --0 for franchise who GivesAdvice = 'N' and 1 for franchise who GivesAdvice = 'Y'
    when @SizeCounter >= 2    and @SizeCounter<= 9    then 'Small (2-9)'
    when @SizeCounter >= 10             then 'Large (10+)'   
   end,
   @SizeCounter
   
   set @SizeCounter = @SizeCounter + 1
  
  end 

 


