CREATE PROCEDURE [dbo].[mscp_NSRefreshCurrentData]

AS

DECLARE @MonthlyDateTime DATETIME
DECLARE @MidMonthlyDateTime DATETIME

SELECT @MonthlyDateTime = (SELECT MAX(MONTH) FROM msct_FeesNonSwiftAccessControl WHERE NOT ListPosition IN (55,60))
SELECT @MidMonthlyDateTime = (SELECT MAX(MONTH) FROM msct_FeesNonSwiftAccessControl WHERE ListPosition = 55)



/*If the data in the main table is more up to date than the current tables or the current tables are empty*/
IF((@MonthlyDateTime > (SELECT TOP 1 MONTH FROM msit_FeesPreSwiftCurrentListing WHERE NOT ListPosition = 55)) 
  OR (@MidMonthlyDateTime > (SELECT TOP 1 MONTH FROM msit_FeesPreSwiftCurrentListing WHERE ListPosition = 55))
  OR ((SELECT COUNT(*) FROM msit_FeesPreSwiftCurrentListing) < 1))
  BEGIN
    /*Dropping tables means that any column type changes are propagated up to the
    derivation tables - important as the same proceedures will run against either table*/
    DROP TABLE msit_FeesPreSwiftCurrentListing
    DROP TABLE msit_FeesZanCurrentListing
    
    --Import PreSwift Data
    SELECT 
      SWIFTFranchise,
      SWIFTSeller,
      OpenworkInd,
      SellerPrefix,
      SellerSerial,
      SellerSuffix,
      SellerID,
      SellerName,
      FranchisePrefix,
      FranchiseSerial,
      FranchiseSuffix,
      FranchiseID,
      ClientForename,
      ClientSurname,
      Client,
      ApplicationDate,
      DeclarationDate,
      StartDate,
      RunDate,
      OrigBranch,
      PolicySerial,
      Member,
      ProductCode,
      Policy,
      Provider,
      SequenceNo,
      SliceNo,
      AgentSplit,
      Premium,
      Frequency,
      IncreaseInd,
      FlexInd,
      InitialPeriod,
      CommRateStd,
      CommRateTrue,
      NPWInd,
      ITInd,
      CommType,
      CommBasis,
      CommBasisDesc,
      EnhancementRate,
      EnhancementAccr,
      StillLeftToAccrue,
      ITAdvance,
      ITAccrued,
      ITLiability,
      UpliftFeeAccr,
      UpliftFeeIT ,
      Value1,
      Value2,
      Value3,
      Value4,
      Value5,
      Value6,
      RemarksString,
      ProdFactor,
      ProdCred,
      PayBasis,
      TotalFees,
      IssuedInd,
      CommEnh,
      TotBaseCommStd,
      TotBaseCommTrue,
      CommNotEnhanced ,
      UpliftRate,
      UpliftAccr,
      UpliftIT,
      FileID,
      ListPosition,
      DateLoaded,
      Month  INTO msit_FeesPreSwiftCurrentListing
    FROM msit_FeesNonSwiftFeeListing WHERE ((Month = @MonthlyDateTime AND NOT ListPosition = 55) OR (Month = @MidMonthlyDateTime AND ListPosition = 55)) AND OpenworkInd = 'Y'
      
      --Import Zan Data
    SELECT 
      SWIFTFranchise,
      SWIFTSeller,
      OpenworkInd,
      SellerPrefix,
      SellerSerial,
      SellerSuffix,
      SellerID,
      SellerName,
      FranchisePrefix,
      FranchiseSerial,
      FranchiseSuffix,
      FranchiseID,
      ClientForename,
      ClientSurname,
      Client,
      ApplicationDate,
      DeclarationDate,
      StartDate,
      RunDate,
      OrigBranch,
      PolicySerial,
      Member,
      ProductCode,
      Policy,
      Provider,
      SequenceNo,
      SliceNo,
      AgentSplit,
      Premium,
      Frequency,
      IncreaseInd,
      FlexInd,
      InitialPeriod,
      CommRateStd,
      CommRateTrue,
      NPWInd,
      ITInd,
      CommType,
      CommBasis,
      CommBasisDesc,
      EnhancementRate,
      EnhancementAccr,
      StillLeftToAccrue,
      ITAdvance,
      ITAccrued,
      ITLiability,
      UpliftFeeAccr,
      UpliftFeeIT ,
      Value1,
      Value2,
      Value3,
      Value4,
      Value5,
      Value6,
      RemarksString,
      ProdFactor,
      ProdCred,
      PayBasis,
      TotalFees,
      IssuedInd,
      CommEnh,
      TotBaseCommStd,
      TotBaseCommTrue,
      CommNotEnhanced ,
      UpliftRate,
      UpliftAccr,
      UpliftIT,
      FileID,
      ListPosition,
      DateLoaded,
      Month INTO msit_FeesZanCurrentListing
     FROM msit_FeesNonSwiftFeeListing WHERE ((Month = @MonthlyDateTime AND NOT ListPosition = 55) OR (Month = @MidMonthlyDateTime AND ListPosition = 55)) AND (OpenworkInd = 'N' OR OpenworkInd IS NULL)
      
  EXEC mspr_NSApplyCurrentIndexes

  END


GO
