CREATE procedure [dbo].[mscp_NSRefreshNonSwiftUserAccessControl]
as

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : mspr_DefComStaPayFra.sql
-- Owner   : ghope@bi
-- Created : 10/04/2006
--
--########################################################################
--
--Amendment History
--
--Date    Who     Description
--11/04/08  A Groves  Commented out "select * from msit_Feesnonswiftrenewallisting"
--            as it seems to serve no purpose except waste time.
--
--########################################################################

truncate table msct_FeesNonSwiftAccessControl

IF EXISTS (SELECT * FROM sysindexes WHERE [Name] = 'IX_msct_FeesNonSwiftAccessControl_1')
 DROP  INDEX [dbo].[msct_FeesNonSwiftAccessControl].[IX_msct_FeesNonSwiftAccessControl_1] 


--DECLARE @Franchises TABLE(Code varchar(7)COLLATE latin1_General_CI_AS,DomainName varchar(50) COLLATE latin1_General_CI_AS)

--INSERT INTO @Franchises
--SELECT  DISTINCT a.FranchiseCode,
--  uac.DomainLogin
--FROM  msdt_Adviser a 
  --INNER JOIN msct_UserAccessControl uac 
  --  ON a.AdviserID = uac.AdviserID

INSERT msct_Feesnonswiftaccesscontrol
select distinct 
CASE WHEN mstt_Agents.TradingName IS NULL THEN RTRIM(mstt_Agents.DESCN) ELSE RTRIM(mstt_Agents.TradingName)  END AS FranchiseName,
mstt_Agents.CODE AS Code,
CASE WHEN mstt_Agents.OSCARDateStarted IS NULL THEN GETDATE()ELSE mstt_Agents.OSCARDateStarted END AS DateStarted,
CASE WHEN mstt_Agents.OSCARAgentSerial IS NULL THEN 'No Oscar Code Available' ELSE mstt_Agents.OSCARAgentPrefix +  mstt_Agents.OSCARAgentSerial + mstt_Agents.OSCARAgentSuffix END AS AgentCode,
sf.[Month],
sf.SellerPrefix + sf.SellerSerial + SellerSuffix + '-' + SellerName As Seller,
sf.SellerID AS SellerID,
sf.OpenworkInd,
sf.ListPosition
FROM         dbo.msit_FeesNonSWIFTFeeListing sf INNER JOIN
dbo.mstt_Agents   ON dbo.mstt_Agents.CODE = sf.SWIFTFranchise
                      
INSERT msct_Feesnonswiftaccesscontrol
select distinct 
CASE WHEN mstt_Agents.TradingName IS NULL THEN RTRIM(mstt_Agents.DESCN) ELSE RTRIM(mstt_Agents.TradingName)  END AS FranchiseName,
mstt_Agents.CODE AS Code,
CASE WHEN mstt_Agents.OSCARDateStarted IS NULL THEN GETDATE()ELSE mstt_Agents.OSCARDateStarted END AS DateStarted,
CASE WHEN mstt_Agents.OSCARAgentSerial IS NULL THEN 'No Oscar Code Available' ELSE mstt_Agents.OSCARAgentPrefix +  mstt_Agents.OSCARAgentSerial + mstt_Agents.OSCARAgentSuffix END AS AgentCode,
f.[Month],
f.SellerPrefix + f.SellerSerial + f.SellerSuffix + '-' + SellerName As Seller,f.SellerID AS SellerID,
f.OpenworkInd,
60
FROM         dbo.msit_FeesNonSWIFTRenewalListing f INNER JOIN
dbo.mstt_Agents   ON dbo.mstt_Agents.CODE = f.SWIFTFranchise

--select * from msit_Feesnonswiftrenewallisting
                      
IF NOT EXISTS (SELECT * FROM sysindexes WHERE [Name] = 'IX_msct_FeesNonSwiftAccessControl_1')
 CREATE  CLUSTERED INDEX [IX_msct_FeesNonSwiftAccessControl_1] ON [dbo].[msct_FeesNonSwiftAccessControl]([CODE],[ListPosition],[Month])   WITH FILLFACTOR = 100 ON [PRIMARY]

UPDATE STATISTICS msct_FeesNonSwiftAccessControl
GO
/****** Object:  StoredProcedure [dbo].[mscp_ReportFailedJobStep]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[mscp_ReportFailedJobStep] (@JobName nvarchar(500))-- WITH RECOMPILE,ENCRYPTION
  /* Param List */
AS
/******************************************************************************
Copyright (C) Moore Stephens Consulting Limited 2005
Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>
*******************************************************************************/
-- PROCEDURE BODY GOES HERE
begin
declare FailureInfo cursor for
select top 1 sjh.Step_Name, sjh.Message 
from msdb.dbo.sysjobhistory sjh, msdb.dbo.sysjobs sj
where sjh.job_id = sj.job_id
and sj.name = @JobName
and sjh.step_id <> 0
and sjh.run_status = 0
order by sjh.run_date desc, sjh.run_time desc
declare @FailedStep nvarchar(500)
declare @FailureMessage nvarchar(2000)
open FailureInfo
fetch next from FailureInfo into @FailedStep, @FailureMessage
declare @EventLogMessage nvarchar(2000)
set @EventLogMessage =  'The Job: "'+@JobName+'" has failed. ' + 
      'The failed step was: "'+@FailedStep+'" ' +
      case when @FailureMessage is not null then 
      'and the reported error was "'+@FailureMessage+'"'
      else '' end
while @@Fetch_Status = 0
begin
  exec master.dbo.xp_logevent 55100, @EventLogMessage, ERROR
  fetch next from FailureInfo into @FailedStep, @FailureMessage
end
close FailureInfo
deallocate FailureInfo
end

GO
/****** Object:  StoredProcedure [dbo].[mscp_UAC_Recruits]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[mscp_UAC_Recruits] -- WITH RECOMPILE,ENCRYPTION
  /* Param List */
AS
/******************************************************************************
Summary : mscp_UAC_Recruits

Date    By      Description
----    --      -----------
02/07/2010  Mike Cawood Move msct_UAC_Recruit processing from 
            zz_mscp_SetUpTestUser.

*******************************************************************************/
-- PROCEDURE BODY GOES HERE
begin

  select 'openwork\'+iu.name as LoginName,
    a.code as SwiftCode,
    a.Descn as SwiftName,
    a.AgentType,
    a.AgentTypeDescription,
    a.AgentCategory,
    a.AgentCategoryDescription
  into #Users
  from msit_IntUsers iu
    inner join mstt_Agents a
      on iu.AssociatedAgent = a.Code
  where iu.name is not null
  and nullif(iu.associatedagent, ' ') is not null
  order by AgentType, AgentCategory
  --Gets all the Practice Principal/Agent combos
  select u.LoginName, 
    u.SwiftCode       as UserSwiftCode, 
    u.SwiftName       as UserSwiftName,
    u.AgentType       as UserAgentType,
    u.AgentTypeDescription    as UserAgentTypeDescription,
    u.AgentCategory     as UserAgentCategory,
    u.AgentCategoryDescription  as UserAgentCategoryDescription,
    a.RecruitCode       as SellerSwiftCode,
    a.RecruitName       as SellerName,
    a.RecruitId     as AdviserId
  into #LoginsExploded
  from mstt_Agents ag
    inner join #Users u
      on u.SwiftCode = ag.Code
    inner join mstt_Agents ag_Business
      on Coalesce(ag.FranchiseCode, 
        ag.OfficeCode, 
        ag.DirectlyAuthorisedCode, 
        ag.StrategicAllianceCode, 
        ag.AccessAgentCode) = ag_Business.Code
    inner join msdt_Recruits a
      on ag_Business.Code = a.FranchiseCode
  where ag.AgentType = '43'
  union all
  --Gets all the Practice Principal/Agent combos (For Targets)
  select u.LoginName, 
    u.SwiftCode       as UserSwiftCode, 
    u.SwiftName       as UserSwiftName,
    u.AgentType       as UserAgentType,
    u.AgentTypeDescription    as UserAgentTypeDescription,
    u.AgentCategory     as UserAgentCategory,
    u.AgentCategoryDescription  as UserAgentCategoryDescription,
    a.AgentCode       as SellerSwiftCode,
    a.Adviser       as SellerName,
    a.AdviserId
  from mstt_Agents ag
    inner join #Users u
      on u.SwiftCode = ag.Code
    inner join mstt_Agents ag_Business
      on Coalesce(ag.FranchiseCode, 
        ag.OfficeCode, 
        ag.DirectlyAuthorisedCode, 
        ag.StrategicAllianceCode, 
        ag.AccessAgentCode) = ag_Business.Code
    inner join msdt_AdviserDummies a
      on ag_Business.Code = a.FranchiseCode
  where a.IsCurrent = 1
  and ag.AgentType = '43'
  union all 
  --Gets all the Franchise/Agent combos
  select u.LoginName, 
    u.SwiftCode       as UserSwiftCode, 
    u.SwiftName       as UserSwiftName,
    u.AgentType       as UserAgentType,
    u.AgentTypeDescription    as UserAgentTypeDescription,
    u.AgentCategory     as UserAgentCategory,
    u.AgentCategoryDescription  as UserAgentCategoryDescription,
    a.RecruitCode       as SellerSwiftCode,
    a.RecruitName       as SellerName,
    a.RecruitId     as AdviserId
  from msdt_Recruits a
    inner join #Users u
      on u.SwiftCode = a.FranchiseCode
  union all
  --Gets all the Franchise/Agent combos (For targets)
  select u.LoginName, 
    u.SwiftCode       as UserSwiftCode, 
    u.SwiftName       as UserSwiftName,
    u.AgentType       as UserAgentType,
    u.AgentTypeDescription    as UserAgentTypeDescription,
    u.AgentCategory     as UserAgentCategory,
    u.AgentCategoryDescription  as UserAgentCategoryDescription,
    a.AgentCode       as SellerSwiftCode,
    a.Adviser       as SellerName,
    a.AdviserId
  from msdt_AdviserDummies a
    inner join #Users u
      on u.SwiftCode = a.FranchiseCode
  where a.IsCurrent = 1
  union all 
  --Gets all the RSM/Agent combos
  select u.LoginName, 
    u.SwiftCode       as UserSwiftCode, 
    u.SwiftName       as UserSwiftName,
