CREATE PROCEDURE [dbo].[mscp_UserAccessControl] -- WITH RECOMPILE,ENCRYPTION
  /* Param List */
AS

/******************************************************************************

Copyright (C) Moore Stephens Consulting Limited 2005

Summary : mscp_UserAccessControl

Date    By        Description
----    --        -----------
02/07/2010  Mike Cawood   Move msct_UserAccessControl processing from 
              zz_mscp_SetUpTestUser.


*******************************************************************************/

begin

  select 'OPENWORK\'+iu.name as LoginName,
    a.code as SwiftCode,
    a.Descn as SwiftName,
    a.AgentType,
    a.AgentTypeDescription,
    a.AgentCategory,
    a.AgentCategoryDescription
  into #Users
  from msit_IntUsers iu
    inner join mstt_Agents a
      on iu.AssociatedAgent = a.Code
  where iu.name is not null
  and nullif(iu.associatedagent, ' ') is not null
  order by AgentType, AgentCategory


  --Gets all the Practice Principal/Agent combos
  select u.LoginName, 
    u.SwiftCode       as UserSwiftCode, 
    u.SwiftName       as UserSwiftName,
    u.AgentType       as UserAgentType,
    u.AgentTypeDescription    as UserAgentTypeDescription,
    u.AgentCategory     as UserAgentCategory,
    u.AgentCategoryDescription  as UserAgentCategoryDescription,
    a.AgentCode       as SellerSwiftCode,
    a.Adviser       as SellerName,
    a.AdviserId
  
  into #LoginsExploded
  from mstt_Agents ag
    inner join #Users u
      on u.SwiftCode = ag.Code
    inner join mstt_Agents ag_Business
      on Coalesce(ag.FranchiseCode, 
        ag.OfficeCode, 
        ag.DirectlyAuthorisedCode, 
        ag.StrategicAllianceCode, 
        ag.AccessAgentCode) = ag_Business.Code
    inner join msdt_Adviser a
      on ag_Business.Code = a.FranchiseCode
      
  where --a.IsCurrent = 1
  --and 
  ag.AgentType = '43'
  
  union all
  
  --Gets all the Practice Principal/Agent combos (For Targets)
  select u.LoginName, 
    u.SwiftCode       as UserSwiftCode, 
    u.SwiftName       as UserSwiftName,
    u.AgentType       as UserAgentType,
    u.AgentTypeDescription    as UserAgentTypeDescription,
    u.AgentCategory     as UserAgentCategory,
    u.AgentCategoryDescription  as UserAgentCategoryDescription,
    a.AgentCode       as SellerSwiftCode,
    a.Adviser       as SellerName,
    a.AdviserId
  
  from mstt_Agents ag
    inner join #Users u
      on u.SwiftCode = ag.Code
    inner join mstt_Agents ag_Business
      on Coalesce(ag.FranchiseCode, 
        ag.OfficeCode, 
        ag.DirectlyAuthorisedCode, 
        ag.StrategicAllianceCode, 
        ag.AccessAgentCode) = ag_Business.Code
    inner join msdt_AdviserDummies a
      on ag_Business.Code = a.FranchiseCode
      
  where --a.IsCurrent = 1
  --and 
  ag.AgentType = '43'
  
  union all
  
  --Gets all the Franchise/Agent combos
  select u.LoginName, 
    u.SwiftCode       as UserSwiftCode, 
    u.SwiftName       as UserSwiftName,
    u.AgentType       as UserAgentType,
    u.AgentTypeDescription    as UserAgentTypeDescription,
    u.AgentCategory     as UserAgentCategory,
    u.AgentCategoryDescription  as UserAgentCategoryDescription,
    a.AgentCode       as SellerSwiftCode,
    a.Adviser       as SellerName,
    a.AdviserId
  
  from msdt_Adviser a
    inner join #Users u
      on u.SwiftCode = a.FranchiseCode
  --where a.IsCurrent = 1
  
  union all
  
  --Gets all the Franchise/Agent combos (For targets)
  select u.LoginName, 
    u.SwiftCode       as UserSwiftCode, 
    u.SwiftName       as UserSwiftName,
    u.AgentType       as UserAgentType,
    u.AgentTypeDescription    as UserAgentTypeDescription,
    u.AgentCategory     as UserAgentCategory,
    u.AgentCategoryDescription  as UserAgentCategoryDescription,
    a.AgentCode       as SellerSwiftCode,
    a.Adviser       as SellerName,
    a.AdviserId

  from msdt_AdviserDummies a
    inner join #Users u
      on u.SwiftCode = a.FranchiseCode
  --where a.IsCurrent = 1
  
  union all 
  
  --Gets all the RSM/Agent combos
  select u.LoginName, 
    u.SwiftCode       as UserSwiftCode, 
    u.SwiftName       as UserSwiftName,
    u.AgentType       as UserAgentType,
    u.AgentTypeDescription    as UserAgentTypeDescription,
    u.AgentCategory     as UserAgentCategory,
    u.AgentCategoryDescription  as UserAgentCategoryDescription,
    a.AgentCode       as SellerSwiftCode,
    a.Adviser       as SellerName,
    a.AdviserId
  from msdt_Adviser a
    inner join #Users u
      on u.SwiftCode = a.RegionalSalesManagerCode
  --where a.IsCurrent = 1


  union all 
  
  --Gets all the RSM/Agent combos (For targets)
  select u.LoginName, 
    u.SwiftCode       as UserSwiftCode, 
    u.SwiftName       as UserSwiftName,
    u.AgentType       as UserAgentType,
    u.AgentTypeDescription    as UserAgentTypeDescription,
    u.AgentCategory     as UserAgentCategory,
    u.AgentCategoryDescription  as UserAgentCategoryDescription,
    a.AgentCode       as SellerSwiftCode,
    a.Adviser       as SellerName,
    a.AdviserId
  from msdt_AdviserDummies a
    inner join #Users u
      on u.SwiftCode = a.RegionalSalesManagerCode
  --where a.IsCurrent = 1
  
  union all 
  
  --Gets all the ASD/Agent combos
  select u.LoginName, 
    u.SwiftCode       as UserSwiftCode, 
    u.SwiftName       as UserSwiftName,
    u.AgentType       as UserAgentType,
    u.AgentTypeDescription    as UserAgentTypeDescription,
    u.AgentCategory     as UserAgentCategory,
    u.AgentCategoryDescription  as UserAgentCategoryDescription,
    a.AgentCode       as SellerSwiftCode,
    a.Adviser       as SellerName,
    a.AdviserId
  from msdt_Adviser a
    inner join #Users u
      on u.SwiftCode = a.AreaSalesManagerCode
  --where a.IsCurrent = 1
  
    union all 
  
  --Gets all the ASD/Agent combos (For Targets)
  select u.LoginName, 
    u.SwiftCode       as UserSwiftCode, 
    u.SwiftName       as UserSwiftName,
    u.AgentType       as UserAgentType,
    u.AgentTypeDescription    as UserAgentTypeDescription,
    u.AgentCategory     as UserAgentCategory,
    u.AgentCategoryDescription  as UserAgentCategoryDescription,
    a.AgentCode       as SellerSwiftCode,
    a.Adviser       as SellerName,
    a.AdviserId
  from msdt_AdviserDummies a
    inner join #Users u
      on u.SwiftCode = a.AreaSalesManagerCode
  --where a.IsCurrent = 1
  
    union all 
  
  --Gets all the SQM/Agent combos
--  select u.LoginName, 
--    u.SwiftCode       as UserSwiftCode, 
--    u.SwiftName       as UserSwiftName,
--    u.AgentType       as UserAgentType,
--    u.AgentTypeDescription    as UserAgentTypeDescription,
--    u.AgentCategory     as UserAgentCategory,
--    u.AgentCategoryDescription  as UserAgentCategoryDescription,
--    a.AgentCode       as SellerSwiftCode,
--    a.Adviser       as SellerName,
--    a.AdviserId
--  from msdt_Adviser a
--    inner join #Users u
--      on u.SwiftCode = a.SalesQualityManagerCode
--  where a.IsCurrent = 1
--  
--  
--    union all
    
  --Get the PFAs themselves
  select u.LoginName, 
    u.SwiftCode       as UserSwiftCode, 
    u.SwiftName       as UserSwiftName,
    u.AgentType       as UserAgentType,
    u.AgentTypeDescription    as UserAgentTypeDescription,
    u.AgentCategory     as UserAgentCategory,
    u.AgentCategoryDescription  as UserAgentCategoryDescription,
    a.AgentCode       as SellerSwiftCode,
    a.Adviser       as SellerName,
    a.AdviserId
  from msdt_Adviser a
    inner join #Users u
      on u.SwiftCode = a.AgentCode
  --where a.IsCurrent = 1 
  order by 1,2,3
  
  truncate table msct_UserAccessControl
  
  insert into msct_UserAccessControl
  select distinct AdviserId, LoginName
  from #LoginsExploded
    
  --get the surrogates
  insert into msct_UserAccessControl (AdviserId, DomainLogin)
  select distinct uac.AdviserId, us.DomainLogin
  from msct_UserSurrogates us
    inner join msct_UserAccessControl uac
      on us.SurrogateOf = uac.DomainLogin
  where not exists (select 'x' 
      from msct_UserAccessControl uac1
      where uac.AdviserId = uac1.AdviserId
      and us.DomainLogin = uac1.DomainLogin)      
  order by 2,1
    
  drop table #LoginsExploded
  drop table #Users

-- START of Processing moved from zz_mscp_SetUpTestUsers    MPC 02/07/2010

declare @Domain varchar(50) 
set @Domain = 'OPENWORK'

select distinct sub.AdviserId, sub.DomainLogin
into #UserAdviserList
from 
(select distinct a.AdviserId, @Domain+'\mitest'+q.Num as DomainLogin
from msdt_Adviser a, 
  (select '1' as Num union 
  select '9' as Num union 
  select '10' as Num union 
  select '11' as Num union 
  select '12' as Num union 
  select '13' as Num union 
  select '14' as Num union
  select '17' as Num union
  select '27' as Num union
  select '28' as Num union
--  select '29' as Num union
  select '30' as Num union
  select '31' as Num union
  select '32' as Num union
  select '33' as Num ) q
union all
select distinct AdviserId, @Domain+'\mitest'+q.Num as DomainLogin
from msdt_AdviserDummies a, 
  (select '1' as Num union 
  select '9' as Num union 
  select '10' as Num union 
  select '11' as Num union 
  select '12' as Num union 
  select '13' as Num union 
  select '14' as Num union
  select '17' as Num union
  select '27' as Num union
  select '28' as Num union
--  select '29' as Num union
  select '30' as Num union
  select '31' as Num union
  select '32' as Num union
  select '33' as Num) q  ) sub
  
insert into #UserAdviserList
select distinct AdviserID, hou.DomainLogin as DomainLogin
from  msdt_Adviser a, msct_HeadOfficeUsers hou
union all
select distinct AdviserID, hou.DomainLogin as DomainLogin
from  msdt_AdviserDummies a, msct_HeadOfficeUsers hou

insert into msct_UserAccessControl (AdviserId, DomainLogin)
select distinct u.AdviserId, u.DomainLogin
from #UserAdviserList u
where not exists (select 'x' from msct_UserAccessControl uac
      where uac.AdviserId = u.AdviserId
      and uac.DomainLogin = u.DomainLogin)
      
drop table #UserAdviserList

-- END of Processing moved from zz_mscp_SetUpTestUsers    MPC 02/07/2010

End



GO
/****** Object:  StoredProcedure [dbo].[msep_DataChangeControl]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[msep_DataChangeControl]
 @Client   nvarchar(50),
 @Name     nvarchar(255),
 @TempName nvarchar(255)
--WITH RECOMPILE, ENCRYPTION

AS

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2005 All rights reserved 
-- 
-- Object      : stored procedure
-- Name        : msep_DataChangeControl.sql
-- Description : Script to generate msep_DataChangeControl
-- Author      : Ermedin Selmanovic
-- Created     : 01/04/2005
-- 
--########################################################################
--
-- $Id:  $
-- $Log: $
--
--########################################################################

declare @ProcedureName nvarchar(255)
set @ProcedureName = object_name(@@procid)
exec msp_ProcessLog 'START', @ProcedureName, null, @Client

declare @String           nvarchar(4000),
        @Error            int,
        @ReturnValue      bit, 
        @Process          nvarchar(100),
        @ErrorDescription nvarchar(255)

set @Error = 0

declare DataChangeCursor cursor
for
select 
 [Database],
 [Table],
 [Column],
 [ChangeFrom],
 [ChangeTo]
from
 mst_DataChangeConfiguration
where
 [Client] = @Client and
 [Table]  = @Name   and
 [Active] = 1
order by
 [Client],
 [ExecuteSequence]
for read only

declare
 @Database   nvarchar(50),
 @Table      nvarchar(255),
 @Column     nvarchar(255),
 @ChangeFrom nvarchar(10),
 @ChangeTo   nvarchar(10)
 
open 
 DataChangeCursor
fetch
 DataChangeCursor
into
 @Database,
 @Table,
 @Column,
 @ChangeFrom,
 @ChangeTo

while @@fetch_status = 0

 begin

  set @Process = 'Updating ' + @TempName + '.' + @Column
  exec msp_ProcessLog 'START', @Process, null, @Client

  if object_id(@TempName) is NOT NULL
   begin
   

    set @String  = ' update ' + @TempName + ' set ' + @Column + 
                   ' = replace (' + @Column + ', char(' + @ChangeFrom + '),char(' + @ChangeTo + ')) ' +
                   'where charindex(char(' + @ChangeFrom + '), ' + @Column + ') > 0'

    exec (@String)
    
--    select @String
    
    exec msp_ProcessLog 'END', @Process, null, @Client
    
   end --  if object_id(@Name) is NOT NULL
  else --  if object_id(@Name) is NOT NULL
   begin
     set @Error = @Error + 1
     set @Process = 'Temp Table ' + @TempName + ' does not exists, please check!'
     exec msp_ProcessLog 'ERROR', @Process, null, @Client
   end --  if object_id(@Name) is NOT NULL

 fetch
  DataChangeCursor
 into
  @Database,
  @Table,
  @Column,
  @ChangeFrom,
  @ChangeTo

 end

close DataChangeCursor
deallocate DataChangeCursor

exec msp_ProcessLog 'END', @ProcedureName, null, @Client


GO
/****** Object:  StoredProcedure [dbo].[msip_DataWhseOpenAccessPart1]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

/****************************************************************************
     Program:   msip_DataWhseOpenAccessPart1          
    Author: A Groves
Date created: 21/09/2009              
                      
 Description:   This procedure has been created from msip_DataWhseOpenAccess to 
        logically group together all OpenAccess modules to enable 
        this process to slot between:

        1) msip_DataWhsePrimaryTransformationPart2
        2) msip_DataWhseSecondaryTransformation

        The purpose of this work is to minimise the modules in Primary
        to enable this OpenAccess module to complete ASAP. OA is then 
        made available to the field while the Secondary module runs.

      It is called as follows:

      exec msip_DataWhseOpenAccessPart1 'Openwork', 'OpenAccess'

                  
  Amendment History               
  -----------------               
                      
  Date			Who			Description       
  ----			---			-----------     
  21/09/2009	A Groves	msip_DataWhseOpenAccess split into:
							1) msip_DataWhseOpenAccessPart1
							2) msip_DataWhseOpenAccessPart2
							This has been done to reduce execution time of 
							each transformation step to facilitate batch 
							step retries.
  02/02/2010	A Groves	Added @Client & @Module parameters to msp_CommissionStatement.
  21/04/2010	A Groves	Added parameter @Mode and passed into msp_CommissionStatement to
							control whether it updates incrementally or via a full refresh.
  02/07/2010	M Cawood	Remove msp_BACSDate. Now run in SecondaryTransformationPart1.
  01/04/2014	A Groves	Added @Client & @Module parameters to omsp_OMSCommissionPayments
							to ensure consistent logging details on table mst_ProcessLog.
  03/04/2020	C Mellors	Removed OMS Swift and OMS Payments data processing
****************************************************************************/
CREATE    PROCEDURE [dbo].[msip_DataWhseOpenAccessPart1]  
  @Client     varchar(50),
  @Module     varchar(50),
  @Mode     varchar(4)
AS

declare @PhaseStart   varchar(50) = 'START',
    @PhaseEnd   varchar(50) = 'END',
    @Process    varchar(100),
    @MainProcess  varchar(100) = @Module + 'Procedure'

exec msp_ProcessLog @PhaseStart, @MainProcess, null, @Module, @Client

set @Process = 'msp_CommissionStatement' 
exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client
exec dbo.msp_CommissionStatement @Client, @Module, @Mode    -- AG 21/04/2010
exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

set @Process = 'msp_OpenworkBankDetailsSwift' 
exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client
exec dbo.msp_OpenworkBankDetailsSwift
exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

exec msp_ProcessLog @PhaseEnd, @MainProcess, null, @Module, @Client
GO
/****** Object:  StoredProcedure [dbo].[msip_DataWhseOpenAccessPart2]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/****************************************************************************
     Program:   msip_DataWhseOpenAccessPart2          
    Author: A Groves
Date created: 21/09/2009              
                      
 Description:   This procedure has been created from msip_DataWhseOpenAccess to 
        logically group together all OpenAccess modules to enable 
        this process to slot between:

        1) msip_DataWhsePrimaryTransformationPart2
        2) msip_DataWhseSecondaryTransformation

        The purpose of this work is to minimise the modules in Primary
        to enable this OpenAccess module to complete ASAP. OA is then 
        made available to the field while the Secondary module runs.

      It is called as follows:

      exec msip_DataWhseOpenAccessPart2 'Openwork', 'OpenAccess', 'MOVE'
        or
      exec msip_DataWhseOpenAccessPart2 'Openwork', 'OpenAccess', 'FULL'
                  
  Amendment History               
  -----------------               
                      
  Date		Who			Description       
  ----		---			-----------     
  21/09/09  A Groves	msip_DataWhseOpenAccess split into:
						1) msip_DataWhseOpenAccessPart1
						2) msip_DataWhseOpenAccessPart2
						This has been done to reduce execution time of 
						each transformation step to facilitate batch 
						step retries.
21/04/2010  A Groves	Introduced @Mode parameter and passed it into
						msp_OpenworkAdviserListingSwift to enable it to
						update either incrementally or via full refresh.
12/03/2013	A Groves	The following rule change was agreed with PSD
						(Debbie Burchell and Tyrone Hamilton) SR 211450
						to the Pipeline Report:
						1)	Include all suspense items from a payment created 
							date of 01/01/2008 up to the present. This date to 
							be maintained in Config to allow it to be tweaked 
							at any time in the future.
						2)	Include any suspended payments where the payment 
							date is within the last 6 months (older suspended 
							payments will therefore drop off the pipeline). 
							Again, this 6 months period can be defined as 180 
							days in Config.
						3)	Exclude from the Pipeline any payments that have 
							been matched.
****************************************************************************/
CREATE    PROCEDURE [dbo].[msip_DataWhseOpenAccessPart2]  
  @Client     varchar(50),
  @Module     varchar(50),
  @Mode     varchar(4)
AS

