--Build/Rebuild the current "Quality Month's" Quality hierarchy - before Policies.
declare @AQHMonth datetime
declare @CurrentMonth datetime
set @CurrentMonth = (select DATEADD(mm, DATEDIFF(mm,0,getdate()), 0))
set @AQHMonth = (select max(ReportMonth) from mstt_AgentQualityAggregation) 


set @Process        = 'mstp_AgentQualityHierarchy_Daily'
exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client
exec mstp_AgentQualityHierarchy_Daily @AQHMonth
exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client


if @CurrentMonth > @AQHMonth
--This typically means that we are in the early stages of a new month, and the quality data is 
--still being checked before having the aggregations run. If we are in this stage, then we
--need to run the AQH process for the current month, so that Policies can be marked with the
--correct quaity hierarchy.
begin
set @Process        = 'mstp_AgentQualityHierarchy_Daily'
exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client
exec mstp_AgentQualityHierarchy_Daily @CurrentMonth
exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client
end


