CREATE PROCEDURE [dbo].[msp_Adviser_Prod] -- WITH RECOMPILE,ENCRYPTION
  @UserId nvarchar(50),
  @Franchise nvarchar(50)
AS

/******************************************************************************

Copyright (C) Moore Stephens Consulting Limited 2005

Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
          
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>

*******************************************************************************/

select distinct
a.AdviserId [value],
left(rtrim(a.Adviser),45) [label],
'1' [orderby]
from
msdt_Adviser a

  INNER JOIN msct_UserAccessControl uac 
    ON a.AdviserID = uac.AdviserID
WHERE uac.DomainLogin = @UserId
and left(rtrim(Franchise),45) = isnull(nullif(@Franchise,'%'), left(rtrim(Franchise),45))


order by 
orderby, label asc




