CREATE procedure [dbo].[msp_AdviserDetails]
 @ASQMCode        nvarchar(50),
 @ASDCode         nvarchar(50),
 @COB             nvarchar(50),
 @UserId          nvarchar(50),
 @AllowDelegates  char(1)

as

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : msp_AdviserDetails.sql
-- Desc    : 
-- Owner   : KS
-- Created : 03/08/2006
-- Amended : 14/08/2006 - MK - Added further security, to ensure that the 
--                             user executing the report is allowed to see
--                             the agent that has been passed in to the proc.
-- Amended : 16/08/2006 - MK - Add function to allow delegate access. That is, allow a user
--                             to impersonate the user to whom they have been given access.
-- Amended : 22/08/2006 - KS - Counts for above SAQ or CQ benchmark should not include when above both.
--
-- Amended : 07/07/2009 - MPC: Replace *= ANSI JOINS as these not allowed in SQL Server 2005
--
--########################################################################


-- declare  @ASDCode     nvarchar(50),
--          @ASQMCode    nvarchar(50),
--          @COB         nvarchar(50)
-- set      @ASDCode = '1003494'
-- set      @ASQMCode = '-1'
-- set      @COB = 'COB'

if isnull(@AllowDelegates, 'N') = 'Y'
  set @UserId = (select dbo.msf_SQGetUserDelegatedFrom(@UserId))

if (dbo.msf_SQCheckPermissions (@UserId, @ASDCode, 'ASD', 'KPI', 6) = 'DENY' 
      and
    dbo.msf_SQCheckPermissions (@UserId, @ASQMCode, 'SQM', 'KPI', 6) = 'DENY')

  select null as [ASDCode],
    null as [COB],
    null as [COBDesc],
    null as [AgentCount],
    null as [COBCount],
    null as [ICOB_GICount],
    null as [ICOB_PPCount],
    null as [MCOBCount],
    null as [Advisers with SAQ rate above benchmark],
    null as [Advisers with CQ rate above benchmark],
    null as [Advisers above both benchmarks],
    null as [Advisers below both benchmarks],
    null as [ReportMonth]
    
else    

begin

select 
 SalesQualityASDLevelCode as [ASDCode],
 ComplianceCategoryCode as [COB],
 ComplianceCategoryCode as [COBDesc],
 AgentCode as [AgentCount],
 cast(SuitableAdviceFailures as Float) as [SAQ],
 cast(CompletionFailures as Float) as [CQ],
 cast(SuitableAdviceFailures as Float) as [SABenchmark],
 cast(CompletionFailures as Float) as [CQBenchmark],
 --CasesAssessed,
 SuitableAdviceFailures as [SAAboveCount],
 CompletionFailures as [CQAboveCount],
 SuitableAdviceFailures as [BothAboveCount],
 CompletionFailures as [BothBelowCount],
 ReportMonth as [ReportMonth]
into
 #AdviserDetails
from 
 msv_AgentQualityAggregation
where 1=2



insert into  
 #AdviserDetails
select distinct
 [ASDCode] = a.SalesQualityASDLevelCode,
 [COB] = a.ComplianceCategoryCode,
 [COBDesc] = b.CategoryOfBusiness,
 [AgentCount] = a.AgentCode,
 [SAQ] = case when a.CasesAssessed = 0 then 0 else (a.SuitableAdviceFailures / cast(a.CasesAssessed as Float)) * 100 end,
 [CQ] = case when a.CasesAssessed = 0 then 0 else (a.CompletionFailures / cast(a.CasesAssessed as Float)) * 100 end,
 [SABenchmark] = 0,
 [CQBenchmark] = 0,
 --CasesAssessed = a.CasesAssessed,
 [SAAboveCount] = 0,
 [CQAboveCount] = 0,
 [BothAboveCount] = 0,
 [BothBelowCount] = 0,
 [ReportMonth] = a.ReportMonth
from
 msv_AgentQualityAggregation a                    --MPC: 07/07/2009
 inner join msv_CategoryOfBusiness b                --MPC: 07/07/2009
  on a.[ComplianceCategoryCode] = b.[ComplianceCategoryCode]    --MPC: 07/07/2009
where
-- a.[ComplianceCategoryCode] *= b.[ComplianceCategoryCode] and   --MPC: 07/07/2009
 a.kpilevel = 'basevalues' and
 a.reportmonth = (select max(reportmonth)
                  from msv_AgentQualityAggregation
                  where KPILevel = 'ADVISERKPI') and
 a.summaryperiod = 1 and
 (@ASDCode = a.SalesQualityASDLevelCode OR @ASQMCode = a.SalesQualitySQMLevelCode)


update #AdviserDetails
set
 [SABenchmark] = c.TargetValue
from
 #AdviserDetails a 
 inner join msit_QualityTargets c on a.COB = c.ComplianceCategoryCode
where
 c.QualityTargetTypeCode = 'Benchmark' and
 c.QualityTargetPurposeCode = 'SA' and
 c.TargetValueTypeCode = 'P' and
 c.AgentType = 'All'  -- update to include correct agent type


update #AdviserDetails
set
 [CQBenchmark] = c.TargetValue
from
 #AdviserDetails a 
 inner join msit_QualityTargets c on a.COB = c.ComplianceCategoryCode
where
 c.QualityTargetTypeCode = 'Benchmark' and
 c.QualityTargetPurposeCode = 'CQ' and
 c.TargetValueTypeCode = 'P' and
 c.AgentType = 'All'  -- update to include correct agent type


update #AdviserDetails
set
 [SAAboveCount] = case when SAQ > SABenchmark then 1 else 0 end
from 
 #AdviserDetails


update #AdviserDetails
set
 [CQAboveCount] = case when CQ > CQBenchmark then 1 else 0 end
from 
 #AdviserDetails



update #AdviserDetails
set
 [BothAboveCount] = case when (SAQ > SABenchmark and CQ > CQBenchmark) then 1 else 0 end
from 
 #AdviserDetails


update #AdviserDetails
set
 [BothBelowCount] = case when (SAQ < SABenchmark and CQ < CQBenchmark) then 1 else 0 end
from 
 #AdviserDetails




select 
 [ASDCode] as [ASDCode],
 [COB] as [COB],
 [COBDesc] as [COBDesc],
 count (distinct AgentCount) as [AgentCount],
 count(distinct case when (COB = 'COB'         and (SAQ + CQ) > 0) then AgentCount end) as [COBCount],
 count(distinct case when (COB = 'ICOB-GI'     and (SAQ + CQ) > 0) then AgentCount end) as [ICOB_GICount],
 count(distinct case when (COB = 'ICOB-PP'     and (SAQ + CQ) > 0) then AgentCount end) as [ICOB_PPCount],
 count(distinct case when (COB = 'MCOB'        and (SAQ + CQ) > 0) then AgentCount end) as [MCOBCount],
 count (distinct case when (SAAboveCount > 0   and (SAQ) > 0 and CQAboveCount = 0) then AgentCount end) as [Advisers with SAQ rate above benchmark],
 count (distinct case when (CQAboveCount > 0   and (CQ) > 0 and SAAboveCount = 0)  then AgentCount end) as [Advisers with CQ rate above benchmark],
 count (distinct case when (BothAboveCount > 0 and (SAQ + CQ) > 0) then AgentCount end) as [Advisers above both benchmarks],
 count (distinct case when (BothBelowCount > 0 and (SAQ + CQ) > 0) then AgentCount end) as [Advisers below both benchmarks],
 [ReportMonth] as [ReportMonth]
from
 #AdviserDetails
where
 @COB = COB
group by
 ASDCode,
 COB,
 COBDesc,
 ReportMonth

 
drop table #AdviserDetails

end




GO
