CREATE procedure [dbo].[msp_AdviserListingEnquiry]
@FranchiseCode nvarchar(10),
@AdviserCode nvarchar (10),
@PeriodType nvarchar(7),
@Period1 datetime,
@Period2 datetime
with recompile--, encryption
as

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : msp_AdviserListingEnquiry.sql
-- Desc    : Retrieve minimum and maximum date from fact table
-- Owner   : CTT
-- Created : 
--
--########################################################################

select
 a.[Franchise Name],
 a.[Franchise Code],
 a.[Provider],
 a.[Adviser_Code],
 a.[Adviser_Name],
 convert(nvarchar(10),a.[Payment_Date],103) [Payment_Date],
 convert(nvarchar(10),a.[BACS_Date],103) [BACS_Date],
 a.[Client_Name],
 a.[Policy_Number],
 a.[Product_Type],
 convert(nvarchar(10),a.[Start_Date],103) [Start_Date],
 a.[Frequency],
 sum(a.[Annual_Premium]) [Annual_Premium],
 a.[Commission_Rate],
 a.[Initial_Period],
 sum(a.[VEE_Issued]) [VEE_Issued],
 sum(a.[VEE_Accrued]) [VEE_Accrued],
 sum(a.[VEE_Still_To_Accrue]) [VEE_Still_To_Accrue],
 sum(a.[VEE_IT_Fees]) [VEE_IT_Fees],
 a.[Enhanced_Rate],
 sum(a.[VIE_Accrued]) [VIE_Accrued],
 sum(a.[VIE_Still_To_Accrue]) [VIE_Still_To_Accrue],
 sum(a.[VIE_IT_Comm]) [VIE_IT_Comm],
 sum(a.[VIE_Clawback_Reserve]) [VIE_Clawback_Reserve],
 sum(a.[VIE_Total]) [VIE_Total],
 a.[AI_Payment_Basis],
 sum(a.[AI_Commission_Sacrifice]) [AI_Commission_Sacrifice],
 a.[AI_Split_%],
 a.[AI_Fee_Type],
 a.[AI_Reason]
from
 mst_CommissionStatement a
where
 a.[Franchise Code] = @FranchiseCode and
 a.[Adviser_Code] like @AdviserCode and
 case when @PeriodType = 'BACS' then a.BACS_Date else a.Payment_Date end between @Period1 and @Period2
group by
 a.[Franchise Name],
 a.[Franchise Code],
 a.[Provider],
 a.[Adviser_Code],
 a.[Adviser_Name],
 convert(nvarchar(10),a.[Payment_Date],103),
 convert(nvarchar(10),a.[BACS_Date],103),
 a.[Client_Name],
 a.[Policy_Number],
 a.[Product_Type],
 convert(nvarchar(10),a.[Start_Date],103),
 a.[Frequency],
 a.[Commission_Rate],
 a.[Initial_Period],
 a.[Enhanced_Rate],
 a.[AI_Payment_Basis],
 a.[AI_Split_%],
 a.[AI_Fee_Type],
 a.[AI_Reason]
 order by
 a.[Franchise Name],
 a.[Adviser_Name],
 a.[Provider],
 convert(nvarchar(10),a.[Payment_Date],103)

GO
/****** Object:  StoredProcedure [dbo].[msp_AdviserSelFranchiseByRsm]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
