GO
CREATE PROCEDURE [dbo].[msp_AdviserSelFranchiseByRsm] -- WITH RECOMPILE,ENCRYPTION
  @RsmCode VARCHAR (255),
  @Year INT
AS
/******************************************************************************
Copyright (C) Moore Stephens Consulting Limited 2005
Summary : %Summary%
Author  : Isaac Abraham
Created : 8th September 2005
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>Isaac Abraham</author>
  <revision>
    <dateCreated>20/12/2005</dateCreated>
    <author>Isaac Abraham</author>
    <summary>
      - No longer use the DateStarted field as the start date to calculate the YTD turnover when year = date started.
      - Use both msdt_adviser and msdt_adviserdummies to get the COMPLETE list of available franchises!
    </summary>
  </revision>
</doc>
*******************************************************************************/
DECLARE @DaysToYearEnd INT
SET @DaysToYearEnd = 365 - DATEPART (dayofyear, GETDATE())
SELECT
  adv.FranchiseCode,
  adv.Franchise,
  sz.FranchiseSizeType AS [Size],
  age.CompetentStatusDescription as Status,
  DateStarted AS AppointedDate,
  age.FranchiseSize AS LiveSellerCount,
-- See change above 20/12/2005
--  CASE @Year
--    WHEN DATEPART (YEAR, DateStarted) THEN dbo.fnFranchiseTurnover (adv.FranchiseCode, DateStarted) -- If the date started = @year, pass in the date started as the from date
--    ELSE dbo.fnFranchiseTurnover (adv.FranchiseCode, (SELECT CAST (@Year AS varchar(4))'-01-01' ))  -- otherwise just pass in 1/1/@year
--  END AS YtdTurnover
  dbo.fnFranchiseTurnover (adv.FranchiseCode, (SELECT CAST (@Year AS varchar(4))'-01-01' )) AS YtdTurnover
-- Commented out this next statement - is now calculated within the application
--  CASE @Year
--    WHEN DATEPART (YEAR, DateStarted) THEN (CAST (dbo.fnFranchiseTurnover (adv.FranchiseCode, DateStarted) AS FLOAT) / DATEDIFF (day, DateStarted, GETDATE()) * DATEDIFF (day, DateStarted, CAST (@Year AS VARCHAR (4))+'-12-31'))
--    -- This chunky statement above calculates the projected turnover by calculating the turnover from the start of the current year until today, and then calculating what the final amount will be as a proportion of that.
--    ELSE dbo.fnFranchiseTurnover (adv.FranchiseCode, (SELECT CAST (@Year AS varchar(4))'-01-01' ))  -- If the date started = @year, pass in the date started as the from date
--  END AS ProjectTurnover
FROM
  (SELECT FranchiseCode, Franchise, RegionalSalesManagerCode, IsCurrent FROM msdt_adviser UNION SELECT FranchiseCode, Franchise, RegionalSalesManagerCode, IsCurrent FROM msdt_adviserdummies) adv
JOIN
  mstt_agents age on age.Code = adv.FranchiseCode
JOIN
  msdt_FranchiseSize sz on sz.FranchiseSize = age.FranchiseSize
WHERE
  RegionalSalesManagerCode=@RsmCode
  AND IsCurrent = 1
GROUP BY
  adv.FranchiseCode,
  adv.Franchise,
  sz.FranchiseSizeType,
  age.CompetentStatusDescription,
  DateStarted,
  age.FranchiseSize
ORDER BY
  Franchise

GO
