CREATE PROCEDURE [dbo].[msp_AgentDetailsReport] -- WITH RECOMPILE,ENCRYPTION
 
--@UserId nvarchar(50)
    
AS


/******************************************************************************

Copyright (C) Moore Stephens Consulting Limited 2005

Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
          
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>

/*******************************************************************************/
--
-- Amendment Log
--
-- Date:    7 July 2009
-- Amended By:  Mike Cawood
-- Reason:    Replace =* and *= ANSI JOINS as these not allowed in SQL Server 2005

*******************************************************************************/

truncate table mst_AgentDetails

insert into  mst_AgentDetails (
  [Agent UID],
  ValidFrom,
  AgentStatus,
  [Date Started],
  [Oscar Date Started],
  [Oscar Prefix],
  [Oscar Serial],
  [Oscar Suffix],
  [Forename],
  [Surname],
  [Portal Code],
  [FSA Reg No],
  [Agent Category],
  [Agent Type],
  [Can Sell],
  [Specialist Code],
  [Mobile Number],
  [Office Email],
  [Office Website],
  [Office Phone],
  [Office Fax],
  [Office Adressee],
  [Office Address1],
  [Office Address2],
  [Office Address3],
  [Office Address4],
  [Office Address5],
  [Office Postcode],
  [Office Country],
  [Home Address1],
  [Home Address2],
  [Home Address3],
  [Home Address4],
  [Home Address5],
  [Home Postcode],
  [Firm],
  [Business UID],
  [F_Oscar Prefix],
  [F_Oscar Serial],
  [F_Oscar Suffix],
  [Business Name],
  [Competition Name],
  [Size],
  [SQMCode],
  [SQM],
  [RSMCode],
  [RSM],
  [ASDCode],
  [ASD],
  [FSA No],
  [F_Address1],
  [F_Address2],
  [F_Address3],
  [F_Address4],
  [F_Address5],
  [F_Postcode],
  [F_Phone No],
  [F_Fax No],
  [F_Email],
  [F_Website]
)
select DISTINCT         --MPC: 07/07/2009
  a.code 'Agent UID',
  a.ValidFromDate,
  (case when a.CompetentStatus = 1 then 'Active' when a.CompetentStatus = 5 then 'Pre-App' else 'In-Active' end),
  a.datestarted 'Date Started',
  a.oscardatestarted 'Oscar Date Started',
  a.oscaragentprefix 'Oscar Prefix',
  a.oscaragentserial 'Oscar Serial',
  a.oscaragentsuffix 'Oscar Suffix',
  ISNULL(RTRIM(SUBSTRING(a.FirstNames, 1, PATINDEX('%[^ ] %',a.FirstNames + ' '))) + ' ', '') 'Forename',
  a.name 'Surname',
  a.portallogon 'Portal Code',
  a.licencenumber 'FSA Reg No',
  a.agentcategorydescription 'Agent Category',
  a.agenttypedescription 'Agent Type',
  cast('' as nvarchar(50))  'Cas Sell', --a.givesadvice 'Can Sell',
  cast('' as nvarchar(50)) 'Specialist Code',
  c.tel_mobile 'Mobile Number',
  a.email 'Office Email',
  a.website 'Office Website',
  a.telephone 'Office Phone',
  a.fax_number 'Office Fax',
  a.addressee'Office Adressee',
  a.address1 'Office Address1',
  a.address2 'Office Address2',
  a.address3 'Office Address3',
  a.address4 'Office Address4',
  a.address5 'Office Address5',
  a.postcode 'Office Postcode',
  a.country 'Office Country',
  c.address1 'Home Address1',
  c.address2 'Home Address2',
  c.address3 'Home Address3',
  c.address4 'Home Address4',
  c.address5 'Home Address5',
  c.postcode 'Home Postcode',
  a.firm 'Firm',
  cast('' as nvarchar(50)) 'Business UID',
  cast('' as nvarchar(255)) 'F_Oscar Prefix',
  cast('' as nvarchar(255)) 'F_Oscar Serial',
  cast('' as nvarchar(255)) 'F_Oscar Suffix',
  cast('' as nvarchar(500)) 'Business Name',
  cast('' as nvarchar(500)) 'Competition Name',
  cast('' as nvarchar(50)) 'Size',
  cast('' as nvarchar(500)) 'SQMCode',
  cast('' as nvarchar(500)) 'SQM',
  cast('' as nvarchar(500)) 'RSMCode',
  cast('' as nvarchar(500)) 'RSM',
  cast('' as nvarchar(500)) 'ASDCode',
  cast('' as nvarchar(500)) 'ASD',
  cast('' as nvarchar(50)) 'FSA No',
  cast('' as nvarchar(500)) 'F_Address1',
  cast('' as nvarchar(500)) 'F_Address2',
  cast('' as nvarchar(500)) 'F_Address3',
  cast('' as nvarchar(500)) 'F_Address4',
  cast('' as nvarchar(500)) 'F_Address5',
  cast('' as nvarchar(500)) 'F_Postcode',
  cast('' as nvarchar(255)) 'F_Phone No',
  cast('' as nvarchar(255)) 'F_Fax No',
  cast('' as nvarchar(500)) 'F_Email',
  cast('' as nvarchar(500)) 'F_Website'
from
  mstt_agentshistory a --,          --MPC: 07/07/2009
  left outer join msdt_Adviser ad     --MPC: 07/07/2009
   on a.Code = ad.AgentCode       --MPC: 07/07/2009
  left outer join mstt_clients c--,     --MPC: 07/07/2009
  on c.refer = a.code           --MPC: 07/07/2009
  --msct_UserAccessControl uac
where
  --a.Code = ad.AgentCode and       --MPC: 07/07/2009
  --ad.AdviserId = uac.AdviserId and
  --uac.DomainLogin = @UserId and
  --c.refer =* a.code and         --MPC: 07/07/2009
  --a.competentstatus = '1' and
  a.agenttypegrouping <> '1' and
  a.firm is not NULL and 
  a.firm <> '' and
  a.firm <> '10002'



declare AgentCodeCursor cursor for
select
 distinct AgentCode
from
 mstt_agentsector


for read only

declare 
 @AgentCode       varchar(20),
 @SpecialistCode  varchar(1000),
 @SpecialistCode2 varchar(1000),
 @SpecialistCodeID varchar(50),
 @SpecialistCodeID2 varchar(50),
 @Priority tinyint 

open 
 AgentCodeCursor
fetch 
 AgentCodeCursor
into 
 @AgentCode 

while @@fetch_status = 0
begin
 set  @SpecialistCode  = ''
 set  @SpecialistCode2 = ''
 set  @SpecialistCodeID  = ''
 set  @SpecialistCodeID2 = ''

--********
 declare SpecialistCodeCursor cursor for
 select
  distinct [SpecialistCodeID] = asec.CodeClusterSectorID, [Specialist Code] = asec.clustersectordescription, Priority = asec.Priority
 from
  mst_AgentDetails ad,
  mstt_agentsector asec,
  mstt_agentshistory a
 where
  a.active = '1' and
  a.agenttypegrouping <> '1' and
  a.firm not in ('NULL', '', '10002') and
  asec.agentcode = @AgentCode and
  ad.[Agent UID] = a.code and
  asec.agentcode = a.code and
  asec.startdate is not NULL and
  asec.startdate <= dateadd(dd,-1,getdate()) and 
  (asec.enddate is null or asec.enddate > dateadd(dd,-1,getdate())) and
  asec.priority = (select min(priority) from 
                                    mstt_agentsector asec2
                                   where
                                    asec2.agentcode = a.code and
         /*asec2.startdate is not NULL and
          asec2.startdate <= dateadd(dd,-1,getdate()) and */
         (asec2.enddate is null or asec2.enddate > dateadd(dd,-1,getdate())))
  order by [Specialist Code]       
  for read only

 open 
  SpecialistCodeCursor
 fetch 
  SpecialistCodeCursor
 into 
  @SpecialistCodeID, @SpecialistCode, @Priority 
 while @@fetch_status = 0
 begin
  set  @SpecialistCode2 = @SpecialistCode2 + ', ' + @SpecialistCode 
  set @SpecialistCodeID2 = @SpecialistCodeID2 + ', ' + @SpecialistCodeID

 fetch 
  SpecialistCodeCursor
 into 
  @SpecialistCodeID, @SpecialistCode, @Priority 
  
 end

update mst_agentdetails
set [SpecialistCodeID] = case when @SpecialistCodeID2 = '' then @SpecialistCodeID2 else right(@SpecialistCodeID2, len(@SpecialistCodeID2)-2) end, 
[Specialist Code] = case when @SpecialistCode2 = '' then @SpecialistCode2 else right(@SpecialistCode2, len(@SpecialistCode2)-2) end,
Priority = @Priority
where [Agent UID] = @AgentCode



 CLOSE SpecialistCodeCursor
 DEALLOCATE SpecialistCodeCursor

--********

fetch 
 AgentCodeCursor
into 
 @AgentCode 

end

CLOSE AgentCodeCursor
DEALLOCATE AgentCodeCursor

 Update mst_AgentDetails
set [Specialist Code] = case when [Specialist Code] = 'Financial Planner, Investment Planner, Retirement Planner' then 'Financial, Investment and Retirement Planner'
when [Specialist Code] = 'Financial Planner, Investment Planner' then 'Financial and Investment Planner'
when [Specialist Code] = 'Financial Planner, Retirement Planner' then 'Financial and Retirement Planner'
when [Specialist Code] = 'Investment Planner, Retirement Planner'  then 'Investment and Retirement Planner'
when [Specialist Code] = 'General Insurance UKPL, Protection Adviser' then 'General Insurance UKPL and Protection Adviser'
when [Specialist Code] = 'General Insurance PaymentShield, Protection Adviser' then 'General Insurance Payment Shield and Protection Adviser'
else [Specialist Code] end

Update mst_AgentDetails
set [GI Provider] = (case when Priority = '4' and SpecialistCodeID = '1' then 'UKPL'
when Priority = '4' and SpecialistCodeID = '2' then 'PaymentShield' else '' end) 

Update mst_AgentDetails
set
ZurichNew = AgencyNumberID
from mstt_AgentAgencyNumbers 
where [Agent UID] = AgentCode
and ProductProviderCode = 'ZURICH NEW'

Update mst_AgentDetails
set
ZurichLegacy = AgencyNumberID
from mstt_AgentAgencyNumbers 
where [Agent UID] = AgentCode
and ProductProviderCode = 'ZURICH LEG'

Update mst_AgentDetails
set
UKPL = AgencyNumberID
from mstt_AgentAgencyNumbers 
where [Agent UID] = AgentCode
and ProductProviderCode = 'UKPL'

Update mst_AgentDetails
set
PaymentShield = AgencyNumberID
from mstt_AgentAgencyNumbers 
where [Agent UID] = AgentCode
and ProductProviderCode = 'PYMTSHLD'

Update mst_AgentDetails
set
SIML = AgencyNumberID
from mstt_AgentAgencyNumbers 
where [Agent UID] = AgentCode
and ProductProviderCode = 'SIML'

Update mst_AgentDetails
set
ScotEq = AgencyNumberID
from mstt_AgentAgencyNumbers 
where [Agent UID] = AgentCode
and ProductProviderCode = 'SCOT EQ'

Update mst_AgentDetails
set
ScotEqLegacy = AgencyNumberID
from mstt_AgentAgencyNumbers 
where [Agent UID] = AgentCode
and ProductProviderCode = 'SCOT EQ LEG'

Update mst_AgentDetails
set
Sterling = AgencyNumberID
from mstt_AgentAgencyNumbers 
where [Agent UID] = AgentCode
and ProductProviderCode = 'STERLING'

update 
  mst_AgentDetails
set
  [Specialist Code] = 'No Current Licence Details'  
from 
  mst_AgentDetails
where
  [Specialist Code] = ''


update
  mst_AgentDetails
set
  [Can Sell] = 'N'
from 
  mst_AgentDetails
where
  [Specialist Code] = 'No Current Licence Details'


update 
  mst_AgentDetails
set
  [Can Sell] = 'Y'
from 
  mst_AgentDetails
where
  [Specialist Code] <> 'No Current Licence Details'



update 
  mst_AgentDetails
set
  [Business UID] = a.code,
  [F_ValidFrom] = a.ValidFromDate,
  [BusinessStatus] = (case when a.CompetentStatus = 1 then 'Active' when a.CompetentStatus = 5 then 'Pre-App' else 'In-Active' end),
  [F_Oscar Prefix] = a.OscarAgentPrefix,
  [F_Oscar Serial] = a.OscarAgentSerial,
  [F_Oscar Suffix] = a.OscarAgentSuffix,
  [BusinessType] = a.AgentTypeDescription,
  [Business Name] = case when a.TradingName = '' or a.TradingName is null then a.descn else a.tradingname end,
  [Competition Name] = CompetitionName,
  [Size] = a.franchisesize,
  [SQMCode] = Manager1Code,
  [RSMCode] = a.Manager2Code,
  [FSA No] = a.LicenceNumber,
  [F_Address1] = a.address1,
  [F_Address2] = a.address2,
  [F_Address3] = a.address3,
  [F_Address4] = a.address4,
  [F_Address5] = a.address5,
  [F_Postcode] = a.postcode,
  [F_Phone No] = a.telephone,
  [F_Fax No] = a.fax_number,
  [F_Email] = a.email,
  [F_Website] = a.website
from 
  mstt_agentshistory a,
  mst_AgentDetails b
where
  b.firm = a.code


update 
  mst_AgentDetails
set
  [SQM] = a.descn
from
  mstt_agentshistory a,
  mst_AgentDetails b
where
  b.SQMCode = a.code


update 
  mst_AgentDetails
set
  [ASDCode] = a.Manager4Code,
  [RSM] = a.descn
from
  mstt_agentshistory a,
  mst_AgentDetails b
where
  b.RSMCode = a.code


update 
  mst_AgentDetails
set
  [ASD] = a.descn
from
  mstt_agentshistory a,
  mst_AgentDetails b
where
  b.ASDCode = a.code





GO
