CREATE PROCEDURE [dbo].[msp_AgentStatus_AgentDetails] -- WITH RECOMPILE,ENCRYPTION
  @UserId nvarchar(50)
AS

/******************************************************************************

Copyright (C) Moore Stephens Consulting Limited 2005

Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
          
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>

*******************************************************************************/


declare @AgentStatus table (OrderBy int, Value varchar(255), Label varchar(255))

insert into @AgentStatus (OrderBy, Value, Label)

select distinct
 1 as OrderBy,
 [AgentStatus] [value],
 [AgentStatus] [label]
from
 msdt_Adviser a, 
 mst_AgentDetails d,
 msct_UserAccessControl uac
where 
  a.AgentCode = d.[Agent UID]
  and a.AdviserId = uac.AdviserId
  and uac.DomainLogin = @UserId

declare @StrippedUser varchar(50)
set @StrippedUser = case when charindex('\', @UserId) = 0 then @UserId
      else substring(@UserId, charindex('\', @UserId)+1, len(@UserId))
      end

declare @UserAgentType int
set @UserAgentType = (select a.AgentType 
      from mstt_Agents a, msit_IntUsers i
      where i.AssociatedAgent = a.Code
      and i.Name = @StrippedUser)

if @UserAgentType is null or @UserAgentType = '55'

  insert into @AgentStatus (OrderBy, Value, Label)
  select
  0 as OrderBy,
  '%' [value],
  'All' [label]

--Finally, select the required list
select  Value,
  Label
from @AgentStatus
order by OrderBy, Label




GO
/****** Object:  StoredProcedure [dbo].[msp_AgentType]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
create procedure [dbo].[msp_AgentType]
as
--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
--
--########################################################################
declare @AgentType nvarchar(50)
declare @UserId nvarchar(50)
--set @UserId = 'BI\mkennedy'
declare @StrippedUser varchar(50)
set @StrippedUser = case when charindex('\', @UserId) = 0 then @UserId
      else substring(@UserId, charindex('\', @UserId)+1, len(@UserId))
      end
set @AgentType = (
select
a.agenttype
from
msit_intusers i,
mstt_agents a
where
i.associatedagent = a.code and
i.name = @StrippedUser)
if
@AgentType is null
Select 'All' else
select
case when a.agenttype = 4 then 'Adviser'
     when a.agenttype = 2 then 'Franchise'
     when a.agenttype = 55 then 'ASM'
     when a.agenttype = 53 then 'RSM'
     when a.agenttype = 49 then 'Franchise'
     when a.agenttype = 51 then 'Franchise'
     when a.agenttype = 3 then 'Adviser'
     when a.agenttype = 52 then 'SQM'
     when a.agenttype = 43 then 'Franchise'
     when a.agenttype = 54 then 'SQM'
     when a.agenttype = 46 then 'Franchise'
end [AgentType]
from
msit_intusers i,
mstt_agents a
where
i.associatedagent = a.code and
i.name = @StrippedUser

GO
