declare @UserAgentType int
set @UserAgentType = (select a.AgentType 
      from mstt_Agents a, msit_IntUsers i
      where i.AssociatedAgent = a.Code
      and i.Name = @StrippedUser)

if @UserAgentType is null

  insert into @AreaManagerList (OrderBy, Value, Label)
  select
  0 as OrderBy,
  '%' [value],
  'All' [label]

--Finally, select the required list
select  Value,
  Label
from @AreaManagerList
order by OrderBy, Label


GO
/****** Object:  StoredProcedure [dbo].[msp_ASD_KeyTriggers]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

create procedure [dbo].[msp_ASD_KeyTriggers]

 @ManagerCode     nvarchar(50),
 @UserId          nvarchar(50),
 @AllowDelegates  char(1)

as

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : msp_ASD_KeyTriggers.sql
-- Desc    : 
-- Owner   : MK
-- Created : 01/09/2006

--########################################################################


  if isnull(@AllowDelegates, 'N') = 'Y'
    set @UserId = (select dbo.msf_SQGetUserDelegatedFrom(@UserId))
  
  
  if dbo.msf_SQCheckPermissions (@UserId, @ManagerCode, 'ASD', 'CURRENT', 1) = 'DENY' 

    SELECT 
      null as Title,
      null as COB_Figure,
      null as MCOB_Figure,
      null as ICOBPP_Figure,
      null as ICOBGI_Figure
  else
  
  begin
  
  -- Local Variables
  DECLARE @ReportMonth AS DATETIME

  

  --Get Report Month
  SELECT @ReportMonth=MAX(ReportMonth) 
  FROM mstt_AgentQualityAggregation
  WHERE KPILevel= 'ADVISERKPI'
  
  declare @LastDayOfReportMonth datetime
  set @LastDayOfReportMonth  = dateAdd(mm, 1, @ReportMonth) - 1

  --Extract Agent Over BenchMarks or on Monitor
  SELECT  1 as OrderBy,
    'Number of Advisers who have had a policy rejected this month (itemised below)' as Title,
    count(distinct case when AQA.ComplianceCategoryCode = 'COB' then aqa.AgentCode else null end) as COB_Figure,
    count(distinct case when AQA.ComplianceCategoryCode = 'MCOB' then aqa.AgentCode else null end) as MCOB_Figure,
    count(distinct case when AQA.ComplianceCategoryCode = 'ICOB-PP' then aqa.AgentCode else null end) as ICOBPP_Figure,
    count(distinct case when AQA.ComplianceCategoryCode = 'ICOB-GI' then aqa.AgentCode else null end) as ICOBGI_Figure
  INTO  
    #Triggers
  FROM
  msv_AgentQualityAggregation AQA 
      INNER JOIN mstt_AgentQualityHierarchy AQH 
        ON AQA.AgentCode = AQH.AgentCode
    inner join msv_AgentQualityCases aqc ON AQA.AgentCode = aqc.SellerAgentCode
    inner join mstt_CaseCheck cc ON cc.TrackGroupId = aqc.TrackGroupId 
  WHERE
    aqa.ReportMonth = @ReportMonth
    and (aqa.Rejects > 0)
    and aqa.KPILevel = 'AdviserKPI'
    and aqa.SummaryPeriod = 1
    AND aqh.SalesQualityASDLevelCode = @ManagerCode 
    AND NBCCFinalStatus = 'Rejected'

  UNION ALL

  SELECT  2 as OrderBy,
    'Number of Advisers who have had a justified complaint this month' as Title,
    count(distinct case when AQA.ComplianceCategoryCode = 'COB' then aqa.AgentCode else null end) as COB_Figure,
    count(distinct case when AQA.ComplianceCategoryCode = 'MCOB' then aqa.AgentCode else null end) as MCOB_Figure,
    count(distinct case when AQA.ComplianceCategoryCode = 'ICOB-PP' then aqa.AgentCode else null end) as ICOBPP_Figure,
    count(distinct case when AQA.ComplianceCategoryCode = 'ICOB-GI' then aqa.AgentCode else null end) as ICOBGI_Figure
  FROM
  msv_AgentQualityAggregation AQA 
      INNER JOIN mstt_AgentQualityHierarchy AQH 
        ON AQA.AgentCode = AQH.AgentCode
    inner join msv_AgentQualityCases aqc ON AQA.AgentCode = aqc.SellerAgentCode
    inner join mstt_CaseCheck cc ON cc.TrackGroupId = aqc.TrackGroupId 
  WHERE
    aqa.ReportMonth = @ReportMonth
    and (aqa.ComplaintQty <> 0)
    and aqa.KPILevel = 'AdviserKPI'
    and aqa.SummaryPeriod = 1
    AND aqh.SalesQualityASDLevelCode = @ManagerCode 
    

    
  if (select count(*) from #Triggers) = 0
  
    SELECT 
      null as Title,
      null as COB_Figure,
      null as MCOB_Figure,
      null as ICOBPP_Figure,
      null as ICOBGI_Figure
    
  else
  
    SELECT 
      Title,
      COB_Figure,
      MCOB_Figure,
      ICOBPP_Figure,
      ICOBGI_Figure
    FROM  
      #Triggers
    
    drop table #Triggers
    
  end






GO
