create procedure [dbo].[msp_ASD_KeyTriggers_Reject]

 @ManagerCode      nvarchar(50),
 @UserId           nvarchar(50),
 @AllowDelegates   char(1),
 @NumberOfMonths INT

as

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : msp_ASD_KeyTriggers_Reject.sql
-- Desc    : 
-- Owner   : KS
-- Created : 25/07/2006
-- Amended : 14/08/2006 - MK - Added further security, to ensure that the 
--                             user executing the report is allowed to see
--                             the agent that has been passed in to the proc.
-- Amended : 16/08/2006 - MK - Add function to allow delegate access. That is, allow a user
--                             to impersonate the user to whom they have been given access.
-- Amended : 23/08/2006 - JL - Missing the KPILevel<>Corp on the Reportdates
-- Amended : 31/08/2006 - MK - Changed the restriction on AgentQualityHierarchy so that it does not
--                             use IsCurrent, rather finds the entry for the last day of the 
--                             focus month.
-- Amended : 31/08/2006 - MK - Ensured a blank line is returned if no entries are found
--
--########################################################################


  if isnull(@AllowDelegates, 'N') = 'Y'
    set @UserId = (select dbo.msf_SQGetUserDelegatedFrom(@UserId))
  
  if dbo.msf_SQCheckPermissions (@UserId, @ManagerCode, 'ASD', 'CURRENT', 1) = 'DENY' 
  
    SELECT 
    null as Code,
    null AS AgentName, 
    --null as Rejects,
    null AS SQMCode, 
    null as SQMName,
    null as RSMCode, 
    null as RSMName,
    null as ASDCode, 
    null as ASDName,
    null as ProductName
  else
  
  begin

    -- Local Variables
    DECLARE @ReportMonth AS DATETIME
    

    --Get Report Month
    SELECT @ReportMonth=MAX(ReportMonth) 
    FROM mstt_AgentQualityAggregation
    WHERE KPILevel= 'ADVISERKPI'


    declare @LastDayOfReportMonth datetime
    set @LastDayOfReportMonth  = dateAdd(mm, 1, @ReportMonth) - 1
      --set @NumberOfMonths = 1
  
    --Extract Agent Over BenchMarks or on Monitor
    SELECT DISTINCT 
      AQC.SellerAgentCode as Code,
      AQC.SellerName AS AgentName, 
      --AQA.Rejects,
      ISNULL(AQC.SQMAgentCode, 'N/A')AS SQMCode, 
      ISNULL(AQC.SQMName, 'N/A') AS SQMName,
      ISNULL(AQC.RSMAgentCode, 'N/A')AS RSMCode, 
      ISNULL(AQC.RSMName, 'N/A') AS RSMName,
      ISNULL(AQC.ASDAgentCode, 'N/A')AS ASDCode, 
      ISNULL(AQC.ASDName, 'N/A') AS ASDName,
      p.ProductName
    INTO
      #Reject
    FROM  
    
      msv_AgentQualityCases aqc
      inner join mstt_casecheck cc on aqc.TrackGroupId = cc.TrackGroupId
      inner JOIN msdt_products P ON aqc.ProductCode = P.ProductCode
      where NBCCFinalStatus = 'Rejected'
      AND AQC.[CaseCheckFinalAssessmentDate] BETWEEN DATEADD(mm,((@NumberOfMonths-1)*-1),@ReportMonth) AND DATEADD(dd,-1,DATEADD(mm,1,@ReportMonth))
      AND AQC.ASDAgentCode = @ManagerCode 
           
      --CREATE TABLE testParameter
      --(NumberOfMonths INT, ReportMonth DATETIME, ManagerCode VARCHAR(10), UserID VARCHAR(20))
      
      --TRUNCATE TABLE testParameter
      --INSERT INTO testParameter VALUES(@NumberOfMonths, @ReportMonth, @ManagerCode,@UserId)
             
           
            
      /*
      msv_AgentQualityCases AQC 
      --INNER JOIN mstt_Agents Agents 
        --ON AQA.SellerAgentCode = Agents.CODE
      --INNER JOIN mstt_AgentQualityAggregation AQA
      --  ON AQA.AgentCode = AQC.SellerAgentCode 
      INNER JOIN mstt_CaseCheck care 
        ON care.AgentCode = AQC.SellerAgentCode
      --INNER JOIN mstt_AgentQualityHierarchy AQH 
        --ON AQH.AgentCode = Agents.CODE
      --INNER JOIN msv_AgentQualityAggregation AQA
        --ON AQA.AgentQualityID = AQC.SellerAgentCode  
      LEFT OUTER JOIN msdt_products P
        ON care.ProductCode = P.ProductId
      --LEFT OUTER JOIN mstt_Agents SQM 
      --  ON SQM.CODE = AQH.SalesQualitySQMLevelCode
      --LEFT OUTER JOIN mstt_Agents RSM
      --  ON RSM.CODE = AQH.SalesQualityRSMLevelCode
      --LEFT OUTER JOIN mstt_Agents ASD
      --  ON ASD.CODE = AQH.SalesQualityASDLevelCode
      --LEFT OUTER JOIN msft_sales S 
      --  ON AQA.agentcode = S.agentcode
    
      
    WHERE
    

         
      --AQA.SummaryPeriod = 1
      AQC.[CaseCheckInitialAssessmentDate] BETWEEN DATEADD(mm,(@NumberOfMonths*-1)+1,@ReportMonth) AND DATEADD(dd,-1,DATEADD(mm,1,@ReportMonth))
      --AND AQC.[CaseCheckInitialAssessmentDate] >= '01 Oct 2006'
      --AND AQA.Rejects > 0
      AND AQC.ASDAgentCode = @ManagerCode
      --AND AQA.SalesQualityASDLevelCode = @ManagerCode
      AND care.NBCCFinalStatus ='Rejected'
      --AND @LastDayOfReportMonth between AQH.AgentHierarchyStartDate and AQH.AgentHierarchyEndDate
      --AND AQA.ReportMonth=@ReportMonth
      -- Case Check must be on or after 1-Oct-2006, as per Item 138
      --AND AQC.KPILevel= 'AdviserKPI'
      */
      
    if (select count(*) from #Reject) = 0
    
      SELECT 
      null as Code,
      null AS AgentName, 
      --null as Rejects,
      null AS SQMCode, 
      null as SQMName,
      null as RSMCode, 
      null as RSMName,
      null as ASDCode, 
      null as ASDName,
      null as ProductName
      
    else
    
      SELECT 
      Code,
      AgentName, 
      --Rejects,
      SQMCode, 
      SQMName,
      RSMCode, 
      RSMName,
      ASDCode, 
      ASDName,
      ProductName
      from #Reject      

  end


GO
/****** Object:  StoredProcedure [dbo].[msp_AverageTurnover]    Script Date: 7/3/2026 3:44:25 PM ******/
