GO
CREATE PROCEDURE [dbo].[msp_AverageTurnover] -- WITH RECOMPILE,ENCRYPTION
  /* Param List */
AS
/******************************************************************************
Copyright (C) Moore Stephens Consulting Limited 2005
Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>
*******************************************************************************/
truncate table mst_averageturnover
insert into mst_AverageTurnover (
 AdviserId,
 AgentCode,
 [Size],
 Turnover,
 Cases,
 DA,
 NBI,
 SalesMargin,
 ComparisonId,
 ProductId,
 DateIssued
)
select 
 b.AdviserId as AdviserId,
 b.AgentCode as AgentCode,
 c.FranchiseSizeType as [Size],
 b.Turnover,
 b.Cases,
 b.DA,
 b.NBI,
 b.Margin,
 b.ComparisonId,
 b.ProductId,
 a.DateTime
from 
 msft_sales b,
 msdt_CalendarTime a,
(
select
 FranchiseSizeId,
 FranchiseSizeType
from
 msdt_FranchiseSize
) c
 where 
   b.FranchiseSizeId = c.FranchiseSizeId and
   b.dateissuedid = a.dateid
update mst_AverageTurnover
set
ProductGroup = p.ProductGroupName
from 
msdt_Products p,
mst_AverageTurnover a
where
a.ProductId = p.ProductId
update mst_AverageTurnover
set
Area = a.AreaSalesManager,
Region = a.RegionalSalesManager
from
msdt_Adviser a,
mst_AverageTurnover av
where
a.AdviserId = av.AdviserId
update mst_AverageTurnover
set
Area = a.AreaSalesManager,
Region = a.RegionalSalesManager
from
msdt_AdviserDummies a,
mst_AverageTurnover av
where
a.AdviserId = av.AdviserId
update mst_AverageTurnover
set
Level = c.Level
from 
msft_CapacityTerminationCounts c,
mst_AverageTurnover a
where
a.AdviserId = c.AdviserId 
update mst_AverageTurnover
set
Level = c.Level
from 
msft_CapacityTerminationCounts c,
mst_AverageTurnover a
where
a.AgentCode = c.AgentCode

GO
/****** Object:  StoredProcedure [dbo].[msp_BACSDate]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE procedure [dbo].[msp_BACSDate]
with recompile
as
/*************************************************************************
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : msp_BACSDate.sql
-- Owner   : CTT
-- Created : 26/10/2005
--
**************************************************************************
-- Amendment Log
--
-- Date:    7 July 2009
-- Amended By:  Mike Cawood
-- Reason:    Replace =* and *= ANSI JOINS as these not allowed in SQL Server 2005

*************************************************************************/

truncate table mst_BACSDate

--Derive List of Latest BACS Dates
select BusinessCode,MAX(isnull(bacsdate,'31 Jan 2006')) as LASTBACSDate
into #BACSDate
from msit_commissionstatement
group by businesscode
order by businesscode

--Derive List of next earliest BACS Dates
select t1.BusinessCode,t1.LastBACSDAte,MAX( isnull(cs.bacsdate, '31 Jan 2006' ) ) as PrevBACSDate
into #BACSDate2
from #BACSDate t1
left outer join msit_commissionstatement cs 
on isnull(t1.businesscode,'X') = isnull(cs.businesscode,'X') and t1.LastBACSDAte <> isnull(cs.bacsdate, convert(datetime,'31 Jan 2006',102) )
group by t1.businesscode,t1.LastBACSDAte
having t1.LastBACSDAte > MAX(isnull(cs.bacsdate,'31 Jan 2006'))
order by t1.businesscode

--Merge Lists
insert into mst_BACSDate
--Apply defaults for 'null' dates held in Commission Statement table
--Couple of overrides to cater for Null Business Code and PrevDate of 31 Jan 2006
select t1.BusinessCode,case when t1.LastBACSDate in ('1 Jan 1901') then '31 Jan 2006' else t1.LastBACSDate end as LastBACSDate,
case when t2.PrevBACSDate in ('1901-01-01','1901-01-02') then '31 Jan 2006' when t1.BusinessCode is NULL then '31 Jan 2006' 
when t2.BusinessCode is NULL then '31 Jan 2006' when t2.PrevBACSDate = '31 Jan 2006' then t2.PrevBACSDate 
else dateadd(dd,1,isnull(t2.PrevBACSDate,t1.LastBACSDate)) end as PrevBACSDate
from #BACSDate t1
left outer join #BACSDate2 t2 on isnull(t1.businesscode,'X') = isnull(t2.businesscode,'X') 

--Drop tables
drop table #BACSDate
drop table #BACSDate2
--drop table #mst_BACSDate


GO
