/****** Object:  StoredProcedure [dbo].[msp_CategoryByKPI_Manager]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE procedure [dbo].[msp_CategoryByKPI_Manager]

@ManagerCode        nvarchar(50),
@KPILevel           nvarchar(50),
@HierarchyTypeCode  nvarchar(50),
@UserId             nvarchar(50),
@AllowDelegates     char(1),
@ReportDate DATETIME = NULL --Default value
as

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : msp_CategoryByKPI_Manager.sql
-- Desc    : 
-- Owner   : KS
-- Created : 28/06/2006
--
-- Amended : 28/07/2006  - BT  - Get Compliance Category of Business desc
--           08/08/2006  - MK  - Alter the subquery to return the max(reportmonth)
--                               so that it does not get unwanted month (ie.
--                               where the KPILevel = 'CORP' as this gets updated
--                               daily.
--           09/08/2006  - JL  - Added New Parameter Called @ReportDate - Default is NULL
--                               If RepotrDate is Null then Assumes Current Date
--                               AS per Matt's Comment 08/08/2006
--           14/08/2006  - MK  - Added further security, to ensure that the 
--                               user executing the report is allowed to see
--                               the agent that has been passed in to the proc.
-- Amended : 16/08/2006  - MK  - Add function to allow delegate access. That is, allow a user
--                               to impersonate the user to whom they have been given access.
-- Amended : 21/08/2006  - KS  - Change Replacements to return 6 months worth of data not 1.
--
-- Amended : 07/07/2009 - MPC: Replace *= ANSI JOINS as these not allowed in SQL Server 2005
--
--########################################################################

if isnull(@AllowDelegates, 'N') = 'Y'
  set @UserId = (select dbo.msf_SQGetUserDelegatedFrom(@UserId))

declare @PermissionSummaryPeriod int
set @PermissionSummaryPeriod = case when @hierarchyTypeCode = 'CURRENT' then 1 else 6 end

if dbo.msf_SQCheckPermissions (@UserId, @ManagerCode,'ASD',@hierarchyTypeCode,@PermissionSummaryPeriod   ) = 'DENY' 
  and
dbo.msf_SQCheckPermissions (@UserId, @ManagerCode,'RSM',@hierarchyTypeCode,@PermissionSummaryPeriod   ) = 'DENY' 
  and
dbo.msf_SQCheckPermissions (@UserId, @ManagerCode,'SQM',@hierarchyTypeCode,@PermissionSummaryPeriod   ) = 'DENY' 
  and
dbo.msf_SQCheckPermissions (@UserId, @ManagerCode,'ASQM',@hierarchyTypeCode,@PermissionSummaryPeriod   ) = 'DENY' 
  and
dbo.msf_SQCheckPermissions (@UserId, @ManagerCode,'PS',@hierarchyTypeCode,@PermissionSummaryPeriod   ) = 'DENY' 
  


  SELECT 
  null as [SQMCode],
  null as [SQMName],
  null as [COB],
  null as [COBDesc],
  null as [Cases Submitted],
  null as [Cases Assessed],
  null as [SuitableAdvicePercent],
  null as [SuitableAdviceFails],
  null as [CompletionQueriesPercent],
  null as [CompletionQueriesFails],
  null as [Rejects],
  null as [ReplacementsPerc],
  null as [Replacements],
  null as [Justified Complaints],
  null as [Competence]
else

begin

--If Report Date not Passed assume Current Reporting date
IF @ReportDate IS NULL
BEGIN
  SELECT @ReportDate=MAX(ReportMonth) 
    FROM mstt_AgentQualityAggregation
    WHERE KPILevel= 'ADVISERKPI'
END

select 
 SalesQualitySQMLevelCode as [SQMCode],
 cast('' as nvarchar(255)) as [SQMName],
 ComplianceCategoryCode as [COB],
 cast('' as nvarchar(255)) as [COBDesc],
 cast('' as nvarchar(255)) as [COBSeq],
 SubmittedRiskProposalQty as [Cases Submitted],
 InitialRiskAssessedQty as [Cases Assessed],
 SAKPIPercent as [SuitableAdvicePercent],
 InitialOtherSuitableAdviceQty as [SuitableAdviceFails],
 CQKPIPercent as [CompletionQueriesPercent],
 InitialOtherCompletionQty as [CompletionQueriesFails],
 RejectKPIPercent as [Rejects],
 ReplacementKPIPercent as [ReplacementsPerc],
 Replacements as [Replacements],
 ComplaintQty as [Justified Complaints],
 cast('' as nvarchar(255)) as [Competence],
 cast('' as nvarchar(50)) as [KPILevel],
 cast('' as nvarchar(50)) as [HierarchyTypeCode]
into
 #mst_SummaryReport
from 
 msv_AgentQualityAggregation
where 1=2



insert into  
 #mst_SummaryReport
select
 [SQMCode] = AgentCode,
 [SQMName] = b.Descn,
 [COB] = a.ComplianceCategoryCode,
 [COBDesc] = c.[CategoryOfBusiness],
 [COBSeq] = c.[CategoryOfBusinessSequence],
 [Cases Submitted] = case when @KPILevel = 'RSMKPI' or @KPILevel = 'ASDKPI' then 
                          case when a.SummaryPeriod = 1 then CasesSubmitted end
                     else
                          case when a.SummaryPeriod = 6 then CasesSubmitted end
                     end,
 [Cases Assessed] = case when @KPILevel = 'RSMKPI' or @KPILevel = 'ASDKPI' then
                         case when a.SummaryPeriod = 1 then CasesAssessed end
                    else
                         case when a.SummaryPeriod = 6 then CasesAssessed end
                    end,
 [SuitableAdvicePercent] = case when @KPILevel = 'RSMKPI' or @KPILevel = 'ASDKPI' then
                                case when a.SummaryPeriod = 1 then SAKPIPercent end
                           else
                                case when a.SummaryPeriod = 6 then SAKPIPercent end
                           end,
 [SuitableAdviceFails] = case when @KPILevel = 'RSMKPI' or @KPILevel = 'ASDKPI' then 
                              case when a.SummaryPeriod = 1 then SuitableAdviceFailures end
                         else
                              case when a.SummaryPeriod = 6 then SuitableAdviceFailures end
                         end,
 [CompletionQueriesPercent] = case when @KPILevel = 'RSMKPI' or @KPILevel = 'ASDKPI' then
                                   case when a.SummaryPeriod = 1 then CQKPIPercent end
                              else
                                   case when a.SummaryPeriod = 6 then CQKPIPercent end
                              end,
 [CompletionQueriesFails] = case when @KPILevel = 'RSMKPI' or @KPILevel = 'ASDKPI' then
                                 case when a.SummaryPeriod = 1 then CompletionFailures end
                            else
                                 case when a.SummaryPeriod = 6 then CompletionFailures end
                            end,
 [Rejects] = case when a.SummaryPeriod = 1 then Rejects end,
 [ReplacementsPerc] = case when @KPILevel = 'RSMKPI' or @KPILevel = 'ASDKPI' then
                                 case when a.SummaryPeriod = 1 then ReplacementKPIPercent end
                            else
                                 case when a.SummaryPeriod = 6 then ReplacementKPIPercent end
                            end,
 [Replacements] = case when @KPILevel = 'RSMKPI' or @KPILevel = 'ASDKPI' then
                                 case when a.SummaryPeriod = 1 then Replacements end
                            else
                                 case when a.SummaryPeriod = 6 then Replacements end
                            end,
 [Justified Complaints] = case when a.SummaryPeriod = 1 then ComplaintQty end,
 [Competence] = '',
 [KPILevel] = a.kpiLevel,
 [HierarchyTypeCode] = a.HierarchyTypeCode
from
 msv_AgentQualityAggregation a                    --MPC: 07/07/2009
 inner join mstt_Agents b                     --MPC: 07/07/2009
  on a.AgentCode = b.Code                     --MPC: 07/07/2009
 left outer join msv_CategoryOfBusiness c             --MPC: 07/07/2009
  on a.[ComplianceCategoryCode] = c.[ComplianceCategoryCode]    --MPC: 07/07/2009
where
-- a.AgentCode *= b.Code and                    --MPC: 07/07/2009
-- a.[ComplianceCategoryCode] *= c.[ComplianceCategoryCode] and   --MPC: 07/07/2009
 a.reportmonth = @ReportDate and
 a.kpilevel = @KPILevel and --in ('asdkpi','sqmkpi', 'pskpi', 'rsmkpi', 'sqmps') and
 a.HierarchyTypeCode = @HierarchyTypeCode and  
 a.AgentCode = @ManagerCode


update s
set [Competence] = 'Competence: ' + c.AgentControlFunctionDescn
from #mst_SummaryReport s
  inner join mstt_AgentCompetence c
    on s.SQMCode = c.AgentCode
where c.EndDate IS NULL and
      s.COB = 'COB'


select 
 [SQMCode] as [SQMCode],
 [SQMName] as [SQMName],
 [COB] as [COB],
 [COBDesc] as [COBDesc],
 sum([Cases Submitted]) as [Cases Submitted],
 sum([Cases Assessed]) as [Cases Assessed],
 sum([SuitableAdvicePercent]) as [SuitableAdvicePercent],
 sum([SuitableAdviceFails]) as [SuitableAdviceFails],
 sum([CompletionQueriesPercent]) as [CompletionQueriesPercent],
 sum([CompletionQueriesFails]) as [CompletionQueriesFails],
 sum([Rejects]) as [Rejects],
 sum([ReplacementsPerc]) as [ReplacementsPerc],
 sum([Replacements]) as [Replacements],
 sum([Justified Complaints]) as [Justified Complaints],
 [Competence] as [Competence]
from
 #mst_SummaryReport
where
 kpiLevel = @KPILevel and
 HierarchyTypeCode = @HierarchyTypeCode
group by
 SQMCode,
 SQMName,
 COB,
 COBDesc,
 COBSeq,
 Competence
order by
 SQMCode,
 COBSeq


drop table #mst_SummaryReport

end




GO
/****** Object:  StoredProcedure [dbo].[msp_CategoryByKPI_Seller]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

create procedure [dbo].[msp_CategoryByKPI_Seller]

@ManagerCode       nvarchar(50),
@Span              nvarchar(50),  --Current or Transferred
@KPILevel          nvarchar(50),
@Report            nvarchar(50),  -- to distinguish between SQM or RSM Summary report, and which aggregation of data for the SQMPS KPILevel
@HierarchyTypeCode nvarchar(50),
@UserId            nvarchar(50),
@AllowDelegates    char(1),
@ReportDate        DATETIME = NULL
as

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : msp_CategoryByKPI_Seller.sql
-- Desc    : 
-- Owner   : KS
-- Created : 03/07/2006
--
-- Amended : 28/07/2006  - BT  - Get Compliance Category of Business desc
--           31/07/2006  - MK  - Alter final select so that it groups records
--                               instead of showing ComplianceCategories twice
--           08/08/2006  - MK  - Alter the subquery to return the max(reportmonth)
--                               so that it does not get unwanted month (ie.
--                               where the KPILevel = 'CORP' as this gets updated
--                               daily.
--           09/08/2006  - JL  - Added New Parameter Called @ReportDate - Default is NULL
--                               If RepotrDate is Null then Assumes Current Date
--                               AS per Matt's Comment 08/08/2006
--           14/08/2006  - MK  - Added further security, to ensure that the 
--                               user executing the report is allowed to see
--                               the agent that has been passed in to the proc.
-- Amended : 16/08/2006  - MK  - Add function to allow delegate access. That is, allow a user
--                               to impersonate the user to whom they have been given access.
-- Amended : 16/08/2006  - KS  - Add temp table to join to mstt_AgentQualityHierarchy, as wasn't joining correctly
--                               to determine hierarchy above SQM
-- Amended : 17/08/2006  - KS  - Join to mstt_AgentQualityHierarchy - date wrong, needs to be end of report month, not start of report month
-- Amended : 21/08/2006  - KS  - Change Replacements to return 6 months worth of data not 1.
-- Amended : 21/08/2006  - BT  - Fix issue with #mstt_AgentQuailityHierarchy so Adviser Snapshot works
--
--########################################################################

-- declare @KPILevel nvarchar(50),
--         @ManagerCode nvarchar(50)
-- set @kpilevel = 'PSSummary'
-- set @ManagerCode = '1003243'

if isnull(@AllowDelegates, 'N') = 'Y'
  set @UserId = (select dbo.msf_SQGetUserDelegatedFrom(@UserId))

declare @PermissionSummaryPeriod int
set @PermissionSummaryPeriod = case when @hierarchyTypeCode = 'CURRENT' then 1 else 6 end

if dbo.msf_SQCheckPermissions (@UserId, @ManagerCode,@KPILevel,@hierarchyTypeCode,@PermissionSummaryPeriod) = 'DENY' 


  SELECT 
  null as [SQMCode],
  null as [AgentCode],
  null as [AgentName],
  null as [Surname],
  --Investment Measures
  null as [Investment Cases Submitted],
  null as [Investment Cases Assessed],
  null as [Investment SuitableAdvicePercent],
  null as [Investment SuitableAdviceFails],
  null as [Investment CompletionQueriesPercent],
  null as [Investment CompletionQueriesFails],
  null as [Investment Rejects],
  null as [Investment Replacements],
  null as [Investment Justified Complaints],
  null as [Investment Competence],
  --Mortgage Measures
  null as [Mortgage Cases Submitted],
  null as [Mortgage Cases Assessed],
  null as [Mortgage SuitableAdvicePercent],
  null as [Mortgage SuitableAdviceFails],
  null as [Mortgage CompletionQueriesPercent],
  null as [Mortgage CompletionQueriesFails],
  null as [Mortgage Rejects],
  null as [Mortgage Replacements],
  null as [Mortgage Justified Complaints],
  null as [Mortgage Competence],
  --PP Measures
  null as [PP Cases Submitted],
  null as [PP Cases Assessed],
  null as [PP SuitableAdvicePercent],
  null as [PP SuitableAdviceFails],
  null as [PP CompletionQueriesPercent],
  null as [PP CompletionQueriesFails],
  null as [PP Rejects],
  null as [PP Replacements],
  null as [PP Justified Complaints],
  null as [PP Competence],
  --GI Measures
  null as [GI Cases Submitted],
  null as [GI Cases Assessed],
  null as [GI SuitableAdvicePercent],
  null as [GI SuitableAdviceFails],
  null as [GI CompletionQueriesPercent],
  null as [GI CompletionQueriesFails],
  null as [GI Rejects],
  null as [GI Replacements],
  null as [GI Justified Complaints],
  null as [GI Competence],
  null as [Practice],
  null as [Contract Status],
  null as [Segment]
else

begin

--If Report Date not Passed assume Current Reporting date
IF @ReportDate IS NULL
BEGIN
  SELECT @ReportDate=MAX(ReportMonth) 
    FROM mstt_AgentQualityAggregation
    WHERE KPILevel= 'ADVISERKPI'
END

select 
 SalesQualitySQMLevelCode as [SupervisorCode],
 AgentCode as [AgentCode],
 cast('' as nvarchar(255)) as [AgentName],
 cast('' as nvarchar(255)) as [Surname],
 --ComplianceCategoryCode as [COB],
 --cast('' as nvarchar(255)) as [COBDesc],
 --cast('' as nvarchar(255)) as [COBSeq],
 --Investment Measures
 SubmittedRiskProposalQty        as [Investment Cases Submitted],
 InitialRiskAssessedQty          as [Investment Cases Assessed],
 SAKPIPercent                    as [Investment SuitableAdvicePercent],
 InitialOtherSuitableAdviceQty   as [Investment SuitableAdviceFails],
 CQKPIPercent                    as [Investment CompletionQueriesPercent],
 InitialOtherCompletionQty       as [Investment CompletionQueriesFails],
 RejectKPIPercent                as [Investment Rejects],
 ReplacementKPIPercent           as [Investment Replacements],
 ComplaintQty                    as [Investment Justified Complaints],
 cast('' as nvarchar(255))       as [Investment Competence],
 --Mortgage Measures
 SubmittedRiskProposalQty        as [Mortgage Cases Submitted],
 InitialRiskAssessedQty          as [Mortgage Cases Assessed],
 SAKPIPercent                    as [Mortgage SuitableAdvicePercent],
 InitialOtherSuitableAdviceQty   as [Mortgage SuitableAdviceFails],
 CQKPIPercent                    as [Mortgage CompletionQueriesPercent],
 InitialOtherCompletionQty       as [Mortgage CompletionQueriesFails],
 RejectKPIPercent                as [Mortgage Rejects],
 ReplacementKPIPercent           as [Mortgage Replacements],
 ComplaintQty                    as [Mortgage Justified Complaints],
 cast('' as nvarchar(255))       as [Mortgage Competence],
 --PP Measures
 SubmittedRiskProposalQty        as [PP Cases Submitted],
 InitialRiskAssessedQty          as [PP Cases Assessed],
 SAKPIPercent                    as [PP SuitableAdvicePercent],
 InitialOtherSuitableAdviceQty   as [PP SuitableAdviceFails],
 CQKPIPercent                    as [PP CompletionQueriesPercent],
 InitialOtherCompletionQty       as [PP CompletionQueriesFails],
 RejectKPIPercent                as [PP Rejects],
 ReplacementKPIPercent           as [PP Replacements],
 ComplaintQty                    as [PP Justified Complaints],
 cast('' as nvarchar(255))       as [PP Competence],
 --GI Measures
 SubmittedRiskProposalQty        as [GI Cases Submitted],
 InitialRiskAssessedQty          as [GI Cases Assessed],
 SAKPIPercent                    as [GI SuitableAdvicePercent],
 InitialOtherSuitableAdviceQty   as [GI SuitableAdviceFails],
 CQKPIPercent                    as [GI CompletionQueriesPercent],
 InitialOtherCompletionQty       as [GI CompletionQueriesFails],
 RejectKPIPercent                as [GI Rejects],
 ReplacementKPIPercent           as [GI Replacements],
 ComplaintQty                    as [GI Justified Complaints],
 cast('' as nvarchar(255))       as [GI Competence],
  cast('' as nvarchar(255)) as [Practice],
 cast('' as nvarchar(255)) as [Contract Status],
 cast('' as nvarchar(255)) as [Segment],
 cast('' as nvarchar(50)) as [Span],
 cast('' as nvarchar(50)) as [KPILevel],
 cast('' as nvarchar(50)) as [HierarchyTypeCode]
into
 #mst_SummaryReport
from 
 msv_AgentQualityAggregation
where 1=2 



select distinct
  AgentHierarchyStartDate,
  AgentHierarchyEndDate,
  (case when @Report = 'RSMSummary' then SalesQualityRSMLevelCode
       when @Report = 'SQMSummary' then SalesQualitySQMLevelCode
       when @Report = 'ASDSummary' then SalesQualityASDLevelCode
       when @Report = 'PSSummary'  then SalesQualityPSLevelCode
       when @Report = 'AdviserSummary' then AgentCode
  end)
  as [ManagerCode],
  (case when @Report = 'RSMSummary' then SalesQualitySQMLevelCode 
       when @Report = 'SQMSummary' then AgentCode
       when @Report = 'ASDSummary' then SalesQualityRSMLevelCode
       when @Report = 'PSSummary'  then AgentCode
       when @Report = 'AdviserSummary' then AgentCode
  end)
  as [SellerCode]
into #mstt_AgentQuailityHierarchy
from mstt_AgentQualityHierarchy



insert into  
 #mst_SummaryReport
select
 [SupervisorCode] = case when @KPILevel = 'PSSummary' then a.SalesQualityPSLevelCode 
                         when @KPILevel = 'RSMSummary' then a.SalesQualityRSMLevelCode
                         when @KPILevel = 'ASDSummary' then a.SalesQualityASDLevelCode
                         else --a.SalesQualitySQMLevelCode  end,
                              Coalesce(a.SalesQualityPSLevelCode, a.SalesQualitySQMLevelCode) end,  --KS - was joining to mstt_AgentQualityHierarchy
 [AgentCode] = a.AgentCode,
 [AgentName] = b.Descn,
 [Surname] = b.[Name],
 --[COB] = a.ComplianceCategoryCode,
 --[COBDesc] = d.[CategoryOfBusiness],
 --[COBSeq] = d.[CategoryOfBusinessSequence],
 --Investment Measures
 [Investment Cases Submitted] = case when d.[ComplianceCategoryCode] = 'COB' then
          case when @KPILevel = 'RSMSummary' or @KPILevel = 'ASDSummary' or @Report = 'ASDSummary' or  @Report = 'RSMSummary' then
            case when a.SummaryPeriod = 1 then CasesSubmitted end
          else
            case when a.SummaryPeriod = 6 then CasesSubmitted end
          end
                                else 0 end,
 [Investment Cases Assessed] = case when d.[ComplianceCategoryCode] = 'COB' then
          case when @KPILevel = 'RSMSummary' or @Report = 'RSMSummary' or @KPILevel = 'ASDSummary' or @Report = 'ASDSummary' then
            case when a.SummaryPeriod = 1 then CasesAssessed end
          else
            case when a.SummaryPeriod = 6 then CasesAssessed end
          end
                               else 0 end,
 [Investment SuitableAdvicePercent] = case when d.[ComplianceCategoryCode] = 'COB' then
          case when @KPILevel = 'RSMSummary' or @Report = 'RSMSummary' or @KPILevel = 'ASDSummary' or @Report = 'ASDSummary' then
            case when a.SummaryPeriod = 1 then SAKPIPercent end
          else
            case when a.SummaryPeriod = 6 then SAKPIPercent end
          end
                                      else 0 end,
 [Investment SuitableAdviceFails] = case when d.[ComplianceCategoryCode] = 'COB' then
          case when @KPILevel = 'RSMSummary' or @Report = 'RSMSummary' or @KPILevel = 'ASDSummary' or @Report = 'ASDSummary' then
            case when a.SummaryPeriod = 1 then SuitableAdviceFailures end
          else
            case when a.SummaryPeriod = 6 then SuitableAdviceFailures end
          end
                                    else 0 end,
 [Investment CompletionQueriesPercent] = case when d.[ComplianceCategoryCode] = 'COB' then
            case when @KPILevel = 'RSMSummary' or @Report = 'RSMSummary' or @KPILevel = 'ASDSummary' or @Report = 'ASDSummary' then
              case when a.SummaryPeriod = 1 then CQKPIPercent end
            else
              case when a.SummaryPeriod = 6 then CQKPIPercent end
            end
                                         else 0 end,
 [Investment CompletionQueriesFails] = case when d.[ComplianceCategoryCode] = 'COB' then
            case when @KPILevel = 'RSMSummary' or @Report = 'RSMSummary' or @KPILevel = 'ASDSummary' or @Report = 'ASDSummary' then
              case when a.SummaryPeriod = 1 then CompletionFailures end
            else
              case when a.SummaryPeriod = 6 then CompletionFailures end
            end
                                       else 0 end,
 [Investment Rejects] = case when d.[ComplianceCategoryCode] = 'COB' then
          case when a.SummaryPeriod = 1 then Rejects end
                        else 0 end,
 [Investment Replacements] = case when d.[ComplianceCategoryCode] = 'COB' then
            case when @KPILevel = 'RSMSummary' or @Report = 'RSMSummary' or @KPILevel = 'ASDSummary' or @Report = 'ASDSummary' then
              case when a.SummaryPeriod = 1 then Replacements end
            else
              case when a.SummaryPeriod = 6 then Replacements end
            end
                                       else 0 end,
 [Investment Justified Complaints] = case when d.[ComplianceCategoryCode] = 'COB' then
                          case when a.SummaryPeriod = 1 then ComplaintQty end
                          else 0 end,
 [Investment Competence] = '',                          
 --Mortgage Measures
 [Mortgage Cases Submitted] = case when d.[ComplianceCategoryCode] = 'MCOB' then
                     case when @KPILevel = 'RSMSummary' or @KPILevel = 'ASDSummary' or @Report = 'ASDSummary' or  @Report = 'RSMSummary' then
                          case when a.SummaryPeriod = 1 then CasesSubmitted end
                     else
                          case when a.SummaryPeriod = 6 then CasesSubmitted end
                     end
                     else 0 end,
 [Mortgage Cases Assessed] = case when d.[ComplianceCategoryCode] = 'MCOB' then
                    case when @KPILevel = 'RSMSummary' or @Report = 'RSMSummary' or @KPILevel = 'ASDSummary' or @Report = 'ASDSummary' then
                         case when a.SummaryPeriod = 1 then CasesAssessed end
                    else
                         case when a.SummaryPeriod = 6 then CasesAssessed end
                    end
                    else 0 end,
 [Mortgage SuitableAdvicePercent] = case when d.[ComplianceCategoryCode] = 'MCOB' then
                           case when @KPILevel = 'RSMSummary' or @Report = 'RSMSummary' or @KPILevel = 'ASDSummary' or @Report = 'ASDSummary' then
                                case when a.SummaryPeriod = 1 then SAKPIPercent end
                           else
                                case when a.SummaryPeriod = 6 then SAKPIPercent end
                           end
                           else 0 end,
 [Mortgage SuitableAdviceFails] = case when d.[ComplianceCategoryCode] = 'MCOB' then
                         case when @KPILevel = 'RSMSummary' or @Report = 'RSMSummary' or @KPILevel = 'ASDSummary' or @Report = 'ASDSummary' then
                              case when a.SummaryPeriod = 1 then SuitableAdviceFailures end
                         else
                              case when a.SummaryPeriod = 6 then SuitableAdviceFailures end
                         end
                         else 0 end,
 [Mortgage CompletionQueriesPercent] = case when d.[ComplianceCategoryCode] = 'MCOB' then
                              case when @KPILevel = 'RSMSummary' or @Report = 'RSMSummary' or @KPILevel = 'ASDSummary' or @Report = 'ASDSummary' then
                                   case when a.SummaryPeriod = 1 then CQKPIPercent end
                              else
                                   case when a.SummaryPeriod = 6 then CQKPIPercent end
                              end
                              else 0 end,
 [Mortgage CompletionQueriesFails] = case when d.[ComplianceCategoryCode] = 'MCOB' then
                            case when @KPILevel = 'RSMSummary' or @Report = 'RSMSummary' or @KPILevel = 'ASDSummary' or @Report = 'ASDSummary' then
                                 case when a.SummaryPeriod = 1 then CompletionFailures end
                            else
                                 case when a.SummaryPeriod = 6 then CompletionFailures end
                            end
                            else 0 end,
 [Mortgage Rejects] = case when d.[ComplianceCategoryCode] = 'MCOB' then
             case when a.SummaryPeriod = 1 then Rejects end
             else 0 end,
 [Mortgage Replacements] = case when d.[ComplianceCategoryCode] = 'MCOB' then
                            case when @KPILevel = 'RSMSummary' or @Report = 'RSMSummary' or @KPILevel = 'ASDSummary' or @Report = 'ASDSummary' then
                                 case when a.SummaryPeriod = 1 then Replacements end
                            else
                                 case when a.SummaryPeriod = 6 then Replacements end
                            end
                            else 0 end,
 [Mortgage Justified Complaints] = case when d.[ComplianceCategoryCode] = 'MCOB' then
                          case when a.SummaryPeriod = 1 then ComplaintQty end
                          else 0 end,
 [Mortgage Competence] = '',                          
 --Pure Protection Measures
 [PP Cases Submitted] = case when d.[ComplianceCategoryCode] = 'ICOB-PP' then
                     case when @KPILevel = 'RSMSummary' or @KPILevel = 'ASDSummary' or @Report = 'ASDSummary' or  @Report = 'RSMSummary' then
                          case when a.SummaryPeriod = 1 then CasesSubmitted end
                     else
                          case when a.SummaryPeriod = 6 then CasesSubmitted end
                     end
                     else 0 end,
 [PP Cases Assessed] = case when d.[ComplianceCategoryCode] = 'ICOB-PP' then
                    case when @KPILevel = 'RSMSummary' or @Report = 'RSMSummary' or @KPILevel = 'ASDSummary' or @Report = 'ASDSummary' then
                         case when a.SummaryPeriod = 1 then CasesAssessed end
                    else
                         case when a.SummaryPeriod = 6 then CasesAssessed end
                    end
                    else 0 end,
 [PP SuitableAdvicePercent] = case when d.[ComplianceCategoryCode] = 'ICOB-PP' then
                           case when @KPILevel = 'RSMSummary' or @Report = 'RSMSummary' or @KPILevel = 'ASDSummary' or @Report = 'ASDSummary' then
                                case when a.SummaryPeriod = 1 then SAKPIPercent end
                           else
                                case when a.SummaryPeriod = 6 then SAKPIPercent end
                           end
                           else 0 end,
 [PP SuitableAdviceFails] = case when d.[ComplianceCategoryCode] = 'ICOB-PP' then
                         case when @KPILevel = 'RSMSummary' or @Report = 'RSMSummary' or @KPILevel = 'ASDSummary' or @Report = 'ASDSummary' then
                              case when a.SummaryPeriod = 1 then SuitableAdviceFailures end
                         else
                              case when a.SummaryPeriod = 6 then SuitableAdviceFailures end
                         end
                         else 0 end,
 [PP CompletionQueriesPercent] = case when d.[ComplianceCategoryCode] = 'ICOB-PP' then
                              case when @KPILevel = 'RSMSummary' or @Report = 'RSMSummary' or @KPILevel = 'ASDSummary' or @Report = 'ASDSummary' then
                                   case when a.SummaryPeriod = 1 then CQKPIPercent end
                              else
                                   case when a.SummaryPeriod = 6 then CQKPIPercent end
                              end
                              else 0 end,
 [PP CompletionQueriesFails] = case when d.[ComplianceCategoryCode] = 'ICOB-PP' then
                            case when @KPILevel = 'RSMSummary' or @Report = 'RSMSummary' or @KPILevel = 'ASDSummary' or @Report = 'ASDSummary' then
                                 case when a.SummaryPeriod = 1 then CompletionFailures end
                            else
                                 case when a.SummaryPeriod = 6 then CompletionFailures end
                            end
                            else 0 end,
 [PP Rejects] = case when d.[ComplianceCategoryCode] = 'ICOB-PP' then
             case when a.SummaryPeriod = 1 then Rejects end
             else 0 end,
 [PP Replacements] = case when d.[ComplianceCategoryCode] = 'ICOB-PP' then
                            case when @KPILevel = 'RSMSummary' or @Report = 'RSMSummary' or @KPILevel = 'ASDSummary' or @Report = 'ASDSummary' then
                                 case when a.SummaryPeriod = 1 then Replacements end
                            else
                                 case when a.SummaryPeriod = 6 then Replacements end
                            end
                            else 0 end,
 [PP Justified Complaints] = case when d.[ComplianceCategoryCode] = 'ICOB-PP' then
                          case when a.SummaryPeriod = 1 then ComplaintQty end
                          else 0 end,
 [PP Competence] = '',                          
 --GI Measures
 [GI Cases Submitted] = case when d.[ComplianceCategoryCode] = 'ICOB-GI' then
                     case when @KPILevel = 'RSMSummary' or @KPILevel = 'ASDSummary' or @Report = 'ASDSummary' or  @Report = 'RSMSummary' then
                          case when a.SummaryPeriod = 1 then CasesSubmitted end
                     else
                          case when a.SummaryPeriod = 6 then CasesSubmitted end
                     end
                     else 0 end,
 [GI Cases Assessed] = case when d.[ComplianceCategoryCode] = 'ICOB-GI' then
                    case when @KPILevel = 'RSMSummary' or @Report = 'RSMSummary' or @KPILevel = 'ASDSummary' or @Report = 'ASDSummary' then
                         case when a.SummaryPeriod = 1 then CasesAssessed end
                    else
                         case when a.SummaryPeriod = 6 then CasesAssessed end
                    end
                    else 0 end,
 [GI SuitableAdvicePercent] = case when d.[ComplianceCategoryCode] = 'ICOB-GI' then
                           case when @KPILevel = 'RSMSummary' or @Report = 'RSMSummary' or @KPILevel = 'ASDSummary' or @Report = 'ASDSummary' then
                                case when a.SummaryPeriod = 1 then SAKPIPercent end
                           else
                                case when a.SummaryPeriod = 6 then SAKPIPercent end
                           end
                           else 0 end,
 [GI SuitableAdviceFails] = case when d.[ComplianceCategoryCode] = 'ICOB-GI' then
                         case when @KPILevel = 'RSMSummary' or @Report = 'RSMSummary' or @KPILevel = 'ASDSummary' or @Report = 'ASDSummary' then
                              case when a.SummaryPeriod = 1 then SuitableAdviceFailures end
                         else
                              case when a.SummaryPeriod = 6 then SuitableAdviceFailures end
                         end
                         else 0 end,
 [GI CompletionQueriesPercent] = case when d.[ComplianceCategoryCode] = 'ICOB-GI' then
                              case when @KPILevel = 'RSMSummary' or @Report = 'RSMSummary' or @KPILevel = 'ASDSummary' or @Report = 'ASDSummary' then
                                   case when a.SummaryPeriod = 1 then CQKPIPercent end
                              else
                                   case when a.SummaryPeriod = 6 then CQKPIPercent end
                              end
                              else 0 end,
 [GI CompletionQueriesFails] = case when d.[ComplianceCategoryCode] = 'ICOB-GI' then
                            case when @KPILevel = 'RSMSummary' or @Report = 'RSMSummary' or @KPILevel = 'ASDSummary' or @Report = 'ASDSummary' then
                                 case when a.SummaryPeriod = 1 then CompletionFailures end
                            else
                                 case when a.SummaryPeriod = 6 then CompletionFailures end
                            end
                            else 0 end,
 [GI Rejects] = case when d.[ComplianceCategoryCode] = 'ICOB-GI' then
      case when a.SummaryPeriod = 1 then Rejects end
                else 0 end,
 [GI Replacements] = case when d.[ComplianceCategoryCode] = 'ICOB-GI' then
                            case when @KPILevel = 'RSMSummary' or @Report = 'RSMSummary' or @KPILevel = 'ASDSummary' or @Report = 'ASDSummary' then
                                 case when a.SummaryPeriod = 1 then Replacements end
                            else
                                 case when a.SummaryPeriod = 6 then Replacements end
                            end
                            else 0 end,
 [GI Justified Complaints] = case when d.[ComplianceCategoryCode] = 'ICOB-GI' then
             case when a.SummaryPeriod = 1 then ComplaintQty end
                             else 0 end,
 [GI Competence] = '',
 [Practice] = '',
 [Contract Status] = '',
 [Segment] = '',
 [Span] =  case when @KPILevel = 'PSSummary' then 
                case when c.ManagerCode is null then 'Transferred'
                when a.SalesQualityPSLevelCode <> c.ManagerCode then 'Transferred'
                else 'Current' end
           when @KPILevel = 'RSMSummary' then 
                case when c.ManagerCode is null then 'Transferred'
                when a.SalesQualityRSMLevelCode <> c.ManagerCode then 'Transferred'
                else 'Current' end
           when @KPILevel = 'ASDSummary' then 
                case when c.ManagerCode is null then 'Transferred'
                when a.SalesQualityASDLevelCode <> c.ManagerCode then 'Transferred'
                else 'Current' end
           else
               case when c.ManagerCode is null then 'Transferred'
                when a.SalesQualitySQMLevelCode <> c.ManagerCode then 'Transferred'
                else 'Current' end
           end,
 [KPILevel]= a.KPILevel,
 [HierarchyTypeCode] = a.HierarchyTypeCode
from
 msv_AgentQualityAggregation a
 left join mstt_Agents b on  a.AgentCode = b.Code
 left join #mstt_AgentQuailityHierarchy c on  a.AgentCode = c.SellerCode and
   DateAdd(d,-1, DateAdd(m,1,a.ReportMonth)) >= c.AgentHierarchyStartDate and
   DateAdd(d,-1, DateAdd(m,1,a.ReportMonth)) <= c.AgentHierarchyEndDate
 left join msv_CategoryOfBusiness d on a.[ComplianceCategoryCode] = d.[ComplianceCategoryCode]
where
 a.reportmonth = @ReportDate and
 a.kpilevel = @KPILevel and --in ('asdsummary','sqmSummary', 'sqmps', 'pssummary','rsmsummary','adviserkpi') and
 a.HierarchyTypeCode = @HierarchyTypeCode and 
 @ManagerCode = case when @KPILevel = 'AdviserKPI' then a.AgentCode
                     when @KPILevel = 'PSSummary'  then a.SalesQualityPSLevelCode
                     when @KPILevel = 'SQMSummary' then a.SalesQualitySQMLevelCode
                     when @KPILevel = 'SQMPS'      then a.SalesQualitySQMLevelCode
                     when @KPILevel = 'RSMSummary' then a.SalesQualityRSMLevelCode
                     when @KPILevel = 'ASDSummary' then a.SalesQualityASDLevelCode
                else null end

--Get Practice, Contract Status and Segment
update s
set Practice = a_Firm.Descn,
  [Contract Status] = a.CompetentStatusDescription,
  [Segment] = a.AgentSpecialistDesc
from #mst_SummaryReport s
  inner join mstt_Agents a
    on s.AgentCode = a.Code
  inner join mstt_Agents a_Firm
    on a.Firm = a_Firm.Code
    
--Get Competencies    
update s
set [Investment Competence] = c.AgentControlFunctionDescn
from #mst_SummaryReport s
  inner join mstt_AgentCompetence c
    on s.AgentCode = c.AgentCode
where c.EndDate IS NULL
and c.compliancecategorycode = 'COB'

update s
set [Mortgage Competence] = c.AgentControlFunctionDescn
from #mst_SummaryReport s
  inner join mstt_AgentCompetence c
    on s.AgentCode = c.AgentCode
where c.EndDate IS NULL
and c.compliancecategorycode = 'MCOB'

update s
set [PP Competence] = c.AgentControlFunctionDescn
from #mst_SummaryReport s
  inner join mstt_AgentCompetence c
    on s.AgentCode = c.AgentCode
where c.EndDate IS NULL
and c.compliancecategorycode = 'ICOB-PP'

update s
set [GI Competence] = c.AgentControlFunctionDescn
from #mst_SummaryReport s
  inner join mstt_AgentCompetence c
    on s.AgentCode = c.AgentCode
where c.EndDate IS NULL
and c.compliancecategorycode = 'ICOB-GI'


select 
 [SupervisorCode] as [SQMCode],
 [AgentCode] as [AgentCode],
 [AgentName] as [AgentName],
 [Surname] as [Surname],
 --[COB] as [COB],
 --[COBDesc] as [COBDesc],
 --Investment Measures
 max([Investment Cases Submitted]) as [Investment Cases Submitted],
 max([Investment Cases Assessed]) as [Investment Cases Assessed],
 max([Investment SuitableAdvicePercent]) as [Investment SuitableAdvicePercent],
 max([Investment SuitableAdviceFails]) as [Investment SuitableAdviceFails],
 max([Investment CompletionQueriesPercent]) as [Investment CompletionQueriesPercent],
 max([Investment CompletionQueriesFails]) as [Investment CompletionQueriesFails],
 max([Investment Rejects]) as [Investment Rejects],
 max([Investment Replacements]) as [Investment Replacements],
 max([Investment Justified Complaints]) as [Investment Justified Complaints],
 max([Investment Competence]) as [Investment Competence],
 --Mortgage Measures
 max([Mortgage Cases Submitted]) as [Mortgage Cases Submitted],
 max([Mortgage Cases Assessed]) as [Mortgage Cases Assessed],
 max([Mortgage SuitableAdvicePercent]) as [Mortgage SuitableAdvicePercent],
 max([Mortgage SuitableAdviceFails]) as [Mortgage SuitableAdviceFails],
 max([Mortgage CompletionQueriesPercent]) as [Mortgage CompletionQueriesPercent],
 max([Mortgage CompletionQueriesFails]) as [Mortgage CompletionQueriesFails],
 max([Mortgage Rejects]) as [Mortgage Rejects],
 max([Mortgage Replacements]) as [Mortgage Replacements],
 max([Mortgage Justified Complaints]) as [Mortgage Justified Complaints],
 max([Mortgage Competence]) as [Mortgage Competence],
 --PP Measures
 max([PP Cases Submitted]) as [PP Cases Submitted],
 max([PP Cases Assessed]) as [PP Cases Assessed],
 max([PP SuitableAdvicePercent]) as [PP SuitableAdvicePercent],
 max([PP SuitableAdviceFails]) as [PP SuitableAdviceFails],
 max([PP CompletionQueriesPercent]) as [PP CompletionQueriesPercent],
 max([PP CompletionQueriesFails]) as [PP CompletionQueriesFails],
 max([PP Rejects]) as [PP Rejects],
 max([PP Replacements]) as [PP Replacements],
 max([PP Justified Complaints]) as [PP Justified Complaints],
 max([PP Competence]) as [PP Competence],
 --GI Measures
 max([GI Cases Submitted]) as [GI Cases Submitted],
 max([GI Cases Assessed]) as [GI Cases Assessed],
 max([GI SuitableAdvicePercent]) as [GI SuitableAdvicePercent],
 max([GI SuitableAdviceFails]) as [GI SuitableAdviceFails],
 max([GI CompletionQueriesPercent]) as [GI CompletionQueriesPercent],
 max([GI CompletionQueriesFails]) as [GI CompletionQueriesFails],
 max([GI Rejects]) as [GI Rejects],
 max([GI Replacements]) as [GI Replacements],
 max([GI Justified Complaints]) as [GI Justified Complaints],
 max([GI Competence]) as [GI Competence],
 [Practice] as [Practice],
 [Contract Status] as [Contract Status],
 [Segment] as [Segment]
from
 #mst_SummaryReport
where
 Span = @Span and
 KPILevel = @KPILevel and
 HierarchyTypeCode = @HierarchyTypeCode
group by
 [SupervisorCode],
 [AgentCode],
 [AgentName],
 [Surname],
 --[COB],
 --[COBDesc],
 --[Competence],
 [Practice],
 [Contract Status],
 [Segment]--,
-- [COBSeq]
order by
 SupervisorCode,
 Surname,
 AgentCode--,
 --COBSeq


drop table #mst_SummaryReport
drop table #mstt_AgentQuailityHierarchy

end



GO
/****** Object:  StoredProcedure [dbo].[msp_CheckRecordCounts]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

create procedure [dbo].[msp_CheckRecordCounts]
 @Client        varchar(50),
 @Module        varchar(50),
 @Type          varchar(50),
 @ProcedureName varchar(255) out,
 @Error         int          out
WITH RECOMPILE --, ENCRYPTION
as

--############################################################################
-- Copyright (c) MOORE STEPHENS CONSULTING LIMITED, 2004 All rights reserved 
-- 
-- Object     : Procedure
-- Name       : msp_CheckRecordCounts.sql
-- Description: To check record counts between MS tables and client tables
-- Owner      : Ermedin Selmanovic
-- Created    : 22/12/2004
-- 
--############################################################################
--
-- $Id: msp_CheckRecordCounts.sql 1.1 2004/12/22 11:57:13Z dselmano Exp $
-- $Log: msp_CheckRecordCounts.sql $
-- Revision 1.1  2004/12/22 11:57:13Z  dselmano
-- Initial revision
--
--############################################################################

declare 
 @Phase          varchar(50),
 @Process        varchar(100),
 @ErrorCode      int,
 @ErrorCount     int,
 @StopProcessing bit

set @ErrorCount     = 0
set @StopProcessing = 0 

set @ProcedureName  = object_name(@@procid)
set @Process        = @ProcedureName
set @Phase          = 'START'

exec msp_ProcessLog @Phase, @Process, null, @Module, @Client

declare
 CheckCounts cursor
for
select
 [Name],
 [DataFileName]
from
 mst_DataImportConfiguration
where
 [Client]  = @Client and
 [Module]  = @Module and
 Type      = @Type
order by
 [Name]
for read only

declare 
 @Name         varchar(50),
 @DataFileName varchar(50),
 @String       varchar(4000)

open
 CheckCounts
fetch
 CheckCounts
into
 @Name, 
 @DataFileName

while (@@fetch_status = 0)
begin

--  select @String = 'declare  @Client nvarchar(50), @Module nvarchar(50), @TableCount nvarchar(50), @FileCount nvarchar(50), @ProcessId integer select @TableCount = isnull((select count(*) from ' + @Name + '), 0)' +
--                   ' select @FileCount = isnull((select RecordCount from msit_RecordCounts where Client = ''' + @Client + ''' and [Module] = ''' + @Module + ''' and DataFileName = ''' + @DataFileName + '''' +
--                   ' and DtTm = (select max(DtTm) from msit_RecordCounts where Client = ''' + @Client + ''' and [Module] = ''' + @Module + ''' and DataFileName = ''' + @DataFileName + ''')), 0)' +
--                   ' select @ProcessId = (select isnull(max(ProcessId), 0) + 1 from mst_ProcessLog)' +
--                   ' if @TableCount = @FileCount begin insert into mst_ProcessLog values (getdate(), @ProcessId, ''CHECK COUNTS'', ''OK in ' + @Name + 
--                   ' (File '' + ' + '@FileCount' + ' + '' Table '' + ' + '@TableCount' + ' + '')'', null, ' + '''' + @Module + ''', ' + '''' + @Client + ''') end' +
--                   ' else begin insert into mst_ProcessLog values (getdate(), @ProcessId, ''CHECK COUNTS'', ''Discrepancy in ' + @Name + 
--                   ' (File '' + ' + '@FileCount' + ' + '' Table '' + ' + '@TableCount' + ' + '')'', null, ' + '''' + @Module + ''', ' + '''' + @Client + ''') end'

 select @String = 'declare  @Client nvarchar(50), @Module nvarchar(50), @TableCount nvarchar(50), @FileCount nvarchar(50), @ProcessId integer select @TableCount = isnull((select count(*) from ' + @Name + '), 0)' +
                  ' select @FileCount = isnull((select RecordCount from msit_RecordCounts where Client = ''' + @Client + ''' and [Module] = ''' + @Module + ''' and DataFileName = ''' + @DataFileName + '''' +
                  ' and DtTm = (select max(DtTm) from msit_RecordCounts where Client = ''' + @Client + ''' and [Module] = ''' + @Module + ''' and DataFileName = ''' + @DataFileName + ''')), 0)' +
                  ' select @ProcessId = (select isnull(max(ProcessId), 0) + 1 from mst_ProcessLog)' +
                  ' if @TableCount = @FileCount begin insert into mst_ProcessLog values (getdate(), @ProcessId, ''CHECK COUNTS'', ''OK in ' + @Name + 
                  ' (File '' + ' + '@FileCount' + ' + '' Table '' + ' + '@TableCount' + ' + '')'', null, ' + '''' + @Module + ''', ' + '''' + @Client + ''') end' +
                  ' else begin insert into mst_ProcessLog values (getdate(), @ProcessId, ''CHECK COUNTS'', ''Discrepancy in ' + @Name + 
                  ' (File '' + ' + '@FileCount' + ' + '' Table '' + ' + '@TableCount' + ' + '')'', null, ' + '''' + @Module + ''', ' + '''' + @Client + ''') raiserror (''Record count error'', 16, 1) end'


 exec (@String)

 set @Error = @@ERROR

 if @Error <> 0
  begin
   set @ErrorCount     = @ErrorCount + 1
  
   set @Phase          = 'ERROR'
   set @ErrorCode      = 170
   set @Process        = (select [Description] from mst_ErrorCodes ec where ec.ErrorCode = @ErrorCode)
   set @StopProcessing = (select StopProcessing from mst_ErrorCodes ec where ec.ErrorCode = @ErrorCode) 
      
   exec msp_ProcessLog @Phase, @Process, null, @Module, @Client
      
  end

 fetch
  CheckCounts
 into
  @Name, 
  @DataFileName
end

close CheckCounts
deallocate CheckCounts

if @ErrorCount > 0
 begin
  set @Phase          = 'ERROR'
  set @ErrorCode      = 1000
  set @Process        = @ProcedureName + ': ' + (select [Description] from mst_ErrorCodes ec where ec.ErrorCode = @ErrorCode)
  set @StopProcessing = (select StopProcessing from mst_ErrorCodes ec where ec.ErrorCode = @ErrorCode) 
 
  exec msp_ProcessLog @Phase, @Process, null, @Module, @Client

  raiserror (@Process, 16, 1)
 end

set @Phase          = 'END'
exec msp_ProcessLog @Phase, @Process, null, @Module, @Client


GO
/****** Object:  StoredProcedure [dbo].[msp_CommissionStatement]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


CREATE procedure [dbo].[msp_CommissionStatement]
	@Client		varchar(50),						--MPC:21/01/2010
	@Module		varchar(50),						--MPC:21/01/2010
	@Mode		varchar(4)		--'FULL' or 'MOVE'	--MPC:21/01/2010

as
--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : msp_CommissionStatement.sql
-- Owner   : CTT
-- Created : 26/10/2005
--
-- Call as 
--	msp_CommissionStatement 'Openwork', 'Open Access','MOVE'
-- OR
--	msp_CommissionStatement 'Openwork', 'Open Access','FULL'
--
--########################################################################

/*
	RH [openwork] 24 jan 2007
	CR 226 - Exclude Declined Authorisations
	CR 229 - Mortgage Early Payments
*/

/*
	MC [openwork] 06 Feb 2007
	CR 236 - Ensure BusinessCode set to UID with AgentType 2, 46 or 49
*/

/*
	MC [openwork] 09 Feb 2007
	CR 239 - Repost BACS entries dated 12/02/2007 to January 2007 period (dated 01/02/2007)
*/

/*
	WI260 Mike Cawood 23/03/2007
	Amendment to derivation of CreateDate and INIssued
	Amendment to zeroise Still to Accrue on earlier payments in same Month
*/

/*
	Mike Cawood 08/06/2007
	Ticket 140 Remove Create Dates override introduced in WI260
	Ticket 143 Assign Mortgage Overrides based on Product code not Provider
*/

/*
	Mike Cawood 11 July 2007
	Repost BACS entries dated 11/07/2007 to June 2007 period (dated 01/07/2007)
*/

/*
	Mike Cawood 18 July 2007
	Open Access - Treat Type 17 Adjustments as APE/NBI movements for IT and SP Accrual cases

	Mike Cawood 25 July 2007 
	Ticket 205 - Fix missing Still to Accrue issue for split commission cases.

	Mike Cawood 14 August 2007
	OW239 - Warehouse cleanup - Revised APE processing so that only set when NBI changes significantly

	Richard Highes - September 2007
	Performance Improvements 
	Perform all processing on internal tables and then table inserts at end of procedure.

	Mike Cawood - 21 September 2007
	Ticket 108 - Default Basis to Accrual if CommType is NULL on mstt_policytransactions
	Fix indeterminate CommissionsID issue - sort entries to ensure consistent ID applied

	Mike Cawood - 13 December 2007
	Post entries created after BACS run on 12:45 on 12 Dec'07 to December period
	Period end date originally 11 Dec'07 but moved due to Swift processing delays

	Mike Cawood - 20 December 2007
	Amend processing to derive correct BusinessCode where TASHH missing or invalid.
	Use DefaultValue = 1 entries only and find owner using Transaction Proposal Date
	or (if manual payment) using Payment Create Date.

	Alan Groves - 23 January 2008
	Performance improvement:
	1)  Drop indexes after TRUNCATE and re-create them after INSERT to make INSERT faster.
	2)  Introduce index IX_AgentCode to make proc msp_OpenworkAdviserListingSwift faster.

	Alan Groves - 30 January 2008
	Performance improvement:
	1)  Drop non-clustered indexes before the clustered index to avoid unnecessary update
		to the non-clustered indexes immediately prior to them being dropped.

	Mike Cawood 19 February 2008 Ref 08/06785
	Include Manager Payments to ensure that payments linked to Seller who has subsequently become a Manager 
	are not dropped. Also include Company Secretary (44) as Seller type.

	Mike Cawood 29 February 2008 
	1)  Move TOTDUE calculation closer to Swift logic as used in CommCalculateCurrentInitialCommission.
            BI Ignores Negative Movements as attempting to show Original Amount due.
	1)B Ensure TOTDUE Ignores IC Payments linked to Adjustment (type 17) with same DATE_DUE to avoid double
	    counting
	2)  For cases where product uses Gross Fee for Turnover (defined on Product Hierarchy) use Actual DA 
	    received to derive APE (applying AgentSplit).
	3)  Add ExpectationID to NBI Table.
	4)  Ensure NBI sign is aligned with Payment Amount.
