 #msit_CommissionStatement
set 
--Ticket143 EnhancementRate = case CommProviderCode when 'MORTGAGE' then 0 else FranchiseUpliftRate/100 end
 EnhancementRate = case when ph.productgroupcode = 3 then 0 else FranchiseUpliftRate/100 end	--Ticket143
from #msit_CommissionStatement cs
inner join mstt_producthierarchy ph on ph.productcode = cs.productcode		-- Ticket143
where 
 cs.CommissionType not in ('4','10','15','16','18','19') and 
 cs.EnhancementRate < = '0' and 
 cs.FranchiseUpliftRate >= '100' 
 
