-- PR 24/03/2010 Code moved from here to just below fix of 04/11/2008

-- Fix by AG 11/06/08.  The BACS payment of 10 June 2008 ran fully
-- after midnight and so ran on 11 June 2008.  11 June was the start
-- of the next period so the Account Statements on Open Access show 
-- a credit closing balance for the previous period (10/06/08) as it 
-- looks like the franchise hasn't been paid at the end of the period.

--update cs
--   set	BACSDate	= '10 Jun 2008',			-- From '11 Jun 2008' 
--		CreateDate	= '10 Jun 2008',			-- from '11 Jun 2008'
--		PaymentDate = '10 Jun 2008',			-- from '11 Jun 2008'
--		Month		= '1 Jun 2008'				-- From '1 Jul 2008'
--   from #msit_CommissionStatement cs
--   where cs.ReportingClassDesc = 'Payments To Bank'
--	and	cs.CreateDate = '11 Jun 2008'


-- AG 04/11/08 start
-- Pre-emptive fix in case monthly pay run on 11/11/08
-- runs past midnight and falls into the next period.
-- This is a generic fix and will fix the 11 Jun 08
-- problem plus all future occurrences.

--Upd #53

/* PR 25/03/2010 Comment out this code and replace with code below.  Cater for changes to all ReportingClassCodes
update	cs
   set	BACSDate	= cs.PaymentDate - 1,												-- Make date the day before 
		CreateDate	= cs.PaymentDate - 1,												-- Make date the day before 
		PaymentDate = cs.PaymentDate - 1												-- Make date the day before 
																					    -- PR 24/03/2010 Comment out the line below as not needed
	--	Month		= convert(datetime,convert(varchar(6),cs.PaymentDate,112)+'01',112)	-- Make 1st of month
from	#msit_CommissionStatement cs
where	datepart(hh,cs.BACSDate) between 0 and 6										-- BACS Date between midnight and 6am so overrun assumed
and		cs.BACSDate > '1 Jun 2008'														-- Fix all BACS overruns from June 08 onwards
and		cs.ReportingClassCode = 4														-- ClassDesc = 'Payments To Bank'

MPC 2011/01/13 PRODFIX
Period covered by this override extend from 0 to 6 (i.e. < 07:00) to 0 to 14 (i.e. < 15:00).
*/
update	cs
   set	BACSDate	= case
						when cs.ReportingClassCode = 4 then cs.PaymentDate - 1
						else cs.BACSDate - 1
					  end,												 
		CreateDate	= case
						when cs.ReportingClassCode = 4 then cs.PaymentDate - 1
						else cs.CreateDate
					  end,
		PaymentDate = case
						when cs.ReportingClassCode = 4 then cs.PaymentDate - 1
						when dateadd(dd,-1, cs.BACSDate) < cs.PaymentDate then dateadd(dd,-1, cs.BACSDate)
						else cs.PaymentDate
					  end												 
from	#msit_CommissionStatement cs
--where	datepart(hh,cs.BACSDate) between 0 and 6		:MPC 2011/01/13					-- BACS Date between midnight and 6am so overrun assumed
where	datepart(hh,cs.BACSDate) between 0 and 14			--:MPC 2011/01/13				-- BACS Date > midnight and < 3pm so overrun assumed
and		cs.BACSDate > '1 Jun 2008'														-- Fix all BACS overruns from June 08 onwards

--  PR 25/03/2010 End
select @RowCount = @@rowcount

--MPC:12/01/2010
set @ProcessMessage = 'Payments To Bank: Datafix to move dates to day earlier = ' + convert(varchar(10), @RowCount)
exec msp_ProcessLog @PhaseStart, @ProcessMessage, null, @ProgressModule, 'Openwork'

