-- Override Create Date for individual Payments on mstt_PaymentsPending
update	cs
   set	CreateDate	= case
						when isdate(cd.Description) = 1 then convert(datetime,cd.Description)
						else cs.CreateDate
					  end												 
from #msit_CommissionStatement cs
inner join dbo.msit_MIWarehouseCodesandDescriptions cd on cs.PendingPaymentId = cd.CODE and cd.ColumnName = 'OA_OverrideCreateDate'
												
select @RowCount = @@rowcount

set @ProcessMessage = 'Create Date Override: Datafix to move Payments by changing Create Date = ' + convert(varchar(10), @RowCount)
exec msp_ProcessLog @PhaseStart, @ProcessMessage, null, @ProgressModule, 'Openwork'
--  MPC: 07/06/2012 - SR162104: END

-- PR 24/03/2010 Start -  Code moved to here from just after where Payments to Bank created.
-- PR 25/03/2010 When BACDate was set earlier (for reportingclasscode 1/2/3) hours/mins/secs
--               were left on the record.  These now to be removed
update 
 #msit_CommissionStatement
set 
 Month = CSP.Month,
 BACSDate = case 
				when ReportingClassCode = 4 then BACSDate
				else dateadd(dd,0,datediff(dd,0,BACSDate))
			end
from
 msit_CommissionStatementPeriods CSP
where
 #msit_CommissionStatement.CreateDate between CSP.PeriodStartDate and CSP.PeriodEndDate


