--Upd #53c	AG 04/09/2015.

--This update is used for setting OAStatus to a value that will stop the payment, 
--standing order, etc. from propagating onto OpenAccess. Note that this suppression
--is enabled/disabled based on the current date - it's not based on any dates 
--associated with the payment.
 
update	cs
	set OAStatus = sc.SelectionType
from	#msit_CommissionStatement cs
		inner join owt_SelectionControl sc
					on sc.KeyValue = cs.PendingPaymentID
					and sc.KeyType = 'PendingPaymentID'
					and sc.Process = 'msp_CommissionStatement'
					and dateadd(dd,0,datediff(dd,0,getdate())) between sc.EffectiveStartDate and sc.EffectiveEndDate

---------------------------------------------------------------------------------

declare @defaultIT	float
	set @defaultIT = 1.00

--Upd #54
update CS			--MPC: 03/05/2012 - SR153273
set
 ProviderCode = PP.ReportingProductProviderCode,
 ProviderName = PP.ReportingProductProviderName ,
 ABCRate	= case 	
			when isnull(PH.RDRType,'') in ('DIRECT','OFPLAT','ONPLAT') then isnull(CD.ShortDescription,'1.00')		 --MPC: 03/05/2012 - SR153273
		  	when CS.FrequencyCode = '6' then			--MPC: 03/05/2012 - SR153273
		    	case 
		     		when PH.SinglePremBasisCode = 'B' then 
				    Round((select top 1 InitialRate from msit_codecommissionshaperatehistory csh where csh.CodeCommissionShapeID = PT.CodeCommissionShapeID order by DateEffective DESC) 
					*(select RebaseCommissionTo from msit_CodeCommissionShape cs where cs.ID = PT.CodeCommissionShapeID) ,4)
		     		when PH.SinglePremBasisCode = 'S' then PH.SinglePremABCRate
		     		else '1'
		    	end
		   	when CS.FrequencyCode = '2' or CS.FrequencyCode = '5' then		--MPC: 03/05/2012 - SR153273
		    	case 
		     		when PH.RegularPremBasisCode = 'B' then 
				    Round((select top 1 InitialRate from msit_codecommissionshaperatehistory csh where csh.CodeCommissionShapeID = PT.CodeCommissionShapeID order by DateEffective DESC) 
					*(select RebaseCommissionTo from msit_CodeCommissionShape cs where cs.ID = PT.CodeCommissionShapeID) ,4)
		     		when PH.RegularPremBasisCode = 'S' or PH.RegularPremBasisCode = 'I' then PH.RegularPremABCRate
		     		else '1'
		    	end
		   	else '1'
                  end,
ABCValue	= case 	
			when isnull(PH.RDRType,'') in ('DIRECT','OFPLAT','ONPLAT') then CS.EXIssued * isnull(CD.ShortDescription,'1.00')		 --MPC: 03/05/2012 - SR153273
		  	when CS.FrequencyCode = '6' then				--MPC: 03/05/2012 - SR153273
		    	case 
		     		when PH.SinglePremBasisCode = 'B' then CS.EXIssued		--MPC: 03/05/2012 - SR153273
		     		when PH.SinglePremBasisCode = 'S' then
					Round(CS.EXIssued *								--MPC: 03/05/2012 - SR153273
					Round(PH.SinglePremABCRate/
  				    	Round((select top 1 InitialRate from msit_codecommissionshaperatehistory csh where csh.CodeCommissionShapeID = PT.CodeCommissionShapeID order by DateEffective DESC) 
					 * (case 
						when (select RebaseForEnhancement from msit_CodeCommissionShape cs where cs.ID = PT.CodeCommissionShapeID) = '1' then 1		
						else			
						   (select RebaseCommissionTo from msit_CodeCommissionShape cs where cs.ID = PT.CodeCommissionShapeID)		
					    end)
					,4),4),2)

                      		else
 					CS.EXIssued				--MPC: 03/05/2012 - SR153273
                     	end
		   	when CS.FrequencyCode = '2' or CS.FrequencyCode = '5' then				--MPC: 03/05/2012 - SR153273
		    	case 
		     		when PH.RegularPremBasisCode = 'B' then
					Round((CS.EXIssued *							--MPC: 03/05/2012 - SR153273
					case
				  	when PT.CommType <> 'T' then @defaultIT 
				  	else (select case when CS.FrequencyCode = '2' then MonthlyIT else AnnualIT end		--MPC: 03/05/2012 - SR153273
					from msit_IndemnityFactors itf where itf.InitialPeriod = CS.InitialPeriod)				--MPC: 03/05/2012 - SR153273
				  	end),2) 
		     		when PH.RegularPremBasisCode = 'S' or PH.RegularPremBasisCode = 'I' then
					Round(Round(CS.EXIssued *					--MPC: 03/05/2012 - SR153273
					Round( PH.RegularPremABCRate / 
  				    	Round((select top 1 InitialRate from msit_codecommissionshaperatehistory csh where csh.CodeCommissionShapeID = PT.CodeCommissionShapeID order by DateEffective DESC) 
					 * (case 
						when (select RebaseForEnhancement from msit_CodeCommissionShape cs where cs.ID = PT.CodeCommissionShapeID) = '1' then 1
						else			
						   (select RebaseCommissionTo from msit_CodeCommissionShape cs where cs.ID = PT.CodeCommissionShapeID)		
					    end)
					,4),4),2) *
					case
				  	when PT.CommType <> 'T' or PH.RegularPremBasisCode = 'I' then @defaultIT 
				  	else (select case when CS.FrequencyCode = '2' then MonthlyIT else AnnualIT end		--MPC: 03/05/2012 - SR153273
						from msit_IndemnityFactors itf where itf.InitialPeriod = CS.InitialPeriod)
					end ,2) 
		     		else CS.EXIssued		--MPC: 03/05/2012 - SR153273
		    	end
		  	else CS.EXIssued			--MPC: 03/05/2012 - SR153273
                  end
 
from #msit_CommissionStatement CS					--MPC: 03/05/2012 - SR153273
 inner join mstt_PolicyTransactions PT on CS.TransactionID = PT.ID			--MPC: 03/05/2012 - SR153273
 inner join mstt_ProductProviders PP on PP.ProductProviderCode = PT.CommCompanyCode			--MPC: 03/05/2012 - SR153273
 inner join mstt_ProductHierarchy PH on PH.productcode = CS.productcode		-- PR:13/05/08		--MPC: 03/05/2012 - SR153273
 left join msit_MIWarehouseCodesandDescriptions CD on CD.ColumnName = 'WH-RDRFeeABCFactor' and CS.[Month] between CD.Code and CD.Description		--MPC: 03/05/2012 - SR153273
 	
