select transactionid,month,agentcode,max(pendingpaymentid) as LastID	-- Ticket 205
into #LastPaymentID
from #msit_CommissionStatement
where FrequencyCode in (2,5) 
and PayBasisCode in ('F','L') 
and CommissionType = '1' 
group by transactionid,month,agentcode		-- Ticket 205
order by transactionid,month,agentcode		-- Ticket 205

