/* 
Ticket 205 - replace current APE processing

-- WI260 set APE to Gross Fees if product is not an APE product for IC and IC Clawback only
-- WI260 Clawback APE is derived as negative value
update 
 #msit_CommissionStatement
set 
 APE = (case when ph.APE_Flag = 'Y' then CO.APE when ph.APE_Flag = 'N' then CO.DistributionAllowance else CO.APE end)
	* (case when CS.Amount < 0 then -1 when CS.Amount > 0 then 1 else 0 end)
from 
 #msit_CommissionStatement CS
 inner join mstt_Commissions CO on CS.CommissionsID = CO.ID
 left outer join mstt_producthierarchy ph on ph.productcode = CO.productcode	-- WI260
where 
 CS.CommissionType in (1,2,17) 
 and  isnull(CS.INIssued,0) <> 0
-- Treat Type 17 movements on SP and IT cases as valid for APE

-- WI260 End of APE Change
*/
/*
Ticket 205 : Fix for Warehouse cleanup

Set APE for first NBI relevant payment on transaction, on any negative payment that reduces total NBI to zero
or on the first NBI relevant payment after NBI reduced to zero (i.e. reinstatement).
NBI relevant payment identified with non-zero INIssued amount.

*/

--Sel #18
select transactionid as TranID,agent_code as Agent,id as CommID,Turnover as TranAPE
into #TranAPE
from mstt_commissions co
where commissiontype = 1
and poltrantranstype <> 39
and agent_code <> 10002
and transactionid in (select distinct transactionid from mstt_expectation)
order by CommID

create table #nbitable (
EXPID int, PPID int,TranID int,Agent varchar(7),CommID int,NBI float,NBITotal float,Amount float,			--MPC :29/02/2008 (3)
APEFlag varchar(1),APE float,APETotal float,TranAPE float)

-- MPC :29/02/2008
-- Calculate TranAPE from Expectation (i.e. Distribution Allowance) for Products where Turnover = Gross Fee (APE_Flag <> 'Y')
-- Otherwise (APE_Flag is null or APE_Flag = 'Y') set TranAPE = DA from Commission Split

--#Ins #1
insert #nbitable(EXPID,PPID ,TranID ,Agent ,CommID ,NBI ,NBITotal ,Amount ,APEFlag ,APE ,APETotal ,TranAPE )		--MPC :29/02/2008 (3)
select ExpectationID,pendingpaymentid,cs.transactionid ,AgentCode,commissionsid,INIssued ,INIssued ,Amount,'N' ,0.00 	--MPC :29/02/2008 (3)
,0.00 ,case when ph.ape_flag <> 'Y' and ex.id is not null and cs.agentsplit > 0 then cast( (ex.amount_rec*(cs.agentsplit/100)) as decimal(15,2)) --MPC :29/02/2008 (2)
else cast(isnull(t1.TranAPE,0) as decimal(15,2)) end									--MPC :29/02/2008 (2)
--,cast(isnull(t1.TranAPE,0) as decimal(15,2)) 										--MPC :29/02/2008 (2)
from #msit_CommissionStatement cs
left outer join #TranAPE t1 on t1.Tranid = cs.transactionid and t1.agent = cs.agentcode
left outer join mstt_producthierarchy ph on ph.productcode = cs.productcode						--MPC :29/02/2008 (2)
left outer join mstt_expectation ex on ex.id = cs.expectationid								--MPC :29/02/2008 (2)
where reportingclasscode = 1 and cs.commissiontype in (1,2,17)
and INissued <> 0
order by cs.transactionid,AgentCode,expectationID,pendingpaymentid							--MPC :29/02/2008 (3)

--Sel #19
select t1.ppid,t1.tranid,t1.agent,sum(isnull(t2.nbi,0)) as PrevNBI
into #PrevNBI
from #NBITable t1
inner join #NBITable t2 on t2.tranid = t1.tranid and t2.agent = t1.agent 
and cast(t2.ppid as decimal(15,0)) < cast(t1.ppid as decimal(15,0))
group by t1.ppid,t1.tranid,t1.agent
order by t1.ppid,t1.tranid,t1.agent

--Upd #58
update #nbiTable
set NBITotal = cast((t1.NBITotal + isnull(t2.PrevNBI,0)) as decimal(15,2)),
APEFlag = case when t2.ppid is null then 'Y' else 'N' end
from #NbiTable t1
left outer join #PrevNBI t2 on t1.tranid = t2.tranid and t1.agent = t2.agent and t1.ppid = t2.ppid

--Upd #59
update #nbitable
set APEFlag = 'Z' 
--where cast(NBITotal as decimal(15,2)) = 0									--MPC :29/02/2008 (4)			
from #nbitable t1															--MPC :29/02/2008 (4)	
left outer join #PrevNBI t2 												--MPC :29/02/2008 (4)
on t1.tranid = t2.tranid and t1.agent = t2.agent and t1.ppid = t2.ppid		--MPC :29/02/2008 (4)
where cast(t1.NBITotal as decimal(15,2)) = 0 and APEFlag = 'N' 				--MPC :29/02/2008 (4)
and cast(isnull(t2.prevnbi,0) as decimal(15,2)) > 0							--MPC :29/02/2008 (4)

--Upd #60
update #nbiTable															--MPC :29/02/2008 (4)
set APEFlag = 'R'															--MPC :29/02/2008 (4)
from #NBITable t1															--MPC :29/02/2008 (4)
inner join #PrevNBI t2 on t1.tranid = t2.tranid and t1.agent = t2.agent and t1.ppid = t2.ppid		--MPC :29/02/2008 (4)
where t2.PrevNBI < 0 and t1.NBITotal > 0 and APEFlag = 'N'					--MPC :29/02/2008 (4)
and t1.TranID in (select distinct TranID From #NBITable where APEFlag = 'C')--MPC :29/02/2008 (4)

--Upd #61
update #nbiTable
set APE = (case when t1.APEFlag in ('C','R','Y','Z') and Amount < 0 then -1*t1.TranAPE		--MPC :29/02/2008 (4)
		when t1.APEFlag in ('C','R','Y','Z') and Amount > 0 then t1.TranAPE	--MPC :29/02/2008 (4)
--set APE = (case when t1.APEFlag = 'Z' and Amount < 0 then -1*t1.TranAPE	--MPC :29/02/2008 (4)
--		when t1.APEFlag = 'Z' and Amount > 0 then t1.TranAPE				--MPC :29/02/2008 (4)
--		when t1.APEFlag = 'Y' and Amount < 0 then -1*t1.TranAPE 			--MPC :29/02/2008 (4)
--		when t1.APEFlag = 'Y' and Amount > 0 then t1.TranAPE 				--MPC :29/02/2008 (4)
		else 0 end)
from #NBITable t1
where t1.tranape <> 0 and t1.APEFlag in ('C','R','Y','Z')					--MPC :29/02/2008 (4)

--Sel #20
select t1.ppid,t1.tranid,t1.agent,sum(isnull(t2.ape,0)) as PrevAPE
into #PrevAPE
from #NBITable t1
inner join #NBITable t2 on t2.tranid = t1.tranid and t2.agent = t1.agent 
and cast(t2.ppid as decimal(15,0)) < cast(t1.ppid as decimal(15,0))
group by t1.ppid,t1.tranid,t1.agent
order by t1.ppid,t1.tranid,t1.agent

--Upd #62
update #nbiTable
set APETotal = cast((t1.APE + isnull(t2.PrevAPE,0)) as decimal(15,2))
from #NbiTable t1
left outer join #PrevAPE t2 on t1.tranid = t2.tranid and t1.agent = t2.agent and t1.ppid = t2.ppid

--Upd #63
update #nbitable
set APEFlag = 'X', 
    APE = (case when Amount < 0 then -1*t1.TranAPE when Amount > 0 then t1.TranAPE else 0 end)		--MPC :29/02/2008 (4)
--where NBITotal <> 0 and cast(APETotal as decimal(15,2)) = 0 and APEFlag = 'N' and TranAPE <> 0	--MPC :29/02/2008 (4)
from #NBITable t1														--MPC :29/02/2008 (4)
inner join #PrevNBI t2 on t1.tranid = t2.tranid and t1.agent = t2.agent and t1.ppid = t2.ppid					--MPC :29/02/2008 (4)
where (cast(t1.NBITotal as decimal(15,2)) > 0 and cast(t2.PrevNBI as decimal(15,2)) <= 0 and Amount > 0 and APEFlag = 'N') 	--MPC :29/02/2008 (4)
or (cast(t1.NBITotal as decimal(15,2)) < 0 and cast(t2.PrevNBI as decimal(15,2)) >= 0 and Amount < 0 and APEFlag = 'N') 	--MPC :29/02/2008 (4)

--update #nbiTable															--MPC :29/02/2008 (4)
