left outer join #PrevAPE2 t2 on t1.tranid = t2.tranid and t1.agent = t2.agent and t1.ppid = t2.ppid	--MPC :29/02/2008 (4)
where cast(t1.apetotal as decimal(15,2)) < 0 and cast(t1.nbitotal as decimal(15,2)) >= 0 		--MPC :29/02/2008 (4)
and t1.apeflag = 'Z' and t1.APE <> 0										--MPC :29/02/2008 (4)

--Upd #68
select t1.ppid,t1.tranid,t1.agent,sum(isnull(t2.ape,0)) as PrevAPE			--MPC :29/02/2008 (4)
into #PrevAPE3																--MPC :29/02/2008 (4)
from #NBITable t1															--MPC :29/02/2008 (4)
inner join #NBITable t2 on t2.tranid = t1.tranid and t2.agent = t1.agent 	--MPC :29/02/2008 (4)
and cast(t2.ppid as decimal(15,0)) < cast(t1.ppid as decimal(15,0))			--MPC :29/02/2008 (4)
group by t1.ppid,t1.tranid,t1.agent											--MPC :29/02/2008 (4)
order by t1.ppid,t1.tranid,t1.agent											--MPC :29/02/2008 (4)

--Upd #69
update #nbiTable															--MPC :29/02/2008 (4)
set APETotal = cast((t1.APE + isnull(t2.PrevAPE,0)) as decimal(15,2))		--MPC :29/02/2008 (4)
from #NbiTable t1															--MPC :29/02/2008 (4)
left outer join #PrevAPE3 t2 on t1.tranid = t2.tranid and t1.agent = t2.agent and t1.ppid = t2.ppid	--MPC :29/02/2008 (4)

--Upd #70
update #msit_CommissionStatement
set APE = t1.APE
from #NBITable t1 
inner join #msit_CommissionStatement cs on cs.pendingpaymentid = t1.ppid
where t1.APE <> 0

drop table #tranAPE
drop table #nbitable
drop table #prevnbi
drop table #prevape
drop table #prevape2
drop table #prevape3															--MPC :29/02/2008 (4)

set @ProcessMessage = 'ApplyAPE'												--MPC:21/01/2010
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client	--MPC:21/01/2010

--End of APE Processing


/*===========================================================================================
    ELITE Points processing - up to and including commission month December 2014.
===========================================================================================*/

-- AG 12/03/2014 Start

set @ProcessMessage = 'Obtain Agent Uplifts'		
exec msp_ProcessLog @PhaseStart, @ProcessMessage, null, @ProgressModule, @Client

-- Obtain all the details needed to be able to look up the firm's uplift for the product

select
		cs.BusinessCode as EnterpriseUID,
		cs.TransactionID,
		cs.ProductCode,
		pt.ProposalDate
into	#TxnUpliftMatches
from	#msit_CommissionStatement cs
		inner join mstt_PolicyTransactions pt on pt.ID = cs.TransactionID
where	cs.ReportingClassCode = 1


-- Derive the ApplicableDateInForce for the transaction

select	tum.TransactionID,
		tum.EnterpriseUID, 
		tum.ProductCode,
		max(DateInForce) as ApplicableDateInForce,
		convert(decimal(8,2),null) as UpliftRate
into	#TxnUpliftValues
from	#TxnUpliftMatches as tum
		left join sa_swift_Agentuplifts au 
			on  au.AgentCode = tum.EnterpriseUID 
			and au.ProductCode = tum.ProductCode 
			and au.AuthorisedDate is not null 
			and au.DateInForce <= tum.ProposalDate 
			and au.Status = 0
group	by  tum.TransactionID,
			tum.EnterpriseUID,
			tum.ProductCode


-- Using the ApplicableDateInForce, look up the uplift for the firm and product

update tuv
	set UpliftRate = au.UpliftRate
from	#TxnUpliftValues tuv
		inner join msit_AgentUplifts au
					on au.AgentCode = tuv.EnterpriseUID
					and au.ProductCode = tuv.ProductCode
					and au.DateInForce = tuv.ApplicableDateInForce
					
select @RowCount = @@rowcount
set @ProcessMessage = 'Obtain Agent Uplifts : Count = ' + convert(varchar(10), @RowCount)		
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client

-- AG 12/03/2014 End

set @ProcessMessage = 'Derive ELITE Factors - Up To Dec 2014'												
exec msp_ProcessLog @PhaseStart, @ProcessMessage, null, @ProgressModule, @Client
					
--SR207107: MPC 11/03/2013 - START: Derive Elite Point Factors
UPDATE #msit_Commissionstatement
SET
Elite_Initial = case when cs.PayBasisCode = 'L' and cs.SchemeNum is not null	-- AG 10/10/2014
				then
					case 
					when cs.commissiontype in (1,2,17) and ph.rdrtype is null and ph.StructuredProduct = 'Y' then round(isnull(cs.EXAccrued * EF1.FACTOR * EF1.Multiplier,0),4)
					when cs.commissiontype in (1,2,17) and ph.rdrtype is null and ph.ProductGroupCode  = '2' then round(isnull(cs.EXAccrued * EF2.FACTOR * EF2.Multiplier,0),4)
					when cs.commissiontype in (1,2,17) and ph.rdrtype is null and ph.ProductGroupCode  = '5' then round(isnull(cs.EXAccrued * EF3.FACTOR * EF3.Multiplier,0),4)
					when cs.commissiontype in (1,2,17) and ph.rdrtype is null and ph.ProductGroupCode  = '1' then round(isnull(cs.EXAccrued * EF4.FACTOR * EF4.Multiplier,0),4)
					when cs.commissiontype in (1,2,17) and ph.rdrtype is null and ph.ProductGroupCode  = '3' then round(isnull(cs.EXAccrued * EF5.FACTOR * EF5.Multiplier,0),4)
					when cs.commissiontype in (1,2,17) and ph.rdrtype is null and ph.ProductGroupCode  = '6' then round(isnull(cs.EXAccrued * EF6.FACTOR * EF6.Multiplier,0),4)
					when cs.commissiontype in (1,2,17) and ph.rdrtype is not null then round(isnull(cs.BaseAmount * EF7.FACTOR * EF7.Multiplier,0),4)	-- AG 06/03/2014
					else 0 
					end
				else
					case 
					when cs.commissiontype in (1,2,17) and ph.rdrtype is null and ph.StructuredProduct = 'Y' then round(isnull(cs.EXIssued * EF1.FACTOR * EF1.Multiplier,0),4)
					when cs.commissiontype in (1,2,17) and ph.rdrtype is null and ph.ProductGroupCode  = '2' then round(isnull(cs.EXIssued * EF2.FACTOR * EF2.Multiplier,0),4)
					when cs.commissiontype in (1,2,17) and ph.rdrtype is null and ph.ProductGroupCode  = '5' then round(isnull(cs.EXIssued * EF3.FACTOR * EF3.Multiplier,0),4)
					when cs.commissiontype in (1,2,17) and ph.rdrtype is null and ph.ProductGroupCode  = '1' then round(isnull(cs.EXIssued * EF4.FACTOR * EF4.Multiplier,0),4)
					when cs.commissiontype in (1,2,17) and ph.rdrtype is null and ph.ProductGroupCode  = '3' then round(isnull(cs.EXIssued * EF5.FACTOR * EF5.Multiplier,0),4)
					when cs.commissiontype in (1,2,17) and ph.rdrtype is null and ph.ProductGroupCode  = '6' then round(isnull(cs.EXIssued * EF6.FACTOR * EF6.Multiplier,0),4)
					when cs.commissiontype in (1,2,17) and ph.rdrtype is not null then round(isnull(cs.BaseAmount * EF7.FACTOR * EF7.Multiplier,0),4)	-- AG 06/03/2014
					else 0 
					end
				end,
Elite_Ongoing = case
				-- ((c.Agent_Perc /((tuv.UpliftRate-20.0)/100.0)) / ((100.0-isnull(Pot.Agent_Perc,0.0))/100.0) / 100.0) this is the adviser's fee split proportion as entered on OWS
				-- ((cs.Amount/c.Agent_Perc) * 100.0) this gives the total ongoing fee that may be shared by multiple advisers. Viewable in Swift
				when cs.commissiontype in (4,15,18,10,16,19) and ph.rdrtype is not null and Pot.Agent_Perc = 100 then 0 -- PR 22/8/14
				when cs.commissiontype in (4,15,18,10,16,19) and ph.rdrtype is not null then round(isnull(((c.Agent_Perc /((tuv.UpliftRate-20.0)/100.0)) / ((100.0-isnull(Pot.Agent_Perc,0.0))/100.0) / 100.0) * ((cs.Amount/c.Agent_Perc) * 100.0) * EF8.FACTOR * EF8.Multiplier,0),4)		-- AG 12/03/2014
				when cs.commissiontype in (10,16,19) and ph.rdrtype is null and SCP.KeyValue is not null then round(isnull(cs.Amount * EF11.FACTOR * EF11.Multiplier,0),2)
				else 0 end,
Elite_NSC	  = case
				when cs.commissiontype in (4,15,18,10,16,19) and ph.rdrtype is not null and Pot.Agent_Perc = 100 then 0 -- PR 22/8/14
				when cs.commissiontype in (4,15,18,10,16,19) and ph.rdrtype is not null then	-- AG 12/03/2014
						-- ((c.Agent_Perc /((tuv.UpliftRate-20.0)/100.0)) / ((100.0-isnull(Pot.Agent_Perc,0.0))/100.0) / 100.0) this is the adviser's fee split proportion as entered on OWS
						round(isnull(((c.Agent_Perc /((tuv.UpliftRate-20.0)/100.0)) / ((100.0-isnull(Pot.Agent_Perc,0.0))/100.0) / 100.0) * isnull(nsc.nsc,0.0) * EF9.FACTOR * EF9.Multiplier,0),4)		-- AG 12/03/2014
				else 0 end,
Elite_NSCFee  = isnull(nsc.NSC,0),
Elite_OMNIS   = case 
				when cs.commissiontype in (4,15,18,10,16,19) and ph.rdrtype is not null then round(isnull(cs.Amount * EF10.FACTOR * EF10.Multiplier,0),4)
				else 0 end,
ELITE_OMNISRatio = OFR.OMNISRatio,
Elite_Category = case 
				when cs.commissiontype in (1,2,17) and ph.rdrtype is null and ph.StructuredProduct = 'Y' then EF1.category
				when cs.commissiontype in (1,2,17) and ph.rdrtype is null and ph.ProductGroupCode  = '2' then EF2.category
				when cs.commissiontype in (1,2,17) and ph.rdrtype is null and ph.ProductGroupCode  = '5' then EF3.category
				when cs.commissiontype in (1,2,17) and ph.rdrtype is null and ph.ProductGroupCode  = '1' then EF4.category
				when cs.commissiontype in (1,2,17) and ph.rdrtype is null and ph.ProductGroupCode  = '3' then EF5.category
				when cs.commissiontype in (1,2,17) and ph.rdrtype is null and ph.ProductGroupCode  = '6' then EF6.category
				when cs.commissiontype in (1,2,17) and ph.rdrtype is not null then EF7.category
				when cs.commissiontype in (4,15,18,10,16,19) and ph.rdrtype is not null then EF8.category
				end
from #msit_Commissionstatement cs
		inner join mstt_Producthierarchy ph on ph.productcode = cs.productcode
		inner join mstt_Policytransactions pt on pt.id = cs.transactionid
		inner join msit_Commissionstatementperiods csp on csp.month = cs.month
		inner join msit_Commissionstatementperiods IssuedMonth on dateadd(dd,0,datediff(dd,0,pt.IssuedDate)) between IssuedMonth.PeriodStartDate and IssuedMonth.PeriodEndDate	-- AG 21/07/2015
		inner join mstt_Agents a on a.Code = cs.AgentCode		-- AG 09/12/2014
		left join mstt_Commissions c							-- AG 12/03/2014 
					on c.TransactionID = cs.TransactionID
					and c.Agent_Code = cs.AgentCode
					and c.CommissionType = 10
		left join owt_SelectionControl SC						-- AG 12/03/2014
					on SC.Process = 'ElitePoints' 
					and SC.KeyType = 'NSCPotCode' 
					and cs.createdate between SC.EffectiveStartDate and SC.EffectiveEndDate
		left join mstt_Commissions pot							-- AG 12/03/2014
					on pot.TransactionID = cs.TransactionID 
					and pot.Agent_Code = sc.KeyValue
					and pot.CommissionType = 10					-- AG 26/08/2014
		left join owt_EliteFactors EF1 on EF1.category = 'STRUCTURED' and csp.year between EF1.startyear and EF1.endyear 
		left join owt_EliteFactors EF2 on EF2.category = 'COMM-INV' and csp.year between EF2.startyear and EF2.endyear 
		left join owt_EliteFactors EF3 on EF3.category = 'COMM-PEN' and csp.year between EF3.startyear and EF3.endyear 
		left join owt_EliteFactors EF4 on EF4.category = 'GI' and csp.year between EF4.startyear and EF4.endyear 
		left join owt_EliteFactors EF5 on EF5.category = 'MCOB' and csp.year between EF5.startyear and EF5.endyear 
		left join owt_EliteFactors EF6 on EF6.category = 'ICOB' and csp.year between EF6.startyear and EF6.endyear 
		left join owt_EliteFactors EF7 on EF7.category = 'COB-FEE' and csp.year between EF7.startyear and EF7.endyear 
		left join owt_EliteFactors EF8 on EF8.category = 'ONGOING' and csp.year between EF8.startyear and EF8.endyear 
		left join owt_EliteFactors EF9 on EF9.category = 'NSC' and csp.year between EF9.startyear and EF9.endyear 
		left join ( Select pp.PACC_ID,sum(pp.amount) as NSC
					From mstt_PaymentsPending PP
					inner join owt_SelectionControl SC on pp.Agent_Code = sc.KeyValue and SC.Process = 'ElitePoints' and SC.KeyType = 'NSCPotCode' and pp.createdatetime between SC.EffectiveStartDate and SC.EffectiveEndDate
					Group by pp.PACC_Id ) NSC on NSC.PACC_ID = cs.ExpectationId
		left join owt_ELITE_OMNISFirmRatios OFR on OFR.BusinessUID = cs.BusinessCode and csp.month between OFR.PeriodStartDate and OFR.PeriodEndDate
		left join owt_EliteFactors EF10 on EF10.category = 'OMNIS' and csp.year between EF10.startyear and EF10.endyear and OFR.OMNISRatio between EF10.RangeFrom and EF10.RangeTo
		left join owt_EliteFactors EF11 on EF11.category = 'TRAIL' and csp.year between EF11.startyear and EF11.endyear 
		left join owt_SelectionControl SCP on pt.commproductcode = SCP.KeyValue and SCP.Process = 'ElitePoints' and SCP.KeyType = 'TrailMargin' and csp.month between SCP.EffectiveStartDate and SCP.EffectiveEndDate
		left join #TxnUpliftValues tuv							-- AG 12/03/2014
						on tuv.TransactionID = cs.TransactionID
						and tuv.EnterpriseUID = cs.BusinessCode
						and tuv.ProductCode = cs.ProductCode
where	cs.reportingclasscode = 1
and		a.Manager2Code <> @OwlManager2Code		-- AG 09/12/2014	Don't calculate for Owl payments
-- AG 21/07/2015 Start
and		((cs.Month < '2015-02-01')				-- Only calculate ELITE using these rules on payments prior to Jan 2015
or		(cs.Month >= '2015-02-01'				-- Payment NORMALLY covered by 2015 rules 
		and IssuedMonth.Month < '2015-02-01'	-- Case issued under old rules
		and cs.commissiontype in (1,2,17)		-- Initial fee
		and cs.PayBasisCode = 'F'				-- Accrual
		and ph.rdrtype is not null				-- COB
		and cs.EXIssued = 0))					-- Not the case's first payment in 2015 rules period
-- AG 21/07/2015 End

set @RowCount = @@ROWCOUNT

set @ProcessMessage = 'Derive ELITE Factors - Up To Dec 2014 = '	+ convert(varchar(20),@Rowcount)
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client

--SR207107: MPC 11/03/2013 - END: Derive Elite Point Factors


/*===========================================================================================
    ELITE Points processing - Commission Month January 2015 onwards
===========================================================================================*/

set @ProcessMessage = 'Derive ELITE Factors - Jan 2015 onwards'												
exec msp_ProcessLog @PhaseStart, @ProcessMessage, null, @ProgressModule, @Client
					
UPDATE #msit_Commissionstatement
SET
Elite_Initial = case 
				when cs.PayBasisCode = 'L' and cs.SchemeNum is not null	-- Special coding for level group scheme payments
				then
					case 
					when cs.commissiontype in (1,2,17) and ph.rdrtype is null and ph.ProductGroupCode  = '5' and abs(e.AMOUNT_REC)*(cs.AgentSplit/100) > abs(cs.INAccrued) then round(isnull((((abs(e.AMOUNT_REC)*(cs.AgentSplit/100)) * case when cs.INIssued < 0 then -1 else 1 end) - cs.INAccrued) * EF3.Multiplier,0),3)	-- commission based pensions
					when cs.commissiontype in (1,2,17) and ph.rdrtype is not null and abs(e.AMOUNT_REC)*(cs.AgentSplit/100) > abs(cs.INAccrued) then round(isnull((((abs(e.AMOUNT_REC)*(cs.AgentSplit/100)) * case when cs.INIssued < 0 then -1 else 1 end) - cs.INAccrued) * EF7.Multiplier,0),3)								-- fee based pensions
					else 0 
					end
				when cs.PayBasisCode = 'T' and cs.SchemeNum is not null	-- Special coding for indemnity group scheme payments
				then
					case 
					when cs.commissiontype in (1,2,17) and ph.rdrtype is null and ph.ProductGroupCode  = '5' and abs(e.AMOUNT_REC)*(cs.AgentSplit/100) > abs(cs.INIssued) then round(isnull((((abs(e.AMOUNT_REC)*(cs.AgentSplit/100)) * case when cs.INIssued < 0 then -1 else 1 end) - cs.INIssued) * EF3.Multiplier,0),3)		-- commission based pensions
					when cs.commissiontype in (1,2,17) and ph.rdrtype is not null and abs(e.AMOUNT_REC)*(cs.AgentSplit/100) > abs(cs.INIssued) then round(isnull((((abs(e.AMOUNT_REC)*(cs.AgentSplit/100)) * case when cs.INIssued < 0 then -1 else 1 end) - cs.INIssued) * EF7.Multiplier,0),3)								-- fee based pensions
					else 0 
					end
				when cs.PayBasisCode = 'F' and cs.SchemeNum is not null	-- Special coding for accrual group scheme payments
				then
					case 
					when cs.commissiontype in (1,2,17) and ph.rdrtype is null and ph.ProductGroupCode  = '5' and cs.INIssued <> 0 and abs(e.AMOUNT_REC)*(cs.AgentSplit/100) * case when cs.InitialPeriod = 0 then 1 else cs.InitialPeriod end > abs(cs.INIssued) then round(isnull((((abs(e.AMOUNT_REC)*(cs.AgentSplit/100) * case when cs.InitialPeriod = 0 then 1 else cs.InitialPeriod end) * case when cs.INIssued < 0 then -1 else 1 end) - (cs.INIssued)) * EF3.Multiplier,0),3)	-- commission based pensions
					when cs.commissiontype in (1,2,17) and ph.rdrtype is not null and cs.INIssued <> 0 and abs(e.AMOUNT_REC)*(cs.AgentSplit/100) * case when cs.InitialPeriod = 0 then 1 else cs.InitialPeriod end > abs(cs.INIssued) then round(isnull((((abs(e.AMOUNT_REC)*(cs.AgentSplit/100) * case when cs.InitialPeriod = 0 then 1 else cs.InitialPeriod end) * case when cs.INIssued < 0 then -1 else 1 end) - (cs.INIssued)) * EF7.Multiplier,0),3)								-- fee based pensions
					else 0 
					end
				else
					case 
					--When the adviser has changed, the AgentSplit can become zero in which case the ELITE points should be zero.
					when cs.AgentSplit = 0 then 0
					--Indemnity payments or SINGLEs or IC Clawbacks or IC adjustments Start
					when (cs.FrequencyCode = 6 or cs.PayBasisCode in ('T') or cs.commissiontype in (2,17)) and cs.commissiontype in (1,2,17) and ph.rdrtype is null and ph.StructuredProduct = 'Y' and cs.INIssued <> 0 and abs(e.AMOUNT_REC*(cs.AgentSplit/100)) >= abs(cs.INIssued) then round(isnull((((abs(e.AMOUNT_REC)*(cs.AgentSplit/100)) * case when cs.INIssued < 0 then -1 else 1 end) - cs.INIssued) * EF1.Multiplier,0),3)
					when (cs.FrequencyCode = 6 or cs.PayBasisCode in ('T') or cs.commissiontype in (2,17)) and cs.commissiontype in (1,2,17) and ph.rdrtype is null and ph.ProductGroupCode  = '2' and cs.INIssued <> 0 and abs(e.AMOUNT_REC*(cs.AgentSplit/100)) >= abs(cs.INIssued) then round(isnull((((abs(e.AMOUNT_REC)*(cs.AgentSplit/100)) * case when cs.INIssued < 0 then -1 else 1 end) - cs.INIssued) * EF2.Multiplier,0),3)
					when (cs.FrequencyCode = 6 or cs.PayBasisCode in ('T') or cs.commissiontype in (2,17)) and cs.commissiontype in (1,2,17) and ph.rdrtype is null and ph.ProductGroupCode  = '5' and cs.INIssued <> 0 and abs(e.AMOUNT_REC*(cs.AgentSplit/100)) >= abs(cs.INIssued) then round(isnull((((abs(e.AMOUNT_REC)*(cs.AgentSplit/100)) * case when cs.INIssued < 0 then -1 else 1 end) - cs.INIssued) * EF3.Multiplier,0),3)
					when (cs.FrequencyCode = 6 or cs.PayBasisCode in ('T') or cs.commissiontype in (2,17)) and cs.commissiontype in (1,2,17) and ph.rdrtype is null and ph.ProductGroupCode  = '1' and cs.INIssued <> 0 and abs(e.AMOUNT_REC*(cs.AgentSplit/100)) >= abs(cs.INIssued) then round(isnull((((abs(e.AMOUNT_REC)*(cs.AgentSplit/100)) * case when cs.INIssued < 0 then -1 else 1 end) - cs.INIssued) * EF4.Multiplier,0),3)
					when (cs.FrequencyCode = 6 or cs.PayBasisCode in ('T') or cs.commissiontype in (2,17)) and cs.commissiontype in (1,2,17) and ph.rdrtype is null and ph.ProductGroupCode  = '3' and cs.INIssued <> 0 and abs(e.AMOUNT_REC*(cs.AgentSplit/100)) >= abs(cs.INIssued) then round(isnull((((abs(e.AMOUNT_REC)*(cs.AgentSplit/100)) * case when cs.INIssued < 0 then -1 else 1 end) - cs.INIssued) * EF5.Multiplier,0),3)
					when (cs.FrequencyCode = 6 or cs.PayBasisCode in ('T') or cs.commissiontype in (2,17)) and cs.commissiontype in (1,2,17) and ph.rdrtype is null and ph.ProductGroupCode  = '6' and cs.INIssued <> 0 and abs(e.AMOUNT_REC*(cs.AgentSplit/100)) >= abs(cs.INIssued) then round(isnull((((abs(e.AMOUNT_REC)*(cs.AgentSplit/100)) * case when cs.INIssued < 0 then -1 else 1 end) - cs.INIssued) * EF6.Multiplier,0),3)
					when (cs.FrequencyCode = 6 or cs.PayBasisCode in ('T') or cs.commissiontype in (2,17)) and cs.commissiontype in (1,2,17) and ph.rdrtype is not null and cs.INIssued <> 0 and abs(e.AMOUNT_REC*(cs.AgentSplit/100)) >= abs(cs.INIssued) then round(isnull((((abs(e.AMOUNT_REC)*(cs.AgentSplit/100)) * case when cs.INIssued < 0 then -1 else 1 end) - cs.INIssued) * EF7.Multiplier,0),3)
					--Indemnity payments or SINGLEs or IC Clawbacks or IC adjustments End
					--Accruals & Level Start - should be for the full amount on the first payment - not on each initial period payment
					--pt.CommInitialAmount = full DA
					--cs.INIssued = Base Commission X Enh Rate
					when cs.commissiontype in (1) and ph.rdrtype is null and ph.StructuredProduct = 'Y' and cs.INIssued <> 0 and cs.FranchiseUpliftRate < 100 then round(isnull(((abs(pt.CommInitialAmount)*(cs.AgentSplit/100)) - ((abs(pt.CommInitialAmount)*(cs.AgentSplit/100)) * (cs.FranchiseUpliftRate/100))) * (case when cs.INIssued < 0 then -1 else 1 end) * EF1.Multiplier,0),3)	-- commission based structured products
					when cs.commissiontype in (1) and ph.rdrtype is null and ph.ProductGroupCode  = '1' and cs.INIssued <> 0 and cs.FranchiseUpliftRate < 100 then round(isnull(((abs(pt.CommInitialAmount)*(cs.AgentSplit/100)) - ((abs(pt.CommInitialAmount)*(cs.AgentSplit/100)) * (cs.FranchiseUpliftRate/100))) * (case when cs.INIssued < 0 then -1 else 1 end) * EF4.Multiplier,0),3)	-- commission based GI
					when cs.commissiontype in (1) and ph.rdrtype is null and ph.ProductGroupCode  = '3' and cs.INIssued <> 0 and cs.FranchiseUpliftRate < 100 then round(isnull(((abs(pt.CommInitialAmount)*(cs.AgentSplit/100)) - ((abs(pt.CommInitialAmount)*(cs.AgentSplit/100)) * (cs.FranchiseUpliftRate/100))) * (case when cs.INIssued < 0 then -1 else 1 end) * EF5.Multiplier,0),3)	-- commission based MCOB
					--Commission based investments, pensions and protection Start - uses CommBaseAmount.
					when cs.commissiontype in (1) and ph.rdrtype is null and ph.ProductGroupCode  = '2' and cs.INIssued <> 0 and abs(pt.CommInitialAmount)*(cs.AgentSplit/100) > abs(pt.CommBaseAmount)*(cs.AgentSplit/100)*(cs.FranchiseUpliftRate/100) then round(isnull(((abs(pt.CommInitialAmount)*(cs.AgentSplit/100)) - ((abs(pt.CommBaseAmount)*(cs.AgentSplit/100)) * (cs.FranchiseUpliftRate/100))) * (case when cs.INIssued < 0 then -1 else 1 end) * EF2.Multiplier,0),3)	-- commission based investments
					when cs.commissiontype in (1) and ph.rdrtype is null and ph.ProductGroupCode  = '5' and cs.INIssued <> 0 and abs(pt.CommInitialAmount)*(cs.AgentSplit/100) > abs(pt.CommBaseAmount)*(cs.AgentSplit/100)*(cs.FranchiseUpliftRate/100) then round(isnull(((abs(pt.CommInitialAmount)*(cs.AgentSplit/100)) - ((abs(pt.CommBaseAmount)*(cs.AgentSplit/100)) * (cs.FranchiseUpliftRate/100))) * (case when cs.INIssued < 0 then -1 else 1 end) * EF3.Multiplier,0),3)	-- commission based pensions
					when cs.commissiontype in (1) and ph.rdrtype is null and ph.ProductGroupCode  = '6' and cs.INIssued <> 0 and abs(pt.CommInitialAmount)*(cs.AgentSplit/100) > abs(pt.CommBaseAmount)*(cs.AgentSplit/100)*(cs.FranchiseUpliftRate/100) then round(isnull(((abs(pt.CommInitialAmount)*(cs.AgentSplit/100)) - ((abs(pt.CommBaseAmount)*(cs.AgentSplit/100)) * (cs.FranchiseUpliftRate/100))) * (case when cs.INIssued < 0 then -1 else 1 end) * EF6.Multiplier,0),3)	-- commission based protection
					--Commission based investments, pensions and protection End
					--COB Fee Start - is always a single
					when cs.commissiontype in (1) and ph.rdrtype is not null and cs.INIssued <> 0 and cs.FranchiseUpliftRate < 100 then round(isnull(((abs(pt.CommInitialAmount)*(cs.AgentSplit/100)) - ((abs(pt.CommInitialAmount)*(cs.AgentSplit/100)) * (cs.FranchiseUpliftRate/100))) * (case when cs.INIssued < 0 then -1 else 1 end) * EF7.Multiplier,0),3)	-- fee based COB (investments and pensions)
					--COB Fee End
					-- Accruals & Level End
					else 0 
					end
				end,
Elite_Ongoing = case
				--When the adviser has changed, the AgentSplit can become zero in which case the ELITE points should be zero.
				when cs.AgentSplit = 0 then 0
				when cs.commissiontype in (4,15,18,10,16,19) and ph.rdrtype is not null then round(isnull(((e.AMOUNT_REC * (SFMpot.AGENT_PERC/100.0)) * case when cs.EXAccrued < 0 then -1 else 1 end) * EF11.Multiplier,0),4)	-- was cs.Amount
				--Products that incur trail margin
				--None of these products come in on EDIs. They are keyed manually to Swift and the 20% margin is taken off prior to keying.
				--Thus the margin is 25% of the amount keyed to Swift i.e. 20% of the gross amount.
				--Note EXAccrued is already apportioned for the Agent Split and correctly signed.
				when cs.commissiontype in (10,16,19) and ph.rdrtype is null and SCP.KeyValue is not null then round(isnull(cs.EXAccrued * 0.25 * EF11.Multiplier,0),4)
				else 0 end,
Elite_NSC	  = case
				--When the adviser has changed, the AgentSplit can become zero in which case the ELITE points should be zero.
				when cs.AgentSplit = 0 then 0
				when cs.commissiontype in (4,15,18,10,16,19) and ph.rdrtype is not null then round(isnull(((e.AMOUNT_REC * (pot.AGENT_PERC/100.0)) * case when cs.EXAccrued < 0 then -1 else 1 end) * EF9.Multiplier,0),4)		-- was cs.Amount
				else 0 end,
Elite_NSCFee  = isnull(nsc.NSC,0),
Elite_OMNIS   = case 
				when cs.commissiontype in (4,15,18,10,16,19) and ph.rdrtype is not null then round(isnull(cs.Amount * EF10.FACTOR * EF10.Multiplier,0),4)
				else 0 end,
ELITE_OMNISRatio = OFR.OMNISRatio,
Elite_Category = case 
				when cs.commissiontype in (1,2,17) and ph.rdrtype is null and ph.StructuredProduct = 'Y' then EF1.category + '-2015'	-- AG 21/07/2015
				when cs.commissiontype in (1,2,17) and ph.rdrtype is null and ph.ProductGroupCode  = '2' then EF2.category + '-2015'	-- AG 21/07/2015
				when cs.commissiontype in (1,2,17) and ph.rdrtype is null and ph.ProductGroupCode  = '5' then EF3.category + '-2015'	-- AG 21/07/2015
				when cs.commissiontype in (1,2,17) and ph.rdrtype is null and ph.ProductGroupCode  = '1' then EF4.category + '-2015'	-- AG 21/07/2015
				when cs.commissiontype in (1,2,17) and ph.rdrtype is null and ph.ProductGroupCode  = '3' then EF5.category + '-2015'	-- AG 21/07/2015
				when cs.commissiontype in (1,2,17) and ph.rdrtype is null and ph.ProductGroupCode  = '6' then EF6.category + '-2015'	-- AG 21/07/2015
				when cs.commissiontype in (1,2,17) and ph.rdrtype is not null then EF7.category + '-2015'	-- AG 21/07/2015
				when cs.commissiontype in (4,15,18,10,16,19) and ph.rdrtype is not null then EF8.category + '-2015'	-- AG 21/07/2015
				end
from	#msit_CommissionStatement cs
		inner join mstt_Producthierarchy ph on ph.productcode = cs.productcode
		inner join mstt_Policytransactions pt on pt.id = cs.transactionid
		inner join mstt_Expectation e on e.ID = cs.ExpectationID
		inner join msit_Commissionstatementperiods csp on csp.month = cs.month
		inner join msit_Commissionstatementperiods IssuedMonth on dateadd(dd,0,datediff(dd,0,pt.IssuedDate)) between IssuedMonth.PeriodStartDate and IssuedMonth.PeriodEndDate 
		inner join mstt_Agents a on a.Code = cs.AgentCode
		left join mstt_Commissions c 
					on c.TransactionID = cs.TransactionID
					and c.Agent_Code = cs.AgentCode				-- Adviser's split
					and c.CommissionType = 10
		left join owt_SelectionControl SC
					on SC.Process = 'ElitePoints' 
					and SC.KeyType = 'NSCPotCode' 
					and cs.createdate between SC.EffectiveStartDate and SC.EffectiveEndDate
		left join mstt_Commissions pot
					on pot.TransactionID = cs.TransactionID 
					and pot.Agent_Code = sc.KeyValue
					and pot.CommissionType = 10
		left join owt_SelectionControl SFMPC						
					on SFMPC.Process = 'ElitePoints' 
					and SFMPC.KeyType = 'ServicingFeeMarginPotCode' 
					and cs.createdate between SFMPC.EffectiveStartDate and SFMPC.EffectiveEndDate
		left join mstt_Commissions SFMpot							
					on SFMpot.TransactionID = cs.TransactionID 
					and SFMpot.Agent_Code = SFMPC.KeyValue
					and SFMpot.CommissionType = 10					
		left join owt_EliteFactors EF1 on EF1.category = 'STRUCTURED' and csp.year between EF1.startyear and EF1.endyear 
		left join owt_EliteFactors EF2 on EF2.category = 'COMM-INV' and csp.year between EF2.startyear and EF2.endyear 
		left join owt_EliteFactors EF3 on EF3.category = 'COMM-PEN' and csp.year between EF3.startyear and EF3.endyear 
		left join owt_EliteFactors EF4 on EF4.category = 'GI' and csp.year between EF4.startyear and EF4.endyear 
		left join owt_EliteFactors EF5 on EF5.category = 'MCOB' and csp.year between EF5.startyear and EF5.endyear 
		left join owt_EliteFactors EF6 on EF6.category = 'ICOB' and csp.year between EF6.startyear and EF6.endyear 
		left join owt_EliteFactors EF7 on EF7.category = 'COB-FEE' and csp.year between EF7.startyear and EF7.endyear 
		left join owt_EliteFactors EF8 on EF8.category = 'ONGOING' and csp.year between EF8.startyear and EF8.endyear 
		left join owt_EliteFactors EF9 on EF9.category = 'NSC' and csp.year between EF9.startyear and EF9.endyear 
		left join ( Select pp.PACC_ID,sum(pp.amount) as NSC
					From mstt_PaymentsPending PP
					inner join owt_SelectionControl SC on pp.Agent_Code = sc.KeyValue and SC.Process = 'ElitePoints' and SC.KeyType = 'NSCPotCode' and pp.createdatetime between SC.EffectiveStartDate and SC.EffectiveEndDate
					Group by pp.PACC_Id ) NSC on NSC.PACC_ID = cs.ExpectationId
		left join owt_ELITE_OMNISFirmRatios OFR on OFR.BusinessUID = cs.BusinessCode and csp.month between OFR.PeriodStartDate and OFR.PeriodEndDate
		left join owt_EliteFactors EF10 on EF10.category = 'OMNIS' and csp.year between EF10.startyear and EF10.endyear and OFR.OMNISRatio between EF10.RangeFrom and EF10.RangeTo
		left join owt_EliteFactors EF11 on EF11.category = 'TRAIL' and csp.year between EF11.startyear and EF11.endyear 
		left join owt_SelectionControl SCP on pt.commproductcode = SCP.KeyValue and SCP.Process = 'ElitePoints' and SCP.KeyType = 'TrailMargin' and csp.month between SCP.EffectiveStartDate and SCP.EffectiveEndDate
where	cs.reportingclasscode = 1
and		a.Manager2Code <> @OwlManager2Code			-- Don't calculate for Owl payments
and	   (cs.Month <= dateadd(yy,1,IssuedMonth.Month)	-- Only calculate ELITE points for up to 12 months after the case has issued
		or
		(cs.SchemeNum is not null)					-- No time limit on group schemes	AG 21/05/2015 (7)
		or
		 cs.commissiontype in (1,2,17)				-- IC is only limited by the initial period which could be up to 48 months
		or 
		 cs.Month >= '2016-02-01')					-- 2016 rules means removal of the 12 months stop rule	AG 03/03/2016
and		cs.Month >= '2015-02-01'					-- Only calculate ELITE using these rules on payments from Jan 2015 onwards
-- AG 21/07/2015 Start
and not	(IssuedMonth.Month < '2015-02-01'			-- Case issued under old rules
		 and cs.commissiontype in (1,2,17)			-- Initial fee
		 and cs.PayBasisCode = 'F'					-- Accrual
		 and ph.rdrtype is not null					-- COB
		 and cs.EXIssued = 0)						-- Not the case's first payment in 2015 rules period
-- AG 21/07/2015 End

set @RowCount = @@ROWCOUNT

set @ProcessMessage = 'Derive ELITE Factors - Jan 2015 onwards = '	+ convert(varchar(20),@Rowcount)
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client


--MPC:21/01/2010  DatabaseUPDATE Changes - START
/*-----------------------------------------------------------------------------------------------
	PERFORM DATABASE UPDATES
-----------------------------------------------------------------------------------------------*/

IF @Mode = 'FULL'	--Full Refresh - Truncate Table, Drop Indexes, Insert then Create Undexes
BEGIN

	truncate table msit_CommissionStatement

	if indexproperty(object_id('msit_CommissionStatement'),'BusinessCode','IndexID') is not null
		DROP  INDEX msit_CommissionStatement.BusinessCode 

	if indexproperty(object_id('msit_CommissionStatement'),'IX_OAReports','IndexID') is not null
		DROP  INDEX msit_CommissionStatement.IX_OAReports

	if indexproperty(object_id('msit_CommissionStatement'),'IX_OAStatus','IndexID') is not null
		DROP  INDEX msit_CommissionStatement.IX_OAStatus

	if indexproperty(object_id('msit_CommissionStatement'),'IX_AgentCode','IndexID') is not null
		DROP  INDEX msit_CommissionStatement.IX_AgentCode

	if indexproperty(object_id('msit_CommissionStatement'),'PendingPaymentId','IndexID') is not null
		DROP  INDEX msit_CommissionStatement.PendingPaymentId

	if indexproperty(object_id('msit_CommissionStatement'),'msit_CommissionStatement_IDX_ID','IndexID') is not null	-- Clustered so drop last
		DROP  INDEX msit_CommissionStatement.msit_CommissionStatement_IDX_ID 

END --  @Mode = 'FULL'

IF @Mode = 'MOVE'		--Delete existing rows in Movements List then Insert new Movements	--MPC:21/01/2010
BEGIN					--MPC:21/01/2010

	--DELETE Movements only
	DELETE FROM msit_CommissionStatement		--MPC:21/01/2010
	WHERE (ReportingClassCode <> 4 AND PendingPaymentID IN (Select ID From #AGMFILChanges))	-- Changed Payment		--MPC 21/01/2010
	   OR (ReportingClassCode = 4  AND BACSExportID IN (Select ID From #BACSChanges))		-- Changed BACS Payment	--MPC 21/01/2010

	select @RowCount = @@rowcount						--MPC:21/01/2010
	set @ProcessMessage = 'Delete Data : Count = ' + convert(varchar(10), @RowCount) 	--MPC:21/01/2010
	exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client		--MPC:21/01/2010

END --@Mode = 'MOVE'		--MPC:21/01/2010

--Main Insert
insert into msit_CommissionStatement(
[AgentCode], [PaymentType], [StandingOrderCode], [StandingOrderDesc], [StandingOrderText], 
[CommissionType], [JournalEntryCode], [JournalEntryDesc], [ReportingClassCode], 
[ReportingClassDesc], [BusinessCode], [SellerName], [FranchiseName], [CommProviderCode], 
[CommProviderDesc], [PaymentDate], [BACSDate], [PaymentStatus], [Amount], [DebitCredit], 
[ExtPolicyNumber], [ClientSurname], [ClientForenames], [ProductCode], [StartDate], 
[FrequencyCode], [FrequencyDesc], [Premium], [CommissionRate], [InitialPeriod], 
[FranchiseUpliftRate], [PayBasisCode], [PayBasisDesc], [CommSacrificeAmt], 
[CommSacrificePct], [AgentSplit], [FranchiseSplit], [CommFeeCode], [CommFeeType], 
[CommReason], [TotDue], [FirstID], [LastID], [ExpectCount], [TotPaid], [AccruedToDate], 
[BaseAmount], [UpliftAmount], [EnhancementRate], [INIssued], [INAccrued], 
[INStilltoAccrue], [INIndemnity], [EXIssued], [EXAccrued], [EXStilltoAccrue], 
[EXIndemnity], [DistributorRef], [DueDate], [AuthDate], [PaidListDate], [AgentPaymentsID], 
[PendingPaymentID], [ExpectationID], [TransactionID], [PolicyID], [ClientID], 
[CommissionsID], [AgtStandingOrderID], [CaseID], [APE], [CreateDate], [Month], -- [ID], 
[ProviderName], [ProviderCode], [SuspendComm], [CommShapeID], [LastAccrualinMonth], [OAStatus], --MPC:16/04/08 SR9
[ABCValue],[ABCRate],[SchemeNum],[BACSExportID]		--MPC: 21/01/2010	-- PR:16/03/09 and 13/05/08
,[ELITE_Initial],[ELITE_Ongoing],[ELITE_NSC],[ELITE_NSCFee],[ELITE_OMNIS],[ELITE_OMNISRatio],[ELITE_Category]		--SR207107: MPC 11/03/2013
)
select 
[AgentCode], [PaymentType], [StandingOrderCode], [StandingOrderDesc], [StandingOrderText], 
[CommissionType], [JournalEntryCode], [JournalEntryDesc], [ReportingClassCode], 
[ReportingClassDesc], [BusinessCode], [SellerName], [FranchiseName], [CommProviderCode], 
[CommProviderDesc], [PaymentDate], [BACSDate], [PaymentStatus], [Amount], [DebitCredit], 
[ExtPolicyNumber], [ClientSurname], [ClientForenames], [ProductCode], [StartDate], 
[FrequencyCode], [FrequencyDesc], [Premium], [CommissionRate], [InitialPeriod], 
[FranchiseUpliftRate], [PayBasisCode], [PayBasisDesc], [CommSacrificeAmt], 
[CommSacrificePct], [AgentSplit], [FranchiseSplit], [CommFeeCode], [CommFeeType], 
[CommReason], [TotDue], [FirstID], [LastID], [ExpectCount], [TotPaid], [AccruedToDate], 
[BaseAmount], [UpliftAmount], [EnhancementRate], [INIssued], [INAccrued], 
[INStilltoAccrue], [INIndemnity], [EXIssued], [EXAccrued], [EXStilltoAccrue], 
[EXIndemnity], [DistributorRef], [DueDate], [AuthDate], [PaidListDate], [AgentPaymentsID], 
[PendingPaymentID], [ExpectationID], [TransactionID], [PolicyID], [ClientID], 
[CommissionsID], [AgtStandingOrderID], [CaseID], [APE], [CreateDate], [Month], -- [ID], 
[ProviderName], [ProviderCode], [SuspendComm], [CommShapeID], [LastAccrualinMonth], [OAStatus], --MPC:16/04/08 SR9
[ABCValue],[ABCRate],[SchemeNum],[BACSExportID]		--MPC: 21/01/2010				-- PR:16/03/09 and 13/05/08
,[ELITE_Initial],[ELITE_Ongoing],[ELITE_NSC],[ELITE_NSCFee],[ELITE_OMNIS],[ELITE_OMNISRatio],[ELITE_Category]		--SR207107: MPC 11/03/2013
from #msit_CommissionStatement						--MPC: 21/01/2010
--ORDER BY ReportingClassCode,PendingPaymentID,AgentPaymentsID,BACSExportID			--MPC 21/01/2010	AG 30/03/2010

select @RowCount = @@rowcount
set @ProcessMessage = 'InsertData : Count = ' + convert(varchar(10), @RowCount)		--MPC:21/01/2010
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client		--MPC:21/01/2010

IF @Mode = 'FULL'	--Full Refresh: Create Undexes	--MPC:21/01/2010
BEGIN												--MPC:21/01/2010

	if indexproperty(object_id('msit_CommissionStatement'),'msit_CommissionStatement_IDX_ID','IndexID') is null	-- Clustered so create first
		CREATE  CLUSTERED INDEX [msit_CommissionStatement_IDX_ID] ON [dbo].[msit_CommissionStatement]([ID]) WITH (DATA_COMPRESSION=PAGE) ON [PRIMARY]

	if indexproperty(object_id('msit_CommissionStatement'),'BusinessCode','IndexID') is null
		CREATE  INDEX [BusinessCode] ON [dbo].[msit_CommissionStatement]([BusinessCode]) WITH (DATA_COMPRESSION=PAGE) ON [PRIMARY]

	if indexproperty(object_id('msit_CommissionStatement'),'IX_OAReports','IndexID') is null
		CREATE  INDEX [IX_OAReports] ON [dbo].[msit_CommissionStatement]([BusinessCode], [ID], [ProductCode]) WITH (DATA_COMPRESSION=PAGE) ON [PRIMARY]

	if indexproperty(object_id('msit_CommissionStatement'),'IX_OAStatus','IndexID') is null
		CREATE  INDEX [IX_OAStatus]  ON [dbo].[msit_CommissionStatement]([OAStatus], [BusinessCode], [Month]) WITH (DATA_COMPRESSION=PAGE) ON [PRIMARY]

	if indexproperty(object_id('msit_CommissionStatement'),'IX_AgentCode','IndexID') is null
		CREATE  INDEX [IX_AgentCode] ON [dbo].[msit_CommissionStatement]([AgentCode]) WITH (DATA_COMPRESSION=PAGE) ON [PRIMARY]

	if indexproperty(object_id('msit_CommissionStatement'),'PendingPaymentId','IndexID') is null
		CREATE  INDEX [PendingPaymentId] ON [dbo].[msit_CommissionStatement]([PendingPaymentId]) WITH (DATA_COMPRESSION=PAGE) ON [PRIMARY]

	set @ProcessMessage = 'CREATE INDEXES'											--MPC:21/01/2010
	exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client	--MPC:21/01/2010

	--Create Indexes

END --  @Mode = 'FULL'

IF @Mode = 'MOVE'											--Update Statistics	--MPC:21/01/2010
BEGIN														--MPC:21/01/2010

	UPDATE STATISTICS msit_CommissionStatement		--MPC:21/01/2010

	set @ProcessMessage = 'UPDATE STATISTICS'										--MPC:21/01/2010
	exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client	--MPC:21/01/2010

END --@Mode = 'MOVE'

--MPC:21/01/2010  DatabaseUPDATE Changes - END

drop table #msit_CommissionStatement

--END
exec msp_ProcessLog @PhaseEnd, @ProcName, null, @Module, @Client		--MPC:21/01/2010
;


