-- Insert Policy Transaction details 

--Upd #19
update cs
set 
 ProductCode = PT.CommProductCode, 
 StartDate = PT.StartDate, 
 FrequencyCode = PT.Frequency, 
 FrequencyDesc = PT.FrequencyDescription, 
 Premium = case when PT.Amount > 0 then PT.Amount else PT.MortgageAmount end, 
 CommissionRate = ROUND(case 
 when CommissionType = '4' and PT.RenewalRate > '0' then PT.RenewalRate 
--Ticket 143 when CommissionType = '1' then case when PT.CommRepProductProviderCode = 'MORTGAGE' then PT.CommBasedOnPercent * 1.25 else PT.CommBasedOnPercent end
when CommissionType = '1' then (case when PT.ProductGroupCode = 3 then PT.CommBasedOnPercent * isnull(srh.Enhancement,1.25) 
                                                        when isnull(PH.RDRType,'') <> '' and ABS(PT.Amount) > 0 then 100*ABS(PT.CommInitialAmount)/ABS(CASE WHEN PT.FREQUENCY = '2' THEN 12 ELSE 1 END * PT.Amount)          --MPC: 03/05/2012 - SR153273
                                                        when isnull(PH.RDRType,'') <> '' then PT.CommBasedOnPercent * (100/(100-isnull(PH.RetentionRateFactor,20)))                     --MPC: 03/05/2012 - SR153273
                                                        else PT.CommBasedOnPercent end)   --Ticket143
else NULL  
 end,2,0), 
 InitialPeriod = PT.CommInitialPeriod, 
 PayBasisCode = PT.CommType,
PayBasisDesc = case
when PT.CommType = 'F' then 'Accr' 
 when PT.CommType = 'T' then 'IT' 
 when PT.CommType = 'L' then 'Level' 
 end, 
-- MPC: 22/03/2010 Start
-- CommSacrificeAmt = case
-- when CommissionType = '1' then PT.CommDeductedAtSource * (AgentSplit / 100)
-- else '0' end 
 CommSacrificeAmt = case
                              when isnull(PH.RDRType,'') <> '' then 0        --MPC: 03/05/2012 - SR153273
                              when CommissionType = '1' and PT.CommDeductedAtSource >= 0.01 then PT.CommDeductedAtSource * (AgentSplit / 100)
                              else 0 end 
-- MPC: 22/03/2010 End
from 
#msit_CommissionStatement cs
inner join mstt_PolicyTransactions PT on PT.ID = cs.TransactionID
left join mstt_ProductHierarchy PH on PH.ProductCode = PT.CommProductCode          --MPC: 03/05/2012 - SR153273
left join sa_swift_CodeCommissionShapeRateHistory srh 
                        on  srh.CodeCommissionShapeID = PT.CodeCommissionShapeID 
                        and srh.DateEffective <= PT.ProposalDate     
where srh.DateEffective =  (
                                                SELECT  MAX(ccsrh.DateEffective) AS DateEffective 
                                                FROM  sa_swift_CodeCommissionShapeRateHistory ccsrh
                                                where ccsrh.CodeCommissionShapeID = PT.CodeCommissionShapeID
                                                and         ccsrh.DateEffective <= PT.ProposalDate
                                                GROUP BY ccsrh.CodeCommissionShapeID      
                                        ) 
or srh.Enhancement is null 


