-- Update CommissionRate 
 
--Sel #6
select 
 PT.[Id], 
 case when isnull(PT.RenewalRate,'0') > '0' then PT.RenewalRate 
 else isnull(CC.RenewalRate,'0') end RenewalRate 
into 
 #CommRate 
from 
 mstt_PolicyTransactions PT, 
( 
select 
 CC2.CodeCommissionShapeID, 
 CC2.RenewalRate 
from 
 msit_CodeCommissionShapeRateHistory CC2, 
( 
select 
 CC.CodeCommissionShapeID, 
 max(CC.DateEffective) DateEffective 
from 
 msit_CodeCommissionShapeRateHistory CC, 
 mstt_PolicyTransactions PT 
where 
 CC.CodeCommissionShapeID = PT.CodeCommissionShapeID and 
 CC.DateEffective < = PT.TransactionDate group by 
 CC.CodeCommissionShapeID 
) CC3 
where 
 CC2.CodeCommissionShapeID = CC3.CodeCommissionShapeID and 
 CC2.DateEffective = CC3.DateEffective 
) CC 
where 
 PT.CodeCommissionShapeID = CC.CodeCommissionShapeID 


--Upd #20
update 
 #msit_CommissionStatement
set 
 CommissionRate = CR.RenewalRate 
from 
 #CommRate CR 
where 
 #msit_CommissionStatement.TransactionID = CR.ID and 
 #msit_CommissionStatement.CommissionType = '4' 
 
drop table 
 #CommRate 
 
--Sel #7
select 
 PT.[Id], 
 isnull(CC.TrailFeeRate,'0') RenewalRate 
into 
 #CommRate1 
from 
 mstt_PolicyTransactions PT, 
( 
select 
 CC2.CodeCommissionShapeID, 
 CC2.TrailFeeRate 
from 
 msit_CodeCommissionShapeRateHistory CC2, 
( 
select 
 CC.CodeCommissionShapeID, 
 max(CC.DateEffective) DateEffective 
from 
 msit_CodeCommissionShapeRateHistory CC, 
 mstt_PolicyTransactions PT 
where 
 CC.CodeCommissionShapeID = PT.CodeCommissionShapeID and 
 CC.DateEffective < = PT.TransactionDate 
group by 
 CC.CodeCommissionShapeID 
) CC3 
where 
 CC2.CodeCommissionShapeID = CC3.CodeCommissionShapeID and 
 CC2.DateEffective = CC3.DateEffective 
) CC 
where 
 PT.CodeCommissionShapeID = CC.CodeCommissionShapeID 
 
--Upd #21
update 
 #msit_CommissionStatement
set 
 CommissionRate = CR.RenewalRate 
from 
 #CommRate1 CR 
where  
 #msit_CommissionStatement.TransactionID = CR.ID and 
 #msit_CommissionStatement.CommissionType = '10' 
 
drop table 
 #CommRate1 
 
