-- Insert IN Calculations 

--Sel #8
select 
 EX.TransactionID, 
 EX.ID, 
 EX.Date_Due, 
-- Amount_Due = case when EX.Adjust in ('1', '2') then EX.Amount_Rec else EX.Amount_Due end,		--:MPC 29/02/2008 (1)
 Amount_Due = case when EX.Status in ('2', '3') and EX.TYPE = 1 then EX.Amount_Rec 		--:MPC 29/02/2008 (1)
		   when EX.Status in ('2', '3') and EX.TYPE = 17 then -1*ABS(EX.Amount_Rec)		--:MPC 29/02/2008 (1)
		   else EX.Amount_Due end,								--:MPC 29/02/2008 (1)
 EX.Status, 
 EX.Adjust,
 EX.Type,
 'N' [Count] 
into 
 #TransExcept 
from 
 mstt_Expectation EX 
where 
 EX.Type = '1'
 OR											--:MPC 29/02/2008 (1)B
 (EX.TYPE = '17' and STATUS in ('2','3'))	--:MPC 29/02/2008 (1)B
order by 
 EX.TransactionID,							--:MPC 29/02/2008 (1)B
 EX.Date_Due, 
 EX.ID 
 
-- select the earliest expectation id for each transaction 
 
--Sel #9
select 
 EX.TransactionID, 
 EX.Date_Due, 
 min(EX.ID) ID 
into 
 #TransExcept2 
from 
 mstt_Expectation EX 
--where 														--:MPC 29/02/2008 (1)B
-- EX.Type = '1'												--:MPC 29/02/2008 (1)B
where															-- PR 13/9/2008
	--EX.Type not in ('4', '15','18','10', '16', '19')			-- PR 13/9/2008
	EX.Type not in ('4', '5','6','15','18','10', '16', '19')    -- PR 4/3/2009
group by 
 EX.TransactionID, 
 EX.Date_Due 
 
-- set the Count field to 'Y' for the earliest Type 1 Expectation found above
-- if earliest payment is Type 17 then set Count to 'A' (not used in Final total)

--Upd #22
update 
 #TransExcept 
set 
 [Count] = case when #TransExcept.TYPE = 1 then 'Y' else 'A' end	--:MPC 29/02/2008 (1)B
from 
 #TransExcept2 TE2 
where 
 #TransExcept.TransactionID = TE2.TransactionID and 
 #TransExcept.Date_Due = TE2.Date_Due and 
 #TransExcept.ID = TE2.ID

--Upd #23
update
 #TransExcept
set
 [Count] = 'X'
where
 Adjust <> 0   and
 [Count] = 'N'

-- for each transaction sum the amount_due for each Count where 'X' and 'Y' 
 
--Sel #10
select 
 TransactionID, 
 sum(Amount_Due) Amount_Due 
into 
 #TransExcept3 
from 
 #TransExcept 
where 
 [Count] in ('X','Y')
group by 
 TransactionID 
 -- update TotDue with the above sum 
 
--Upd #24
update 
 #msit_CommissionStatement
set 
-- PR 3/12/2008 - change calc for Regular Prem ISA
 TotDue = 
			case 
				when productcode = 'ISA' and  FrequencyCode = '2' then Amount * 60 
				else EX.Amount_Due * FranchiseSplit * (AgentSplit / 100) 
			end
from 
 #TransExcept3 EX 
where 
 #msit_CommissionStatement.TransactionID = EX.TransactionID and 
 PayBasisCode < > 'T' and 
 CommissionType = '1' 

--Upd #25
update
 #msit_CommissionStatement
set
 TotDue = TotDue * -1
where
 Amount < 0
 
-- select the earliest ExpectationId for each transaction 
 
--Sel #11
select 
 EX.TransactionID, 
 min(EX.ID) FirstID 
into 
 #Expectations4 
from 
 #TransExcept EX 
where 
 EX.[Count] = 'Y' 
group by 
 EX.TransactionID 
 
-- Update FirstID with the ID above 
 
--Upd #26
update 
 #msit_CommissionStatement
set 
 FirstID = EX4.FirstID 
from 
 #Expectations4 EX4 
where 
 #msit_CommissionStatement.TransactionID = EX4.TransactionID 
 
-- select the latest ExpectationId for each transaction 
 
--Sel #12
select 
 EX.TransactionID, 
 max(EX.ID) LastID 
into 
 #Expectations5 
from 
 #TransExcept EX 
where 
 EX.[Count] = 'Y' 
group by 
 EX.TransactionID 
 
-- Update LastID with the ID above 

--Upd #27
update 
 #msit_CommissionStatement
set 
 LastID = EX5.LastID 
from 
 #Expectations5 EX5 
where 
 #msit_CommissionStatement.TransactionID = EX5.TransactionID 
 
-- count the number of Expectation ID's for each transaction 
 
--Sel #13
select 
 EX.transactionid, 
 count(EX.ID) count 
into 
 #Expectations6 
from 
 #TransExcept EX 
where 
 EX.[Count] = 'Y' 
group by 
 transactionid 
 
