[ReportingClassDesc], [BusinessCode], [SellerName], [FranchiseName], [CommProviderCode], 
[CommProviderDesc], [PaymentDate], [BACSDate], [PaymentStatus], [Amount], [DebitCredit], 
[ExtPolicyNumber], [ClientSurname], [ClientForenames], [ProductCode], [StartDate], 
[FrequencyCode], [FrequencyDesc], [Premium], [CommissionRate], [InitialPeriod], 
[FranchiseUpliftRate], [PayBasisCode], [PayBasisDesc], [CommSacrificeAmt], 
