/****** Object:  StoredProcedure [dbo].[msp_CommissionStatementTest]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE procedure [dbo].[msp_CommissionStatementTest]
with recompile
as

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : msp_CommissionStatementTest.sql
-- Owner   : CTT
-- Created : 26/10/2005
--
--########################################################################

truncate table
 msit_CommissionStatementTest
/*
-------------------------

-- insert details from  mstt_AgentPayments, mstt_PaymentsPending &
-- mstt_Agents

insert into
 msit_CommissionStatementTest
select
 PP.Agent_Code,
 AP.PaymentType,
 PP.StandingOrderCode * 1,
 PP.Notes,
 '',
 PP.CommissionType,
 PP.JournalEntryCode,
 PP.JournalEntryCodeDesc,
 '',
 '',
 case when AG.AgentType in ('3','4','5','43','51') then
 case
 when len(coalesce(PP.StrategicAllianceAgentCode,
 PP.AccessAgentCode,
 PP.FranchiseAgentCode,
 PP.DirectlyAuthorisedAgentCode)) = '0' then
 AG.Firm
 when coalesce(PP.StrategicAllianceAgentCode,
 PP.AccessAgentCode,
 PP.FranchiseAgentCode,
 PP.DirectlyAuthorisedAgentCode) is null then
 AG.Firm
 else
 coalesce(PP.StrategicAllianceAgentCode,
 PP.AccessAgentCode,
 PP.FranchiseAgentCode,
 PP.DirectlyAuthorisedAgentCode)
 end
 else PP.Agent_Code
 end [BusinessCode],
 PP.Manager2Code,
 PP.Manager4Code,
 rtrim(AG.Descn),
 '',
 '',
 '',

convert(datetime,coalesce(AP.PaymentDate,PP.CreateDateTime,'1901-01-01'),103) [PaymentDate],

convert(datetime,isnull(convert(varchar(10),AP.Export_Date,103),'01/01/1901'),103) [BACSDate],

 case
 when AP.Export_Date is null then 'Pending'
 else 'Paid'
 end [PaymentStatus],
 PP.Amount,
 case
 when PP.Amount < '0' then 'D'
 else 'C'
 end [DebitCredit],
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 PP.CommissionType,
 case when PP.CommissionType in ('1','2','17') then 'IC'
      when PP.CommissionType = '3' then 'Adv'
      when PP.CommissionType in ('4','15','18') then 'RC'
      when PP.CommissionType in ('10','16','19') then 'Trail'
      when PP.CommissionType in ('11','12') then 'Adj'
      when PP.CommissionType = '13' then 'Fee'
      when PP.CommissionType in ('15','16') then 'Claw'
      else 'Oth' end,
 case
 when PP.CommissionType in ('1','4','10','13') then 'New'
 when PP.CommissionType in ('2','15','16') then 'Claw'
 else 'Adj'
 end,
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 case when PP.Due_Date < '2006-01-01' then PP.PaymentDueDate else PP.Due_Date end,
 PP.AuthorisedDate,
 AP.PaymentDate,
 AP.ID,
 PP.ID,
 PP.PACC_ID,
 PP.TransactionID,
 '',
 '',
 '',
 PP.StandingOrderId,
 ''
from
 mstt_AgentPayments AP,
 mstt_PaymentsPending PP,
 mstt_Agents AG
where
 AP.AGMID =* PP.ID and
 PP.AGENT_CODE = AG.Code and
 AG.AgentType in ('2','3','4','5','43','46','47','49','51') and
 (PP.CommissionType not in ('0','7','14') or
 (PP.CommissionType in ('0','7','14') and
  isnull(PP.AuthorisedDate,'1901-01-01') <> '1901-01-01'))

----------------------------------------------------

-- Insert StandOrderDesc

update
 msit_CommissionStatementTest
set
 StandingOrderDesc = PP.StandingOrderCodeDesc
from
 msit_CommissionReportingClassCodes CRCC,
 mstt_PaymentsPending PP
where
 msit_CommissionStatementTest.CommissionType = CRCC.SwiftCode and
 msit_CommissionStatementTest.PendingPaymentId = PP.ID and
 CRCC.SwiftField = 'CommissionType' and
 CRCC.ReportingClassCode = 'S'

------------------------------

-- Insert Standing Order Text

update
 msit_CommissionStatementTest
set
 StandingOrderText = SO.Description
from
 msit_CommAgentStandingOrders SO
where
 msit_CommissionStatementTest.AgentCode = SO.AgentCode and
 msit_CommissionStatementTest.AgtStandingOrderID = SO.ID

update
 msit_CommissionStatementTest
set
 StandingOrderText = null
where
 StandingOrderText = ''

----------------------------------------------------

-- Update StandOrderDesc

update
 msit_CommissionStatementTest
set
 StandingOrderDesc = CRCC.SwiftDescription
from
 msit_CommissionReportingClassCodes CRCC
where
 msit_CommissionStatementTest.CommissionType = CRCC.SwiftCode and
 CRCC.SwiftField = 'CommissionType' and
 isnull(msit_CommissionStatementTest.StandingOrderDesc,'X') = 'X' and
 isnull(msit_CommissionStatementTest.StandingOrderText,'X') = 'X'

-----------------------------------------------------------------

-- Insert Reporting Class Code

update
 msit_CommissionStatementTest
set
 ReportingClassCode = isnull(RC.ReportingClassCode,'S')
from
 msit_CommissionReportingClassCodes RC
where
 msit_CommissionStatementTest.CommissionType *= RC.SwiftCode and
 RC.SwiftField = 'CommissionType'

---------------------------------------------------

-- Insert Standing Order details

update
 msit_CommissionStatementTest
set
 ReportingClassCode = RC.ReportingClassCode
from
 msit_CommissionReportingClassCodes RC
where
 msit_CommissionStatementTest.StandingOrderCode *= RC.SwiftCode and
 msit_CommissionStatementTest.ReportingClassCode = 'S' and
 RC.SwiftField = 'StandingOrderCode'

---------------------------------------------------

-- Insert Reporting Class Description details

select distinct
 CO.AGENT_CODE,
 CO.TransactionID,
 CO.ID,
 CO.CommissionType,
 CP.ReportingProductProviderName
into
 #ReportingClassDesc
from
 mstt_Commissions CO,
 mstt_CodeReportingProductProvider CP
where
 CO.CommRepProductProviderCode = CP.ReportingProductProviderCode

update
 msit_CommissionStatementTest
set
 CommissionsID = RC.ID,
 ReportingClassDesc = RC.ReportingProductProviderName
from
 #ReportingClassDesc RC
where
 msit_CommissionStatementTest.AgentCode *= RC.AGENT_CODE and
 msit_CommissionStatementTest.TransactionId *= RC.TransactionID and
 case when msit_CommissionStatementTest.CommissionType in ('2','17') then
'1'
      when msit_CommissionStatementTest.CommissionType in ('15','18') then
'4'
      when msit_CommissionStatementTest.CommissionType in ('16','19') then
'10'
 else msit_CommissionStatementTest.CommissionType end *= RC.CommissionType

drop table
 #ReportingClassDesc

update
 msit_CommissionStatementTest
set
 ReportingClassDesc =
 case
 when ReportingClassCode = '2' then 'Charges'
 when ReportingClassCode = '3' then 'Manual Adjustments'
 when ReportingClassCode = '4' then 'Payment To Bank'
 else 'Uncoded'
 end
where
 ReportingClassCode <> '1'

---------------------------------------------------

-- Insert Franchise Name

select distinct
 AG.Code,
 isnull(AG.TradingName, AG.Descn) FranchiseName
into
 #FranchiseName
from
 mstt_Agents AG

update
 msit_CommissionStatementTest
set
 FranchiseName = FR.FranchiseName
from
 #FranchiseName FR
where
 msit_CommissionStatementTest.BusinessCode *= FR.Code

drop table
 #FranchiseName

----------------------------------------------------------------

-- Insert CommProviderCode

select distinct
 CO.AGENT_CODE,
 CO.TransactionID,
 CO.ID,
 CO.CommRepProductProviderCode,
 PP.CommRepProductProviderName
into
 #CommProdProv
from
 mstt_Commissions CO,
 mstt_ProductProviders PP
where
 CO.ProductProviderCode = PP.ProductProviderCode

update
 msit_CommissionStatementTest
set
 CommProviderCode = CP.CommRepProductProviderCode,
 CommProviderDesc = CP.CommRepProductProviderName
from
 #CommProdProv CP
where
 msit_CommissionStatementTest.CommissionsID *= CP.ID

drop table
 #CommProdProv

-------------------

-- Insert Policy Number

select distinct
 PT.ID,
 PO.Pol_Num,
 PO.Cont_Num,
 PO.PolicyRef
into
 #PolicyNumber
from
 mstt_PolicyTransactions PT,
 mstt_Policies PO
where
 PT.PolicyID = PO.Pol_Num

update
 msit_CommissionStatementTest
set
 ExtPolicyNumber = PN.Cont_Num,
 PolicyID = PN.Pol_Num,
 CaseId = PN.PolicyRef
from
 #PolicyNumber PN
where
 msit_CommissionStatementTest.TransactionID *= PN.ID

drop table
 #PolicyNumber

--------------

-- Insert Client Names

select distinct
 PO.Pol_Num,
 CL.Client_Num,
 CL.Name,
 CL.Firstnames
into
 #ClientNames
from
 mstt_Policies PO,
 mstt_Clients CL
where
 PO.Client_Num = CL.Client_Num

update
 msit_CommissionStatementTest
set
 ClientSurname = CN.Name,
 ClientForenames = CN.Firstnames,
 ClientID = CN.Client_Num
from
 #ClientNames CN
where
 msit_CommissionStatementTest.PolicyID *= CN.Pol_Num

drop table
 #ClientNames

--------------

-- Insert Commission details

update
 msit_CommissionStatementTest
set
 FranchiseUpliftRate = case when
 msit_CommissionStatementTest.CommissionType in
 ('4','10','15','16','18','19') then '100' else CO.FranchiseUpliftPercent
 end,
 AgentSplit = CO.Agent_Perc,
 FranchiseSplit =
 case when CO.DistributionAllowance = '0' then '0'
 else CO.FixedAmount / CO.DistributionAllowance
 end,
 BaseAmount = Co.BaseAmount,
 UpliftAmount = CO.UpliftAmount
from
 mstt_Commissions CO
where
 msit_CommissionStatementTest.CommissionsID = CO.ID

update
 msit_CommissionStatementTest
set
 FranchiseUpliftRate = '100'
where
 FranchiseUpliftRate = '0'

------------------------------------------------

-- Insert Policy Transaction details

update
 msit_CommissionStatementTest
set
 ProductCode = PT.CommProductCode,
 StartDate = PT.StartDate,
 FrequencyCode = PT.Frequency,
 FrequencyDesc = PT.FrequencyDescription,
 Premium = case when PT.Amount > 0 then PT.Amount else PT.MortgageAmount
end,
 CommissionRate =
 case
 when CommissionType = '4' and PT.RenewalRate > '0' then PT.RenewalRate
 when CommissionType = '1' then PT.CommBasedOnPercent
 else ''
 end,
 InitialPeriod = PT.CommInitialPeriod,
 PayBasisCode = PT.CommType,
 PayBasisDesc = case when PT.CommType = 'F' then 'Accr'
                     when PT.CommType = 'T' then 'IT'
                     when PT.CommType = 'L' then 'Level'
                     else '' end,
 CommSacrificeAmt = case when CommissionType = '1' then
PT.CommDeductedAtSource * (AgentSplit / 100) else '0' end
from
 mstt_PolicyTransactions PT
where
 msit_CommissionStatementTest.TransactionID = PT.ID

------------------------------------------------

-- Update CommissionRate

select
 PT.[Id],
 case when isnull(PT.RenewalRate,'0') > '0' then PT.RenewalRate
 else isnull(CC.RenewalRate,'0') end RenewalRate
into
 #CommRate
from
 mstt_PolicyTransactions PT,
(
select
 CC2.CodeCommissionShapeID,
 CC2.RenewalRate
from
 msit_CodeCommissionShapeRateHistory CC2,
(
select
 CC.CodeCommissionShapeID,
 max(CC.DateEffective) DateEffective
from
 msit_CodeCommissionShapeRateHistory CC,
 mstt_PolicyTransactions PT
where
 CC.CodeCommissionShapeID = PT.CodeCommissionShapeID and
 CC.DateEffective <= PT.TransactionDate
group by
 CC.CodeCommissionShapeID
) CC3
where
 CC2.CodeCommissionShapeID = CC3.CodeCommissionShapeID and
 CC2.DateEffective = CC3.DateEffective
) CC
where
 PT.CodeCommissionShapeID = CC.CodeCommissionShapeID

update
 msit_CommissionStatementTest
set
 CommissionRate = CR.RenewalRate
from
 #CommRate CR
where
 msit_CommissionStatementTest.TransactionID = CR.ID and
 msit_CommissionStatementTest.CommissionType = '4'

drop table
 #CommRate

select
 PT.[Id],
 isnull(CC.TrailFeeRate,'0') RenewalRate
into
 #CommRate1
from
 mstt_PolicyTransactions PT,
(
select
 CC2.CodeCommissionShapeID,
 CC2.TrailFeeRate
from
 msit_CodeCommissionShapeRateHistory CC2,
(
select
 CC.CodeCommissionShapeID,
 max(CC.DateEffective) DateEffective
from
 msit_CodeCommissionShapeRateHistory CC,
 mstt_PolicyTransactions PT
where
 CC.CodeCommissionShapeID = PT.CodeCommissionShapeID and
 CC.DateEffective <= PT.TransactionDate
group by
 CC.CodeCommissionShapeID
) CC3
where
 CC2.CodeCommissionShapeID = CC3.CodeCommissionShapeID and
 CC2.DateEffective = CC3.DateEffective
) CC
where
 PT.CodeCommissionShapeID = CC.CodeCommissionShapeID

update
 msit_CommissionStatementTest
set
 CommissionRate = CR.RenewalRate
from
 #CommRate1 CR
where
 msit_CommissionStatementTest.TransactionID = CR.ID and
 msit_CommissionStatementTest.CommissionType = '10'

drop table
 #CommRate1

------------------------------------------------

-- Insert IN Calculations

-- Insert IN Calculations

select
 EX.TransactionID,
 EX.ID,
 EX.Date_Due,
 EX.Amount_Due,
 EX.Status,
 'N' [Count]
into
 #TransExcept
from
 mstt_Expectation EX
where
 EX.Type = '1'
order by
 EX.Date_Due,
 EX.ID

-- select the earliest expectation id for each transaction

select
 EX.TransactionID,
 EX.Date_Due,
 min(EX.ID) ID
into
 #TransExcept2
from
 mstt_Expectation EX
where
 EX.Type = '1'
group by
 EX.TransactionID,
 EX.Date_Due

-- set the Count field to 'Y' for the earliest transactions found above

update
 #TransExcept
set
 [Count] = 'Y'
from
 #TransExcept2 TE2
where
 #TransExcept.TransactionID = TE2.TransactionID and
 #TransExcept.Date_Due = TE2.Date_Due and
 #TransExcept.ID = TE2.ID

-- for each transaction sum the amount_due for each 'Y' count

select
 TransactionID,
 sum(Amount_Due) Amount_Due
into
 #TransExcept3
from
 #TransExcept
where
 [Count] = 'Y'
group by
 TransactionID

-- update TotDue with the above sum

update
 msit_CommissionStatementTest
set
 TotDue = EX.Amount_Due * FranchiseSplit * (AgentSplit / 100)
from
 #TransExcept3 EX
where
 msit_CommissionStatementTest.TransactionID = EX.TransactionID and
 PayBasisCode <> 'T' and
 CommissionType = '1'

-- select the earliest ExpectationId for each transaction

select
 EX.TransactionID,
 min(EX.ID) FirstID
into
 #Expectations4
from
 #TransExcept EX
where
 EX.[Count] = 'Y'
group by
 EX.TransactionID

-- Update FirstID with the ID above

update
 msit_CommissionStatementTest
set
 FirstID = EX4.FirstID
from
 #Expectations4 EX4
where
 msit_CommissionStatementTest.TransactionID = EX4.TransactionID

-- select the latest ExpectationId for each transaction

select
 EX.TransactionID,
 max(EX.ID) LastID
into
 #Expectations5
from
 #TransExcept EX
where
 EX.[Count] = 'Y'
group by
 EX.TransactionID

-- Update LastID with the ID above

update
 msit_CommissionStatementTest
set
 LastID = EX5.LastID
from
 #Expectations5 EX5
where
 msit_CommissionStatementTest.TransactionID = EX5.TransactionID

-- count the number of Expectation ID's for each transaction

select
 EX.transactionid,
 count(EX.ID) count
into
 #Expectations6
from
 #TransExcept EX
where
 EX.[Count] = 'Y'
group by
 transactionid

-- Update ExpectCoutn with the above

update
 msit_CommissionStatementTest
set
 ExpectCount = EX6.Count
from
 #Expectations6 EX6
where
 msit_CommissionStatementTest.TransactionID = EX6.TransactionID

---------------------------------------------------------------

drop table #TransExcept
drop table #TransExcept2
drop table #TransExcept3
drop table #Expectations4
drop table #Expectations5
drop table #Expectations6

-------------------------

select
 Agent_Code,
 transactionId,
 commissiontype,
 sum(amount) amount
into
 #TotPaid
from
 mstt_paymentsPending
group by
 Agent_Code,
 transactionId,
 commissiontype

update
 msit_CommissionStatementTest
set
 TotPaid = TP.amount
from
 #TotPaid TP
where
 msit_CommissionStatementTest.AgentCode = TP.Agent_Code and
 msit_CommissionStatementTest.TransactionID = TP.TransactionID and
 msit_CommissionStatementTest.CommissionType = TP.CommissionType

drop table
 #TotPaid

------------------------------

select
 CS.TransactionID,
 CS.AgentCode,
 CS.ExpectationId,
 CS.PaymentDate,
 CS.PendingPaymentId,
 CS.Amount
into
 #AccruedToDate
from
 msit_CommissionStatementTest CS
where
 CS.PayBasisCode <> 'T' and CS.CommissionType = '1'
order by
 CS.TransactionID,
 CS.AgentCode,
 CS.ExpectationId,
 CS.PaymentDate,
 CS.PendingPaymentId

select
 CS.TransactionID,
 CS.AgentCode,
 CS.ExpectationId,
 CS.PaymentDate,
 CS.PendingPaymentId,
 sum(ATD.Amount) Amount
into
 #AccruedToDate2
from
 msit_CommissionStatementTest CS,
 #AccruedToDate ATD
where
 CS.TransactionID = ATD.TransactionID and
 CS.AgentCode = ATD.AgentCode and
 ATD.ExpectationId <= CS.ExpectationId and
 CS.PayBasisCode <> 'T' and CS.CommissionType = '1'
group by
 CS.TransactionID,
 CS.AgentCode,
 CS.ExpectationId,
 CS.PaymentDate,
 CS.PendingPaymentId
order by
 CS.TransactionID,
 CS.AgentCode,
 CS.ExpectationId,
 CS.PaymentDate,
 CS.PendingPaymentId

update
 msit_CommissionStatementTest
set
 AccruedToDate = ATD2.Amount
from
 #AccruedToDate2 ATD2
where
 msit_CommissionStatementTest.TransactionID = ATD2.TransactionID and
 msit_CommissionStatementTest.AgentCode = ATD2.AgentCode and
 ATD2.PaymentDate = msit_CommissionStatementTest.PaymentDate and
 ATD2.PendingPaymentId = msit_CommissionStatementTest.PendingPaymentId and
 msit_CommissionStatementTest.PayBasisCode <> 'T' and
 msit_CommissionStatementTest.CommissionType = '1'

------------------------------

update
 msit_CommissionStatementTest
set
 CommSacrificePct =
 case
 when TotDue = '0' then 0
 else (CommSacrificeAmt * 100) / TotDue
 end
where
 PayBasisCode <> 'T'

update
 msit_CommissionStatementTest
set
 CommSacrificePct =
 case
 when TotPaid = '0' then 0
 else (CommSacrificeAmt * 100) / TotPaid
 end
where
 PayBasisCode = 'T'

update
 msit_CommissionStatementTest
set
 InIssued = case when ExpectationId = FirstId then TotDue else '0' end
where
 PayBasisCode <> 'T' and
 CommissionType = '1' and
 ExpectCount > '1'

update
 msit_CommissionStatementTest
set
 InIssued = Amount
where
 PayBasisCode <> 'T' and
 CommissionType = '1' and
 ExpectCount = '1'

update
 msit_CommissionStatementTest
set
 InIssued = Amount
where
 PayBasisCode = 'T' and
 CommissionType = '1'

update
 msit_CommissionStatementTest
set
 EnhancementRate = '1'
where
 CommissionType in ('4','10','15','16','18','19')

update
 msit_CommissionStatementTest
set
 EnhancementRate = ((BaseAmount + UpliftAmount) / BaseAmount)
where
 CommissionType not in ('4','10','15','16','18','19') and
 UpliftAmount > '0' and
 BaseAmount > '0'

update
 msit_CommissionStatementTest
set
 EnhancementRate = FranchiseUpliftRate/100
where
 CommissionType not in ('4','10','15','16','18','19') and
 EnhancementRate <= '0' and FranchiseUpliftRate >= '100'

update
 msit_CommissionStatementTest
set
 EnhancementRate = '1'
where
 EnhancementRate = '0'

-----------------

-- Insert Additional IN calculations

update
 msit_CommissionStatementTest
set
 INAccrued = Amount
where
 (PayBasisCode <> 'T' or CommissionType in ('4','10','15','16','18','19'))

update
 msit_CommissionStatementTest
set
 InStillToAccrue =
 case when ExpectationID = LastID then '0' else TotDue - AccruedToDate end
where
 PayBasisCode <> 'T' and
 CommissionType = '1'

update
 msit_CommissionStatementTest
set
 InIndemnity = Amount
where
 PayBasisCode = 'T' and
 CommissionType not in ('4','10','15','16','18','19')

-------------------------------------

-- Insert EX calculations

update
 msit_CommissionStatementTest
set
 EXIssued =
 case
 when EnhancementRate > '0' then INIssued / (EnhancementRate)
 else '0'
 end,
 EXAccrued =
 case
 when EnhancementRate > '0' then INAccrued / (EnhancementRate)
 else '0'
 end,
 EXStillToAccrue =
 case
 when EnhancementRate > '0' then INStillToAccrue / (EnhancementRate)
 else '0'
 end,
 EXIndemnity =
 case
 when EnhancementRate > '0' then INIndemnity / (EnhancementRate)
 else '0'
 end

--------------------------------------------

-- Insert Payments To Bank

insert into
 msit_CommissionStatementTest
select
 a.AgentCode,
 '',
 '',
 '',
 'Payment to Account: ' + convert(varchar,a.AccountNumber) + ' - Sort Code:
' + convert(varchar,a.SortCode),
 '',
 '',
 '',
 '4',
 'Payments To Bank',
 a.AgentCode,
 '',
 '',
 a.AgentDescription,
 isnull(b.TradingName,b.DESCN),
 '',
 '',
 convert(datetime,convert(varchar(10),a.ExportDate,103),103),
 convert(datetime,convert(varchar(10),a.ExportDate,103),103),
 'Paid',
 a.AmountPaid,
 case
 when a.AmountPaid  < '0' then 'C'
 else 'D'
 end,
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 ''
from
 msit_ReportBACSExport a,
 mstt_Agents b
where
 a.AgentCode = b.Code

------------------------

-- insert DistributorRef

update
 msit_CommissionStatementTest
set
 DistributorRef = UserField9
from
 msit_PolicyUserDefinedFields
where
 msit_CommissionStatementTest.PolicyId =
msit_PolicyUserDefinedFields.PolicyId

---------------------------------------


*/


