GO
CREATE PROCEDURE [dbo].[msp_CreateRolesAndUsers] -- WITH RECOMPILE,ENCRYPTION
  @Role     varchar(255),
  @User     varchar(255),
  @Password varchar(255)  /* Param List */
AS
/******************************************************************************
Copyright (C) Moore Stephens Consulting Limited 2005
Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>
*******************************************************************************/
-- PROCEDURE BODY GOES HERE
/*** CURSOR to drop any redundant users ***/ 
DECLARE
@name VARCHAR(100),
@sid UNIQUEIDENTIFIER
DECLARE dbusers CURSOR FOR
  SELECT sid, [name] FROM sysusers 
  WHERE hasdbaccess = 1 AND islogin = 1
OPEN dbusers
FETCH NEXT FROM dbusers INTO @sid, @name
WHILE @@FETCH_STATUS = 0
BEGIN
  IF NOT EXISTS(SELECT * FROM master.dbo.sysxlogins WHERE sid = @sid)
  BEGIN
    IF (@name <> 'dbo')
    BEGIN
      EXEC sp_revokedbaccess @name
      PRINT 'User ' + @name + ' has been removed.'
    END
    ELSE
    BEGIN
      PRINT '*********************************************************************************************'
      PRINT '****** User dbo is not valid, but cannot be removed.  DB owner may need to be updated. ******'
      PRINT '*********************************************************************************************'
    END
  END 
  ELSE
  BEGIN
    PRINT 'User ' + @name + ' exists.'
  END
  FETCH NEXT FROM dbusers INTO @sid, @name
END
CLOSE dbusers
DEALLOCATE dbusers 
IF NOT (EXISTS (SELECT * FROM sysusers WHERE NAME IN (@Role)))
BEGIN
  EXEC sp_addrole @Role,'dbo' 
  PRINT 'Created Role'
END
ELSE
BEGIN
  PRINT 'Role already exists'
END
IF NOT (EXISTS (SELECT * FROM master.dbo.sysxlogins WHERE NAME IN (@User)))
  BEGIN
  EXEC sp_addlogin @User, @Password
  PRINT 'Created login'
  END
ELSE
BEGIN
  EXEC sp_password @new=@Password,@loginame=@User
  PRINT 'Login already exists - password reset'
END
if NOT  (EXISTS (SELECT * FROM sysusers WHERE NAME IN (@User)))
  BEGIN
  EXEC sp_adduser @User, @User, @Role
  PRINT 'Created user'
  END
ELSE
  BEGIN
  PRINT 'User already exists'
  END

GO
