/****** Object:  StoredProcedure [dbo].[msp_DateTimeControl]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[msp_DateTimeControl] -- WITH RECOMPILE,ENCRYPTION
   @Module    nvarchar(50),
   @ClientName  nvarchar(20)
AS
/******************************************************************************
Copyright (C) Moore Stephens Consulting Limited 2005
Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>
*******************************************************************************/
declare @ProcedureName nvarchar(255)
set @ProcedureName = object_name(@@procid)
exec msp_ProcessLog 'START', @ProcedureName, null, @Module, @ClientName
truncate table msdt_CalendarTime
declare
  @EntryTypeId     int,
  @EntryType       nvarchar(20),
  @SourceTable     nvarchar(50),
  @SourceColumn    nvarchar(50),
  @CommandString   nvarchar(4000),
  @MinimumDateTime datetime,
  @MaximumDateTime datetime,
  @AutoCorrect     bit
declare DateTimeControlCursor cursor for
 select
  EntryTypeId,
  EntryType,
  SourceTable,
  SourceColumn,
  AutoCorrect
 from
  mst_DateTimeControl
 where
  ClientName  = @ClientName and
  Active      = 1
 order by
  EntryTypeId
open DateTimeControlCursor 
fetch
 DateTimeControlCursor 
into 
 @EntryTypeId,
 @EntryType,
 @SourceTable,
 @SourceColumn,
 @AutoCorrect
while @@fetch_status = 0
 begin
 if @AutoCorrect = 1
  begin
   set @CommandString = 'declare @EntryTypeId int set @EntryTypeId = ' + convert(nvarchar(10),@EntryTypeId) + 
                        ' update mst_DateTimeControl set MinimumDateTime = (select min(' + @SourceColumn + ') from ' + 
                        @SourceTable +  '), MaximumDateTime = (select max(' + @SourceColumn + ') from ' + 
                        @SourceTable + ') where mst_DateTimeControl.EntryTypeId = @EntryTypeId'
   exec (@CommandString)
  end
 select
  @MinimumDateTime = MinimumDateTime,
  @MaximumDateTime = MaximumDateTime
 from
  mst_DateTimeControl
 where
  ClientName  = @ClientName and
  EntryTypeId = @EntryTypeId
 exec msp_PopulateTimeTables @EntryTypeId, @MinimumDateTime, @MaximumDateTime, @Module, @ClientName
 fetch
  DateTimeControlCursor 
 into 
  @EntryTypeId,
  @EntryType,
  @SourceTable,
  @SourceColumn,
  @AutoCorrect
 end
close DateTimeControlCursor 
deallocate DateTimeControlCursor 
exec msp_ProcessLog 'END', @ProcedureName, null, @Module, @ClientName

GO
/****** Object:  StoredProcedure [dbo].[msp_DeleteUserAccess]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
Create procedure [dbo].[msp_DeleteUserAccess]

as


select *
   into #Delete
   from msct_useraccesscontrol uac
   where exists (select 'x'
            from msdt_adviser adv
            inner join msit_intusers iu on adv.agentcode =
   iu.associatedagent
            inner join mstt_agents ag on ag.code = iu.associatedagent
            where adv.iscurrent = 0
            and adv.adviserid = uac.adviserid
            and 'OPENWORK\' + iu.name = uac.Domainlogin)
   order by 2,1


--Delete the Delegates
  Delete uac
  from msct_useraccesscontrol uac
   inner join #delete t1 on t1.adviserid = uac.adviserid
   inner join msct_usersurrogates sur on sur.surrogateof = t1.domainlogin
   where uac.domainlogin = sur.domainlogin

--Delete the rest
delete msct_useraccesscontrol 
where exists (select 'x' 
    from msdt_adviser adv 
    inner join msit_intusers iu on adv.agentcode = iu.associatedagent 
    inner join mstt_agents ag on ag.code = iu.associatedagent 
    where adv.iscurrent = 0 
    and adv.adviserid = msct_useraccesscontrol.adviserid 
    and 'OPENWORK\' + iu.name = msct_useraccesscontrol.Domainlogin)

Drop Table #Delete

GO
/****** Object:  StoredProcedure [dbo].[msp_FailureBreakdown]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

create procedure [dbo].[msp_FailureBreakdown]

 @ASDCode          nvarchar(50),
-- @ASQMCode       nvarchar(50),
 @COB              nvarchar(50),
 @UserId           nvarchar(50),
 @AllowDelegates   char(1)

as

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : msp_FailureBreakdown.sql
-- Desc    : 
-- Owner   : KS
-- Created : 04/08/2006
-- Amended : 14/08/2006 - MK - Added further security, to ensure that the 
--                             user executing the report is allowed to see
--                             the agent that has been passed in to the proc.
-- Amended : 16/08/2006 - MK - Add function to allow delegate access. That is, allow a user
--                             to impersonate the user to whom they have been given access.
--
--########################################################################


if isnull(@AllowDelegates, 'N') = 'Y'
  set @UserId = (select dbo.msf_SQGetUserDelegatedFrom(@UserId))

if dbo.msf_SQCheckPermissions (@UserId, @ASDCode, 'ASD', 'CURRENT', 1) = 'DENY' 

  SELECT 
  null as [ASDCode],
  null as [COB],
  null as [COBDesc],
  null as [RSMName],
  null as [SAQ],
  null as [CQ],
  null as [Both],
  null as [ReportMonth]
else

begin


  SELECT 
    KPILevel,
    ComplianceCategoryCode,
    QualityTargetTypeCode,
    TargetValue AS SATarget,
    (SELECT 
      TargetValue AS CQTarget
      FROM mstt_QualityTarget
        WHERE
          KPILevel='ALL'
          AND ComplianceCategoryCode=QT.ComplianceCategoryCode
          AND QualityTargetPurposeCode='CQ'
          AND QualityTargetTypeCode='BENCHMARK'
          AND TargetValueTypeCode = 'P') CQTarget
  INTO #tmp_QualityTargets
  FROM 
    mstt_QualityTarget QT
  WHERE
    KPILevel='ALL'
    AND QualityTargetPurposeCode='SA'
    AND QualityTargetTypeCode='BENCHMARK'
    AND TargetValueTypeCode = 'P'





select 
 a.SalesQualityASDLevelCode as [ASDCode],
 a.ComplianceCategoryCode as [COB],
 b.CategoryOfBusiness as [COBDesc],
 a.AgentCode as [RSMCode],
 c.Descn as [RSMName],
 a.SAKPIPercent as [SAQ],
 a.CQKPIPercent as [CQ],
 a.ReportMonth as [ReportMonth]
into  
 #FailuresBreakdown
from
 msv_AgentQualityAggregation a
 left outer join msv_CategoryOfBusiness b on a.ComplianceCategoryCode = b.ComplianceCategoryCode
 inner join mstt_Agents c on a.AgentCode = c.Code
where
 a.kpilevel = 'ASDSummary' and
 a.reportmonth = (select max(reportmonth)
                  from msv_AgentQualityAggregation 
                  where KPILevel = 'ADVISERKPI') and
 a.summaryperiod = 6 and
 a.HierarchyTypeCode = 'Current' and
 (@ASDCode = a.SalesQualityASDLevelCode) -- or @ASQMCode = a.SalesQualitySQMLevelCode)





select 
 [ASDCode] as [ASDCode],
 [COB] as [COB],
 [COBDesc] as [COBDesc],
 [RSMName] as [RSMName],
 count(distinct case when (F.SAQ > (QT.SATarget/100)) then RSMCode end) as [SAQ],
 count(distinct case when (F.CQ > (QT.CQTarget/100)) then RSMCode end) as [CQ],
 count(distinct case when ((F.SAQ > (QT.SATarget/100))and (F.CQ > (QT.CQTarget/100))) then RSMCode end) as [Both],
 [ReportMonth] as [ReportMonth]
from
 #FailuresBreakdown F
 inner join #tmp_QualityTargets QT on QT.ComplianceCategoryCode = F.COB
where
 @COB = COB
group by
 ASDCode,
 COB,
 COBDesc,
 RSMName,
 ReportMonth

 
end



GO
