/****** Object:  StoredProcedure [dbo].[msp_Franchise_AgentDetails]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO



CREATE PROCEDURE [dbo].[msp_Franchise_AgentDetails] -- WITH RECOMPILE,ENCRYPTION
  @UserId nvarchar(50)
AS

/******************************************************************************

Copyright (C) Moore Stephens Consulting Limited 2005

Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
          
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>

*******************************************************************************/


declare @FranchiseList table (OrderBy int, Value varchar(255), Label varchar(255))

insert into @FranchiseList (OrderBy, Value, Label)

select distinct
 1 as OrderBy,
 [Business Name] [value],
 [Business Name] [label]
from
 mst_AgentDetails b,
 msdt_Adviser a, 
 msct_UserAccessControl uac
where 
  b.[Agent UID] =  a.AgentCode
  and a.AdviserId = uac.AdviserId
  and uac.DomainLogin = @UserId

declare @StrippedUser varchar(50)
set @StrippedUser = case when charindex('\', @UserId) = 0 then @UserId
      else substring(@UserId, charindex('\', @UserId)+1, len(@UserId))
      end

declare @UserAgentType int
set @UserAgentType = (select a.AgentType 
      from mstt_Agents a, msit_IntUsers i
      where i.AssociatedAgent = a.Code
      and i.Name = @StrippedUser)

if @UserAgentType is null or @UserAgentType = '55' or @UserAgentType = '53' or @UserAgentType = '52'

  insert into @FranchiseList (OrderBy, Value, Label)
  select
  0 as OrderBy,
  '%' [value],
  'All' [label]

--Finally, select the required list
select  Value,
  Label
from @FranchiseList
order by OrderBy, Label


GO
