/****** Object:  StoredProcedure [dbo].[msp_FranchiseABCLeague]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/*
drop procedure [dbo].[msp_FranchiseABCLeague] 
*/

CREATE PROCEDURE [dbo].[msp_FranchiseABCLeague] 
  /* Param List */
  @CalcLastMonthPositions nchar(1) = 'N'
AS


/******************************************************************************

Franchise League Refresh
========================

Amended by Mike Cawood (February 2008)

From 2008 Franchise Leagues to be sourced from Open Access Commission Table
instead of Sales Fact table (msft_Sales). In addition:

1. Minor change to Agent Hierarchy processing to use entries where Default Flag 
   is ticked (defaultvalue = 1).
2. New Flag to be added to product hierarchy to enable products to be switched 
   on or off for inclusion in League table.
3. Add Product Code and Source to all 3 Franchise League tables.
4. Add EffectiveDate to Current and Previous tables.
5. Empty Previous table if refreshing for first month in Commission Year.
6. Add DefaultValue = 1 checks to Agent Hierarchy processing (0 denotes invalid rows).

ABC Currency
============

Amended by Paul Robathan (April 2008)

1. Sum ABC Value into field Turnover instead of APE

Amended by Paul Robathan (Aug 2008)

1. Include Access Agents where started >= 23 May 2008
*******************************************************************************/

set dateformat dmy


--Get overrides and other info from CodesAndDescriptions spreadsheet.

--Competent Status Overrides
select distinct 
  Code as FranchiseCode,
  Description as CompetentStatus
into #CompetentStatusOverride
from msit_MIWarehouseCodesAndDescriptions
where ColumnName = 'LG-Status'

--Franchise Size Overrides
select distinct 
  Code as FranchiseCode,
  case 
    when Description = 'SOLE' then 1 
    when Description = 'SMALL' then 2
    when Description = 'LARGE' then 10
  else Description  
  end as FranchiseSize 
into #FranchiseSizeOverride
from msit_MIWarehouseCodesAndDescriptions
where ColumnName = 'LG-Size'

--Mergers
select distinct 
  Code as FromFranchiseCode,
  Description as ToFranchiseCode 
into #Merger
from msit_MIWarehouseCodesAndDescriptions
where ColumnName = 'LG-Merge'

--Business Types
select distinct 
  Code as AgentType
into #BusinessAgentType
from msit_MIWarehouseCodesAndDescriptions
where ColumnName = 'LG-AgtType'
and Description = 'Business'

--Seller Types
select distinct 
  Code as AgentType
into #SellerAgentType
from msit_MIWarehouseCodesAndDescriptions
where ColumnName = 'LG-AgtType'
and Description = 'Seller'


--Put other 'Competent' Agents into the #CompetentStatusOverride table
insert into #CompetentStatusOverride
select Code, CompetentStatus
from mstt_Agents a
where CompetentStatus = 1
and not exists (select 'x' from #CompetentStatusOverride c
        where a.Code = c.FranchiseCode)

--Get Current League Month - first commission start date after the value stored in LastMonth
declare @CurrentLeagueMonth datetime
set @CurrentLeagueMonth = (
  select min(PeriodStartDate)
  from msit_commissionstatementperiods
  where PeriodStartDate > (select top 1 LastMonth from mstt_FranchiseABCLeagueTable_Last)
  )

--Get Current Year from commission statement period table :MPC 16/01/2008
declare @CurrentYear int
set @CurrentYear = (select Year from msit_commissionstatementperiods 
         where PeriodStartDate = @CurrentLeagueMonth)

--Determine current end-of-month date value from commission statement periods
declare @EndOfMonthDate datetime
set @EndOfMonthDate = (
  select PeriodEndDate
  from msit_commissionstatementperiods
  where PeriodStartDate = @CurrentLeagueMonth
  )

--Get Current Month from commission statement period table  :MPC 16/01/2008
declare @CurrentMonth datetime
set @CurrentMonth = (select Month from msit_commissionstatementperiods 
         where PeriodEndDate = @EndOfMonthDate)

--Determine first day-of-year date value from commission statement periods
declare @FirstDayThisYear datetime
set @FirstDayThisYear = (
  select min(PeriodStartDate)
  from msit_commissionstatementperiods
  where PeriodStartDate >= convert(datetime, convert(char(4),year(@CurrentLeagueMonth)) + '0101', 112)
  )


--Determine maximum franchise size during the year for each franchise
select code, 
  max(FranchiseSize) as FranchiseSize, 
  -99 as FranchiseSizeId
into #MaxFranchiseSizeForYear
from mstt_AgentsHistory
where ValidToDate >= @FirstDayThisYear
group by Code

--Apply Franchise Size overrides
update m
set FranchiseSize = fso.FranchiseSize
from #MaxFranchiseSizeForYear m
  inner join #FranchiseSizeOverride fso
    on m.Code = fso.FranchiseCode

--Update Franchise size id's from msdt_FranchiseSize table
update m
set FranchiseSizeId = f.FranchiseSizeId
from #MaxFranchiseSizeForYear m
  inner join msdt_FranchiseSize f
    on m.FranchiseSize = f.FranchiseSize

  
select agentcode,max(id) as ID,max(startdate) as StartDate
into #RSM_ValidASD
from msit_agenthierarchyhistory 
where participanttype = 2                   --ASD
and defaultvalue = 1                    --Ticked rows only
and @EndofMonthDate between startdate and isnull(enddate,'31 dec 9999')       --Hierarchy as at Run Date
and agentcode in (select distinct code from mstt_agentshistory where agenttype in (52,53))  --RSM/BQM
group by agentcode
order by agentcode

select agentcode,max(id) as ID,max(startdate) as StartDate
into #Franchise_ValidRSM
from msit_agenthierarchyhistory 
where participanttype = 4             --RSM
and defaultvalue = 1              --Ticked rows only
and @EndofMonthDate between startdate and isnull(enddate,'31 dec 9999') --Hierarchy as at Run Date
and 
agentcode in (select code from mstt_agents where (agenttype in (select distinct AgentType from #BusinessAgentType)   or 
(AgentType = '46' and DateStarted >= '23 May 2008'))  )   --Franchise Agent types in list of business types
group by agentcode
order by agentcode

select af.code as FranchiseCode,rtrim(ltrim(coalesce(af.CompetitionName, af.TradingName, af.DESCN))) as Franchise,
ar.code as RegionalSalesManagerCode,rtrim(ar.descn) as RegionalSalesManager,
aa.code as AreaSalesManagerCode,rtrim(aa.descn) as AreaSalesManager
into #HistoricalHierarchy
from mstt_agents af 
inner join #Franchise_ValidRSM t1 on af.code = t1.agentcode
inner join msit_agenthierarchyhistory RSM on rsm.id = t1.id
inner join mstt_agents ar on ar.code = rsm.detailagentcode
inner join #RSM_ValidASD t2 on ar.code = t2.agentcode
inner join msit_agenthierarchyhistory ASD on asd.id = t2.id
inner join mstt_agents aa on aa.code = asd.detailagentcode
where 
  af.agenttype in (select distinct AgentType from #BusinessAgentType)  or   --Franchise Agent types in list of business types
  (af.AgentType = '46' and af.DateStarted >= '23 May 2008')
order by 1

/*
Insert Turnover values from msit_OpenworkAdviserListing (OAL)and mstt_ProductionAdjustments (ADJ)
into a temporary table. 

This section replaces the msft_Sales extract in the previous version. To be included the OAL and 
ADJ entries must match to the Product Hierarchy, have a valid RSM and fall within the 
Commission Period being processed.
*/
--Extract Openwork Adviser Listing movements

select
 oal.BusinessCode as Code,
 p.ProductName,
 p.ProductSubGroupName,
 p.ProductGroupName,
 p.ProductCategoryName,
 m.FranchiseSizeId,
 fs.FranchiseSizeType,
 sum(isnull(oal.ABCValue,0)) as Turnover,  
 rtrim(ltrim(coalesce(ag.CompetitionName, ag.TradingName, ag.DESCN))) as Franchise, -- as per CR 66
 hh.AreaSalesManagerCode,
 rtrim(ltrim(hh.AreaSalesManager)) as AreaSalesManager,
 hh.RegionalSalesManagerCode,
 rtrim(ltrim(hh.RegionalSalesManager)) as RegionalSalesManager,
 left(p.ProductCode,8) as HierarchyProdCode,
 oal.Source,
 CAST(CONVERT(NVARCHAR, getdate(), 112) AS DATETIME) as Updated
 
into #CurrentLeagueTable
from msit_OpenworkAdviserListing oal
  inner join mstt_Agents ag on oal.BusinessCode = ag.Code
  inner join #HistoricalHierarchy hh on ag.Code = hh.FranchiseCode
  inner join msit_CommissionStatementPeriods csp on csp.Month = oal.Month
  inner join mstt_ProductHierarchy p 
        on  p.productcode = case when oal.source = 'OMS' then 'O_' + left(oal.prodtype,6) 
         when oal.source = 'Payshield' then 'PY_' + left(oal.prodtype,5) 
         when oal.source = 'Openwork 2005' and listposition not in (6,51,54,55) then 'NBI_' + left(oal.prodtype,4)
         when oal.source = 'Openwork 2005' and listposition = 6 and left(oal.prodtype,3) = 'MOR' then 'NBI_MOR'
         when oal.source = 'Openwork 2005' and listposition = 6 and left(oal.prodtype,3) <> 'MOR' then 'NBI_UKPL'
         when oal.source = 'Openwork 2005' and listposition = 54 then 'NBI_SCO'
         when oal.source = 'Openwork 2005' and listposition in (51,55) then 'NBI_STE'
         when oal.source = 'openwork 2006' and oal.prodtype = 'MORTGAGE' then 'NBI_MTG'
         when oal.source = 'openwork 2006' and oal.prodtype is null then oal.prodtype
         when oal.source = 'openwork 2006' and oal.prodtype <> 'MORTGAGE' then oal.prodtype 
        else oal.prodtype end
  inner join #MaxFranchiseSizeForYear m on ag.Code = m.Code
  inner join msdt_FranchiseSize fs on m.FranchiseSizeId = fs.FranchiseSizeId
where
 --Franchise Agent type is in list of Business Types
 --ag.AgentType in (select distinct AgentType from #BusinessAgentType)
 (ag.AgentType in (select distinct AgentType from #BusinessAgentType) or (ag.AgentType = '46' and ag.DateStarted >= '23 May 2008'))  -- PR 20/08/2008
 AND
 --Franchise is Competent OR Franchise is being merged into another
  (ag.Code in (select distinct FranchiseCode from #CompetentStatusOverride where CompetentStatus = 1) 
   or ag.Code in (select distinct FromFranchiseCode from #Merger))
 AND
 --Sale earlier then current Commission Month
  oal.Month <= @CurrentMonth
 AND
 --Sale linked to Commission Month made in Current Year
  csp.Year = @CurrentYear
 AND
 -- Select Payments with Turnover
 isnull(oal.ABCValue,0) <> 0
 AND
 --Product exists on Hierarchy and is required for League
  p.LeagueIncludeFlag = 'Y'
group by 
 oal.BusinessCode,
 p.ProductName,
 p.ProductSubGroupName,
 p.ProductGroupName,
 p.ProductCategoryName,
 m.FranchiseSizeId,
 fs.FranchiseSizeType,
 rtrim(ltrim(coalesce(ag.CompetitionName, ag.TradingName, ag.DESCN))),
 hh.AreaSalesManagerCode,
 rtrim(ltrim(hh.AreaSalesManager)),
 hh.RegionalSalesManagerCode,
 rtrim(ltrim(hh.RegionalSalesManager)),
 p.ProductCode,
 oal.Source
/*
union all

-- Add All Production Adjustments 

select
 ag.Code,
 p.ProductName,
 p.ProductSubGroupName,
 p.ProductGroupName,
 p.ProductCategoryName,
 m.FranchiseSizeId,
 fs.FranchiseSizeType,
 s.Turnover as Turnover,  
 rtrim(ltrim(coalesce(ag.CompetitionName, ag.TradingName, ag.DESCN))) as Franchise, -- as per CR 66
 hh.AreaSalesManagerCode,
 rtrim(ltrim(hh.AreaSalesManager)) as AreaSalesManager,
 hh.RegionalSalesManagerCode,
 rtrim(ltrim(hh.RegionalSalesManager)) as RegionalSalesManager,
 left(ph.ProductCode,8) as HierarchyProdCode,
 'Adjustment' as Source,
 CAST(CONVERT(NVARCHAR, getdate(), 112) AS DATETIME) as Updated

from mstt_ProductionAdjustments s
  inner join mstt_Agents ag on s.AgentCode = ag.Code
  inner join #HistoricalHierarchy hh on ag.Code = hh.FranchiseCode
  inner join msdt_Products p on s.ProductId = p.ProductId
  inner join mstt_ProductHierarchy ph on ph.ProductCode = p.ProductCode
  inner join #MaxFranchiseSizeForYear m on ag.Code = m.Code
  inner join msdt_FranchiseSize fs on m.FranchiseSizeId = fs.FranchiseSizeId

where
 --Franchise Agent type is in list of Business Types
 ag.AgentType in (select distinct AgentType from #BusinessAgentType)
 AND
 --Franchise is Competent OR Franchise is being merged into another
 (ag.Code in (select distinct FranchiseCode from #CompetentStatusOverride where CompetentStatus = 1) 
   or ag.Code in (select distinct FromFranchiseCode from #Merger))   
 AND
 -- Select Adjustments for Current Year (regardless of Date added) :MPC 16/01/2008
 s.[Year] = @CurrentYear
 AND
 -- Select Adjustments with Turnover
 isnull(s.Turnover,0) <> 0
 AND
 --Product exists on Hierarchy and is required for League
  ph.LeagueIncludeFlag = 'Y'

*/
--Apply the Mergers
update c
set Code = m.ToFranchiseCode,
  FranchiseSizeId = ms.FranchiseSizeId,
  FranchiseSizeType = fs.FranchiseSizeType,
  Franchise = hh.Franchise,
  AreaSalesManagerCode = hh.AreaSalesManagerCode,
  AreaSalesManager = hh.AreaSalesManager,
  RegionalSalesManagerCode = hh.RegionalSalesManagerCode,
  RegionalSalesManager = hh.RegionalSalesManager
from #CurrentLeagueTable c
  inner join #Merger m on c.Code = m.FromFranchiseCode
  inner join #HistoricalHierarchy hh on m.ToFranchiseCode = hh.FranchiseCode
  inner join #MaxFranchiseSizeForYear ms on m.ToFranchiseCode = ms.Code
  inner join msdt_FranchiseSize fs on ms.FranchiseSizeId = fs.FranchiseSizeId

--Truncate target table and insert values from #CurrentLeagueTable temporary table
--Production adjustments inserted into #CurrentLeagueTable are aggregated with main turnover values at this stage
truncate table mstt_FranchiseABCLeagueTable_Current

insert into mstt_FranchiseABCLeagueTable_Current
select 
 c.Code,
 c.ProductName,
 c.ProductSubGroupName,
 c.ProductGroupName,
 c.ProductCategoryName,
 c.FranchiseSizeId,
 c.FranchiseSizeType,
 round(sum(c.Turnover),2) as Turnover,  
 c.Franchise, 
 c.AreaSalesManagerCode,
 c.AreaSalesManager,
 c.RegionalSalesManagerCode,
 c.RegionalSalesManager,
 null as numAdvisers,
 c.HierarchyProdCode,
 c.Source,
 c.Updated
from 
 #CurrentLeagueTable c
 --Left join msdt_Adviser a ON a.Franchise = c.Franchise
group by 
 c.Code,
 c.ProductName,
 c.ProductSubGroupName,
 c.ProductGroupName,
 c.ProductCategoryName,
 c.FranchiseSizeId,
 c.FranchiseSizeType,
 c.Franchise, 
 c.AreaSalesManagerCode,
 c.AreaSalesManager,
 c.RegionalSalesManagerCode,
 c.RegionalSalesManager,
 c.HierarchyProdCode,
 c.Source, 
 c.Updated
--having round(sum(c.Turnover),2) <> 0

--Update number of advisers per franchise
SELECT COUNT(*) as advisers, FIRM
INTO #advisers
FROM msft_CapacityCountsbyDay c
INNER JOIN mstt_Agents a ON a.Code = c.AgentCode
WHERE StatusDate = 
(
SELECT MAX(StatusDate) 
FROM dbo.msft_CapacityCountsByDay
WHERE Comparison = 'Actual'
)
AND Comparison = 'Actual' and Level = 'Adviser'
GROUP BY a.FIRM

update c
SET c.numAdvisers = a.advisers
FROM mstt_FranchiseABCLeagueTable_Current c
INNER JOIN #advisers a ON a.FIRM = c.Code 

--Roll if parameter is set to 'Y' or the @EndOfMonthDate is the day prior to executing this procedure
if @CalcLastMonthPositions = 'Y' or @EndOfMonthDate = convert(datetime,convert(varchar(8),getdate()-1,112),112)

begin

  --Truncate Previous
  Truncate table mstt_FranchiseABCLeagueTable_Previous
  
  --Copy Last to Previous except at start of year
  --(as Commission Year of Last is earlier than CommissionYear 

  --declare @CurrentYear int set @CurrentYear = 2009

  declare @LastMonth datetime 
  set @LastMonth = (select max(lastmonth) from mstt_FranchiseABCLeagueTable_Last)
  
  declare @LastYear int
  set @LastYear = (select Year from msit_commissionstatementperiods 
           where PeriodStartDate = @LastMonth)

  -- Only populate Previous table if reloading data for the same commission year 
  if @LastYear = @CurrentYear
  begin

    insert into mstt_FranchiseABCLeagueTable_Previous
    select Code, ProductName, ProductSubGroupName, ProductGroupName, 
    ProductCategoryName, FranchiseSizeId, FranchiseSizeType, 
    Turnover, Franchise, AreaSalesManagerCode, AreaSalesManager, 
    RegionalSalesManagerCode, RegionalSalesManager, 
    HierarchyProductCode, Source, LastMonth
    from mstt_FranchiseABCLeagueTable_Last

  end

  --Truncate Last
  Truncate table mstt_FranchiseABCLeagueTable_Last
  
  --Copy Current to Last
  insert into mstt_FranchiseABCLeagueTable_Last
  select Code, ProductName, ProductSubGroupName, ProductGroupName, 
  ProductCategoryName, FranchiseSizeId, FranchiseSizeType, 
  Turnover, Franchise, AreaSalesManagerCode, AreaSalesManager, 
  RegionalSalesManagerCode, RegionalSalesManager, 
  HierarchyProductCode, Source, @CurrentLeagueMonth
  from mstt_FranchiseABCLeagueTable_Current

end

 
--Update names of Franchises on Last and Prev tables. This safeguards us against name changes. Without doing this, 
--both old and new names would appear, which is an error.
update l
set Franchise = rtrim(ltrim(coalesce(ag.CompetitionName, ag.TradingName, ag.DESCN)))
from mstt_FranchiseABCLeagueTable_Last l
  inner join mstt_Agents ag on l.Code = ag.Code
    
update p
set Franchise = rtrim(ltrim(coalesce(ag.CompetitionName, ag.TradingName, ag.DESCN)))
from mstt_FranchiseABCLeagueTable_Previous p
  inner join mstt_Agents ag on p.Code = ag.Code
 
drop table #CurrentLeagueTable
drop table #HistoricalHierarchy
drop table #MaxFranchiseSizeForYear
drop table #Franchise_ValidRSM
drop table #RSM_ValidASD
--drop table #AgentHierarchyHistory
drop table #CompetentStatusOverride
drop table #FranchiseSizeOverride
drop table #Merger
drop table #BusinessAgentType
drop table #SellerAgentType
drop table #advisers

GO
/****** Object:  StoredProcedure [dbo].[msp_FranchiseLeague]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [dbo].[msp_FranchiseLeague] -- WITH RECOMPILE,ENCRYPTION
  /* Param List */
  @CalcLastMonthPositions nchar(1) = 'N'
AS


/******************************************************************************

Franchise League Refresh
========================

Amended by Mike Cawood (February 2008)

From 2008 Franchise Leagues to be sourced from Open Access Commission Table
instead of Sales Fact table (msft_Sales). In addition:

1. Minor change to Agent Hierarchy processing to use entries where Default Flag 
   is ticked (defaultvalue = 1).
2. New Flag to be added to product hierarchy to enable products to be switched 
   on or off for inclusion in League table.
3. Add Product Code and Source to all 3 Franchise League tables.
4. Add EffectiveDate to Current and Previous tables.
5. Empty Previous table if refreshing for first month in Commission Year.
6. Add DefaultValue = 1 checks to Agent Hierarchy processing (0 denotes invalid rows).

*******************************************************************************/

set dateformat dmy


--Get overrides and other info from CodesAndDescriptions spreadsheet.

--Competent Status Overrides
select distinct 
  Code as FranchiseCode,
  Description as CompetentStatus
into #CompetentStatusOverride
from msit_MIWarehouseCodesAndDescriptions
where ColumnName = 'LG-Status'

--Franchise Size Overrides
select distinct 
  Code as FranchiseCode,
  case 
    when Description = 'SOLE' then 1 
    when Description = 'SMALL' then 2
    when Description = 'LARGE' then 10
  else Description  
  end as FranchiseSize 
into #FranchiseSizeOverride
from msit_MIWarehouseCodesAndDescriptions
where ColumnName = 'LG-Size'

--Mergers
select distinct 
  Code as FromFranchiseCode,
  Description as ToFranchiseCode 
into #Merger
from msit_MIWarehouseCodesAndDescriptions
where ColumnName = 'LG-Merge'

--Business Types
select distinct 
  Code as AgentType
into #BusinessAgentType
from msit_MIWarehouseCodesAndDescriptions
where ColumnName = 'LG-AgtType'
and Description = 'Business'

--Seller Types
select distinct 
  Code as AgentType
into #SellerAgentType
from msit_MIWarehouseCodesAndDescriptions
where ColumnName = 'LG-AgtType'
and Description = 'Seller'


--Put other 'Competent' Agents into the #CompetentStatusOverride table
insert into #CompetentStatusOverride
select Code, CompetentStatus
from mstt_Agents a
where CompetentStatus = 1
and not exists (select 'x' from #CompetentStatusOverride c
        where a.Code = c.FranchiseCode)

--Get Current League Month - first commission start date after the value stored in LastMonth
declare @CurrentLeagueMonth datetime
set @CurrentLeagueMonth = (
  select min(PeriodStartDate)
  from msit_commissionstatementperiods
  where PeriodStartDate > (select top 1 LastMonth from mstt_FranchiseLeagueTable_Last)
  )

--Get Current Year from commission statement period table :MPC 16/01/2008
declare @CurrentYear int
set @CurrentYear = (select Year from msit_commissionstatementperiods 
         where PeriodStartDate = @CurrentLeagueMonth)

--Determine current end-of-month date value from commission statement periods
declare @EndOfMonthDate datetime
set @EndOfMonthDate = (
  select PeriodEndDate
  from msit_commissionstatementperiods
  where PeriodStartDate = @CurrentLeagueMonth
  )

--Get Current Month from commission statement period table  :MPC 16/01/2008
declare @CurrentMonth datetime
set @CurrentMonth = (select Month from msit_commissionstatementperiods 
         where PeriodEndDate = @EndOfMonthDate)

--Determine first day-of-year date value from commission statement periods
declare @FirstDayThisYear datetime
set @FirstDayThisYear = (
  select min(PeriodStartDate)
  from msit_commissionstatementperiods
  where PeriodStartDate >= convert(datetime, convert(char(4),year(@CurrentLeagueMonth)) + '0101', 112)
  )

/*
--MPC: Commented out Feb'08
--Determine OSCAR current end-of-month date value from commission statement periods
declare @OscarEndOfMonthDate datetime
set @OscarEndOfMonthDate = (
  select OSCAREndDate
  from msit_commissionstatementperiods
  where PeriodStartDate = @CurrentLeagueMonth
  )

--Determine OSCAR first day-of-year date value from commission statement periods
declare @OscarFirstDayThisYear datetime
set @OscarFirstDayThisYear = (
  select min(OscarStartDate)
  from msit_commissionstatementperiods
  where PeriodStartDate >= convert(datetime, convert(char(4),year(@CurrentLeagueMonth)) + '0101', 112)
  )
*/

--Determine maximum franchise size during the year for each franchise
select code, 
  max(FranchiseSize) as FranchiseSize, 
  -99 as FranchiseSizeId
into #MaxFranchiseSizeForYear
from mstt_AgentsHistory
where ValidToDate >= @FirstDayThisYear
group by Code

--Apply Franchise Size overrides
update m

set FranchiseSize = fso.FranchiseSize
from #MaxFranchiseSizeForYear m
  inner join #FranchiseSizeOverride fso
    on m.Code = fso.FranchiseCode

--Update Franchise size id's from msdt_FranchiseSize table
update m
set FranchiseSizeId = f.FranchiseSizeId
from #MaxFranchiseSizeForYear m
  inner join msdt_FranchiseSize f
    on m.FranchiseSize = f.FranchiseSize

  
--Create temporary table to store agent hierarchy history values
/*
select AgentCode, 
  DefaultValue, 
  StartDate, 
  EndDate, 
  Status, 
  DetailAgentCode, 
  ParticipantType
into #AgentHierarchyHistory 
from msit_AgentHierarchyHistory
where 1=0

CREATE INDEX AgentHierarchyHistory_AgentCode ON #AgentHierarchyHistory (AgentCode)

insert into #AgentHierarchyHistory  
select ahh4.AgentCode, 
  ahh4.DefaultValue, 
  ahh4.StartDate, 
  ahh4.EndDate, 
  ahh4.Status, 
  ahh4.DetailAgentCode, 
  ahh4.ParticipantType 
from msit_AgentHierarchyHistory ahh4
  inner join 
    (--Get the max Id if there are multiple entries for a 
    --StartDate/EndDate/ParticipantType combo
    select max(ahh2.Id) as Id, 
      ahh2.AgentCode, 
      ahh2.ParticipantType, 
      ahh2.StartDate, 
      ahh2.EndDate 
    from msit_AgentHierarchyHistory ahh2
      inner join (--Get the latest end date for each start date
          select ahh.AgentCode, 
            ahh.ParticipantType, 
            ahh.StartDate, 
            max(isnull(ahh.EndDate, '31 Dec 9999')) as EndDate
          from msit_agenthierarchyhistory ahh
          where ahh.defaultvalue = 1    --MPC: Change to Comm Basis
          group by ahh.AgentCode, ahh.ParticipantType, ahh.StartDate ) ahh1
        on ahh2.AgentCode = ahh1.AgentCode
        and ahh2.ParticipantType = ahh1.ParticipantType
        and ahh2.StartDate = ahh1.StartDate
        and isnull(ahh2.EndDate, '31 Dec 9999') = ahh1.EndDate
    where ahh2.defaultvalue = 1     --MPC: Change to Comm Basis
    group by ahh2.AgentCode, 
      ahh2.ParticipantType, 
      ahh2.StartDate, 
      ahh2.EndDate ) ahh3
    on ahh4.id = ahh3.Id
  inner join mstt_Agents a on ahh4.AgentCode = a.Code
where ahh4.ParticipantType = 4            --Hierarchy relationship type is to a RSM
and a.AgentType in (select distinct AgentType from #BusinessAgentType)  --Franchise Agent types in list of business types
and isnull(ahh4.EndDate, '31 dec 2999') >= '01 Jan 2006'    --Exclude records prior to 1st Jan 2006
and ahh4.StartDate <> isnull(ahh4.EndDate, '31 dec 2999')   --Exclude records where StartDate = EndDate
and ahh4.defaultvalue = 1           --MPC: Change to Comm Basis
order by 1

--Using the agent hierarchy history table create a list of franchises and their matching RSM & ASD
select distinct Franchise.AgentCode as FranchiseCode,
  FranchiseAgent.Descn as Franchise,
  RSM.AgentCode as RegionalSalesManagerCode,
  RSMAgent.Descn as RegionalSalesManager,
  ASD.AgentCode as AreaSalesManagerCode,
  ASDAgent.Descn as AreaSalesManager
into #HistoricalHierarchy
from #AgentHierarchyHistory Franchise
  inner join mstt_Agents FranchiseAgent
    on Franchise.AgentCode = FranchiseAgent.Code
  inner join msit_AgentHierarchyHistory RSM
    on Franchise.DetailAgentCode = RSM.AgentCode
  inner join mstt_Agents RSMAgent
    on RSM.AgentCode = RSMAgent.Code
  inner join msit_AgentHierarchyHistory ASD
    on RSM.DetailAgentCode = ASD.AgentCode
  inner join mstt_Agents ASDAgent
    on ASD.AgentCode = ASDAgent.Code
where @EndOfMonthDate between Franchise.StartDate and isnull(Franchise.EndDate, '31 Dec 9999')
and @EndOfMonthDate between RSM.StartDate and isnull(RSM.EndDate, '31 Dec 9999')
and @EndOfMonthDate between ASD.StartDate and isnull(ASD.EndDate, '31 Dec 9999')
and RSM.ParticipantType = 2   --Hierarchy relationship type is to an ASD
and Franchise.DefaultValue = 1
order by 1, 2, 3
*/

select agentcode,max(id) as ID,max(startdate) as StartDate
into #RSM_ValidASD
from msit_agenthierarchyhistory 
where participanttype = 2                   --ASD
and defaultvalue = 1                    --Ticked rows only
and @EndofMonthDate between startdate and isnull(enddate,'31 dec 9999')       --Hierarchy as at Run Date
and agentcode in (select distinct code from mstt_agentshistory where agenttype in (52,53))  --RSM/BQM
group by agentcode
order by agentcode

select agentcode,max(id) as ID,max(startdate) as StartDate
into #Franchise_ValidRSM
from msit_agenthierarchyhistory 
where participanttype = 4             --RSM
and defaultvalue = 1              --Ticked rows only
and @EndofMonthDate between startdate and isnull(enddate,'31 dec 9999') --Hierarchy as at Run Date
and agentcode in (select code from mstt_agents where agenttype in (select distinct AgentType from #BusinessAgentType))  --Franchise Agent types in list of business types
group by agentcode
order by agentcode

select af.code as FranchiseCode,rtrim(ltrim(coalesce(af.CompetitionName, af.TradingName, af.DESCN))) as Franchise,
ar.code as RegionalSalesManagerCode,rtrim(ar.descn) as RegionalSalesManager,
aa.code as AreaSalesManagerCode,rtrim(aa.descn) as AreaSalesManager
into #HistoricalHierarchy
from mstt_agents af 
inner join #Franchise_ValidRSM t1 on af.code = t1.agentcode
inner join msit_agenthierarchyhistory RSM on rsm.id = t1.id
inner join mstt_agents ar on ar.code = rsm.detailagentcode
inner join #RSM_ValidASD t2 on ar.code = t2.agentcode
inner join msit_agenthierarchyhistory ASD on asd.id = t2.id
inner join mstt_agents aa on aa.code = asd.detailagentcode
where af.agenttype in (select distinct AgentType from #BusinessAgentType)   --Franchise Agent types in list of business types
order by 1

/*
Insert Turnover values from msit_OpenworkAdviserListing (OAL)and mstt_ProductionAdjustments (ADJ)
into a temporary table. 

This section replaces the msft_Sales extract in the previous version. To be included the OAL and 
ADJ entries must match to the Product Hierarchy, have a valid RSM and fall within the 
Commission Period being processed.
*/
--Extract Openwork Adviser Listing movements

select
 oal.BusinessCode as Code,
 p.ProductName,
 p.ProductSubGroupName,
 p.ProductGroupName,
 p.ProductCategoryName,
 m.FranchiseSizeId,
 fs.FranchiseSizeType,
 sum(isnull(oal.APE,0)) as Turnover,  
 rtrim(ltrim(coalesce(ag.CompetitionName, ag.TradingName, ag.DESCN))) as Franchise, -- as per CR 66
 hh.AreaSalesManagerCode,
 rtrim(ltrim(hh.AreaSalesManager)) as AreaSalesManager,
 hh.RegionalSalesManagerCode,
 rtrim(ltrim(hh.RegionalSalesManager)) as RegionalSalesManager,
 left(p.ProductCode,8) as HierarchyProdCode,
 oal.Source,
 CAST(CONVERT(NVARCHAR, getdate(), 112) AS DATETIME) as Updated
 
into #CurrentLeagueTable
from msit_OpenworkAdviserListing oal
  inner join mstt_Agents ag on oal.BusinessCode = ag.Code
  inner join #HistoricalHierarchy hh on ag.Code = hh.FranchiseCode
  inner join msit_CommissionStatementPeriods csp on csp.Month = oal.Month
  inner join mstt_ProductHierarchy p 
        on  p.productcode = case when oal.source = 'OMS' then 'O_' + left(oal.prodtype,6) 
         when oal.source = 'Payshield' then 'PY_' + left(oal.prodtype,5) 
         when oal.source = 'Openwork 2005' and listposition not in (6,51,54,55) then 'NBI_' + left(oal.prodtype,4)
         when oal.source = 'Openwork 2005' and listposition = 6 and left(oal.prodtype,3) = 'MOR' then 'NBI_MOR'
         when oal.source = 'Openwork 2005' and listposition = 6 and left(oal.prodtype,3) <> 'MOR' then 'NBI_UKPL'
         when oal.source = 'Openwork 2005' and listposition = 54 then 'NBI_SCO'
         when oal.source = 'Openwork 2005' and listposition in (51,55) then 'NBI_STE'
         when oal.source = 'openwork 2006' and oal.prodtype = 'MORTGAGE' then 'NBI_MTG'
         when oal.source = 'openwork 2006' and oal.prodtype is null then oal.prodtype
         when oal.source = 'openwork 2006' and oal.prodtype <> 'MORTGAGE' then oal.prodtype 
        else oal.prodtype end
  inner join #MaxFranchiseSizeForYear m on ag.Code = m.Code
  inner join msdt_FranchiseSize fs on m.FranchiseSizeId = fs.FranchiseSizeId
where
 --Franchise Agent type is in list of Business Types
 ag.AgentType in (select distinct AgentType from #BusinessAgentType)
 AND
 --Franchise is Competent OR Franchise is being merged into another
  (ag.Code in (select distinct FranchiseCode from #CompetentStatusOverride where CompetentStatus = 1) 
   or ag.Code in (select distinct FromFranchiseCode from #Merger))
 AND
 --Sale earlier then current Commission Month
  oal.Month <= @CurrentMonth
 AND
 --Sale linked to Commission Month made in Current Year
  csp.Year = @CurrentYear
 AND
 -- Select Payments with Turnover
 isnull(oal.APE,0) <> 0
 AND
 --Product exists on Hierarchy and is required for League
  p.LeagueIncludeFlag = 'Y'
group by 
 oal.BusinessCode,
 p.ProductName,
 p.ProductSubGroupName,
 p.ProductGroupName,
 p.ProductCategoryName,
 m.FranchiseSizeId,
 fs.FranchiseSizeType,
 rtrim(ltrim(coalesce(ag.CompetitionName, ag.TradingName, ag.DESCN))),
 hh.AreaSalesManagerCode,
 rtrim(ltrim(hh.AreaSalesManager)),
 hh.RegionalSalesManagerCode,
 rtrim(ltrim(hh.RegionalSalesManager)),
 p.ProductCode,
 oal.Source

union all

-- Add All Production Adjustments 

select
 ag.Code,
 p.ProductName,
 p.ProductSubGroupName,
 p.ProductGroupName,
 p.ProductCategoryName,
 m.FranchiseSizeId,
 fs.FranchiseSizeType,
 s.Turnover as Turnover,  
 rtrim(ltrim(coalesce(ag.CompetitionName, ag.TradingName, ag.DESCN))) as Franchise, -- as per CR 66
 hh.AreaSalesManagerCode,
 rtrim(ltrim(hh.AreaSalesManager)) as AreaSalesManager,
 hh.RegionalSalesManagerCode,
 rtrim(ltrim(hh.RegionalSalesManager)) as RegionalSalesManager,
 left(ph.ProductCode,8) as HierarchyProdCode,
 'Adjustment' as Source,
 CAST(CONVERT(NVARCHAR, getdate(), 112) AS DATETIME) as Updated

from mstt_ProductionAdjustments s
  inner join mstt_Agents ag on s.AgentCode = ag.Code
  inner join #HistoricalHierarchy hh on ag.Code = hh.FranchiseCode
  inner join msdt_Products p on s.ProductId = p.ProductId
  inner join mstt_ProductHierarchy ph on ph.ProductCode = p.ProductCode
  inner join #MaxFranchiseSizeForYear m on ag.Code = m.Code
  inner join msdt_FranchiseSize fs on m.FranchiseSizeId = fs.FranchiseSizeId

where
 --Franchise Agent type is in list of Business Types
 ag.AgentType in (select distinct AgentType from #BusinessAgentType)
 AND
 --Franchise is Competent OR Franchise is being merged into another
 (ag.Code in (select distinct FranchiseCode from #CompetentStatusOverride where CompetentStatus = 1) 
   or ag.Code in (select distinct FromFranchiseCode from #Merger))   
 AND
 -- Select Adjustments for Current Year (regardless of Date added) :MPC 16/01/2008
 s.[Year] = @CurrentYear
 AND
 -- Select Adjustments with Turnover
 isnull(s.Turnover,0) <> 0
 AND
 --Product exists on Hierarchy and is required for League
  ph.LeagueIncludeFlag = 'Y'

--Apply the Mergers
update c
set Code = m.ToFranchiseCode,
  FranchiseSizeId = ms.FranchiseSizeId,
  FranchiseSizeType = fs.FranchiseSizeType,
  Franchise = hh.Franchise,
  AreaSalesManagerCode = hh.AreaSalesManagerCode,
  AreaSalesManager = hh.AreaSalesManager,
  RegionalSalesManagerCode = hh.RegionalSalesManagerCode,
  RegionalSalesManager = hh.RegionalSalesManager
from #CurrentLeagueTable c
  inner join #Merger m on c.Code = m.FromFranchiseCode
  inner join #HistoricalHierarchy hh on m.ToFranchiseCode = hh.FranchiseCode
  inner join #MaxFranchiseSizeForYear ms on m.ToFranchiseCode = ms.Code
  inner join msdt_FranchiseSize fs on ms.FranchiseSizeId = fs.FranchiseSizeId

--Truncate target table and insert values from #CurrentLeagueTable temporary table
--Production adjustments inserted into #CurrentLeagueTable are aggregated with main turnover values at this stage
truncate table mstt_FranchiseLeagueTable_Current

insert into mstt_FranchiseLeagueTable_Current
select 
 c.Code,
 c.ProductName,
 c.ProductSubGroupName,
 c.ProductGroupName,
 c.ProductCategoryName,
 c.FranchiseSizeId,
 c.FranchiseSizeType,
 round(sum(c.Turnover),2) as Turnover,  
 c.Franchise, 
 c.AreaSalesManagerCode,
 c.AreaSalesManager,
 c.RegionalSalesManagerCode,
 c.RegionalSalesManager,
 null as numAdvisers,
 c.HierarchyProdCode,
 c.Source,
 c.Updated
from 
 #CurrentLeagueTable c
 --Left join msdt_Adviser a ON a.Franchise = c.Franchise
group by 
 c.Code,
 c.ProductName,
 c.ProductSubGroupName,
 c.ProductGroupName,
 c.ProductCategoryName,
 c.FranchiseSizeId,
 c.FranchiseSizeType,
 c.Franchise, 
 c.AreaSalesManagerCode,
 c.AreaSalesManager,
 c.RegionalSalesManagerCode,
 c.RegionalSalesManager,
 c.HierarchyProdCode,
 c.Source, 
 c.Updated
--having round(sum(c.Turnover),2) <> 0

--Update number of advisers per franchise
SELECT COUNT(*) as advisers, FIRM
INTO #advisers
FROM msft_CapacityCountsbyDay c
INNER JOIN mstt_Agents a ON a.Code = c.AgentCode
WHERE StatusDate = 
(
SELECT MAX(StatusDate) 
FROM dbo.msft_CapacityCountsByDay
WHERE Comparison = 'Actual'
)
AND Comparison = 'Actual' and Level = 'Adviser'
GROUP BY a.FIRM

update c
SET c.numAdvisers = a.advisers
FROM mstt_FranchiseLeagueTable_Current c
INNER JOIN #advisers a ON a.FIRM = c.Code 

--Roll if parameter is set to 'Y' or the @EndOfMonthDate is the day prior to executing this procedure
if @CalcLastMonthPositions = 'Y' or @EndOfMonthDate = convert(datetime,convert(varchar(8),getdate()-1,112),112)

begin

  --Truncate Previous
  Truncate table mstt_FranchiseLeagueTable_Previous
  
  --Copy Last to Previous except at start of year
  --(as Commission Year of Last is earlier than CommissionYear 

  --declare @CurrentYear int set @CurrentYear = 2009

  declare @LastMonth datetime 
  set @LastMonth = (select max(lastmonth) from mstt_FranchiseLeagueTable_Last)
  
  declare @LastYear int
  set @LastYear = (select Year from msit_commissionstatementperiods 
           where PeriodStartDate = @LastMonth)

  -- Only populate Previous table if reloading data for the same commission year 
  if @LastYear = @CurrentYear
  begin

    insert into mstt_FranchiseLeagueTable_Previous
    select Code, ProductName, ProductSubGroupName, ProductGroupName, 
    ProductCategoryName, FranchiseSizeId, FranchiseSizeType, 
    Turnover, Franchise, AreaSalesManagerCode, AreaSalesManager, 
    RegionalSalesManagerCode, RegionalSalesManager, 
    HierarchyProductCode, Source, LastMonth
    from mstt_FranchiseLeagueTable_Last

  end

  --Truncate Last
  Truncate table mstt_FranchiseLeagueTable_Last
  
  --Copy Current to Last
  insert into mstt_FranchiseLeagueTable_Last
  select Code, ProductName, ProductSubGroupName, ProductGroupName, 
  ProductCategoryName, FranchiseSizeId, FranchiseSizeType, 
  Turnover, Franchise, AreaSalesManagerCode, AreaSalesManager, 
  RegionalSalesManagerCode, RegionalSalesManager, 
  HierarchyProductCode, Source, @CurrentLeagueMonth
  from mstt_FranchiseLeagueTable_Current

end

 
--Update names of Franchises on Last and Prev tables. This safeguards us against name changes. Without doing this, 
--both old and new names would appear, which is an error.
update l
set Franchise = rtrim(ltrim(coalesce(ag.CompetitionName, ag.TradingName, ag.DESCN)))
from mstt_FranchiseLeagueTable_Last l
  inner join mstt_Agents ag on l.Code = ag.Code
    
update p
set Franchise = rtrim(ltrim(coalesce(ag.CompetitionName, ag.TradingName, ag.DESCN)))
from mstt_FranchiseLeagueTable_Previous p
  inner join mstt_Agents ag on p.Code = ag.Code
 
drop table #CurrentLeagueTable
drop table #HistoricalHierarchy
drop table #MaxFranchiseSizeForYear
drop table #Franchise_ValidRSM
drop table #RSM_ValidASD
--drop table #AgentHierarchyHistory
drop table #CompetentStatusOverride
drop table #FranchiseSizeOverride
drop table #Merger
drop table #BusinessAgentType
drop table #SellerAgentType
drop table #advisers




GO
