create procedure [dbo].[msp_HeadOfficeUsersForReports] as 

begin

truncate table mst_HeadOfficeUsersForReports

declare @MaxRowCount int 

select DomainLogin, count(distinct AdviserId) as RowCountValue
into #UserRowCounts
from msct_UserAccessControl
group by DomainLogin
 
set @MaxRowCount = (select max(RowCountValue) from 
(select DomainLogin, count(distinct AdviserId) as RowCountValue
from msct_UserAccessControl
group by DomainLogin) sub)
 
Insert mst_HeadOfficeUsersForReports
select distinct DomainLogin
from #UserRowCounts
where RowCountValue = @MaxRowCount

end


