CREATE procedure [dbo].[msp_ImportControlStatus]
 @Client        varchar(50),
 @Module        varchar(50),
 @Area          varchar(50),  -- valid options Imp, Post or All
 @Suspend       varchar(50),  -- 1(Suspend) or 0(Enable)
 @ProcedureName varchar(255) out,
 @Error         int          out
WITH RECOMPILE --, ENCRYPTION
as

--############################################################################
-- Copyright (c) MOORE STEPHENS CONSULTING LIMITED, 2004 All rights reserved
 
-- 
-- Object     : Procedure
-- Name       : msp_ImportControlStatus.sql
-- Description: Maintains table mst_ImportControl
-- Owner      : Ermedin Selmanovic
-- Created    : 22/12/2004
-- 
--############################################################################
--
-- $Id: msp_ImportControlStatus.sql 1.1 2004/12/22 11:57:16Z dselmano Exp $
-- $Log: msp_ImportControlStatus.sql $
-- Revision 1.1  2004/12/22 11:57:16Z  dselmano
-- Initial revision
--
--############################################################################

declare 
 @Phase          varchar(50),
 @Process        varchar(100),
 @ErrorCode      int,
 @ErrorCount     int,
 @StopProcessing bit

set @ErrorCount     = 0
set @StopProcessing = 0 

set @ProcedureName  = object_name(@@procid)
set @Process        = @ProcedureName
set @Phase          = 'START'

exec msp_ProcessLog @Phase, @Process, null, @Module, @Client


if exists (select NULL from mst_ImportControl where Type = @Client and Module = @Module)
 begin
 if @Area in ('Imp', 'Post', 'All')
  begin
   update
    mst_ImportControl
   set
    ImportSuspended = case 
                       when @Area in ('Imp', 'All') then @Suspend
                      else
                       ImportSuspended
                      end,
    PostSuspended   = case 
                       when @Area in ('Post', 'All') then @Suspend
                      else
                       PostSuspended
                      end
   where
    Type   = @Client  and
    Module = @Module
  end -- if @Area in ('Imp', 'Post')
 else -- if @Area in ('Imp', 'Post')
  begin
   set @Phase          = 'ERROR'
   set @Process        = 'INVALID AREA USED, Imp, Post or All ARE VALID OPTIONS TO USE'
   exec msp_ProcessLog @Phase, @Process, null, @Module, @Client
--   exec msp_ProcessLog 'ERROR', 'INVALID AREA USED, Imp, Post or All ARE VALID OPTIONS TO USE', NULL, @Client

   raiserror ('ERROR - See mst_ProcessLog for more detail', 16, 1)
  end -- if @Area in ('Imp', 'Post')
 
 end -- if exists (select NULL from mst_ImportControl where Type = @Client)
 else -- if exists (select NULL from mst_ImportControl where Type = @Client)
  begin
   set @Phase          = 'ERROR'
   set @Process        = 'INVALID TYPE or MODULE, CHECK mst_ImportControl TABLE - ABORTING'
   exec msp_ProcessLog @Phase, @Process, null, @Module, @Client

--   exec msp_ProcessLog 'ERROR', 'INVALID TYPE or MODULE, CHECK mst_ImportControl TABLE - ABORTING', NULL, @Client
   raiserror ('ERROR - See mst_ProcessLog for more detail', 16, 1)
  end -- if exists (select NULL from mst_ImportControl where Type = @Client)

set @ProcedureName = case
                      when @Suspend = 1 then @ProcedureName + ' - REFRESH FAILED, check job history and mst_ProcessLog for more details'
                     else
                      @ProcedureName + ' - REFRESH OK'
                     end

set @Phase          = 'END'
exec msp_ProcessLog @Phase, @Process, null, @Module, @Client
GO
