CREATE procedure [dbo].[msp_InsertConfigurationData]
  @Client   varchar(50),
  @Module   varchar(50),
  @Path     varchar(255),
  @Server   varchar(255),
  @Database varchar(255)
  
--WITH ENCRYPTION
as

delete mst_ImportControl where Type = @Client and Module = @Module

-- set @Client          = 'Openwork'
-- set @Module          = 'MI SALES'
-- set @Path            = '\\PROD-MIDB-001\d$\ClientData\Openwork\Swift\Current\'
-- set @Server          = 'PROD-MIDB-001'
-- set @Database        = 'Zurich_Openwork_DataWarehouse_Dev'

insert into mst_ImportControl values (@Client, @Module, '00:01:00', '23:59:00', @Server, @Database, @Path + 'Swift\Current\', 'mset_Finished.txt', '00:02:00', null, null, null, null, 0, 0, 1, 0, dateadd(dd,0,datediff(dd,-1,getdate())))
--select * from mst_ImportControl

truncate table mst_DataImportConfiguration
--delete mst_DataImportConfiguration where Client = @Client and Module = @Module
--select * from mst_DataImportConfiguration
--select * from mst_DataImportConfiguration order by Name
--select * from mst_DataImportConfiguration where Active = 1 order by Name

 declare DataImportCursor cursor
 for
 select 
  [name]
 from
  sysobjects
 where
  type   = 'u'           and
  [name] like 'msit_%' --and
--  [name] not like '%OLD'
 order by
  [name]
 for read only

 declare
--   @Client                 varchar(50),
