/****** Object:  StoredProcedure [dbo].[msp_KeyTriggers]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE procedure [dbo].[msp_KeyTriggers]

 @ManagerCode     nvarchar(50),
 @KPILevel        nvarchar(50),
 @UserId          nvarchar(50),
 @AllowDelegates  char(1)

as

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : msp_KeyTriggers.sql
-- Desc    : 
-- Owner   : KS
-- Created : 21/07/2006
-- Amended : 14/08/2006 - MK - Added further security, to ensure that the 
--                             user executing the report is allowed to see
--                             the agent that has been passed in to the proc.
-- Amended : 16/08/2006 - MK - Add function to allow delegate access. That is, allow a user
--                             to impersonate the user to whom they have been given access.
-- Amended : 04/10/2006 - BT - Add SummaryPeriod = 1 clause to ensure that values only reflect the current month
--
-- Amended : 07/07/2009 - MPC: Replace *= ANSI JOINS as these not allowed in SQL Server 2005
--
--########################################################################

if isnull(@AllowDelegates, 'N') = 'Y'
  set @UserId = (select dbo.msf_SQGetUserDelegatedFrom(@UserId))

if dbo.msf_SQCheckPermissions (@UserId, @ManagerCode, @KPILevel, 'CURRENT', 1) = 'DENY' 

  SELECT 
  null as [SQMCode],
  null as [AgentCode],
  null as [AgentName],
  null as [Complaint_COB],
  null as [Reject_COB],
  null as [Complaint_ICOB_GI],
  null as [Reject_ICOB_GI],
  null as [Complaint_ICOB_PP],
  null as [Reject_ICOB_PP],
  null as [Complaint_MCOB],
  null as [Reject_MCOB]
else

begin

select 
 SalesQualitySQMLevelCode as [SupervisorCode],
 AgentCode as [AgentCode],
 cast('' as nvarchar(255)) as [AgentName],
 ComplianceCategoryCode as [COB],
 ComplaintQty as [Complaint],
 Rejects as [Reject],
 KPILevel as [KPILevel]
into
 #Triggers
from 
 msv_AgentQualityAggregation
where 1=2



insert into  
 #Triggers
select
 [SupervisorCode] = a.SalesQualitySQMLevelCode,
 [AgentCode] = a.AgentCode,
 [AgentName] = b.Descn,
 [COB] = ComplianceCategoryCode,
 --[Complaint] = case when a.SummaryPeriod = 1 then ComplaintQty end,
 --[Reject] = case when a.SummaryPeriod = 1 then Rejects end,
 [Complaint] = ComplaintQty,
 [Reject] = Rejects,
 [KPILevel] = a.KPILevel
from
 msv_AgentQualityAggregation a      --MPC: 07/07/2009
 inner join mstt_Agents b       --MPC: 07/07/2009
  on a.AgentCode = b.Code       --MPC: 07/07/2009
where
-- a.AgentCode *= b.Code and      --MPC: 07/07/2009
 (ComplaintQty <> 0 OR Rejects <> 0) and
 a.reportmonth = (select max(reportmonth)
                         from msv_AgentQualityAggregation where KPILevel = 'ADVISERKPI') and
 a.kpilevel in ('sqmSummary', 'psSummary', 'rsmSummary', 'asdSummary', 'sqmps') and
 a.hierarchytypecode = 'Current' and
 a.summaryperiod = 1 and
 @ManagerCode = case when @KPILevel = 'PSSummary' then a.SalesQualityPSLevelCode
                     when @KPILevel = 'RSMSummary' then a.SalesQualityRSMLevelCode
                     when @KPILevel = 'ASDSummary' then a.SalesQualityASDLevelCode
                     else a.SalesQualitySQMLevelCode  end



if (select count(*) from #Triggers where KPILevel = @KPILevel) = 0

  SELECT 
  null as [SQMCode],
  null as [AgentCode],
  null as [AgentName],
  null as [Complaint_COB],
  null as [Reject_COB],
  null as [Complaint_ICOB_GI],
  null as [Reject_ICOB_GI],
  null as [Complaint_ICOB_PP],
  null as [Reject_ICOB_PP],
  null as [Complaint_MCOB],
  null as [Reject_MCOB]

else

select 
 [SupervisorCode] as [SQMCode],
 [AgentCode] as [AgentCode],
 [AgentName] as [AgentName],
 sum(case when COB = 'COB' then Complaint else 0 end) as [Complaint_COB],
 sum(case when COB = 'COB' then Reject else 0 end) as [Reject_COB],
 sum(case when COB = 'ICOB-GI' then Complaint else 0 end) as [Complaint_ICOB_GI],
 sum(case when COB = 'ICOB-GI' then Reject else 0 end) as [Reject_ICOB_GI],
 sum(case when COB = 'ICOB-PP' then Complaint else 0 end) as [Complaint_ICOB_PP],
 sum(case when COB = 'ICOB-PP' then Reject else 0 end) as [Reject_ICOB_PP],
 sum(case when COB = 'MCOB' then Complaint else 0 end) as [Complaint_MCOB],
 sum(case when COB = 'MCOB' then Reject else 0 end) as [Reject_MCOB]
from
 #Triggers
where
 KPILevel = @KPILevel
group by
 SupervisorCode,
 AgentCode,
 AgentName
 
 
drop table #Triggers

end




GO
/****** Object:  StoredProcedure [dbo].[msp_KeyTriggers_Checking]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER OFF
GO

CREATE Procedure [dbo].[msp_KeyTriggers_Checking]

        @ManagerCode as nvarchar(50),
    @Level AS VARCHAR(10)
AS

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2006 All rights reserved
--
-- Object  : procedure
-- Name    : msp_msp_KeyTriggers_Checking.sql
-- Desc    : Returns Agents Where Flagged for Checking or Outside Targets
-- Owner   : KS
-- Created : 07/08/2006
-- Amended : 14/08/2006 - MK - Added further security, to ensure that the 
--                             user executing the report is allowed to see
--                             the agent that has been passed in to the proc.
--
--       15/08/2006 - JL - Originally only worked for SQM, Added Level
--                 Indicator to Allow different levels. 
--           06/09/2006 - MK - Changed rules to only look for agents on 100%
--                             as defined by the mstt_AgentCompetence table.
--                             Returning CategoryOfBusinessLongDescription.
--########################################################################


  -- Local Variables
  DECLARE @ReportMonth AS DATETIME
  

  --Get Report Month
  SELECT @ReportMonth=MAX(ReportMonth) FROM mstt_AgentQualityAggregation where KPILevel = 'ADVISERKPI'
  
  
  /*

  if dbo.msf_SQCheckPermissions (
  @UserId     
  ,@AgentCode       
  ,@KPILevel      
  ,@hierarchyTypeCode 
  ,@NumberOfMonths   ) = 'DENY' 

  */
  if 1=2
    SELECT 
      null as AgentName, 
      null as ComplianceCategoryCode, 
      null as PracticeCode,
      null as SalesQualityPS,
      null as QMCode, 
      null as QMName
  else

  begin

/*
  --Pivots Quality Targets into Flat Table
  SELECT 
    KPILevel,
    ComplianceCategoryCode,
    QualityTargetTypeCode,
    TargetValue AS SATarget,
    (SELECT 
      TargetValue AS CQTarget
      FROM mstt_QualityTarget
        WHERE
          KPILevel='ALL'
          AND ComplianceCategoryCode=QT.ComplianceCategoryCode
          AND QualityTargetPurposeCode='CQ'
          AND QualityTargetTypeCode='BENCHMARK') CQTarget,
    (SELECT 
      TargetValue AS RejectTarget
      FROM mstt_QualityTarget
        WHERE
          KPILevel='ALL'
          AND ComplianceCategoryCode=QT.ComplianceCategoryCode
          AND QualityTargetPurposeCode='Reject'
          AND QualityTargetTypeCode='BENCHMARK') RejectTarget
  INTO #tmp_QualityTargets
  FROM 
    mstt_QualityTarget QT
  WHERE
    KPILevel='ALL'
    AND QualityTargetPurposeCode='SA'
    AND QualityTargetTypeCode='BENCHMARK'

  --Extract Agent Over BenchMarks or on Monitor
  SELECT DISTINCT 
    --Agents.CODE AS AgentCode, 
    Agents.DESCN AS AgentName, 
    QT.ComplianceCategoryCode, 
    PC.Descn as PracticeCode,
                PS.Descn as SalesQualityPS,
    ISNULL(QM.CODE, 'N/A')AS QMCode, 
    ISNULL(QM.DESCN, 'N/A') AS QMName
  FROM         
    mstt_AgentQualityAggregation AQA 
    INNER JOIN mstt_AgentCompetence AC 
      ON AQA.AgentCode = AC.AgentCode 
--        AND AC.ComplianceCategoryCode=@ComplianceCategoryCode
        AND @ReportMonth Between AchievedDate And IsNULL(EndDate,GetDAte())
    INNER JOIN mstt_Agents Agents 
      ON AQA.AgentCode = Agents.CODE 
    INNER JOIN #tmp_QualityTargets QT 
      ON QT.ComplianceCategoryCode = AQA.ComplianceCategoryCode
    INNER JOIN mstt_AgentQualityHierarchy AQH 
      ON AQH.AgentCode = Agents.CODE 
    LEFT OUTER JOIN mstt_Agents QM 
      ON QM.CODE = AQH.SalesQualitySQMLevelCode
    LEFT OUTER JOIN mstt_Agents PC 
      ON PC.CODE = AQH.PracticeCode
    LEFT OUTER JOIN mstt_Agents PS
      ON PS.CODE = AQH.SalesQualityPSLevelCode
  WHERE     
    (QT.KPILevel = 'All') 
    AND (AQA.SummaryPeriod = 1) 
--    AND (QT.ComplianceCategoryCode = @ComplianceCategoryCode) 
    AND (AQH.IsCurrent = 1)
    AND AQA.ReportMonth=@ReportMonth
    --AND AQA.KPILevel= 'AdviserKPI'
    --Level To Obtain Depends on  ASQM or Standard
    AND AQA.KPILevel in (SELECT CASE @Level
                  WHEN 'ASQM' Then 'SQMKPI' 
                  ELSE 'AdviserKPI'
                  END 
              UNION SELECT CASE @Level
                  WHEN 'ASQM' Then 'RSMKPI' 
                  ELSE 'AdviserKPI'
                  END )
    --For ASQM use the SQM Level, and BUT RSM Must also be NULL
    AND CASE @Level
        WHEN 'ASD' THEN AQH.SalesQualityASDLevelCode
        WHEN 'ASQM' THEN AQH.SalesQualitySQMLevelCode
        WHEN 'RSM' THEN AQH.SalesQualityRSMLevelCode
        WHEN 'SQM' THEN AQH.SalesQualitySQMLevelCode
        WHEN 'PS' THEN AQH.SalesQualityPSLevelCode
        END  = @ManagerCode
    --IF ASQM Level then RSM must be NULL.
    AND CASE @Level
        WHEN 'ASQM' THEN AQH.SalesQualityRSMLevelCode 
        ELSE NULL
      END IS NULL
    AND (AQA.SAKPIPercent * 100.00 >= SATarget * 3
        OR AQA.CQKPIPercent*100>= CQTarget * 3
        OR AC.PercentageMon = 1 
        OR AC.EntryStatusCode IN ('INE', 'ENE'))
  GROUP BY
    QT.ComplianceCategoryCode,
    Agents.DESCN,
    PC.Descn,
    PS.Descn,
    QM.CODE,
    QM.DESCN
    
drop table #tmp_QualityTargets

*/

    SELECT 
    ag.Descn as AgentName, 
    cob.CategoryOfBusinessLongDescription as ComplianceCategoryCode, 
    pc.Descn as PracticeCode,
    ps.Descn as SalesQualityPS,
    ISNULL(QM.CODE, 'N/A')AS QMCode, 
    ISNULL(QM.DESCN, 'N/A') AS QMName
    into #Checking
    from
      mstt_AgentCompetence ac
        inner join msv_CategoryOfBusiness cob
          on ac.ComplianceCategoryCode = cob.ComplianceCategoryCode
        inner join mstt_AgentQualityHierarchy aqh
          on ac.AgentCode = aqh.AgentCode
        inner join mstt_Agents ag
          on aqh.AgentCode = ag.Code
        left join mstt_Agents pc
          on aqh.PracticeCode = pc.Code
        left join mstt_Agents ps
          on aqh.SalesQualityPSLevelCode = ps.Code
        left join mstt_Agents QM
          on aqh.SalesQualitySQMLevelCode = qm.Code
    where
      @ReportMonth between ac.AchievedDate and isnull(EndDate,getdate())
      and @ReportMonth between aqh.AgentHierarchyStartDate and aqh.AgentHierarchyEndDate
      AND CASE @Level
        WHEN 'ASD' THEN AQH.SalesQualityASDLevelCode
        WHEN 'ASQM' THEN AQH.SalesQualitySQMLevelCode
        WHEN 'RSM' THEN AQH.SalesQualityRSMLevelCode
        WHEN 'SQM' THEN AQH.SalesQualitySQMLevelCode
        WHEN 'PS' THEN AQH.SalesQualityPSLevelCode
        END  = @ManagerCode
    --IF ASQM Level then RSM must be NULL.
    AND CASE @Level
        WHEN 'ASQM' THEN AQH.SalesQualityRSMLevelCode 
        ELSE NULL
      END IS NULL
    and AC.PercentageMon = 1 
    and AC.EntryStatusCode IN ('INE', 'ENE')
    order by cob.CategoryOfBusinessSequence, 1
    
    if (select count(*) from #Checking) = 0 
    
      SELECT 
        null as AgentName, 
        null as ComplianceCategoryCode, 
        null as PracticeCode,
        null as SalesQualityPS,
        null as QMCode, 
        null as QMName

    else
    
      SELECT 
        AgentName, 
        ComplianceCategoryCode, 
        PracticeCode,
        SalesQualityPS,
        QMCode, 
        QMName
      FROM
        #Checking
    
end


GO
/****** Object:  StoredProcedure [dbo].[msp_Level]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
