CREATE PROCEDURE [dbo].[msp_ManagerLeague] -- WITH RECOMPILE,ENCRYPTION
  /* Param List */
AS

/******************************************************************************

Copyright (C) Moore Stephens Consulting Limited 2005

Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
          
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>

Amendment History
=================

Date		Author		Description
----------	------		-----------
20/10/2014	A Groves	SR341528. Handle non-numeric UIDs to protect the batch.
*******************************************************************************/
truncate table mst_ManagerLeague

insert into
 mst_ManagerLeague
select
 s.PolicyNumber,
 c.Code,
 s.ProductId,
 '',
 '',
 b.DateTime,
 a.FranchiseSizeId,
 '',
 s.Turnover,  --measure
 rtrim(ltrim(a.AreaSalesManager)) [Area],
 rtrim(ltrim(a.RegionalSalesManager)) [Region]
from 
 msft_Sales s,
 msdt_Adviser a,
 mstt_Agents c,
 msdt_CalendarTime b
where
 s.AdviserId = a.AdviserId			and
 a.FranchiseCode = c.Code			and
 c.code not like '%[A-Z]%'			and	-- AG 20/10/2014
 s.DateIssuedId = b.DateId			and
 c.AgentType in (2,52,53,54,55,49)  and --2=Franchise, 52-55=Manager Level 1 to 4, 49=Directly Authorised
 b.entrytypeid = 2					and
 s.BusinessTypeId = 2				and --business type 2 = issued
 left(b.YearMonth,4) between year(getdate())-1 and year(getdate())  and --current & previous years
 right(b.YearMonth,2) >= '01'		and
 right(b.YearMonth,2) <= month(getdate()) and
 s.comparisonId = 1  -- comparisonid 1 = Actual
 
--Include Sales for Inactive franchises as found in the AdviserDummies table
insert into
 mst_ManagerLeague
select
 s.PolicyNumber,
 a.adviserid,
 s.ProductId,
 '',
 '',
 b.DateTime,
 a.FranchiseSizeId,
 '',
 s.Turnover,  --measure
 rtrim(ltrim(a.AreaSalesManager)) [Area],
 rtrim(ltrim(a.RegionalSalesManager)) [Region]
from 
 msft_Sales s,
 msdt_AdviserDummies a,
 msdt_CalendarTime b
where
 s.AdviserId = a.AdviserId      and
 s.DateIssuedId = b.DateId      and
 b.entrytypeid = 2        and
 s.BusinessTypeId = 2       and --business type 2 = issued
 left(b.YearMonth,4) between year(getdate())-1 and year(getdate())  and --current & previous years
 right(b.YearMonth,2) >= '01'     and
 right(b.YearMonth,2) <= month(getdate()) and
 s.comparisonId = 1  -- comparisonid 1 = Actual

--
--21/6/2006 - Franchise Dummies have since been included in the adviser table so this is no longer required
--
----Get the same information, but this time join to AdviserDummies, as there is a lot of
----business that is linked to Franchises, rather than Advisers. The AdviserId for the franchises
----are in the dummies table. 
--
--insert into
-- mst_ManagerLeague
--select
-- s.PolicyNumber,
-- c.Code,
-- s.ProductId,
-- '',
-- '',
-- b.DateTime,
-- a.FranchiseSizeId,
-- '',
-- s.Turnover,  --measure
-- rtrim(ltrim(a.AreaSalesManager)) [Area],
-- rtrim(ltrim(a.RegionalSalesManager)) [Region]
--from 
-- msft_Sales s,
-- msdt_AdviserDummies a,
-- mstt_Agents c,
-- msdt_CalendarTime b
--where
-- s.AdviserId = a.AdviserId    and
-- a.FranchiseCode = c.Code     and
-- s.DateIssuedId = b.DateId    and
-- c.AgentType = 2          and
-- b.entrytypeid = 2        and
-- s.BusinessTypeId = 2       and --business type 2 = issued
-- left(b.YearMonth,4) between year(getdate())-1 and year(getdate())  and --current & previous years
-- right(b.YearMonth,2) >= '01'     and
-- right(b.YearMonth,2) <= month(getdate()) and
-- s.comparisonId = 1  -- comparisonid 1 = Actual


--
--21/6/2006 - League Only Production Adjustments should not be included in RSM League Tables
--        Confirmed in e-mail from Terry Lister
--
----
---- Add League only Production Adjustments 
----
--insert into
-- mst_ManagerLeague
--select
-- s.PolicyNumber,
-- c.Code,
-- s.ProductId,
-- '',
-- '',
-- b.DateTime,
-- s.FranchiseSizeId,
-- '',
-- s.Turnover,  --measure
-- rtrim(ltrim(a.AreaSalesManager)) [Area],
-- rtrim(ltrim(a.RegionalSalesManager)) [Region]
--from 
-- mstt_ProductionAdjustments s,
-- msdt_Adviser a,
-- mstt_Agents c,
--(
--select
-- DateId,
-- Year [IssuedDate],
-- DateTime [DateTime]
--from
-- msdt_CalendarTime
--where
-- entrytypeid = 2   -- entry type id = 2 for issued 
--) b
--where
-- c.Code = a.FranchiseCode and
-- a.AgentCode = s.AgentCode and
-- s.DateIssuedId = b.DateId and  --change to dateissuedid
--/*
--   For Production Adjustments:
--  AgentType is always Franchise
--  Business Type is always Issued
--  Comparison is always Actual
--*/
---- c.AgentType = 2 and
---- s.BusinessTypeId = 2 and --business type 2 = issued
---- s.ComparisonId = 1   --ComparisonId 1 = Actual
--/*
--   Only add league only adjustments as production adjustments are already
--   in the msft_Sales table.
--*/
-- s.ProductionFlag = 'N'
-- -- Ignore any records where the year of the Date Issued is different from the Year column.
---- They would be different when either adjusted in advance for the next year or are
---- adjustments for the previous year.
--and b.IssuedDate = s.[Year] 

update
 mst_ManagerLeague
set
 ProductGroup = p.ProductGroupName,
 ProductSubGroup = p.ProductSubGroupName
from 
 msdt_Products p
where
 mst_ManagerLeague.ProductId = p.ProductId


--Do the same for business that is at a ProductGroup level, such as Mortgage and GI transition business

update
 mst_ManagerLeague
set
 ProductGroup = p.ProductGroupName,
 ProductSubGroup = p.ProductSubGroupName
from 
 msdt_ProductDummies p
where
 mst_ManagerLeague.ProductId = p.ProductId
 

update
 mst_ManagerLeague
set
 Size = s.FranchiseSizeType
from 
 msdt_FranchiseSize s
where
 mst_ManagerLeague.SizeId = s.FranchiseSizeId
 






