/****** Object:  StoredProcedure [dbo].[msp_matrixtest]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
create procedure [dbo].[msp_matrixtest]
@BusinessType nvarchar(50),
@Measure nvarchar(50),
@DateRange nvarchar(50),
@UserId nvarchar(50)
as
select 
Area,
Region,
Franchise,
Adviser,
case when ActiveStatus = '1' then 'Y' else 'N' end ActiveStatus,
ProductGroup,
case when @BusinessType = 'Written' then DateWritten else DateIssued end [Period],
case when @BusinessType = 'Written' then DateWritten else DateIssued end [Period2],
case when @Measure = 'Turnover' then sum(p.Turnover) 
     when @Measure = 'Cases' then sum(p.Cases)
     when @Measure = 'Distibution Allowance' then sum(p.DA)
     when @Measure = 'NBI' then sum(p.NBI)
     when @Measure = 'Sales Margin' then sum(p.SalesMargin)
     else 0 end [Amount]
into #mst_matrix
from 
 mst_Production p
where
 case when @BusinessType = 'Written' then p.DateWritten else p.DateIssued end between
 case when @DateRange = 'Month by Month'  then convert(nvarchar(6),getdate(),112)
      when @DateRange = 'Rolling 12 Months' then convert(nvarchar(6),dateadd(mm,-12,getdate()),112)
      else convert(nvarchar(6),dateadd(mm,-6,getdate()),112) end and
 convert(nvarchar(6),getdate(),112) and
Franchise in (
select distinct Franchise
from msdt_Adviser a
  inner join msct_UserAccessControl uac
    on a.AdviserId = uac.AdviserId
where uac.DomainLogin = @UserId )
group by
Area,
Region,
Franchise,
Adviser,
ActiveStatus,
ProductGroup,
case when @BusinessType = 'Written' then DateWritten else DateIssued end
insert into #mst_matrix
select 
Area,
Region,
Franchise,
Adviser,
case when ActiveStatus = '1' then 'Y' else 'N' end,
ProductGroup,
'YTD',
(year(getdate()) * 100) + 12,
case when @Measure = 'Turnover' then sum(p.Turnover) 
     when @Measure = 'Cases' then sum(p.Cases)
     when @Measure = 'Distibution Allowance' then sum(p.DA)
     when @Measure = 'NBI' then sum(p.NBI)
     when @Measure = 'Sales Margin' then sum(p.SalesMargin)
     else 0 end [Amount]
from 
 mst_Production p
where
 case when @BusinessType = 'Written' then left(p.DateWritten,4) else left(p.DateIssued,4) end =
 year(getdate()) and
 Franchise in (
select distinct Franchise
from msdt_Adviser a
  inner join msct_UserAccessControl uac
    on a.AdviserId = uac.AdviserId
where uac.DomainLogin = @UserId )
group by
Area,
Region,
Franchise,
Adviser,
ActiveStatus,
ProductGroup
insert into #mst_matrix
select 
Area,
Region,
Franchise,
Adviser,
case when ActiveStatus = '1' then 'Y' else 'N' end,
ProductGroup,
'YTDP',
(year(dateadd(yy,-1,getdate())) * 100) + 12,
case when @Measure = 'Turnover' then sum(p.Turnover) 
     when @Measure = 'Cases' then sum(p.Cases)
     when @Measure = 'Distibution Allowance' then sum(p.DA)
     when @Measure = 'NBI' then sum(p.NBI)
     when @Measure = 'Sales Margin' then sum(p.SalesMargin)
     else 0 end [Amount]
from 
 mst_Production p
where
 case when @BusinessType = 'Written' then p.DateWritten else p.DateIssued end between
 convert(nvarchar(4),dateadd(yy,-1,getdate()),112) + '01'
 and
 convert(nvarchar(6),dateadd(yy,-1,getdate()),112) and
 Franchise in (
select distinct Franchise
from msdt_Adviser a
  inner join msct_UserAccessControl uac
    on a.AdviserId = uac.AdviserId
where uac.DomainLogin = @UserId )
group by
Area,
Region,
Franchise,
Adviser,
ActiveStatus,
ProductGroup
select
 Area,
 Region,
 Franchise,
 Adviser,
 ActiveStatus,
 ProductGroup,
--  [Period],
--  [Period2],
--  [Amount],
 sum(case when left(Period,3) <> 'YTD' and datediff(mm,convert(datetime,([Period2]) + '01'), convert(datetime,(convert(nvarchar(6),getdate(),112) + '01'))) = '11' then [Amount] else '0' end) '1',
 sum(case when left(Period,3) <> 'YTD' and datediff(mm,convert(datetime,([Period2]) + '01'), convert(datetime,(convert(nvarchar(6),getdate(),112) + '01'))) = '10' then [Amount] else '0' end) '2',
 sum(case when left(Period,3) <> 'YTD' and datediff(mm,convert(datetime,([Period2]) + '01'), convert(datetime,(convert(nvarchar(6),getdate(),112) + '01'))) = '9' then [Amount] else '0' end) '3',
 sum(case when left(Period,3) <> 'YTD' and datediff(mm,convert(datetime,([Period2]) + '01'), convert(datetime,(convert(nvarchar(6),getdate(),112) + '01'))) = '8' then [Amount] else '0' end) '4',
 sum(case when left(Period,3) <> 'YTD' and datediff(mm,convert(datetime,([Period2]) + '01'), convert(datetime,(convert(nvarchar(6),getdate(),112) + '01'))) = '7' then [Amount] else '0' end) '5',
 sum(case when left(Period,3) <> 'YTD' and datediff(mm,convert(datetime,([Period2]) + '01'), convert(datetime,(convert(nvarchar(6),getdate(),112) + '01'))) = '6' then [Amount] else '0' end) '6',
 sum(case when left(Period,3) <> 'YTD' and datediff(mm,convert(datetime,([Period2]) + '01'), convert(datetime,(convert(nvarchar(6),getdate(),112) + '01'))) = '5' then [Amount] else '0' end) '7',
 sum(case when left(Period,3) <> 'YTD' and datediff(mm,convert(datetime,([Period2]) + '01'), convert(datetime,(convert(nvarchar(6),getdate(),112) + '01'))) = '4' then [Amount] else '0' end) '8',
 sum(case when left(Period,3) <> 'YTD' and datediff(mm,convert(datetime,([Period2]) + '01'), convert(datetime,(convert(nvarchar(6),getdate(),112) + '01'))) = '3' then [Amount] else '0' end) '9',
 sum(case when left(Period,3) <> 'YTD' and datediff(mm,convert(datetime,([Period2]) + '01'), convert(datetime,(convert(nvarchar(6),getdate(),112) + '01'))) = '2' then [Amount] else '0' end) '10',
 sum(case when left(Period,3) <> 'YTD' and datediff(mm,convert(datetime,([Period2]) + '01'), convert(datetime,(convert(nvarchar(6),getdate(),112) + '01'))) = '1' then [Amount] else '0' end) '11',
 sum(case when left(Period,3) <> 'YTD' and datediff(mm,convert(datetime,([Period2]) + '01'), convert(datetime,(convert(nvarchar(6),getdate(),112) + '01'))) = '0' then [Amount] else '0' end) '12',
 sum(case when [Period] = 'YTD' then [Amount] else '0' end) 'YTD',
 sum(case when [Period] = 'YTDP' then [Amount] else '0' end) 'YTDP'
from
 #mst_matrix
where
Franchise in (
select distinct Franchise
from msdt_Adviser a
  inner join msct_UserAccessControl uac
    on a.AdviserId = uac.AdviserId
where uac.DomainLogin = @UserId )
group by
 Area,
 Region,
 Franchise,
 Adviser,
 ActiveStatus,
 ProductGroup--,
--  [Period],
--  [Period2],
--  [Amount]
order by
 4,7
drop table #mst_matrix

GO
/****** Object:  StoredProcedure [dbo].[msp_MCVTranTotals]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO



CREATE procedure [dbo].[msp_MCVTranTotals]
with recompile
as
 
--########################################################################
--
-- Object  : procedure
-- Name    : msp_MCVTranTotals.sql
-- Owner   : MPC
-- Created : 25 May 2007
-- Project : MCV 
--
--########################################################################

-- Scan repopulates the MCV Transaction table (mstt_MCVTranTotals)
-- Scan defaults end date to last day of Run nonth and populates data for the next 15 years
-- Data reported at Business within Transaction
-- Separate report procs enable the business to extract details for a Business

set nocount on

--declare @StartDate datetime -- Start Date for Finstat and Reporting Period
--set @StartDate = '2006/01/01'    

declare @PrdEndDate datetime  -- set to first of next Month for Finstat Balance
set @PrdEndDate = convert(datetime,convert(nvarchar(6), dateadd(mm,1,getdate()),112) + '01')  

declare @EndDate datetime -- End Date for Reporting Period (end of CURRENT Month)
set @EndDate = CAST(CONVERT(NVARCHAR,dateadd(dd,-1,@PrdEndDate), 112) AS DATETIME)  

declare @TFSellerMonths int   -- Protected Trail Fee period for original seller
set @TFSellerMonths = 60

declare @LevelIPMonths int  -- Nominal Initial Period for Level cases
set @LevelIPMonths = 60

select 'Starting',getdate()

/*
  Following ripped from cscp_Finstat001a procedure
  and expanded to include cscp_Finstat7c handling of margin calcs and amount
`*/

IF OBJECT_ID('tempdb..#Exp') IS NOT NULL
   DROP TABLE #Exp
IF OBJECT_ID('tempdb..#Comms') IS NOT NULL
   DROP TABLE #Comms
IF OBJECT_ID('tempdb..#Trans') IS NOT NULL
  drop table #Trans
IF OBJECT_ID('tempdb..#FutureExp') IS NOT NULL
  drop table #FutureExp
IF OBJECT_ID('tempdb..#FutureMonthICRC') IS NOT NULL
  drop table #FutureMonthICRC
IF OBJECT_ID('tempdb..#TranFees') IS NOT NULL
  drop table #TranFees
IF OBJECT_ID('tempdb..#TrailFees') IS NOT NULL
  drop table #TrailFees
IF OBJECT_ID('tempdb..#FutureMonth') IS NOT NULL
  drop table #FutureMonth
IF OBJECT_ID('tempdb..#TranMonth') IS NOT NULL
  drop table #TranMonth
IF OBJECT_ID('tempdb..#Paid') IS NOT NULL
  drop table #Paid

-- Calculate Margin percent for each Transaction
create table #Comms 
  (TransactionID  int, 
   NetAmount  decimal(15,2), 
   TotalAmount  decimal(15,2), 
   Margin_Pct   float,
   Primary Key (TransactionID)
  )
insert #Comms
select  TransactionID,
  sum(case GrossOrNet
    when 'N' then FixedAmount
    else 0
  end),
  sum(FixedAmount),
  case  when coalesce(sum(FixedAmount),0)<>0 then
      sum(case GrossOrNet when 'N' then FixedAmount else 0 end)
      / sum(FixedAmount)
    else 0
    -- from UDF comments
    -- Set Margin % = 0 (i.e. Commission % = 100)
    -- Set Margin % = NULL (i.e. Margin % = 0; Commission % = 0)
  end
from  mstt_Commissions
where CommissionType = 1
group by TransactionID

select 'one',getdate()

-- Table to store calculated data for each expectation (Accruals only)
create table #Exp (
  ExpectationID int,
  TransactionID int,
  Type    tinyint,
  DisplayType tinyint,
  ProviderCode  varchar(10) collate LATIN1_GENERAL_CI_AS,
  BasisCode varchar(1) collate LATIN1_GENERAL_CI_AS,
  Basis   varchar(50) collate LATIN1_GENERAL_CI_AS,
  Amount_Due  decimal(15,2),
  Amount_Rec  decimal(15,2),
  Date_Due  datetime,
  DueYrMth  varchar(7),
  Date_Recv datetime,
  Margin_Pct  float,
  Margin_Due  decimal(15,2),
  Margin_Recv decimal(15,2),
  Commission_Due  decimal(15,2),
  Commission_Recv decimal(15,2),
  IRD   datetime,
  PolicyID  int,
  Status    tinyint,
  Adjust    tinyint,
  firm            VARCHAR(7)
  )
insert #Exp
Select  e.ID,
  e.TransactionID,
  e.Type,
  CASE e.Type
    WHEN 1 THEN 1   -- IC
    When 2 then 1   -- IC Clawback (treat as negative below)
    WHEN 17 THEN 1  -- IC adjustment (treat as negative below)
    WHEN 4 THEN 4   -- RC
    WHEN 15 THEN 4  -- RC clawback (treat as negative below)
    WHEN 18 THEN 4  -- RC adjustment (treat as negative below)
    WHEN 10 THEN 10 -- Trail
    WHEN 16 THEN 10 -- Trail clawback (treat as negative below)
    WHEN 19 THEN 10 -- Trail adjustment (treat as negative below)
  END ,       -- Display Type
  e.COMP_CODE,    -- provider code
  pt.CommType as BasisCode,   -- Basis code
  ISNULL(pt.CommissionTypeDesc, 'Unknown'), -- Basis description
  CASE
    WHEN e.Type in (1,4,10) THEN COALESCE(e.Amount_Due,0)
    ELSE COALESCE(e.Amount_Due,0) * (-1)
  END,  -- Amount_Due
  CASE 
    WHEN e.Type in (1,4,10) THEN COALESCE(e.Amount_Rec,0)
    ELSE COALESCE(e.Amount_Rec,0) * (-1)
  END,  -- Amount_Recv

  CAST(CONVERT(NVARCHAR, e.Date_Due, 112) AS DATETIME),
  substring(cast(convert(nvarchar, e.date_due, 120) as varchar), 1, 7) as DueYrMth,
  CAST(CONVERT(NVARCHAR, e.Date_Recv, 112) AS DATETIME),  -- convert to "whole day" 
  
  c.Margin_Pct, -- Margin Pct
  
  COALESCE(e.Amount_Due
  * CASE WHEN e.Type in (1,4,10) THEN 1 ELSE -1 END 
  * CASE WHEN e.Type in (1,2,17) THEN c.Margin_Pct ELSE 0 END,0) 
  , -- Margin Due

  COALESCE(e.Amount_Rec
  * CASE WHEN e.Type in (1,4,10) THEN 1 ELSE -1 END 
  * CASE WHEN e.Type in (1,2,17) THEN c.Margin_Pct ELSE 0 END,0) 
  , -- Margin Recv

  COALESCE(
  CASE WHEN e.Type in (1,4,10) THEN 1 ELSE -1 END 
  * CASE WHEN e.Type in (1,2,17) THEN (convert(decimal(15,2),e.Amount_Due) - convert(decimal(15,2),e.Amount_Due * c.Margin_Pct)) ELSE e.Amount_Due END
  ,0) , -- Commission Due

  COALESCE(
  CASE WHEN e.Type in (1,4,10) THEN 1 ELSE -1 END 
  * CASE WHEN e.Type in (1,2,17) THEN (convert(decimal(15,2),e.Amount_Rec) - convert(decimal(15,2),e.Amount_Rec * c.Margin_Pct)) ELSE e.Amount_Rec END
  ,0) , -- Commission Recv

  e.IncomeRecognitionDate,  -- IRD
  pt.PolicyID,
  e.status,
  e.adjust,
        A.firm
from  mstt_Expectation e
  inner join mstt_PolicyTransactions pt on e.TransactionID = pt.ID
  INNER JOIN mstt_Agents a ON pt.AgentCode = a.Code                          --restrict to openwork
  left outer join #Comms c on e.transactionID = c.TransactionID
where a.CompanyCode = 10002  -- Openwork (excludes Access)
and   e.Status = 1
and e.Type in (1,2,17,4,15,18)

create index ExpID on #exp(ExpectationID)
create index TranID on #exp(TransactionID)

select 'Done #exp',getdate()

select pol_num as PolicyID,sum(amountreceived) as Amount
into #Suspense
from mstt_Expectation ex
inner join msit_s_paccun un on un.pacc_id = ex.id
inner join mstt_policies po on po.cont_num = un.policy
inner join msit_edifactcommissionstatementcontents edc on edc.pacc_id = ex.id
where ex.type in (5,6) and ex.INIT_ID is NULL       -- Unmatched Suspense
--and edc.amountreceived > 0            -- Credits only
and (edc.CommissionType in ('I','Y') or edc.PaymentType = '04')   -- IC Accrual or IC Indemnity
group by pol_num
having sum(amountreceived) > 0
order by pol_num

select codecommissionshapeid as ShapeID,max(id) as LastRateID
into #LastShapeRate
from msit_codecommissionshaperatehistory
group by codecommissionshapeid
order by codecommissionshapeid

select  pt.Policyid,
  po.policyref as CaseID,
  po.cont_num as ProviderRef,
  coalesce(pt.commproductcode,po.productcode) as Product,
  pt.productgroupcode as ProdGroup,
  pt.productsubgroupcode as ProdSubGroup,
  coalesce(pt.commcompanycode,po.comp_code) as Provider,
  case when pt.StartDate > getdate() then pt.ProposalDate else pt.StartDate end as TranStartDate,
  isnull(pt.comminitialperiod,0) as InitPeriod,
  dateadd(mm,pt.comminitialperiod,pt.startdate) as IPEndDate,
  case when dateadd(mm,isnull(pt.comminitialperiod,0),pt.startdate) > @EndDate 
       then datediff(mm,pt.startdate,@EndDate) else 0 end as IPMonths,
  datediff(mm,pt.startdate,@EndDate) as TFMonths,
  dateadd(mm,@TFSellerMonths,pt.startdate) as ProtTFEndDate,
  dateadd(mm,@LevelIPMonths,pt.startdate) as LevelIPEndDate,
  pt.comminitialamount as TranDA,
  pt.ID as TranID,
  pt.TransType,
  pt.CommType as BasisCode,
  pt.frequency as FreqCode,
  case pt.frequency when 2 then 'Month' when 5 then 'Annual' when 6 then 'Single' end as Freq,
  case pt.commtype when 'F' then 'Accrual' when 'L' then 'Level' when 'T' then 'Indemnity' end as Basis,
  pt.amount as Premium,
  pt.codecommissionshapeid as ShapeId,
        sh.Description as Shapedescription,
  sr.trailfeerate as TFRate,
  case when sr.trailfeerate <> 0 then 'With TF' when sr.trailfeerate = 0 then 'No TF' end as TranTF,
  pt.createdatetime as CreateDate,
  case when t2.policyid is not null then 'Y' else 'N' end as PolinSusp,
  isnull(t2.Amount,0.00) as SuspAmount,
  NULL as ICDebt
into  #Trans
from  mstt_policytransactions pt
  inner join mstt_policies po on po.pol_num = pt.policyid
  left outer join msit_codecommissionshape sh on sh.id = pt.codecommissionshapeid
  left outer join #LastShapeRate t1 on t1.shapeid = sh.id
  left outer join msit_codecommissionshaperatehistory sr on sr.id = t1.LastRateID
  left outer join #Suspense t2 on t2.policyid = pt.policyid
where pt.id in (select transactionid from mstt_Expectation where type not in (5,6))
order by pt.id

drop table #LastShapeRate
drop table #Suspense

create index TranID on #Trans(TranID)

select 'Done #trans',getdate()

select co.transactionid as TranID,co.Firm,co.CommissionType as CommType,sum(co.agent_perc) as SplitPC
into #Splits
from mstt_Commissions co
inner join #Trans t1 on t1.Tranid = co.transactionid
where co.agent_code <> 10002
and co.Firm is not null
and co.GrossOrNet = 'G'
and co.agent_perc > 0
Group by co.transactionid,co.CommissionType,co.firm
Order by co.transactionid,co.CommissionType,co.firm

select t1.*,t2.Firm,t2.CommType,t2.SplitPC 
into #Transplits 
from #Trans t1 
inner join #Splits t2 on t1.TranID = t2.TranID
order by t1.TranID,t2.CommType,t2.Firm

--drop table #Trans
drop table #Splits

create index TranID on #Transplits(TranID)

select 'Done #transplits',getdate()

select  ex.transactionid as TranID,
  ex.DueYrMth,
  ex.DisplayType,
  ex.Basis,
  cast( t1.SplitPC/100 * sum(case when ex.status = 1 and ex.type in (1,4) then ex.amount_due 
                      when ex.status = 1 and ex.type in (2,15,17,18) then abs(ex.amount_due) * -1 else 0 end) 
              as decimal(15,2)) as GrossDueAmount,
  cast( t1.SplitPC/100 * sum(case when ex.status = 1 and ex.type in (1,4) then ex.commission_due 
                      when ex.status = 1 and ex.type in (2,15,17,18) then abs(ex.commission_due) * -1 else 0 end) 
              as decimal(15,2)) as DueAmount,
  t1.firm,
  t1.SplitPC,
  t1.Product,
  t1.ProdGroup,
  t1.ProdSubGroup
into  #FutureExp
from  #Exp ex
  inner join #Transplits t1 on t1.tranid = ex.transactionid
  and t1.CommType = case when ex.Type in (1,2,17) then 1 when ex.Type in (4,15,18) then 4 end
where   (  (ex.type = 1 and t1.BasisCode = 'F' and ex.date_due > @EndDate and ex.Amount_Due > 0) 
  OR (ex.date_due <= @EndDate)
  )
  and ex.status = 1         -- Unmatched
  and ex.IRD <= @EndDate        -- Matched amounts received
  and (t1.BasisCode = 'F' or ex.displaytype = 4)  -- exclude IC Indemnity and Level
group by ex.transactionid,
  t1.FIRM,
  t1.SplitPC,
  t1.Product,
  t1.ProdGroup,
  t1.ProdSubGroup,
  ex.DisplayType,
  ex.Basis,
  ex.DueYrMth,
  ex.date_due
order by ex.transactionid,
  ex.DisplayType,
  ex.Basis,
  ex.DueYrMth,
  ex.date_due

create index TranID on #FutureExp(TranID)

select 'Done #Futureexp',getdate()

