  Sum(case when substring(cast(convert(nvarchar, dateadd(mm,180,@EndDate), 120) as varchar), 1, 7) = DueYrMth then dueamount else 0 end) as AmtM180,

  Sum(case when substring(cast(convert(nvarchar, @EndDate, 120) as varchar), 1, 7) >= DueYrMth then dueamount else 0 end) as AmtBefore,
  Sum(case when substring(cast(convert(nvarchar, dateadd(mm,180,@EndDate), 120) as varchar), 1, 7) < DueYrMth then dueamount else 0 end) as AmtOver180,
  Sum(case when substring(cast(convert(nvarchar, @EndDate, 120) as varchar), 1, 7) > DueYrMth then dueamount else 0 end) as Debt
into  #FutureMonthICRC
from  #futureexp
group by TranID,Firm,SplitPC,DisplayType,Basis,Product,ProdGroup,ProdSubGroup
order by Tranid

create index TranID on #Futuremonthicrc (TranID)
select 'Done #Futuremonthicrc',getdate()

select t1.* into #FutureMonthValid
from #FutureMonthICRC t1
inner join #Trans t2 on t1.tranid = t2.tranid
where (isnull(t1.Debt,0) = 0 or (isnull(t1.debt,0) > 0 and t2.polinsusp = 'Y'))
and ((t1.AmtBefore >= 0 and t1.displayType = 1) or (t1.AmtBefore > 0 and t1.displayType = 4))

create index TranID on #Futuremonthvalid (TranID)
select 'Done #Futuremonthvalid',getdate()

drop table #FutureMonthICRC

update #Trans
set ICDebt = t1.Debt
from #FuturemonthValid t1
inner join #Trans t2 on t2.tranid = t1.tranid 
where t1.displaytype = 1

select 'Done Update #Trans',getdate()

select ex.transactionid as TranID,t1.Firm,t1.SplitPC,ex.Type,t1.Basis,t1.Product,t1.ProdGroup,t1.ProdSubGroup,
sum(amount_rec)*(t1.SplitPC/100) as AmountPaid,ex.PolicyID,count(*) as PaymentCount,
min(date_due) as FirstDue,max(date_due) as LastDue,(datediff(mm,min(date_due),max(date_due)) +1) as DueDiffMonths,
min(date_recv) as FirstRec,max(date_recv) as LastRec,(datediff(mm,min(date_recv),max(date_recv)) +1) as RecDiffMonths,
cast((sum(amount_rec)*12)/(datediff(mm,min(date_due),max(date_due)) +1)*(t1.SplitPC/100) as decimal(15,2)) as AnnualFee,
cast((sum(amount_rec)*12)/(datediff(mm,min(date_due),max(date_due)) +1)*(t1.SplitPC/100) as decimal(15,2)) as TrailFee
into #TranFees
from mstt_expectation ex
inner join #Transplits t1 on t1.Tranid = ex.transactionid and t1.Commtype = ex.Type
left outer join #Trans t2 on t2.tranid = ex.transactionid 
where ex.type = 10  -- Trail Fee
and status in (2,3)   -- Matched/Processed
and ex.amount_rec > 0   -- Postive Payments only
and (isnull(t2.ICDebt,0) = 0 or (isnull(t2.ICDebt,0) > 0 and t2.polinsusp = 'Y'))
group by ex.transactionid,t1.Firm,t1.Basis,ex.Type,ex.policyid,
t1.SplitPC,t1.Product,t1.ProdGroup,t1.ProdSubGroup
order by 1

select 'Done #TranFees',getdate()

select ex.PolicyID,max(ex.transactionid) as TranID
into #LatestTrailTran
from mstt_expectation ex
where ex.type = 10  -- Trail Fee
and status in (2,3)   -- Matched/Processed
and ex.amount_rec > 0   -- Postive Payments only
group by ex.policyid
order by 2

select 'Done #LatestTrailTran',getdate()

