order by t1.TranID

select 'Done #TrailFees',getdate()

select t1.Tranid,t1.InitPeriod,t1.IPMonths,isnull(t2.Margin_Pct,0) as Margin,
sum(case when status in (2,3) and amount_rec = 0 then -1 * abs(amount_due) 
when status in (2,3) and type in (2,17) then -1 * abs(amount_rec) 
when status in (2,3) and type = 1 then amount_rec else 0 end) as Received,
sum(case when status = 1 and ex.type in (2,17) then -1 * abs(amount_due)
when status = 1 and ex.type = 1 then amount_due else 0 end) as Due 
into #ITReceived
from #Trans t1
inner join mstt_expectation ex on ex.transactionid = t1.tranid
left outer join #Comms t2 on t2.transactionid = t1.tranid
where ex.type in (1,2,17)     -- IC/ Clawback/ Adjustments
--and ex.status in (2,3)      -- Matched/ Processed
and t1.basiscode = 'T'      -- IT
and t1.InitPeriod > 0     -- Init Period present
and t1.InitPeriod > t1.IPMonths   -- IP not completed 
group by t1.Tranid,t1.InitPeriod,t1.IPMonths,isnull(t2.Margin_Pct,0)
having -- Amount Received > 0
sum(case when status in (2,3) and amount_rec = 0 then -1 * abs(amount_due) 
when status in (2,3) and type in (2,17) then -1 * abs(amount_rec) 
when status in (2,3) and type = 1 then amount_rec else 0 end) > 0
AND -- Amount Due >= 0
sum(case when status = 1 and ex.type in (2,17) then -1 * abs(amount_due)
when status = 1 and ex.type = 1 then amount_due else 0 end) >= 0
order by t1.tranid

create index TranID on #ITReceived(TranID)

