--- Derive Future RC and Level payments ---

-- Step A: First extract Transaction details

select pt.id as TranID,co.Firm,co.commissiontype as DisplayType,
pt.CommProductCode as Product,pt.ProductGroupCode as ProdGroup,pt.ProductSubGroupCode as ProdSubGroup,
case pt.commtype when 'F' then 'Accrual' when 'L' then 'Level' when 'T' then 'Indemnity' end as OrigBasis,
case when pt.commtype = 'L' then pt.commlevelinstallment*(1-isnull(t1.margin_pct,0))/(case pt.frequency when 5 then 12 else 1 end)
else pt.commrenewalamount / (case pt.commrenewalfrequency when 3 then 3 when 5 then 12 else 1 end) 
end as NetAmount,t1.margin_pct as Margin,dateadd(mm,@LevelIPMonths,pt.startdate) as LevelIPEndDate,
case when dateadd(mm,isnull(pt.comminitialperiod,0),pt.startdate) > @EndDate 
then datediff(mm,pt.startdate,@EndDate) else 0 end as IPMonths,
case when pt.commtype = 'L' then pt.commlevelinstallment else pt.commrenewalamount end as GrossAmount,
case when pt.commtype = 'L' then pt.frequency else pt.commrenewalfrequency end as Freq,
pt.StartDate as TranStartDate,dateadd(mm,-1,isnull(pt.finishdate,'31 Dec 2999')) as TranEndDate,
dateadd(mm,isnull(pt.comminitialperiod,0),pt.startdate) as TranICEndDate,
pt.commlevellastinstallmentdate as LastLevelDate,
case when pt.commtype = 'L' then dateadd(mm,(case pt.frequency when 2 then 1 when 5 then 12 when 3 then 3 else 0 end),pt.commlevellastinstallmentdate)
else dateadd(mm,(case pt.commrenewalfrequency when 2 then 1 when 3 then 3 when 5 then 12 else 0 end),dateadd(mm,isnull(pt.comminitialperiod,0),pt.startdate))
end as StartDate,sum(agent_perc) as SplitPC

into #RCLevelTran

from mstt_policytransactions pt
inner join mstt_commissions co on co.transactionid = pt.id
left outer join #Comms t1 on pt.ID = t1.TransactionID

where co.agent_code <> 10002
and pt.id in (select distinct transactionid from mstt_Expectation)
and ((pt.Commtype = 'L' and co.commissiontype = 1 and pt.frequency <> 6) 
or (pt.renewalrate > 0 and co.commissiontype = 4))

group by pt.id ,co.Firm,co.commissiontype,pt.CommProductCode,pt.ProductGroupCode,pt.ProductSubGroupCode,
case pt.commtype when 'F' then 'Accrual' when 'L' then 'Level' when 'T' then 'Indemnity' end,
case when pt.commtype = 'L' then pt.commlevelinstallment*(1-isnull(t1.margin_pct,0))/(case pt.frequency when 5 then 12 else 1 end)
else pt.commrenewalamount / (case pt.commrenewalfrequency when 3 then 3 when 5 then 12 else 1 end) end,
t1.margin_pct,dateadd(mm,@LevelIPMonths,pt.startdate),
case when dateadd(mm,isnull(pt.comminitialperiod,0),pt.startdate) <= @EndDate then isnull(pt.comminitialperiod,0)
else datediff(mm,pt.startdate,@EndDate) end,
case when pt.commtype = 'L' then pt.commlevelinstallment else pt.commrenewalamount end,
case when pt.commtype = 'L' then pt.frequency else pt.commrenewalfrequency end,
pt.StartDate,dateadd(mm,-1,isnull(pt.finishdate,'31 Dec 2999')),
dateadd(mm,isnull(pt.comminitialperiod,0),pt.startdate),pt.commlevellastinstallmentdate,
case when pt.commtype = 'L' then dateadd(mm,(case pt.frequency when 2 then 1 when 5 then 12 when 3 then 3 else 0 end),pt.commlevellastinstallmentdate)
else dateadd(mm,(case pt.commrenewalfrequency when 2 then 1 when 3 then 3 when 5 then 12 else 0 end),dateadd(mm,isnull(pt.comminitialperiod,0),pt.startdate)) end

order by pt.id,co.commissiontype,co.firm

drop table #Comms

select 'Done #RCLevelTran',getdate()

-- Step B: Then update table if entries already exist

-- Update first 60 months for Renewals and Level (as Accrual) 
update mstt_mcvtrantotals
set 
mth001 = case when dateadd(mm,1,@EndDate) <= t1.LevelIPEndDate and dateadd(mm,1,@EndDate) between t1.StartDate and t1.TranEndDate then mcv.mth001 + t1.netamount else mcv.mth001 end,
mth002 = case when dateadd(mm,2,@EndDate) <= t1.LevelIPEndDate and dateadd(mm,2,@EndDate) between t1.StartDate and t1.TranEndDate then mcv.mth002 + t1.netamount else mcv.mth002 end,
mth003 = case when dateadd(mm,3,@EndDate) <= t1.LevelIPEndDate and dateadd(mm,3,@EndDate) between t1.StartDate and t1.TranEndDate then mcv.mth003 + t1.netamount else mcv.mth003 end, 
mth004 = case when dateadd(mm,4,@EndDate) <= t1.LevelIPEndDate and dateadd(mm,4,@EndDate) between t1.StartDate and t1.TranEndDate then mcv.mth004 + t1.netamount else mcv.mth004 end, 
mth005 = case when dateadd(mm,5,@EndDate) <= t1.LevelIPEndDate and dateadd(mm,5,@EndDate) between t1.StartDate and t1.TranEndDate then mcv.mth005 + t1.netamount else mcv.mth005 end, 
mth006 = case when dateadd(mm,6,@EndDate) <= t1.LevelIPEndDate and dateadd(mm,6,@EndDate) between t1.StartDate and t1.TranEndDate then mcv.mth006 + t1.netamount else mcv.mth006 end, 
mth007 = case when dateadd(mm,7,@EndDate) <= t1.LevelIPEndDate and dateadd(mm,7,@EndDate) between t1.StartDate and t1.TranEndDate then mcv.mth007 + t1.netamount else mcv.mth007 end, 
