mth011 = case when dateadd(mm,11,@EndDate) <= t1.LevelIPEndDate and dateadd(mm,11,@EndDate) between t1.StartDate and t1.TranEndDate then mcv.mth011 + t1.netamount else mcv.mth011 end,
mth012 = case when dateadd(mm,12,@EndDate) <= t1.LevelIPEndDate and dateadd(mm,12,@EndDate) between t1.StartDate and t1.TranEndDate then mcv.mth012 + t1.netamount else mcv.mth012 end, 
mth013 = case when dateadd(mm,13,@EndDate) <= t1.LevelIPEndDate and dateadd(mm,13,@EndDate) between t1.StartDate and t1.TranEndDate then mcv.mth013 + t1.netamount else mcv.mth013 end, 
mth014 = case when dateadd(mm,14,@EndDate) <= t1.LevelIPEndDate and dateadd(mm,14,@EndDate) between t1.StartDate and t1.TranEndDate then mcv.mth014 + t1.netamount else mcv.mth014 end, 
mth015 = case when dateadd(mm,15,@EndDate) <= t1.LevelIPEndDate and dateadd(mm,15,@EndDate) between t1.StartDate and t1.TranEndDate then mcv.mth015 + t1.netamount else mcv.mth015 end, 
mth016 = case when dateadd(mm,16,@EndDate) <= t1.LevelIPEndDate and dateadd(mm,16,@EndDate) between t1.StartDate and t1.TranEndDate then mcv.mth016 + t1.netamount else mcv.mth016 end, 
mth017 = case when dateadd(mm,17,@EndDate) <= t1.LevelIPEndDate and dateadd(mm,17,@EndDate) between t1.StartDate and t1.TranEndDate then mcv.mth017 + t1.netamount else mcv.mth017 end, 
mth018 = case when dateadd(mm,18,@EndDate) <= t1.LevelIPEndDate and dateadd(mm,18,@EndDate) between t1.StartDate and t1.TranEndDate then mcv.mth018 + t1.netamount else mcv.mth018 end, 
mth019 = case when dateadd(mm,19,@EndDate) <= t1.LevelIPEndDate and dateadd(mm,19,@EndDate) between t1.StartDate and t1.TranEndDate then mcv.mth019 + t1.netamount else mcv.mth019 end, 
