/****** Object:  StoredProcedure [dbo].[msp_MenuLogMostPopularForRole]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER OFF
GO
CREATE Procedure [dbo].[msp_MenuLogMostPopularForRole]
@Role VARCHAR(64)
AS
 
/******************************************************************************
**                     File: 
**                     Name: msp_MenuLogMostPopularForRole
**                     Desc: 
**
**                     This template can be customized:
**              
**                     Return values:
** 
**                     Called by:   
**              
**                     Parameters:
**                     Input                                                                             Output
**     ----------                                                                           -----------
**
**                     Auth: 
**                     Date: 
*******************************************************************************
**                     Change History
*******************************************************************************
**                     Date:                Author:                                     Description:
**                     --------              --------                                      -------------------------------------------
**    
*******************************************************************************/
 
 
select top 10 MenuItemId, MenuItemName, MenuItemType,Role, Count(*) as Executions
from mst_MenuLog
where role = @Role AND (MenuItemType='pas' OR MenuItemType='rs')
group by MenuItemId, MenuItemName, Role,MenuItemType
order by Count(*) desc
 
 

GO
