/****** Object:  StoredProcedure [dbo].[msp_MIAccessControl]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- msp_MIAccessControl 'Openwork', 'Data Warehouse', null, null, null, null, null
create procedure [dbo].[msp_MIAccessControl] 
 @Client        varchar(50),
 @Module        varchar(50),
 @IsAvailable   bit          out,
 @StartRun      datetime     out,
 @EndRun        datetime     out,
 @ProcedureName varchar(255) out,
 @Error         int          out
as
--############################################################################
-- Copyright (c) MOORE STEPHENS CONSULTING LIMITED, 2004 All rights reserved 
-- 
-- Object     : Procedure
-- Name       : msp_MIAccessControl.sql
-- Description: Controls whether or not MI can be accessed
-- Owner      : Ermedin Selmanovic
-- Created    : 26/09/2005
-- 
--############################################################################
--
-- $Id: $
-- $Log: $
--
--############################################################################
declare 
 @Phase          varchar(50),
 @Process        varchar(100),
 @ErrorCode      int,
 @StopProcessing bit
set @ErrorCode      = 0
set @StopProcessing = 0 
set @ProcedureName  = object_name(@@procid)
set @Process        = @ProcedureName
declare @Count int
set @Count = (select count(*) from mst_MIAccessControl where Type = @Client and Module = @Module and Active = 1)
if @Count = 1
 begin   
  select
   @IsAvailable = IsAvailable,
   @StartRun    = convert(varchar(8),StartRun, 112),
   @EndRun      = EndRun
  from
   mst_MIAccessControl
  where
   Type   = @Client   and
   Module = @Module and
   Active = 1
  set @Error = @@Error
  if @Error <> 0
   begin
    set @Phase          = 'ERROR'
    set @ErrorCode      = 20
    set @Process        = @Process + ': ' + (select [Description] from mst_ErrorCodes ec where ec.ErrorCode = @ErrorCode)
    set @StopProcessing = (select StopProcessing from mst_ErrorCodes ec where ec.ErrorCode = @ErrorCode) 
    exec msp_ProcessLog @Phase, @Process, null, @Module, @Client
  end
 end
else
 if @Count > 1
  begin
   set @Phase          = 'ERROR'
   set @ErrorCode      = 10
   set @Process        = @Process + ': ' + (select [Description] from mst_ErrorCodes ec where ec.ErrorCode = @ErrorCode)
   set @StopProcessing = (select StopProcessing from mst_ErrorCodes ec where ec.ErrorCode = @ErrorCode)
   exec msp_ProcessLog @Phase, @Process, null, @Module, @Client
 end
 if @Count = 0
  begin
   set @Phase          = 'ERROR'
   set @ErrorCode      = 11
   set @Process        = @Process + ': ' + (select [Description] from mst_ErrorCodes ec where ec.ErrorCode = @ErrorCode)
   set @StopProcessing = (select StopProcessing from mst_ErrorCodes ec where ec.ErrorCode = @ErrorCode)
   exec msp_ProcessLog @Phase, @Process, null, @Module, @Client
  end
if @StopProcessing <> 0
 begin
  set @Error   = 99
  set @Process = 'Processing failed'
  exec msp_ProcessLog @Phase, @Process, null, @Module, @Client
 end  -- if @PostSuspended = 0

GO
/****** Object:  StoredProcedure [dbo].[msp_MIAccessControlUpdate]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- msp_MIAccessControlUpdate 'Openwork', 'Data Warehouse', null, null, null, null, null
create procedure [dbo].[msp_MIAccessControlUpdate] 
 @Client            varchar(50),
 @Module          varchar(50),
 @IsAvailable     bit,
 @MIProcessPhase  varchar(10),
 @ProcedureName   varchar(255) out,
 @Error           int          out
as
--############################################################################
-- Copyright (c) MOORE STEPHENS CONSULTING LIMITED, 2004 All rights reserved 
-- 
-- Object     : Procedure
-- Name       : msp_MIAccessControlUpdate.sql
-- Description: Updates IsAvailable flag
-- Owner      : Ermedin Selmanovic
-- Created    : 28/09/2005
-- 
--############################################################################
--
-- $Id: $
-- $Log: $
--
--############################################################################
declare 
 @Phase          varchar(50),
 @Process        varchar(100),
 @ErrorCode      int,
 @StopProcessing bit
set @ErrorCode      = 0
set @StopProcessing = 0 
set @ProcedureName  = object_name(@@procid)
set @Process        = @ProcedureName
set @Phase          = 'START'
exec msp_ProcessLog @Phase, @ProcedureName, null, @Module, @Client
declare 
 @Count int,
 @CurrentDateTime datetime
set @CurrentDateTime = getdate()
set @Count = (select count(*) from mst_MIAccessControl where Type = @Client and Module = @Module and Active = 1)
if @Count = 1
 begin   
  update
   mst_MIAccessControl
  set
   IsAvailable = @IsAvailable,
   StartRun    = case
                  when @MIProcessPhase = 'START' then @CurrentDateTime
                 else
                  StartRun
                 end,
   EndRun      = case
                  when @MIProcessPhase = 'END' then @CurrentDateTime
                 else
                  StartRun
                 end
  where
   Type   = @Client   and
   Module = @Module and
   Active = 1
  set @Error = @@Error
  if @Error <> 0
   begin
    set @Phase          = 'ERROR'
    set @ErrorCode      = 30
    set @Process        = @Process + ': ' + (select [Description] from mst_ErrorCodes ec where ec.ErrorCode = @ErrorCode)
    set @StopProcessing = (select StopProcessing from mst_ErrorCodes ec where ec.ErrorCode = @ErrorCode) 
    exec msp_ProcessLog @Phase, @Process, null, @Module, @Client
  end
 end
else
 if @Count > 1
  begin
   set @Phase          = 'ERROR'
   set @ErrorCode      = 10
   set @Process        = @Process + ': ' + (select [Description] from mst_ErrorCodes ec where ec.ErrorCode = @ErrorCode)
   set @StopProcessing = (select StopProcessing from mst_ErrorCodes ec where ec.ErrorCode = @ErrorCode)
   exec msp_ProcessLog @Phase, @Process, null, @Module, @Client
 end
 if @Count = 0
  begin
   set @Phase          = 'ERROR'
   set @ErrorCode      = 15
   set @Process        = @Process + ': ' + (select [Description] from mst_ErrorCodes ec where ec.ErrorCode = @ErrorCode)
   set @StopProcessing = (select StopProcessing from mst_ErrorCodes ec where ec.ErrorCode = @ErrorCode)
   exec msp_ProcessLog @Phase, @Process, null, @Module, @Client
  end
if @StopProcessing <> 0
 begin
  set @Error   = 99
  set @Process = 'Processing failed'
  exec msp_ProcessLog @Phase, @Process, null, @Module, @Client
 end  -- if @PostSuspended = 0
set @Phase = 'END'
exec msp_ProcessLog @Phase, @ProcedureName, null, @Module, @Client

GO
/****** Object:  StoredProcedure [dbo].[msp_NewRecruit]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO



CREATE PROCEDURE [dbo].[msp_NewRecruit] -- WITH RECOMPILE,ENCRYPTION
  /* Param List */
AS

/******************************************************************************

Copyright (C) Moore Stephens Consulting Limited 2005

Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
          
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>

*******************************************************************************/

truncate table mst_NewRecruit

insert into
 mst_NewRecruit
select 
 a.AdviserId as AdviserId,
 a.AgentCode as AgentCode,
 rtrim(ltrim(d.Adviser)) as Adviser,
 rtrim(ltrim(d.AreaSalesManager)) as Area,
 rtrim(ltrim(d.RegionalSalesManager)) as Region,
 rtrim(ltrim(d.Franchise)) as Franchise,
 a.ProductId as ProductId,
 e.ProductGroupName as ProductGroup,
 '' as DateIssuedId,
 c.[IssuedDate] as DateIssued,
 sum(a.Turnover) as Turnover,
 sum(a.Cases)  as Cases,
 sum(a.NBI) as NBI,
 sum(a.DA) as DA,
 sum(a.Margin) as Margin,
 '' as DateAppointedId,
 convert(nvarchar(12), b.AppointedDate, 106) as DateAppointed
-- b.AppointedDate
from
 msft_Sales a,
(
select distinct
 a.AdviserId,
 (case when 
  (ag.Datestarted = '1 Jun 2005' and ag.OscarDateStarted is not null) then ag.OscarDateStarted 
           else ag.Datestarted end) as AppointedDate
from
 msdt_Adviser a,
 mstt_Agents ag
where 
 a.AgentCode = ag.Code and
 (case when 
  (ag.Datestarted = '1 Jun 2005' and ag.OscarDateStarted is not null) then ag.OscarDateStarted 
           else ag.Datestarted end) > dateadd(mm,-12,getdate())
--
-- s.adviserid,
-- a.DateAppointedId,
-- convert(nvarchar(10), ct.[datetime], 103) [AppointedDate]
--from
-- msdt_calendartime ct,
-- msft_agents a,
-- msft_sales s
--where
-- s.adviserid = a.adviserid and 
-- s.adviserid <> '-99' and
-- s.comparisonid = 1 and
-- a.dateappointedId=ct.dateid and 
-- ct.entrytypeid = 4 and
-- ct.datetime > dateadd(mm,-12,getdate())
 ) b,
(
select
 DateId,
 YearMonth [IssuedDate]
from
 msdt_CalendarTime
where
 entrytypeid = 2
) c,
 msdt_Adviser d,
 msdt_Products e,
 mstt_Agents f  -- KS 31/05/06 - TPR around recruitment numbers too high
where
 d.AgentCode = f.Code and
 f.agenttypedescription <> 'Directly Authorised' and  -- KS 31/05/06 - TPR around recruitment numbers too high
 a.adviserid = b.adviserid and
 a.DateIssuedId = c.DateId and
 a.AdviserId = d.AdviserId and
 a.ProductId = e.ProductId and
 a.comparisonId = '1' --ComparisonId 1 = Actual
group by
 a.AdviserId,
 a.AgentCode,
 a.ProductId,
 c.[IssuedDate],
 b.[AppointedDate],
 d.Adviser,
 d.Franchise,
 d.AreaSalesManager,
 d.RegionalSalesManager,
 e.ProductGroupName



GO
