/****** Object:  StoredProcedure [dbo].[msp_NSStatement]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE procedure [dbo].[msp_NSStatement]
with recompile
as
--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : msp_NSStatement.sql
-- Owner   : CTT
-- Created : 26/10/2005
-- Updated : 02/11/2007 PR - use new xref table plus changes for for BI Datawarehouse cleanup
--                      PR - default OpenworkInd = 'X'
--                      PR - remove delete step at the bottom if OpenworkInd is empty 
--
--  Mike Cawood - 7 July 2009
--  Replace =* and *= ANSI JOINS as these not allowed in SQL Server 2005
--
--  Mike Cawood - 15 Sept 2009
--  a) Fix OpenworkInd logic as 'N' no longer assigned under SQL 2005 environment.
--  b) Ensure Update processing on msit_NSStatementFile only executed once.
--
--########################################################################

declare @DateLen int                        --MPC: 15/09/2009 (b)
set @DateLen = (select max(len(Date)) from msit_NSStatementFile)  --MPC: 15/09/2009 (b)

-- Only execute following updates to msit_NSStatementFile once to enable this
-- procedure to be rerun against the same monthly data loaded onto
-- msit_NSStatementFile (useful for testing and clean-ups). Data inserted onto 
-- mst_NSStatement from previous run would need to be deleted.

IF @DateLen > 7       --MPC: 15/09/2009 (b)
BEGIN           --MPC: 15/09/2009 (b)

-- apply correction to format of Date to enable it to be updated to SQL format next step
  update
   msit_NSStatementFile
  set
   [Date] = substring(Date,2,7)

-- update msit_NSStatementFile.  Set Month = OpeningBalance ledger date for each Branch

  select distinct top 1
  convert(datetime,(convert(nvarchar(4),(substring(date,2,2) + 2000)) + '-' +
  convert(nvarchar(4),substring(date,4,2)) + '-01'),102) SDate,
  count(date) [count]
  into
   #OpeningBalance
  from
   msit_NSStatementFile
  where
   sortcode = '0' -- and PR Oct 2007 - remove for BI Datawarehouse cleanup
  --branch <> '99F'
  group by
   convert(datetime,(convert(nvarchar(4),(substring(date,2,2) + 2000)) + '-' +
   convert(nvarchar(4),substring(date,4,2)) + '-01'),102)
  order by
   2 desc

  update msit_NSStatementFile
  set
   [Month] = #OpeningBalance.[SDate]
  from
   #OpeningBalance
  drop table
   #OpeningBalance

END       --MPC: 15/09/2009 (b)

-----------------

-- insert all records from PKP9504E into mst_NSStatement
insert into mst_NSStatement
select
 Getdate(),
 'X',
 '',
 '',
 '',
 '',
 '',
 '',
 '',
 a.[Branch], 
 rtrim(a.[Prefix]), 
 rtrim(a.[Serial]),
 rtrim(a.[Suffix]),
 rtrim(a.[N]),
 rtrim(a.[O]),
 rtrim(a.[SortCode]),
 convert(datetime,(case when left(a.[Date],1) = '0' then '19'
      when left(a.[Date],1) = '1' then '20'
      else 'Error' end +
 substring(a.[Date],2,2) + '-' +
 substring(a.[Date],4,2) + '-' +
 right(a.[Date],2))),
 [Month],
 rtrim(a.[LedgerDescription]),
 convert(float,a.[Value]),
 a.K
from
 msit_NSStatementFile a
where
-- a.[Branch] <> '99F' and PR Oct 2007 - remove for BI Datawarehouse cleanup 
 a.[X] <> 'Z'
-----------------------
-- Send ID's from owhot_OSCARSwiftAgentXref into #table
select distinct
 a.[OSCAR_Serial] [OAS],
 a.[OSCAR_ID] [OAID],
 a.[AgentCode] [SAID]
into #table1
from
  Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref a
where
 a.[AgentLevel] = 'B'
-------------------

-- START of revised processing to derive AgentId, Franchise UID and OpenworkInd 
-- MPC: 15/09/2009 (a)
--
-- The source data is keyed by unique Agent Serial. This links to unique AgentID and Swift
-- UID codes via the owhot_OSCARSwiftAgentXref table (maintained on Head Office screens).
-- If a business has ZAN and Openwork bank statement details then two different Serial
-- codes are used on the source file from OSCAR. The msit_DB3OWLinkID table is used to
-- identify the Openwork code (defined by LinkType of 'OW'). New OSCAR Serial codes added
-- during the preceding month should be linked to the SWIFT UID for the relevant business
-- before the Bank Statement file is loaded. Otherwise, details for the new business would
-- not find a match and would remain with OpenworkInd of 'X' (i.e. not shown on OA reports).
--
select distinct AgentId,left(OtherPartyID,5) [OPID],
t1.OAS as MainSerial,t1.SAID as UID
into #table2
from msit_DB3OWLinkID A
inner join #table1 t1 on t1.OAID = A.AgentId
where LinkType = 'OW'

select DISTINCT t2.opid as Serial,t2.AgentId as AgentId,t2.UID as UID,'Y' as OWInd
into #table3
from #table2 t2
UNION ALL
select DISTINCT t1.OAS as Serial,t1.OAID as AgentId,t1.SAID as UID,'N' as OWInd
from #table1 t1 
where t1.OAS not in (select distinct OPID from #table2)

update mst_NSStatement
set
 [OSCARAgentID]  = t3.AgentId,
 [FranchiseCode] = t3.UID,
 [OpenworkInd]   = t3.OWInd
from mst_NSStatement A
inner join #table3 t3 on A.Serial = t3.Serial
where A.OpenworkInd = 'X'

drop table #table1
drop table #table2
drop table #table3

-- END of revised processing to derive AgentId, Franchise UID and OpenworkInd
--MPC: 15/09/2009 (a)

/*
--MPC: 15/09/2009 (a) - Code Removed START
-- Update mst_NSStatement with ID's
update mst_NSStatement
set
 [OSCARAgentID]  = [OAID],
 [FranchiseCode] = [SAID]
from
 #table1
where
 mst_NSStatement.[Serial] = #table1.[OAS]
---------------------------------------
drop table #table1
-----------------
-- Send Openwork indicator from msit_DB3OWLinkID into #table1
select distinct
left(OtherPartyID,5) [OPID],
case when LinkType = 'OW' then 'Y' else 'N' end [OWI]
into #table2
from
msit_DB3OWLinkID
----------------
-- Update mst_NSStatement with Openwork indicator from #table1
update mst_NSStatement
set
 [OpenworkInd] = isnull([OWI],'N')
from
 #table2
 inner join mst_NSStatement on mst_NSStatement.[Serial] = #table2.[OPID]  --MPC: 07/07/2009
-- len(mst_NSStatement.[OSCARAgentID]) <> '0'               --MPC: 07/07/2009
where
-- mst_NSStatement.[Serial] *= #table2.[OPID] and             --MPC: 07/07/2009
 len(mst_NSStatement.[OSCARAgentID]) <> '0'
-------------------------------------------
drop table #table2
------------------
-- Send ID's for codes not in msit_OscarSwiftAgents into #table2
select distinct
 b.[TempID],
 a.[AgentID] [AID],
 case when a.[LinkType] = 'OW' then 'Y' else 'N' end [OWI],
 c.[OSCAR_ID] [OAID],
 c.[AgentCode] [SAID]
into
 #table3
from
 msit_DB3OWLinkID a,
(
select distinct
 a.[Serial] [TempID]
from
 mst_NSStatement a
where
 a.[OpenworkInd] = 'X' 
-- len(a.[OpenworkInd]) = '0'
) b,
  Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref c
where
 left(a.[OtherPartyID],5) = b.[TempID] and
 a.[AgentID] = c.[OSCAR_ID] and
 c.[AgentLevel] = 'B' and ISNUMERIC(a.AgentID) = 1
--------------------
-- Update mst_NSStatement with ID's in #table2
update mst_NSStatement
set
 [OpenworkInd]   = [OWI],
 [OSCARAgentID]  = [OAID],
 [FranchiseCode] = [SAID]
from
 #table3
where
 mst_NSStatement.[Serial] = #table3.[TempID]
--------------------------------------------
drop table #table3
------------------
--MPC: 15/09/2009 (a) - Code Removed END
*/

/*  
--MPC: 07/07/2009 - Code Removed START
select distinct
 a.[Code],
 isnull(a.[TradingName],a.[DESCN]) TradingName,
 isnull(a.Manager2Code,'Uncoded') [RSMCode],
 isnull(b.Descn,'Uncoded') [RSMDescn],
 isnull(a.Manager4Code,'Uncoded') [ASMCode],
 isnull(c.Descn,'Uncoded') [ASMDescn]
into #table4
from
 mstt_Agents a,
(
select distinct
 a.Code,
 a.Descn
from
 mstt_Agents a
) b,
(
select distinct
 a.Code,
 a.Descn
from
 mstt_Agents a
) c
where
 a.Manager2Code *= b.Code and
 a.Manager4Code *= c.Code
--MPC: 07/07/2009 - Code Removed END
*/

--MPC: 07/07/2009 - Code Added START
Select distinct
 a1.[Code],
 isnull(a1.[TradingName],a1.[DESCN]) TradingName,
 isnull(a1.Manager2Code,'Uncoded') [RSMCode],
 isnull(a2.Descn,'Uncoded') [RSMDescn],
 isnull(a1.Manager4Code,'Uncoded') [ASMCode],
 isnull(a3.Descn,'Uncoded') [ASMDescn]
into #table4
from
 mstt_Agents a1
 left outer join mstt_Agents a2 
  on a1.Manager2Code = a2.Code
 left outer join mstt_Agents a3
  on a1.Manager4Code = a3.Code
--MPC: 07/07/2009 - Code Added END

--------------
update mst_NSStatement
set
 [FranchiseName] = [TradingName],
 [RegionCode]    = [RSMCode],
 [RegionName]    = [RSMDescn],
 [AreaCode]      = [ASMCode],
 [AreaName]      = [ASMDescn]
from
 #table4
where
 mst_NSStatement.[FranchiseCode] = #table4.[Code]
--------------------------------------------
drop table #table4
------------------
-- PR 11/2007 - remove delete step
--delete
--from
-- mst_NSStatement
--where
-- len(OpenworkInd) = '0'
----------------------
GO
