CREATE  Procedure [dbo].[msp_NSUpdateFeesBACSDates]
AS
UPDATE msit_FeesNonSWIFTFeeListing 
SET  msit_FeesNonSWIFTFeeListing.BACSDate =  a.BACSDate
FROM
  msit_FeesNonSWIFTFeeListing INNER JOIN
        msit_NonSwiftBACSDate a ON msit_FeesNonSWIFTFeeListing.SWIFTFranchise = a.FranchiseCode
WHERE
  /*Where record is from the main sourcefile*/
  NOT msit_FeesNonSWIFTFeeListing.ListPosition = 51 
  AND NOT msit_FeesNonSWIFTFeeListing.ListPosition = 54 
  AND NOT msit_FeesNonSWIFTFeeListing.ListPosition =55 
  AND ISNULL(msit_FeesNonSWIFTFeeListing.OpenworkInd,'N') = a.OpenworkInd
  /*Where bacs date is the default*/
  AND msit_FeesNonSWIFTFeeListing.BacsDate = '01-01-1901 00:00:00'
  /*Set the bacs date equal to the closest bacs date for this frnachise which occurred after the load date*/
  AND a.Bacsdate =
  (SELECT MIN(b.BACSDate)
    FROM msit_NonSwiftBACSDate b
    WHERE msit_FeesNonSWIFTFeeListing.SwiftFranchise = b.FranchiseCode AND
      ISNULL(msit_FeesNonSWIFTFeeListing.OpenworkInd,'N') = b.OpenworkInd
      AND b.BACSDate > msit_FeesNonSWIFTFeeListing.DateLoaded)


GO
