CREATE Procedure [dbo].[msp_NSUpdateFeesBACSDatesPreSwift]
AS

-- Mike Cawood : 30 Jan 2008
-- Ticket 445 - reset BACS Date on Pre-Swift Commission listing data

UPDATE msit_OpenworkAdviserListing 
SET  msit_OpenworkAdviserListing.BACSDate =  a.BACSDate
FROM
  msit_OpenworkAdviserListing oal INNER JOIN
        msit_NonSwiftBACSDate a ON oal.BusinessCode = a.FranchiseCode
WHERE
  /*Where record is from the main sourcefile*/
   isnull(a.OpenworkInd,'N') = 'Y'
  and oal.Source = 'Openwork 2005'
  /*Where bacs date is the default*/
  AND oal.BacsDate = '01-01-1901 00:00:00'
  /*Set the bacs date equal to the closest bacs date for this frnachise which occurred after the load date*/
  AND a.Bacsdate =
  (SELECT MIN(b.BACSDate)
    FROM msit_NonSwiftBACSDate b
    WHERE oal.BusinessCode = b.FranchiseCode AND
      isnull(b.OpenworkInd,'N') = 'Y'
--      AND b.BACSDate > oal.CreateDate)  --:MPC - Ticket 445
      AND b.BACSDate > case when oal.CreateDate > oal.Month then oal.Month else oal.CreateDate end) --:MPC - Ticket 445




