-- Ticket 445 - reset BACS Date on Pre-Swift Commission listing data

UPDATE msit_ZANAdviserListing 
SET  msit_ZANAdviserListing.BACSDate =  a.BACSDate
FROM
  msit_ZANAdviserListing zal INNER JOIN
