  AND zal.BacsDate = '01-01-1901 00:00:00'
  /*Set the bacs date equal to the closest bacs date for this frnachise which occurred after the load date*/
  AND a.Bacsdate =
  (SELECT MIN(b.BACSDate)
    FROM msit_NonSwiftBACSDate b
    WHERE zal.BusinessCode = b.FranchiseCode AND
      isnull(b.OpenworkInd,'N') <> 'Y'
--      AND b.BACSDate > zal.CreateDate)  --MPC: Ticket 445
      AND b.BACSDate > case when zal.CreateDate > zal.Month then zal.Month else zal.CreateDate end) --MPC: Ticket 445





