update
 #msit_OpenworkAdviserListing
set
 Provider = pp.CommRepProductProviderName
from
 mstt_ProductProviders pp
where
 #msit_OpenworkAdviserListing.Provider = pp.CommRepProductProviderCode-- and
 --Source                               = 'Openwork 2005'
 --and 
--  ((Month >= @LoadMidMonth
--  and ListPosition = 55)
--  or (Month >= @LoadEndMonth
--  and ListPosition in (0,1,2,3,6,51,54,100))) 
 
  exec msp_ProcessLog 'OALPS', 'Update 3', null, 'OALPS', 'Openwork'

