-- UPDATE PROVIDER WITH THE PROVIDER NAME USING THE CODE DETERMINED IN THE PREVIOUS INSERT STATEMENT
update
 #msit_OpenworkAdviserListing
set
 Provider = pp.CommRepProductProviderName
from mstt_ProductProviders pp
where
 #msit_OpenworkAdviserListing.Provider = pp.CommRepProductProviderCode-- and
 --Source                               = 'Openwork 2005'
 --and 
--  ((Month >= @LoadMidMonth
--  and ListPosition = 55)
--  or (Month >= @LoadEndMonth
--  and ListPosition in (0,1,2,3,6,51,54,100))) 
-- PR 16/03/09 set product group
update oal
set ProductGroup =  case 
            when oal.provider='General Insurance' then 'GI' 
            when oal.provider='SIML' then 'Investment'
            when oal.provider='Sterling' then 'Investment'
            when oal.provider='Scottish Equitable' then 'Pensions'
            else isNull(ph.productgroupname,'Other') 
          end                   
from  #msit_OpenworkAdviserListing oal
 LEFT OUTER join mstt_producthierarchy ph on 'NBI_'+ oal.ProductCode = ph.productCode
 
  exec msp_ProcessLog 'OALPS', 'Update 3', null, 'OALPS', 'Openwork'

