update
 #msit_OpenworkAdviserListing
set
 Premium             = round(Premium,2),
 APE                 = round(APE,2),
 CommRate            = round(CommRate,2),
 Sacrifice           = round(Sacrifice,2),
 AgentSplit          = round(AgentSplit,2),
 TotDue_Base         = round(TotDue_Base,2),
 Accrued_Base        = round(Accrued_Base,2),
 StillToAccr_Base    = round(StillToAccr_Base,2),
 ITAdvanced_Base     = round(ITAdvanced_Base,2),
 EnhancementRate     = round(EnhancementRate,2),
 TotDue_Enhd         = round(TotDue_Enhd,2),
 Accrued_Enhd        = round(Accrued_Enhd,2),
 StillToAccr_Enhd    = round(StillToAccr_Enhd,2),
 ITAdvanced_Enhd     = round(ITAdvanced_Enhd,2),
 TotalPayment        = round(isnull(TotalPayment, (Accrued_Enhd + ITAdvanced_Enhd)),2),
 ProdType            = isnull(ProdType, ProductCode)
--  where ((Month >= @LoadMidMonth
--  and ListPosition = 55)
--  or (Month >= @LoadEndMonth
--  and ListPosition in (0,1,2,3,6,51,54,100))) 
 
  exec msp_ProcessLog 'OALPS', 'Update 5', null, 'OALPS', 'Openwork'

-- Extract Positive NBI Movements (exclude MTG/GI)

select t1.Policy,isnull(t1.StartDate,'1 jan 1901') as StartDate,t1.Premium,t1.SellerName,t1.Month,  
t1.SourceID as POSID,t1.TotDue_enhd as NBI,t1.APE
into #NBIPositives
from msit_OpenworkAdviserListing t1
where t1.TotDue_Enhd > 0 and Source = 'Openwork 2005' and t1.ListPosition <> 6        
Order by t1.Policy,t1.StartDate,t1.Premium,t1.SellerName,t1.Month,t1.SourceID       

exec msp_ProcessLog 'OALPS', '#APE1', null, 'SPEX', 'Openwork'

-- Extract Negative NBI Movements and Prev NBI Total (exclude MTG/GI)

select t1.Policy,isnull(t1.StartDate,'1 jan 1901') as StartDate,t1.Premium,t1.SellerName,t1.Month,  
t1.SourceID as NegID,t1.TotDue_enhd as NBI,t1.APE,
sum(isnull(t2.NBI,0)) as PrevNBI
into #NBINegatives
from msit_OpenworkAdviserListing t1
inner join #NBIPositives t2     
on t2.Policy = t1.Policy and t2.StartDate = isnull(t1.StartDate,'1 jan 1901') and round(t1.Premium,2) = round(t2.Premium,2) 
and t1.SellerName = t2.SellerName and (t2.POSID < t1.SourceID or t2.Month < t1.Month)
where t1.TotDue_Enhd < 0 and Source = 'Openwork 2005' and t1.ListPosition <> 6
Group by t1.Policy,t1.StartDate,t1.Premium,t1.SellerName,t1.Month,t1.SourceID,t1.TotDue_enhd,t1.APE
Order by t1.Policy,t1.StartDate,t1.Premium,t1.SellerName,t1.Month,t1.SourceID

exec msp_ProcessLog 'OALPS', '#APE2', null, 'SPEX', 'Openwork'

-- Extract Prev NBI Total for Positive movements

Select Policy,StartDate,Premium,SellerName,Month,POSID as ID,NBI,APE
into #NBIALL
from #NBIPositives
UNION ALL
select Policy,StartDate,Premium,SellerName,Month,NegID as ID,NBI,APE
from #NBINegatives
order by 1,2,3,4,5,6

exec msp_ProcessLog 'OALPS', '#APE3', null, 'SPEX', 'Openwork'

select t1.*,sum(isnull(t2.NBI,0)) as PrevNBI,sum(isnull(t2.APE,0)) as PrevAPE
into #NBIPREV
from #NBIAll t1
left outer join #NBIAll t2      
on t2.Policy = t1.Policy and t2.StartDate = t1.StartDate and round(t1.Premium,2) = round(t2.Premium,2) and t1.SellerName = t2.SellerName 
and (t2.ID < t1.ID or t2.Month < t1.Month)
group by t1.Policy,t1.StartDate,t1.Premium,t1.SellerName,t1.Month,t1.ID,t1.NBI,t1.APE
order by t1.Policy,t1.StartDate,t1.Premium,t1.SellerName,t1.Month,t1.ID               

exec msp_ProcessLog 'OALPS', '#APE4', null, 'SPEX', 'Openwork'

-- Now Zeroise APE if not applicable (i.e. NBI = zero or Negative NBI but net NBI > zero)
-- Also Zeroise TotDue and Still to Accrue if Fee Type not IC
-- For Sterling/Scot EQ RC/Trail always log as Accrued even if IT basis
-- Do not reset APE for MTG/GI as derived from NBI  --MPC: 29/02/2008
update #msit_OpenworkAdviserListing
set APE = round(case
			when ListPosition = 6 then t1.APE   --MPC: 29/02/2008
			when t1.FeeType <> 'IC' and ListPosition <> 6 then 0.0
--			when isnull(t1.Frequency,'Z') <> 'S' and t2.NegID is not null and isnull(t2.NBI,0) + t2.PrevNBI > 0 then 0.0  --MPC: 29/02/2008
			when isnull(TotDue_Enhd,0) < 0 and t2.ID is not null and round(t2.NBI + t2.PrevNBI,2) > 0 then 0.0  --MPC: 29/02/2008
			when isnull(TotDue_Enhd,0) < 0 and t2.ID is not null and round(t2.PrevNBI,2) <= 0 then 0.0    --MPC: 29/02/2008
			when isnull(TotDue_Enhd,0) < 0 and t2.ID is not null and round(t2.PrevAPE,2) <= 0 then 0.0    --MPC: 29/02/2008
			when isnull(TotDue_Enhd,0) < 0 and t2.ID is null then 0.0           --MPC: 29/02/2008
			when isnull(TotDue_Enhd,0) = 0 then 0.0
			when isnull(TotDue_Enhd,0) > 0 and t2.ID is not null and round(t2.PrevNBI,2) > 0.0 then 0.0   --MPC: 29/02/2008
			when isnull(TotDue_Enhd,0) > 0 and t2.ID is not null and round(t2.PrevAPE,2) > 0.0 then 0.0   --MPC: 29/02/2008
			--      when isnull(TotDue_Enhd,0) > 0 and t1.TotalPayment < 0 then 0.0         --MPC: 29/02/2008
			else t1.APE
			end,2),
	Totdue_Enhd = case when t1.FeeType <> 'IC' and ListPosition <> 6 then 0.0 else t1.TotDue_Enhd end,
	Totdue_Base = case when t1.FeeType <> 'IC' and ListPosition <> 6 then 0.0 else t1.TotDue_Base end,
	Accrued_Enhd = case when t1.FeeType <> 'IC' and ListPosition in (51,54,55) and t1.PayBasis = 'IT' then t1.ITAdvanced_Enhd else t1.Accrued_Enhd end,
	Accrued_Base = case when t1.FeeType <> 'IC' and ListPosition in (51,54,55) and t1.PayBasis = 'IT' then t1.ITAdvanced_Base else t1.Accrued_Base end,
	ITAdvanced_Enhd = case when t1.FeeType <> 'IC' and ListPosition in (51,54,55) and t1.PayBasis = 'IT' then 0.0 else t1.ITAdvanced_Enhd end,
	ITAdvanced_Base = case when t1.FeeType <> 'IC' and ListPosition in (51,54,55) and t1.PayBasis = 'IT' then 0.0 else t1.ITAdvanced_Base end,
	StillToAccr_Enhd = case when t1.FeeType <> 'IC' then 0.0 else t1.StillToAccr_Enhd end,
	StillToAccr_Base = case when t1.FeeType <> 'IC' then 0.0 else t1.StillToAccr_Base end,
	-- AG 11/05/2015 Start
	ELITE_Points =	
		case when t1.Month < '2015-02-01'		
		then 
			case	-- Old rules 
				when t1.ProductGroup = 'Investment' and t1.FeeType = 'IC' then round(isnull(t1.TotDue_Base * EF1.FACTOR * EF1.Multiplier,0),4)		--SR207107: MPC 11/03/2013
				when t1.ProductGroup = 'Pensions'	and t1.FeeType = 'IC' then round(isnull(t1.TotDue_Base * EF2.FACTOR * EF2.Multiplier,0),4)		--SR207107: MPC 11/03/2013
				when t1.ProductGroup = 'GI'			and t1.FeeType = 'IC' then round(isnull(t1.TotDue_Base * EF3.FACTOR * EF3.Multiplier,0),4)		--SR207107: MPC 11/03/2013
				when t1.ProductGroup = 'Mortgage'	and t1.FeeType = 'IC' then round(isnull(t1.TotDue_Base * EF4.FACTOR * EF4.Multiplier,0),4)		--SR207107: MPC 11/03/2013
				when t1.ProductGroup = 'Protection' and t1.FeeType = 'IC' then round(isnull(t1.TotDue_Base * EF5.FACTOR * EF5.Multiplier,0),4)		--SR207107: MPC 11/03/2013
			end	
		else
			case	-- TotDue_Enh is the NBI figure as seen on the Detail screen when clicking on the Detail hyperlink on the OpenAccess Comm Listing
				when t1.ProductGroup = 'Investment' and t1.FeeType = 'IC' then 
						case when t1.TotDue_Enhd < 0 
							then -ceiling(abs(isnull(t1.TotDue_Enhd * 0.24 * EF1.Multiplier,0)))
							else ceiling(isnull(t1.TotDue_Enhd * 0.24 * EF1.Multiplier,0))
						end
				when t1.ProductGroup = 'Pensions' and t1.FeeType = 'IC' then 
						case when t1.TotDue_Enhd < 0 
							then -ceiling(abs(isnull(t1.TotDue_Enhd * 0.24 * EF2.Multiplier,0)))	
							else ceiling(isnull(t1.TotDue_Enhd * 0.24 * EF2.Multiplier,0))
						end	
				when t1.ProductGroup = 'GI' and t1.FeeType = 'IC' then 
						case when t1.TotDue_Enhd < 0 
							then -ceiling(abs(isnull(t1.TotDue_Enhd * 0.20 * EF3.Multiplier,0)))
							else ceiling(isnull(t1.TotDue_Enhd * 0.20 * EF3.Multiplier,0))
						end		
				when t1.ProductGroup = 'Protection' and t1.FeeType = 'IC' then 
						case when t1.TotDue_Enhd < 0 
							then -ceiling(abs(isnull(t1.TotDue_Enhd * 0.28 * EF5.Multiplier,0)))
							else ceiling(isnull(t1.TotDue_Enhd * 0.28 * EF5.Multiplier,0))
						end	
				else 0	-- Marcus Cossey wanted no handling for mortgages as he stated these are one-off fees
						-- and further advances, etc. cannot happen.  
			end	
		end	
	-- AG 11/05/2015 End																															--SR207107: MPC 11/03/2013
from #msit_OpenworkAdviserListing t1
--left outer join #NBINegatives t2 on t1.SourceID = t2.NegID        --MPC: 29/02/2008
left outer join #NBIPREV t2 on t1.SourceID = t2.ID          --MPC: 29/02/2008
inner join msit_Commissionstatementperiods csp on csp.month = t1.month		--SR207107: MPC 11/03/2013
--inner join owt_SelectionControl TSC on csp.Year >= TSC.KeyValue and TSC.KeyType = 'EliteStartYear' and TSC.Process = 'ElitePoints' and TSC.SelectionType = 'CreateDate' and t1.StartDate between TSC.EffectiveStartDate and TSC.EffectiveEndDate		--SR207107: MPC 11/03/2013
left join owt_EliteFactors EF1 on EF1.category = 'COMM-INV' and csp.year between EF1.startyear and EF1.endyear	--SR207107: MPC 11/03/2013
left join owt_EliteFactors EF2 on EF2.category = 'COMM-PEN' and csp.year between EF2.startyear and EF2.endyear	--SR207107: MPC 11/03/2013
left join owt_EliteFactors EF3 on EF3.category = 'GI' and csp.year between EF3.startyear and EF3.endyear		--SR207107: MPC 11/03/2013
left join owt_EliteFactors EF4 on EF4.category = 'MCOB' and csp.year between EF4.startyear and EF4.endyear		--SR207107: MPC 11/03/2013
left join owt_EliteFactors EF5 on EF5.category = 'ICOB' and csp.year between EF5.startyear and EF5.endyear		--SR207107: MPC 11/03/2013

exec msp_ProcessLog 'OALPS', '#APEUpd', null, 'OALPS', 'Openwork'

drop table #NBIPositives
drop table #NBINegatives
drop table #NBIALL    --MPC: 29/02/2008
drop table #NBIPREV     --MPC: 29/02/2008

 --insert the rows into the table

insert into msit_OpenworkAdviserListing
select 
BusinessCode, BusinessName, SellerCode, SellerName, SellerForename, SellerSurname, Client, 
ClientForename, ClientSurname, BACSDate, Policy, CaseId, ProdType, StartDate, PaymentDate, 
Frequency, Premium, APE, CommRate, InitialPeriod, PayBasis, Sacrifice, AgentSplit, FeeType, 
Remarks, Provider, ProviderCode, SourceID, ListPosition, Month, Source, TotDue_Base, Accrued_Base, 
StillToAccr_Base, ITAdvanced_Base, EnhancementRate, TotDue_Enhd, Accrued_Enhd, StillToAccr_Enhd, 
ITAdvanced_Enhd, TotalPayment, DistributorRef, CreateDate , TransactionID,          --WI260
TotDue_Base, NULL,                      -- PR 15/05/08
NULL,ProductGroup                     -- PR 16/03/09
,ELITE_Points			--SR207107: MPC 11/03/2013
from #msit_OpenworkAdviserListing 

 exec msp_ProcessLog 'OALPS', 'Insert', null, 'OALPS', 'Openwork'

drop table #msit_OpenworkAdviserListing

end

--Update with BACS Dates

--Update #msit_OpenworkAdviserListing
--set BACSDate = ns.BACSDate
--from msit_NonSwiftBACSDate ns, #msit_OpenworkAdviserListing oal
--where oal.BusinessCode = ns.FranchiseCode
--and oal.Source = 'Openwork 2005'
--and oal.BACSDate = '01/01/1900'
