/****** Object:  StoredProcedure [dbo].[msp_OpenworkAdviserListingPreSwift_Reload]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


CREATE procedure [dbo].[msp_OpenworkAdviserListingPreSwift_Reload]
@Month datetime
with recompile
as

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : msp_OpenworkAdviserListingPreSwift_Reload.sql
-- Owner   : MWA
-- Created : 20/07/2006
--
--########################################################################

-- Mike Cawood 08/12/2007
-- Version to load specified month

exec msp_ProcessLog 'OALPS', 'Variables Filled', null, 'OALPS', 'Openwork'

-- INSERT PRE-SWIFT DATA
-- CREATE A TEMP TABLE TO HOLD THE AL_ENHANCEMENTRATE LOGIC AGAINST THE ID FIELD WHICH IS USED IN THE TABLE POPULATION
select
 s.ID,
 EnhancementRate  = case
--                     when s.Listposition = 6 and ProductCode =  'MOR' then s.CommRateStd           -- WI260
--                     when s.ListPosition = 6 and ProductCode <> 'MOR' then 0.0                   -- WI260
                     when s.Listposition = 6 and ProductCode =  'MOR' and isnull(s.CommRateTrue, 0) < 80.0 then 80.0     -- WI260
                     when s.Listposition = 6 and ProductCode =  'MOR' and isnull(s.CommRateTrue, 0) >= 80.0 then s.CommRateTrue  -- WI260
                     when s.ListPosition = 6 and ProductCode <> 'MOR' and isnull(s.CommRateTrue, 0) < 27.5 then 27.5       -- WI260
                     when s.ListPosition = 6 and ProductCode <> 'MOR' and isnull(s.CommRateTrue, 0) >= 27.5 then s.CommRateTrue  -- WI260
                     when s.ListPosition = 100 then EnhancementRate
                     when s.ListPosition in (51,54,55) and isnull(EnhancementRate,0) < 100 then 100
                     when s.ListPosition in (51,54,55) and isnull(EnhancementRate,0) >= 100 then EnhancementRate
                     when s.ListPosition < 6 and (isnull(UpLiftAccr,0) + isnull(UpLiftIT,0)) <> 0 then round(((UpLiftRate + 1) * 100),2)
                     when s.ListPosition < 6 and (isnull(UpLiftAccr,0) + isnull(UpLiftIT,0))  = 0 then 100
                     else 0.0
                    end,
s.SwiftFranchise,
s.SwiftSeller,
s.SellerName,
s.Client,
s.ClientForename,
s.ClientSurname,
s.BACSDate,
s.Policy, 
s.ProductCode,
s.DeclarationDate,
s.StartDate,
s.[Month],
s.Frequency,
abs(s.Premium) as Premium,
s.Value1,
s.Value4,
s.TotalFees,
abs(s.CommRateTrue) as CommRateTrue,
abs(s.CommRateStd) as CommRateStd,
InitialPeriod = case 
      when s.ListPosition in (51,55) then 60
      when s.ListPosition in (54) and s.InitialPeriod > 0 then abs(s.InitialPeriod)
      when s.ListPosition in (54) and (s.InitialPeriod is NULL or s.InitialPeriod = 0) then 27 
      else abs(s.InitialPeriod) 
    end,
s.PayBasis,
s.Value5,
s.Value6,
s.RemarkCode1,                    
s.RemarkCode2,
s.RemarkCode3,
s.RemarkCode4,
s.RemarkCode5,
s.RemarkCode6,
s.RemarksData1,
s.RemarksData2,
s.RemarksData3,
s.RemarksData4,
s.RemarksData5,
s.RemarksData6,
s.BIRemarks,
s.RemarksString,    -- WI260
s.ListPosition,
s.Value2,
s.EnhancementAccr,
s.StillLeftToAccrue,
s.Value3,
s.ITAdvance,
s.DateLoaded,
s.OpenworkInd,
s.UpLiftAccr,
s.UpLiftIT,
'N' as 'NBI_Flag',
case 
  when s.ListPosition in (51,54,55) then s.Value1 -- Nominal Calc to force Zero
  else 0.0
end as 'TOT_DUE',
DATEDIFF ( mm , s.Month , s.Month ) as 'MONTHS'   -- Nominal Calc to force Zero

into
 #EnhancementRate
from 
 msit_FeesNonSWIFTFeeListing s 
where
 s.OpenworkInd = 'Y' 
 and s.ListPosition not in (7,8)
 and Month = @Month 

exec msp_ProcessLog 'OALPS', '#EnhancementRate', null, 'OALPS', 'Openwork'

-- Reset PayBasis on Scot Eq cases (IT to Accr or Accr to IT)
update
 #EnhancementRate
set
 PayBasis = case 
   when paybasis <> 'I' and (totalfees >= 2 *
    (premium * case when frequency = 'A' then (1/12) else 1 end * (0.25/3)
     * case when isnull(enhancementrate,0) <= 100 then 1 else enhancementrate/100 end))
   then 'I'
   when paybasis = 'I' and (totalfees < 2 *
    (premium * case when frequency = 'A' then (1/12) else 1 end * (0.25/3)
     * case when isnull(enhancementrate,0) <= 100 then 1 else enhancementrate/100 end))
   then 'A'
   end,
 BIRemarks = case when BIRemarks is null or len(BIRemarks) = 0 then 'Basis' else BIRemarks + ',Basis' end

from #EnhancementRate
where listposition = 54 and frequency in ('A','M')
and Premium > 0 and TotalFees > 0 and RemarksString not like '%renew%' 
and (
  (paybasis <> 'I' and (totalfees >= 2 *
  (premium * case when frequency = 'A' then (1/12) else 1 end 
   * case when isnull(enhancementrate,0) <= 100 then 1 else enhancementrate/100 end * (0.25/3))))
OR
  (paybasis = 'I' and (totalfees < 2 *
  (premium * case when frequency = 'A' then (1/12) else 1 end 
   * case when isnull(enhancementrate,0) <= 100 then 1 else enhancementrate/100 end * (0.25/3))))
)

exec msp_ProcessLog 'OALPS', '#BasisIPCalc', null, 'OALPS', 'Openwork'

-- Extract NBI 'Transaction' details
select Policy,StartDate,Premium,min(ID) as FirstID,min(Month) as FirstMonth
into #NBITrigger
from msit_FeesNonSWIFTFeeListing
where ListPosition in (51,54,55) and TotalFees > 0 
Group by Policy,StartDate,Premium
Order by Policy,StartDate,Premium

exec msp_ProcessLog 'OALPS', '#ScotEq1', null, 'OALPS', 'Openwork'

/*
select t2.Policy,t2.StartDate,t2.Premium,t2.FirstID,
case when (t1.premium * case when t1.frequency = 'A' then (1/12) else 1 end * (0.25/3)
     * case when isnull(t1.enhancementrate,0) <= 100 then 1 else t1.enhancementrate/100 end) > 0
     then round(t1.TotalFees/(t1.premium * case when t1.frequency = 'A' then (1/12) else 1 end * (0.25/3)
     * case when isnull(t1.enhancementrate,0) <= 100 then 1 else t1.enhancementrate/100 end),0)
else 0 end as IPFactor
into #ScotEqIP
from #EnhancementRate t1
inner join #NBITrigger t2 on t1.ID = t2.FirstID
where t1.ListPosition = 54 and t1.Premium > 0 and t1.RemarksString not like '%renew%'

update #EnhancementRate
set InitialPeriod = case when IPFactor between 1 and 27 then IPFactor else 27 end
from #EnhancementRate t1
inner join #ScotEqIP t2 on t2.Policy = t1.Policy and t2.StartDate = t1.StartDate and t1.Premium = t2.Premium
where t1.ListPosition = 54 and t2.IPFactor > 0

drop table #ScotEqIP

exec msp_ProcessLog 'OALPS', '#ScotEqIP', null, 'OALPS', 'Openwork'
*/

-- Set APE Flag for first Regular Accrual on Scot Eq/Sterling
update #EnhancementRate
set NBI_Flag = 'Y'
from #NBITrigger t1
inner join #EnhancementRate t2 on t2.id = t1.firstID
where t2.ListPosition in (51,54,55) and t2.TotalFees > 0 

exec msp_ProcessLog 'OALPS', '#ScotEq2', null, 'OALPS', 'Openwork'

-- Derive Months and TotDue for Regular Accrual on Scot Eq/Sterling
update #EnhancementRate
set MONTHS = DATEDIFF ( mm , t1.FirstMonth , t2.Month ) + 1,
    TOT_DUE = case
      when t2.ListPosition in (54) then 
       case
         when t2.Frequency = 'M' then t2.TotalFees * isnull(t2.InitialPeriod,27)
         when t2.Frequency = 'A' then t2.TotalFees * isnull(t2.InitialPeriod,27)/12
         else 0
       end
      when t2.ListPosition in (51,55) then
       case
         when t2.Frequency in ('M','R') then t2.TotalFees * isnull(t2.InitialPeriod,60)
         when t2.Frequency = 'A' then t2.TotalFees * (isnull(t2.InitialPeriod,60)/12)
         else 0
       end
  else 0
end
from #NBITrigger t1
inner join #EnhancementRate t2 
on t2.Policy = t1.Policy and t2.StartDate = t1.StartDate and t1.Premium = t2.Premium
where t2.ListPosition in (51,54,55) and t2.TotalFees > 0 
and t2.PayBasis <> 'I' and t2.Frequency in ('A','M','R')

exec msp_ProcessLog 'OALPS', '#ScotEq3', null, 'OALPS', 'Openwork'

drop table #NBITrigger

-- POPULATE THE TEMP msit_OpenworkAdviserListing TABLE WITH PRE-SWIFT
select
 BusinessCode     = er.SwiftFranchise,
 BusinessName     = case
                     when a.TradingName is not NULL then a.TradingName
                     else a.DESCN
                    end,
 SellerCode       = er.SwiftSeller,
 SellerName       = case
                     when er.SwiftSeller is null then cast(rtrim(ltrim(er.SellerName)) as varchar(50))
                     else cast(rtrim(ltrim(er.SellerName)) as varchar(50)) + ' - ' + er.SwiftSeller
                    end,
 SellerForename   = case
                     when er.SwiftSeller is not null and a.FirstNames is not null and charindex(' ', a.FirstNames) = 0 then a.FirstNames 
                     when er.SwiftSeller is not null and a.FirstNames is not null and charindex(' ', a.FirstNames) > 0 then rtrim(substring(a.FirstNames, 1, charindex(' ', a.FirstNames)))
                     when charindex(' ', ltrim(er.SellerName)) = 0 then ltrim(er.SellerName)
                     else rtrim(substring(ltrim(er.SellerName), 1, charindex(' ', ltrim(er.SellerName))))
                    end,
 SellerSurname    = case
                     when er.SwiftSeller is not null and a.[Name] is not null then a.[Name]
                     when charindex(' ', reverse(rtrim(er.SellerName))) = 0 then er.SellerName
                     else reverse(rtrim(substring(reverse(rtrim(er.SellerName)), 1, charindex(' ', reverse(rtrim(er.SellerName))))))
                    end,
 Client           = er.Client,
 ClientForename    = case
                     when charindex(' ', er.ClientForename) = 0 then substring(er.ClientForename,1,30)
                     else rtrim(substring(er.ClientForename, 1, charindex(' ', er.ClientForename)))
                    end,
 ClientSurname    = er.ClientSurname,
 BACSDate         = BACSDate,
 Policy           = Policy,
 CaseId           = NULL,
 --ProdType         = isnull((select 
 --                            substring(lp.SWIFTProdType,1,8)
 --                          from
 --                            msit_LegacyProducts lp
 --                           where
 --                            er.ProductCode           = lp.LegacyProdCode and
 --                            er.DeclarationDate between lp.StartDate      and lp.EndDate), er.ProductCode),
 ProdType         = cast(null as varchar(8)),
 StartDate        = er.StartDate,
 PaymentDate      = er.[Month],
-- Reset Frequency of Y to A (annual) and X to S (single)
 Frequency        = case
                     when er.Frequency in ('A','M','S','R') then er.Frequency
                     when er.Frequency = 'Y' then 'A'
         when er.Frequency = 'X' then 'S'
                     else NULL
                    end,
 Premium          = case
      -- RH 23 Jan 2007 CR230 Fix Scot Eq Monthly Premium Value
      when er.ListPosition = 54 then er.Premium
      -- Annualise Sterling Premium for monthly cases
      when er.ListPosition in (51,55) and er.Frequency = 'R' then er.Premium * 12
                      when er.Frequency = 'M' then er.Premium / 12
                      else er.Premium
                    end,
-- APE              = case
--                     when (isnull(er.Value1, 0.0) > 0 or isnull(er.Value4, 0.0) > 0 or isnull(er.TotalFees, 0.0) > 0) and er.Frequency     in ('M', 'A', 'R') then er.Premium / 100
--                     when (isnull(er.Value1, 0.0) > 0 or isnull(er.Value4, 0.0) > 0 or isnull(er.TotalFees, 0.0) > 0) and er.Frequency not in ('M', 'A', 'R') then er.Premium / 1000
--                     else 0.0
--                    end,
-- Doing this calculation here, as all elements are available, rather than requiring its own update (commented out below)
 APE              = -- RH 23 Jan 2007 CR230 Fix Scot Eq Monthly Premium Value
        -- WI260 Mike Cawood 23/03/2007 - cater for negative APE and MTG/GI APE
        case
         when er.ListPosition = 6 and er.ProductCode = 'MOR' then (isnull(er.Value2, 0.0) * 0.8)/(0.8 * er.EnhancementRate)   -- WI260 MTG Calc = BASE/80%
         when er.ListPosition = 6 and er.ProductCode <> 'MOR' then (isnull(er.Value2, 0.0) * 0.275)/(0.725 * er.EnhancementRate)   -- WI260 GI Calc = BASE/72.5%
                     when (isnull(er.Value1, 0.0) <> 0 or isnull(er.Value4, 0.0) <> 0 or isnull(er.TotalFees, 0.0) <> 0) and er.Frequency     in ('M', 'A', 'R') then er.Premium / 100
                     when (isnull(er.Value1, 0.0) <> 0 or isnull(er.Value4, 0.0) <> 0 or isnull(er.TotalFees, 0.0) <> 0) and er.Frequency not in ('M', 'A', 'R') then er.Premium / 1000 -- Single Premium / 10
                     else 0.0
                    end 
        * 
        -- Sign --WI260
        case
      when (isnull(er.Value1, 0.0) < 0 or isnull(er.Value4, 0.0) < 0 or isnull(er.TotalFees, 0.0) < 0) then -1
      else 1
        end
                    * 
        -- multiplier for ScotEq/Sterling NBI - all other options remain the same
        case
      when er.ListPosition in (51,54,55) and er.NBI_Flag = 'Y' then 1
      when er.ListPosition in (51,54,55) and er.NBI_Flag <> 'Y' and isnull(er.TotalFees, 0.0) < 0 then 1
      when er.ListPosition in (51,54,55) and er.NBI_Flag <> 'Y' and isnull(er.TotalFees, 0.0) >= 0 then 0
      else 1
        end
                    * 
        -- multiplier for ScotEq monthly - all other options remain the same
        -- annualise Sterling Premium if Freq = R
        case
      when er.ListPosition = 54 and er.Frequency = 'M' then 12
      when er.ListPosition in (51,55) and er.Frequency = 'R' then 12
      else 1
        end
        *
                    case  -- AgentSplit
                     when er.RemarkCode1 in ('012','805','905') 
      then isnull(cast(convert(float,replace(er.RemarksData1, '%', '')) as decimal(15,2)),100.0)
--      then replace(er.RemarksData1, '%', '')
                     when er.RemarkCode2 in ('012','805','905') 
      then isnull(cast(convert(float,replace(er.RemarksData2, '%', '')) as decimal(15,2)),100.0)
--      then replace(er.RemarksData2, '%', '')
                     when er.RemarkCode3 in ('012','805','905') 
      then isnull(cast(convert(float,replace(er.RemarksData3, '%', '')) as decimal(15,2)),100.0)
--      then replace(er.RemarksData3, '%', '')
                     when er.RemarkCode4 in ('012','805','905') 
      then isnull(cast(convert(float,replace(er.RemarksData4, '%', '')) as decimal(15,2)),100.0)
--      then replace(er.RemarksData4, '%', '')
                     when er.RemarkCode5 in ('012','805','905') 
      then isnull(cast(convert(float,replace(er.RemarksData5, '%', '')) as decimal(15,2)),100.0)
--      then replace(er.RemarksData5, '%', '')
                     when er.RemarkCode6 in ('012','805','905')
      then isnull(cast(convert(float,replace(er.RemarksData6, '%', '')) as decimal(15,2)),100.0) 
--      then replace(er.RemarksData6, '%', '')
                     else 100.0

                    end,                    
 CommRate         = case
                     when er.ListPosition = 6 and er.ProductCode  = 'MOR' then null 
                     else case 
                           when isnull(er.CommRateTrue, 0) <> 0 then er.CommRateTrue
                           else er.CommRateStd
                          end
                    end,
 InitialPeriod    = InitialPeriod,
 PayBasis         = case
                     when er.PayBasis = 'I' then 'IT'
                     when er.PayBasis = 'A' then 'Accr'
                     else case
                           when abs(isnull(er.Value4, 0.0) + isnull(er.Value5, 0.0) + isnull(er.Value6, 0.0)) > 0 then 'IT'
                           else 'Accr'
                          end
                    end,
 Sacrifice        = case
                     when er.RemarkCode1 in ('016','091','092','802') and substring(er.RemarksData1,2,9) is not NULL
      then isnull(cast(convert(float,rtrim(substring(er.RemarksData1,2,9))) as decimal(15,2)),0.0)
                     when er.RemarkCode2 in ('016','091','092','802') and substring(er.RemarksData2,2,9) is not NULL
      then isnull(cast(convert(float,rtrim(substring(er.RemarksData2,2,9))) as decimal(15,2)),0.0)
                     when er.RemarkCode3 in ('016','091','092','802') and substring(er.RemarksData3,2,9) is not NULL
      then isnull(cast(convert(float,rtrim(substring(er.RemarksData3,2,9))) as decimal(15,2)),0.0)
                     when er.RemarkCode4 in ('016','091','092','802') and substring(er.RemarksData4,2,9) is not NULL
      then isnull(cast(convert(float,rtrim(substring(er.RemarksData4,2,9))) as decimal(15,2)),0.0)
                     when er.RemarkCode5 in ('016','091','092','802') and substring(er.RemarksData5,2,9) is not NULL
      then isnull(cast(convert(float,rtrim(substring(er.RemarksData5,2,9))) as decimal(15,2)),0.0)
                     when er.RemarkCode6 in ('016','091','092','802') and substring(er.RemarksData6,2,9) is not NULL
      then isnull(cast(convert(float,rtrim(substring(er.RemarksData6,2,9))) as decimal(15,2)),0.0)
                     else 0.0
--                     when er.RemarkCode1 in ('016','091','092','802') then replace(er.RemarksData1, '$', '')
--                     when er.RemarkCode2 in ('016','091','092','802') then replace(er.RemarksData2, '$', '')
--                     when er.RemarkCode3 in ('016','091','092','802') then replace(er.RemarksData3, '$', '')
--                     when er.RemarkCode4 in ('016','091','092','802') then replace(er.RemarksData4, '$', '')
--                     when er.RemarkCode5 in ('016','091','092','802') then replace(er.RemarksData5, '$', '')
--                     when er.RemarkCode6 in ('016','091','092','802') then replace(er.RemarksData6, '$', '')
--                     else '0.0'
                    end,
 AgentSplit       = case
                     when er.RemarkCode1 in ('012','805','905')
      then isnull(cast(convert(float,replace(er.RemarksData1, '%', '')) as decimal(15,2)),100.0) 
--      then replace(er.RemarksData1, '%', '')
                     when er.RemarkCode2 in ('012','805','905') 
      then isnull(cast(convert(float,replace(er.RemarksData2, '%', '')) as decimal(15,2)),100.0)
--      then replace(er.RemarksData2, '%', '')
                     when er.RemarkCode3 in ('012','805','905') 
      then isnull(cast(convert(float,replace(er.RemarksData3, '%', '')) as decimal(15,2)),100.0)
--      then replace(er.RemarksData3, '%', '')
                     when er.RemarkCode4 in ('012','805','905') 
      then isnull(cast(convert(float,replace(er.RemarksData4, '%', '')) as decimal(15,2)),100.0)
--      then replace(er.RemarksData4, '%', '')
                     when er.RemarkCode5 in ('012','805','905') 
      then isnull(cast(convert(float,replace(er.RemarksData5, '%', '')) as decimal(15,2)),100.0)
--      then replace(er.RemarksData5, '%', '')
                     when er.RemarkCode6 in ('012','805','905') 
      then isnull(cast(convert(float,replace(er.RemarksData6, '%', '')) as decimal(15,2)),100.0)
--      then replace(er.RemarksData6, '%', '')
                     else '100.0'
                    end,
 FeeType          = -- 'IC',
        -- RH 23 Jan 2007 CR224 Fix Fee Type Descriptions
        -- slightly more efficient though more wordy to do as seperate searched case clauses
        -- than OR statements. Also ordered clauses this way as more likely to find match in Code1 than Code6
      case
        when er.ListPosition in (51,54,55) and er.RemarksString like '%renew%' then 'RC'
        when er.ListPosition in (51,55) 
          and isnull(er.Premium,0) = 0        -- WI260
          and er.RemarksString like '%trai%'      -- WI260
          and er.RemarksString not like '%no tra%' then 'TF'  -- WI260
        when er.RemarkCode1 in (73, 86, 94, 162) then 'IC'
        when er.RemarkCode1 in (74, 87, 99, 100, 112, 155, 156, 157, 159, 185, 813, 908) then 'Fee'
        when er.RemarkCode1 in (75, 167) then 'RC'
        when er.RemarkCode1 in (111, 170) then 'AF'
        when er.RemarkCode1 = 154 then 'PR'
        when er.RemarkCode1 in (163, 166, 173, 174, 184) then 'TF'
        when er.RemarkCode1 = 175 then 'LF'
        when er.RemarkCode2 in (73, 86, 94, 162) then 'IC'
        when er.RemarkCode2 in (74, 87, 99, 100, 112, 155, 156, 157, 159, 185, 813, 908) then 'Fee'
        when er.RemarkCode2 in (75, 167) then 'RC'
        when er.RemarkCode2 in (111, 170) then 'AF'
        when er.RemarkCode2 = 154 then 'PR'
        when er.RemarkCode2 in (163, 166, 173, 174, 184) then 'TF'
        when er.RemarkCode2 = 175 then 'LF'
        when er.RemarkCode3 in (73, 86, 94, 162) then 'IC'
        when er.RemarkCode3 in (74, 87, 99, 100, 112, 155, 156, 157, 159, 185, 813, 908) then 'Fee'
        when er.RemarkCode3 in (75, 167) then 'RC'
        when er.RemarkCode3 in (111, 170) then 'AF'
        when er.RemarkCode3 = 154 then 'PR'
        when er.RemarkCode3 in (163, 166, 173, 174, 184) then 'TF'
        when er.RemarkCode3 = 175 then 'LF'
        when er.RemarkCode4 in (73, 86, 94, 162) then 'IC'
        when er.RemarkCode4 in (74, 87, 99, 100, 112, 155, 156, 157, 159, 185, 813, 908) then 'Fee'
        when er.RemarkCode4 in (75, 167) then 'RC'
        when er.RemarkCode4 in (111, 170) then 'AF'
        when er.RemarkCode4 = 154 then 'PR'
        when er.RemarkCode4 in (163, 166, 173, 174, 184) then 'TF'
        when er.RemarkCode4 = 175 then 'LF'
        when er.RemarkCode5 in (73, 86, 94, 162) then 'IC'
        when er.RemarkCode5 in (74, 87, 99, 100, 112, 155, 156, 157, 159, 185, 813, 908) then 'Fee'
        when er.RemarkCode5 in (75, 167) then 'RC'
        when er.RemarkCode5 in (111, 170) then 'AF'
        when er.RemarkCode5 = 154 then 'PR'
        when er.RemarkCode5 in (163, 166, 173, 174, 184) then 'TF'
        when er.RemarkCode5 = 175 then 'LF'
        when er.RemarkCode6 in (73, 86, 94, 162) then 'IC'
        when er.RemarkCode6 in (74, 87, 99, 100, 112, 155, 156, 157, 159, 185, 813, 908) then 'Fee'
        when er.RemarkCode6 in (75, 167) then 'RC'
        when er.RemarkCode6 in (111, 170) then 'AF'
        when er.RemarkCode6 = 154 then 'PR'
        when er.RemarkCode6 in (163, 166, 173, 174, 184) then 'TF'
        when er.RemarkCode6 = 175 then 'LF'
        else 'IC'
      end
        ,
 Remarks          = er.BIRemarks,
 Provider         = cast(case
                     when er.ListPosition = 6 and er.ProductCode  = 'MOR' then 'MORTGAGE'
                     when er.ListPosition = 6 and er.ProductCode <> 'MOR' then 'GI'
                     when er.ListPosition = 54                           then 'SCOT EQ'
                     when er.ListPosition in (51,55)                     then 'STERLING'
                     else 'ZURICH'
                    end as varchar(100)), 
-- SEE GRAHAM ABOUT WHETHER THE PROVIDER CODE SHOULD HAVE BEEN INCLUDED IN THE MSIT_FEESNONSWIFTFEELISTING TABLE

 ProviderCode     = case
                     when er.ListPosition = 6 and er.ProductCode  = 'MOR' then 'MORTGAGE'
                     when er.ListPosition = 6 and er.ProductCode <> 'MOR' then 'GI'
                     when er.ListPosition = 54                           then 'SCOT EQ'
                     when er.ListPosition in (51,55)                     then 'STERLING'
                     else 'ZURICH'
                    end,
 SourceID         = er.[Id],
 ListPosition     = er.ListPosition,
 [Month]          = er.[Month],
 Source           = 'Openwork 2005',
 TotDue_Base      =  case 
            when er.ListPosition = 6 and er.ProductCode = 'MOR' then isnull(er.Value2, 0.0)* 80.0/er.EnhancementRate  -- WI260 MTG 
            when er.ListPosition = 6 and er.ProductCode <> 'MOR' then isnull(er.Value2, 0.0)* 27.5/er.EnhancementRate -- WI260 GI
                        when er.ListPosition in (51,54,55) then
         case 
        when er.TotalFees < 0 then er.TotalFees/(er.EnhancementRate/100)
        when er.TotalFees > 0 and er.PayBasis <> 'I' and er.NBI_Flag = 'Y' then er.TOT_DUE/(er.EnhancementRate/100)
        when er.TotalFees > 0 and er.PayBasis = 'I' then er.TotalFees/(er.EnhancementRate/100)
        else 0.0
         end
      else isnull(er.Value1, 0.0)
         end,
 Accrued_Base     = case 
--                     when er.ListPosition = 6 then 0.0  -- WI260
         when er.ListPosition = 6 and er.ProductCode = 'MOR' and er.EnhancementRate > 0 then isnull(er.Value2, 0.0)* 80.0/er.EnhancementRate  -- WI260 MTG 
         when er.ListPosition = 6 and er.ProductCode <> 'MOR' and er.EnhancementRate > 0 then isnull(er.Value2, 0.0)* 27.5/er.EnhancementRate -- WI260 GI
                     when er.ListPosition in (51,54,55) and er.PayBasis = 'I' then 0.0
                     when er.ListPosition in (51,54,55) and er.PayBasis <> 'I' and er.EnhancementRate > 0 then er.TotalFees/(er.EnhancementRate/100)
                     else isnull(er.Value2, 0.0)
                    end,
 StillToAccr_Base = case
          when er.ListPosition in (51,54,55) and er.PayBasis = 'I' then 0.0
          when er.ListPosition in (51,54,55) and er.PayBasis <> 'I' and er.EnhancementRate > 0 then 
        case er.Frequency 
         when 'M' then cast((er.TOT_DUE - (er.MONTHS * er.TotalFees))/(er.EnhancementRate/100) as decimal(15,2))
         when 'R' then cast((er.TOT_DUE - (er.MONTHS * er.TotalFees))/(er.EnhancementRate/100) as decimal(15,2))
         when 'A' then cast((er.TOT_DUE - ((er.MONTHS/12) * er.TotalFees))/(er.EnhancementRate/100) as decimal(15,2))
             else 0.0 
            end
          else isnull(er.Value3, 0.0)
        end,
 ITAdvanced_Base  = case 
          when er.ListPosition in (51,54,55) and er.PayBasis = 'I' and er.EnhancementRate > 0 then er.TotalFees/(er.EnhancementRate/100)
          when er.ListPosition in (51,54,55) and er.PayBasis <> 'I' then 0.0
          else isnull(er.Value4, 0.0)
        end,
 EnhancementRate  = er.EnhancementRate,
 TotDue_Enhd      = case 
                        when er.ListPosition = 6 then isnull(er.Value2,0.0)
          when er.ListPosition in (51,54,55) then
         case 
        when er.TotalFees < 0 then er.TotalFees
        when er.TotalFees > 0 and er.Frequency not in ('A','M','R') then er.TotalFees
        when er.TotalFees > 0 and er.PayBasis <> 'I' and er.NBI_Flag = 'Y' then er.TOT_DUE
        when er.TotalFees > 0 and er.PayBasis = 'I' then er.TotalFees
        else 0.0
         end
      else isnull(er.Value1, 0.0) * er.EnhancementRate / 100
        end,
 Accrued_Enhd     = case
                     when er.ListPosition = 6 then isnull(er.Value2,0.0)
                     when er.ListPosition < 6 then isnull(er.Value2,0.0) + isnull(er.UpLiftAccr,0.0)
                     when er.ListPosition > 6 and isnull(er.EnhancementAccr,0.0) <> 0 then er.EnhancementAccr
                     when er.ListPosition in (51,54,55) and er.PayBasis = 'I' then 0.0
                     when er.ListPosition in (51,54,55) and er.PayBasis <> 'I' then er.TotalFees
                     else isnull(er.Value2,0.0) * isnull(er.EnhancementRate,0.0) / 100
                    end,
 StillToAccr_Enhd = case 
          when er.ListPosition in (51,54,55) and er.PayBasis = 'I' then 0.0 
          when er.ListPosition in (51,54,55) and er.PayBasis <> 'I' then 
        case er.Frequency 
         when 'M' then cast((er.TOT_DUE - (er.MONTHS * er.TotalFees)) as decimal(15,2))
         when 'R' then cast((er.TOT_DUE - (er.MONTHS * er.TotalFees)) as decimal(15,2))
         when 'A' then cast((er.TOT_DUE - ((er.MONTHS/12) * er.TotalFees)) as decimal(15,2))
--             when er.TOT_DUE - (er.MONTHS * er.TotalFees) > 0 then er.TOT_DUE - (er.MONTHS * er.TotalFees) 
             else 0.0 
            end
             else
                case
            when isnull(StillLeftToAccrue,0.0) <> 0 then StillLeftToAccrue
            else isnull(er.Value3,0.0) * isnull(er.EnhancementRate,0.0) / 100
                end
        end,
 ITAdvanced_Enhd  = case
                     when er.ListPosition < 6 then isnull(Value4,0.0) + isnull(UpLiftIT,0.0)
                     when er.ListPosition > 6 and isnull(ITAdvance,0.0) <> 0 then ITAdvance
                     when er.ListPosition in (51,54,55) and er.PayBasis = 'I' then er.TotalFees
                     when er.ListPosition in (51,54,55) and er.PayBasis <> 'I' then 0.0
                     else isnull(Value4,0.0) * isnull(er.EnhancementRate,0.0) / 100
                    end,
 TotalPayment     = case
                     when ListPosition in (51,54,55) then isnull(TotalFees,0.0)
                     else NULL
                    end,
 DistributorRef   = NULL,
 CreateDate       = DateLoaded,
 TransactionID    = NULL,   --WI260
 er.ProductCode,
 er.DeclarationDate

into
 #msit_OpenworkAdviserListing
from
 --msit_FeesNonSWIFTFeeListing s,
 mstt_Agents                 a,
 #EnhancementRate            er
where
 er.SwiftFranchise      = a.Code and
 --er.ID                  = er.ID  and
 er.OpenworkInd         = 'Y'    and
 er.ListPosition   not in (7,8)
--  and ((Month >= @LoadMidMonth
--  and ListPosition = 55)
--  or (Month >= @LoadEndMonth
--  and ListPosition in (0,1,2,3,6,51,54,100))) 
 
 exec msp_ProcessLog 'OALPS', '#msit_OpenworkAdviserListing', null, 'OALPS', 'Openwork'
 
create index ix_msit_oal1 on #msit_OpenworkAdviserListing (Month, ListPosition, Source)
 exec msp_ProcessLog 'OALPS', 'ix_msit_oal1', null, 'OALPS', 'Openwork'
 
create index ix_msit_oal2 on #msit_OpenworkAdviserListing (BusinessCode)
 exec msp_ProcessLog 'OALPS', 'ix_msit_oal2', null, 'OALPS', 'Openwork'
 
create index ix_msit_oal3 on #msit_OpenworkAdviserListing (BACSDate)
 exec msp_ProcessLog 'OALPS', 'ix_msit_oal3', null, 'OALPS', 'Openwork'
 
create index ix_msit_oal4 on #msit_OpenworkAdviserListing (Provider)
 exec msp_ProcessLog 'OALPS', 'ix_msit_oal4', null, 'OALPS', 'Openwork'

drop table #EnhancementRate
 
--UPDATE ProdType column. We do this update instead of the nested select in the insert above
--to assist performance.
update
 oal
set
 ProdType  = substring(lp.SWIFTProdType,1,8)
from
 #msit_OpenworkAdviserListing oal,
 msit_LegacyProducts lp
where
 oal.ProductCode           = lp.LegacyProdCode and
 oal.DeclarationDate between lp.StartDate      and lp.EndDate
 
 exec msp_ProcessLog 'OALPS', 'Update 1', null, 'OALPS', 'Openwork'

-- update
--  oal
-- set
--  ProdType  = ProductCode
-- from
--  #msit_OpenworkAdviserListing oal
-- where
--  oal.ProdType  is null
--  
--  exec msp_ProcessLog 'OALPS', 'Update 2', null, 'OALPS', 'Openwork'

--MK: Commenting out this update, as the calc is done in the insert above
-- UPDATE THE APE FIELD BASE ON THE VALUE CONTAINED WITHIN AGENT SPLIT
--update
-- #msit_OpenworkAdviserListing
--set
-- APE = APE * AgentSplit
--where
-- --Source = 'Openwork 2005'
-- --and 
-- ((Month >= @LoadMidMonth
-- and ListPosition = 55)
-- or (Month >= @LoadEndMonth
-- and ListPosition in (0,1,2,3,6,51,54,100))) 


-- UPDATE PROVIDER WITH THE PROVIDER NAME USING THE CODE DETERMINED IN THE PREVIOUS INSERT STATEMENT
update
 #msit_OpenworkAdviserListing
set
 Provider = pp.CommRepProductProviderName
from
 mstt_ProductProviders pp
where
 #msit_OpenworkAdviserListing.Provider = pp.CommRepProductProviderCode-- and
 --Source                               = 'Openwork 2005'
 --and 
--  ((Month >= @LoadMidMonth
--  and ListPosition = 55)
--  or (Month >= @LoadEndMonth
--  and ListPosition in (0,1,2,3,6,51,54,100))) 
 
  exec msp_ProcessLog 'OALPS', 'Update 3', null, 'OALPS', 'Openwork'

-- -- UPDATE TOTALPAYMENT FIELD
-- update
--  #msit_OpenworkAdviserListing
-- set
--  TotalPayment = Accrued_Enhd + ITAdvanced_Enhd
-- where
--  TotalPayment is NULL --and
--  --Source = 'Openwork 2005'
--  and ((Month >= @LoadMidMonth
--  and ListPosition = 55)
--  or (Month >= @LoadEndMonth
--  and ListPosition in (0,1,2,3,6,51,54,100))) 
--  
--  exec msp_ProcessLog 'OALPS', 'Update 4', null, 'OALPS', 'Openwork'

update
 #msit_OpenworkAdviserListing
set
 Premium             = round(Premium,2),
 APE                 = round(APE,2),
 CommRate            = round(CommRate,2),
 Sacrifice           = round(Sacrifice,2),
 AgentSplit          = round(AgentSplit,2),
 TotDue_Base         = round(TotDue_Base,2),
 Accrued_Base        = round(Accrued_Base,2),
 StillToAccr_Base    = round(StillToAccr_Base,2),
 ITAdvanced_Base     = round(ITAdvanced_Base,2),
 EnhancementRate     = round(EnhancementRate,2),
 TotDue_Enhd         = round(TotDue_Enhd,2),
 Accrued_Enhd        = round(Accrued_Enhd,2),
 StillToAccr_Enhd    = round(StillToAccr_Enhd,2),
 ITAdvanced_Enhd     = round(ITAdvanced_Enhd,2),
 TotalPayment        = round(isnull(TotalPayment, (Accrued_Enhd + ITAdvanced_Enhd)),2),
 ProdType            = isnull(ProdType, ProductCode)
--  where ((Month >= @LoadMidMonth
--  and ListPosition = 55)
--  or (Month >= @LoadEndMonth
--  and ListPosition in (0,1,2,3,6,51,54,100))) 
 
  exec msp_ProcessLog 'OALPS', 'Update 5', null, 'OALPS', 'Openwork'

-- Extract Positive NBI Movements

select t1.Policy,t1.StartDate,t1.Premium,t1.SourceID as POSID,t1.TotDue_enhd as NBI
into #NBIPositives
from #msit_OpenworkAdviserListing t1
where t1.TotDue_Enhd > 0
Order by t1.Policy,t1.StartDate,t1.Premium,t1.SourceID

exec msp_ProcessLog 'OALPS', '#APE1', null, 'OALPS', 'Openwork'

-- Extract Negative NBI Movements and Prev NBI Total
select t1.Policy,t1.StartDate,t1.Premium,t1.SourceID as NegID,t1.TotDue_enhd as NBI,
sum(isnull(t2.NBI,0)) as PrevNBI
into #NBINegatives
from #msit_OpenworkAdviserListing t1
left outer join #NBIPositives t2
on t2.Policy = t1.Policy and t2.StartDate = t1.StartDate and t1.Premium = t2.Premium and t2.POSID < t1.SourceID 
where t1.TotDue_Enhd < 0
Group by t1.Policy,t1.StartDate,t1.Premium,t1.SourceID,t1.TotDue_enhd
Order by t1.Policy,t1.StartDate,t1.Premium,t1.SourceID

exec msp_ProcessLog 'OALPS', '#APE2', null, 'OALPS', 'Openwork'

-- Now Zeroise APE if not applicable (i.e. NBI = zero or Negative NBI but net NBI > zero)
-- Also Zeroise TotDue and Still to Accrue if Fee Type not IC
-- For Sterling/Scot EQ RC/Trail always log as Accrued even if IT basis
update #msit_OpenworkAdviserListing
set APE = case
      when t1.FeeType <> 'IC' and ListPosition <> 6 then 0.0
      when isnull(t1.Frequency,'Z') <> 'S' and t2.NegID is not null and isnull(t2.NBI,0) + t2.PrevNBI > 0 then 0.0
      when isnull(TotDue_Enhd,0) = 0 then 0.0
      else t1.APE
    end,
Totdue_Enhd = case when t1.FeeType <> 'IC' and ListPosition <> 6 then 0.0 else t1.TotDue_Enhd end,
Totdue_Base = case when t1.FeeType <> 'IC' and ListPosition <> 6 then 0.0 else t1.TotDue_Base end,
Accrued_Enhd = case when t1.FeeType <> 'IC' and ListPosition in (51,54,55) and t1.PayBasis = 'IT' then t1.ITAdvanced_Enhd else t1.Accrued_Enhd end,
Accrued_Base = case when t1.FeeType <> 'IC' and ListPosition in (51,54,55) and t1.PayBasis = 'IT' then t1.ITAdvanced_Base else t1.Accrued_Base end,
ITAdvanced_Enhd = case when t1.FeeType <> 'IC' and ListPosition in (51,54,55) and t1.PayBasis = 'IT' then 0.0 else t1.ITAdvanced_Enhd end,
ITAdvanced_Base = case when t1.FeeType <> 'IC' and ListPosition in (51,54,55) and t1.PayBasis = 'IT' then 0.0 else t1.ITAdvanced_Base end,
StillToAccr_Enhd = case when t1.FeeType <> 'IC' then 0.0 else t1.StillToAccr_Enhd end,
StillToAccr_Base = case when t1.FeeType <> 'IC' then 0.0 else t1.StillToAccr_Base end
from #msit_OpenworkAdviserListing t1
left outer join #NBINegatives t2 on t1.SourceID = t2.NegID

exec msp_ProcessLog 'OALPS', '#APEUpd', null, 'OALPS', 'Openwork'

drop table #NBIPositives
drop table #NBINegatives

 --insert the rows into the table

insert into msit_OpenworkAdviserListing
select 
BusinessCode, BusinessName, SellerCode, SellerName, SellerForename, SellerSurname, Client, 
ClientForename, ClientSurname, BACSDate, Policy, CaseId, ProdType, StartDate, PaymentDate, 
Frequency, Premium, APE, CommRate, InitialPeriod, PayBasis, Sacrifice, AgentSplit, FeeType, 
Remarks, Provider, ProviderCode, SourceID, ListPosition, Month, Source, TotDue_Base, Accrued_Base, 
StillToAccr_Base, ITAdvanced_Base, EnhancementRate, TotDue_Enhd, Accrued_Enhd, StillToAccr_Enhd, 
ITAdvanced_Enhd, TotalPayment, DistributorRef, CreateDate , TransactionID           --WI260
from #msit_OpenworkAdviserListing

 exec msp_ProcessLog 'OALPS', 'Insert', null, 'OALPS', 'Openwork'

drop table #msit_OpenworkAdviserListing

--end

