                    END,                     --Ticket125091: MPC 06/10/2011
--   ABCRate        =  cs.ABCRate,      --PR ABC May 2008   --Ticket125091: MPC 06/10/2011
   SchemeNum        =  cs.SchemeNum,    --PR Mar 2009
   ProductGroup   = case        --PR Mar 2009
              when ph.StructuredProduct = 'Y' then 'Structured' 
              else COALESCE(ph.productgroupname,'Unknown')
            end,
   --SR371343 AG 30/04/2015 Start
   --ELITE_Points = round(isnull(cs.ELITE_Initial,0)+isnull(cs.ELITE_Ongoing,0)+isnull(cs.ELITE_NSC,0)+isnull(cs.ELITE_OMNIS,0),0)	--SR207107: MPC 11/03/2013	SR271363 AG 12/03/2014
   ELITE_Points =
	case when cs.Month >= '2015-02-01'
		then round(isnull(cs.ELITE_Initial,0)+isnull(cs.ELITE_Ongoing,0)+isnull(cs.ELITE_NSC,0)+isnull(cs.ELITE_OMNIS,0),1)	-- AG 05/06/2015
		else round(isnull(cs.ELITE_Initial,0)+isnull(cs.ELITE_Ongoing,0)+isnull(cs.ELITE_NSC,0)+isnull(cs.ELITE_OMNIS,0),0)	-- Original rounding for payments prior to Jan 2015 comm period.
	end
   --SR371343 AG 30/04/2015 End
   from
   msit_CommissionStatement cs
   inner join mstt_Agents a on cs.AgentCode = a.Code
   left outer join mstt_producthierarchy ph on ph.productcode = cs.productcode			--Ticket143
   left join ( select PACC_ID, sum(isnull(Agent_Perc,0)) as SumAgentPerc
				from mstt_PaymentsPending 
				where agent_code in (@OpenworkMarginPotCode,@OpenworkBSCPotCode)
				and	AMOUNT > 0
				group by PACC_ID
			 ) as PP_PosPotCodeSplits on PP_PosPotCodeSplits.pacc_ID = cs.expectationid 	
   left join ( select PACC_ID, sum(isnull(Agent_Perc,0)) as SumAgentPerc
				from mstt_PaymentsPending 
				where agent_code in (@OpenworkMarginPotCode,@OpenworkBSCPotCode)
				and	AMOUNT < 0
				group by PACC_ID
			 ) as PP_NegPotCodeSplits on PP_NegPotCodeSplits.pacc_ID = cs.expectationid  
   left join (select	PACC_ID, CONVERT(date,CreateDateTime) as PaymentMatchedDate, MAX(isnull(Agent_Perc,0)) as AdviserSplitPerc
				from	mstt_PaymentsPending
				where	agent_code <> '10002'
				group	by PACC_ID, CONVERT(date,CreateDateTime)
			 ) as AdviserSplit on AdviserSplit.PACC_ID = cs.ExpectationID 
								and AdviserSplit.PaymentMatchedDate = cs.CreateDate	-- PaymentDate included to handle backdated agent change (BAC) which does NOT create new expectation records
  where
   cs.ReportingClassCode = 1
   and cs.OAStatus = 'Valid'            --MPC: 16/04/2008 SR9
   -- PKID occurs lots of times for criteria, therefore a conventional join would have created dupes.
   and cs.PendingPaymentID IN (Select Distinct PKID From owt_TransformationMovements  --MPC:25/01/2010
                 where  DriverTableName = 'sa_swift_S_AGMFIL'     --MPC:25/01/2010
                 and  AdviserListing = 'Y')             -- AG 30/03/2010

  select @RowCount = @@rowcount                           
  set @ProcessMessage = @Mode + ' - 02) End INSERT : Count = ' + convert(varchar(10), @RowCount)
  exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client    

  UPDATE STATISTICS msit_OpenworkAdviserListing

  set @ProcessMessage = @Mode + ' - 04) End UPDATE STATISTICS'            --MPC:25/01/2010
  exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client    --MPC:25/01/2010

END   --@Mode = 'MOVE'

--MPC:25/01/2010  Movements Only - END

/******************************************************************************************************************
    END of PROCESSING
******************************************************************************************************************/

--END
exec msp_ProcessLog @PhaseEnd, @ProcName, null, @Module, @Client    --MPC:25/01/2010;

GO
/****** Object:  StoredProcedure [dbo].[msp_OpenworkAdviserListingSwift_Backup20190628AG]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE procedure [dbo].[msp_OpenworkAdviserListingSwift_Backup20190628AG] 
  @Client   varchar(50),            --MPC:25/01/2010
  @Module   varchar(50),            --MPC:25/01/2010
  @Mode   varchar(4)    --'FULL' or 'MOVE'  --MPC:25/01/2010

with recompile

as

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : msp_OpenworkAdviserListingSwift.sql
-- Owner   : MR
-- Created : 24/11/2006
--
-- Call as 
--  msp_OpenworkAdviserListingSwift 'Openwork', 'Open Access','MOVE'
-- OR
--  msp_OpenworkAdviserListingSwift 'Openwork', 'Open Access','FULL'
--
--########################################################################

/*
  Mike Cawood 08/06/2007
  Ticket 143 - Assign Mortgage Overrides based on Product Code not Provider

  Mike Cawood 08/10/2007
  Ticket 108 - Assign APE calculated on msit_CommissionStatement

  Alan Groves 23/01/2008
  Performance improvements:
  1)  Indexes dropped before DELETE then CREATED after INSERT.
  2)  Index on AgentCode added to table msit_CommissionStatement in proc msp_CommissionStatement
    to make INSERT faster.

  Alan Groves 25/01/2008
  performance improvements:
  1) DROP the clustered index last to ensure the NonClus indexes aren't rebuilt - this really happens!
  2) DROP "source" index before DELETE as the execution plan with no indexes is simpler.
  Note that the CREATE INDEX statements are already in the right sequence.

  Mike Cawood 16/04/2008 
  SR9 - Only include Entries where OAStatus = 'Valid'
  SR9 - Zeroise APE if LeagueInclude flag on ProductHierarchy is not 'Y'

  Paul Robathan May 2008
  ABC Currency Project.  Insert ABC Value/Rate from msit_commissionstatement

  Paul Robathan Mar 2009
  Add SchemeNum and ProductGroup to the table for showing on Open Access

  Paul Robathan - 27th Apr 2009
  Margin on Trail.  Set Commission Rate for Trail Cases split with Openwork to show pre split value
  i.e. if rate 80% agent 20% openwork then show Agent comm Rate as 100%

  Mike Cawood - 25 January 2010
  a) Performance Improvements. New Run Control parameter @mode added with two settings:

    'FULL': This triggers the full refresh of the Swift data held on the
        msit_OpenworkAdviserListing table using the primary keys held on the 
        owt_TransformationMovements table. All existing Swift rows (identified by
        Source of 'Openwork 2006') are deleted. The load table indexes are dropped 
        and recreated after the insert.

    'MOVE': In this mode only those Swift rows that are linked to daily movements of the
        driver sa_swift_S_AGMFIL table are processed. The primary keys of these movements 
        are held on the owt_TransformationMovements table with DriverTableName of
        'sa_swift_S_AGMFIL' (as thses movements are used to drive updates to the rows on
        the msit_CommissionStatement table with ReportingClassCode of 1). 
        All msit_CommissionStatement rows with Source of 'Openwork 2006' whose SourceID 
        matches to a primary key held on the movements table are deleted and then 
        inserted from the new data generated by the procedure. 
        Indexes are not dropped/created in this mode.
  
  b) Process Log processing introduced.

  Mike Cawood - 9 February 2010 
  a)  Fix to Delete step of Movements mode.

  Mike Cawood - 10 February 2010 
  a)  Fix to use PARALLEL version of msit_CommissionStatement.
  b)  Fix to use msit_CommissionStatement ID's captured on owt_TransformationMovements
    as driver for Delete step of 'MOVE' Mode. These ID's relate to the 
    sa_swift_S_AGMFIL movements captured on owt_TransformationMovements.

  Alan Groves - 30 March 2010
  a)  Used flag "AdviserListing" to reduce number of rows to process in "MOVE" mode.

  Alan Groves - 16 April 2010
  a)  CREATE and DROP indexes conditionally to improve robustness.

  Mike Cawood - 6 October 2011 - Ticket125091
  a)  Zeroise ABCRate and ABCValue where LeagueIncludeFlag is "N".

  Mike Cawood - 17 August 2012 - SR174877
  a)  Amend AgentSplit logic so that Pt Code sub-query only returns one value
	  for positive valued payments and one for negative valued payments.

  Mike Cawood - 11 March 2013 - SR207107
  a)  Add Elite_Points column and derive from msit_CommissionStatement values.
 
  Alan Groves - 25 February 2014 - SR292645
  a)	Include the Business Service Charge (BSC) pot code when grossing up
		the adviser split percentage so that the sum of adviser splits is
		always 100% when both ongoing fee margin and BSC splits occur on an
		ongoing payment. This change was requested by both Mark Cooper and 
		Debs Burchell.
		
  Alan Groves - 12 March 2014 - SR271363
  a)	Marcus Cossey requested ELITE points to be integer values. Previously was to 2dp.

  Alan Groves - 10 October 2014 - SR337443
  a)	Correction to the fix of 25/02/2014 (SR292645) which previously did 
		not include trail clawbacks and trail adjustments in the trail calculation.

  Alan Groves - 20 November 2014 - SR346475
  a)	Amended for Owl Financial. In order to pay advisers the correct amount, the 
		commission shapes have been set up in such a way that adviser split % does
		not calculate correctly. This change introduces adjustment processing to
		restore the adviser split % to the value that the adviser would expect to see.

  Alan Groves - 30/04/2015 SR371343
  New ELITE points calculation introduced as requested by Mark Duckworth via Marcus Cossey. 
  See proc "msp_CommissionStatement" for the actual calculation. The change in this proc
  merely concerns itself with the new ELITE points rounding method that the new calculation
  has introduced. The rounding works as follows: 
  27.00 rounds to 27		-27.00 rounds to -27
  27.01 rounds to 28		-27.01 rounds to -28
  27.49 rounds to 28		-27.49 rounds to -28
  27.51 rounds to 28		-27.51 rounds to -28
  27.99 rounds to 28		-27.99 rounds to -28

  Alan Groves - 05/06/2015 SR380825
  Change ELITE_Points rounding from the CEILING value to rounded to one decimal place as
  per Marcus Cossey's instructions.
  
  Alan Groves - 10/08/2016 Break fix
  This proc got stuck on the main INSERT in MOVE mode on 10/08/2016.
  "WITH RECOMPILE" was added, as there was a concern that a low volume query plan
  had been used as a result of patching and a re-boot. If this was so, then this 
  low volume query plan would have been inappropriate for this run which was of
  high volume following a monthly pay run earlier that night. 

  Alan Groves - 07/11/2016 SR457552/CH15313
  Owl agent split amendments for the introduction of panel markers 033 and 034. This change
  adds new config to table @SpecialCaseCommShapes to change the splits as follows:
  ASM
  ---
  18.52% was 20% needs to be 25%
  17.86% was 20% needs to be 25%
  Introducer
  ----------
  7.41% was 15% needs to be 10%
  7.14% was 15% needs to be 10%
  In addition, this check: "and convert(decimal(12,2),cs.AgentSplit) = sccs.AdviserSplitPct" moved
  from the SELECT to the FROM clause.

  Alan Groves - 21/12/2017	SR496817/CH19971
  Two changes as follows:
  1) The Openwork Agent Splits calculation queries table mstt_PaymentsPending in the SELECT part of 
	 the query. This was only made robust by executing "UPDATE STATISTICS with fullscan" in 
	 mstp_PaymentsPending, but this line was taking from 45 mins to 1 hour to run. The Agent Splits
	 calculation has been recoded to do all the work in the FROM clause. This will enable the "with
	 fullscan" to be removed which should introduce a BI Main Batch performance improvement.
  2) The Owl Agent Splits smoothing previously used banding table "owt_Bandings" along with a config'd
     list of special case commission shape IDs where the banding did not give the required results.
     The bandings and special cases have been replaced by arithmetic. Apart from being simpler, the
	 arithmetic should always work even when PSD introduce new commission shapes that would previously
	 have been in the group of special case commission shape IDs.

	Alan Groves 02/05/2018	SR504834/CH21153/CR630.
	This amendment makes no functional/logical change to this proc. It has been carried out to enable
	the new column "msit_OpenworkAdviserListing.VNB_Points" to be introduced without having to change
	and deploy this proc simultaneously. It is all part of the work to separate VNB from the legacy
	batch procs to protect them as VNB is likely to be subject to many tweaks as was the case with ELITE.
	The changes are as follows:
	1) Removal of the duplicate INSERT statements into msit_OpenworkAdviserListing by combining the
		MOVE and FULL logic. Previously, the two INSERTs were an unnecessary maintenance overhead.
	2) Introduction of listed columns in the INSERT statement. When the "msit_OpenworkAdviserListing.VNB_Points"
		 column is introduced, this proc will default the column to null.
	

  Chris Mellors - 17/04/2019
  Added Page compression to msit_OpenworkAdviserListing and indexes
*/

--MPC:25/01/2010 New ProcessLog Start
declare	@PhaseStart		varchar(50),
		@PhaseEnd		varchar(50),
		@ProcName		varchar(100),
		@ProgressModule	varchar(50),
		@RowCount		int,
		@ProcessMessage	varchar(100)

set @ProcName		= object_name(@@procid) + ' - ' + @Mode
set @PhaseStart		= 'START'
set @PhaseEnd		= 'END'
set @ProgressModule	= 'OAL'

exec msp_ProcessLog @PhaseStart, @ProcName, null, @Module, @Client
--MPC:25/01/2010 New ProcessLog End

declare	@OpenworkMarginPotCode		nvarchar(10),	-- PR 27/04/2009
		@OpenworkMarginScriptDate	datetime,		-- PR 27/04/2009
		@OpenworkBSCPotCode			nvarchar(10),	-- AG 25/02/2014
		@OwlManager2Code			varchar(7)		-- AG 20/11/2014

set @OpenworkMarginPotCode = (select Rtrim(longdescription) from msit_MIWarehouseCodesAndDescriptions 
          where columnname = 'OpenworkMarginOnTrail' and description = 'AgentCode')		-- PR 27/04/2009
set @OpenworkMarginScriptDate = (select cast(longdescription as datetime) from msit_MIWarehouseCodesAndDescriptions 
          where  columnname = 'OpenworkMarginOnTrail' and description = 'ScriptDate')	-- PR 27/04/2009
set @OpenworkBSCPotCode = (select Rtrim(longdescription) from msit_MIWarehouseCodesAndDescriptions 
          where columnname = 'BusinessServiceCharge' and description = 'AgentCode')		-- AG 25/02/2014
set @OwlManager2Code = (select cde.Code from msit_MIWarehouseCodesAndDescriptions cde	-- AG 20/11/2014
			where cde.ColumnName = 'Manager2Code' and cde.Description = 'Owl Financial')

/******************************************************************************************************************
    If FULL mode, then drop indexes and delete all the Openwork 2006 data
    If MOVE mode, then delete just the data to be inserted
******************************************************************************************************************/

IF @Mode = 'FULL'   --MPC:25/01/2010
BEGIN				--MPC:25/01/2010

  if indexproperty(object_id('msit_OpenworkAdviserListing'),'BusinessCode','IndexID') is not null
    DROP INDEX msit_OpenworkAdviserListing.BusinessCode

  if indexproperty(object_id('msit_OpenworkAdviserListing'),'IX_OpenworkAdviserListing_Month','IndexID') is not null
    DROP INDEX msit_OpenworkAdviserListing.IX_OpenworkAdviserListing_Month

  if indexproperty(object_id('msit_OpenworkAdviserListing'),'IX_OpenworkAdviserListing_Policy','IndexID') is not null
    DROP INDEX msit_OpenworkAdviserListing.IX_OpenworkAdviserListing_Policy

  if indexproperty(object_id('msit_OpenworkAdviserListing'),'IX_OpenworkAdviserListing_alID','IndexID') is not null
    DROP INDEX msit_OpenworkAdviserListing.IX_OpenworkAdviserListing_alID

  if indexproperty(object_id('msit_OpenworkAdviserListing'),'IX_OpenworkAdviserListing_TransactionID','IndexID') is not null
    DROP INDEX msit_OpenworkAdviserListing.IX_OpenworkAdviserListing_TransactionID

  if indexproperty(object_id('msit_OpenworkAdviserListing'),'IX_OpenworkdviserListing_Source','IndexID') is not null
    DROP INDEX msit_OpenworkAdviserListing.IX_OpenworkdviserListing_Source

  if indexproperty(object_id('msit_OpenworkAdviserListing'),'IX_OpenworkAdviserListing_SchemeNum','IndexID') is not null
    DROP INDEX msit_OpenworkAdviserListing.IX_OpenworkAdviserListing_SchemeNum    -- PR 16 Mar 2009

  if indexproperty(object_id('msit_OpenworkAdviserListing'),'IX_OpenworkAdviserListing_SourceId','IndexID') is not null
    DROP INDEX msit_OpenworkAdviserListing.IX_OpenworkAdviserListing_SourceId     --MPC:25/01/2010

  if indexproperty(object_id('msit_OpenworkAdviserListing'),'IX_msit_OpenworkAdviserListing','IndexID') is not null
    DROP INDEX msit_OpenworkAdviserListing.IX_msit_OpenworkAdviserListing -- Clustered index so drop last for efficiency

  set @ProcessMessage = @Mode + ' - 01) End DROP INDEX'             --MPC:25/01/2010
  exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client  --MPC:25/01/2010

  Delete msit_OpenworkAdviserListing
  where Source = 'Openwork 2006'

  select @RowCount = @@rowcount                           --MPC:25/01/2010
  set @ProcessMessage = @Mode + ' - 02) End DELETE : Count = ' + convert(varchar(10), @RowCount) --MPC:25/01/2010
  exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client    --MPC:25/01/2010

END
ELSE	--@Mode = 'MOVE' 
BEGIN

  -- AG 30/03/2010 Start
  --Delete msit_OpenworkAdviserListing
  --Where Source = 'Openwork 2006'
  --and SourceID IN (Select Distinct PKID From owt_TransformationMovements			--MPC:10/02/2010
  --           where DriverTableName = 'msit_CommissionStatement')					--MPC:10/02/2010

  Delete  OAL
  from  msit_OpenworkAdviserListing OAL
      inner join owt_TransformationMovements TM on TM.PKID = OAL.SourceID 
  Where OAL.Source = 'Openwork 2006'
  and   TM.DriverTableName = 'msit_CommissionStatement'
  and   TM.AdviserListing = 'Y'
  -- AG 30/03/2010 End

  select @RowCount = @@rowcount                           
  set @ProcessMessage = @Mode + ' - 01) End DELETE : Count = ' + convert(varchar(10), @RowCount) 
  exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client        

END

-- INSERT SWIFT DATA
insert into msit_OpenworkAdviserListing		--AG 02/05/2018
(
	BusinessCode,
	BusinessName,
	SellerCode,
	SellerName,
	SellerForename,
	SellerSurname,
	Client,
	ClientForename,
	ClientSurname,
	BACSDate,
	Policy,
	CaseId,
	ProdType,
	StartDate,
	PaymentDate,
	Frequency,
	Premium,
	APE,
	CommRate,
	InitialPeriod,
	PayBasis,
	Sacrifice,
	AgentSplit,
	FeeType,
	Remarks,
	Provider,
	ProviderCode,
	SourceID,
	ListPosition,
	Month,
	Source,
	TotDue_Base,
	Accrued_Base,
	StillToAccr_Base,
	ITAdvanced_Base,
	EnhancementRate,
	TotDue_Enhd,
	Accrued_Enhd,
	StillToAccr_Enhd,
	ITAdvanced_Enhd,
	TotalPayment,
	DistributorRef,
	CreateDate,
	TransactionID,
	ABCValue,
	ABCRate,
	SchemeNum,
	ProductGroup,
	ELITE_Points
)
select	BusinessCode	= cs.BusinessCode,
		BusinessName	= cs.FranchiseName,
		SellerCode		= cs.AgentCode,
		SellerName		= cast(cs.SellerName as varchar(50)) + ' - ' + cs.AgentCode,
		SellerForename	= case when charindex(' ', a.FirstNames) = 0 
							then a.FirstNames
							else rtrim(substring(a.FirstNames, 1, charindex(' ', a.FirstNames)))
						  end,
		SellerSurname	= a.[Name],
		Client			= cast(cs.ClientSurname as varchar(60)) + case when cs.ClientForenames is null then '' else ' ' + cast(cs.ClientForenames as varchar(1)) end,
		ClientForname	= case when charindex(' ', cs.ClientForenames) = 0 
							then cs.ClientForenames
							else rtrim(substring(cs.ClientForenames, 1, charindex(' ', cs.ClientForenames)))
						  end,
		ClientSurname	= cs.ClientSurname,
		BACSDate		= cs.BACSDate,
		Policy			= cs.ExtPolicyNumber,
		CaseId			= cs.CaseId,
		-- ProdType         = case when CommProviderCode = 'MORTGAGE' then cs.CommProviderCode  --Ticket143
		ProdType		= case when ph.productgroupcode = 3 
							then cs.CommProviderCode    --Ticket143
							else cs.ProductCode 
						  end,
		StartDate		= cs.StartDate,
		PaymentDate		= cs.PaymentDate,
		Frequency		= cast(cs.FrequencyDesc as varchar(1)),
		Premium			= cs.Premium,
		APE				= case when isnull(ph.LeagueIncludeFlag,'N') = 'Y'	--SR9: MPC 16/04/08
							then  isnull(cs.APE,0.0) --SR9: MPC 16/04/08
							else 0.0               --SR9: MPC 16/04/08
						   end,                 --SR9: MPC 16/04/08
		-- APE             = isnull(cs.APE,0.0),            --Ticket 108  --SR9: MPC 16/04/08
		-- APE              = case                --Ticket 108
		--                     when cs.INIssued > 0 or cs.INIndemnity > 0 then cs.APE   --Ticket 108
		--                     else 0.0               --Ticket 108
		--                    end,                --Ticket 108
		CommRate		= cs.CommissionRate,
		InitialPeriod	= cs.InitialPeriod,
		PayBasis		= cast(cs.PayBasisDesc as varchar(10)),
		Sacrifice		= cs.CommSacrificeAmt,
		--AgentSplit		= case when a.Manager2Code = @OwlManager2Code then	-- AG 20/11/2014
				--			case when sccs.CommissionShapeID is not null	-- AG 07/11/2016
				--				then sccs.OverrideSplitPct
				--				else b.BandValue
				--			end
				--		 when (cs.AgentSplit between 1 and 99) and cs.CommissionType in (10,16,19) and DueDate >= @OpenworkMarginScriptDate then		-- AG 10/10/2014
				--		   isnull((cs.AgentSplit/(100-
				--		--    isnull((select Agent_Perc from mstt_PaymentsPending where agent_code = @OpenworkMarginPotCode and			--SR174877: MPC 17/08/2012
				--		--           TransactionID=cs.TransactionID and pacc_ID=cs.expectationid),0))) * 100, cs.AgentSplit)			--SR174877: MPC 17/08/2012
				--		   isnull(CASE																									--SR174877: MPC 17/08/2012
				--					WHEN cs.Amount > 0 then																				--SR174877: MPC 17/08/2012
				--					(select sum(Agent_Perc) from mstt_PaymentsPending where (agent_code = @OpenworkMarginPotCode or agent_code = @OpenworkBSCPotCode) and	--SR174877: MPC 17/08/2012 & SR292645 AG 25/02/2014
				--					 pacc_ID=cs.expectationid and isnull(Agent_Perc,0) > 0 and Amount > 0)					--SR174877: MPC 17/08/2012
				--					WHEN cs.Amount < 0 then																				--SR174877: MPC 17/08/2012
				--					(select sum(Agent_Perc) from mstt_PaymentsPending where (agent_code = @OpenworkMarginPotCode or agent_code = @OpenworkBSCPotCode) and	--SR174877: MPC 17/08/2012 & SR292645 AG 25/02/2014
				--					 pacc_ID=cs.expectationid and isnull(Agent_Perc,0) > 0 and Amount < 0)					--SR174877: MPC 17/08/2012
				--					ELSE 0																								--SR174877: MPC 17/08/2012
				--					END ,0)	) ) * 100 , cs.AgentSplit)																	--SR174877: MPC 17/08/2012
				--		 else
				--		  cs.AgentSplit
				--		end,
		AgentSplit		= case 
							when a.Manager2Code = @OwlManager2Code then
								case when AdviserSplit.AdviserSplitPerc >= 0.01
									then round(((cs.AgentSplit / AdviserSplit.AdviserSplitPerc) * 100.0) * 4.0, 0) / 4.0					--Rounds to nearest 0.25.
									else cs.AgentSplit
								end
							when (cs.AgentSplit between 1 and 99) and cs.CommissionType in (10,16,19) and DueDate >= @OpenworkMarginScriptDate then		-- AG 10/10/2014
							   isnull((cs.AgentSplit/(100-
							   isnull(CASE																									--SR174877: MPC 17/08/2012
										WHEN cs.Amount > 0 then																				--SR174877: MPC 17/08/2012
											PP_PosPotCodeSplits.SumAgentPerc							
										WHEN cs.Amount < 0 then																				--SR174877: MPC 17/08/2012
											PP_NegPotCodeSplits.SumAgentPerc
										ELSE 0																								--SR174877: MPC 17/08/2012
										END ,0)	) ) * 100 , cs.AgentSplit)																	--SR174877: MPC 17/08/2012
							 else
							  cs.AgentSplit
						   end,		
		FeeType			= cast(cs.CommFeeType as varchar(10)),
		-- Remarks          = case when CommProviderCode = 'MORTGAGE'   --Ticket143
		Remarks			= case when ph.productgroupcode = 3   --Ticket143 
							then (select substring(cd.Description,1,150) 
									from msit_MIWarehouseCodesandDescriptions cd
									WHERE cd.ColumnName = 'CodeCommissionShapeID'
									and cd.Code = cs.CommShapeID)
							else cs.CommReason 
						   end,
		Provider		= cs.ProviderName,                    
		ProviderCode	= cs.ProviderCode,
		SourceID		= cs.[Id],
		ListPosition	= NULL,
		[Month]			= cs.[Month],
		Source			= 'Openwork 2006',
		TotDue_Base		= isnull(cs.EXIssued, 0.0),
		Accrued_Base	= isnull(cs.EXAccrued, 0.0),
		StillToAccr_Base= isnull(cs.EXStilltoAccrue, 0.0),
		ITAdvanced_Base	= isnull(cs.EXIndemnity, 0.0),
		EnhancementRate	= isnull(cs.FranchiseUpliftRate, 0.0),
		TotDue_Enhd		= isnull(cs.INIssued, 0.0),
		Accrued_Enhd	= isnull(cs.INAccrued, 0.0),
		StillToAccr_Enhd= isnull(cs.INStilltoAccrue, 0.0),
		ITAdvanced_Endh	= isnull(cs.INIndemnity, 0.0),
		TotalPayment	= isnull(cs.INAccrued, 0.0) + isnull(cs.INIndemnity, 0.0),
		DistributorRef	= cs.DistributorRef,
		CreateDate		= cs.CreateDate,    -- WI260
		TransactionID	= cs.TransactionID,     -- WI260
		ABCValue		= CASE                     --Ticket125091: MPC 06/10/2011
							when isnull(ph.LeagueIncludeFlag,'N') = 'Y' then isnull(cs.ABCValue,0.0) --Ticket125091: MPC 06/10/2011
							else 0.0               --Ticket125091: MPC 06/10/2011
						  END,                     --Ticket125091: MPC 06/10/2011
		--   ABCValue       =  cs.ABCValue,      --PR ABC May 2008    --Ticket125091: MPC 06/10/2011
		ABCRate			= CASE                     --Ticket125091: MPC 06/10/2011
							when isnull(ph.LeagueIncludeFlag,'N') = 'Y' then isnull(cs.ABCRate,0.0) --Ticket125091: MPC 06/10/2011
							else 0.0               --Ticket125091: MPC 06/10/2011
		  				  END,                     --Ticket125091: MPC 06/10/2011
		--   ABCRate        =  cs.ABCRate,      --PR ABC May 2008   --Ticket125091: MPC 06/10/2011
		SchemeNum		= cs.SchemeNum,    --PR Mar 2009
		ProductGroup	= case when ph.StructuredProduct = 'Y'       --PR Mar 2009
							then 'Structured' 
							else COALESCE(ph.productgroupname,'Unknown')
						  end,
		--SR371343 AG 30/04/2015 Start
		--ELITE_Points = round(isnull(cs.ELITE_Initial,0)+isnull(cs.ELITE_Ongoing,0)+isnull(cs.ELITE_NSC,0)+isnull(cs.ELITE_OMNIS,0),0)	--SR207107: MPC 11/03/2013	SR271363 AG 12/03/2014
		ELITE_Points	= case when cs.Month >= '2015-02-01'
							then round(isnull(cs.ELITE_Initial,0)+isnull(cs.ELITE_Ongoing,0)+isnull(cs.ELITE_NSC,0)+isnull(cs.ELITE_OMNIS,0),1)	-- AG 05/06/2015
							else round(isnull(cs.ELITE_Initial,0)+isnull(cs.ELITE_Ongoing,0)+isnull(cs.ELITE_NSC,0)+isnull(cs.ELITE_OMNIS,0),0)	-- Original rounding for payments prior to Jan 2015 comm period.
						  end
		--SR371343 AG 30/04/2015 End
from	msit_CommissionStatement cs
		inner join mstt_Agents a on cs.AgentCode = a.Code
		left outer join mstt_producthierarchy ph on ph.productcode = cs.productcode			--Ticket143
		left join ( select PACC_ID, sum(isnull(Agent_Perc,0)) as SumAgentPerc
					from mstt_PaymentsPending 
					where agent_code in (@OpenworkMarginPotCode,@OpenworkBSCPotCode)
					and	AMOUNT > 0
					group by PACC_ID
				 ) as PP_PosPotCodeSplits on PP_PosPotCodeSplits.pacc_ID = cs.expectationid 	
		left join ( select PACC_ID, sum(isnull(Agent_Perc,0)) as SumAgentPerc
					from mstt_PaymentsPending 
					where agent_code in (@OpenworkMarginPotCode,@OpenworkBSCPotCode)
					and	AMOUNT < 0
					group by PACC_ID
				 ) as PP_NegPotCodeSplits on PP_NegPotCodeSplits.pacc_ID = cs.expectationid  
		left join (select	PACC_ID, CONVERT(date,CreateDateTime) as PaymentMatchedDate, MAX(isnull(Agent_Perc,0)) as AdviserSplitPerc
					from	mstt_PaymentsPending
					where	agent_code <> '10002'
					group	by PACC_ID, CONVERT(date,CreateDateTime)
				 ) as AdviserSplit  on  AdviserSplit.PACC_ID = cs.ExpectationID 
									and AdviserSplit.PaymentMatchedDate = cs.CreateDate	-- PaymentDate included to handle backdated agent change (BAC) which does NOT create new expectation records
		left join (Select	Distinct PKID 
					From	owt_TransformationMovements					--MPC:25/01/2010
				   where	DriverTableName = 'sa_swift_S_AGMFIL'		--MPC:25/01/2010
					 and	AdviserListing = 'Y' 						--AG 30/03/2010
				   ) tm on tm.PKID = cs.PendingPaymentID
where	cs.ReportingClassCode = 1
and		cs.OAStatus = 'Valid'											--MPC: 16/04/2008 SR9
and		((@Mode = 'FULL') or (@Mode = 'MOVE' and tm.PKID is not null))	--AG 02/05/2018

select @RowCount = @@rowcount											--MPC:25/01/2010


/******************************************************************************************************************
    If FULL mode, then add the indexes back onto the table
    If MOVE mode, then update the table statistics
******************************************************************************************************************/

IF @Mode = 'FULL'   
BEGIN 

  set @ProcessMessage = @Mode + ' - 03) End INSERT : Count = ' + convert(varchar(10), @RowCount) --MPC:25/01/2010
  exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client  --MPC:25/01/2010

  if indexproperty(object_id('msit_OpenworkAdviserListing'),'IX_msit_OpenworkAdviserListing','IndexID') is null
    CREATE  CLUSTERED  INDEX [IX_msit_OpenworkAdviserListing] ON [dbo].[msit_OpenworkAdviserListing]([BusinessCode], [Month], [Source]) WITH (DATA_COMPRESSION=PAGE) ON [PRIMARY] -- Needs to be first!

  if indexproperty(object_id('msit_OpenworkAdviserListing'),'BusinessCode','IndexID') is null
    CREATE  INDEX [BusinessCode] ON [dbo].[msit_OpenworkAdviserListing]([BusinessCode]) WITH (DATA_COMPRESSION=PAGE) ON [PRIMARY]

  if indexproperty(object_id('msit_OpenworkAdviserListing'),'IX_OpenworkAdviserListing_Month','IndexID') is null
    CREATE  INDEX [IX_OpenworkAdviserListing_Month] ON [dbo].[msit_OpenworkAdviserListing]([Month]) WITH (DATA_COMPRESSION=PAGE) ON [PRIMARY]

  if indexproperty(object_id('msit_OpenworkAdviserListing'),'IX_OpenworkdviserListing_Source','IndexID') is null
    CREATE  INDEX [IX_OpenworkdviserListing_Source] ON [dbo].[msit_OpenworkAdviserListing]([Source]) WITH (DATA_COMPRESSION=PAGE) ON [PRIMARY]

  if indexproperty(object_id('msit_OpenworkAdviserListing'),'IX_OpenworkAdviserListing_Policy','IndexID') is null
    CREATE  INDEX [IX_OpenworkAdviserListing_Policy] ON [dbo].[msit_OpenworkAdviserListing]([Policy]) WITH (DATA_COMPRESSION=PAGE) ON [PRIMARY]

  if indexproperty(object_id('msit_OpenworkAdviserListing'),'IX_OpenworkAdviserListing_alID','IndexID') is null
    CREATE  INDEX [IX_OpenworkAdviserListing_alID] ON [dbo].[msit_OpenworkAdviserListing]([alID]) WITH (DATA_COMPRESSION=PAGE) ON [PRIMARY]

  if indexproperty(object_id('msit_OpenworkAdviserListing'),'IX_OpenworkAdviserListing_TransactionID','IndexID') is null
    CREATE  INDEX [IX_OpenworkAdviserListing_TransactionID] ON [dbo].[msit_OpenworkAdviserListing]([TransactionID]) WITH (DATA_COMPRESSION=PAGE) ON [PRIMARY]

  if indexproperty(object_id('msit_OpenworkAdviserListing'),'IX_OpenworkAdviserListing_SchemeNum','IndexID') is null
    CREATE  INDEX [IX_OpenworkAdviserListing_SchemeNum] ON [dbo].[msit_OpenworkAdviserListing]([SchemeNum]) WITH (DATA_COMPRESSION=PAGE) ON [PRIMARY]  -- PR Mar 2009

  if indexproperty(object_id('msit_OpenworkAdviserListing'),'IX_OpenworkAdviserListing_SourceId','IndexID') is null
    CREATE  INDEX [IX_OpenworkAdviserListing_SourceId] ON [dbo].[msit_OpenworkAdviserListing]([Source],[SourceId]) WITH (DATA_COMPRESSION=PAGE) ON [PRIMARY]  --MPC:25/01/2010

  set @ProcessMessage = @Mode + ' - 04) End CREATE INDEX'							--MPC:25/01/2010
  exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client	--MPC:25/01/2010

END   --@Mode = 'FULL'    --MPC:25/01/2010
ELSE  --@Mode = 'MOVE' 
BEGIN

  set @ProcessMessage = @Mode + ' - 02) End INSERT : Count = ' + convert(varchar(10), @RowCount)
  exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client    

  UPDATE STATISTICS msit_OpenworkAdviserListing

  set @ProcessMessage = @Mode + ' - 03) End UPDATE STATISTICS'						--MPC:25/01/2010
  exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client    --MPC:25/01/2010

END   --@Mode = 'MOVE'

--MPC:25/01/2010  Movements Only - END

/******************************************************************************************************************
    END of PROCESSING
******************************************************************************************************************/

exec msp_ProcessLog @PhaseEnd, @ProcName, null, @Module, @Client    --MPC:25/01/2010;

GO
