create procedure [dbo].[msp_OpenworkBankDetailsPreSwift]
with recompile
as

set dateformat ymd

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : msp_OpenworkBankDetails.sql
-- Owner   : MWA
-- Created : 07/09/2006
--
--########################################################################

-- WI260 Mike Cawood 23/03/2007

-- truncate table msit_OpenworkBankDetails

declare
 @ExtractMonth  DateTime,
 @ExtractMonth2 DateTime,
 @CurrentMonth  DateTime,
 @CurrEndDate   DateTime

-- Determine the Month value for the current month by comparing the PeriodStartDate and todays date.
select
 @ExtractMonth = max([Month])
from
 msit_CommissionStatementPeriods
where
 PeriodEndDate <= getdate()

-- Determine the lowest Month value with 'Y' in the RefreshAccount field.
select
 @ExtractMonth2 = min([Month])
from
  msit_CommissionStatementPeriods
where
 RefreshAccount = 'Y'

-- Compair the two ExtractMonth values and set @ExtractMonth to equal the lowest.
if @ExtractMonth > @ExtractMonth2
begin
 set @ExtractMonth = @ExtractMonth2
end

select
 @CurrentMonth = max([Month])
from
 msit_CommissionStatementPeriods
where
 PeriodStartDate <= getdate()

select
 @CurrEndDate = PeriodEndDate
from
 msit_CommissionStatementPeriods
where
 [Month] = @ExtractMonth

-- SET EXTRACTMONTH FOR TESTING, AS THE DATA IN DEVELOPMENT IS NOT CURRENT
-- set @ExtractMonth = '2006-01-01' -- DEVSQL4

-- Delete each row from msit_OpenworkBankDetails with Month >= ExtractMonth
delete from 
 msit_OpenworkBankDetails
where
 [Month] >= @ExtractMonth
 and Source = 'Openwork 2005'

-- Derive Agent Details
declare @AgentDetails table 
 (
 BusinessCode nvarchar(10), 
 ECode        nvarchar(50), 
 StartDate    datetime, 
 StartMonth datetime
 )

insert into
 @AgentDetails
select
 BusinessCode = CODE,
 ECode        = OSCARAgentPrefix + OSCARAgentSerial + OSCARAgentSuffix,
 StartDate    = case when DateStarted > OSCARDateStarted then OSCARDateStarted
                     else DateStarted
                end,
 StartMonth   = isnull((select max([Month]) from msit_CommissionStatementPeriods where PeriodStartDate <= case when DateStarted > OSCARDateStarted then OSCARDateStarted else DateStarted end), (select min([Month]) from msit_CommissionStatementPeriods))
from 
 mstt_Agents 
where 
 AgentType in (2,46,49)

-- Set the StatDate and StartMonth values equal to 2006-01-01 where StartDates are less than 2006-01-01
-- January 2006 is the default value for business with a StartDate earlier than 2006.
update
 @AgentDetails
set
 StartDate = '2006-01-01'
where
 StartDate < '2006-01-01'

update
 @AgentDetails
set
 StartMonth = (select max([Month]) from msit_CommissionStatementPeriods where PeriodStartDate <= StartDate)
where
 StartMonth < '2006-01-01'


-- Extract Pre_SWIFT Data
insert into
 msit_OpenworkBankDetails
select
 BusinessCode    = FranchiseCode,
 BusinessName    = FranchiseName,
 BusinessECode   = Prefix + Serial + Suffix,
 [Month]         = dateadd(mm, 1, [Month]),
 Source          = 'Openwork 2005',
 Amount          = LedgerValue,
 TranscationDate = LedgerDate,
 PaymentType     = case when SortCode = 0 then 0
                        when SortCode = 2 then 99
                        when LedgerDescription in ('Payment by Direct Credit','DC Payment') then 2
                        else 1
                   end,
 TransactionType = case when SortCode = 0 then 'Opening Balance'
                        when SortCode = 2 then 'Closing Balance'
                        else 'Openwork 2005 Ledger'
                   end,
 Description     = LedgerDescription,
 Notes           = NULL,
 Sequence        = SortSeq,
 TotalType       = case when SortCode = 0 then 0
                        when SortCode = 2 then 9
                        when LedgerDescription in ('Payment by Direct Credit','DC Payment') then 3
                        when LedgerValue > 0 then 2
                        else 1
                   end,
 SortCode        = SortCode,    -- WI260
 Provider  = NULL     -- WI260
from
 mst_NSStatement
where
 OpenworkInd = 'Y' and
 dateadd(mm, 1, [Month]) >= @ExtractMonth

-- Create entry for Pre-Swift transactions where no closing balance is currently displayed
insert into
 msit_OpenworkBankDetails
select 
 BusinessCode    = BusinessCode,
 BusinessName    = BusinessName,
 BusinessECode   = BusinessECode,
 [Month]         = [Month],
 Source          = Source,
 Amount          = Amount,
 TransactionDate = (select PeriodEndDate from msit_CommissionStatementPeriods where [Month] = m.[Month]),
 PaymentType     = 99,
 TransactionType = 'Closing Balance',
 Description     = 'Closing Balance',
 Notes           = NULL,
 Sequence        = 0,
 TotalType       = 9,
 SortCode        = 2,     -- WI260
 Provider  = NULL     -- WI260
from 
 msit_OpenworkBankDetails m
where 
 Source = 'Openwork 2005' and 
 not exists (select NULL from msit_OpenworkBankDetails where BusinessCode = m.BusinessCode and [Month] = m.[Month] and Source = 'Openwork 2005' and PaymentType = 99)

-- Round the amounts to 2dp
update
 msit_OpenworkBankDetails
set
 Amount = round(Amount,2)


GO
/****** Object:  StoredProcedure [dbo].[msp_OpenworkBankDetailsSwift]    Script Date: 7/3/2026 3:44:25 PM ******/
