CREATE procedure [dbo].[msp_OpenworkBankDetailsSwift]
with recompile
as

set dateformat ymd

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : msp_OpenworkBankDetails.sql
-- Owner   : MWA
-- Created : 07/09/2006
--
--########################################################################

-- CHANGE LOG

-- WI260 Mike Cawood 23/03/2007

-- WI287 Mike Cawood 22/06/2007 (Ensure Tran Date format ccyy/mm/dd)

-- Mike Cawood 12/09/2007
-- Override TransactionDate (to 11 Sep 2007) for Swift Payments to Bank dated 10 Sep 2007
-- Production Issue caused by BACS run being triggered a day early
-- PR Nov 2007 - Changes for BI Datawarehouse cleanup project

--Mike Cawood 16/04/2008 
--SR9 - Only include Entries where OAStatus = 'Valid'

--PR 25/6/2009
--Added an extra condition of Source = Openwork 2006 when inserting the second set of 
--Opening Balance records

--Mike Cawood 07/07/2009
--Replace =* and *= ANSI JOINS as these not allowed in SQL Server 2005

--Mike Cawood 21/07/2009
--Fix Prod Issue on Opening Balances where Payments found for month earlier than StartMonth

--Stephen Lancaster 20/08/2025
--Fix to correct rounding issue, as payment to 4 decimal places and credit rounded to 2 making the closing balance incorrect (change R347882)

--########################################################################

--truncate table msit_OpenworkBankDetails

declare
 @ExtractMonth  DateTime,
 @ExtractMonth2 DateTime,
 @CurrentMonth  DateTime,
 @CurrEndDate   DateTime

-- Determine the Month value for the current month by comparing the PeriodStartDate and todays date.
select
 @ExtractMonth = max([Month])
from
 msit_CommissionStatementPeriods
where
 PeriodEndDate <= getdate()

-- Determine the lowest Month value with 'Y' in the RefreshAccount field.
select
 @ExtractMonth2 = min([Month])
from
  msit_CommissionStatementPeriods
where
 RefreshAccount = 'Y'

-- Compair the two ExtractMonth values and set @ExtractMonth to equal the lowest.
if @ExtractMonth > @ExtractMonth2
begin
 set @ExtractMonth = @ExtractMonth2
end

select
 @CurrentMonth = max([Month])
from
 msit_CommissionStatementPeriods
where
 PeriodStartDate <= getdate()

select
 @CurrEndDate = PeriodEndDate
from
 msit_CommissionStatementPeriods
where
 [Month] = @ExtractMonth

-- SET EXTRACTMONTH FOR TESTING, AS THE DATA IN DEVELOPMENT IS NOT CURRENT
-- set @ExtractMonth = '2006-01-01' -- DEVSQL4

-- Delete each row from msit_OpenworkBankDetails with Month >= ExtractMonth
delete from 
 msit_OpenworkBankDetails
where
 [Month] >= @ExtractMonth
 and Source = 'Openwork 2006'

-- Derive Agent Details
declare @AgentDetails table 
 (
 BusinessCode nvarchar(10), 
 ECode        nvarchar(10),     --MPC: 07/07/2009
 StartDate    datetime, 
 StartMonth   datetime,
 NewBusiness  nvarchar(1)     --MPC: 07/07/2009
 )

insert into
 @AgentDetails
select
 BusinessCode = CODE,
 ECode        = OSCARAgentPrefix + OSCARAgentSerial + OSCARAgentSuffix,
 StartDate    = case when DateStarted > OSCARDateStarted then OSCARDateStarted
                     else DateStarted
                end,
 StartMonth   = isnull((select max([Month]) from msit_CommissionStatementPeriods 
            where PeriodStartDate <= case when DateStarted > OSCARDateStarted then OSCARDateStarted 
                            else DateStarted end), (select min([Month]) from msit_CommissionStatementPeriods)), --MPC: 07/07/2009
 NewBusiness  = NULL    --MPC: 07/07/2009
from 
 mstt_Agents 
where 
 AgentType in (2,46,49)

-- Set the StatDate and StartMonth values equal to 2006-01-01 where StartDates are less than 2006-01-01
-- January 2006 is the default value for business with a StartDate earlier than 2006.
update
 @AgentDetails
set
 StartDate = '1 Jan 2006'   --MPC: 07/07/2009
where
 StartDate < '1 Jan 2006'   --MPC: 07/07/2009

update
 @AgentDetails
set
 StartMonth = (select max([Month]) from msit_CommissionStatementPeriods where PeriodStartDate <= StartDate)
where
 StartMonth < '1 Jan 2006'    --MPC: 07/07/2009

-- Extract SWIFT data
insert into
 msit_OpenworkBankDetails
select
 BusinessCode    = cs.BusinessCode,
 BusinessName    = cs.FranchiseName,
 BusinessECode   = ad.ECode,
 [Month]         = cs.[Month],
 Source          = 'Openwork 2006',
 Amount          = case when cs.ReportingClassCode = 4 then cs.Amount * -1
                        else cs.Amount
                   end,
 TransactionDate = CAST(CONVERT(NVARCHAR, cs.CreateDate, 112) AS DATETIME),   --WI287
 PaymentType     = case when cs.ReportingClassCode = 4 then 2
                        when cs.CommissionType = 8     then 3
                        when cs.CommissionType = 14    then 4
                        else 5
                   end,
 TransactionType = case when cs.ReportingClassCode = 4 then cs.ReportingClassDesc
                        when cs.CommissionType = 8     then 'Standing Order'
                        when cs.CommissionType = 14    then 'Telegraphic Transfer'
                        else 'Adjustment'
                   end,
 Description     = case when cs.ReportingClassCode = 4 then cs.ReportingClassDesc
                        when cs.CommissionType = 3     then 'Agent Adjustment'
                        when cs.CommissionType = 8     then 'Standing Order: ' + substring(cs.StandingOrderDesc,1,239)  -- WI260
                        when cs.CommissionType = 14    then 'Telegraphic Transfer'
                        when cs.CommissionType = 20    then 'Bonus Payment'
                        when cs.CommissionType = 21    then 'Mortgage Early Payment'
                        else 'Manual Adjustment'
                   end,
 Notes           = case when cs.CommissionType = 8 and cs.StandingOrderDesc <> cs.StandingOrderText then cs.StandingOrderText   -- WI260
       when cs.CommissionType <> 8 then cs.StandingOrderDesc              -- WI260
       else NULL                          -- WI260
       end,                           -- WI260
 Sequence        = NULL,
 TotalType       = case when cs.ReportingClassCode = 4 then 3
                        when cs.Amount >= 0            then 2
                        else 1
                   end,
 SortCode        = 1,   -- WI260
 Provider  = NULL   -- WI260
from
 msit_CommissionStatement cs                      --MPC: 07/07/2009
 left outer join @AgentDetails ad                   --MPC: 07/07/2009
    on cs.BusinessCode = ad.BusinessCode              --MPC: 07/07/2009
--    on cs.BusinessCode collate Database_Default = ad.BusinessCode --MPC: 07/07/2009
where
-- cs.BusinessCode collate Database_Default  *= ad.BusinessCode and   --MPC: 07/07/2009
 ReportingClassCode                        <> 1               and
 [Month]                                   >= @ExtractMonth   and   --MPC: 16/04/2008 SR9
 cs.OAStatus = 'Valid'                          --MPC: 16/04/2008 SR9

-- Extract Non-SWIFT data

-- Determine each entries type
declare @Type table 
 (
 BusinessCode nvarchar(7),
 BusinessName nvarchar(255), 
 [Month]      DateTime, 
-- Type         smallint,
 ProviderName nvarchar(255),
 ProviderCode nvarchar(15), -- WI260
 Amount       float, 
 Base         float, 
 Uplift       float
 )

insert into
 @Type
select
 BusinessCode = BusinessCode,
 BusinessName = FranchiseName,
 [Month]      = [Month],
-- Type         = case when CommissionType in (1,2,17)   then 1
--                     when CommissionType in (4,15,18)  then 4
--                     when CommissionType in (10,16,19) then 10
--                end,
 ProviderName = ProviderName,
 ProviderCode = ProviderCode, 
 --Amount       = round(Amount,2),
 Amount		  = Amount,
 Base         = BaseAmount,
 Uplift       = UpliftAmount
from
 msit_CommissionStatement
where
 ReportingClassCode = 1   and
 [Month] >= @ExtractMonth and --MPC: 16/04/2008 SR9
 OAStatus = 'Valid'     --MPC: 16/04/2008 SR9

-- Group Commission Payment entries by type and total amounts
declare @TypeGroup table 
 (
 BusinessCode nvarchar(7),
 BusinessName nvarchar(255), 
 [Month]      DateTime, 
-- Type         smallint, 
 ProviderName nvarchar(255),
 ProviderCode nvarchar(15),   -- WI260
 Amount       float, 
 Base         float, 
 Uplift       float, 
 [Count]      int
 )

insert into
 @TypeGroup
select
 BusinessCode = BusinessCode,
 BusinessName = BusinessName,
 [Month]      = [Month],
-- Type         = Type,
 ProviderName = ProviderName,
 ProviderCode = ProviderCode,
 Amount       = sum(Amount),
 Base         = sum(Base),
 Uplift       = sum(Uplift),
 [Count]      = count(*)
from
 @Type
group by
 BusinessCode,
 BusinessName,
 [Month],
 --Type
 ProviderCode,
 ProviderName

-- If Count > 0
insert into
 msit_OpenworkBankDetails
select
 BusinessCode    = tg.BusinessCode,
 BusinessName    = tg.BusinessName,
 BusinessECode   = ad.ECode,
 [Month]         = tg.[Month],
 Source          = 'Openwork 2006',
 Amount          = tg.Amount,
-- TransactionDate = case when getdate() < @CurrEndDate then getdate()
--                        else @CurrEndDate
--                   end,
 TransactionDate = (select case when getdate() > c.PeriodEndDate then c.PeriodEndDate      --WI287
        else CAST(CONVERT(NVARCHAR, getdate(), 112) AS DATETIME) end     --WI287
        from msit_CommissionStatementPeriods c where c.[Month] = tg.[Month]),  --WI287
 PaymentType     = 90,
 TransactionType = 'Commission Accrual',
 Description     = 'Commission Accrual' + ' - ' + tg.ProviderName,
 Notes           = case when tg.[Count] = 1 then '1 payment in period'      -- WI260
      else cast(tg.[Count] as varchar(20)) + ' payments in period'  -- WI260
       end,                 -- WI260
 Sequence        = NULL,
 TotalType       = case when tg.Amount >= 0 then 2
                        else 1
                   end,
 SortCode        = 1,             -- WI260
 Provider  = tg.ProviderCode          -- WI260
from
 @TypeGroup tg                  --MPC: 07/07/2009
 left outer join @AgentDetails ad       --MPC: 07/07/2009
    on tg.BusinessCode = ad.BusinessCode  --MPC: 07/07/2009
where
-- tg.BusinessCode *= ad.BusinessCode and   --MPC: 07/07/2009
-- tg.Type          = 1               and
 tg.[Count]       > 0               

-- If Type = 1 and Count > 0
--insert into
-- msit_OpenworkBankDetails
--select
-- BusinessCode    = tg.BusinessCode,
-- BusinessName    = tg.BusinessName,
-- BusinessECode   = ad.ECode,
-- [Month]         = tg.[Month],
-- Source          = 'Openwork 2006',
-- Amount          = tg.Uplift,
---- TransactionDate = case when getdate() < @CurrEndDate then getdate()
----                        else @CurrEndDate
----                   end,
-- TransactionDate = (select case when getdate() > c.PeriodEndDate then c.PeriodEndDate else getdate() end from msit_CommissionStatementPeriods c where c.[Month] = tg.[Month]),
-- PaymentType     = 90,
-- TransactionType = 'Commission Accrual',
-- Description     = 'IC Uplift Accrual',
-- Notes           = NULL,
-- Sequence        = NULL,
-- TotalType       = case when tg.Uplift >= 0 then 2
--                        else 1
--                   end,
-- SortCode        = 1
--from
-- @AgentDetails            ad,
-- @TypeGroup               tg
--where
-- tg.BusinessCode *= ad.BusinessCode and
-- tg.Type          = 1               and
-- tg.[Count]       > 0

-- If Type = 4 and Count > 0
--insert into
-- msit_OpenworkBankDetails
--select
