-- If Type = 10 and Count > 0
--insert into
-- msit_OpenworkBankDetails
--select
-- BusinessCode    = tg.BusinessCode,
-- BusinessName    = tg.BusinessName,
-- BusinessECode   = ad.ECode,
-- [Month]         = tg.[Month],
