---- TransactionDate = case when getdate() < @CurrEndDate then getdate()
----                        else @CurrEndDate
----                   end,
-- TransactionDate = (select case when getdate() > c.PeriodEndDate then c.PeriodEndDate else getdate() end from msit_CommissionStatementPeriods c where c.[Month] = tg.[Month]),
-- PaymentType     = 90,
-- TransactionType = 'Commission Accrual',
-- Description     = 'Trail Fees',
-- Notes           = NULL,
-- Sequence        = NULL,
-- TotalType       = case when tg.Amount >= 0 then 2
--                        else 1
--                   end,
-- SortCode        = 1
--from
-- @AgentDetails            ad,
-- @TypeGroup               tg
--where
-- tg.BusinessCode *= ad.BusinessCode and
-- tg.Type          = 10              and
-- tg.[Count]       > 0

-- MPC: 21/07/2009 - START of CODE
-- Derive earliest Month of the transactions stored for each Business 
-- Reset StartMonth in @AgentDetails if Earliest Transaction Month predates StartMonth

Select BusinessCode,Min(Month) as FirstTranMonth
into #FirstTranMonth
from msit_OpenworkBankDetails
where Source = 'Openwork 2006'
group by BusinessCode
order by BusinessCode

update 
  @AgentDetails
set
  StartMonth = t2.FirstTranMonth
from @AgentDetails t1
inner join #FirstTranMonth t2 
  on t1.BusinessCode = t2.BusinessCode
where t1.StartMonth > t2.FirstTranMonth

drop table #FirstTranMonth
-- MPC: 21/07/2009 - END of CODE

-- Calculate opening and closing balances for subsequent daily overnight refresh
-- Use previous months closing balance if exists to generate opening balance

-- Set the innital @CurrentExtractMonth value to equal the @ExtractMonth.
 declare
  @CurrentExtractMonth DateTime
 set
  @CurrentExtractMonth = @ExtractMonth 

-- Compare the @CurrentExtractMonth value to @CurrentMonth in order to ensure all months 
-- are individually extracted between @ExtractMonth to @CurrentMonth.
 while @CurrentExtractMonth <= @CurrentMonth
 begin

-- Insert Opening Balances where previous records exist in the table
-- Uses the previous months closing balance to generate the opening balance value.
  insert into
   msit_OpenworkBankDetails
  select
   BusinessCode    = BusinessCode,
   BusinessName    = BusinessName,
   BusinessECode   = BusinessECode,
   [Month]         = dateadd(mm, 1, [Month]),
   Source          = Source,
   Amount          = isnull(Amount,0),
   TransactionDate = (select PeriodStartDate from msit_CommissionStatementPeriods where [Month] = dateadd(mm, 1, m.[Month])),
   PaymentType     = 0,
   TransactionType = 'Opening Balance',
   Description     = 'Opening Balance',
   Notes           = NULL,
   Sequence        = NULL,
   TotalType       = 0,
   SortCode        = 0,     -- WI260
   Provider    = NULL   -- WI260
  from
   msit_OpenworkBankDetails m
  where
   [Month]      = dateadd(mm, -1, @CurrentExtractMonth) and
   PaymentType  = 99                                    and
   Source       = 'Openwork 2006'

option (maxdop 1)

  declare @PeriodStartDate datetime                           --MPC: 07/07/2009
  set @PeriodStartDate = (select PeriodStartDate from msit_CommissionStatementPeriods --MPC: 07/07/2009 
                where [Month] = @CurrentExtractMonth)             --MPC: 07/07/2009
  declare @PeriodEndDate datetime                           --MPC: 21/07/2009
  set @PeriodEndDate = (select PeriodEndDate from msit_CommissionStatementPeriods   --MPC: 21/07/2009 
              where [Month] = @CurrentExtractMonth)             --MPC: 21/07/2009

-- Identify new Businesses where an Opening Balance needs to be created
  select distinct BusinessCode                  --MPC: 07/07/2009
  into #OpeningBalanceList                  --MPC: 07/07/2009
  from msit_OpenworkBankDetails                 --MPC: 07/07/2009
  where Month   = @CurrentExtractMonth            --MPC: 07/07/2009
  and   PaymentType = 0                     --MPC: 07/07/2009
  and   Source    = 'Openwork 2006'             --MPC: 07/07/2009

-- Refresh New Business flag on Agent Details data
  update                                    --MPC: 07/07/2009
  @AgentDetails                               --MPC: 07/07/2009
  set                                     --MPC: 07/07/2009
    NewBusiness = (case when @CurrentExtractMonth = ad.StartMonth       --MPC: 07/07/2009
            and m.BusinessCode is NULL then 'Y' else 'N' end)   --MPC: 07/07/2009
  from @AgentDetails ad                             --MPC: 07/07/2009
  left outer join #OpeningBalanceList m                     --MPC: 07/07/2009
    on m.BusinessCode  = ad.BusinessCode                  --MPC: 07/07/2009

-- Insert Opening where no previous records exist for the business code
-- Generates a Opening balance of 0.0 for each new entry.
  insert into
   msit_OpenworkBankDetails
  select distinct
--   BusinessCode    = isnull(m.BusinessCode,ad.BusinessCode),          --MPC: 07/07/2009
--   BusinessName    = isnull(m.BusinessName,isnull(a.TradingName,a.Descn)),  --MPC: 07/07/2009
--   BusinessECode   = isnull(m.BusinessECode,ad.ECode),            --MPC: 07/07/2009
   BusinessCode    = ad.BusinessCode,                     --MPC: 07/07/2009
   BusinessName    = isnull(a.TradingName,a.Descn),               --MPC: 07/07/2009
   BusinessECode   = ad.ECode,                          --MPC: 07/07/2009
   [Month]         = @CurrentExtractMonth,
   Source          = 'Openwork 2006',
   Amount          = 0.0,
   TransactionDate = (case 
            when isnull(ad.StartDate,'1 Jan 2006') > @PeriodEndDate then @PeriodEndDate   --MPC: 21/07/2009
            when isnull(ad.StartDate,'1 Jan 2006') > @PeriodStartDate then ad.StartDate   --MPC: 07/07/2009
            else @PeriodStartDate end ),  
   PaymentType     = 0,
   TransactionType = 'Opening Balance',
   Description     = 'Opening Balance',
   Notes           = NULL,
   Sequence        = NULL,
   TotalType       = 0,
   SortCode        = 0,   -- WI260
   Provider    = NULL -- WI260
  from
   @AgentDetails ad                             --MPC: 07/07/2009
--  left outer join msit_OpenworkBankDetails m                --MPC: 07/07/2009
--    on m.BusinessCode  = ad.BusinessCode                --MPC: 07/07/2009
--    on m.BusinessCode  collate Database_Default = ad.BusinessCode   --MPC: 07/07/2009
   inner join mstt_Agents a                         --MPC: 07/07/2009
    on a.Code = ad.BusinessCode                     --MPC: 07/07/2009
--    on a.Code = isnull(m.BusinessCode,ad.BusinessCode)          --MPC: 07/07/2009
--    on ad.BusinessCode collate Database_Default = a.Code        --MPC: 07/07/2009
  where
     ad.NewBusiness  = 'Y'                          --MPC: 07/07/2009
--   m.BusinessCode  collate Database_Default =* ad.BusinessCode and    --MPC: 07/07/2009
--   ad.BusinessCode collate Database_Default = a.Code           and    --MPC: 07/07/2009
--   Source                 = 'Openwork 2006'  and              --MPC: 07/07/2009
--   @CurrentExtractMonth   = ad.StartMonth    and              --MPC: 07/07/2009
--   not exists (select NULL from msit_OpenworkBankDetails          --MPC: 07/07/2009
--         where BusinessCode = m.BusinessCode and [Month] = m.[Month] and PaymentType = 0)

-- Reset New Business ready for next month
  update              --MPC: 07/07/2009
  @AgentDetails         --MPC: 07/07/2009
  set               --MPC: 07/07/2009
    NewBusiness = 'N'       --MPC: 07/07/2009

  drop table #OpeningBalanceList  --MPC: 07/07/2009

-- Insert Closing Balances where previous records exist in the table
-- Sums all transactions for each BusinessCode for @CurrentExtractMonth, including Opening Balance entries.
  insert into
   msit_OpenworkBankDetails
  select
   BusinessCode    = BusinessCode,
   BusinessName    = BusinessName,
   BusinessECode   = BusinessECode,
   [Month]         = [Month],
   Source          = Source,
   --Amount          = isnull((select sum(Amount) from msit_OpenworkBankDetails where BusinessCode = m.BusinessCode and [Month] = m.[Month] and Source = m.Source),0),
   Amount          = round(isnull((select sum(Amount) from msit_OpenworkBankDetails where BusinessCode = m.BusinessCode and [Month] = m.[Month] and Source = m.Source),0),4),
   TransactionDate = (select PeriodEndDate from msit_CommissionStatementPeriods where [Month] = m.[Month]),
   PaymentType     = 99,
   TransactionType = 'Closing Balance',
   Description     = 'Closing Balance',
   Notes           = NULL,
   Sequence        = NULL,
   TotalType       = 9,
   SortCode        = 2,   -- WI260
   Provider    = NULL -- WI260
  from
   msit_OpenworkBankDetails m
  where
   [Month] = @CurrentExtractMonth and
   Source  = 'Openwork 2006'
  group by
   BusinessCode,
   BusinessName,
   BusinessECode,
   [Month],
   Source

-- Add one month to @CurrentExtractMonth in order to extract the following months data
  set @CurrentExtractMonth = dateadd(mm, 1, @CurrentExtractMonth)
 end

