-- Mike Cawood 12 Sep 2007
-- Override TransactionDate (to 11 Sep 2007) for Swift Payments to Bank dated 10 Sep 2007
-- Production Issue caused by BACS run being triggered a day early

Update msit_openworkbankdetails
set transactiondate = '11 sep 2007'
from msit_openworkbankdetails
where source = 'openwork 2006' and totaltype = 3 and sortcode = 1
and transactiondate = '10 sep 2007'


