CREATE PROCEDURE [dbo].[msp_PopulateDashboard] -- WITH RECOMPILE,ENCRYPTION
  /* Param List */
AS
/*************************************************************************
*****
Copyright (C) Moore Stephens Consulting Limited 2005
Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>

CHANGE HISTORY

Date		WHO			WHAT
05/07/2012	A Harrison	Cater for Divide by zero issue (startdate same as leavingdate on mstt_agents when 
						a sale is in the msft_sales table).

*******************************************************************************/
truncate table mst_dashboard
-- Turnover Written Actuals
insert into mst_Dashboard(
 KPIName,
 OrderBy,
 agentcode,
 AdviserId,
 ComparisonId,
 YTD,
 YTDP,
 ActualThisMonth,
 ActualThisMonthPY
)
select
 KPIName = 'Turnover Written', 
 OrderBy = 2,
 s.AgentCode as AgentCode, 
 s.AdviserId as AdviserId,
 '-999' as ComparisonId,
 sum(case when a.[Year] = year(dateadd(mm,-1,getdate())) and a.[Month] >= '01' and a.[Month] <= month(dateadd(mm,-1,getdate())) then
      s.turnover
 else 0
 end) as YTD,
 sum(case when a.[Year] = year(dateadd(yy,-1,getdate())) and a.[Month] >= '01' and a.[Month] <= month(dateadd(mm,-1,getdate())) then
      s.turnover
 else 0
 end) as YTDP,
 sum(case when a.[Month] = month(getdate()) and a.[Year] = year(getdate()) then
     s.turnover
 else 0
 end) as ActualThisMonth,
 sum(case when a.[Month] = month(getdate()) and a.[Year] = year(dateadd(yy,-1,getdate())) then
     s.turnover
 else 0
 end) as ActualThisMonthPY
from
 msft_sales s,
(
select
 DateId,
 YearMonth [WrittenDate],
 [Month],
 [Year]
from
 msdt_CalendarTime
where
 entrytypeid = 1
) a
where
 s.ComparisonId  = '1' and
 s.DateWrittenId = a.DateId and
 s.BusinessTypeId = 1
group by
 AgentCode,
 AdviserId
-- Turnover Issued Actuals
insert into mst_Dashboard(
