 sum(case when a.[Year] = year(dateadd(mm,-1,getdate())) and a.[Month] >= '01' and a.[Month] <= month(dateadd(mm,-1,getdate())) then
      s.turnover
 else 0
 end) as YTD,
 sum(case when a.[Year] = year(dateadd(yy,-1,getdate())) and a.[Month] >= '01' and a.[Month] <= month(dateadd(mm,-1,getdate())) then
      s.turnover
 else 0
 end) as YTDP,
 sum(case when a.[Month] = month(getdate()) and a.[Year] = year(getdate()) then
     s.turnover
 else 0
