-- Turnover Issued Targets
insert into mst_Dashboard(
 KPIName,
 OrderBy,
 agentcode,
 AdviserId,
 ComparisonId,
 TargetThisMonth,
 TargetLastMonth
)
select
 KPIName = 'Turnover Issued', 
 OrderBy = 1,
 s.AgentCode as AgentCode, 
 s.AdviserId as AdviserId,
 s.ComparisonId as ComparisonId,
 sum(case when a.[Month] = month(getdate()) and a.[Year] = year(getdate()) then
     s.turnover
 else 0
 end) as TargetThisMonth,
 sum(case when a.[Year] = year(getdate()) and a.[Month] >= '01' and a.[Month] <= month(dateadd(mm,-1,getdate())) then
      s.turnover
 else 0
 end) as TargetLastMonth
from
 msft_sales s,
(
select
 DateId,
 YearMonth [IssuedDate],
 [Month],
 [Year]
from
 msdt_CalendarTime
where
 entrytypeid = 2
) a
where
 s.ComparisonId  <> '1' and
 s.DateIssuedId = a.DateId and
 s.BusinessTypeId = 2
group by
 AgentCode,
 AdviserId,
 ComparisonId
