-- Counts - Franchise - Targets
insert into mst_Dashboard(
 KPIName,
 OrderBy,
 AgentCode,
 AdviserId,
 ComparisonId,
 TargetThisMonth,
 TargetLastMonth
)
select
 KPIName = 'Number of Franchises', 
 OrderBy = 9,
 case when TargetRevision like 'Company%' then 'EXEC_DUMMY_CODE'
  when TargetRevision like 'Area%' then cast(SwiftASMAgentID as varchar(50))+'_ASM_DUMMY_CODE'
  when TargetRevision like 'Region%' then cast(SwiftRSMAgentID as varchar(50))+'_RSM_DUMMY_CODE'
  else null end as AgentCode,
 -99 as AdviserId,
 ComparisonId,
 sum(case when targetmonth = month(getdate()) and targetyear = year(getdate()) then
 Franchises 
 else 0
 end) as TargetThisMonth,
  sum(case when month(getdate()) = 1 then 
  case when targetmonth = 12 and targetyear = year(dateadd(yy,-1,getdate())) then Franchises else 0 end
  else 
  case when targetmonth = month(dateadd(mm,-1,getdate())) and targetyear = year(getdate()) then Franchises else 0 end
  end) as TargetLastMonth
from
 mstt_targetcompany
group by
 ComparisonId,
 TargetRevision,
 SwiftASMAgentId,
 SwiftRSMAgentId
update d
set AdviserId = ad.AdviserId
from mst_Dashboard d
  inner join msdt_AdviserDummiesHistory ad
    on d.AgentCode = ad.AgentCode
where KPIName = 'Number of Franchises'
and ad.IsCurrent = 1
