-- Recruits Appointed - target
insert into mst_Dashboard(
 KPIName,
 OrderBy,
 Area,
 ComparisonId,
 TargetThisMonth,
 TargetLastMonth
)
select
 KPIName = 'Recruits (Advisers Appointed) YTD', 
 OrderBy = 13,
 rs.AreaSalesManager as Area,
 ComparisonId,
 sum(case when month(r.PeriodStart) = month(getdate()) and year(r.PeriodStart) = year(getdate()) then
 r.numberRecruits
 else 0
 end) as TargetThisMonth,
  sum(case when month(r.PeriodStart) >= '01' and month(r.PeriodStart) <= month(dateadd(mm,-1,getdate())) and year(r.PeriodStart) = year(getdate()) then
 r.numberRecruits
 else 0
 end) as TargetLastMonth
from
 msft_recruitment r,
 msdt_recruits rs
where
 r.ComparisonId <> '1' and
 r.RecruitStatus = 'APPS' and
 r.RecruitId = rs.RecruitId
group by
 r.ComparisonId,
 rs.AreaSalesManager
