declare @AdviserCapacitySecondLastDate datetime
set @AdviserCapacitySecondLastDate = (select max(StatusDate) from msft_CapacityTerminationCounts
          where Level = 'Adviser' and
          ReportType = 'Capacity' and
          Comparison = 'Actual'
          and StatusDate < (select max(StatusDate) from msft_CapacityTerminationCounts
          where Level = 'Adviser' and
          ReportType = 'Capacity' and
          Comparison = 'Actual'))
--Number of Advisers - Actuals
insert into mst_Dashboard(
 KPIName,
 OrderBy,
 AgentCode,
 AdviserId,
 ComparisonId,
 YTD,
 YTDP,
 ActualThisMonth,
 ActualThisMonthPY
)
select
 KPIName = 'Number of Advisers',
 OrderBy = 10,
 AgentCode as AgentCode,
 AdviserId as AdviserId,
 '-999' as ComparisonId,
 sum(--case when month(getdate()) = 1 then 
  --case when year(StatusDate) = year(dateadd(yy,-1,getdate())) and month(StatusDate) = 12 then Val else 0 end
  --else
  case when year(StatusDate) = year(@AdviserCapacitySecondLastDate) and month(statusDate) = month(@AdviserCapacitySecondLastDate) then Val else 0 end
  --end
  ) as YTD,
 sum(case when month(getdate()) = 1 then 
  case when year(StatusDate) = year(dateadd(yy,-2,getdate())) and month(StatusDate) = 12 then Val else 0 end
  else
  case when year(StatusDate) = year(dateadd(yy,-1,@AdviserCapacitySecondLastDate)) and month(statusDate) = month(@AdviserCapacitySecondLastDate) then Val else 0 end
  end) as YTDP,
 sum(case when month(StatusDate) = month(getdate()) and year(StatusDate) = year(getdate()) then
     Val
 else 0
 end) as ActualThisMonth,
 sum(case when month(StatusDate) = month(getdate()) and year(StatusDate) = year(dateadd(yy,-1,getdate())) then
     Val
 else 0
 end) as ActualThisMonthPY 
from
 msft_capacityterminationcounts a
where
Level = 'Adviser' and
ReportType = 'Capacity' and
ComparisonId = '1'
group by
AgentCode,
AdviserId
--Number of Leavers - Advisers - Actuals
insert into mst_Dashboard(
 KPIName,
 OrderBy,
 AgentCode,
 AdviserId,
 ComparisonId,
 YTD,
 YTDP,
 ActualThisMonth,
 ActualThisMonthPY
)
select
 KPIName = 'Number of Leavers - Advisers',
 OrderBy = 12,
 AgentCode as AgentCode,
 AdviserId as AdviserId,
 '-999' as ComparisonId,
 sum(case when month(getdate()) = 1 then 
  case when year(StatusDate) = year(dateadd(yy,-1,getdate())) then Val else 0 end
  else
  case when year(StatusDate) = year(getdate()) and month(statusDate) between 1 and month(dateadd(mm,-1,getdate())) then Val else 0 end
  end) as YTD,
 sum(case when month(getdate()) = 1 then 
  case when year(StatusDate) = year(dateadd(yy,-2,getdate())) then Val else 0 end
  else
  case when year(StatusDate) = year(dateadd(yy,-1,getdate())) and month(statusDate) between 1 and month(dateadd(mm,-1,getdate())) then Val else 0 end
  end) as YTDP,
 sum(case when month(StatusDate) = month(getdate()) and year(StatusDate) = year(getdate()) then
     Val
 else 0
 end) as ActualThisMonth,
 sum(case when month(StatusDate) = month(getdate()) and year(StatusDate) = year(dateadd(yy,-1,getdate())) then
     Val
 else 0
 end) as ActualThisMonthPY 
from
 msft_capacityterminationcounts a
where
Level = 'Adviser' and
ReportType = 'Terminations' and
ComparisonId = '1'
group by
AgentCode,
AdviserId
--Recruits still active after 12 months - Actuals
insert into mst_Dashboard(
 KPIName,
 OrderBy,
 Area,
 ComparisonId,
 YTD,
 YTDP
)
select
 KPIName = 'Recruits still active after 12 months',
 OrderBy = 15,
 rs.AreaSalesManager as Area,
 '-999' as ComparisonId,
sum(case when r.PeriodStart >= dateadd(mm,-12,getdate()) and r.PeriodStart <= getdate() then
  r.NumberRecruits
 else 0
 end) as YTD,
sum(case when r.PeriodStart >= dateadd(mm,-24,getdate()) and r.PeriodStart <= dateadd(mm,-12,getdate()) then
  r.NumberRecruits
 else 0
 end) as YTDP
from
 msft_recruitment r,
 msdt_recruits rs
where
 r.RecruitStatus = 'APPS' and
 r.ComparisonId = '1' and
 r.recruitid = rs.recruitid
group by 
 rs.AreaSalesManager
