 sum(case when month(getdate()) = 1 then 
  case when year(StatusDate) = year(dateadd(yy,-2,getdate())) and month(StatusDate) = 12 then Val else 0 end
  else
  case when year(StatusDate) = year(dateadd(yy,-1,@FranchiseCapacitySecondLastDate)) and month(statusDate) = month(@FranchiseCapacitySecondLastDate) then Val else 0 end
  end) as YTDP,
 sum(case when month(StatusDate) = month(getdate()) and year(StatusDate) = year(getdate()) then
     Val
 else 0
 end) as ActualThisMonth,
 sum(case when month(StatusDate) = month(getdate()) and year(StatusDate) = year(dateadd(yy,-1,getdate())) then
     Val
 else 0
 end) as ActualThisMonthPY 
from
 msft_capacityterminationcounts a
where
a.Level = 'Franchise' and
a.ReportType = 'Capacity' and
ComparisonId = '1'
group by
AgentCode,
AdviserId
select
 distinct RegionalSalesManagerCode , 1 as RSMCount
into
 #RSM
from 
 msdt_adviser
declare  @RSMTotal int
set @RSMTotal = (select sum(RSMCount) from #RSM )
--Franchises / RSM Ratio - Actuals
insert into mst_Dashboard(
 KPIName,
 OrderBy,
 AgentCode,
 AdviserId,
 ComparisonId,
 YTD,
 YTDP,
 ActualThisMonth
)
select
 KPIName = 'Franchise / RSM Ratio',
 OrderBy = 18,
 AgentCode as AgentCode,
 AdviserId as AdviserId,
 '-999' as ComparisonId,
 sum(case when year(a.StatusDate) = year(dateadd(mm,-1,getdate())) and month(a.StatusDate) >= '01' and month(a.StatusDate) <= month(dateadd(mm,-1,getdate())) then
      Val
 else 0
 end) / @RSMTotal as YTD,
 sum(case when year(a.StatusDate) = year(dateadd(yy,-1,getdate())) and month(a.StatusDate) >= '01' and month(a.StatusDate) <= month(dateadd(mm,-1,getdate())) then
      Val
 else 0
 end) / @RSMTotal as YTDP,
 sum(case when month(a.StatusDate) = month(getdate()) and year(a.StatusDate) = year(dateadd(mm,-1,getdate())) then
     Val
 else 0
 end) / @RSMTotal as ActualThisMonth
from
 msft_capacityterminationcounts a
where
 a.Level = 'Franchise' and
 a.ReportType = 'Capacity' and
ComparisonId = '1'
group by
AgentCode,
AdviserId
--Number of Leavers - Franchises - Actuals
insert into mst_Dashboard(
 KPIName,
 OrderBy,
 AgentCode,
 AdviserId,
 ComparisonId,
 YTD,
 YTDP,
 ActualThisMonth,
 ActualThisMonthPY
)
select
 KPIName = 'Number of Leavers - Franchises',
 OrderBy = 11,
 AgentCode as AgentCode,
 AdviserId as AdviserId,
 '-999' as ComparisonId,
 sum(case when month(getdate()) = 1 then 
  case when year(StatusDate) = year(dateadd(yy,-1,getdate())) then Val else 0 end
  else
  case when year(StatusDate) = year(getdate()) and month(statusDate) between 1 and month(dateadd(mm,-1,getdate())) then Val else 0 end
  end) as YTD,
 sum(case when month(getdate()) = 1 then 
  case when year(StatusDate) = year(dateadd(yy,-2,getdate())) then Val else 0 end
  else
  case when year(StatusDate) = year(dateadd(yy,-1,getdate())) and month(statusDate) between 1 and month(dateadd(mm,-1,getdate())) then Val else 0 end
  end) as YTDP,
 sum(case when month(StatusDate) = month(getdate()) and year(StatusDate) = year(getdate()) then
     Val
 else 0
 end) as ActualThisMonth,
 sum(case when month(StatusDate) = month(getdate()) and year(StatusDate) = year(dateadd(yy,-1,getdate())) then
     Val
 else 0
 end) as ActualThisMonthPY 
from
 msft_capacityterminationcounts a
where
Level = 'Franchise' and
ReportType = 'Terminations' and
ComparisonId = '1'
group by
AgentCode,
AdviserId
--Average Productivity - Franchise - Actuals
insert into mst_Dashboard(
 KPIName,
 OrderBy,
 AgentCode,
 AdviserId,
 ComparisonId,
 YTD,
 YTDP
)
select
 KPIName = 'Average Productivity - Franchise', 
 OrderBy = 16,
 s.AgentCode as AgentCode, 
 s.AdviserId as AdviserId,
 '-999' as ComparisonId,
 (sum(case when a.[Year] = year(dateadd(mm,-1,getdate())) and a.[Month] >= '01' and a.[Month] <= month(dateadd(mm,-1,getdate())) then
      s.turnover
 else 0
 end) / 
(case when
     (case when (b.Datestarted = '2005-06-01 00:00:00.000' and b.OscarDateStarted is not null) then b.OscarDateStarted 
           else b.Datestarted
           end)   
      <  (convert(nvarchar(4),year(dateadd(mm,-1,getdate())),112) + '01' + '01' )
then 1 --0 MK: This used to say ZERO, and was causing divide by zero errors
else datediff(dd,(case when (b.Datestarted = '2005-06-01 00:00:00.000' and b.OscarDateStarted is not null) then b.OscarDateStarted 
           else b.Datestarted
           end),getdate())
      end) * 365) as YTD,
 (sum(case when a.[Year] = year(dateadd(yy,-1,getdate())) and a.[Month] >= '01' and a.[Month] <= month(dateadd(yy,-1,getdate())) then
      s.turnover
 else 0
 end) / 
 (case when
     (case when (b.Datestarted = '2005-06-01 00:00:00.000' and b.OscarDateStarted is not null) then b.OscarDateStarted 
           else b.Datestarted
           end)   
      <  (convert(nvarchar(4),year(dateadd(mm,-1,getdate())),112) + '01' + '01' )
then 1 --0 MK: This used to say ZERO, and was causing divide by zero errors 
else datediff(dd,(case when (b.Datestarted = '2005-06-01 00:00:00.000' and b.OscarDateStarted is not null) then b.OscarDateStarted 
           else b.Datestarted
           end),getdate())
      end) * 365) as YTDP
from
 msft_sales s,
 mstt_agents b,
(
select
 DateId,
 YearMonth [IssuedDate],
 [Month],
 [Year]
from
 msdt_CalendarTime
where
 entrytypeid = 2
) a
where
 s.ComparisonId  = '1' and
 s.DateIssuedId = a.DateId and
 s.AgentCode = b.Code and
 s.BusinessTypeId = 2 --and
 --b.CompetentStatus = 1 and
 --b.givesadvice = 'Y' and
 --b.AgentType in (4, 43, 51)
group by
 AgentCode,
 AdviserId,
 b.OscarDateStarted,
 b.DateStarted
--Average Productivity - Adviser - Actuals
insert into mst_Dashboard(
 KPIName,
 OrderBy,
 AgentCode,
 AdviserId,
 ComparisonId,
 YTD,
 YTDP
)
select
 KPIName = 'Average Productivity - Adviser', 
 OrderBy = 17,
 s.AgentCode as AgentCode, 
 s.AdviserId as AdviserId,
 '-999' as ComparisonId,
 (sum(case when a.[Year] = year(dateadd(mm,-1,getdate())) and a.[Month] >= '01' and a.[Month] <= month(dateadd(mm,-1,getdate())) then
      s.turnover
 else 0
 end) / 
(case when
     (case when (b.Datestarted = '2005-06-01 00:00:00.000' and b.OscarDateStarted is not null) 
      then b.OscarDateStarted 
      else b.Datestarted
      end)   
      <  (convert(nvarchar(4),year(dateadd(mm,-1,getdate())),112) + '01' + '01' )
 then a.DayOfYear --0 MK: This used to say ZERO, and was causing divide by zero errors --KS:Used to say 1, but changed to Day Number of Year
 when (case when (b.Datestarted = '2005-06-01 00:00:00.000' and b.OscarDateStarted is not null) 
      then b.OscarDateStarted 
      else b.Datestarted
      end)   
      <  (convert(nvarchar(4),year(dateadd(mm,-1,getdate())),112) + '01' + '01' ) and 
      b.DateLeaving > (convert(nvarchar(4),year(dateadd(mm,-1,getdate())),112) + '01' + '01' )
 then datediff(dd,(convert(nvarchar(4),year(dateadd(mm,-1,getdate())),112) + '01' + '01' ),b.DateLeaving)
 when (case when (b.Datestarted = '2005-06-01 00:00:00.000' and b.OscarDateStarted is not null) 
      then b.OscarDateStarted 
      else b.Datestarted
      end)   
      >  (convert(nvarchar(4),year(dateadd(mm,-1,getdate())),112) + '01' + '01' ) and 
      b.DateLeaving > (convert(nvarchar(4),year(dateadd(mm,-1,getdate())),112) + '01' + '01' )
 then datediff(dd,(case when (b.Datestarted = '2005-06-01 00:00:00.000' and b.OscarDateStarted is not null) then b.OscarDateStarted 
                       else b.Datestarted
                       end),b.DateLeaving)
 else datediff(dd,(case when (b.Datestarted = '2005-06-01 00:00:00.000' and b.OscarDateStarted is not null) then b.OscarDateStarted 
                       else b.Datestarted
                       end),getdate())
 end) 
 / a.DayOfYear * 365) as YTD,
 (sum(case when a.[Year] = year(dateadd(yy,-1,getdate())) and a.[Month] >= '01' and a.[Month] <= month(dateadd(yy,-1,getdate())) then
      s.turnover
 else 0
 end) / 
 (case when
     (case when (b.Datestarted = '2005-06-01 00:00:00.000' and b.OscarDateStarted is not null) 
      then b.OscarDateStarted 
      else b.Datestarted
      end)   
      <  (convert(nvarchar(4),year(dateadd(mm,-1,getdate())),112) + '01' + '01' )
  then a.DayOfYear --0 MK: This used to say ZERO, and was causing divide by zero errors -- KS:Used to say 1 but changed to Day Number of Year
  when (case when (b.Datestarted = '2005-06-01 00:00:00.000' and b.OscarDateStarted is not null) 
      then b.OscarDateStarted 
      else b.Datestarted
      end)   
      <  (convert(nvarchar(4),year(dateadd(mm,-1,getdate())),112) + '01' + '01' ) and 
      b.DateLeaving > (convert(nvarchar(4),year(dateadd(mm,-1,getdate())),112) + '01' + '01' )
  then datediff(dd,(convert(nvarchar(4),year(dateadd(mm,-1,getdate())),112) + '01' + '01' ),b.DateLeaving)
 when (case when (b.Datestarted = '2005-06-01 00:00:00.000' and b.OscarDateStarted is not null) 
      then b.OscarDateStarted 
      else b.Datestarted
      end)   
      >  (convert(nvarchar(4),year(dateadd(mm,-1,getdate())),112) + '01' + '01' ) and 
      b.DateLeaving > (convert(nvarchar(4),year(dateadd(mm,-1,getdate())),112) + '01' + '01' )
 then datediff(dd,(case when (b.Datestarted = '2005-06-01 00:00:00.000' and b.OscarDateStarted is not null) then b.OscarDateStarted 
                       else b.Datestarted
                       end),b.DateLeaving)
  else datediff(dd,(case when (b.Datestarted = '2005-06-01 00:00:00.000' and b.OscarDateStarted is not null) then b.OscarDateStarted 
                       else b.Datestarted
                       end),getdate())
 end)
 / a.DayOfYear * 365) as YTDP
from
 msft_sales s,
 mstt_agents b,
(
select
 DateId,
 DayOfYear,
 YearMonth [IssuedDate],
 [Month],
 [Year]
from
 msdt_CalendarTime
where
 entrytypeid = 2
) a
where
 s.ComparisonId  = '1' 
and s.DateIssuedId = a.DateId 
and s.AgentCode = b.Code 
and s.BusinessTypeId = 2 
and datediff(dd,b.datestarted,b.dateleaving) <> 0 --AH 5Jul2012 - divide by zero error (start/leave dates same and entry in sales table)    
--  and b.CompetentStatus = 1 
--  and b.givesadvice = 'Y' 
--  and b.AgentType in (4, 43, 51)  -- KS:Can not filter on Appointed advisers only as need to determineProductive days for terminated advisers
group by
 AgentCode,
 AdviserId,
 b.OscarDateStarted,
 b.DateStarted,
 a.DayOfYear,
 b.DateLeaving
update mst_dashboard
set
ProjectedThisMonth = (ActualThisMonth/(case when day(getdate()) = 1 then day(getdate()) else (day(getdate()))-1 end)) * 30
where
 KPIName in ('Turnover Issued', 'Turnover Written', 'Applications Issued', 'Applications Written', 'NTU Cases')
update mst_dashboard
set
ProjectedThisMonth = 0
where
 KPIName in ('Applications Pipeline', 'Turnover Pipeline', 'Number of Franchises', 'Number of Advisers', 'Number of Leavers - Franchises', 'Number of Leavers - Advisers', 'Recruits (Advisers Appointed) - YTD', 'Recruits (Advisers) in Pipeline', 'Recruits Still Active After 12 Months')


