CREATE PROCEDURE [dbo].[msp_PopulateDefaultDates] -- WITH RECOMPILE,ENCRYPTION
  /* Param List */
AS
/******************************************************************************
Copyright (C) Moore Stephens Consulting Limited 2005
Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>
*******************************************************************************/
/**** THIS PROCEDURE ONLY NEEDS TO BE RUN ONCE ****/
--Force a record for Unknown with -99 id
SET IDENTITY_INSERT msdt_calendartime ON
declare 
  @DefaultDateWrittenID     int,
  @DateWrittenEntryTypeId     int,
  @DefaultDateWritten     datetime,
  @DefaultDateIssuedID      int,
  @DateIssuedEntryTypeId      int,
  @DefaultDateIssued      datetime,
  @DefaultTerminatedDateID    int,
  @TerminatedDateEntryTypeId    int,
  @DefaultTerminatedDate      datetime,
  @DefaultDateAppointedID     int,
  @DateAppointedEntryTypeId   int,
  @DefaultDateAppointed     datetime,
  @DefaultPreAppointedDateID    int,
  @PreAppointedDateEntryTypeId    int,
  @DefaultPreAppointedDate    datetime,
  @DefaultTransactionDateID   int,
  @TransactionDateEntryTypeId   int,
  @DefaultTransactionDate     datetime,
  @DefaultRecPeriodStartDateID    int,
  @RecPeriodStartDateEntryTypeId    int,
  @DefaultRecPeriodStartDate    datetime
set @DefaultDateWrittenID  = (select convert(int,DefaultValue) from mstt_DefaultCodeValues where codecolumn = 'DateWrittenID')
set @DateWrittenEntryTypeId  = (select EntryTypeId from mst_DateTimeControl where EntryType = 'DateWritten')
set @DefaultDateWritten    = (select DefaultValue from mstt_DefaultCodeValues where codecolumn = 'DateWritten')
set @DefaultDateIssuedID   = (select convert(int,DefaultValue) from mstt_DefaultCodeValues where codecolumn = 'DateIssuedID')
set @DateIssuedEntryTypeId   = (select EntryTypeId from mst_DateTimeControl where EntryType = 'DateIssued')
set @DefaultDateIssued     = (select DefaultValue from mstt_DefaultCodeValues where codecolumn = 'DateIssued')
set @DefaultTerminatedDateID   = (select convert(int,DefaultValue) from mstt_DefaultCodeValues where codecolumn = 'TerminatedDateID')
set @TerminatedDateEntryTypeId   = (select EntryTypeId from mst_DateTimeControl where EntryType = 'TerminatedDate')
set @DefaultTerminatedDate       = (select DefaultValue from mstt_DefaultCodeValues where codecolumn = 'TerminatedDate')
set @DefaultDateAppointedID  = (select convert(int,DefaultValue) from mstt_DefaultCodeValues where codecolumn = 'DateAppointedID')
set @DateAppointedEntryTypeId  = (select EntryTypeId from mst_DateTimeControl where EntryType = 'DateAppointed')
set @DefaultDateAppointed  = (select DefaultValue from mstt_DefaultCodeValues where codecolumn = 'DateAppointed')
set @DefaultPreAppointedDateID   = (select convert(int,DefaultValue) from mstt_DefaultCodeValues where codecolumn = 'PreAppointedDateID')
set @PreAppointedDateEntryTypeId = (select EntryTypeId from mst_DateTimeControl where EntryType = 'PreAppointedDate')
set @DefaultPreAppointedDate     = (select DefaultValue from mstt_DefaultCodeValues where codecolumn = 'PreAppointedDate')
set @DefaultTransactionDateID  = @DefaultDateIssuedID
set @TransactionDateEntryTypeId  = (select EntryTypeId from mst_DateTimeControl where EntryType = 'TransactionDate')
set @DefaultTransactionDate      = @DefaultDateIssued
set @DefaultRecPeriodStartDateID  = @DefaultDateIssuedID
set @RecPeriodStartDateEntryTypeId  = (select EntryTypeId from mst_DateTimeControl  where EntryType = 'RecPeriodStartDate')
set @DefaultRecPeriodStartDate    = @DefaultDateIssued
--DateWritten
insert into msdt_calendartime ( DateID, EntryTypeId, DateTime,
        Day, YearMonthDay,DayOfWeek,
        DayOfYear,BDayOfYear,Week,
        BWeek,Month,BMonth,
        YearMonth,BYearMonth,BYearMonthD,
        Quarter,BQuarter,YearQuarter,
        BYearQuarter,BYearQuarterD,Year,
        BYear,BYearD,AggType) 
      values (@DefaultDateWrittenID, @DateWrittenEntryTypeId, @DefaultDateWritten, '00', '00000000', '0', '0', '0', '0', '0', '0', '0', '000000', '000000', 'Unknown', '00', '00', '000000', '000000', 'Unknown', '0000', '0000', 'Unknown', 'Period')
--DateIssued
insert into msdt_calendartime ( DateID, EntryTypeId, DateTime,
        Day, YearMonthDay,DayOfWeek,
        DayOfYear,BDayOfYear,Week,
        BWeek,Month,BMonth,
        YearMonth,BYearMonth,BYearMonthD,
        Quarter,BQuarter,YearQuarter,
        BYearQuarter,BYearQuarterD,Year,
        BYear,BYearD,AggType) 
      values (@DefaultDateIssuedID, @DateIssuedEntryTypeId, @DefaultDateIssued, '00', '00000000', '0', '0', '0', '0', '0', '0', '0', '000000', '000000', 'Unknown', '00', '00', '000000', '000000', 'Unknown', '0000', '0000', 'Unknown', 'Period')
--TerminatedDate
insert into msdt_calendartime ( DateID, EntryTypeId, DateTime,
        Day, YearMonthDay,DayOfWeek,
        DayOfYear,BDayOfYear,Week,
        BWeek,Month,BMonth,
        YearMonth,BYearMonth,BYearMonthD,
        Quarter,BQuarter,YearQuarter,
        BYearQuarter,BYearQuarterD,Year,
        BYear,BYearD,AggType) 
      values (@DefaultTerminatedDateID, @TerminatedDateEntryTypeId, @DefaultTerminatedDate, '00', '00000000', '0', '0', '0', '0', '0', '0', '0', '000000', '000000', 'Unknown', '00', '00', '000000', '000000', 'Unknown', '0000', '0000', 'Unknown', 'Period')
--DateAppointed
insert into msdt_calendartime ( DateID, EntryTypeId, DateTime,
        Day, YearMonthDay,DayOfWeek,
        DayOfYear,BDayOfYear,Week,
        BWeek,Month,BMonth,
        YearMonth,BYearMonth,BYearMonthD,
        Quarter,BQuarter,YearQuarter,
        BYearQuarter,BYearQuarterD,Year,
        BYear,BYearD,AggType) 
      values (@DefaultDateAppointedID, @DateAppointedEntryTypeId, @DefaultDateAppointed, '00', '00000000', '0', '0', '0', '0', '0', '0', '0', '000000', '000000', 'Unknown', '00', '00', '000000', '000000', 'Unknown', '0000', '0000', 'Unknown', 'Period')
--PreAppointedDate
insert into msdt_calendartime ( DateID, EntryTypeId, DateTime,
        Day, YearMonthDay,DayOfWeek,
        DayOfYear,BDayOfYear,Week,
        BWeek,Month,BMonth,
        YearMonth,BYearMonth,BYearMonthD,
        Quarter,BQuarter,YearQuarter,
        BYearQuarter,BYearQuarterD,Year,
        BYear,BYearD,AggType) 
      values (@DefaultPreAppointedDateID,@PreAppointedDateEntryTypeId, @DefaultPreAppointedDate, '00', '00000000', '0', '0', '0', '0', '0', '0', '0', '000000', '000000', 'Unknown', '00', '00', '000000', '000000', 'Unknown', '0000', '0000', 'Unknown', 'Period')
--TransactionDate
insert into msdt_calendartime ( DateID, EntryTypeId, DateTime,
        Day, YearMonthDay,DayOfWeek,
        DayOfYear,BDayOfYear,Week,
        BWeek,Month,BMonth,
        YearMonth,BYearMonth,BYearMonthD,
        Quarter,BQuarter,YearQuarter,
        BYearQuarter,BYearQuarterD,Year,
        BYear,BYearD,AggType) 
      values (@DefaultTransactionDateID,@TransactionDateEntryTypeId, @DefaultTransactionDate, '00', '00000000', '0', '0', '0', '0', '0', '0', '0', '000000', '000000', 'Unknown', '00', '00', '000000', '000000', 'Unknown', '0000', '0000', 'Unknown', 'Period')
--RecPeriodStartDateDate
insert into msdt_calendartime ( DateID, EntryTypeId, DateTime,
        Day, YearMonthDay,DayOfWeek,
        DayOfYear,BDayOfYear,Week,
        BWeek,Month,BMonth,
        YearMonth,BYearMonth,BYearMonthD,
        Quarter,BQuarter,YearQuarter,
        BYearQuarter,BYearQuarterD,Year,
        BYear,BYearD,AggType) 
      values (@DefaultRecPeriodStartDateID,@RecPeriodStartDateEntryTypeId, @DefaultRecPeriodStartDate, '00', '00000000', '0', '0', '0', '0', '0', '0', '0', '000000', '000000', 'Unknown', '00', '00', '000000', '000000', 'Unknown', '0000', '0000', 'Unknown', 'Period')      
SET IDENTITY_INSERT msdt_calendartime OFF
GRANT EXEC ON msp_PopulateDefaultDates TO PUBLIC

