CREATE PROCEDURE [dbo].[msp_PopulateFranchiseLeagueLastPositionTable] -- WITH RECOMPILE,ENCRYPTION
  /* Param List */
AS
/******************************************************************************
Copyright (C) Moore Stephens Consulting Limited 2005
Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>
*******************************************************************************/
/** THIS NEEDS TO BE RUN ONE-OFF AFTER mstp_PopulateReportingServicesTables is run **/
set dateformat dmy
truncate table mst_FranchiseLeagueLastPosition
insert into mst_FranchiseLeagueLastPosition
select 
 AdviserId,
 ProductId,
 ProductGroup,
 ProductSubGroup,
 SizeId,
 Size,
 DateIssued,
 DateTime, --this is Issued fulldate
 Turnover,
 Franchise,
 Area,
 Region,
 Type,
 PositionThis,
 PositionLast,
 convert(nvarchar(4),year(dateadd(mm,-1,getdate()))) 
  + case when month(dateadd(mm,-1,getdate())) < 10 then '0' else '' end
  + convert(nvarchar(2),month(dateadd(mm,-1,getdate()))) as AsAtYearMonth,
 getdate() as RunDate
from 
 mst_LeagueTables
where
 --Issued business that fell in the previous month and prior
 [DateTime] <  convert(datetime, convert(nvarchar(4),year(getdate())) 
      + case when month(getdate()) < 10 then '0' else '' end
      + convert(nvarchar(2),month(getdate()))  
      + '01')

