CREATE PROCEDURE [dbo].[msp_PopulateTimeTables] -- WITH RECOMPILE,ENCRYPTION
 @EntryTypeId int,
 @StartDate   datetime,
 @EndDate     datetime,
 @Module    nvarchar(50), 
 @ClientName  nvarchar(20)
AS
/******************************************************************************
Copyright (C) Moore Stephens Consulting Limited 2005
Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>
*******************************************************************************/
begin
 exec msp_ProcessLog 'START', 'Populate Time Tables', NULL, @Module, @ClientName
-- truncate table msdt_CalendarTime
 declare @Day           varchar(2),
         @YearMonthDay  varchar(8),
         @DayOfWeek     varchar(2),
         @DayOfYear     varchar(3),
         @BDayOfYear    varchar(3),
         @Week          varchar(2),
         @BWeek         varchar(2),
         @Month         varchar(2),
         @BMonth        varchar(2),
         @YearMonth     varchar(6),
         @BYearMonth    varchar(6),
         @BYearMonthD   varchar(15),
         @Quarter       varchar(2),
         @BQuarter      varchar(2),
         @YearQuarter   varchar(6),
         @BYearQuarter  varchar(6),
         @BYearQuarterD varchar(15),
         @Year          varchar(4),
         @BYear         varchar(4),
         @BYearD        varchar(15),
         @YearSt        varchar(4), 
         @YearEnd       varchar(4),
         @DaySt         varchar(8),
         @DayEnd        varchar(8),
         @DevDay        varchar(5),
         @DevBDay       varchar(5),
         @DevWeek       varchar(4),
         @DevBWeek      varchar(4),
         @DevMonth      varchar(3),
         @DevBMonth     varchar(3),
         @DevQuarter    varchar(3),
         @DevBQuarter   varchar(3),
         @DevYear       varchar(3),
         @DevBYear      varchar(3),
         @BStartDate    datetime,
         @BStartDate2   datetime
 select @DayEnd    = convert(varchar(8), @EndDate, 112)
 while (@StartDate <= @EndDate)
 begin
  select
   @BStartDate    =  dateadd(dd, case substring(convert(varchar(8), @StartDate, 112), 5, 4)
                                  when '0321' then -48
                                  when '0322' then -48
                                  when '0323' then -48
                                  when '0521' then -50
                                  when '0721' then -50
                                  when '1021' then -50
                                  when '1221' then -50
                                  else -51
                                 end,
                             @StartDate),
   @BStartDate2   = dateadd(dd, -51, @StartDate),
   @Day           = replicate('0', 2-len(day(@StartDate))) + convert(varchar(2), day(@StartDate)),
   @YearMonthDay  = convert(varchar(4), year(@StartDate)) +
                    replicate('0', 2-len(month(@StartDate))) + convert(varchar(2), month(@StartDate)) +
                    replicate('0', 2-len(day(@StartDate))) + convert(varchar(2), day(@StartDate)),
   @DayOfWeek     = datepart(dw, @StartDate),
   @DayOfYear     = datepart(dy, @StartDate),
   @BDayOfYear    = datepart(dy, @BStartDate2),
   @Week          = replicate('0', 2-len(datepart(wk, @StartDate))) + convert(varchar(2), datepart(wk, @StartDate)),
   @BWeek         = replicate('0', 2-len(datepart(wk, @BStartDate2))) + convert(varchar(2), datepart(wk, @BStartDate2)),
   @Month         = replicate('0', 2-len(month(@StartDate))) + convert(varchar(2), month(@StartDate)),
   @BMonth        = replicate('0', 2-len(month(@BStartDate))) + convert(varchar(2), month(@BStartDate)),
   @YearMonth     = convert(varchar(4), year(@StartDate)) +
                    replicate('0', 2-len(month(@StartDate))) + convert(varchar(2), month(@StartDate)),
   @BYearMonth    = convert(varchar(4), year(@BStartDate)) +
                    replicate('0', 2-len(month(@BStartDate))) + convert(varchar(2), month(@BStartDate)),
   @BYearMonthD   = 'As at 20-' + substring(datename(mm, dateadd(mm, 2, @BStartDate)), 1, 3) + '-' +
                    case substring(datename(mm, dateadd(mm, 2, @BStartDate)), 1, 3)
                     when 'Jan' then substring(convert(varchar(4), datepart(yy, dateadd(yy, 1, @BStartDate))), 3, 2)
                     when 'Feb' then substring(convert(varchar(4), datepart(yy, dateadd(yy, 1, @BStartDate))), 3, 2)
                     else substring(convert(varchar(4), datepart(yy, @BStartDate)), 3, 2)
                    end,
   @Quarter       = 'Q' + convert(varchar(1), datepart(qq, @StartDate)),
   @BQuarter      = 'Q' + convert(varchar(1), datepart(qq, @BStartDate)),
   @YearQuarter   = convert(varchar(4), year(@StartDate)) +
                    'Q' + convert(varchar(1), datepart(qq, @StartDate)),
   @BYearQuarter  = convert(varchar(4), year(@BStartDate)) +
                    'Q' + convert(varchar(1), datepart(qq, @BStartDate)),
   @BYearQuarterD = 'As at 20-' + case datepart(qq, @BStartDate)
                                   when 1 then 'May'
                                   when 2 then 'Aug'
                                   when 3 then 'Nov'
                                   else 'Feb'
                                  end + '-' + 
                                  case datepart(qq, @BStartDate)
                                   when 4 then substring(convert(varchar(4), datepart(yy, dateadd(yy, 1, @BStartDate))), 3, 2)
                                   else substring(convert(varchar(4), datepart(yy, @StartDate)), 3, 2)
                                  end,
   @Year          = year(@StartDate),
   @BYear         = year(@BStartDate),
   @BYearD        = 'As at 20-Feb-' + substring(convert(varchar(4), datepart(yy, dateadd(yy, 1, @BStartDate))), 3, 2)
  insert into
   msdt_CalendarTime
   (EntryTypeId, DateTime, Day, YearMonthDay, DayOfWeek, DayOfYear, BDayOfYear, Week, BWeek, Month, BMonth, YearMonth, BYearMonth, BYearMonthD, Quarter, BQuarter, YearQuarter, BYearQuarter, BYearQuarterD, Year, BYear, BYearD, AggType)
  values
   (@EntryTypeId, @StartDate, @Day, @YearMonthDay, @DayOfWeek, @DayOfYear, @BDayOfYear, @Week, @BWeek, @Month, @BMonth, @YearMonth, @BYearMonth, @BYearMonthD, @Quarter, @BQuarter, @YearQuarter, @BYearQuarter, @BYearQuarterD, @Year, @BYear, @BYearD, 'Period')
  select @StartDate = dateadd(day, 1, @StartDate)
 end
 update statistics msdt_CalendarTime
 exec msp_ProcessLog 'END', 'Populate Time Tables', NULL, @Module, @ClientName
end

GO
