CREATE PROCEDURE [dbo].[msp_ProcessLog] -- WITH RECOMPILE,ENCRYPTION
 @Phase         nvarchar(50),
 @Process       nvarchar(100),
 @BRN           nvarchar(8),
 @Module    nvarchar(50),
 @Type          nvarchar(50)
--WITH RECOMPILE --, ENCRYPTION
AS

/******************************************************************************

Copyright (C) Moore Stephens Consulting Limited 2005

Summary : Add process events to Log Table (ProcessLog)
Author  : SSweeney
Created : %DateCreated%  
          
<doc>
  <summary>Add process events to Log Table (ProcessLog)</summary>
  <param name='@Phase'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>

*******************************************************************************/

declare @DtTm      datetime,
        @ProcessId integer

select @DtTm      = getdate(),
       @ProcessId = (select isnull(max(ProcessId), 0) + 1 from mst_ProcessLog)

insert into
 mst_ProcessLog
values
 (@DtTm, @ProcessId, @Phase, @Process, isnull(@BRN, ''), isnull(@Module,''), isnull(@Type, ''))
GO
