CREATE PROCEDURE [dbo].[msp_Production] -- WITH RECOMPILE,ENCRYPTION
  /* Param List */
AS

/******************************************************************************

Copyright (C) Moore Stephens Consulting Limited 2005

Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
          
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>


Date    Author    Description
----------  --------  -----------
15/11/2005  MK      Added several isnulls, -99s, UNKs and Unknowns as there are now
            several columns which do not accept nulls.
10/02/2009  A Groves  Added index creates and drops to check if it improves
            performance of msp_YTDProduction_PopulateCache.
10/07/2009  M Cawood  Replace *= ANSI JOINS as these not allowed in SQL Server 2005
04/07/2011	A Harrison	Removed IX_mst_Production_Compound index as causing batch failures.

*******************************************************************************/

-- AG 10/02/2009 start

declare 
    @PhaseStart   varchar(50),
    @PhaseEnd   varchar(50),
    @Client     varchar(50),
    @Module     varchar(50),
    @Process    varchar(100)
    
set @PhaseStart     = 'START'
set @PhaseEnd       = 'END'
set @Module         = 'msp_Production'
set @Client         = 'Openwork'

set @Process      = '01 Drop mst_Production & Indexes'
exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client


truncate table mst_production


if indexproperty(object_id('mst_Production'),'IX_mst_Production_AdviserId','IndexID') is not null
  DROP INDEX mst_Production.IX_mst_Production_AdviserId

--CH4177
--if indexproperty(object_id('mst_Production'),'IX_mst_Production_Compound','IndexID') is not null
--  DROP INDEX mst_Production.IX_mst_Production_Compound

if indexproperty(object_id('mst_Production'),'IX_mst_Production_Comparison','IndexID') is not null
  DROP INDEX mst_Production.IX_mst_Production_Comparison

if indexproperty(object_id('mst_Production'),'IDX_mst_Production_1','IndexID') is not null
  DROP INDEX mst_Production.IDX_mst_Production_1  -- Clustered index so drop last for efficiency


set @Process      = '02 Insert mst_Production 1'
exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

-- AG 10/02/2009 end

--Select Products and Dummy Products into single list
--MPC: 10/07/2009
select DISTINCT
 ProductId,
 ProductGroupName
into #Products
from
 msdt_Products
union 
select DISTINCT
 ProductId,
 ProductGroupName
from
 msdt_ProductDummies
order by ProductId

--Written Data 
insert into
 mst_production(
 AdviserId,
 AgentCode,
 Adviser,
 Franchise,
 Area,
 Region,
 ProductId, 
 ProductGroup,
 ActiveStatus,
 BusinessTypeId,
 BusinessType,
 DateWritten,
 Turnover,
 Cases,
 DA,
 NBI,
 SalesMargin,
 Comparison
) 
select 
 isnull(a.AdviserId, -99) as AdviserId,
 isnull(a.AgentCode, 'UNK') as AgentCode,
 'Unknown' as Adviser,
 'Yet to be allocated' as Franchise,
 'Yet to be allocated' as Area,
 'Yet to be allocated' as Region,
 -99 as ProductId,
 isnull(p.ProductGroupName, 'Unknown') as ProductGroup,
 isnull(c.CompetentStatus, 1) as ActiveStatus,
 isnull(a.BusinessTypeId, -99) as BusinessTypeId,
 'Unknown' as BusinessType,
 b.YearMonth [WrittenDate],   --MPC: 10/07/2009
 sum(a.Turnover) [Turnover],
 sum(a.Cases) [Cases],
 sum(a.DA) [DA],
 sum(a.NBI) [NBI],
 sum(a.Margin) [SalesMargin],
 isnull(d.Comparison, 'Unknown') as Comparison
from
 msft_Sales a             --MPC: 10/07/2009
 inner join msdt_CalendarTime b     --MPC: 10/07/2009
  on a.DateWrittenId = b.DateId and b.entrytypeid = 1   --MPC: 10/07/2009
 left outer join msdt_Comparison d      --MPC: 10/07/2009
  on a.ComparisonId = d.ComparisonId  --MPC: 10/07/2009
 left outer join mstt_Agents c      --MPC: 10/07/2009
  on a.AgentCode = c.Code       --MPC: 10/07/2009
 left outer join #Products p          --MPC: 10/07/2009
  on a.ProductId = p.ProductId    --MPC: 10/07/2009
where
 a.BusinessTypeId = 1         --MPC: 10/07/2009

/* 
-- CODE REMOVED - START 10/07/2009
(
select
 DateId,
 YearMonth [WrittenDate]
from
 msdt_CalendarTime
where
 entrytypeid = 1
) b,
(
select
 Code,
 CompetentStatus
from
 mstt_Agents
) c,
(
select
 ComparisonId,
 Comparison
from
 msdt_Comparison
) d,
(
select
 ProductId,
 ProductGroupName
from
 msdt_Products
union all 
select
 ProductId,
 ProductGroupName
from
 msdt_ProductDummies
) p
where
 a.DateWrittenId = b.DateId and
 a.AgentCode *= c.Code and
 a.ComparisonId = d.ComparisonId and
 a.ProductId = p.ProductId and
 a.BusinessTypeId = 1
-- CODE REMOVED - END 10/07/2009
*/ 
group by
 a.AdviserId,
 a.AgentCode,
 --a.ProductId,   --removed so that not grouping at lowest level, only need to group by productgroup not productgroupid.
 p.ProductGroupName,
 c.CompetentStatus,
 a.BusinessTypeId,
 b.YearMonth,   --MPC: 10/07/2009
 d.Comparison


set @Process      = '03 Insert mst_Production 2'
exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client


--Issued Data 
insert into
 mst_production(
 AdviserId,
 AgentCode,
 Adviser,
 Franchise,
 Area,
 Region,
 ProductId,
 ProductGroup,
 ActiveStatus,
 BusinessTypeId,
 BusinessType,
 DateIssued,
 Turnover,
 Cases,
 DA,
 NBI,
 SalesMargin,
 Comparison
) 
select 
 isnull(a.AdviserId, -99) as AdviserId,
 isnull(a.AgentCode, 'UNK') as AgentCode,
 'Unknown' as Adviser,
 'Yet to be allocated' as Franchise,
 'Yet to be allocated' as Area,
 'Yet to be allocated' as Region,
 -99 as ProductId, 
 isnull(p.ProductGroupName, 'Unknown') as ProductGroup,
 isnull(c.CompetentStatus, 1) as ActiveStatus,
 isnull(a.BusinessTypeId, -99) as BusinessTypeId,
 'Unknown' as BusinessType,
 b.YearMonth [IssuedDate],        --MPC: 10/07/2009
 sum(a.Turnover) [Turnover],
 sum(a.Cases) [Cases],
 sum(a.DA) [DA],
 sum(a.NBI) [NBI],
 sum(a.Margin) [SalesMargin],
 isnull(d.Comparison, 'Unknown') as Comparison
from
 msft_Sales a             --MPC: 10/07/2009
 inner join msdt_CalendarTime b     --MPC: 10/07/2009
  on a.DateIssuedId = b.DateId and b.entrytypeid = 2    --MPC: 10/07/2009
 left outer join msdt_Comparison d      --MPC: 10/07/2009
  on a.ComparisonId = d.ComparisonId  --MPC: 10/07/2009
 left outer join mstt_Agents c      --MPC: 10/07/2009
  on a.AgentCode = c.Code       --MPC: 10/07/2009
