from
 msft_Sales a             --MPC: 10/07/2009
 inner join msdt_CalendarTime b     --MPC: 10/07/2009
  on a.DateIssuedId = b.DateId and b.entrytypeid = 2    --MPC: 10/07/2009
 left outer join msdt_Comparison d      --MPC: 10/07/2009
  on a.ComparisonId = d.ComparisonId  --MPC: 10/07/2009
 left outer join mstt_Agents c      --MPC: 10/07/2009
  on a.AgentCode = c.Code       --MPC: 10/07/2009
