) d,
(
select
 ProductId,
 ProductGroupName
from
 msdt_Products
union all 
select
 ProductId,
 ProductGroupName
from
 msdt_ProductDummies
) p
where
 a.DateIssuedId = b.DateId and
 a.AgentCode *= c.Code and
 a.ComparisonId = d.ComparisonId and
 a.ProductId = p.ProductId and
 a.BusinessTypeId = 2
-- CODE REMOVED - END 10/07/2009
*/ 
group by
