CREATE PROCEDURE [dbo].[msp_ProductionHistory_CacheWarmer] -- WITH RECOMPILE,ENCRYPTION
    @id int,
    @Measure nvarchar(50),
    @BusinessType nvarchar(50),
    @DateRange nvarchar(50),
    @Comparison nvarchar(50),
    @UserId nvarchar(50)
    
AS

--set @DateRange = 'Last 6 Months'

/******************************************************************************

Copyright (C) Moore Stephens Consulting Limited 2005

Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
          
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>

*******************************************************************************/
-- declare @BusinessType nvarchar(50)
-- set @BusinessType = 'Written'
-- declare @UserId nvarchar(50)
-- set @UserId = 'bi\kstokes'
-- declare @Measure nvarchar(50)
-- set @Measure = 'Turnover'
-- declare @DateRange nvarchar(50)
-- set @DateRange = 'Last 6 Months'
-- declare @id int
-- set @id = 1
-- declare @Comparison varchar(50)
-- set @Comparison = 'Actual'
-- 
-- drop table #mst_matrix

--Issued, Actuals, this year
select 
p.AdviserId,
@id as id,
'Company' as Company,
Area,
Region,
Franchise,
Adviser,
case when ActiveStatus = '1' then 'Y' else 'N' end ActiveStatus,
ProductGroup,
case when @BusinessType = 'Written' then DateWritten else DateIssued end [Period],
case when @BusinessType = 'Written' then DateWritten else DateIssued end [Period2],
case when @Measure = 'Turnover' then sum(p.Turnover) 
when @Measure = 'No. of Cases' then sum(p.Cases)
when @Measure = 'DA' then sum(p.DA)
when @Measure = 'NBI' then sum(p.NBI)
when @Measure = 'Sales Margin' then sum(p.SalesMargin)
else 0 end [Amount]
into #mst_matrix
from 
mst_Production p,
msct_UserAccessControl uac
where 
p.AdviserId = uac.AdviserId and
uac.DomainLogin = @UserId and
p.Comparison = 'Actual' and
     
case when @BusinessType = 'Issued' then p.DateIssued end between
     case when @DateRange = 'Month by Month'  then convert(nvarchar(6),getdate(),112)
          when @DateRange = 'Last 12 Months' then convert(nvarchar(6),dateadd(mm,-13,getdate()),112)
          else convert(nvarchar(6),dateadd(mm,-7,getdate()),112) 
     end and
     convert(nvarchar(6),dateadd(mm,-1,getdate()),112)

group by
p.AdviserId,
Area,
Region,
Franchise,
Adviser,
ActiveStatus,
ProductGroup,
case when @BusinessType = 'Written' then DateWritten else DateIssued end


--Written, Actuals, This Year
insert into #mst_matrix
select 
p.AdviserId,
@id as id,
'Company' as Company,
Area,
Region,
Franchise,
Adviser,
case when ActiveStatus = '1' then 'Y' else 'N' end ActiveStatus,
ProductGroup,
case when @BusinessType = 'Written' then DateWritten else DateIssued end [Period],
case when @BusinessType = 'Written' then DateWritten else DateIssued end [Period2],
case when @Measure = 'Turnover' then sum(p.Turnover) 
when @Measure = 'No. of Cases' then sum(p.Cases)
when @Measure = 'DA' then sum(p.DA)
when @Measure = 'NBI' then sum(p.NBI)
when @Measure = 'Sales Margin' then sum(p.SalesMargin)
else 0 end [Amount]
from 
mst_Production p,
msct_UserAccessControl uac
where 
p.AdviserId = uac.AdviserId and
uac.DomainLogin = @UserId and
p.Comparison = 'Actual' and
case when @BusinessType = 'Written' then p.DateWritten end between
     case when @DateRange = 'Month by Month'  then convert(nvarchar(6),getdate(),112)
          when @DateRange = 'Last 12 Months' then convert(nvarchar(6),dateadd(mm,-13,getdate()),112)
          else convert(nvarchar(6),dateadd(mm,-7,getdate()),112) 
     end and
     convert(nvarchar(6),dateadd(mm,-1,getdate()),112)

group by
p.AdviserId,
Area,
Region,
Franchise,
Adviser,
ActiveStatus,
ProductGroup,
case when @BusinessType = 'Written' then DateWritten else DateIssued end

--Issued, Actuals, YTD
if @BusinessType = 'Issued' 
    
  insert into #mst_matrix
  select 
  p.AdviserId,
  @id as id,
  'Company' as Company,
  Area,
  Region,
  Franchise,
  Adviser,
  case when ActiveStatus = '1' then 'Y' else 'N' end,
  ProductGroup,
  'YTD',
  (year(getdate()) * 100) + 12,
  case when @Measure = 'Turnover' then sum(p.Turnover) 
  when @Measure = 'No. of Cases' then sum(p.Cases)
  when @Measure = 'DA' then sum(p.DA)
  when @Measure = 'NBI' then sum(p.NBI)
  when @Measure = 'Sales Margin' then sum(p.SalesMargin)
  else 0 end [Amount]
  from 
  mst_Production p,
  msct_UserAccessControl uac
  where 
  p.AdviserId = uac.AdviserId and
  uac.DomainLogin = @UserId and
  p.Comparison = 'Actual' and
  case when @BusinessType = 'Written' then left(p.DateWritten,4) else left(p.DateIssued,4) end = year(getdate()) and
  right(case when @BusinessType = 'Written' then p.DateWritten else p.DateIssued end,2) >= '01' and 
  right(case when @BusinessType = 'Issued' then p.DateIssued end,2) < month(getdate())
  group by
  p.AdviserId,
  Area,
  Region,
  Franchise,
  Adviser,
  ActiveStatus,
  ProductGroup

  
else --Written, Actuals, YTD
  
  insert into #mst_matrix
  select 
  p.AdviserId,
  @id as id,
  'Company' as Company,
  Area,
  Region,
  Franchise,
  Adviser,
  case when ActiveStatus = '1' then 'Y' else 'N' end,
  ProductGroup,
  'YTD',
  (year(getdate()) * 100) + 12,
  case when @Measure = 'Turnover' then sum(p.Turnover) 
  when @Measure = 'No. of Cases' then sum(p.Cases)
  when @Measure = 'DA' then sum(p.DA)
  when @Measure = 'NBI' then sum(p.NBI)
  when @Measure = 'Sales Margin' then sum(p.SalesMargin)
  else 0 end [Amount]
  from 
  mst_Production p,
  msct_UserAccessControl uac
  where 
  p.AdviserId = uac.AdviserId and
  uac.DomainLogin = @UserId and
  p.Comparison = 'Actual' and
  case when @BusinessType = 'Written' then left(p.DateWritten,4) else left(p.DateIssued,4) end = year(getdate()) and
  right(case when @BusinessType = 'Written' then p.DateWritten else p.DateIssued end,2) >= '01' and 
  right(case when @BusinessType = 'Written' then p.DateWritten end,2) < month(getdate())
  group by
  p.AdviserId,
  Area,
  Region,
  Franchise,
  Adviser,
  ActiveStatus,
  ProductGroup



if @Comparison = 'Actual'

  begin
  
    declare @CurrentMonthLastYearWeightingFactor float
    set @CurrentMonthLastYearWeightingFactor = 
          (select cast(day(getdate()-1) as Float) / 
            cast((DAY(DATEADD(d, -DAY(DATEADD(m,1,getdate()-1)),DATEADD(m,1,getdate()-1)))) as Float))
            
                --Issued, YTDP
                if @BusinessType = 'Issued' 
                
      insert into #mst_matrix
      select 
      p.AdviserId,
      @id as id,
      'Company' as Company,
      Area,
      Region,
      Franchise,
      Adviser,
      case when ActiveStatus = '1' then 'Y' else 'N' end,
      ProductGroup,
      'YTDP',
      (year(dateadd(yy,-1,getdate())) * 100) + 12,
      --This Pro-rating should not be here, as only completed months are being displayed in
      --the Production History Report.
  --    case when p.DateIssued = convert(nvarchar(6), (year(dateadd(yy,-1,getdate())) * 100) + month(getdate()-1))
  --    then
  --      case when @Measure = 'Turnover' then sum(p.Turnover * @CurrentMonthLastYearWeightingFactor) 
  --      when @Measure = 'No. of Cases' then sum(p.Cases * @CurrentMonthLastYearWeightingFactor)
  --      when @Measure = 'DA' then sum(p.DA * @CurrentMonthLastYearWeightingFactor)
  --      when @Measure = 'NBI' then sum(p.NBI * @CurrentMonthLastYearWeightingFactor)
  --      when @Measure = 'Sales Margin' then sum(p.SalesMargin * @CurrentMonthLastYearWeightingFactor)
  --      else 0 end 
  --    else
      case when @Measure = 'Turnover' then sum(p.Turnover) 
        when @Measure = 'No. of Cases' then sum(p.Cases)
        when @Measure = 'DA' then sum(p.DA)
        when @Measure = 'NBI' then sum(p.NBI)
        when @Measure = 'Sales Margin' then sum(p.SalesMargin)
        else 0 --end
      end [Amount]
      from 
      mst_Production p,
      msct_UserAccessControl uac
      where 
      p.AdviserId = uac.AdviserId and
      uac.DomainLogin = @UserId and
      case when @BusinessType = 'Issued' then p.DateIssued end between
      convert(nvarchar(4),dateadd(yy,-1,getdate()),112) + '01'
      and
      convert(nvarchar(6),dateadd(yy,-1,getdate()),112) -1 and
      Comparison = @Comparison
      group by
      p.AdviserId,
      Area,
      Region,
      Franchise,
      Adviser,
      ActiveStatus,
      ProductGroup,
      DateIssued
      
    else  --Written, YTDP
    
      insert into #mst_matrix
      select 
      p.AdviserId,
      @id as id,
      'Company' as Company,
      Area,
      Region,
      Franchise,
      Adviser,
      case when ActiveStatus = '1' then 'Y' else 'N' end,
      ProductGroup,
      'YTDP',
      (year(dateadd(yy,-1,getdate())) * 100) + 12,
      case when @Measure = 'Turnover' then sum(p.Turnover) 
      when @Measure = 'No. of Cases' then sum(p.Cases)
      when @Measure = 'DA' then sum(p.DA)
      when @Measure = 'NBI' then sum(p.NBI)
      when @Measure = 'Sales Margin' then sum(p.SalesMargin)
      else 0 end [Amount]
      from 
      mst_Production p,
      msct_UserAccessControl uac
      where 
      p.AdviserId = uac.AdviserId and
      uac.DomainLogin = @UserId and
      case when @BusinessType = 'Written' then p.DateWritten end between
      convert(nvarchar(4),dateadd(yy,-1,getdate()),112) + '01'
      and
      convert(nvarchar(6),dateadd(yy,-1,getdate()),112) -1 and
      Comparison = @Comparison
      group by
      p.AdviserId,
      Area,
      Region,
      Franchise,
      Adviser,
      ActiveStatus,
      ProductGroup
  
  end

else 

  begin
                --Issued
                if @BusinessType = 'Issued'
                
      insert into #mst_matrix
      select 
      p.AdviserId,
      @id as id,
      'Company' as Company,
      case when @Comparison like 'Company%' then 'TargetHolder' else p.Area end as Area,
      case when @Comparison like 'Company%' or @Comparison like 'Area%' then 'TargetHolder' else p.Region end as Region,
      case when @Comparison like 'Company%' or @Comparison like 'Area%' or @Comparison like 'Region%' then 'TargetHolder' else p.Franchise end as Franchise,
      case when @Comparison like 'Company%' or @Comparison like 'Area%' or @Comparison like 'Region%' or @Comparison like 'Franchise%' then 'TargetHolder' else p.Adviser end as Adviser,
      case when ActiveStatus = '1' then 'Y' else 'N' end,
      ProductGroup,
      'YTDP',
      (year(dateadd(yy,-1,getdate())) * 100) + 12,
      --This Pro-rating should not be here, as only completed months are being displayed in
      --the Production History Report.
  --    case when p.DateIssued = convert(nvarchar(6), (year(dateadd(yy,-1,getdate())) * 100) + month(getdate()-1))
  --    then
  --      case when @Measure = 'Turnover' then sum(p.Turnover * @CurrentMonthLastYearWeightingFactor) 
  --      when @Measure = 'No. of Cases' then sum(p.Cases * @CurrentMonthLastYearWeightingFactor)
  --      when @Measure = 'DA' then sum(p.DA * @CurrentMonthLastYearWeightingFactor)
  --      when @Measure = 'NBI' then sum(p.NBI * @CurrentMonthLastYearWeightingFactor)
  --      when @Measure = 'Sales Margin' then sum(p.SalesMargin * @CurrentMonthLastYearWeightingFactor)
  --      else 0 end 
  --    else
      case when @Measure = 'Turnover' then sum(p.Turnover) 
        when @Measure = 'No. of Cases' then sum(p.Cases)
        when @Measure = 'DA' then sum(p.DA)
        when @Measure = 'NBI' then sum(p.NBI)
        when @Measure = 'Sales Margin' then sum(p.SalesMargin)
        else 0 --end
      end [Amount]
      from 
      mst_Production p,
      msct_UserAccessControl uac
      where 
      p.AdviserId = uac.AdviserId and
      uac.DomainLogin = @UserId and
      case when @BusinessType = 'Issued' then p.DateIssued end between
      convert(nvarchar(4),dateadd(yy,0,getdate()),112) + '01'
      and
      convert(nvarchar(6),dateadd(yy,0,getdate()),112) - 1 and
      Comparison = @Comparison
      group by
      p.AdviserId,
      Area,
      Region,
      Franchise,
      Adviser,
      ActiveStatus,
      ProductGroup,
      DateIssued
      
    else  --Written
    
      insert into #mst_matrix
      select 
      p.AdviserId,
      @id as id,
      'Company' as Company,
      case when @Comparison like 'Company%' then 'TargetHolder' else p.Area end as Area,
      case when @Comparison like 'Company%' or @Comparison like 'Area%' then 'TargetHolder' else p.Region end as Region,
      case when @Comparison like 'Company%' or @Comparison like 'Area%' or @Comparison like 'Region%' then 'TargetHolder' else p.Franchise end as Franchise,
      case when @Comparison like 'Company%' or @Comparison like 'Area%' or @Comparison like 'Region%' or @Comparison like 'Franchise%' then 'TargetHolder' else p.Adviser end as Adviser,
      case when ActiveStatus = '1' then 'Y' else 'N' end,
      ProductGroup,
      'YTDP',
      (year(dateadd(yy,-1,getdate())) * 100) + 12,
      case when @Measure = 'Turnover' then sum(p.Turnover) 
      when @Measure = 'No. of Cases' then sum(p.Cases)
      when @Measure = 'DA' then sum(p.DA)
      when @Measure = 'NBI' then sum(p.NBI)
      when @Measure = 'Sales Margin' then sum(p.SalesMargin)
      else 0 end [Amount]
      from 
      mst_Production p,
      msct_UserAccessControl uac
      where 
      p.AdviserId = uac.AdviserId and
      uac.DomainLogin = @UserId and
      case when @BusinessType = 'Written' then p.DateWritten end between
      convert(nvarchar(4),dateadd(yy,0,getdate()),112) + '01'
      and
      convert(nvarchar(6),dateadd(yy,0,getdate()),112) - 1 and
      Comparison = @Comparison
      group by
      p.AdviserId,
      Area,
      Region,
      Franchise,
      Adviser,
      ActiveStatus,
      ProductGroup

  end

insert into mst_ProductionHistory_CacheDetail
select
AdviserId,
@id as id,
 'Company' as Company,
 Area,
 Region,
 Franchise,
 Adviser,
 ActiveStatus,
 ProductGroup,
 sum(case when left(Period,3) <> 'YTD' and datediff(mm,convert(datetime,([Period2]) + '01'), convert(datetime,(convert(nvarchar(6),getdate(),112) + '01'))) = '12' then [Amount] else '0' end) '1',
 sum(case when left(Period,3) <> 'YTD' and datediff(mm,convert(datetime,([Period2]) + '01'), convert(datetime,(convert(nvarchar(6),getdate(),112) + '01'))) = '11' then [Amount] else '0' end) '2',
 sum(case when left(Period,3) <> 'YTD' and datediff(mm,convert(datetime,([Period2]) + '01'), convert(datetime,(convert(nvarchar(6),getdate(),112) + '01'))) = '10' then [Amount] else '0' end) '3',
 sum(case when left(Period,3) <> 'YTD' and datediff(mm,convert(datetime,([Period2]) + '01'), convert(datetime,(convert(nvarchar(6),getdate(),112) + '01'))) = '9' then [Amount] else '0' end) '4',
 sum(case when left(Period,3) <> 'YTD' and datediff(mm,convert(datetime,([Period2]) + '01'), convert(datetime,(convert(nvarchar(6),getdate(),112) + '01'))) = '8' then [Amount] else '0' end) '5',
 sum(case when left(Period,3) <> 'YTD' and datediff(mm,convert(datetime,([Period2]) + '01'), convert(datetime,(convert(nvarchar(6),getdate(),112) + '01'))) = '7' then [Amount] else '0' end) '6',
 sum(case when left(Period,3) <> 'YTD' and datediff(mm,convert(datetime,([Period2]) + '01'), convert(datetime,(convert(nvarchar(6),getdate(),112) + '01'))) = '6' then [Amount] else '0' end) '7',
 sum(case when left(Period,3) <> 'YTD' and datediff(mm,convert(datetime,([Period2]) + '01'), convert(datetime,(convert(nvarchar(6),getdate(),112) + '01'))) = '5' then [Amount] else '0' end) '8',
 sum(case when left(Period,3) <> 'YTD' and datediff(mm,convert(datetime,([Period2]) + '01'), convert(datetime,(convert(nvarchar(6),getdate(),112) + '01'))) = '4' then [Amount] else '0' end) '9',
 sum(case when left(Period,3) <> 'YTD' and datediff(mm,convert(datetime,([Period2]) + '01'), convert(datetime,(convert(nvarchar(6),getdate(),112) + '01'))) = '3' then [Amount] else '0' end) '10',
 sum(case when left(Period,3) <> 'YTD' and datediff(mm,convert(datetime,([Period2]) + '01'), convert(datetime,(convert(nvarchar(6),getdate(),112) + '01'))) = '2' then [Amount] else '0' end) '11',
 sum(case when left(Period,3) <> 'YTD' and datediff(mm,convert(datetime,([Period2]) + '01'), convert(datetime,(convert(nvarchar(6),getdate(),112) + '01'))) = '1' then [Amount] else '0' end) '12',
 sum(case when [Period] = 'YTD' then [Amount] else '0' end) 'YTD',
 sum(case when [Period] = 'YTDP' then [Amount] else '0' end) 'YTDP'
from
 #mst_matrix
group by
AdviserId,
 Area,
 Region,
 Franchise,
 Adviser,
 ActiveStatus,
 ProductGroup
order by 
 3,4,6,7,8,9   --AMENDED ORDER TO MIRROR msp_SelectYTDProduction

drop table #mst_matrix






GO
/****** Object:  StoredProcedure [dbo].[msp_ProductionHistory_PopulateCache]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE procedure [dbo].[msp_ProductionHistory_PopulateCache] as 

begin

truncate table mst_ProductionHistory_CacheHeader
truncate table mst_ProductionHistory_CacheDetail

insert into mst_ProductionHistory_CacheHeader
select *
from (  select 'Written' as BusinessType
  union select 'Issued') BusinessType
cross join 
  (select 'Turnover' as Measure
  union select 'DA'
  union select 'No. of Cases'
  union select 'NBI'
  union select 'Sales Margin') Measure
cross join
  (select 'Company' as Comparison
  union select 'Actual') Comparison


declare Executions cursor for
select id, BusinessType, Measure, Comparison
from mst_ProductionHistory_CacheHeader
order by id

declare @id int
declare @BusinessType varchar(20)
declare @Measure varchar(20)
declare @Comparison varchar(20)

open Executions
fetch next from Executions into @id, @BusinessType, @Measure, @Comparison

while @@Fetch_Status = 0

begin

insert into mst_ProductionHistory_CacheDetail
exec msp_ProductionHistory_CacheWarmer
@id,
@Measure,
@BusinessType,
'Last 12 Months',
@Comparison,
'OPENWORK\mitest10'

fetch next from Executions into @id, @BusinessType, @Measure, @Comparison

end

close Executions
deallocate Executions

end



GO
