truncate table mst_Recruitment
insert into mst_Recruitment
select 
 R.AreaSalesManagerCode,
 R.AreaSalesManager,
 R.RegionalSalesManager,
 R.RegionalSalesManagerCode,
 R.FranchiseName,
 R.FranchiseCode,
 R.FranchiseSizeId,
 '',
 R.RecruitName,
 R.RecruitCode,
 R.RecruitId,
 RF.RecruitType,
 RF.RecruitCategory,
 RF.PipeLineStageCode,
 RF.PipeLineStageDescription,
 RF.RecruitStatus,
 RF.RecruitStatusDescription,
