where 
 RF.RecruitId = R.RecruitID and
 RF.ComparisonId = C.ComparisonId and
 C.Comparison = 'Actual' 
 --and RF.RecruitType in ('Franchise','Seller') --not sure, needs confirming
update 
 mst_Recruitment
set
 FranchiseSize = FranchiseSizeType
from
 mst_Recruitment    R,
 msdt_FranchiseSize F
where
 R.FranchiseSizeId = F.FranchiseSizeId

