/****** Object:  StoredProcedure [dbo].[msp_RetrievePDSId]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- msp_RetrievePDSId 'Openwork', 'XML Configuration', null, null, null, null
create procedure [dbo].[msp_RetrievePDSId] 
as
--############################################################################
-- Copyright (c) MOORE STEPHENS CONSULTING LIMITED, 2004 All rights reserved 
-- 
-- Object     : Procedure
-- Name       : msp_RetrievePDSId.sql
-- Description: Retrievs the id for a PDS view
-- Owner      : Ermedin Selmanovic
-- Created    : 24/10/2005
-- 
--############################################################################
--
-- $Id: $
-- $Log: $
--
--############################################################################
declare 
 @Phase          varchar(50),
 @Process        varchar(100),
 @ErrorCode      int,
 @StopProcessing bit,
 @ProcedureName varchar(255),
 @Error         int,
 @Module        varchar(50),
 @Client        varchar(50)
set @ProcedureName = 'msp_RetrievePDSId'
set @Module = 'XML Menu'
set @Client = 'Installer'
set @ErrorCode      = 0
set @StopProcessing = 0 
set @ProcedureName  = object_name(@@procid)
set @Process        = @ProcedureName
set @ProcedureName  = object_name(@@procid)
set @Process        = @ProcedureName
set @Phase          = 'START'
exec msp_ProcessLog @Phase, @ProcedureName, null, @Module, @Client
select vcName, intGAID from ProClarity_PDS..T_GUIDED_ANALYSIS
set @Error = @@Error
 if @Error <> 0
  begin
   set @Phase          = 'ERROR'
   set @ErrorCode      = 1100
   set @Process        = @Process + ': ' + (select [Description] from mst_ErrorCodes ec where ec.ErrorCode = @ErrorCode)
   set @StopProcessing = (select StopProcessing from mst_ErrorCodes ec where ec.ErrorCode = @ErrorCode) 
   exec msp_ProcessLog @Phase, @Process, null, @Module, @Client
  end
 else
  begin
   set @Phase          = 'END'
   exec msp_ProcessLog @Phase, @ProcedureName, null, @Module, @Client
  end

GO
