CREATE PROCEDURE [dbo].[msp_Select1to1Production] -- WITH RECOMPILE,ENCRYPTION
    @BusinessType nvarchar(50),
    @UserId nvarchar(50),
    @Franchise nvarchar(50),
    @Adviser nvarchar(50)
    
AS



/******************************************************************************

Copyright (C) Moore Stephens Consulting Limited 2005

Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
          
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>

*******************************************************************************/


create table #mst_production (
ProductGroupName nvarchar(50) COLLATE Latin1_General_CI_AS NULL,
Cases0 float NULL,
Cases1 float NULL,
Cases2 float NULL,
Cases3 float NULL,
Cases4 float NULL,
Cases5 float NULL,
Cases6 float NULL,
Cases7 float NULL,
Cases8 float NULL,
Cases9 float NULL,
Cases10 float NULL,
Cases11 float NULL,
Cases12 float NULL,
CasesYTDCurrent float NULL,
CasesYTD float NULL,
Turnover0 float NULL,
Turnover1 float NULL,
Turnover2 float NULL,
Turnover3 float NULL,
Turnover4 float NULL,
Turnover5 float NULL,
Turnover6 float NULL,
Turnover7 float NULL,
Turnover8 float NULL,
Turnover9 float NULL,
Turnover10 float NULL,
Turnover11 float NULL,
Turnover12 float NULL,
TurnoverYTDCurrent float NULL,
TurnoverYTD float NULL)




if @BusinessType = 'Written'
begin
insert into #mst_production
select
p.ProductGroupName,
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '12' then [Cases] else '0' end) 'Cases0',
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '11' then [Cases] else '0' end) 'Cases1',
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '10' then [Cases] else '0' end) 'Cases2',
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '9' then [Cases] else '0' end) 'Cases3',
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '8' then [Cases] else '0' end) 'Cases4',
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '7' then [Cases] else '0' end) 'Cases5',
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '6' then [Cases] else '0' end) 'Cases6',
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '5' then [Cases] else '0' end) 'Cases7',
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '4' then [Cases] else '0' end) 'Cases8',
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '3' then [Cases] else '0' end) 'Cases9',
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '2' then [Cases] else '0' end) 'Cases10',
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '1' then [Cases] else '0' end) 'Cases11',
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '0' then [Cases] else '0' end) 'Cases12',
sum(case when d.DateTime between convert(nvarchar(4), year(getdate()),112) + '01' + '01' and (convert(nvarchar(6),getdate(),112)) then [Cases] else '0' end) 'CasesYTDCurrent',
sum(case when d.DateTime >= convert(nvarchar(4), year(getdate()),112) + '01' + '01' and d.DateTime < (convert(nvarchar(6),getdate(),112))+'01' then [Cases] else '0' end) 'CasesYTD',
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '12' then [Turnover] else '0' end) 'Turnover0',
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '11' then [Turnover] else '0' end) 'Turnover1',
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '10' then [Turnover] else '0' end) 'Turnover2',
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '9' then [Turnover] else '0' end) 'Turnover3',
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '8' then [Turnover] else '0' end) 'Turnover4',
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '7' then [Turnover] else '0' end) 'Turnover5',
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '6' then [Turnover] else '0' end) 'Turnover6',
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '5' then [Turnover] else '0' end) 'Turnover7',
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '4' then [Turnover] else '0' end) 'Turnover8',
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '3' then [Turnover] else '0' end) 'Turnover9',
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '2' then [Turnover] else '0' end) 'Turnover10',
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '1' then [Turnover] else '0' end) 'Turnover11',
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '0' then [Turnover] else '0' end) 'Turnover12',
sum(case when d.DateTime between convert(nvarchar(4), year(getdate()),112) + '01' + '01' and (convert(nvarchar(6),getdate(),112)) then [Turnover] else '0' end) 'TurnoverYTDCurrent',
sum(case when d.DateTime >= convert(nvarchar(4), year(getdate()),112) + '01' + '01' and d.DateTime < (convert(nvarchar(6),getdate(),112))+'01' then [Turnover] else '0' end) 'TurnoverYTD'
from
msft_sales s,
msdt_Adviser a,
msdt_products p,
msdt_calendartime d,
msct_UserAccessControl uac
where
s.Productid = p.productId and
s.BusinessTypeid = 1 and
s.ComparisonId = 1 and
s.datewrittenid = d.dateid and
s.datewrittenid <> '-99' and
s.AdviserId = uac.AdviserId and
uac.DomainLogin = @UserId and
s.AdviserId = a.AdviserId and
left(rtrim(a.Franchise),45) = @Franchise and
left(rtrim(a.Adviser),45) = @Adviser
group by
d.yearmonth,
p.productgroupname
end
else

begin
insert into #mst_production
select
p.ProductGroupName,
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '12' then [Cases] else '0' end) 'Cases0',
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '11' then [Cases] else '0' end) 'Cases1',
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '10' then [Cases] else '0' end) 'Cases2',
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '9' then [Cases] else '0' end) 'Cases3',
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '8' then [Cases] else '0' end) 'Cases4',
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '7' then [Cases] else '0' end) 'Cases5',
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '6' then [Cases] else '0' end) 'Cases6',
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '5' then [Cases] else '0' end) 'Cases7',
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '4' then [Cases] else '0' end) 'Cases8',
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '3' then [Cases] else '0' end) 'Cases9',
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '2' then [Cases] else '0' end) 'Cases10',
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '1' then [Cases] else '0' end) 'Cases11',
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '0' then [Cases] else '0' end) 'Cases12',
sum(case when d.DateTime between convert(nvarchar(4), year(getdate()),112) + '01' + '01' and (convert(nvarchar(6),getdate(),112)) then [Cases] else '0' end) 'CasesYTDCurrent',
sum(case when d.DateTime >= convert(nvarchar(4), year(getdate()),112) + '01' + '01' and d.DateTime < (convert(nvarchar(6),getdate(),112))+'01' then [Cases] else '0' end) 'CasesYTD',
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '12' then [Turnover] else '0' end) 'Turnover0',
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '11' then [Turnover] else '0' end) 'Turnover1',
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '10' then [Turnover] else '0' end) 'Turnover2',
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '9' then [Turnover] else '0' end) 'Turnover3',
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '8' then [Turnover] else '0' end) 'Turnover4',
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '7' then [Turnover] else '0' end) 'Turnover5',
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '6' then [Turnover] else '0' end) 'Turnover6',
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '5' then [Turnover] else '0' end) 'Turnover7',
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '4' then [Turnover] else '0' end) 'Turnover8',
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '3' then [Turnover] else '0' end) 'Turnover9',
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '2' then [Turnover] else '0' end) 'Turnover10',
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '1' then [Turnover] else '0' end) 'Turnover11',
sum(case when datediff(mm,(d.yearmonth + '01'), (convert(nvarchar(6),getdate(),112) + '01'))= '0' then [Turnover] else '0' end) 'Turnover12',
sum(case when d.DateTime between convert(nvarchar(4), year(getdate()),112) + '01' + '01' and (convert(nvarchar(6),getdate(),112)) then [Turnover] else '0' end) 'TurnoverYTDCurrent',
sum(case when d.DateTime >= convert(nvarchar(4), year(getdate()),112) + '01' + '01' and d.DateTime < (convert(nvarchar(6),getdate(),112))+'01' then [Turnover] else '0' end) 'TurnoverYTD'
from
msft_sales s,
msdt_Adviser a,
msdt_products p,
msdt_calendartime d,
msct_UserAccessControl uac
where
s.Productid = p.productId and
s.BusinessTypeid = 2 and
s.ComparisonId = 1 and
s.dateissuedid = d.dateid and
s.dateissuedid <> '-99' and
s.AdviserId = uac.AdviserId and
uac.DomainLogin = @UserId and
s.AdviserId = a.AdviserId and
left(rtrim(a.Franchise),45) = @Franchise and
left(rtrim(a.Adviser),45) = @Adviser
group by
d.yearmonth,
p.productgroupname
end 



select
ProductGroupName,
case when ProductGroupName = 'Investment' then 5 
     when ProductGroupName = 'Pensions' then 6
     when ProductGroupName = 'Protection' then 7
     when ProductGroupName = 'Mortgage' then 8
     when ProductGroupName = 'GI' then 9
     else 10
     end [OrderBy],
sum(Turnover1 + Turnover2 + Turnover3 + Turnover4 + Turnover5+Turnover0) [First6],
sum(Turnover6) [Current-6],
sum(Turnover7) [Current-5],
sum(Turnover8) [Current-4],
sum(Turnover9) [Current-3],
sum(Turnover10) [Current-2],
sum(Turnover11) [Current-1],
sum(Turnover12) [Current],
sum(Turnover0+ Turnover1 + Turnover2 + Turnover3 + Turnover4 + Turnover5+Turnover6+Turnover7+Turnover8+Turnover9+Turnover10+Turnover11) [Rolling12],
sum(TurnoverYTDCurrent) [TurnoverYTD-Current],
sum(TurnoverYTD) [TurnoverYTD]
from 
#mst_production
group by
ProductGroupName

union

select
'Turnover Actual',
4,
sum(Turnover1 + Turnover2 + Turnover3 + Turnover4 + Turnover5+Turnover0) [First6],
sum(Turnover6) [Current-6],
sum(Turnover7) [Current-5],
sum(Turnover8) [Current-4],
sum(Turnover9) [Current-3],
sum(Turnover10) [Current-2],
sum(Turnover11) [Current-1],
sum(Turnover12) [Current],
sum(Turnover0 + Turnover1 + Turnover2 + Turnover3 + Turnover4 + Turnover5+Turnover6+Turnover7+Turnover8+Turnover9+Turnover10+Turnover11 ) [Rolling12],
sum(TurnoverYTDCurrent) [TurnoverYTD-Current],
sum(TurnoverYTD) [TurnoverYTD]
from 
#mst_production

union

select
'Cases Actual',
1,
sum(Cases1 + Cases2 + Cases3 + Cases4 + Cases5 + Cases0) [First6],
sum(Cases6) [Current-6],
sum(Cases7) [Current-5],
sum(Cases8) [Current-4],
sum(Cases9) [Current-3],
sum(Cases10) [Current-2],
sum(Cases11) [Current-1],
sum(Cases12) [Current],
sum(Cases0 + Cases1 + Cases2 + Cases3 + Cases4 + Cases5 + Cases6 + Cases7 + Cases8 + Cases9 + Cases10 + Cases11) [Rolling12],
sum(CasesYTDCurrent) [TurnoverYTD-Current],
sum(CasesYTD) [TurnoverYTD]
from 
#mst_production

union

select
'Target',
2,
0 [First6],
0 [Current-6],
0 [Current-5],
0 [Current-4],
0 [Current-3],
0 [Current-2],
0 [Current-1],
0 [Current],
0 [Rolling12],
0 [TurnoverYTD-Current],
0 [TurnoverYTD]
from 
#mst_production

union

select
'% of Target Achieved',
3,
0 [First6],
0 [Current-6],
0 [Current-5],
0 [Current-4],
0 [Current-3],
0 [Current-2],
0 [Current-1],
0 [Current],
0 [Rolling12],
0 [TurnoverYTD-Current],
0 [TurnoverYTD]
from 
#mst_production
Order by
OrderBy



