CREATE PROCEDURE [dbo].[msp_Select1to1Production2] -- WITH RECOMPILE,ENCRYPTION
    @UserId nvarchar(50),
    @Franchise nvarchar(50),
    @Adviser nvarchar(50),
    @BusinessType nvarchar(50),
    @Filter nvarchar(50),
    @ProductGroup nvarchar(50)
    
AS

BEGIN


/******************************************************************************

Copyright (C) Moore Stephens Consulting Limited 2005

Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
          
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>
--
-- Amended : 08/07/2009 - MPC: Replace *= ANSI JOINS as these not allowed in SQL Server 2005
--
*******************************************************************************/


--   declare @UserId nvarchar(50),
--    @Adviser nvarchar(50),
--    @Franchise nvarchar(50),
--    @BusinessType nvarchar(50),
--         @Filter nvarchar(50),
--         @ProductGroup nvarchar(50)
-- 
--   set @UserId = 'bi\kstokes'
--   set @Adviser = 'Catherine Simpson'
--   set @Franchise = 'First Class Mortgages (Scotland) Ltd'
--   set @BusinessType = 'Issued'
--  set @Filter = 'Current_1'
--  set @ProductGroup = 'Investment'

-- select * from msft_sales
-- select * from msdt_adviser where adviser = 'catherine simpson'
-- 
-- select c.datetime, s.ape, s.nbi
-- from msft_sales s,
--      msdt_calendartime c
-- where s.adviserid = '4336'
-- --and s.businesstypeid = 1
-- and c.entrytypeid = 2
-- and s.datewrittenid = c.dateid
-- group by s.policynumber, c.datetime, s.ape, s.nbi
-- order by datetime desc

-- select * from msdt_adviser where adviser = 'howard kristall'
--select * from msft_sales

select
    s.adviserid as AdviserID,
    a.agentcode as AgentCode,
    a.adviser as Adviser,
    cast ('' as nvarchar(250)) as Client,
    s.ProductId as ProductId,
    cast ('' as nvarchar(50)) as Product,
    cast ('' as nvarchar(50)) as ProductGroup,
    cast ('' as nvarchar(50)) as PolicyNumber, --s.PolicyNumber as PolicyNumber,
    p.Cont_Num as Cont_Num,
    cast ('' as nvarchar(50)) as Premium,
    cast ('' as nvarchar(50)) as Frequency,
    cast (sum(s.APE) as decimal(18,2)) [APE],
    cast (sum(s.nbi) as decimal(18,2)) [NBI],
    sum(s.Cases) [Adviser Split],
    cast ('' as nvarchar(50)) as TransactionDate,
    s.DateWrittenId as DateWrittenId,
    cast ('' as nvarchar(50)) as WrittenDate,
    s.DateIssuedId,
    cast ('' as nvarchar(50)) as IssuedDate
into  
    #mst_production2
from
--NEW CODE Start: MPC 08/07/2009
  msft_sales s
    inner join mstt_policies p on s.PolicyNumber = p.Pol_Num
    inner join msdt_adviser a on a.adviserid = s.adviserid
    inner join msct_UserAccessControl uac on s.AdviserId = uac.AdviserId
    inner join msdt_BusinessType bt on s.BusinessTypeId = bt.BusinessTypeId
where
    bt.BusinessType = @BusinessType and
    uac.DomainLogin = @UserId and
    left(rtrim(a.Franchise),45) = @Franchise and
    left(rtrim(a.Adviser),45) = @Adviser
--NEW CODE End: MPC 08/07/2009
 /*
--OLD CODE Start: MPC 08/07/2009
    msft_sales s,
    msdt_adviser a,
    msct_UserAccessControl uac,
    msdt_BusinessType bt,
    mstt_policies p
where
    s.PolicyNumber *= p.Pol_Num and
    s.BusinessTypeId = bt.BusinessTypeId and
    bt.BusinessType = @BusinessType and
    s.AdviserId = uac.AdviserId and
    uac.DomainLogin = @UserId and
    left(rtrim(a.Franchise),45) = @Franchise and
    left(rtrim(a.Adviser),45) = @Adviser and
    a.adviserid = s.adviserid
--OLD CODE End: MPC 08/07/2009
*/
group by
    s.adviserid,
    a.agentcode,
    a.adviser,
    p.Cont_Num,
    s.ProductId,
    s.TransactionDateId,
    s.DateWrittenId,
    s.DateIssuedId



update #mst_production2
set
 Product = pd.ProductName,
 ProductGroup = pd.ProductGroupName
from
 #mst_production2 p,
 msdt_products pd
where
 p.productid = pd.productid


update #mst_production2
set 
Client = c.Name
from 
  mstt_clients c,
  #mst_production2 p,
  mstt_policies pol
where
  p.cont_num = pol.cont_num and
  pol.client_num = c.client_num



update #mst_production2
set 
Premium = pol.Amount,
Frequency = pol.frequencyDescription
from 
  #mst_production2 p,
  mstt_policies pp,
  mstt_policytransactions pol
where
  p.cont_num = pp.cont_num and
  pp.pol_num = pol.policyid



update #mst_production2
set
IssuedDate = cal.DateTime --convert(nvarchar(10),cal.DateTime,103)
from
      msdt_CalendarTime cal,
      #mst_production2 p--,
      --msft_sales s
where 
      p.DateIssuedId = cal.dateid and
      cal.entrytypeid = 2 and
      p.dateissuedid <> '-99'
      
      
update #mst_production2
set
WrittenDate = cal.DateTime --convert(nvarchar(10),cal.DateTime,103)
from
      msdt_CalendarTime cal,
      #mst_production2 p--,
      --msft_sales s
where 
      p.DateWrittenId = cal.dateid and
      cal.entrytypeid = 1 and
      p.dateWrittenId <> '-99'
      
      
update #mst_production2
set
TransactionDate = cal.datetime --convert(nvarchar(10),cal.DateTime,103)
from
      msdt_CalendarTime cal,
      #mst_production2 p--,
      --msft_sales s
where 
      p.DateWrittenId = cal.dateid and
      cal.entrytypeid = 1 and  
      p.DateWrittenId <> '-99'



if @BusinessType = 'Written' 
begin
--Written
select
  Adviser,
  Client,
  Product as Product,
  Cont_Num as PolicyNumber,
  Premium,
  Frequency,
  APE,
  NBI,
  [Adviser Split],
  convert(nvarchar(10),convert(datetime,TransactionDate,103),103) as TransactionDate,
        convert(nvarchar(10),convert(datetime,WrittenDate,103),103) as OrderBy,
        convert(nvarchar(10),convert(datetime,IssuedDate,103),103)
from
#mst_production2
where
 ProductGroup = @ProductGroup and
 WrittenDate >= case when @Filter = 'Rolling12' then dateadd(mm,-12,getdate())
      when @Filter = 'Current' then '01 ' + left(convert(nvarchar(12),datename(mm,getdate()),106),3) + ' ' + convert(nvarchar(12),year(getdate()),106)
                        when @Filter = 'Current_1' then '01 ' + left(convert(nvarchar(12),datename(mm,dateadd(m,-1,getdate())),106),3) + ' ' + convert(nvarchar(12),year(dateadd(mm,-1,getdate())),106)
                        when @Filter = 'Current_2' then '01 ' + left(convert(nvarchar(12),datename(mm,dateadd(m,-2,getdate())),106),3) + ' ' + convert(nvarchar(12),year(dateadd(mm,-2,getdate())),106)
                        when @Filter = 'Current_3' then '01 ' + left(convert(nvarchar(12),datename(mm,dateadd(m,-3,getdate())),106),3) + ' ' + convert(nvarchar(12),year(dateadd(mm,-3,getdate())),106)
                        when @Filter = 'Current_4' then '01 ' + left(convert(nvarchar(12),datename(mm,dateadd(m,-4,getdate())),106),3) + ' ' + convert(nvarchar(12),year(dateadd(mm,-4,getdate())),106)
                        when @Filter = 'Current_5' then '01 ' + left(convert(nvarchar(12),datename(mm,dateadd(m,-5,getdate())),106),3) + ' ' + convert(nvarchar(12),year(dateadd(mm,-5,getdate())),106)
                        when @Filter = 'Current_6' then '01 ' + left(convert(nvarchar(12),datename(mm,dateadd(m,-6,getdate())),106),3) + ' ' + convert(nvarchar(12),year(dateadd(mm,-6,getdate())),106)
                        when @Filter = 'First6' then dateadd(mm,-12,getdate())
                        when @Filter = 'YTD' then convert(nvarchar(4), year(getdate()),112) + '01' + '01'
      when @Filter = 'YTD_Current' then convert(nvarchar(4), year(getdate()),112) + '01' + '01'
                    end  and

 WrittenDate < case when @Filter = 'Rolling12' then getdate() 
       when @Filter = 'Current' then getdate()
                         when @Filter = 'Current_1' then '01 ' + left(convert(nvarchar(12),datename(mm,dateadd(m,0,getdate())),106),3) + ' ' + convert(nvarchar(12),year(dateadd(mm,0,getdate())),106)
                         when @Filter = 'Current_2' then '01 ' + left(convert(nvarchar(12),datename(mm,dateadd(m,-1,getdate())),106),3) + ' ' + convert(nvarchar(12),year(dateadd(mm,-1,getdate())),106)
