CREATE      PROCEDURE [dbo].[msp_SelectAdvisorsOverBenchmark]
  @UserId VARCHAR(20), --current User Id
  @CategoryType VARCHAR(20), --COB/MCOB/ICOB-PP/ICOB-GI
  @FailureType VARCHAR(20),  --SA/CQ/ALL
  @BenchMarkReportRequired VARCHAR(20), --ASD6Month/ASDPeriod/NONASD6Month
  @ReportPeriod INT = 0
AS

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2006 All rights reserved
--
-- Object  : procedure
-- Name    : msp_SelectAdvisorsOverBenchmark
-- Desc    : Selects Agent Details that exceed the benchmark
-- Owner   : JNHL
-- Created : 02/08/2006
--
-- Amended : 08/08/2006 - Added Default Data fields so sub reports show.
--       : 09/08/2006 - Added KPILevel<>CORP 
--       : 10/08/2006 - Removed Reliance on mstt_INTUser
--       : 30/08/2006 - Override AgentType for ASQM's to join on SQM level code.  Also outer join RSM,ASD etc (BT)
--       : 02/10/2006 - Retrieve CategoryOfBusiness Sequence for NONASD6MONTH variation to sequence categories correctly
--
--########################################################################

  --Local Vars
  DECLARE @ASDCode AS VARCHAR(20)
  DECLARE @ReportMonth AS DATETIME
  DECLARE @ReportStart AS DATETIME 
  DECLARE @StrippedUserId VARCHAR(20) --current User Id
  DECLARE @SummaryPeriod AS INT

  --Get the Current reporting Month
  SELECT @ReportMonth=MAX(ReportMonth) 
  FROM mstt_AgentQualityAggregation
  WHERE KPILevel= 'ADVISERKPI'

  --Default Summary Period=6 for 6 Month Rolling
  SET @SummaryPeriod=6

  --If Period is Specified Then Set Start Month
  IF @ReportPeriod<>0 
  BEGIN
    SET @ReportStart=DateAdd(M,-(@ReportPeriod),@ReportMonth)
    --Summary Period is 1 if Using a Rolling Period
    SET @SummaryPeriod=1 
  END
  --Otherwise ReportStart is Empty
  ELSE
  BEGIN
    SET @ReportStart=@ReportMonth
  END   

  --Create Table Variable
  DECLARE @AgentList TABLE 
    (AdvisorCode VARCHAR(20),
      PSCode VARCHAR(20),
      SQMCode VARCHAR(20),
      RSMCode VARCHAR(20),
      ASDCode VARCHAR(20))
/*  
  --Remove usless Leading details from user name
  SET @StrippedUserId = CASE WHEN CHARINDEX('\', @UserId) = 0 THEN @UserId
        ELSE SUBSTRING(@UserId, CHARINDEX('\', @UserId)+1, LEN(@UserId))
        END
  
  -- GET THE ASD Code for the current User, using Logged in as user
  SELECT 
    @ASDCode=AssociatedAgent
  FROM
    msit_IntUsers 
  WHERE 
    [Name]=@StrippedUserId
*/  
  --Get the correct Agent hierarchy
  INSERT INTO 
    @AgentList
  SELECT 
    AgentCode 
    , SalesQualityPSLevelCode
    , SalesQualitySQMLevelCode
    , SalesQualityRSMLevelCode
    , SalesQualityASDLevelCode
  FROM mstt_AgentQualityHierarchy
  WHERE 
    CASE (SELECT CASE WHEN AgentCategory = 'ASQMNS' THEN 52 ELSE AgentType END FROM Mstt_Agents WHERE Code=@UserId)
      --ASD
      WHEN 55 THEN SalesQualityASDLevelCode
      --RSM
      WHEN 53 THEN SalesQualityRSMLevelCode
      --SQM
      WHEN 52 THEN SalesQualitySQMLevelCode
      --Practice Manager
      WHEN 43 THEN SalesQualityPSLevelCode
      --Sellers
      WHEN 4 THEN AgentCode
      --All Others
      ELSE AgentCode
    END = @UserId
  And IsCurrent=1

  --Pivots Quality Targets into Flat Table
  SELECT 
    KPILevel,
    ComplianceCategoryCode,
    QualityTargetTypeCode,
    TargetValue AS SATarget,
    (SELECT 
      TargetValue AS CQTarget
      FROM mstt_QualityTarget
        WHERE
          KPILevel='ALL'
          AND ComplianceCategoryCode=QT.ComplianceCategoryCode
          AND QualityTargetPurposeCode='CQ'
          AND QualityTargetTypeCode='BENCHMARK') CQTarget,
    (SELECT 
      TargetValue AS RejectTarget
      FROM mstt_QualityTarget
        WHERE
          KPILevel='ALL'
          AND ComplianceCategoryCode=QT.ComplianceCategoryCode
          AND QualityTargetPurposeCode='Reject'
          AND QualityTargetTypeCode='BENCHMARK') RejectTarget
  INTO #tmp_QualityTargets
  FROM 
    mstt_QualityTarget QT
  WHERE
    KPILevel='ALL'
    AND QualityTargetPurposeCode='SA'
    AND QualityTargetTypeCode='BENCHMARK'

  IF @BenchMarkReportRequired='ASD6Month' 
  BEGIN
    -- IF FailureType<>"ALL" AND @ReportPeriod is 0 Then Extract by failureType
    IF UPPER(@FailureType)<>'ALL'
    BEGIN 
      SELECT 
          Advisor.Code
        , Advisor.Descn
        , AQA.SubmittedRiskProposalQty+AQA.SubmittedRandomProposalQty+AQA.SubmittedOtherProposalQty SubmittedCases
        , AQA.InitialRiskAssessedQty+AQA.InitialRandomAssessedQty+AQA.InitialOtherAssessedQty AssessedCases
        , AQA.InitialRiskSuitableAdviceQty+AQA.InitialRandomSuitableAdviceQty+InitialOtherSuitableAdviceQty SAFail
        , AQA.InitialRiskCompletionQty+AQA.InitialRandomCompletionQty+InitialOtherCompletionQty CQFail
        , CQKPIPercent
        , SAKPIPercent
        , ASD.Descn ASD_Name
        , RSM.Descn RSM_Name
        , SQM.Descn SQM_Name
        , CASE
            WHEN PSM.Descn<>SQM.Descn THEN PSM.Descn
            ELSE ''
          END PSM_Name
      FROM mstt_AgentQualityAggregation AQA 
        INNER JOIN @AgentList AgentList ON AdvisorCode=AQA.AgentCode
  
          INNER JOIN mstt_Agents Advisor ON AgentList.AdvisorCode=Advisor.Code
          LEFT OUTER JOIN mstt_Agents PSM ON AgentList.PSCode=PSM.Code
          LEFT OUTER JOIN mstt_Agents SQM ON AgentList.SQMCode=SQM.Code
          LEFT OUTER JOIN mstt_Agents RSM ON AgentList.RSMCode=RSM.Code
          LEFT OUTER JOIN mstt_Agents ASD ON AgentList.ASDCode=ASD.Code
    
        INNER JOIN mstt_AgentQualityHierarchy AQH 
          ON AQH.AgentCode=AgentList.AdvisorCode
        INNER JOIN #tmp_QualityTargets QT
          ON QT.ComplianceCategoryCode=AQA.ComplianceCategoryCode
      WHERE SummaryPeriod=@SummaryPeriod
        AND ReportMonth BETWEEN @ReportStart AND @ReportMonth
        AND QT.KPILevel='ALL'
        AND AQA.KPILevel='ADVISERKPI'
        AND QT.QualityTargetTypeCode='BENCHMARK'
        AND QT.ComplianceCategoryCode=@CategoryType
        AND HierarchyTypeCode='KPI'
        AND CASE @FailureType
            WHEN 'SA' THEN SAKPIPercent*100
            WHEN 'CQ' THEN CQKPIPercent*100
          END > CASE @FailureType 
                WHEN 'SA' THEN SATarget
                WHEN 'CQ' THEN CQTarget
              END
        AND IsCurrent=1
    END
    ELSE 
    -- Otherwise, Extract All Data if Either SA/CQ Fail Targets
    BEGIN
      SELECT 
          Advisor.Code
        , Advisor.Descn
        , AQA.SubmittedRiskProposalQty+AQA.SubmittedRandomProposalQty+AQA.SubmittedOtherProposalQty SubmittedCases
        , AQA.InitialRiskAssessedQty+AQA.InitialRandomAssessedQty+AQA.InitialOtherAssessedQty AssessedCases
        , AQA.InitialRiskSuitableAdviceQty+AQA.InitialRandomSuitableAdviceQty+InitialOtherSuitableAdviceQty SAFail
        , AQA.InitialRiskCompletionQty+AQA.InitialRandomCompletionQty+InitialOtherCompletionQty CQFail
        , CQKPIPercent
        , SAKPIPercent
        , ASD.Descn ASD_Name
        , RSM.Descn RSM_Name
        , SQM.Descn SQM_Name
        , CASE
            WHEN PSM.Descn<>SQM.Descn THEN PSM.Descn
            ELSE ''
          END PSM_Name
      FROM mstt_AgentQualityAggregation AQA 
        INNER JOIN @AgentList AgentList ON AdvisorCode=AQA.AgentCode
          INNER JOIN mstt_Agents Advisor ON AgentList.AdvisorCode=Advisor.Code
          LEFT OUTER JOIN mstt_Agents PSM ON AgentList.PSCode=PSM.Code
          LEFT OUTER JOIN mstt_Agents SQM ON AgentList.SQMCode=SQM.Code
          LEFT OUTER JOIN mstt_Agents RSM ON AgentList.RSMCode=RSM.Code
          LEFT OUTER JOIN mstt_Agents ASD ON AgentList.ASDCode=ASD.Code
    
        INNER JOIN mstt_AgentQualityHierarchy AQH 
          ON AQH.AgentCode=AgentList.AdvisorCode
        INNER JOIN #tmp_QualityTargets QT
          ON QT.ComplianceCategoryCode=AQA.ComplianceCategoryCode
      WHERE SummaryPeriod=@SummaryPeriod
        AND ReportMonth BETWEEN @ReportStart AND @ReportMonth 
        AND QT.KPILevel='ALL'
        AND AQA.KPILevel='ADVISERKPI'
        AND QT.QualityTargetTypeCode='BENCHMARK'
        AND QT.ComplianceCategoryCode=@CategoryType
        AND HierarchyTypeCode='KPI'
        AND (SAKPIPercent*100>=SATarget 
            AND CQKPIPercent*100>=CQTarget)
        AND IsCurrent=1
    END
  END   
  ELSE
  --Over BenchMark For Given Period (ASDPeriod)
  BEGIN
    IF @BenchMarkReportRequired='ASDPeriod'
    BEGIN
      SELECT
        AQA.AgentCode,
        COUNT(*) Times_Over_Benchmark
      INTO #tmp_Count
      FROM mstt_AgentQualityAggregation AQA 
        INNER JOIN @AgentList AgentList ON AdvisorCode=AQA.AgentCode
        INNER JOIN mstt_AgentQualityHierarchy AQH 
          ON AQH.AgentCode=AgentList.AdvisorCode
        INNER JOIN #tmp_QualityTargets QT
          ON QT.ComplianceCategoryCode=AQA.ComplianceCategoryCode
      WHERE SummaryPeriod=@SummaryPeriod
        AND ReportMonth BETWEEN @ReportStart AND @ReportMonth
        AND QT.KPILevel='ALL'
        AND AQA.KPILevel='ADVISERKPI'
        AND QT.QualityTargetTypeCode='BENCHMARK'
        AND QT.ComplianceCategoryCode=@CategoryType
        AND HierarchyTypeCode='KPI'
        AND CASE @FailureType
            WHEN 'SA' THEN SAKPIPercent*100
            WHEN 'CQ' THEN CQKPIPercent*100
          END > CASE @FailureType 
                WHEN 'SA' then SATarget
                WHEN 'CQ' then CQTarget
              END
        AND IsCurrent=1
      GROUP BY 
        AQA.AgentCode

      SELECT 
          Advisor.Code
        , Advisor.Descn
        , ReportMonth
        , ASD.Descn ASD_Name
        , RSM.Descn RSM_Name
        , SQM.Descn SQM_Name
        , CASE
            WHEN PSM.Descn<>SQM.Descn THEN PSM.Descn
            ELSE ''
          END PSM_Name
        , InitialRiskSuitableAdviceQty RiskFail_SA
        , InitialRandomSuitableAdviceQty RandomFail_SA
        , InitialOtherSuitableAdviceQty OtherFail_SA
        , InitialRiskCompletionQty RiskFail_CQ
        , InitialRandomCompletionQty RandomFail_CQ
        , InitialOtherCompletionQty OtherFail_CQ
        , SAKPIPercent
        , CQKPIPercent
        , Times_Over_Benchmark
      FROM mstt_AgentQualityAggregation AQA 
          INNER JOIN @AgentList AgentList ON AdvisorCode=AQA.AgentCode
          INNER JOIN mstt_Agents Advisor ON AgentList.AdvisorCode=Advisor.Code
          LEFT OUTER JOIN mstt_Agents PSM ON AgentList.PSCode=PSM.Code
          LEFT OUTER JOIN mstt_Agents SQM ON AgentList.SQMCode=SQM.Code
          LEFT OUTER JOIN mstt_Agents RSM ON AgentList.RSMCode=RSM.Code
          LEFT OUTER JOIN mstt_Agents ASD ON AgentList.ASDCode=ASD.Code
        INNER JOIN mstt_AgentQualityHierarchy AQH 
          ON AQH.AgentCode=AgentList.AdvisorCode
        INNER JOIN #tmp_QualityTargets QT
          ON QT.ComplianceCategoryCode=AQA.ComplianceCategoryCode
        INNER JOIN (SELECT 
                  AgentCode
                , Times_Over_Benchmark
                FROM #tmp_Count) tmp2 ON tmp2.AgentCode=AQA.AgentCode
      WHERE SummaryPeriod=@SummaryPeriod
        AND ReportMonth = @ReportMonth --BETWEEN @ReportStart AND @ReportMonth
        AND QT.KPILevel='ALL'
        AND AQA.KPILevel='ADVISERKPI'
        AND QT.QualityTargetTypeCode='BENCHMARK'
        AND QT.ComplianceCategoryCode=@CategoryType
        AND HierarchyTypeCode='KPI'
        AND CASE @FailureType
            WHEN 'SA' THEN SAKPIPercent*100
            WHEN 'CQ' THEN CQKPIPercent*100
          END > CASE @FailureType 
                WHEN 'SA' then SATarget
                WHEN 'CQ' then CQTarget
              END
        AND IsCurrent=1
        AND Times_Over_Benchmark>CASE @ReportPeriod
                        WHEN 0 Then 1
                        ELSE @ReportPeriod-1
                      END
    END
    ELSE
    BEGIN
      --NON ASD 6 Month Roling Failures
      SELECT 
          Advisor.Code
        , Advisor.Descn
        , QT.ComplianceCategoryCode
        , AQA.SubmittedRiskProposalQty+AQA.SubmittedRandomProposalQty+AQA.SubmittedOtherProposalQty SubmittedCases
        , AQA.InitialRiskAssessedQty+AQA.InitialRandomAssessedQty+AQA.InitialOtherAssessedQty AssessedCases
        , AQA.InitialRiskSuitableAdviceQty+AQA.InitialRandomSuitableAdviceQty+InitialOtherSuitableAdviceQty SAFail
        , AQA.InitialRiskCompletionQty+AQA.InitialRandomCompletionQty+InitialOtherCompletionQty CQFail
        , SAKPIPercent
        , SATarget
        , CQKPIPercent
        , CQTarget
        , ASD.Descn ASD_Name
        , RSM.Descn RSM_Name
        , SQM.Descn SQM_Name
        , CASE
            WHEN PSM.Descn<>SQM.Descn THEN PSM.Descn
            ELSE ''
          END PSM_Name
      INTO #tmp_BenchMarks
      FROM mstt_AgentQualityAggregation AQA 
        INNER JOIN @AgentList AgentList ON AdvisorCode=AQA.AgentCode
          INNER JOIN mstt_Agents Advisor ON AgentList.AdvisorCode=Advisor.Code
          LEFT OUTER JOIN mstt_Agents PSM ON AgentList.PSCode=PSM.Code
          LEFT OUTER JOIN mstt_Agents SQM ON AgentList.SQMCode=SQM.Code
          LEFT OUTER JOIN mstt_Agents RSM ON AgentList.RSMCode=RSM.Code
          LEFT OUTER JOIN mstt_Agents ASD ON AgentList.ASDCode=ASD.Code
        INNER JOIN mstt_AgentQualityHierarchy AQH 
          ON AQH.AgentCode=AgentList.AdvisorCode
        INNER JOIN #tmp_QualityTargets QT
          ON QT.ComplianceCategoryCode=AQA.ComplianceCategoryCode
      WHERE SummaryPeriod=@SummaryPeriod
        AND ReportMonth=@ReportMonth
        AND QT.KPILevel='ALL'
        AND AQA.KPILevel='ADVISERKPI'
        AND QT.QualityTargetTypeCode='BENCHMARK'
        AND HierarchyTypeCode='KPI'
        AND IsCurrent=1
      

      --Return All Data For Agents failing one or more Categoryies
      SELECT 
          BenchMark.Code
        , BenchMark.Descn
        , BenchMark.ComplianceCategoryCode
        , BenchMark.SubmittedCases
        , BenchMark.AssessedCases
        , BenchMark.SAFail
        , BenchMark.CQFail
        , BenchMark.SAKPIPercent
        , BenchMark.SATarget
        , BenchMark.CQKPIPercent
        , BenchMark.CQTarget
        , BenchMark.ASD_Name
        , BenchMark.RSM_Name
        , BenchMark.SQM_Name
        , BenchMark.PSM_Name
        , cofb.[CategoryOfBusinessSequence]
      FROM #tmp_BenchMarks BenchMark 
        INNER JOIN msv_CategoryOfBusiness cofb 
          ON cofb.ComplianceCategoryCode = BenchMark.ComplianceCategoryCode
        JOIN (SELECT DISTINCT Code 
            FROM #tmp_BenchMarks
            WHERE SAKPIPercent*100>SATarget
              OR CQKPIPercent*100>CQTarget
              OR Code=0) OverBenchMark 
                    ON BenchMark.Code=OverBenchMark.Code
    END
  END

GO
