CREATE procedure [dbo].[msp_SelectAgentCompetence]
    @AgentCode       nvarchar(50),
    @UserId          nvarchar(50),
    @AllowDelegates  char(1)

as

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2006 All rights reserved
--
-- Object  : procedure
-- Name    : msp_SelectAgentCompetence.sql
-- Desc    : Returns Competence for each Category for the specfied agent
-- Owner   : BT
-- Created : 04/07/2006
--
-- Amended : 13/07/2006  - BT  - Remove Audience & UserId parameters
-- Amended : 21/07/2006  - BT  - Retrieve Category values even if no data to retrieve
-- Amended : 31/07/2006  - BT  - Only retrieve the latest competence value
-- Amended : 14/08/2006  - MK  - Added further security, to ensure that the 
--                               user executing the report is allowed to see
--                               the agent that has been passed in to the proc.
-- Amended : 16/08/2006  - MK  - Add function to allow delegate access. That is, allow a user
--                               to impersonate the user to whom they have been given access.
--       14/02/2007  - RH/OW - Tuned for performance as part of Agent KPI report production issue
--         - Fixes to affected procs/fns include explicit conversion of datatypes in query
--           expressions where parameter type is not matched to table data type
--           allowing Index seeks rather than scans
--         - Addition of indexes to required Quality tables
--         - Explicit alternative logic paths for queries where global parameter (eg Filter) is not supplied
--           avoiding table/index scans forced by unnecessary OR statememnts
--         - Use permissions caching wrapper around existing permissions/span checks

--
--########################################################################

if isnull(@AllowDelegates, 'N') = 'Y'
  set @UserId = (select dbo.msf_SQGetUserDelegatedFrom(@UserId))

declare @PermCheck nvarchar(50)
exec dbo.owp_SQCheckCachedPermissions @UserId, @AgentCode, 'AdviserKPI', 'CURRENT', 1, @PermCheck output

if @PermCheck = 'DENY'
--if dbo.msf_SQCheckPermissions (@UserId, @AgentCode, 'AdviserKPI', 'CURRENT', 1) = 'DENY' 


  SELECT 
  null as [pp_CategoryOfBusiness],
  null as [pp_AgentCompetence],
  null as [gi_CategoryOfBusiness],
  null as [gi_AgentCompetence],
  null as [m_CategoryOfBusiness],
  null as [m_AgentCompetence],
  null as [i_CategoryOfBusiness],
  null as [i_AgentCompetence]
else

begin

SELECT pp.[CategoryOfBusiness] AS [pp_CategoryOfBusiness]
      ,pp.[AgentControlFunctionDescn] AS [pp_AgentCompetence]
      ,gi.[CategoryOfBusiness] AS [gi_CategoryOfBusiness]
      ,gi.[AgentControlFunctionDescn] AS [gi_AgentCompetence]
      ,m.[CategoryOfBusiness] AS [m_CategoryOfBusiness]
      ,m.[AgentControlFunctionDescn] AS [m_AgentCompetence]
      ,i.[CategoryOfBusiness] AS [i_CategoryOfBusiness]
      ,i.[AgentControlFunctionDescn] AS [i_AgentCompetence]
FROM
(
SELECT a.[AgentCode], a.[ComplianceCategoryCode], a.[AgentControlFunctionDescn], c.[CategoryOfBusiness] 
FROM   [msv_CategoryOfBusiness] c LEFT JOIN [mstt_AgentCompetence] a 
       ON  a.[ComplianceCategoryCode] = c.[ComplianceCategoryCode] 
       AND a.[AgentCode] = convert(varchar(7),@AgentCode)
       AND a.[EndDate] IS NULL
WHERE  c.compliancecategorycode = 'ICOB-PP'
) pp,
(
SELECT a.[AgentCode], a.[ComplianceCategoryCode], a.[AgentControlFunctionDescn], c.[CategoryOfBusiness] 
FROM   [msv_CategoryOfBusiness] c LEFT JOIN [mstt_AgentCompetence] a 
       ON  a.[ComplianceCategoryCode] = c.[ComplianceCategoryCode] 
       AND a.[AgentCode] = convert(varchar(7),@AgentCode)
       AND a.[EndDate] IS NULL
WHERE  c.compliancecategorycode = 'ICOB-GI'
) gi,
(
SELECT a.[AgentCode], a.[ComplianceCategoryCode], a.[AgentControlFunctionDescn], c.[CategoryOfBusiness] 
FROM   [msv_CategoryOfBusiness] c LEFT JOIN [mstt_AgentCompetence] a 
       ON  a.[ComplianceCategoryCode] = c.[ComplianceCategoryCode] 
       AND a.[AgentCode] = convert(varchar(7),@AgentCode)
       AND a.[EndDate] IS NULL
WHERE  c.compliancecategorycode = 'MCOB'
) m,
(
SELECT a.[AgentCode], a.[ComplianceCategoryCode], a.[AgentControlFunctionDescn], c.[CategoryOfBusiness] 
FROM   [msv_CategoryOfBusiness] c LEFT JOIN [mstt_AgentCompetence] a 
       ON  a.[ComplianceCategoryCode] = c.[ComplianceCategoryCode] 
       AND a.[AgentCode] = convert(varchar(7),@AgentCode)
       AND a.[EndDate] IS NULL
WHERE  c.compliancecategorycode = 'COB'
) i

end




GO
