CREATE PROCEDURE [dbo].[msp_SelectAgentDetails] -- WITH RECOMPILE,ENCRYPTION
  --@UserId nvarchar(50),
  @ASD nvarchar(50),
  @RSM nvarchar(50),
  @SQM nvarchar(50),
  @Franchise nvarchar(50),
  @AgentStatus nvarchar (50),
  @BusinessStatus nvarchar (50),
  @BusinessType nvarchar (50),
  @SpecialistCode nvarchar (50),
  @ChangedSinceDate nvarchar (10)
AS

/******************************************************************************

Copyright (C) Moore Stephens Consulting Limited 2005

Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
          
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>

*******************************************************************************/

Select 
   [Agent UID],
   [ValidFrom],
   [AgentStatus],
   [Date Started],
   [Oscar Date Started],
   [Oscar Prefix],
   [Oscar Serial],
   [Oscar Suffix],
   [ZurichNew],
   [ZurichLegacy],
   [UKPL],
   [PaymentShield],
   [SIML],
   [ScotEq],
   [ScotEqLegacy],
   [Sterling],
   [Forename],
   [Surname],
   [Portal Code],
   [FSA Reg No],
   [Agent Category],
   [Agent Type],
   [Can Sell],
   [Specialist Code],
   [GI Provider],
   [Mobile Number],
   [Office Email],
   [Office Website],
   [Office Phone],
   [Office Fax],
   [Office Adressee],
   [Office Address1],
   [Office Address2],
   [Office Address3],
   [Office Address4],
   [Office Address5],
   [Office Postcode],
   [Office Country],
   [Home Address1],
   [Home Address2],
   [Home Address3],
   [Home Address4],
   [Home Address5],
   [Home Postcode],
   [Business UID],
   [F_ValidFrom],
   [BusinessStatus],
   [F_Oscar Prefix],
   [F_Oscar Serial],
   [F_Oscar Suffix],
   [BusinessType],
   [Business Name],
   [Competition Name],
   [Size],
   [SQM],
   [RSM],
   [ASD],
   [FSA No],
   [F_Address1],
   [F_Address2],
   [F_Address3],
   [F_Address4],
   [F_Address5],
   [F_Postcode],
   [F_Phone No],
   [F_Fax No],
   [F_Email],
   [F_Website]
from 
   mst_AgentDetails a--,
   --msdt_Adviser ad,
   --msct_UserAccessControl uac
where
  --a.[Agent UID] = ad.AgentCode and
  --ad.AdviserId = uac.AdviserId and
  --uac.DomainLogin = @UserId and
  a.ASD = case when @ASD = '%' then a.ASD else @ASD end and
  a.RSM = case when @RSM = '%' then a.RSM else @RSM end and
  a.SQM = case when @SQM = '%' then a.SQM else @SQM end and
  a.[Business Name] = case when @Franchise = '%' then a.[Business Name] else @Franchise end and
  a.[AgentStatus] = case when @AgentStatus= '%' then a.[AgentStatus] else @AgentStatus end and
  a.[BusinessStatus] = case when @BusinessStatus = '%' then a.[BusinessStatus] else @BusinessStatus end and
  a.[BusinessType] = case when @BusinessType = '%' then a.[BusinessType] else @BusinessType end and
  a.[Specialist Code] = case when @SpecialistCode = '%' then a.[Specialist Code] else @SpecialistCode end and
  (a.ValidFrom >= (select convert (datetime, @ChangedSinceDate, 105))

 or a.F_ValidFrom >= (select convert (datetime, @ChangedSinceDate, 105)))
 Order by 1



GO
