CREATE procedure [dbo].[msp_SelectAgentKPI] 
    @AgentCode            nvarchar(50)
   ,@KPILevel             nvarchar(50)
   ,@HierarchyTypeCode    nvarchar(50)
   ,@ReportMonth          datetime
   ,@NumberOfMonths       int
   ,@UserId               nvarchar(50)
   ,@AllowDelegates       char(1)
   ,@CascadeSelection     bit

as

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : msp_SelectAgentKPI.sql
-- Desc    : 
-- Owner   : BT
-- Created : 03/07/2006
--
-- Amended : 13/07/2006  - BT  - Remove Audience & UserId parameters
-- Amended : 14/07/2006  - BT  - Add target retrieval
-- Amended : 14/07/2006  - BT  - Add target retrieval for next month
-- Amended : 19/07/2006  - BT  - Add KPILevel & HierachyTypeCode parameters, retrieve Corporate KPI's
-- Amended : 20/07/2006  - BT  - Retrieve Single month KPI Percent values
-- Amended : 21/07/2006  - BT  - Add ReportMonth and NumberOfMonths parameters
-- Amended : 25/07/2006  - BT  - Add agent name and AgentCode = 'ALL' option
-- Amended : 09/08/2006  - BT  - Add Reject Pct Target
-- Amended : 11/08/2006  - BT  - Use msf_SQGetAgentsInSpan function to get list of agents to retrieve KPI's for
-- Amended : 14/08/2006  - MK  - Added further security, to ensure that the 
--                               user executing the report is allowed to see
--                               the agent that has been passed in to the proc.
-- Amended : 16/08/2006  - MK  - Add function to allow delegate access. That is, allow a user
--                               to impersonate the user to whom they have been given access.
-- Amended : 16/08/2006  - BT  - Add CascadeSelection parameter to control whether to run for agent or children or agent
-- Amended : 17/08/2006  - JL  - Added code To Get current Users Agent code IF @AgentCode=ALL
--                   Changed Security Checks to  Variable @tmpAgentCode
-- Amended : 17/08/2006  - BT  - Use permission summary period when getting users in span instead of number of months
-- Amended : 06/09/2006  - MK  - Add CategoryOfBusinessLongDescription to the output
--       14/02/2007  - RH/OW - Tuned for performance as part of Agent KPI report production issue
--         - Fixes to affected procs/fns include explicit conversion of datatypes in query
--           expressions where parameter type is not matched to table data type
--           allowing Index seeks rather than scans
--         - Addition of indexes to required Quality tables
--         - Explicit alternative logic paths for queries where global parameter (eg Filter) is not supplied
--           avoiding table/index scans forced by unnecessary OR statememnts
--         - Use permissions caching wrapper around existing permissions/span checks
--########################################################################

DECLARE @TmpAgentCode as varchar(50)

if isnull(@AllowDelegates, 'N') = 'Y'
  set @UserId = (select dbo.msf_SQGetUserDelegatedFrom(@UserId))

--Used to Get the current AgentId for Securitycheck, If AgentCode is ALL
IF @AgentCode='ALL'
BEGIN
  --Get Agent Code from User Id
  SET @TmpAgentCode=(SELECT dbo.msf_SQGetAgentCode(@UserId, @AllowDelegates))
END
ELSE
  SET @TmpAgentCode = @AgentCode

declare @PermissionSummaryPeriod int
set @PermissionSummaryPeriod = case when @hierarchyTypeCode = 'CURRENT' then 1 else 6 end


--select @UserId, @TmpAgentCode, @KPILevel, @HierarchyTypeCode, @PermissionSummaryPeriod

declare @PermCheck nvarchar(50)
exec dbo.owp_SQCheckCachedPermissions @UserId, @TmpAgentCode, @KPILevel, @HierarchyTypeCode, @PermissionSummaryPeriod, @PermCheck output

if @PermCheck = 'DENY'
--if dbo.msf_SQCheckPermissions 
--  (@UserId, @TmpAgentCode, @KPILevel, @HierarchyTypeCode, @PermissionSummaryPeriod) = 'DENY' 


select null as [AgentCode]
      ,null as [AgentName]
      ,null as [KPILevel]
      ,null as [HierarchyTypeCode]
      ,null as [ReportMonth]
      ,null as [ComplianceCategoryCode]
      ,null as [CategoryOfBusiness]
      ,null as [CategoryOfBusinessLongDescription]
      ,null as [CategoryOfBusinessSequence]
      ,null as [SAKPIPercentRolling6Month]
      ,null as [SuitableAdviceFailuresRolling6Month]
      ,null as [CQKPIPercentRolling6Month]
      ,null as [CompletionFailuresRolling6Month]
      ,null as [ComplaintQtyRolling6Month]
      ,null as [CasesSubmittedSingleMonth]
      ,null as [CasesAssessedSingleMonth]
      ,null as [SAKPIPercentSingleMonth]
      ,null as [SuitableAdviceFailuresSingleMonth]
      ,null as [CQKPIPercentSingleMonth]
      ,null as [CompletionFailuresSingleMonth]
      ,null as [ReplacementsSingleMonth]
      ,null as [ReplacementKPIPercentSingleMonth]
      ,null as [RejectsSingleMonth]
      ,null as [RejectKPIPercentSingleMonth]
      ,null as [SATargetPct]
      ,null as [CQTargetPct]
      ,null as [RejectTargetNum]
      ,null as [RejectTargetPct]
      ,null as [CorpSAKPIPercentRolling6Month]
      ,null as [CorpSuitableAdviceFailuresRolling6Month]
      ,null as [CorpCQKPIPercentRolling6Month]
      ,null as [CorpCompletionFailuresRolling6Month]
      ,null as [CorpComplaintQtyRolling6Month]
      ,null as [CorpCasesSubmittedSingleMonth]
      ,null as [CorpCasesAssessedSingleMonth]
      ,null as [CorpSAKPIPercentSingleMonth]
      ,null as [CorpSuitableAdviceFailuresSingleMonth]
      ,null as [CorpCQKPIPercentSingleMonth]
      ,null as [CorpCompletionFailuresSingleMonth]
      ,null as [CorpReplacementsSingleMonth]
      ,null as [CorpReplacementKPIPercentSingleMonth]
      ,null as [CorpRejectsSingleMonth]
      ,null as [CorpRejectKPIPercentSingleMonth]

else

begin


-- next section creates the temp table of initial results
-- in 1 of 3 ways.  Split into 3 code paths to avoid poor performance of tablescan forced by original OR clauses

-- Create temporary table
SELECT a.*
      ,ag.[Descn] as [AgentName]
      ,c.[CategoryOfBusiness]
      ,c.[CategoryOfBusinessLongDescription]
      ,c.[CategoryOfBusinessSequence]
      ,IsNull(t1.[TargetValue],0)/100 as [SATargetPct]
      ,IsNull(t2.[TargetValue],0)/100 as [CQTargetPct]
      ,IsNull(t3.[TargetValue],0) as [RejectTargetNum]
      ,IsNull(t4.[TargetValue],0)/100 as [RejectTargetPct]
      ,corp.[SAKPIPercent] AS [CorpSAKPIPercent]
      ,corp.[SuitableAdviceFailures] AS [CorpSuitableAdviceFailures]
      ,corp.[CQKPIPercent] AS [CorpCQKPIPercent]
      ,corp.[CompletionFailures] AS [CorpCompletionFailures]
      ,corp.[ComplaintQty] AS [CorpComplaintQty]
      ,corp.[CasesSubmitted] AS [CorpCasesSubmitted]
      ,corp.[CasesAssessed] AS [CorpCasesAssessed]
      ,corp.[Replacements] AS [CorpReplacements]
      ,corp.[ReplacementKPIPercent] AS [CorpReplacementKPIPercent]
      ,corp.[Rejects] AS [CorpRejects]
      ,corp.[RejectKPIPercent] AS [CorpRejectKPIPercent]
INTO #Results
FROM  [msv_AgentQualityAggregation] a 
      LEFT JOIN [mstt_Agents] ag on a.[AgentCode] = ag.[Code]
      LEFT JOIN [msv_CategoryOfBusiness] c ON a.[ComplianceCategoryCode] = c.[ComplianceCategoryCode]
      LEFT JOIN [msv_AgentQualityAggregation] corp ON a.[ComplianceCategoryCode] = corp.[ComplianceCategoryCode]
      AND a.[ReportMonth] = corp.[ReportMonth]
      AND a.[SummaryPeriod] = corp.[SummaryPeriod]
      AND corp.[KPILevel] = 'CORP'
      AND corp.[HierarchyTypeCode] = 'KPI' --Corporate does not differentiate between span affecting and current
      LEFT JOIN mstt_QualityTarget t1 ON a.[ComplianceCategoryCode] = t1.[ComplianceCategoryCode] 
      AND a.[ReportMonth] BETWEEN t1.[EffectiveDate] AND t1.[EndDate]
      AND t1.[KPILevel] = 'All'
      AND t1.[QualityTargetTypeCode] = 'Benchmark'
      AND t1.[QualityTargetPurposeCode] = 'SA' 
      AND t1.[TargetValueTypeCode] = 'P'
      AND a.[SummaryPeriod] = 1 --Only Join to SingleMonth aggregate to avoid multiplying targets
      LEFT JOIN mstt_QualityTarget t2 ON a.[ComplianceCategoryCode] = t2.[ComplianceCategoryCode] 
      AND a.[ReportMonth] BETWEEN t2.[EffectiveDate] AND t2.[EndDate]
      AND t2.[KPILevel] = 'All'
      AND t2.[QualityTargetTypeCode] = 'Benchmark'
      AND t2.[QualityTargetPurposeCode] = 'CQ' 
      AND t2.[TargetValueTypeCode] = 'P' 
      AND a.[SummaryPeriod] = 1 --Only Join to SingleMonth aggregate to avoid multiplying targets
      LEFT JOIN mstt_QualityTarget t3 ON a.[ComplianceCategoryCode] = t3.[ComplianceCategoryCode] 
      AND a.[ReportMonth] BETWEEN t3.[EffectiveDate] AND t3.[EndDate]
      AND t3.[KPILevel] = 'All'
      AND t3.[QualityTargetTypeCode] = 'Benchmark'
      AND t3.[QualityTargetPurposeCode] = 'Reject' 
      AND t3.[TargetValueTypeCode] = 'N' 
      AND a.[SummaryPeriod] = 1 --Only Join to SingleMonth aggregate to avoid multiplying targets
      LEFT JOIN mstt_QualityTarget t4 ON a.[ComplianceCategoryCode] = t4.[ComplianceCategoryCode] 
      AND a.[ReportMonth] BETWEEN t4.[EffectiveDate] AND t4.[EndDate]
      AND t4.[KPILevel] = 'CORP'
      AND t4.[QualityTargetTypeCode] = 'Benchmark'
      AND t4.[QualityTargetPurposeCode] = 'Reject' 
      AND t4.[TargetValueTypeCode] = 'P' 
      AND a.[SummaryPeriod] = 1 --Only Join to SingleMonth aggregate to avoid multiplying targets
--WHERE a.KPILevel = @KPILevel

WHERE 1=2


if (@CascadeSelection = 1)
begin
  --Create the list of agents under the managers span of control OR insert the sellers agent code
  SELECT [AgentCode] = [AgentCode]
  INTO   #Agents
  FROM   dbo.msf_SQGetAgentsInSpan(@TmpAgentCode, @KPILevel, @HierarchyTypeCode, @PermissionSummaryPeriod, NULL)

  INSERT #Results
  SELECT a.*
        ,ag.[Descn] as [AgentName]
        ,c.[CategoryOfBusiness]
        ,c.[CategoryOfBusinessLongDescription]
        ,c.[CategoryOfBusinessSequence]
        ,IsNull(t1.[TargetValue],0)/100 as [SATargetPct]
        ,IsNull(t2.[TargetValue],0)/100 as [CQTargetPct]
        ,IsNull(t3.[TargetValue],0) as [RejectTargetNum]
        ,IsNull(t4.[TargetValue],0)/100 as [RejectTargetPct]
        ,corp.[SAKPIPercent] AS [CorpSAKPIPercent]
        ,corp.[SuitableAdviceFailures] AS [CorpSuitableAdviceFailures]
        ,corp.[CQKPIPercent] AS [CorpCQKPIPercent]
        ,corp.[CompletionFailures] AS [CorpCompletionFailures]
        ,corp.[ComplaintQty] AS [CorpComplaintQty]
        ,corp.[CasesSubmitted] AS [CorpCasesSubmitted]
        ,corp.[CasesAssessed] AS [CorpCasesAssessed]
        ,corp.[Replacements] AS [CorpReplacements]
        ,corp.[ReplacementKPIPercent] AS [CorpReplacementKPIPercent]
        ,corp.[Rejects] AS [CorpRejects]
        ,corp.[RejectKPIPercent] AS [CorpRejectKPIPercent]
  FROM  [msv_AgentQualityAggregation] a 
        LEFT JOIN [mstt_Agents] ag on a.[AgentCode] = ag.[Code]
        LEFT JOIN [msv_CategoryOfBusiness] c ON a.[ComplianceCategoryCode] = c.[ComplianceCategoryCode]
        LEFT JOIN [msv_AgentQualityAggregation] corp ON a.[ComplianceCategoryCode] = corp.[ComplianceCategoryCode]
        AND a.[ReportMonth] = corp.[ReportMonth]
        AND a.[SummaryPeriod] = corp.[SummaryPeriod]
        AND corp.[KPILevel] = 'CORP'
        AND corp.[HierarchyTypeCode] = 'KPI' --Corporate does not differentiate between span affecting and current
        LEFT JOIN mstt_QualityTarget t1 ON a.[ComplianceCategoryCode] = t1.[ComplianceCategoryCode] 
        AND a.[ReportMonth] BETWEEN t1.[EffectiveDate] AND t1.[EndDate]
        AND t1.[KPILevel] = 'All'
        AND t1.[QualityTargetTypeCode] = 'Benchmark'
        AND t1.[QualityTargetPurposeCode] = 'SA' 
        AND t1.[TargetValueTypeCode] = 'P'
        AND a.[SummaryPeriod] = 1 --Only Join to SingleMonth aggregate to avoid multiplying targets
        LEFT JOIN mstt_QualityTarget t2 ON a.[ComplianceCategoryCode] = t2.[ComplianceCategoryCode] 
        AND a.[ReportMonth] BETWEEN t2.[EffectiveDate] AND t2.[EndDate]
        AND t2.[KPILevel] = 'All'
        AND t2.[QualityTargetTypeCode] = 'Benchmark'
        AND t2.[QualityTargetPurposeCode] = 'CQ' 
        AND t2.[TargetValueTypeCode] = 'P' 
        AND a.[SummaryPeriod] = 1 --Only Join to SingleMonth aggregate to avoid multiplying targets
        LEFT JOIN mstt_QualityTarget t3 ON a.[ComplianceCategoryCode] = t3.[ComplianceCategoryCode] 
        AND a.[ReportMonth] BETWEEN t3.[EffectiveDate] AND t3.[EndDate]
        AND t3.[KPILevel] = 'All'
        AND t3.[QualityTargetTypeCode] = 'Benchmark'
        AND t3.[QualityTargetPurposeCode] = 'Reject' 
        AND t3.[TargetValueTypeCode] = 'N' 
        AND a.[SummaryPeriod] = 1 --Only Join to SingleMonth aggregate to avoid multiplying targets
        LEFT JOIN mstt_QualityTarget t4 ON a.[ComplianceCategoryCode] = t4.[ComplianceCategoryCode] 
        AND a.[ReportMonth] BETWEEN t4.[EffectiveDate] AND t4.[EndDate]
        AND t4.[KPILevel] = 'CORP'
        AND t4.[QualityTargetTypeCode] = 'Benchmark'
        AND t4.[QualityTargetPurposeCode] = 'Reject' 
        AND t4.[TargetValueTypeCode] = 'P' 
        AND a.[SummaryPeriod] = 1 --Only Join to SingleMonth aggregate to avoid multiplying targets
  WHERE a.[KPILevel] = @KPILevel --ADVISER, PS, SQM, RSM, ASQM, ASD (Agents may have mulitple levels e.g. selling RSM)
  AND   a.[HierarchyTypeCode] = @HierarchyTypeCode --KPI or CURRENT (KPI is span affecting, at some levels KPI and CURRENT are the same so only KPI exists)
  AND   (@CascadeSelection = 1 AND a.[AgentCode] IN (SELECT [AgentCode] FROM #Agents)) 
  AND   a.[ReportMonth] BETWEEN DATEADD(m,(@NumberOfMonths-1)*-1,@ReportMonth) AND @ReportMonth

end
else if @CascadeSelection = 0 and @AgentCode <> 'ALL'
begin
  INSERT #Results
  SELECT a.*
        ,ag.[Descn] as [AgentName]
        ,c.[CategoryOfBusiness]
        ,c.[CategoryOfBusinessLongDescription]
        ,c.[CategoryOfBusinessSequence]
        ,IsNull(t1.[TargetValue],0)/100 as [SATargetPct]
        ,IsNull(t2.[TargetValue],0)/100 as [CQTargetPct]
        ,IsNull(t3.[TargetValue],0) as [RejectTargetNum]
        ,IsNull(t4.[TargetValue],0)/100 as [RejectTargetPct]
        ,corp.[SAKPIPercent] AS [CorpSAKPIPercent]
        ,corp.[SuitableAdviceFailures] AS [CorpSuitableAdviceFailures]
        ,corp.[CQKPIPercent] AS [CorpCQKPIPercent]
        ,corp.[CompletionFailures] AS [CorpCompletionFailures]
        ,corp.[ComplaintQty] AS [CorpComplaintQty]
        ,corp.[CasesSubmitted] AS [CorpCasesSubmitted]
        ,corp.[CasesAssessed] AS [CorpCasesAssessed]
        ,corp.[Replacements] AS [CorpReplacements]
        ,corp.[ReplacementKPIPercent] AS [CorpReplacementKPIPercent]
        ,corp.[Rejects] AS [CorpRejects]
        ,corp.[RejectKPIPercent] AS [CorpRejectKPIPercent]
  FROM  [msv_AgentQualityAggregation] a 
        LEFT JOIN [mstt_Agents] ag on a.[AgentCode] = ag.[Code]
        LEFT JOIN [msv_CategoryOfBusiness] c ON a.[ComplianceCategoryCode] = c.[ComplianceCategoryCode]
        LEFT JOIN [msv_AgentQualityAggregation] corp ON a.[ComplianceCategoryCode] = corp.[ComplianceCategoryCode]
        AND a.[ReportMonth] = corp.[ReportMonth]
        AND a.[SummaryPeriod] = corp.[SummaryPeriod]
        AND corp.[KPILevel] = 'CORP'
        AND corp.[HierarchyTypeCode] = 'KPI' --Corporate does not differentiate between span affecting and current
        LEFT JOIN mstt_QualityTarget t1 ON a.[ComplianceCategoryCode] = t1.[ComplianceCategoryCode] 
        AND a.[ReportMonth] BETWEEN t1.[EffectiveDate] AND t1.[EndDate]
        AND t1.[KPILevel] = 'All'
        AND t1.[QualityTargetTypeCode] = 'Benchmark'
        AND t1.[QualityTargetPurposeCode] = 'SA' 
        AND t1.[TargetValueTypeCode] = 'P'
        AND a.[SummaryPeriod] = 1 --Only Join to SingleMonth aggregate to avoid multiplying targets
        LEFT JOIN mstt_QualityTarget t2 ON a.[ComplianceCategoryCode] = t2.[ComplianceCategoryCode] 
        AND a.[ReportMonth] BETWEEN t2.[EffectiveDate] AND t2.[EndDate]
        AND t2.[KPILevel] = 'All'
        AND t2.[QualityTargetTypeCode] = 'Benchmark'
        AND t2.[QualityTargetPurposeCode] = 'CQ' 
        AND t2.[TargetValueTypeCode] = 'P' 
        AND a.[SummaryPeriod] = 1 --Only Join to SingleMonth aggregate to avoid multiplying targets
        LEFT JOIN mstt_QualityTarget t3 ON a.[ComplianceCategoryCode] = t3.[ComplianceCategoryCode] 
        AND a.[ReportMonth] BETWEEN t3.[EffectiveDate] AND t3.[EndDate]
        AND t3.[KPILevel] = 'All'
        AND t3.[QualityTargetTypeCode] = 'Benchmark'
        AND t3.[QualityTargetPurposeCode] = 'Reject' 
        AND t3.[TargetValueTypeCode] = 'N' 
        AND a.[SummaryPeriod] = 1 --Only Join to SingleMonth aggregate to avoid multiplying targets
        LEFT JOIN mstt_QualityTarget t4 ON a.[ComplianceCategoryCode] = t4.[ComplianceCategoryCode] 
        AND a.[ReportMonth] BETWEEN t4.[EffectiveDate] AND t4.[EndDate]
        AND t4.[KPILevel] = 'CORP'
        AND t4.[QualityTargetTypeCode] = 'Benchmark'
        AND t4.[QualityTargetPurposeCode] = 'Reject' 
        AND t4.[TargetValueTypeCode] = 'P' 
        AND a.[SummaryPeriod] = 1 --Only Join to SingleMonth aggregate to avoid multiplying targets
  WHERE a.[KPILevel] = @KPILevel --ADVISER, PS, SQM, RSM, ASQM, ASD (Agents may have mulitple levels e.g. selling RSM)
  AND   a.[HierarchyTypeCode] = @HierarchyTypeCode --KPI or CURRENT (KPI is span affecting, at some levels KPI and CURRENT are the same so only KPI exists)
  AND   (@CascadeSelection = 0 AND a.[AgentCode] = convert(varchar(50),@AgentCode))
  AND   a.[ReportMonth] BETWEEN DATEADD(m,(@NumberOfMonths-1)*-1,@ReportMonth) AND @ReportMonth

end
else if @AgentCode = 'ALL'
begin
  INSERT #Results
  SELECT a.*
        ,ag.[Descn] as [AgentName]
        ,c.[CategoryOfBusiness]
        ,c.[CategoryOfBusinessLongDescription]
        ,c.[CategoryOfBusinessSequence]
        ,IsNull(t1.[TargetValue],0)/100 as [SATargetPct]
        ,IsNull(t2.[TargetValue],0)/100 as [CQTargetPct]
        ,IsNull(t3.[TargetValue],0) as [RejectTargetNum]
        ,IsNull(t4.[TargetValue],0)/100 as [RejectTargetPct]
        ,corp.[SAKPIPercent] AS [CorpSAKPIPercent]
        ,corp.[SuitableAdviceFailures] AS [CorpSuitableAdviceFailures]
        ,corp.[CQKPIPercent] AS [CorpCQKPIPercent]
        ,corp.[CompletionFailures] AS [CorpCompletionFailures]
        ,corp.[ComplaintQty] AS [CorpComplaintQty]
        ,corp.[CasesSubmitted] AS [CorpCasesSubmitted]
        ,corp.[CasesAssessed] AS [CorpCasesAssessed]
        ,corp.[Replacements] AS [CorpReplacements]
        ,corp.[ReplacementKPIPercent] AS [CorpReplacementKPIPercent]
        ,corp.[Rejects] AS [CorpRejects]
        ,corp.[RejectKPIPercent] AS [CorpRejectKPIPercent]
  FROM  [msv_AgentQualityAggregation] a 
        LEFT JOIN [mstt_Agents] ag on a.[AgentCode] = ag.[Code]
        LEFT JOIN [msv_CategoryOfBusiness] c ON a.[ComplianceCategoryCode] = c.[ComplianceCategoryCode]
        LEFT JOIN [msv_AgentQualityAggregation] corp ON a.[ComplianceCategoryCode] = corp.[ComplianceCategoryCode]
        AND a.[ReportMonth] = corp.[ReportMonth]
        AND a.[SummaryPeriod] = corp.[SummaryPeriod]
        AND corp.[KPILevel] = 'CORP'
        AND corp.[HierarchyTypeCode] = 'KPI' --Corporate does not differentiate between span affecting and current
        LEFT JOIN mstt_QualityTarget t1 ON a.[ComplianceCategoryCode] = t1.[ComplianceCategoryCode] 
        AND a.[ReportMonth] BETWEEN t1.[EffectiveDate] AND t1.[EndDate]
        AND t1.[KPILevel] = 'All'
        AND t1.[QualityTargetTypeCode] = 'Benchmark'
        AND t1.[QualityTargetPurposeCode] = 'SA' 
        AND t1.[TargetValueTypeCode] = 'P'
        AND a.[SummaryPeriod] = 1 --Only Join to SingleMonth aggregate to avoid multiplying targets
        LEFT JOIN mstt_QualityTarget t2 ON a.[ComplianceCategoryCode] = t2.[ComplianceCategoryCode] 
        AND a.[ReportMonth] BETWEEN t2.[EffectiveDate] AND t2.[EndDate]
        AND t2.[KPILevel] = 'All'
        AND t2.[QualityTargetTypeCode] = 'Benchmark'
        AND t2.[QualityTargetPurposeCode] = 'CQ' 
        AND t2.[TargetValueTypeCode] = 'P' 
        AND a.[SummaryPeriod] = 1 --Only Join to SingleMonth aggregate to avoid multiplying targets
        LEFT JOIN mstt_QualityTarget t3 ON a.[ComplianceCategoryCode] = t3.[ComplianceCategoryCode] 
        AND a.[ReportMonth] BETWEEN t3.[EffectiveDate] AND t3.[EndDate]
        AND t3.[KPILevel] = 'All'
        AND t3.[QualityTargetTypeCode] = 'Benchmark'
        AND t3.[QualityTargetPurposeCode] = 'Reject' 
        AND t3.[TargetValueTypeCode] = 'N' 
        AND a.[SummaryPeriod] = 1 --Only Join to SingleMonth aggregate to avoid multiplying targets
        LEFT JOIN mstt_QualityTarget t4 ON a.[ComplianceCategoryCode] = t4.[ComplianceCategoryCode] 
        AND a.[ReportMonth] BETWEEN t4.[EffectiveDate] AND t4.[EndDate]
        AND t4.[KPILevel] = 'CORP'
        AND t4.[QualityTargetTypeCode] = 'Benchmark'
        AND t4.[QualityTargetPurposeCode] = 'Reject' 
        AND t4.[TargetValueTypeCode] = 'P' 
        AND a.[SummaryPeriod] = 1 --Only Join to SingleMonth aggregate to avoid multiplying targets
  WHERE a.[KPILevel] = @KPILevel --ADVISER, PS, SQM, RSM, ASQM, ASD (Agents may have mulitple levels e.g. selling RSM)
  AND   a.[HierarchyTypeCode] = @HierarchyTypeCode --KPI or CURRENT (KPI is span affecting, at some levels KPI and CURRENT are the same so only KPI exists)
  AND   @AgentCode = 'ALL'
  AND   a.[ReportMonth] BETWEEN DATEADD(m,(@NumberOfMonths-1)*-1,@ReportMonth) AND @ReportMonth

end



SELECT [AgentCode]
      ,[AgentName]
      ,[KPILevel]
      ,[HierarchyTypeCode]
      ,[ReportMonth]
      ,[ComplianceCategoryCode]
      ,[CategoryOfBusiness]
      ,[CategoryOfBusinessLongDescription]
      ,[CategoryOfBusinessSequence]
      ,SUM(CASE WHEN [SummaryPeriod] = 6 THEN [SAKPIPercent] ELSE 0 END) as [SAKPIPercentRolling6Month]
      ,SUM(CASE WHEN [SummaryPeriod] = 6 THEN [SuitableAdviceFailures] ELSE 0 END) as [SuitableAdviceFailuresRolling6Month]
      ,SUM(CASE WHEN [SummaryPeriod] = 6 THEN [CQKPIPercent] ELSE 0 END) as [CQKPIPercentRolling6Month]
      ,SUM(CASE WHEN [SummaryPeriod] = 6 THEN [CompletionFailures] ELSE 0 END) as [CompletionFailuresRolling6Month]
      ,SUM(CASE WHEN [SummaryPeriod] = 6 THEN [ComplaintQty] ELSE 0 END) as [ComplaintQtyRolling6Month]
      ,SUM(CASE WHEN [SummaryPeriod] = 1 THEN [CasesSubmitted] ELSE 0 END) as [CasesSubmittedSingleMonth]
      ,SUM(CASE WHEN [SummaryPeriod] = 1 THEN [CasesAssessed] ELSE 0 END) as [CasesAssessedSingleMonth]
      ,SUM(CASE WHEN [SummaryPeriod] = 1 THEN [SAKPIPercent] ELSE 0 END) as [SAKPIPercentSingleMonth]
      ,SUM(CASE WHEN [SummaryPeriod] = 1 THEN [SuitableAdviceFailures] ELSE 0 END) as [SuitableAdviceFailuresSingleMonth]
      ,SUM(CASE WHEN [SummaryPeriod] = 1 THEN [CQKPIPercent] ELSE 0 END) as [CQKPIPercentSingleMonth]
      ,SUM(CASE WHEN [SummaryPeriod] = 1 THEN [CompletionFailures] ELSE 0 END) as [CompletionFailuresSingleMonth]
      ,SUM(CASE WHEN [SummaryPeriod] = 1 THEN [Replacements] ELSE 0 END) as [ReplacementsSingleMonth]
      ,SUM(CASE WHEN [SummaryPeriod] = 1 THEN [ReplacementKPIPercent] ELSE 0 END) as [ReplacementKPIPercentSingleMonth]
      ,SUM(CASE WHEN [SummaryPeriod] = 1 THEN [Rejects] ELSE 0 END) as [RejectsSingleMonth]
      ,SUM(CASE WHEN [SummaryPeriod] = 1 THEN [RejectKPIPercent] ELSE 0 END) as [RejectKPIPercentSingleMonth]
      ,SUM([SATargetPct]) as [SATargetPct]
      ,SUM([CQTargetPct]) as [CQTargetPct]
      ,SUM([RejectTargetNum]) as [RejectTargetNum]
      ,SUM([RejectTargetPct]) as [RejectTargetPct]
      ,SUM(CASE WHEN [SummaryPeriod] = 6 THEN [CorpSAKPIPercent] ELSE 0 END) as [CorpSAKPIPercentRolling6Month]
      ,SUM(CASE WHEN [SummaryPeriod] = 6 THEN [CorpSuitableAdviceFailures] ELSE 0 END) as [CorpSuitableAdviceFailuresRolling6Month]
      ,SUM(CASE WHEN [SummaryPeriod] = 6 THEN [CorpCQKPIPercent] ELSE 0 END) as [CorpCQKPIPercentRolling6Month]
      ,SUM(CASE WHEN [SummaryPeriod] = 6 THEN [CorpCompletionFailures] ELSE 0 END) as [CorpCompletionFailuresRolling6Month]
      ,SUM(CASE WHEN [SummaryPeriod] = 6 THEN [CorpComplaintQty] ELSE 0 END) as [CorpComplaintQtyRolling6Month]
      ,SUM(CASE WHEN [SummaryPeriod] = 1 THEN [CorpCasesSubmitted] ELSE 0 END) as [CorpCasesSubmittedSingleMonth]
      ,SUM(CASE WHEN [SummaryPeriod] = 1 THEN [CorpCasesAssessed] ELSE 0 END) as [CorpCasesAssessedSingleMonth]
      ,SUM(CASE WHEN [SummaryPeriod] = 1 THEN [CorpSAKPIPercent] ELSE 0 END) as [CorpSAKPIPercentSingleMonth]
      ,SUM(CASE WHEN [SummaryPeriod] = 1 THEN [CorpSuitableAdviceFailures] ELSE 0 END) as [CorpSuitableAdviceFailuresSingleMonth]
      ,SUM(CASE WHEN [SummaryPeriod] = 1 THEN [CorpCQKPIPercent] ELSE 0 END) as [CorpCQKPIPercentSingleMonth]
      ,SUM(CASE WHEN [SummaryPeriod] = 1 THEN [CorpCompletionFailures] ELSE 0 END) as [CorpCompletionFailuresSingleMonth]
      ,SUM(CASE WHEN [SummaryPeriod] = 1 THEN [CorpReplacements] ELSE 0 END) as [CorpReplacementsSingleMonth]
      ,SUM(CASE WHEN [SummaryPeriod] = 1 THEN [CorpReplacementKPIPercent] ELSE 0 END) as [CorpReplacementKPIPercentSingleMonth]
      ,SUM(CASE WHEN [SummaryPeriod] = 1 THEN [CorpRejects] ELSE 0 END) as [CorpRejectsSingleMonth]
      ,SUM(CASE WHEN [SummaryPeriod] = 1 THEN [CorpRejectKPIPercent] ELSE 0 END) as [CorpRejectKPIPercentSingleMonth]
FROM  #Results
GROUP BY
       [AgentCode]
      ,[AgentName]
      ,[KPILevel]
      ,[HierarchyTypeCode]
      ,[ReportMonth]
      ,[ComplianceCategoryCode]
      ,[CategoryOfBusiness]
      ,[CategoryOfBusinessLongDescription]
      ,[CategoryOfBusinessSequence]
UNION
--Union with Targets for next month
SELECT '' AS [AgentCode]
      ,'' AS [AgentName]
      ,'' AS [KPILevel]
      ,'' AS [HierarchyTypeCode]
      ,c.[FutureMonth] AS [ReportMonth]
      ,c.[ComplianceCategoryCode] AS [ComplianceCategoryCode]
      ,[CategoryOfBusiness]
      ,[CategoryOfBusinessLongDescription]
      ,[CategoryOfBusinessSequence]
      ,NULL AS [SAKPIPercentRolling6Month]
      ,NULL AS [SuitableAdviceFailuresRolling6Month]
      ,NULL AS [CQKPIPercentRolling6Month]
      ,NULL AS [CompletionFailuresRolling6Month]
      ,NULL AS [ComplaintQtyRolling6Month]
      ,NULL AS [CasesSubmittedSingleMonth]
      ,NULL AS [CasesAssessedSingleMonth]
      ,NULL AS [SAKPIPercentSingleMonth]
      ,NULL AS [SuitableAdviceFailuresSingleMonth]
      ,NULL AS [CQKPIPercentSingleMonth]
      ,NULL AS [CompletionFailuresSingleMonth]
      ,NULL AS [ReplacementsSingleMonth]
      ,NULL AS [ReplacementKPIPercentSingleMonth]
      ,NULL AS [RejectsSingleMonth]
      ,NULL AS [RejectKPIPercentSingleMonth]
      ,IsNull(t1.[TargetValue],0)/100 as [SATargetPct]
      ,IsNull(t2.[TargetValue],0)/100 as [CQTargetPct]
      ,IsNull(t3.[TargetValue],0) as [RejectTargetNum]
      ,IsNull(t4.[TargetValue],0)/100 as [RejectTargetPct]
      ,NULL as [CorpSAKPIPercentRolling6Month]
      ,NULL as [CorpSuitableAdviceFailuresRolling6Month]
      ,NULL as [CorpCQKPIPercentRolling6Month]
      ,NULL as [CorpCompletionFailuresRolling6Month]
      ,NULL as [CorpComplaintQtyRolling6Month]
      ,NULL as [CorpCasesSubmittedSingleMonth]
      ,NULL as [CorpCasesAssessedSingleMonth]
      ,NULL AS [CorpSAKPIPercentSingleMonth]
      ,NULL as [CorpSuitableAdviceFailuresSingleMonth]
      ,NULL AS [CorpCQKPIPercentSingleMonth]
      ,NULL as [CorpCompletionFailuresSingleMonth]
      ,NULL as [CorpReplacementsSingleMonth]
      ,NULL as [CorpReplacementKPIPercentSingleMonth]
      ,NULL as [CorpRejectsSingleMonth]
      ,NULL as [CorpRejectKPIPercentSingleMonth]
FROM  (SELECT *, (SELECT DATEADD(m,1,MAX([ReportMonth])) 
                  FROM mstt_AgentQualityAggregation
                  WHERE [ReportMonth] <= @ReportMonth) AS [FutureMonth] 
       FROM [msv_CategoryOfBusiness]) c
      LEFT JOIN mstt_QualityTarget t1 ON c.[ComplianceCategoryCode] = t1.[ComplianceCategoryCode] 
      AND [FutureMonth] BETWEEN t1.[EffectiveDate] AND t1.[EndDate]
      AND t1.[KPILevel] = 'All'
      AND t1.[QualityTargetTypeCode] = 'Benchmark'
      AND t1.[QualityTargetPurposeCode] = 'SA' 
      AND t1.[TargetValueTypeCode] = 'P'
      LEFT JOIN mstt_QualityTarget t2 ON c.[ComplianceCategoryCode] = t2.[ComplianceCategoryCode] 
      AND [FutureMonth] BETWEEN t2.[EffectiveDate] AND t2.[EndDate]
      AND t2.[KPILevel] = 'All'
      AND t2.[QualityTargetTypeCode] = 'Benchmark'
      AND t2.[QualityTargetPurposeCode] = 'CQ' 
      AND t2.[TargetValueTypeCode] = 'P' 
      LEFT JOIN mstt_QualityTarget t3 ON c.[ComplianceCategoryCode] = t3.[ComplianceCategoryCode] 
      AND [FutureMonth] BETWEEN t3.[EffectiveDate] AND t3.[EndDate]
      AND t3.[KPILevel] = 'All'
      AND t3.[QualityTargetTypeCode] = 'Benchmark'
      AND t3.[QualityTargetPurposeCode] = 'Reject' 
      AND t3.[TargetValueTypeCode] = 'N'
      LEFT JOIN mstt_QualityTarget t4 ON c.[ComplianceCategoryCode] = t4.[ComplianceCategoryCode] 
      AND [FutureMonth] BETWEEN t4.[EffectiveDate] AND t4.[EndDate]
      AND t4.[KPILevel] = 'CORP'
      AND t4.[QualityTargetTypeCode] = 'Benchmark'
      AND t4.[QualityTargetPurposeCode] = 'Reject' 
      AND t4.[TargetValueTypeCode] = 'P' 
ORDER BY [ReportMonth]

end






GO
