CREATE Procedure [dbo].[msp_SelectAgentsOnChecking]
  @ComplianceCategoryCode as Varchar(50),
  @SummaryPeriod as integer
AS

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2006 All rights reserved
--
-- Object  : procedure
-- Name    : msp_SelectAgentsOnChecking.sql
-- Desc    : Returns Agents Where Flagged for Checking or Outside Targets
-- Owner   : JNHL
-- Created : 26/07/2006
--
-- Amended : 03/08/2006  - Simplified the Procedure and Added 
--              Report Month Local Paramater
--       : 09/08/2006 Added KPILevel<>CORP 
--########################################################################

  ------ TEST DATA
  --Declare @ComplianceCategoryCode as Varchar(50)
  --Declare @SummaryPeriod as integer
  --Set @ComplianceCategoryCode='COB'
  --Set @SummaryPeriod=6
  ------

  -- Local Variables
  DECLARE @ReportMonth AS DATETIME

  --Get Report Month
  SELECT @ReportMonth=MAX(ReportMonth) 
  FROM mstt_AgentQualityAggregation
  WHERE KPILevel= 'ADVISERKPI'

  --Pivots Quality Targets into Flat Table
  SELECT 
    KPILevel,
    ComplianceCategoryCode,
    QualityTargetTypeCode,
    TargetValue AS SATarget,
    (SELECT 
      TargetValue AS CQTarget
      FROM mstt_QualityTarget
        WHERE
          KPILevel='ALL'
          AND ComplianceCategoryCode=QT.ComplianceCategoryCode
          AND QualityTargetPurposeCode='CQ'
          AND QualityTargetTypeCode='BENCHMARK') CQTarget,
    (SELECT 
      TargetValue AS RejectTarget
      FROM mstt_QualityTarget
        WHERE
          KPILevel='ALL'
          AND ComplianceCategoryCode=QT.ComplianceCategoryCode
          AND QualityTargetPurposeCode='Reject'
          AND QualityTargetTypeCode='BENCHMARK') RejectTarget
  INTO #tmp_QualityTargets
  FROM 
    mstt_QualityTarget QT
  WHERE
    KPILevel='ALL'
    AND QualityTargetPurposeCode='SA'
    AND QualityTargetTypeCode='BENCHMARK'

  --Extract Agent Over BenchMarks or on Monitor
  SELECT DISTINCT 
    Agents.CODE AS AgentCode, 
    Agents.DESCN AS AgentName, 
    AC.PercentageMon, 
    AC.EntryStatusCode, 
    QT.ComplianceCategoryCode, 
    QT.SATarget, 
    AQA.SAKPIPercent, 
    QT.CQTarget,
    AQA.CQKPIPercent, 
    AQA.SummaryPeriod, 
    ISNULL(QM.CODE, 'N/A')AS QMCode, 
    ISNULL(QM.DESCN, 'N/A') AS QMName
  FROM         
    mstt_AgentQualityAggregation AQA 
    INNER JOIN mstt_AgentCompetence AC 
      ON AQA.AgentCode = AC.AgentCode 
        AND AC.ComplianceCategoryCode=@ComplianceCategoryCode
        AND @ReportMonth Between AchievedDate And IsNULL(EndDate,GetDAte())
    INNER JOIN mstt_Agents Agents 
      ON AQA.AgentCode = Agents.CODE 
    INNER JOIN #tmp_QualityTargets QT 
      ON QT.ComplianceCategoryCode = AQA.ComplianceCategoryCode
    INNER JOIN mstt_AgentQualityHierarchy AQH 
      ON AQH.AgentCode = Agents.CODE 
    LEFT OUTER JOIN mstt_Agents QM 
      ON QM.CODE = AQH.SalesQualitySQMLevelCode
  WHERE     
    (QT.KPILevel = 'All') 
    AND (AQA.SummaryPeriod = @SummaryPeriod) 
    AND (QT.ComplianceCategoryCode = @ComplianceCategoryCode) 
    AND (AQH.IsCurrent = 1)
    AND AQA.ReportMonth=@ReportMonth
    AND AQA.KPILevel='ADVISERKPI'
    AND (AQA.SAKPIPercent * 100.00 >= SATarget * 3
        OR AQA.CQKPIPercent*100>= CQTarget * 3
        OR AC.PercentageMon = 1 
        OR AC.EntryStatusCode IN ('INE', 'ENE'))



GO
