CREATE PROCEDURE [dbo].[msp_SelectAgentTransfers]
  @UserId VARCHAR(20), --current User Id
  @ReportType VARCHAR(20),
  @AgentType VARCHAR(20)
AS

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2006 All rights reserved
--
-- Object  : procedure
-- Name    : msp_SelectAgentTransfers
-- Desc    : Selects Agetns Transfered From or To a Supervisor
-- Owner   : JNHL
-- Created : 02/08/2006
--
-- Amended : 07/08/2006 - JL - Added Extra Parameter 
--            - JL - Added Code to return Dummy Data if no data found
--       : 09/08/2006 - JL - Added KPILevel<>CORP 
--       : 24/08/2006 - JL - Added New Param Agent Type (SQM or PS)
--########################################################################



  --- SP PARAMETERS Variables Normally Passed in Query
  --DECLARE @UserId VARCHAR(20) --current User Id
  --DECLARE @ReportType VARCHAR(20)
  --- Variables required in 

  -------TESTING Parameters
  --SET @UserId='ptl90299' 
  --SET @ReportType='Leaving'
  ------- 

  --Local Vars
  DECLARE @AgentCode AS VARCHAR(20)
  DECLARE @ReportMonth AS DATETIME
  DECLARE @ReportStart AS DATETIME 
  DECLARE @StrippedUserId VARCHAR(20) --current User Id
  DECLARE @SummaryPeriod AS INT
  
  --Get the Current reporting Month
  SELECT @ReportMonth=MAX(ReportMonth) 
  FROM mstt_AgentQualityAggregation
  WHERE KPILevel= 'ADVISERKPI'

  SET @AgentCode=@UserId

  --Create Table Variable for Current Hierarcy
  DECLARE @AgentHierarchy TABLE 
    (AgentHierarchyId INT,
      AgentHierarchyDate DATETIME,
      HierarchyLevel VARCHAR(10),
      AdvisorCode VARCHAR(20),
      PSCode VARCHAR(20),
      SQMCode VARCHAR(20),
      RSMCode VARCHAR(20),
      ASDCode VARCHAR(20))

  CREATE TABLE #tmp_Transfers(
      AdvisorCode VARCHAR(20)
    , AdvisorName VARCHAR(40)
    , AgentHierarchyDate DATETIME
    , CurrentSupervisor VARCHAR(20)
    , CurrentSupervisorName VARCHAR(40)
    , PreviousSupervisor VARCHAR(20)
    , PreviousSupervisorName VARCHAR(40)
  )

  SET @SummaryPeriod=6
    
    
  -- Advisors joining Hierarchy
  IF UPPER(@ReportType)='JOINING'
  BEGIN
    --Get the Current Reporting Agent hierarchy
    INSERT INTO 
      @AgentHierarchy
    SELECT 
        AgentHierarchyId
      , AgentHierarchyStartDate
      , @AgentType
      , AgentCode 
      , SalesQualityPSLevelCode
      , SalesQualitySQMLevelCode
      , SalesQualityRSMLevelCode
      , SalesQualityASDLevelCode
    FROM mstt_AgentQualityHierarchy
    WHERE 
      CASE @AgentType
        --SQM
        WHEN 'SQM' THEN SalesQualitySQMLevelCode
        --Practice Manager
        WHEN 'PS' THEN SalesQualityPSLevelCode
      END = @AgentCode
    AND IsCurrent=1
    AND AgentHierarchyStartDate>DateAdd(M,-@SummaryPeriod,@ReportMonth)

    --Get Previous 
    INSERT INTO 
      #tmp_Transfers
    SELECT 
        AdvisorCode
      , Advisor.Descn AdvisorName 
      , CAH.AgentHierarchyDate
      , CASE HierarchyLevel
          WHEN 'SQM' THEN SQMCode
          WHEN 'PS' THEN PSCode
        END CurrentSupervisor
      , CurrentSupervisor.Descn CurrentSupervisorName 
      , CASE HierarchyLevel
          WHEN 'SQM' THEN SQMCode
          WHEN 'PS' THEN PSCode
      End PreviousSupervisor
      , PreviousSupervisor.Descn PreviousSupervisorName     
    FROM mstt_AgentQualityHierarchy AQH
      JOIN @AgentHierarchy CAH
        ON AdvisorCode=AgentCode
          AND CASE HierarchyLevel
              WHEN 'SQM' THEN SQMCode
              WHEN 'PS' THEN PSCode
            END <> CASE HierarchyLevel
                  WHEN 'SQM' THEN SalesQualitySQMLevelCode
                  WHEN 'PS' THEN SalesQualityPSLevelCode
                END
      JOIN mstt_Agents Advisor
        ON Advisor.Code=AdvisorCode
      JOIN mstt_Agents CurrentSupervisor
        ON CurrentSupervisor.Code=CASE HierarchyLevel
                        WHEN 'SQM' THEN SalesQualitySQMLevelCode
                        WHEN 'PS' THEN SalesQualityPSLevelCode
                      END
      JOIN mstt_Agents PreviousSupervisor
        ON PreviousSupervisor.Code=CASE HierarchyLevel
                        WHEN 'SQM' THEN SalesQualitySQMLevelCode
                        WHEN 'PS' THEN SalesQualityPSLevelCode
                      END
    WHERE 
      AgentHierarchyEndDate=DateADD(D,-1,CAH.AgentHierarchyDate)
      
  END
  --Agent Leaving Hierarchy
  ELSE
  BEGIN
  -- Advisors joining Hierarchy
    IF UPPER(@ReportType)='LEAVING'
    BEGIN
      --Get the Current Reporting Agent hierarchy
      INSERT INTO 
        @AgentHierarchy
      SELECT 
          AgentHierarchyId
        , AgentHierarchyEndDate
        , @AgentType  
        , AgentCode 
        , SalesQualityPSLevelCode
        , SalesQualitySQMLevelCode
        , SalesQualityRSMLevelCode
        , SalesQualityASDLevelCode
      FROM mstt_AgentQualityHierarchy
      WHERE 
        CASE @AgentType
          --SQM
          WHEN 'SQM' THEN SalesQualitySQMLevelCode
          --Practice Manager
          WHEN 'PS' THEN SalesQualityPSLevelCode
        END = @AgentCode
      AND IsCurrent=0
      AND AgentHierarchyEndDate>DateAdd(M,-@SummaryPeriod,@ReportMonth)

      --Get Previous 
      INSERT INTO 
        #tmp_Transfers
      SELECT 
          AdvisorCode
        , Advisor.Descn AdvisorName 
        , PAH.AgentHierarchyDate
        , CASE HierarchyLevel
            WHEN 'SQM' THEN SQMCode
            WHEN 'PS' THEN PSCode
          END CurrentSupervisor
        , CurrentSupervisor.Descn CurrentSupervisorName 
        , CASE HierarchyLevel
            WHEN 'SQM' THEN SQMCode
            WHEN 'PS' THEN PSCode
        End PreviousSupervisor  
        , PreviousSupervisor.Descn PreviousSupervisorName 
      FROM mstt_AgentQualityHierarchy AQH
        JOIN @AgentHierarchy PAH
          ON AdvisorCode=AgentCode
            AND CASE HierarchyLevel
                WHEN 'SQM' THEN SQMCode
                WHEN 'PS' THEN PSCode
              END <> CASE HierarchyLevel
                    WHEN 'SQM' THEN SalesQualitySQMLevelCode
                    WHEN 'PS' THEN SalesQualityPSLevelCode
                END

        JOIN mstt_Agents Advisor
          ON Advisor.Code=AdvisorCode
        JOIN mstt_Agents CurrentSupervisor
          ON CurrentSupervisor.Code=CASE HierarchyLevel
                          WHEN 'SQM' THEN SalesQualitySQMLevelCode
                          WHEN 'PS' THEN SalesQualityPSLevelCode
                        END
        JOIN mstt_Agents PreviousSupervisor
          ON PreviousSupervisor.Code=CASE HierarchyLevel
                          WHEN 'SQM' THEN SalesQualitySQMLevelCode
                          WHEN 'PS' THEN SalesQualityPSLevelCode
                        END
      WHERE
        AQH.AgentHierarchyStartDate=DateADD(D,1,PAH.AgentHierarchyDate)
      
    END 
  END 


  Select * From #tmp_Transfers  
    

GO
