CREATE PROCEDURE [dbo].[msp_SelectAverageTurnover] -- WITH RECOMPILE,ENCRYPTION
  @Measure nvarchar (50),
  @Comparison nvarchar (50),
  @ProductGroup nvarchar (50),
  @Level nvarchar (50),
  @Size nvarchar(50),
  @UserId nvarchar(50),
  @Area nvarchar(50),
  @Region nvarchar(50)
AS
/******************************************************************************
Copyright (C) Moore Stephens Consulting Limited 2005
Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>
select * from msdt_FranchiseSize
select * from mst_averageturnover where level = 'franchise'
select * from msft_capacityterminationcounts where adviserid=10000018
*******************************************************************************/
declare @Franchise int
set
 @Franchise = (select sum(c.Val)
from 
 msft_capacityterminationcounts c,
 msdt_FranchiseSize f,
 msct_UserAccessControl uac
where
 c.StatusDate between dateadd(mm,-12,getdate()) and getdate() and
 c.Level = 'Franchise' and
 c.ReportType = 'Capacity' and
 f.FranchiseSizeId = c.FranchiseSizeId and
 f.FranchiseSizeType like @Size and
 c.AdviserId = uac.AdviserId and
 uac.DomainLogin = @UserId)
declare @Adviser int
set 
 @Adviser = (select sum(c.Val)
from 
 msft_capacityterminationcounts c,
 msdt_FranchiseSize f,
 msct_UserAccessControl uac
where
 c.StatusDate between dateadd(mm,-12,getdate()) and getdate() and
 c.Level = 'Adviser' and
 c.ReportType = 'Capacity' and
 f.FranchiseSizeId = c.FranchiseSizeId and
 f.FranchiseSizeType like @Size and
 c.AdviserId = uac.AdviserId and
 uac.DomainLogin = @UserId)
declare @FranchiseP int
set 
 @FranchiseP = (select sum(c.Val)
from
 msft_capacityterminationcounts c,
 msdt_FranchiseSize f,
 msct_UserAccessControl uac
where
 c.StatusDate between dateadd(mm,-24,getdate()) and dateadd(mm,-12,getdate()) and
 c.Level = 'Franchise' and
 c.ReportType = 'Capacity' and
 f.FranchiseSizeId = c.FranchiseSizeId and
 f.FranchiseSizeType like @Size and
 c.AdviserId = uac.AdviserId and
 uac.DomainLogin = @UserId)
declare @AdviserP int
set @AdviserP = (select sum(c.Val)
from
 msft_capacityterminationcounts c,
 msdt_FranchiseSize f,
 msct_UserAccessControl uac
where
 c.StatusDate between dateadd(mm,-24,getdate()) and dateadd(mm,-12,getdate()) and
 c.Level = 'Adviser' and
 c.ReportType = 'Capacity' and
 f.FranchiseSizeId = c.FranchiseSizeId and
 f.FranchiseSizeType like @Size and
 c.AdviserId = uac.AdviserId and
 uac.DomainLogin = @UserId)
select
 x.[Month],
 x.[Order],
 sum(case when x.[Type] = 'Actual' then x.[Amount] else '0' end) [Actual],
 sum(case when x.[Type] = 'Measure' then x.[Amount] else '0' end) [Comparison]
from
(
--current year actuals
select
'Actual' [Type],
 a.ProductGroup,
 a.Size,
left(datename(month,a.DateIssued),3) [Month],
month(a.DateIssued) [Order],
sum(case when a.dateissued between dateadd(mm,-12,getdate()) and getdate() then
         case when @Measure = 'Turnover' then a.Turnover
              when @Measure = 'No. of Cases' then a.Cases
              when @Measure = 'DA' then a.DA
              when @Measure = 'NBI' then a.NBI
              when @Measure = 'Sales Margin' then a.SalesMargin
         end
    end) / (case when @Level = 'Franchise' then @Franchise else @Adviser 
               end) [Amount]
from
mst_averageturnover a,
msct_UserAccessControl uac
where
 a.Area like @Area and
 a.Region like @Region and
 a.Size like @Size and
 a.ProductGroup like @ProductGroup and
 a.ComparisonId = '1' and
 a.AdviserId = uac.AdviserId and
 uac.DomainLogin = @UserId
group by
 a.ProductGroup,
 a.Size,
 left(datename(month,a.DateIssued),3),
 (a.DateIssued)
union
--Comparisons
select
'Measure' [Type],
 a.ProductGroup,
 a.Size,
left(datename(month,a.DateIssued),3) [Month],
month(a.DateIssued) [Order],
sum(case when a.dateissued between dateadd(mm,-12,getdate()) and getdate() then
         case when @Measure = 'Turnover' then a.Turnover
              when @Measure = 'No. of Cases' then a.Cases
              when @Measure = 'DA' then a.DA
              when @Measure = 'NBI' then a.NBI
              when @Measure = 'Sales Margin' then a.SalesMargin
         end
    end) / (case when @Level = 'Franchise' then @Franchise else @Adviser 
               end) [Amount]
from
mst_averageturnover a,
msct_UserAccessControl uac
where
 a.Area like @Area and
 a.Region like @Region and
 a.Size like @Size and
 a.ProductGroup like @ProductGroup and
 a.ComparisonId = @Comparison and
 a.AdviserId = uac.AdviserId and
 uac.DomainLogin = @UserId
group by
 a.ProductGroup,
 a.Size,
 left(datename(month,a.DateIssued),3),
 (a.DateIssued)
union
--previous year actuals
select
'Measure' [Type],
 a.ProductGroup,
 a.Size,
left(datename(month,a.DateIssued),3) [Month],
month(a.DateIssued) [Order],
sum(case when a.dateissued between dateadd(mm,-24,getdate()) and dateadd(mm,-12,getdate()) then
         case when @Measure = 'Turnover' then a.Turnover
              when @Measure = 'No. of Cases' then a.Cases
              when @Measure = 'DA' then a.DA
              when @Measure = 'NBI' then a.NBI
              when @Measure = 'Sales Margin' then a.SalesMargin
         end
    end) / (case when @Level = 'Franchise' then @FranchiseP else @AdviserP 
               end) [Amount]
from
 mst_averageturnover a,
 msct_UserAccessControl uac
where
 a.Area like @Area and
 a.Region like @Region and
 a.Size like @Size and
 a.ProductGroup like @ProductGroup and
 @Comparison = '-999' and
 a.AdviserId = uac.AdviserId and
 uac.DomainLogin = @UserId
group by
 a.ProductGroup,
 a.Size,
 left(datename(month,a.DateIssued),3),
 (a.DateIssued)
union
select
'Actual' [Type],
 '',
 '',
'Jan' [Month],
1 [Order],
0 [Amount]
union
select
'Actual' [Type],
 '',
 '',
'Feb' [Month],
2 [Order],
0 [Amount]
union
select
'Actual' [Type],
 '',
 '',
'Mar' [Month],
3 [Order],
0 [Amount]
union
select
'Actual' [Type],
 '',
 '',
'Apr' [Month],
4 [Order],
0 [Amount]
union
select
'Actual' [Type],
 '',
 '',
'May' [Month],
5 [Order],
0 [Amount]
union
select
'Actual' [Type],
 '',
 '',
'Jun' [Month],
6 [Order],
0 [Amount]
union
select
'Actual' [Type],
 '',
 '',
'Jul' [Month],
7 [Order],
0 [Amount]
union
select
'Actual' [Type],
 '',
 '',
'Aug' [Month],
8 [Order],
0 [Amount]
union
select
'Actual' [Type],
 '',
 '',
'Sep' [Month],
9 [Order],
0 [Amount]
union
select
'Actual' [Type],
 '',
 '',
'Oct' [Month],
10 [Order],
0 [Amount]
union
select
'Actual' [Type],
 '',
 '',
'Nov' [Month],
11 [Order],
0 [Amount]
union
select
'Actual' [Type],
 '',
 '',
'Dec' [Month],
12 [Order],
0 [Amount]
) x
-- where
--   x.ProductGroup like @ProductGroup --and
--   x.Size like @Size
group by
 x.[Month],
 x.[Order]
order by
2 asc

GO
