CREATE Procedure [dbo].[msp_SelectBusinessCategory]
AS 
  SELECT 
    '%' Value
    ,'~ALL~' Label
    , 1 SortOrder
  UNION SELECT 
    'COB' Value
    ,'Investment' Label
    ,2 SortOrder
  UNION SELECT 
    'MCOB' Value
    ,'Mortgage' Label
    ,3 SortOrder
  UNION SELECT 
    'ICOB-PP' Value
    ,'Pure Protection' Label
    ,4 SortOrder
  UNION SELECT 
    'ICOB-GI' Value
    ,'General Insurance' Label
    ,5 SortOrder
  ORDER BY SortOrder



