create procedure [dbo].[msp_SelectCasesAssessedAndReasonsForFailure]
    @AgentCode         nvarchar(50),
    @Role              nvarchar(50),  --Seller or Manager
    @Frequency         int,           --1 or 6 (months)
    @KPILevel          nvarchar(50)

as

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : msp_SelectCasesAssessedAndReasonsForFailure.sql
-- Desc    : 
-- Owner   : BT
-- Created : 03/07/2006
--
-- Amended : 06/07/2006  - KS  - To allow for managers and sellers, ie. returning more than 1 agent code
-- Amended : 13/07/2006  - BT  - Remove Audience & UserId parameters
--
--########################################################################

select distinct
  [AgentCode] = a.AgentCode
into #Agents
from
  msv_AgentQualityAggregation a
where
  a.reportmonth = (select max(reportmonth)
                   from msv_AgentQualityAggregation) and
  a.kpilevel in ('sqmSummary', 'pssummary') and
  a.HierarchyTypeCode = 'Current' and  --Only 1 month of data so don't need Parameter
  (case when @KPILevel = 'PSSummary' then a.SalesQualityPSLevelCode else a.SalesQualitySQMLevelCode end) = @AgentCode




SELECT a.[Code] AS [AgentCode]
      ,a.[Descn] AS [AgentName]
      ,c.[CLIENT_NUM] AS [ClientNum]
      ,c.[TITLE] + ' ' + c.[FIRSTNAMES] + ' ' + c.[NAME] AS [ClientName]
      ,p.[POL_NUM] AS [PolicyNum]
      ,p.[PolicyRef] AS [PolicyReference]
      ,p.[CreateDate] AS [PolicyCreateDate]
      ,p.[ProductCode]
      ,p.[Replacement]
      ,CASE WHEN p.[Replacement] = 0 THEN 'No' 
            WHEN p.[Replacement] IN (1,2,3) THEN 'Yes' 
            ELSE NULL END AS [IsAReplacement]
      ,CASE WHEN p.[Replacement] = 0 THEN 'N' 
            WHEN p.[Replacement] = 1 THEN 'A' 
            WHEN p.[Replacement] = 2 THEN 'B' 
            WHEN p.[Replacement] = 3 THEN 'C' 
            ELSE NULL END AS [ReplacementType]
      ,cc.[NBCCStatus] AS [CaseCheckStatus]
      ,cc.[NBCCReferralReasonCode] AS [CaseCheckReferralReasonCode]
      ,cc.[NBCCReferralReasonDesc] AS [CaseCheckReferralReasonDesc]
      ,cc.[CaseCheckValidatedDate]
      ,cc.[NBCCInitialFailureReasonCode] AS [CaseCheckInitialFailureReasonCode]
      ,cc.[NBCCInitialFailureReasonDesc] AS [CaseCheckInitialFailureReasonDesc]
      ,cc.[FinalCheckValidatedDate]
      ,cc.[NBCCFinalFailureReasonCode] AS [CaseCheckFinalFailureReasonCode]
      ,cc.[NBCCFinalFailureReasonDesc] AS [CaseCheckFinalFailureReasonDesc]
      ,'Dummy Question' AS [QuestionText] --Update once table Case Compliance Question has been built
      ,cc.[SalesQualityASDLevelCode]
      ,cc.[SalesQualityRSMLevelCode]
      ,cc.[SalesQualitySQMLevelCode]
      ,cc.[SalesQualityPSLevelCode]
      ,cc.[ComplianceCategoryCode]
      ,cofb.[CategoryOfBusiness]
      ,cofb.[CategoryOfBusinessSequence]
FROM [mstt_CaseCheck] cc
    INNER JOIN [mstt_Policies] p ON cc.[Policy_Id] = p.[POL_NUM]
    INNER JOIN [mstt_Clients] c ON cc.[ClientId] = c.[CLIENT_NUM]
    INNER JOIN [mstt_Agents] a on cc.[AgentCode] = a.[Code]
    INNER JOIN [msv_CategoryOfBusiness] cofb ON cc.[ComplianceCategoryCode] = cofb.[ComplianceCategoryCode]
WHERE ((@Role = 'Seller' and cc.[AgentCode] = @AgentCode)
      or
      (@Role = 'Manager' and cc.[AgentCode] in (select * from #Agents)))
  AND cc.[RequestedDate] > convert(nvarchar(6),dateadd(mm,case when @Frequency = 1 then -2 else -7 end,getdate()),112) + '01'
  AND cc.[RequestedDate] <=  convert(nvarchar(6),dateadd(mm,-1,getdate()),112) + '01'



drop table #Agents


GO
