Create Procedure [dbo].[msp_SelectConfidenceInterval]
  @ComplianceCategoryCode as Varchar(50),
  @KPILevel as varchar(50),
  @SummaryPeriod as Int
AS

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2006 All rights reserved
--
-- Object  : procedure
-- Name    : msp_SelectConfidenceInterval
-- Desc    : Extracts and Calculates the Confidence and CQ/SA KPI values.
-- Owner   : JNHL
-- Created : 26/07/2006
--
-- Amended : 09/08/2006 Added KPILevel<>CORP 
--
--########################################################################

DECLARE @ReportMonth AS DATETIME

SELECT @ReportMonth=MAX(ReportMonth) 
FROM mstt_AgentQualityAggregation
WHERE KPILevel= 'ADVISERKPI'

SELECT
  ReportMonth,
  SummaryPeriod,
  CASE ComplianceCategoryCode
    WHEN 'COB' THEN 'Investment'
    WHEN 'MCOB' THEN 'Mortgages'
  END ReportSection,
  NRSubmitted,
  RiskFails,
  OtherFail,
  RandomFails,
  RiskAssessed,
  RandomAssessed,
  OtherAssessed,
  TotalSubmitted,
  RiskSubmitted,
  RiskCompletionFail,
  RandomCompletionFail,
  OtherCompletionFail,
  RiskSAFail,
  RandomSAFail,
  OtherSAFail,

  (OtherCompletionFail+((RiskCompletionFail/CAST(RiskAssessed AS FLOAT))*RiskSubmitted)+((RandomCompletionFail/CAST(RandomAssessed AS FLOAT))*(NRSubmitted-OtherAssessed)))/CAST(TotalSubmitted AS FLOAT) CQWeightedKPI,
  (OtherSAFail+((RiskSAFail/CAST(RiskAssessed AS FLOAT))*RiskSubmitted)+((RandomSAFail/CAST(RandomAssessed as FLOAT))*(NRSubmitted-OtherAssessed)))/CAST(TotalSubmitted AS FLOAT) SAWeightedKPI,

  (OtherFail+((RiskFails/CAST(RiskAssessed AS FLOAT))*RiskSubmitted)+((RandomFails/CAST(RandomAssessed AS FLOAT))*(NRSubmitted-OtherAssessed)))/CAST(TotalSubmitted AS FLOAT) WeightCalculation,
  (POWER((((POWER(1.96,2)*(RandomSAFail/CAST(RandomAssessed AS FLOAT))*(1-(RandomSAFail/CAST(RandomAssessed AS FLOAT))))*((TotalSubmitted-RiskAssessed-OtherAssessed)-RandomAssessed))/CAST((RandomAssessed*(TotalSubmitted-RiskAssessed-OtherAssessed-1)) AS FLOAT)),0.5))*((TotalSubmitted-RiskAssessed-OtherAssessed)/CAST(TotalSubmitted AS FLOAT)) ConfidenceIntervalCalc
FROM 
  (SELECT  
    ReportMonth,
    SummaryPeriod,
    ComplianceCategoryCode,
    SubmittedRandomProposalQty+SubmittedOtherProposalQty NRSubmitted,
    InitialRiskCompletionQty RiskCompletionFail,
    InitialRandomCompletionQTY RandomCompletionFail,
    InitialOtherCompletionQty OtherCompletionFail,
    InitialRiskSuitableAdviceQty RiskSAFail,
    InitialRandomSuitableAdviceQTY RandomSAFail,
    InitialOtherSuitableAdviceQty OtherSAFail,
    InitialRiskCompletionQTY+ InitialRiskSuitableAdviceQty RiskFails,
    InitialOtherCompletionQTY + InitialOtherSuitableAdviceQty OtherFail,
    InitialRandomCompletionQTY + InitialRandomSuitableAdviceQty RandomFails,
    InitialRiskAssessedQty RiskAssessed,
    InitialRandomAssessedQty RandomAssessed,
    InitialOtherAssessedQty OtherAssessed,
    SubmittedRiskProposalQty+SubmittedRandomProposalQty+SubmittedOtherProposalQty TotalSubmitted,
    SubmittedRiskProposalQty RiskSubmitted
  FROM 
    mstt_AgentQualityAggregation
  WHERE 
    ReportMonth=@ReportMonth
    AND KPILevel=@KPILevel
    AND SummaryPeriod=@SummaryPeriod
    AND ComplianceCategoryCode=@ComplianceCategoryCode) Data


GO
