CREATE PROCEDURE [dbo].[msp_SelectDashboard] -- WITH RECOMPILE,ENCRYPTION
@Area nvarchar(50),
--@Region nvarchar(50),
@Comparison nvarchar(50)
AS
/******************************************************************************
Copyright (C) Moore Stephens Consulting Limited 2005
Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>
*******************************************************************************/
declare @CountAd int
select @CountAd = sum(a.ActualThisMonth)
from 
  mst_Dashboard a
where
 a.KPIName = 'Number of Advisers'
 and isnull(a.Area,'%') like @Area
declare @CountFran int
select @CountFran = sum(a.ActualThisMonth)
from 
  mst_Dashboard a
where
 a.KPIName = 'Number of Franchises'
 and isnull(a.Area,'%') like @Area
select 
 x.[kpiname],
 x.[orderby],
 sum(case when x.[Type] = 'Prev' then x.[TargetLastMonth] else '0' end) [PrevYear],
 sum(case when x.[Type] = 'Target' then x.[TargetLastMonth] else '0' end) [TargetLastMonth],
 sum(case when x.[Type] = 'Target' then x.[TargetThisMonth] else '0' end) [TargetThisMonth],
 sum(x.[YTD]) [YTD],
 sum(x.[ActualThisMonth]) [ActualThisMonth],
 sum(x.[ProjectedThisMonth]) [ProjectedThisMonth],
 sum(case when x.[Type] = 'Prev' then x.[TargetThisMonth] else '0' end) [PrevThisMonth],
 'R' as RAG,
 'R' as RAG_Trend
 into #Dashboard
from
(
select 
kpiname, 
orderby,
'Prev' [Type],
sum(YTD) YTD, 
sum(case when @Comparison = '-999' then YTDP else 0 end) TargetLastMonth, 
sum(ActualThisMonth) ActualThisMonth, 
sum(ProjectedThisMonth) ProjectedThisMonth, 
sum(case when @Comparison = '-999' then ActualThisMonthPY else 0 end) TargetThisMonth
from 
mst_Dashboard 
where
isnull(Area,'%') like @Area
group by
kpiname,
orderby
union
select 
kpiname, 
orderby,
'Target' [Type],
'0' YTD, 
sum(case when @Comparison = 'Previous Year Actual' then 0 else TargetLastMonth end) TargetLastMonth, 
'0' ActualThisMonth, 
'0' ProjectedThisMonth, 
sum(case when @Comparison = 'Previous Year Actual' then 0 else TargetThisMonth end) TargetThisMonth
from 
mst_Dashboard 
where
ComparisonId = @Comparison and
isnull(Area,'%') like @Area
group by
kpiname,
orderby
   ) x
group by 
kpiname,
orderby
order by
2
update #Dashboard
set RAG = case when KPIName in ('Turnover Pipeline',
        'Applications Pipeline',
        'NTU Cases',
        'NTU Turnover',
        'Number of Leavers - Franchises',
        'Number of Leavers - Advisers') then
    case when @Comparison = '-999' then
      case when (isnull(YTD,0) - isnull(PrevYear,0)) / isnull(nullif(PrevYear,0),1) > 0 then 'R'
        when (isnull(YTD,0) - isnull(PrevYear,0)) / isnull(nullif(PrevYear,0),1) between -0.1 and 0 then 'A'
        else 'G' 
      end
      else
        case when (isnull(YTD,0) - isnull(TargetLastMonth,0)) / isnull(nullif(TargetLastMonth,0),1) > 0 then 'R'
          when (isnull(YTD,0) - isnull(TargetLastMonth,0)) / isnull(nullif(TargetLastMonth,0),1) between -0.1 and 0 then 'A'
          else 'G' 
        end
    end
    else  case when @Comparison = '-999' then
        case when (isnull(YTD,0) - isnull(PrevYear,0)) / isnull(nullif(PrevYear,0),1) < 0 then 'R'
          when (isnull(YTD,0) - isnull(PrevYear,0)) / isnull(nullif(PrevYear,0),1) between 0 and 0.1 then 'A'
          else 'G' 
        end
        else
          case when (isnull(YTD,0) - isnull(TargetLastMonth,0)) / isnull(nullif(TargetLastMonth,0),1) < 0 then 'R'
            when (isnull(YTD,0) - isnull(TargetLastMonth,0)) / isnull(nullif(TargetLastMonth,0),1) between 0 and 0.1 then 'A'
            else 'G' 
          end
      end
  end
update #Dashboard
set RAG_Trend = case when KPIName in ('Turnover Pipeline',
        'Applications Pipeline',
        'NTU Cases',
        'NTU Turnover',
        'Number of Leavers - Franchises',
        'Number of Leavers - Advisers') then
    case when @Comparison = '-999' then
      case when (isnull(ActualThisMonth,0) - isnull(PrevThisMonth,0)) / isnull(nullif(PrevThisMonth,0),1) > 0 then 'R'
        when (isnull(ActualThisMonth,0) - isnull(PrevThisMonth,0)) / isnull(nullif(PrevThisMonth,0),1) between -0.1 and 0 then 'A'
        else 'G' 
      end
      else
        case when (isnull(ActualThisMonth,0) - isnull(TargetThisMonth,0)) / isnull(nullif(TargetThisMonth,0),1) > 0 then 'R'
          when (isnull(ActualThisMonth,0) - isnull(TargetThisMonth,0)) / isnull(nullif(TargetThisMonth,0),1) between -0.1 and 0 then 'A'
          else 'G' 
        end
    end
    else  case when @Comparison = '-999' then
        case when (isnull(ActualThisMonth,0) - isnull(PrevThisMonth,0)) / isnull(nullif(PrevThisMonth,0),1) < 0 then 'R'
          when (isnull(ActualThisMonth,0) - isnull(PrevThisMonth,0)) / isnull(nullif(PrevThisMonth,0),1) between 0 and 0.1 then 'A'
          else 'G' 
        end
        else
          case when (isnull(ActualThisMonth,0) - isnull(TargetThisMonth,0)) / isnull(nullif(TargetThisMonth,0),1) < 0 then 'R'
            when (isnull(ActualThisMonth,0) - isnull(TargetThisMonth,0)) / isnull(nullif(TargetThisMonth,0),1) between 0 and 0.1 then 'A'
            else 'G' 
          end
      end
  end
-- update #Dashboard
-- set
-- YTD = case when KPIName = 'Average Productivity - Adviser' then
--       YTD/ @CountAd
--       else YTD
--       end
-- 
-- update #Dashboard
-- set
-- YTD = case when KPIName = 'Average Productivity - Franchise' then
--       YTD/ @CountFran
--       else YTD
--       end
--       
--       
-- update #Dashboard
-- set
-- PrevYear = case when KPIName = 'Average Productivity - Adviser' then
--       PrevYear/ @CountAd
--       else PrevYear
--       end
-- 
-- update #Dashboard
-- set
-- PrevYear = case when KPIName = 'Average Productivity - Franchise' then
--       PrevYear/ @CountFran
--       else PrevYear
--       end
--Now retrieve the results
select [kpiname],
 [orderby],
 [PrevYear],
 [TargetLastMonth],
 [TargetThisMonth],
 [YTD],
 [ActualThisMonth],
 [ProjectedThisMonth],
 [PrevThisMonth],
 RAG,
 RAG_Trend 
from #Dashboard
order by OrderBy

GO
