CREATE PROCEDURE [dbo].[msp_SelectFranchiseABCLeague] -- WITH RECOMPILE,ENCRYPTION
    @Product nvarchar(50),
    @ProductSubGroup nvarchar(50),
    @ProductGroup nvarchar(50),
    @ProductCategory nvarchar(50),
    @Size nvarchar(50),
    @Area nvarchar(50),
    @Region nvarchar(50)
AS

/******************************************************************************

Amended by Paul Robathan (April 2008)

1. Read mstt_FranchiseABCLeagueTable_Current instead of mstt_FranchiseLeagueTable_Current

*******************************************************************************/

begin

--Attempt seventy four
-- declare @Size varchar(50)
-- declare @Region varchar(50)
-- declare @Area varchar(50)
-- 
-- set @Size = 'All'
-- set @Region = 'All'
-- set @Area = 'All'

declare @LastMonth datetime
set @LastMonth = (select top 1 LastMonth from mstt_FranchiseABCLeagueTable_Last)


  create table #Current (FranchiseCode varchar(50), 
        Franchise varchar(255), 
        Area varchar(255), 
        Region varchar(255),
        Turnover float,
        numAdvisers INT,
        Position int not null identity (1,1))


  create table #Last (FranchiseCode varchar(50), 
        Franchise varchar(255), 
        Area varchar(255), 
        Region varchar(255),
        Turnover float,
        --numAdvisers INT,
        Position int not null identity (1,1))


  create table #Prev (FranchiseCode varchar(50), 
        Franchise varchar(255), 
        Area varchar(255), 
        Region varchar(255),
        Turnover float,
        --numAdvisers INT,
        Position int not null identity (1,1))


  insert into #Current (FranchiseCode, Franchise, Area, Region, Turnover, numAdvisers)
  select Code, Franchise, AreaSalesManager, RegionalSalesManager, sum(Turnover) as Turnover, numAdvisers 
  from mstt_FranchiseABCLeagueTable_Current
  where ProductCategoryName = case when @ProductCategory = '%' then ProductCategoryName else @ProductCategory end
  and ProductGroupName = case when @ProductGroup = '%' then ProductGroupName else @ProductGroup end
  and ProductSubGroupName = case when @ProductSubGroup = '%' then ProductSubGroupName else @ProductSubGroup end
  and ProductName = case when @Product = '%' then ProductName else @Product end
  and FranchiseSizeId = FranchiseSizeId
  and FranchiseSizeType = case when @Size = '%' then FranchiseSizeType else @Size end
  and AreaSalesManager = case when @Area = '%' then AreaSalesManager else @Area end
  and RegionalSalesManager = case when @Region = '%' then RegionalSalesManager else @Region end
  group by Code, Franchise, AreaSalesManager, RegionalSalesManager, numAdvisers
  order by sum(Turnover) desc, Franchise


  insert into #Last (FranchiseCode, Franchise, Area, Region, Turnover)--, numAdvisers)
  select Code, Franchise, AreaSalesManager, RegionalSalesManager, sum(Turnover) as Turnover--, numAdvisers 
  from mstt_FranchiseABCLeagueTable_Last
  where ProductCategoryName = case when @ProductCategory = '%' then ProductCategoryName else @ProductCategory end
  and ProductGroupName = case when @ProductGroup = '%' then ProductGroupName else @ProductGroup end
  and ProductSubGroupName = case when @ProductSubGroup = '%' then ProductSubGroupName else @ProductSubGroup end
  and ProductName = case when @Product = '%' then ProductName else @Product end
  and FranchiseSizeId = FranchiseSizeId
  and FranchiseSizeType = case when @Size = '%' then FranchiseSizeType else @Size end
  and AreaSalesManager = case when @Area = '%' then AreaSalesManager else @Area end
  and RegionalSalesManager = case when @Region = '%' then RegionalSalesManager else @Region end
  group by Code, Franchise, AreaSalesManager, RegionalSalesManager--, numAdvisers
  order by sum(Turnover) desc, Franchise


  insert into #Prev (FranchiseCode, Franchise, Area, Region, Turnover) --, numAdvisers)
  select Code, Franchise, AreaSalesManager, RegionalSalesManager, sum(Turnover) as Turnover--, numAdvisers
  from mstt_FranchiseABCLeagueTable_Previous
  where ProductCategoryName = case when @ProductCategory = '%' then ProductCategoryName else @ProductCategory end
  and ProductGroupName = case when @ProductGroup = '%' then ProductGroupName else @ProductGroup end
  and ProductSubGroupName = case when @ProductSubGroup = '%' then ProductSubGroupName else @ProductSubGroup end
  and ProductName = case when @Product = '%' then ProductName else @Product end
  and FranchiseSizeId = FranchiseSizeId
  and FranchiseSizeType = case when @Size = '%' then FranchiseSizeType else @Size end
  and AreaSalesManager = case when @Area = '%' then AreaSalesManager else @Area end
  and RegionalSalesManager = case when @Region = '%' then RegionalSalesManager else @Region end
  group by Code, Franchise, AreaSalesManager, RegionalSalesManager--, numAdvisers
  order by sum(Turnover) desc, Franchise


  --Select the Results
  select 
  @LastMonth as LastMonth,
  FranchiseCode,
  Franchise,
  Area,
  Region,
  null as Type,
  max(CurrentAmount) as Turnover,
  max(CurrentPos) as PositionCurrent,
  max(LastPos) as LastPosition,
  max(LastAmount) as TurnoverLast,
  max(PrevPos) as PreviousPosition,
  MAX(numAdvisers) as numAdvisers
  from (select Position as PrevPos, 
      Turnover as PrevAmount, 
      null as LastPos, 
      null as LastAmount, 
      null as CurrentPos, 
      FranchiseCode, 
      Franchise,
      null as numAdvisers, 
      null as CurrentAmount,
      --case when @Region = '%' then Region else 'Region' end as Region, 
      --case when @Area = '%' then Area else 'Area' end as Area
      case when @Region = '%' then isnull((select Region from #Current where FranchiseCode = #Prev.FranchiseCode), Region) else Region end as Region, 
      case when @Area = '%' then isnull((select Area from #Current where FranchiseCode = #Prev.FranchiseCode), Area) else Area end as Area
    from #Prev
      union all
    select null as PrevPos, 
      null as PrevAmount, 
      Position as LastPos, 
      Turnover as LastAmount, 
      null as CurrentPos, 
      FranchiseCode, 
      Franchise,
      null as numAdvisers, 
      null as CurrentAmount,
      --case when @Region = '%' then Region else 'Region' end as Region, 
      --case when @Area = '%' then Area else 'Area' end as Area 
      case when @Region = '%' then isnull((select Region from #Current where FranchiseCode = #Last.FranchiseCode), Region) else Region end as Region, 
      case when @Area = '%' then isnull((select Area from #Current where FranchiseCode = #Last.FranchiseCode), Area) else Area end as Area
    from #Last 
      union all
    select null as PrevPos, 
      null as PrevAmount, 
      null as LastPos, 
      null as LastAmount, 
      Position as CurrentPos, 
      FranchiseCode, 
      Franchise,
      numAdvisers, 
      Turnover as CurrentAmount, 
      Region, 
      Area
    from #Current) sub
  group by FranchiseCode, Franchise, Area, Region--, numAdvisers
  having max(CurrentAmount) is not null or max(LastAmount) is not null --Filter out Franchises with null Current Amount AND null Last Amount
  order by case when max(LastPos) is null then 1000000 else max(LastPos) end 

drop table #Prev
drop table #Last 
drop table #Current



end









GO
/****** Object:  StoredProcedure [dbo].[msp_SelectFranchiseABCLeagueBreakdown]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO



CREATE PROCEDURE [dbo].[msp_SelectFranchiseABCLeagueBreakdown]
    @Product nvarchar(50),
    @ProductSubGroup nvarchar(50),
    @ProductCategory nvarchar(50),
    @Area nvarchar(50),
    @Region nvarchar(50)
AS

/******************************************************************************

Created by Paul Robathan (Feb 2009)
Steve Berry requested that the ABC Leagues are made more granular so that both Enterprise
and Adviser Leagues have overall totals plus breakdown by Product Type.

Marcus Cossey asked that we
- do not split tables by size i.e. Large, Small, Sole Trader

Example Call
	exec msp_SelectFranchiseABCLeagueBreakdown '%','%','%','%','%'

*******************************************************************************/

begin

	create table #Total (FranchiseCode varchar(50), 
				Franchise varchar(255), 
				Area varchar(255), 
				Region varchar(255),
				Turnover float,
				Position int not null identity (1,1))
	create table #Prot (FranchiseCode varchar(50), 
				Turnover float)
	create table #GI (FranchiseCode varchar(50), 
				Turnover float)
	create table #Inv (FranchiseCode varchar(50), 
				Turnover float)
	create table #Pen (FranchiseCode varchar(50), 
				Turnover float)
	create table #Mort (FranchiseCode varchar(50), 
				Turnover float)

	insert into #Total (FranchiseCode, Franchise, Area, Region, Turnover)
	select Code, Franchise, AreaSalesManager, RegionalSalesManager, sum(Turnover) as Turnover 
	from mstt_FranchiseABCLeagueTable_Current
	where ProductCategoryName = case when @ProductCategory = '%' then ProductCategoryName else @ProductCategory end
	and ProductSubGroupName = case when @ProductSubGroup = '%' then ProductSubGroupName else @ProductSubGroup end
	and ProductName = case when @Product = '%' then ProductName else @Product end
	and FranchiseSizeId = FranchiseSizeId
	and AreaSalesManager = case when @Area = '%' then AreaSalesManager else @Area end
	and RegionalSalesManager = case when @Region = '%' then RegionalSalesManager else @Region end
	group by Code, Franchise, AreaSalesManager, RegionalSalesManager
	order by sum(Turnover) desc, Franchise

	insert into #Prot (FranchiseCode, Turnover)
	select Code, sum(Turnover) as Turnover 
	from mstt_FranchiseABCLeagueTable_Current
	where  ProductGroupName = 'Protection'
	and ProductCategoryName = case when @ProductCategory = '%' then ProductCategoryName else @ProductCategory end
	and ProductSubGroupName = case when @ProductSubGroup = '%' then ProductSubGroupName else @ProductSubGroup end
	and ProductName = case when @Product = '%' then ProductName else @Product end
	and FranchiseSizeId = FranchiseSizeId
	and AreaSalesManager = case when @Area = '%' then AreaSalesManager else @Area end
	and RegionalSalesManager = case when @Region = '%' then RegionalSalesManager else @Region end
	group by Code
	order by Code

	insert into #GI (FranchiseCode, Turnover)
	select Code, sum(Turnover) as Turnover 
	from mstt_FranchiseABCLeagueTable_Current
	where  ProductGroupName = 'GI'
	and ProductCategoryName = case when @ProductCategory = '%' then ProductCategoryName else @ProductCategory end
	and ProductSubGroupName = case when @ProductSubGroup = '%' then ProductSubGroupName else @ProductSubGroup end
	and ProductName = case when @Product = '%' then ProductName else @Product end
	and FranchiseSizeId = FranchiseSizeId
	and AreaSalesManager = case when @Area = '%' then AreaSalesManager else @Area end
	and RegionalSalesManager = case when @Region = '%' then RegionalSalesManager else @Region end
	group by Code
	order by Code

	insert into #Inv (FranchiseCode, Turnover)
	select Code, sum(Turnover) as Turnover 
	from mstt_FranchiseABCLeagueTable_Current
	where  ProductGroupName = 'Investment'
	and ProductCategoryName = case when @ProductCategory = '%' then ProductCategoryName else @ProductCategory end
	and ProductSubGroupName = case when @ProductSubGroup = '%' then ProductSubGroupName else @ProductSubGroup end
	and ProductName = case when @Product = '%' then ProductName else @Product end
	and FranchiseSizeId = FranchiseSizeId
	and AreaSalesManager = case when @Area = '%' then AreaSalesManager else @Area end
	and RegionalSalesManager = case when @Region = '%' then RegionalSalesManager else @Region end
	group by Code
	order by Code

	insert into #Pen (FranchiseCode, Turnover)
	select Code, sum(Turnover) as Turnover 
	from mstt_FranchiseABCLeagueTable_Current
	where  ProductGroupName = 'Pensions'
	and ProductCategoryName = case when @ProductCategory = '%' then ProductCategoryName else @ProductCategory end
	and ProductSubGroupName = case when @ProductSubGroup = '%' then ProductSubGroupName else @ProductSubGroup end
	and ProductName = case when @Product = '%' then ProductName else @Product end
	and FranchiseSizeId = FranchiseSizeId
	and AreaSalesManager = case when @Area = '%' then AreaSalesManager else @Area end
	and RegionalSalesManager = case when @Region = '%' then RegionalSalesManager else @Region end
	group by Code
	order by Code

	insert into #Mort (FranchiseCode, Turnover)
	select Code, sum(Turnover) as Turnover 
	from mstt_FranchiseABCLeagueTable_Current
	where  ProductGroupName = 'Mortgage'
	and ProductCategoryName = case when @ProductCategory = '%' then ProductCategoryName else @ProductCategory end
	and ProductSubGroupName = case when @ProductSubGroup = '%' then ProductSubGroupName else @ProductSubGroup end
	and ProductName = case when @Product = '%' then ProductName else @Product end
	and FranchiseSizeId = FranchiseSizeId
	and AreaSalesManager = case when @Area = '%' then AreaSalesManager else @Area end
	and RegionalSalesManager = case when @Region = '%' then RegionalSalesManager else @Region end
	group by Code
	order by Code

	select t.FranchiseCode as 'Enterprise Code',t.Franchise as Enterprise,t.Area,t.Region,round(t.Turnover,0) as 'Overall', 
			isnull(round(p.Turnover,0),0) as 'Protection',isnull(round(pe.Turnover,0),0) as 'Pensions',isnull(round(i.Turnover,0),0) as 'Investments',
			isnull(round(m.Turnover,0),0) as 'Mortgages',isnull(round(g.Turnover,0),0) as 'GI'
	from #Total t
	left outer join #Prot p on p.FranchiseCode = t.FranchiseCode
	left outer join #Pen pe on pe.FranchiseCode = t.FranchiseCode
	left outer join #Inv i on i.FranchiseCode = t.FranchiseCode
	left outer join #Mort m on m.FranchiseCode = t.FranchiseCode
	left outer join #GI g on g.FranchiseCode = t.FranchiseCode
	order by t.position 

	drop table #Total
	drop table #Prot
	drop table #Pen
	drop table #Inv
	drop table #Mort
	drop table #GI

end

GO
