CREATE PROCEDURE [dbo].[msp_SelectFranchiseLeague] -- WITH RECOMPILE,ENCRYPTION
    @Product nvarchar(50),
    @ProductSubGroup nvarchar(50),
    @ProductGroup nvarchar(50),
    @ProductCategory nvarchar(50),
    @Size nvarchar(50),
    @Area nvarchar(50),
    @Region nvarchar(50)
AS

/******************************************************************************

Copyright (C) Moore Stephens Consulting Limited 2005

Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
          
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>

*******************************************************************************/

begin

--Attempt seventy four
-- declare @Size varchar(50)
-- declare @Region varchar(50)
-- declare @Area varchar(50)
-- 
-- set @Size = 'All'
-- set @Region = 'All'
-- set @Area = 'All'

declare @LastMonth datetime
set @LastMonth = (select top 1 LastMonth from mstt_FranchiseLeagueTable_Last)


  create table #Current (FranchiseCode varchar(50), 
        Franchise varchar(255), 
        Area varchar(255), 
        Region varchar(255),
        Turnover float,
        numAdvisers INT,
        Position int not null identity (1,1))


  create table #Last (FranchiseCode varchar(50), 
        Franchise varchar(255), 
        Area varchar(255), 
        Region varchar(255),
        Turnover float,
        --numAdvisers INT,
        Position int not null identity (1,1))


  create table #Prev (FranchiseCode varchar(50), 
        Franchise varchar(255), 
        Area varchar(255), 
        Region varchar(255),
        Turnover float,
        --numAdvisers INT,
        Position int not null identity (1,1))


  insert into #Current (FranchiseCode, Franchise, Area, Region, Turnover, numAdvisers)
  select Code, Franchise, AreaSalesManager, RegionalSalesManager, sum(Turnover) as Turnover, numAdvisers 
  from mstt_FranchiseLeagueTable_Current
  where ProductCategoryName = case when @ProductCategory = '%' then ProductCategoryName else @ProductCategory end
  and ProductGroupName = case when @ProductGroup = '%' then ProductGroupName else @ProductGroup end
  and ProductSubGroupName = case when @ProductSubGroup = '%' then ProductSubGroupName else @ProductSubGroup end
  and ProductName = case when @Product = '%' then ProductName else @Product end
  and FranchiseSizeId = FranchiseSizeId
  and FranchiseSizeType = case when @Size = '%' then FranchiseSizeType else @Size end
  and AreaSalesManager = case when @Area = '%' then AreaSalesManager else @Area end
  and RegionalSalesManager = case when @Region = '%' then RegionalSalesManager else @Region end
  group by Code, Franchise, AreaSalesManager, RegionalSalesManager, numAdvisers
  order by sum(Turnover) desc, Franchise


  insert into #Last (FranchiseCode, Franchise, Area, Region, Turnover)--, numAdvisers)
  select Code, Franchise, AreaSalesManager, RegionalSalesManager, sum(Turnover) as Turnover--, numAdvisers 
  from mstt_FranchiseLeagueTable_Last
  where ProductCategoryName = case when @ProductCategory = '%' then ProductCategoryName else @ProductCategory end
  and ProductGroupName = case when @ProductGroup = '%' then ProductGroupName else @ProductGroup end
  and ProductSubGroupName = case when @ProductSubGroup = '%' then ProductSubGroupName else @ProductSubGroup end
  and ProductName = case when @Product = '%' then ProductName else @Product end
  and FranchiseSizeId = FranchiseSizeId
  and FranchiseSizeType = case when @Size = '%' then FranchiseSizeType else @Size end
  and AreaSalesManager = case when @Area = '%' then AreaSalesManager else @Area end
  and RegionalSalesManager = case when @Region = '%' then RegionalSalesManager else @Region end
  group by Code, Franchise, AreaSalesManager, RegionalSalesManager--, numAdvisers
  order by sum(Turnover) desc, Franchise


  insert into #Prev (FranchiseCode, Franchise, Area, Region, Turnover) --, numAdvisers)
  select Code, Franchise, AreaSalesManager, RegionalSalesManager, sum(Turnover) as Turnover--, numAdvisers
  from mstt_FranchiseLeagueTable_Previous
  where ProductCategoryName = case when @ProductCategory = '%' then ProductCategoryName else @ProductCategory end
  and ProductGroupName = case when @ProductGroup = '%' then ProductGroupName else @ProductGroup end
  and ProductSubGroupName = case when @ProductSubGroup = '%' then ProductSubGroupName else @ProductSubGroup end
  and ProductName = case when @Product = '%' then ProductName else @Product end
  and FranchiseSizeId = FranchiseSizeId
  and FranchiseSizeType = case when @Size = '%' then FranchiseSizeType else @Size end
  and AreaSalesManager = case when @Area = '%' then AreaSalesManager else @Area end
  and RegionalSalesManager = case when @Region = '%' then RegionalSalesManager else @Region end
  group by Code, Franchise, AreaSalesManager, RegionalSalesManager--, numAdvisers
  order by sum(Turnover) desc, Franchise


  --Select the Results
  select 
  @LastMonth as LastMonth,
  FranchiseCode,
  Franchise,
  Area,
  Region,
  null as Type,
  max(CurrentAmount) as Turnover,
  max(CurrentPos) as PositionCurrent,
  max(LastPos) as LastPosition,
  max(LastAmount) as TurnoverLast,
  max(PrevPos) as PreviousPosition,
  MAX(numAdvisers) as numAdvisers
  from (select Position as PrevPos, 
      Turnover as PrevAmount, 
      null as LastPos, 
      null as LastAmount, 
      null as CurrentPos, 
      FranchiseCode, 
      Franchise,
      null as numAdvisers, 
      null as CurrentAmount,
      --case when @Region = '%' then Region else 'Region' end as Region, 
      --case when @Area = '%' then Area else 'Area' end as Area
      case when @Region = '%' then isnull((select Region from #Current where FranchiseCode = #Prev.FranchiseCode), Region) else Region end as Region, 
      case when @Area = '%' then isnull((select Area from #Current where FranchiseCode = #Prev.FranchiseCode), Area) else Area end as Area
    from #Prev
      union all
    select null as PrevPos, 
      null as PrevAmount, 
      Position as LastPos, 
      Turnover as LastAmount, 
      null as CurrentPos, 
      FranchiseCode, 
      Franchise,
      null as numAdvisers, 
      null as CurrentAmount,
      --case when @Region = '%' then Region else 'Region' end as Region, 
      --case when @Area = '%' then Area else 'Area' end as Area 
      case when @Region = '%' then isnull((select Region from #Current where FranchiseCode = #Last.FranchiseCode), Region) else Region end as Region, 
      case when @Area = '%' then isnull((select Area from #Current where FranchiseCode = #Last.FranchiseCode), Area) else Area end as Area
    from #Last 
      union all
    select null as PrevPos, 
      null as PrevAmount, 
      null as LastPos, 
      null as LastAmount, 
      Position as CurrentPos, 
      FranchiseCode, 
      Franchise,
      numAdvisers, 
      Turnover as CurrentAmount, 
      Region, 
      Area
    from #Current) sub
  group by FranchiseCode, Franchise, Area, Region--, numAdvisers
  having max(CurrentAmount) is not null or max(LastAmount) is not null --Filter out Franchises with null Current Amount AND null Last Amount
  order by case when max(LastPos) is null then 1000000 else max(LastPos) end 

drop table #Prev
drop table #Last 
drop table #Current



end







GO
