CREATE PROCEDURE [dbo].[msp_SelectFranchiseStatement] -- WITH RECOMPILE,ENCRYPTION
  /* Param List */
  @FranchiseCode nvarchar(50),
  /* @Franchise varchar(255), */
  @UserId nvarchar(50),
  @Date nvarchar(50),
  @RunMonth nvarchar(50)
AS

/******************************************************************************

Copyright (C) Moore Stephens Consulting Limited 2005

Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
          
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>

*******************************************************************************/

/*
   The first page of the Franchise statement has 2 sections.
      - Product Groups broken down by Product
      - Remaining Product Groups as summaries only
        NB: Also contains a League only Adjustment Summary
*/

--
-- Create ProductGroup Breakdown table to identify the Product Groups
-- that need to be broken down by product and those that remain as
-- just product group summaries.
--

--CREATE TABLE #mst_ProductionGroupBreakdown
--(
--  ProductGroupName  [varchar]  (255) NOT NULL ,
--  BreakDownFlag   [char]     (1) NOT NULL
--) 


select distinct cast(ProductGroupName as varchar(255)) as ProductGroupName,
       cast(case ProductGroupName 
    when 'Pension' then 'Y'
    when 'Pensions' then 'Y'
    when 'Protection' then 'Y'
    when 'Investment' then 'Y'
    else 'N'
  end as char(1)) as [BreakdownFlag]
into #mst_ProductionGroupBreakdown
from msdt_Products

--truncate table mst_ProductionProduct

--CREATE TABLE #mst_ProductionProduct
--(
--  [AdviserId]   [nvarchar] (50) NOT NULL ,
--  [FranchiseCode]   [varchar] (255) NOT NULL ,
--  [Area]      [varchar]  (50) NOT NULL ,
--  [Region]    [varchar]  (50) NOT NULL ,
--  [Franchise]   [varchar] (255) NOT NULL ,
--  [ProductGroup]    [varchar]  (50) NOT NULL ,
--  [ProductName]   [varchar]  (50) NOT NULL ,
--  [DateIssued]    [nvarchar] (50) NULL ,
--  [BreakDownFlag]   [char]     (1) NOT NULL,
--  [Turnover]    [float]   NULL ,
--  [NBI]     [float]   NULL
--) 

--
-- Get Issued Data at Advisor level and put it nito a temp table
--
--insert 
--(
--  AdviserId,
--  FranchiseCode,
--  Area,
--  Region,
--  Franchise,
--  ProductGroup,
--  ProductName,
--  DateIssued,
--  BreakDownFlag,
--  Turnover,
--  NBI
--) 
select  cast(isnull(a.AdviserId, -99) as nvarchar(50)) as AdviserId,
  cast('Unknown' as varchar(255)) as FranchiseCode,
  cast('Yet to be allocated' as varchar(50)) as Area,
  cast('Yet to be allocated' as varchar(50)) as Region,
  cast('Yet to be allocated' as varchar(255)) as Franchise,
  cast(isnull(p.ProductGroupName, 'Unknown') as varchar(50)) as ProductGroup,
  cast(isnull(p.ReportingProductName, 'Unknown') as varchar(50)) as ProductName,
  cast(b.[IssuedDate] as nvarchar(50)) as [DateIssued],
  cast(p.BreakDownFlag as char(1)) as BreakDownFlag,
  sum(a.Turnover) [Turnover],
  sum(a.NBI) [NBI]
into #mst_ProductionProduct 
from  msft_Sales a,
  (
    select  DateId,
      YearMonth [IssuedDate]
    from  msdt_CalendarTime
    where entrytypeid = 2
    and   [Year] = year(getdate())
  ) b,
  (
    select  p.ProductId,
      p.ReportingProductName,
      p.ProductGroupName,
      pb.BreakDownFlag
    from  msdt_Products p inner join #mst_ProductionGroupBreakdown pb
      on p.ProductGroupName = pb.ProductGroupName
    union all 
    select  p.ProductId,
      p.ReportingProductName,
      p.ProductGroupName,
      pb.BreakDownFlag
    from  msdt_ProductDummies p inner join #mst_ProductionGroupBreakdown pb
      on p.ProductGroupName = pb.ProductGroupName
  ) p,
  (
    select  AdviserID,
      FranchiseCode,
      Franchise
    from  msdt_Adviser
    union all
    select  AdviserID,
      FranchiseCode,
      Franchise
    from  msdt_AdviserDummies
  ) adv,
  msct_UserAccessControl uac    -- Add security
where a.AdviserId =adv.AdviserID
  and adv.FranchiseCode = @FranchiseCode
--  and adv.Franchise = @Franchise
  and a.AdviserId = uac.AdviserId   -- Add security
  and uac.DomainLogin = @UserId   -- Add security
  and a.DateIssuedId = b.DateId
  and a.ProductId = p.ProductId
  and a.BusinessTypeId = 2    -- Issued Values only
group by
  a.AdviserId,
  p.ReportingProductName,
  p.ProductGroupName,
  b.[IssuedDate],
  p.BreakDownFlag

--
-- Add in League Only Adjustments line (Competition Ponits Adj)
--
insert into #mst_ProductionProduct
(
  AdviserId,
  FranchiseCode,
  Area,
  Region,
  Franchise,
  ProductGroup,
  ProductName,
  DateIssued,
  BreakDownFlag,
  Turnover,
  NBI
) 
select  isnull(a.AdviserId, -99) as AdviserId,
  'Unknown' as FranchiseCode,
  'Yet to be allocated' as Area,
  'Yet to be allocated' as Region,
  'Yet to be allocated' as Franchise,
  'Competition Points Adj' as ProductGroup,
  'Competition Points Adj' as ProductName,
  b.[IssuedDate],
  'N' as BreakdownFlag,
  sum(a.Turnover) [Turnover],
  sum(a.NBI) [NBI]
from  mstt_ProductionAdjustments a,
  (
    select  DateId,
      YearMonth [IssuedDate],
      [Year]
    from  msdt_CalendarTime
    where entrytypeid = 2
    and   [Year] = year(getdate())
  ) b,
  (
    select  AdviserID,
      FranchiseCode,
      Franchise
    from  msdt_Adviser
    union all
    select  AdviserID,
      FranchiseCode,
      Franchise
    from  msdt_AdviserDummies
  ) adv,
  msct_UserAccessControl uac    -- Add security
where a.AdviserId =adv.AdviserID
  and adv.FranchiseCode = @FranchiseCode
--  and adv.Franchise = @Franchise
  and a.AdviserId = uac.AdviserId   -- Add security
  and uac.DomainLogin = @UserId   -- Add security
  and a.DateIssuedId = b.DateId
    and ProductionFlag = 'N'
-- Ignore any records where the year of the Date Issued is different from the Year column.
-- They would be different when either adjusted in advance for the next year or are
-- adjustments for the previous year.
    and a.[Year] = b.[Year]     
group by
  a.AdviserId,
  b.[IssuedDate]


update #mst_ProductionProduct
set Franchise = isnull(rtrim(ltrim(coalesce(c.CompetitionName, c.TradingName, c.DESCN))), 'Yet to be allocated'), -- as per CR 66
  FranchiseCode = isnull(a.FranchiseCode, 'Unknown'),
  Area    = isnull(a.AreaSalesManager, 'Yet to be allocated'),
  Region    = isnull(a.RegionalSalesManager, 'Yet to be allocated')
from  msdt_Adviser a, 
  mstt_Agents c
where #mst_ProductionProduct.AdviserId = a.AdviserId
and a.FranchiseCode = c.Code
 
--now update for the targets
update #mst_ProductionProduct
set Franchise = isnull(rtrim(ltrim(coalesce(c.CompetitionName, c.TradingName, c.DESCN))), 'Yet to be allocated'), -- as per CR 66
  FranchiseCode = isnull(a.FranchiseCode, 'Unknown'),
  Area    = isnull(a.AreaSalesManager, 'Yet to be allocated'),
  Region    = isnull(a.RegionalSalesManager, 'Yet to be allocated')
from  msdt_AdviserDummies a,
  mstt_Agents c
where #mst_ProductionProduct.AdviserId = a.AdviserId
and a.FranchiseCode = c.Code


--
-- Get the results
--


select  cYear.FranchiseCode,
  cYear.Franchise,
  cYear.Area,
  cYear.Region,
  cYear.ProductGroup,
  cYear.ProductName,
  cYear.BreakDownFlag,
  IsNull(cMonth.[Turnover],0) Turnover_CurrentMonth,
  IsNull(cMonth.[NBI],0)    NBI_CurrentMonth,
  IsNull(cYear.[Turnover],0)  Turnover_CurrentYear,
  IsNull(cYear.[NBI],0)   NBI_CurrentYear
from
(
  select  p.FranchiseCode,
    p.Franchise,
    p.Area,
    p.Region,
    p.ProductGroup,
    p.ProductName,
    p.BreakDownFlag,
    sum(p.Turnover) [Turnover],
    sum(p.NBI) [NBI]
  from  #mst_ProductionProduct p
  where 
  left(p.DateIssued,4) = case when @Date = 'Current Position' then year(getdate()) else  year(@RunMonth) end
  and right(p.DateIssued,2) >= '01'
  and right(p.DateIssued,2) <= case when @Date = 'Current Position' then month(getdate()) else month(@RunMonth) end
  group by
    p.FranchiseCode,
    p.Franchise,
    p.Area,
    p.Region,
    p.ProductGroup,
    p.ProductName,
    p.BreakDownFlag
) cYear LEFT OUTER JOIN 
(
  select  p.FranchiseCode,
    p.Franchise,
    p.Area,
    p.Region,
    p.ProductGroup,
    p.ProductName,
    p.BreakDownFlag,
    sum(p.Turnover) [Turnover],
    sum(p.NBI) [NBI]
  from  #mst_ProductionProduct p
  where 
  left(p.DateIssued,4) = case when @Date = 'Current Position' then year(getdate()) else year(@RunMonth) end
  and right(p.DateIssued,2) = case when @Date = 'Current Position' then month(getdate()) else month(@RunMonth) end
  group by
    p.FranchiseCode,
    p.Franchise,
    p.Area,
    p.Region,
    p.ProductGroup,
    p.ProductName,
    p.BreakDownFlag
) cMonth ON cMonth.FranchiseCode = cYear.FranchiseCode
  and cMonth.productgroup = cYear.productgroup
  and cMonth.productname = cYear.productname
order by
  case cYear.ProductName
    when 'Competition Points Adj' then 1
    else 2
  end desc



drop table #mst_ProductionGroupBreakdown
drop table #mst_ProductionProduct


GO
