CREATE PROCEDURE [dbo].[msp_SelectFranchiseStatementAdj] -- WITH RECOMPILE,ENCRYPTION
  /* Param List */
  @FranchiseCode nvarchar(50),
  /* @Franchise varchar(255), */
  @UserId nvarchar(50),
  @Date nvarchar(50),
        @RunMonth nvarchar(50)
AS

/******************************************************************************

Copyright (C) Moore Stephens Consulting Limited 2005

Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
          
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>

*******************************************************************************/

select  b.[IssuedDate] EffectiveDate,
  isnull(a.Turnover,0) Turnover,
  isnull(a.NBI,0) NBI,
  a.Comment
from  mstt_ProductionAdjustments a,
  (
    select  DateId,
      [DateTime] [IssuedDate],
      [Year]
    from  msdt_CalendarTime
    where entrytypeid = 2
    and   [Year] = case when @Date = 'Current Position' then year(getdate()) else  year(@RunMonth) end
      and [Month] >= '01'
      and [Month] <= case when @Date = 'Current Position' then month(getdate()) else month(@RunMonth) end
    
    
    --[Year] = year(getdate())
  
  
  ) b,
  (
    select  AdviserID,
      FranchiseCode,
      Franchise
    from  msdt_Adviser
    union all
    select  AdviserID,
      FranchiseCode,
      Franchise
    from  msdt_AdviserDummies
  ) adv,
  msct_UserAccessControl uac    -- Add security
where a.AdviserId =adv.AdviserID
  and adv.FranchiseCode = @FranchiseCode
--  and adv.Franchise = @Franchise
  and a.AdviserId = uac.AdviserId   -- Add security
  and uac.DomainLogin = @UserId   -- Add security
  and a.DateIssuedId = b.DateId
  and a.ProductionFlag = 'N'
  and a.[Year] = b.[Year]
order by b.[IssuedDate] desc



GO
