CREATE PROCEDURE [dbo].[msp_SelectHistoricMonths]
AS
--########################################################################
-- Copyright (c) MOORE STEPHENS, 2006 All rights reserved
--
-- Object  : procedure
-- Name    : msp_SelectHistoricMonths
-- Desc    : Retreives a list of Valid months in the Quality Aggregation Table
-- Owner   : JNHL
-- Created : 09/08/2006
--
-- Amended : 
--########################################################################


  SELECT DISTINCT 
    ReportMonth AS Value,
    DateName(Month,ReportMonth)+' '+DateName(Year,ReportMonth) AS Label
  FROM mstt_AgentQualityAggregation
  WHERE KPILevel= 'ADVISERKPI'
    AND ReportMonth>DateAdd(M,-12,(SELECT MAX(ReportMonth) 
                    FROM mstt_AgentQualityAggregation
                    WHERE KPILevel= 'ADVISERKPI'))
  ORDER BY ReportMonth DESC

    

GO
