CREATE PROCEDURE [dbo].[msp_SelectInitialAssessmentFilter]
AS
--########################################################################
-- Copyright (c) MOORE STEPHENS, 2006 All rights reserved
--
-- Object  : procedure
-- Name    : msp_SelectInitialAssessmentFilter
-- Desc    : Select A List Of Filters for Initial Assessment.
-- Owner   : JL
-- Created : 22/08/2006
--
--########################################################################


  SELECT Distinct 
        CaseCheckInitialAssessment Label, 
        CaseCheckInitialAssessment AS Value
  FROM [msv_AgentQualityCases]
  WHERE 
    CaseCheckInitialAssessment IS NOT NULL
  UNION SELECT '~ALL~' Label,'*' Value




