CREATE PROCEDURE [dbo].[msp_SelectManagerLeague] -- WITH RECOMPILE,ENCRYPTION
    @ProductGroup nvarchar(50),
    @Size nvarchar(50),
    @ProductSubGroup nvarchar(50),
    @Area nvarchar(50),
    @Sequence nvarchar(50),
    @Date nvarchar(50)
AS

/******************************************************************************

Copyright (C) Moore Stephens Consulting Limited 2005

Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
          
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>

*******************************************************************************/

--Calculate weighting factor
declare @CurrentMonthLastYearWeightingFactor float
set @CurrentMonthLastYearWeightingFactor = 
  (select cast(day(getdate()-1) as Float) / 
    cast((DAY(DATEADD(d, -DAY(DATEADD(m,1,getdate()-1)),DATEADD(m,1,getdate()-1)))) as Float))

--Select Regional Sales Manager League results
select  Area as [ASDName]
,   Region as [RSMName]
,   FranchiseCount
,   AdviserCount
,   isnull(YTD_Turnover,0) as [YTD_Turnover]
,   isnull(Prev_YTD_Turnover,0)as [Prev_YTD_Turnover]
,   isnull(YTD_Turnover,0) - isnull(Prev_YTD_Turnover,0) as [YTD_Turnover_Growth]
,   (YTD_Turnover - Prev_YTD_Turnover)/Prev_YTD_Turnover as [YTD_Turnover_Pct_Growth]
from
(
  select  Area
  ,   Region 
  ,   FranchiseCount
  ,   AdviserCount
  ,   --Select either AtCurrentDate or AtPrevMonthEnd figures depending on @Date parameter
      case when @Date='Current Date' then [YTD_Turnover_AtCurrentDate] 
      when @Date='End of Prev Month End' then [YTD_Turnover_AtPrevMonthEnd] 
      else null end as [YTD_Turnover]
  ,   --Select either AtCurrentDate or AtPrevMonthEnd figures depending on @Date parameter
      case when @Date='Current Date' then [Prev_YTD_Turnover_AtCurrentDate] 
      when @Date='End of Prev Month End' then [Prev_YTD_Turnover_AtPrevMonthEnd] 
      else null end as [Prev_YTD_Turnover]
  from
  (
    select  Area
    ,   Region
    ,   (
        --Select Franchise Count
        select sum(val)
        from msft_CapacityTerminationCounts ctc 
          inner join msdt_adviserdummieshistory adh on ctc.adviserid = adh.adviserid
          inner join msdt_FranchiseSize fs on ctc.FranchiseSizeId = fs.FranchiseSizeId
        where level = 'Franchise'
        and reporttype = 'Capacity'
        and comparison = 'Actual'
        and statusdate = (select max(statusdate) from msft_CapacityTerminationCounts where comparison = 'Actual')
        and AreaSalesManager = Area
        and RegionalSalesManager = Region
        and FranchiseSizeType like @Size
        ) [FranchiseCount]
     ,    (
        --Select Adviser Count
        select sum(val)
        from msft_CapacityTerminationCounts ctc 
          inner join msdt_adviserhistory adh on ctc.adviserid = adh.adviserid
          inner join msdt_FranchiseSize fs on ctc.FranchiseSizeId = fs.FranchiseSizeId
        where level = 'Adviser'
        and reporttype = 'Capacity'
        and comparison = 'Actual'
        and statusdate = (select max(statusdate) from msft_CapacityTerminationCounts where comparison = 'Actual')
        and AreaSalesManager = Area
        and RegionalSalesManager = Region
        and FranchiseSizeType like @Size
        ) [AdviserCount]
     ,    sum(case when year(dateissued) = year(getdate()) then Measure 
          else NULL end) [YTD_Turnover_AtCurrentDate]
     ,    --Apply weighting factor to corresponding month in previous year (for transitional data only - PolicyNumber = -99)
        sum(case when year(dateissued) = year(getdate())-1 and month(dateissued) <= month(getdate())-1 then Measure 
          when policynumber <> -99 and year(dateissued) = year(getdate())-1 and month(dateissued) = month(getdate()) and day(dateissued) <= day(getdate())-1 then Measure 
          when policynumber = -99 and year(dateissued) = year(getdate())-1 and month(dateissued) = month(getdate()) then Measure*@CurrentMonthLastYearWeightingFactor 
          else NULL end) [Prev_YTD_Turnover_AtCurrentDate]
     ,    sum(case when year(dateissued) = year(getdate()) and month(dateissued) <= month(getdate()) -1 then Measure 
          else NULL end) [YTD_Turnover_AtPrevMonthEnd]
     ,    sum(case when year(dateissued) = year(getdate())-1 and month(dateissued) <= month(getdate()) -1 then Measure 
          else NULL end) [Prev_YTD_Turnover_AtPrevMonthEnd]
    from 
     mst_ManagerLeague
    where 
     Area like @Area and
     ProductGroup like @ProductGroup and
     ProductSubGroup like @ProductSubGroup and
     Size like @Size
    group by
     Area,
     Region
  ) as BaseQuery
) as DateQuery
order by
 --Order by column depending on @Sequence parameter
 case when @sequence='YTD Turnover' then [YTD_Turnover] 
 when @sequence='Amount of Growth' then isnull([YTD_Turnover],0)-isnull([Prev_YTD_Turnover],0)
 when @sequence='% Growth' then ([YTD_Turnover]-[Prev_YTD_Turnover])/[Prev_YTD_Turnover]
 else Region end
desc


GO
/****** Object:  StoredProcedure [dbo].[msp_SelectMonthFilter]    Script Date: 7/3/2026 3:44:25 PM ******/
