CREATE PROCEDURE [dbo].[msp_SelectMonthFilter]
AS

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2006 All rights reserved
--
-- Object  : procedure
-- Name    : msp_SelectMonthFilter
-- Desc    : Select A List Of Filters for the last Six Months
-- Owner   : JL
-- Created : 22/08/2006
--
-- Amended : 
--########################################################################


SELECT     
  CAST(DATEPART(M, DATEADD(M, -Mon, ReportMonth)) AS varchar) + '/' + CAST(DATEPART(Year, DATEADD(M, - Mon, ReportMonth)) AS Varchar) Value, 
    CAST(DATEPART(M, DATEADD(M, -Mon, ReportMonth)) AS varchar) + '/' + CAST(DATEPART(Year, DATEADD(M, - Mon, ReportMonth)) AS Varchar) Label
FROM         
  (SELECT DISTINCT MAX(ReportMonth) ReportMonth
       FROM          mstt_AgentQualityAggregation
       WHERE      KPILevel = 'ADVISERKPI') Actual CROSS JOIN
          (SELECT     0 Mon
            UNION
            SELECT     1 Mon
            UNION
            SELECT     2 Mon
            UNION
            SELECT     3 Mon
            UNION
            SELECT     4 Mon
            UNION
            SELECT     5 Mon) Adder
UNION SELECT     
    '*' VALUE, 
    '~ALL~' Label
    

GO
