CREATE PROCEDURE [dbo].[msp_SelectNewRecruits] -- WITH RECOMPILE,ENCRYPTION
  @Measure nvarchar(50),
    @DateRange nvarchar(50),
    @UserId nvarchar(50)
    
AS

--set @DateRange = 'Last 6 Months'

/******************************************************************************

Copyright (C) Moore Stephens Consulting Limited 2005

Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
          
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>

*******************************************************************************/


select 
Area,
Region,
Franchise,
Adviser,
ProductGroup,
DateIssued [Period],
DateIssued [Period2],
DateAppointed = convert(nvarchar(12),DateAppointed, 106),
case when @Measure = 'Turnover' then sum(p.Turnover) 
     when @Measure = 'No. of Cases' then sum(p.Cases)
     when @Measure = 'NBI' then sum(p.NBI)
--     when @Measure = 'DA' then sum(p.DA)   --removed as per TPR 885
--     when @Measure = 'Sales Margin' then sum(p.Margin)
     else 0 end [Amount]
into #mst_matrix
from 
 mst_NewRecruit p,
 msct_UserAccessControl uac
where
 p.AdviserId = uac.AdviserId and
 uac.DomainLogin = @UserId and
 p.DateIssued between
      case when @DateRange = 'Last 12 Months' then convert(nvarchar(6),dateadd(yy,-1,getdate()),112)
           else convert(nvarchar(6),dateadd(mm,-6,getdate()),112) end and
           convert(nvarchar(6),getdate(),112) 
group by
Area,
Region,
Franchise,
Adviser,
ProductGroup,
DateIssued,
DateAppointed


insert into #mst_matrix

select 
Area,
Region,
Franchise,
Adviser,
ProductGroup,
'YTD',
(year(getdate()) * 100) + 12,
DateAppointed = convert(nvarchar(12),DateAppointed, 106),
case when @Measure = 'Turnover' then sum(p.Turnover) 
     when @Measure = 'Cases' then sum(p.Cases)
     when @Measure = 'NBI' then sum(p.NBI)
     else 0 end [Amount]
from 
 mst_NewRecruit p,
 msct_UserAccessControl uac
where
 p.AdviserId = uac.AdviserId and
 uac.DomainLogin = @UserId and
 left(p.DateIssued,4)=
 convert(nvarchar(4),year(getdate())) 
group by
Area,
Region,
Franchise,
Adviser,
ProductGroup,
DateAppointed


insert into #mst_matrix

select 
Area,
Region,
Franchise,
Adviser,
ProductGroup,
'YTDP',
(year(dateadd(yy,-1,getdate())) * 100) + 12,
DateAppointed = convert(nvarchar(12),DateAppointed, 106),
case when @Measure = 'Turnover' then sum(p.Turnover) 
     when @Measure = 'Cases' then sum(p.Cases)
     when @Measure = 'NBI' then sum(p.NBI)
     else 0 end [Amount]
from 
 mst_NewRecruit p,
 msct_UserAccessControl uac
where
 p.AdviserId = uac.AdviserId and
 uac.DomainLogin = @UserId and
 p.DateIssued between
 convert(nvarchar(4),dateadd(yy,-1,getdate()),112) + '01'
 and
 convert(nvarchar(6),dateadd(yy,-1,getdate()),112) 
group by
Area,
Region,
Franchise,
Adviser,
ProductGroup,
DateAppointed

select
 'Company' as Company,
 Area,
 Region,
 Franchise,
 Adviser,
 ProductGroup,
DateAppointed = convert(nvarchar(12),DateAppointed, 106),
--  [Period],
--  [Period2],
--  [Amount],
 sum(case when left(Period,3) <> 'YTD' and datediff(mm,convert(datetime,([Period2]) + '01'), convert(datetime,(convert(nvarchar(6),getdate(),112) + '01'))) = '11' then [Amount] else '0' end) '1',
 sum(case when left(Period,3) <> 'YTD' and datediff(mm,convert(datetime,([Period2]) + '01'), convert(datetime,(convert(nvarchar(6),getdate(),112) + '01'))) = '10' then [Amount] else '0' end) '2',
 sum(case when left(Period,3) <> 'YTD' and datediff(mm,convert(datetime,([Period2]) + '01'), convert(datetime,(convert(nvarchar(6),getdate(),112) + '01'))) = '9' then [Amount] else '0' end) '3',
 sum(case when left(Period,3) <> 'YTD' and datediff(mm,convert(datetime,([Period2]) + '01'), convert(datetime,(convert(nvarchar(6),getdate(),112) + '01'))) = '8' then [Amount] else '0' end) '4',
 sum(case when left(Period,3) <> 'YTD' and datediff(mm,convert(datetime,([Period2]) + '01'), convert(datetime,(convert(nvarchar(6),getdate(),112) + '01'))) = '7' then [Amount] else '0' end) '5',
 sum(case when left(Period,3) <> 'YTD' and datediff(mm,convert(datetime,([Period2]) + '01'), convert(datetime,(convert(nvarchar(6),getdate(),112) + '01'))) = '6' then [Amount] else '0' end) '6',
 sum(case when left(Period,3) <> 'YTD' and datediff(mm,convert(datetime,([Period2]) + '01'), convert(datetime,(convert(nvarchar(6),getdate(),112) + '01'))) = '5' then [Amount] else '0' end) '7',
 sum(case when left(Period,3) <> 'YTD' and datediff(mm,convert(datetime,([Period2]) + '01'), convert(datetime,(convert(nvarchar(6),getdate(),112) + '01'))) = '4' then [Amount] else '0' end) '8',
 sum(case when left(Period,3) <> 'YTD' and datediff(mm,convert(datetime,([Period2]) + '01'), convert(datetime,(convert(nvarchar(6),getdate(),112) + '01'))) = '3' then [Amount] else '0' end) '9',
 sum(case when left(Period,3) <> 'YTD' and datediff(mm,convert(datetime,([Period2]) + '01'), convert(datetime,(convert(nvarchar(6),getdate(),112) + '01'))) = '2' then [Amount] else '0' end) '10',
 sum(case when left(Period,3) <> 'YTD' and datediff(mm,convert(datetime,([Period2]) + '01'), convert(datetime,(convert(nvarchar(6),getdate(),112) + '01'))) = '1' then [Amount] else '0' end) '11',
 sum(case when left(Period,3) <> 'YTD' and datediff(mm,convert(datetime,([Period2]) + '01'), convert(datetime,(convert(nvarchar(6),getdate(),112) + '01'))) = '0' then [Amount] else '0' end) '12',
 sum(case when [Period] = 'YTD' then [Amount] else '0' end) 'YTD',
 sum(case when [Period] = 'YTDP' then [Amount] else '0' end) 'YTDP',
sum(case when [Period] = 'YTD' then 
         case when DateAppointed < convert(datetime,(convert(nvarchar(4),getdate(),112) + '01'+'01')) then
                       [Amount] / datepart(dayofyear,getdate()) * 365 else
                       [Amount] / (datepart(dayofyear,getdate()) - datepart(dayofyear,DateAppointed)) * (365 - datepart(dayofyear,DateAppointed)) end
         else '0' end) 'ProjTY',
sum(case when [Period] = 'YTD' then 
         case when DateAppointed < convert(datetime,(convert(nvarchar(4),getdate(),112) + '01'+'01')) then
                       [Amount]/datepart(dayofyear,(getdate()))* 365 else
                       [Amount]/(datepart(dayofyear,(getdate()))- datepart(dayofyear,DateAppointed))* 365 end
        else '0' end) 'ProjFY'
from
 #mst_matrix 

group by
 Area,
 Region,
 Franchise,
 Adviser,
 ProductGroup,
 DateAppointed
--  [Period],
--  [Period2],
--  [Amount]
order by
 4,7

drop table #mst_matrix





GO
