CREATE procedure [dbo].[msp_SelectQualityAgentDetails]
    @AgentCode       nvarchar(50),
    @UserId          nvarchar(50),
    @AllowDelegates  char(1)

as

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : msp_SelectQualityAgentDetails.sql
-- Desc    : 
-- Owner   : BT
-- Created : 03/07/2006
--
-- Amended : 13/07/2006  - BT  - Remove Audience & UserId parameters
-- Amended : 31/07/2006  - BT  - Add segment field and Practice code/name
-- Amended : 02/08/2006  - BT  - Set SupervisorStatus to 'Not Supervisor'
-- Amended : 14/08/2006  - MK  - Added further security, to ensure that the 
--                               user executing the report is allowed to see
--                               the agent that has been passed in to the proc.
-- Amended : 16/08/2006  - MK  - Add function to allow delegate access. That is, allow a user
--                               to impersonate the user to whom they have been given access.
-- Amended : 18/10/2006  - MK  - Use Max Date for the Agent, so as to catch Agents
--                               who have left.
--
--       14/02/2007  - RH/OW - Tuned for performance as part of Agent KPI report production issue
--         - Fixes to affected procs/fns include explicit conversion of datatypes in query
--           expressions where parameter type is not matched to table data type
--           allowing Index seeks rather than scans
--         - Addition of indexes to required Quality tables
--         - Explicit alternative logic paths for queries where global parameter (eg Filter) is not supplied
--           avoiding table/index scans forced by unnecessary OR statememnts
--         - Use permissions caching wrapper around existing permissions/span checks
--########################################################################


if isnull(@AllowDelegates, 'N') = 'Y'
  set @UserId = (select dbo.msf_SQGetUserDelegatedFrom(@UserId))
  

declare @PermCheck nvarchar(50)
exec dbo.owp_SQCheckCachedPermissions @UserId, @AgentCode, 'AdviserKPI', 'CURRENT', 1, @PermCheck output

if @PermCheck = 'DENY'
--if dbo.msf_SQCheckPermissions (@UserId, @AgentCode, 'AdviserKPI', 'CURRENT', 1) = 'DENY' 
 

select 
null as [AdviserCode],
null as [AdviserName],
null as [Contract],
null as [SupervisorStatus],
null as [Segment],
null as [SalesQualityASDLevelCode],
null as [SalesQualityASDLevelName],
null as [SalesQualityRSMLevelCode],
null as [SalesQualityRSMLevelName],
null as [SalesQualitySQMLevelCode],
null as [SalesQualitySQMLevelName],
null as [SalesQualityPSLevelCode],
null as [SalesQualityPSLevelName],
null as [PracticeCode],
null as [PracticeName]

else

begin

select distinct a.[Code] AS [AdviserCode]
      ,a.[Descn] AS [AdviserName]
      ,a.[CompetentStatusDescription] AS [Contract]
      ,CASE WHEN a.[CanSupervise] = 1 THEN 'Supervisor' 
            ELSE 'Not Supervisor' 
       END AS [SupervisorStatus]
      ,a.[AgentSpecialistDesc] AS [Segment]
      ,h.[SalesQualityASDLevelCode]
      ,asd.[Descn] AS [SalesQualityASDLevelName]
      ,h.[SalesQualityRSMLevelCode]
      ,rsm.[Descn] AS [SalesQualityRSMLevelName]
      ,h.[SalesQualitySQMLevelCode]
      ,sqm.[Descn] AS [SalesQualitySQMLevelName]
      ,h.[SalesQualityPSLevelCode]
      ,ps.[Descn] AS [SalesQualityPSLevelName]
      ,h.[PracticeCode]
      ,prac.[Descn] AS [PracticeName]
from   [mstt_Agents] a
       INNER JOIN [mstt_AgentQualityHierarchy] h on h.[AgentCode] = a.[Code]
       LEFT JOIN [mstt_Agents] asd ON asd.[Code] = [SalesQualityASDLevelCode]
       LEFT JOIN [mstt_Agents] rsm ON rsm.[Code] = [SalesQualityRSMLevelCode]
       LEFT JOIN [mstt_Agents] sqm ON sqm.[Code] = [SalesQualitySQMLevelCode]
       LEFT JOIN [mstt_Agents] ps ON ps.[Code] = [SalesQualityPSLevelCode]
       LEFT JOIN [mstt_Agents] prac ON prac.[Code] = h.[PracticeCode]
where  a.[Code] = convert(varchar(7),@AgentCode)
and    [AgentHierarchyEndDate] = 
  (select max([AgentHierarchyEndDate]) 
  from [mstt_AgentQualityHierarchy]
  where AgentCode = convert(varchar(50),@AgentCode))


end




GO
/****** Object:  StoredProcedure [dbo].[msp_SelectQualityAgentHierarchy]    Script Date: 7/3/2026 3:44:25 PM ******/
