create procedure [dbo].[msp_SelectQualityAgentHierarchy]
    @Level          nvarchar(50),
    @UserId         nvarchar(50),
    @AllowDelegates char(1) = NULL,
    @Filter         nvarchar(50) = NULL --Filter is optional

as

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2006 All rights reserved
--
-- Object  : procedure
-- Name    : msp_SelectQualityAgentHierarchy.sql
-- Desc    : Select a list of values and labels for agents at the specified level
--           Apply an optional filter for the parent agent code
-- Owner   : BT
-- Created : 06/07/2006
--
-- Amended : 21/07/2006  - BT  - Retrieve ASQM's ASD from both selling RSM's and SQM's
-- Amended : 24/07/2006  - BT  - Add Practice hierarchy level
-- Amended : 31/07/2006  - BT  - Grant full access to head office users
-- Amended : 31/07/2006  - BT  - Limit hierarchy records to current aggregation period
-- Amended : 31/07/2006  - BT  - Modify expected return value for head office users
-- Amended : 10/08/2006  - BT  - Use max(ReportMonth) where KPILevel = 'ADVISERKPI'
-- Amended : 10/08/2006  - MK  - Re-point this proc to point to msf_SQGetAgentsInSpan,
--                               which in turn points at msct_AdvisersInQualitySpan,
--                               which is populated overnight, in order to net a performance
--                               improvement.
-- Amended : 10/08/2006  - MK  - Add function to allow delegate access. That is, allow a user
--                               to impersonate the user to whom they have been given access. 
-- Amended : 17/08/2006  - BT  - Perform concatenation of Label here instead of in msf_SQGetAgentsInSpan
-- Amended : 31/08/2006  - MK  - Remove delegation UserId translation, as this now occurs in msf_SQGetAgentCode
--
--########################################################################


declare @AgentCode nvarchar(50)
set @AgentCode = dbo.msf_SQGetAgentCode(@UserId, @AllowDelegates)

declare @Table table (Value varchar(50), Label varchar(255))

if @Filter = '-1'
set @Filter = null

insert into @Table
select [AgentCode], ltrim(rtrim([Description])) + ' (' + AgentCode + ')'
from msf_SQGetAgentsInSpan(@AgentCode, @Level, 'CURRENT', 1, @Filter)

insert into @Table
select -1, '~ALL~'

if @Level = 'ADVISER'
  insert into @Table
  select -2, 'ZZ~Not a Seller~ZZ'

select * from @Table
where Value is not null
order by [label]


GO
/****** Object:  StoredProcedure [dbo].[msp_SelectQualityAgentHierarchyCascading]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

create procedure [dbo].[msp_SelectQualityAgentHierarchyCascading]
    @AgentCode            nvarchar(50)
   ,@KPILevel             nvarchar(50)
   ,@HierarchyTypeCode    nvarchar(50)
   ,@ReportMonth          datetime
   ,@NumberOfMonths       int

as

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : msp_SelectQualityAgentHierarchyCascading.sql
-- Desc    : Returns a list of Seller Agent Codes that are within the specified Agents span
-- Owner   : BT
-- Created : 27/07/2006
--
--########################################################################

--Sellers who work for an SQM (Both SQM's and ASQM's)
SELECT DISTINCT sqm.[AgentCode] 
FROM   [msv_AgentQualityAggregation] sqm
       LEFT JOIN [msv_AgentQualityAggregation] rsm
             ON rsm.[ReportMonth] = sqm.[ReportMonth] 
             AND rsm.[HierarchyTypeCode] = sqm.[HierarchyTypeCode] 
             AND rsm.[SummaryPeriod] = sqm.[SummaryPeriod]
             AND rsm.[AgentCode] = sqm.[SalesQualitySQMLevelCode]
             AND rsm.[KPILevel] = 'RSMSUMMARY'
       LEFT JOIN [msv_AgentQualityAggregation] asd
             ON asd.[ReportMonth] = rsm.[ReportMonth] 
             AND asd.[HierarchyTypeCode] = rsm.[HierarchyTypeCode] 
             AND asd.[SummaryPeriod] = rsm.[SummaryPeriod]
             AND asd.[AgentCode] = rsm.[SalesQualityRSMLevelCode]
             AND asd.[KPILevel] = 'ASDSUMMARY'
WHERE  sqm.[ReportMonth] = @ReportMonth
AND    sqm.[KPILevel] = 'SQMSUMMARY'
AND    sqm.[HierarchyTypeCode] = @HierarchyTypeCode
AND    sqm.[SummaryPeriod] = @NumberOfMonths
AND    CASE WHEN @KPILevel = 'ASDSUMMARY' THEN asd.[SalesQualityASDLevelCode] 
            WHEN @KPILevel = 'RSMSUMMARY' THEN rsm.[SalesQualityRSMLevelCode] 
            WHEN @KPILevel = 'SQMSUMMARY' THEN sqm.[SalesQualitySQMLevelCode] 
       END = @AgentCode 
UNION
--Sellers who work for a PS
SELECT DISTINCT ps.AgentCode
FROM   [msv_AgentQualityAggregation] ps
       LEFT JOIN [msv_AgentQualityAggregation] sqmps
             ON sqmps.[ReportMonth] = ps.[ReportMonth] 
             AND sqmps.[HierarchyTypeCode] = ps.[HierarchyTypeCode] 
             AND sqmps.[SummaryPeriod] = ps.[SummaryPeriod]
             AND sqmps.[AgentCode] = ps.[SalesQualityPSLevelCode]
             AND sqmps.[KPILevel] = 'SQMPS'
       LEFT JOIN [msv_AgentQualityAggregation] rsm
             ON rsm.[ReportMonth] = sqmps.[ReportMonth] 
             AND rsm.[HierarchyTypeCode] = sqmps.[HierarchyTypeCode] 
             AND rsm.[SummaryPeriod] = sqmps.[SummaryPeriod]
             AND rsm.[AgentCode] = sqmps.[SalesQualitySQMLevelCode]
             AND rsm.[KPILevel] = 'RSMSUMMARY'
       LEFT JOIN [msv_AgentQualityAggregation] asd
             ON asd.[ReportMonth] = rsm.[ReportMonth] 
             AND asd.[HierarchyTypeCode] = rsm.[HierarchyTypeCode] 
             AND asd.[SummaryPeriod] = rsm.[SummaryPeriod]
             AND asd.[AgentCode] = rsm.[SalesQualityRSMLevelCode]
             AND asd.[KPILevel] = 'ASDSUMMARY'
WHERE  ps.[ReportMonth] = @ReportMonth
AND    ps.[KPILevel] = 'PSSUMMARY'
AND    ps.[HierarchyTypeCode] = @HierarchyTypeCode
AND    ps.[SummaryPeriod] = @NumberOfMonths
AND    CASE WHEN @KPILevel = 'ASDSUMMARY' THEN asd.[SalesQualityASDLevelCode] 
            WHEN @KPILevel = 'RSMSUMMARY' THEN rsm.[SalesQualityRSMLevelCode] 
            WHEN @KPILevel = 'SQMSUMMARY' THEN sqmps.[SalesQualitySQMLevelCode] 
            WHEN @KPILevel = 'PSSUMMARY'  THEN ps.[SalesQualityPSLevelCode] 
       END = @AgentCode 
UNION
--SQM Sellers who work for an ASQM
SELECT DISTINCT sqm.[AgentCode] 
FROM   [msv_AgentQualityAggregation] sqm
       LEFT JOIN [msv_AgentQualityAggregation] rsm
             ON rsm.[ReportMonth] = sqm.[ReportMonth] 
             AND rsm.[HierarchyTypeCode] = sqm.[HierarchyTypeCode] 
             AND rsm.[SummaryPeriod] = sqm.[SummaryPeriod]
             AND rsm.[AgentCode] = sqm.[AgentCode] --Join on SQM's agent code instead of ASQM's
             AND rsm.[KPILevel] = 'RSMSUMMARY'
       LEFT JOIN [msv_AgentQualityAggregation] asd
             ON asd.[ReportMonth] = rsm.[ReportMonth] 
             AND asd.[HierarchyTypeCode] = rsm.[HierarchyTypeCode] 
             AND asd.[SummaryPeriod] = rsm.[SummaryPeriod]
             AND asd.[AgentCode] = rsm.[SalesQualityRSMLevelCode]
             AND asd.[KPILevel] = 'ASDSUMMARY'
WHERE  sqm.[ReportMonth] = @ReportMonth
AND    sqm.[KPILevel] = 'SQMSUMMARY'
AND    sqm.[HierarchyTypeCode] = @HierarchyTypeCode
AND    sqm.[SummaryPeriod] = @NumberOfMonths
AND    CASE WHEN @KPILevel = 'ASDSUMMARY' THEN asd.[SalesQualityASDLevelCode] 
       END = @AgentCode 
UNION
--RSM Sellers who work for an ASQM
SELECT DISTINCT sqm.[AgentCode] 
FROM   [msv_AgentQualityAggregation] sqm
       LEFT JOIN [msv_AgentQualityAggregation] asd
             ON asd.[ReportMonth] = sqm.[ReportMonth] 
             AND asd.[HierarchyTypeCode] = sqm.[HierarchyTypeCode] 
             AND asd.[SummaryPeriod] = sqm.[SummaryPeriod]
             AND asd.[AgentCode] = sqm.[AgentCode]  --Join on RSM's agent code instead of ASQM's
             AND asd.[KPILevel] = 'ASDSUMMARY'
WHERE  sqm.[ReportMonth] = @ReportMonth
AND    sqm.[KPILevel] = 'SQMSUMMARY'
AND    sqm.[HierarchyTypeCode] = @HierarchyTypeCode
AND    sqm.[SummaryPeriod] = @NumberOfMonths
AND    CASE WHEN @KPILevel = 'ASDSUMMARY' THEN asd.[SalesQualityASDLevelCode] 
       END = @AgentCode 
UNION
--Sellers
SELECT DISTINCT [AgentCode] 
FROM   [msv_AgentQualityAggregation]
WHERE  [ReportMonth] = @ReportMonth
AND    [KPILevel] = 'ADVISERKPI'
AND    CASE WHEN @KPILevel = 'ADVISERKPI' THEN [AgentCode] 
       END = @AgentCode 


GO
/****** Object:  StoredProcedure [dbo].[msp_SelectQualityAgentHierarchyChanges]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER OFF
GO

Create Procedure [dbo].[msp_SelectQualityAgentHierarchyChanges]
  @ReportType varchar(10)= NULL
AS

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2006 All rights reserved
--
-- Object  : procedure
-- Name    : msp_SelectQualityAgentHierarchyChanges
-- Desc    : Selects All Agent Heirarchy Changes in the Current Period or ALL
-- Owner   : JNHL
-- Created : 26/07/2006
--
-- Amended : 09/08/2006 Added KPILevel<>CORP 
--
--########################################################################


  Declare @ReportMonth DateTime

  IF @ReportType='ALL'
    BEGIN
      SELECT @ReportMonth=MIN(Reportmonth) FROM mstt_AgentQualityAggregation
    END
  ELSE
    BEGIN
      SELECT @ReportMonth=MAX(Reportmonth) 
      FROM mstt_AgentQualityAggregation
      WHERE KPILevel= 'ADVISERKPI'
    END

  SELECT     
    Agent.CODE AS AgentCode, 
    Agent.DESCN AS AgentName, 
    ISNULL(Agent.CompetentStatusDescription, 'N/A') AS AgentStatus, 
    Agent.AgentCategoryDescription, 
    Agent.CDIStatusDate AS AgentStatusDate, 
    Super.CODE AS SupervisorCode, 
    Super.DESCN AS SupervisorName, 
    Super.CompetentStatusDescription AS SupervisorStatus, 
    Super.CDIStatusDate AS SupervisorStatusDate, 
    AQH.AgentHierarchyStartDate, 
    Super.AgentCategoryDescription AS SuperCategoryDescription
  FROM         
    mstt_Agents Agent 
    LEFT OUTER JOIN mstt_Agents Super 
      ON Agent.SpanSupervisorCode = Super.CODE 
    INNER JOIN mstt_AgentQualityHierarchy AQH 
      ON Agent.CODE = AQH.AgentCode
  WHERE     (AQH.IsCurrent = 1)
    And (Agent.CDIStatusDate>=@ReportMonth Or Super.CDIStatusDate>=@ReportMonth)
  ORDER BY Agent.CODE


GO
