CREATE procedure [dbo].[msp_SelectQualityCases]
    @AgentCode            nvarchar(50)
   ,@KPILevel             nvarchar(50)
   ,@HierarchyTypeCode    nvarchar(50)
   ,@ReportMonth          datetime
   ,@NumberOfMonths       int
   ,@UserId               nvarchar(50)
   ,@AllowDelegates       char(1)
   ,@SecurityByPass       char(1)='N'
as

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : msp_SelectQualityCases.sql
-- Desc    : Select Quality Case Checks for the specified agent as seller or manager
-- Owner   : BT
-- Created : 26/07/2006
--
-- Amended : 28/07/2006  - BT  - Trim fields, Use function to get agents in span instead of proc
-- Amended : 03/08/2006  - BT  - Return blank rows for Compliance Categories if no cases are found
-- Amended : 07/08/2006  - BT  - Sort by CaseCheckValidatedDate descending
-- Amended : 09/08/2006  - BT  - Use shortened failure description
-- Amended : 10/08/2006  - MK  - Remove @ReportMonth parameter from call to msf_SQGetAgentsInSpan
-- Amended : 11/08/2006  - BT  - Specify filter parameter in call to msf_SQGetAgentsInSpan
-- Amended : 11/08/2006  - MK  - Remove User's AgentCode from #Agents if @KPILevel <> 'AdviserKPI'
-- Amended : 14/08/2006  - MK  - Added further security, to ensure that the 
--                               user executing the report is allowed to see
--                               the agent that has been passed in to the proc.
-- Amended : 15/08/2006  - BT  - Use view msv_AgentQualityCases to retrieve Cases data
-- Amended : 16/08/2006  - BT  - Fix issue where Adviser KPI report for PS/SQM/RSM included all advisers that report to them
-- Amended : 16/08/2006  - MK  - Add function to allow delegate access. That is, allow a user
--                               to impersonate the user to whom they have been given access.
-- Amended : 21/08/2006  - JL  - Added Security ByPass to Procedure so that Can by pass as part of filters
--                   NB - @SecurityByPass has a default value of 'N'
-- Amended : 21/08/2006  - JL  - Added Code to ensure that the @SecurityByPass is Set to Either Y or N, and N by default
-- Amended : 22/08/2006  - BT  - Add new column CaseCheckFinalAssessment
-- Amended : 29/08/2006  - BT  - Replace nulls with blank string because RS cannot perform like operation on nulls
-- Amended : 30/08/2006  - MK  - Add further checks to ensure that results are filtered by the AgentCode (Manager)
--                               passed in, if looking at KPI view.
-- Amended : 09/10/2006  - MK  - Add date logic/restrictions as per Item 138
--
--       14/02/2007  - RH/OW - Tuned for performance as part of Agent KPI report production issue
--         - Fixes to affected procs/fns include explicit conversion of datatypes in query
--           expressions where parameter type is not matched to table data type
--           allowing Index seeks rather than scans
--         - Addition of indexes to required Quality tables
--         - Explicit alternative logic paths for queries where global parameter (eg Filter) is not supplied
--           avoiding table/index scans forced by unnecessary OR statememnts
--########################################################################

if isnull(@AllowDelegates, 'N') = 'Y'
  set @UserId = (select dbo.msf_SQGetUserDelegatedFrom(@UserId))

declare @PermissionSummaryPeriod int
set @PermissionSummaryPeriod = case when @hierarchyTypeCode = 'CURRENT' then 1 else 6 end

--Ensure SecurityByPass is either Y or N, if Not either, default to N
IF @SecurityByPass NOT IN ('Y','N')
  SET @SecurityByPass='N'


IF @SecurityByPass='N'
BEGIN
  if dbo.msf_SQCheckPermissions (
      @UserId     
      ,@AgentCode       
      ,@KPILevel      
      ,@hierarchyTypeCode 
      ,@PermissionSummaryPeriod   ) = 'DENY' 

  BEGIN
    select 
      '' as [SellerAgentCode],
      '' as [SellerName],
      '' as [ClientNum],
      '' as [ClientName],
      '' as [ContractNum],
      '' as [PolicyRef],
      '' as [DateOfSale],
      '' as [ProductCode],
      '' as [Replacement],
      '' as [IsAReplacement],
      '' as [ReplacementType] ,
      '' as [TrackGroupId],
      '' as [ComplianceCategoryCode],
      '' as [CategoryOfBusiness],
      '' as [CategoryOfBusinessSequence],
      '' as [CaseCheckStatus],
      '' as [CaseCheckReferralReasonCode],
      '' as [CaseCheckReferralReasonDesc],
      '' as [CaseCheckInitialAssessmentMonthYear],
      '' as [CaseCheckInitialAssessmentDate],
      '' as [CaseCheckInitialFailureReasonCode],
      '' as [CaseCheckInitialFailureReasonDesc],
      '' as [CaseCheckFinalAssessmentDate],
      '' as [CaseCheckFinalFailureReasonCode],
      '' as [CaseCheckFinalFailureReasonDesc],
      '' as [CaseCheckInitialAssessment],
      '' as [CaseCheckFinalAssessment],
      '' as [QuestionText],
      '' as [QuestionStandardWording],
      '' as [QuestionFailureReasonCode],
      '' as [QuestionFailureReasonDesc],
      '' as [ASDAgentCode],
      '' as [ASDName],
      '' as [RSMAgentCode],
      '' as [RSMName],
      '' as [SQMAgentCode],
      '' as [SQMName],
      '' as [PSAgentCode],
      '' as [PSName]
    RETURN --Exit SP no need to continue
  END 
END

-- explicitly create #Agents table so we don't get collation issue with dev env
create table #Agents(AgentCode varchar(7) collate LATIN1_GENERAL_CI_AS)

--Create the list of agents under the managers span of control OR insert the sellers agent code
INSERT #Agents(AgentCode)
SELECT [AgentCode]
FROM   dbo.msf_SQGetAgentsInSpan(@AgentCode, @KPILevel, @HierarchyTypeCode, @PermissionSummaryPeriod, NULL)

--#Agents will possibly include the AgentCode of the User running the report. 
--This is only required if the user is running the AdviserKPI report in which case you only want them. 
--If the @Level is not AdviserKPI, the AgentCode must be removed.
if @KPILevel = 'AdviserKPI'
  delete from #Agents where AgentCode <> @AgentCode
else
  delete from #Agents where AgentCode = @AgentCode

--Retrieve the list of quality case checks
SELECT [SellerAgentCode]
      ,[SellerName]
      ,[ClientNum]
      ,[ClientName]
      ,[ContractNum]
      ,[PolicyRef]
      ,[DateOfSale]
      ,[ProductCode]
      ,[Replacement]
      ,[IsAReplacement]
      ,[ReplacementType]
      ,[TrackGroupId]
      ,[ComplianceCategoryCode]
      ,[CategoryOfBusiness]
      ,[CategoryOfBusinessSequence]
      ,[CaseCheckStatus]
      ,[CaseCheckReferralReasonCode]
      ,[CaseCheckReferralReasonDesc]
      ,[CaseCheckInitialAssessmentMonthYear]
      ,[CaseCheckInitialAssessmentDate]
      ,[CaseCheckInitialFailureReasonCode]
      ,[CaseCheckInitialFailureReasonDesc]
      ,[CaseCheckFinalAssessmentDate]
      ,[CaseCheckFinalFailureReasonCode]
      ,[CaseCheckFinalFailureReasonDesc]
      ,[CaseCheckInitialAssessment]
      ,[CaseCheckFinalAssessment]
      ,[QuestionText]
      ,[QuestionStandardWording]
      ,[QuestionFailureReasonCode]
      ,[QuestionFailureReasonDesc]
      ,ISNULL([ASDAgentCode], '') AS [ASDAgentCode]
      ,ISNULL([ASDName], '') AS [ASDName]
      ,ISNULL([RSMAgentCode], '') AS [RSMAgentCode]
      ,ISNULL([RSMName], '') AS [RSMName]
      ,ISNULL([SQMAgentCode], '') AS [SQMAgentCode]
      ,ISNULL([SQMName], '') AS [SQMName]
      ,ISNULL([PSAgentCode], '') AS [PSAgentCode]
      ,ISNULL([PSName], '') AS [PSName]
FROM  [msv_AgentQualityCases] cc 
WHERE cc.[SellerAgentCode] IN (SELECT [AgentCode] FROM #Agents)
-- Case Check must be within the specified number of months of the report month and the last day of the report month
AND cc.[CaseCheckInitialAssessmentDate] BETWEEN DATEADD(mm,(@NumberOfMonths*-1)+1,@ReportMonth) AND DATEADD(dd,-1,DATEADD(mm,1,@ReportMonth))
-- Case Check must be on or after 1-Oct-2006, as per Item 138
AND cc.[CaseCheckInitialAssessmentDate] >= '01 Oct 2006'
AND   ((@HierarchyTypeCode = 'KPI' and @AgentCode = cc.PSAgentCode)
  or (@HierarchyTypeCode = 'KPI' and @AgentCode = cc.SQMAgentCode)
  or (@HierarchyTypeCode = 'KPI' and @AgentCode = cc.RSMAgentCode)
  or (@HierarchyTypeCode = 'KPI' and @AgentCode = cc.ASDAgentCode)
  or (@HierarchyTypeCode = 'KPI' and @AgentCode = cc.SellerAgentCode)
  or (@HierarchyTypeCode = 'CURRENT'))
ORDER BY
      cc.[CaseCheckInitialAssessmentDate] DESC


drop table #Agents





GO
