CREATE procedure [dbo].[msp_SelectQualityCasesByPolicy]
    @AgentCode            nvarchar(50)
   ,@KPILevel             nvarchar(50)
   ,@HierarchyTypeCode    nvarchar(50)
   ,@ReportMonth          datetime
   ,@NumberOfMonths       int
   ,@SellerFilter         nvarchar(50)
   ,@UserId               nvarchar(50)
   ,@AllowDelegates       char(1)
   ,@SecurityByPass     char(1)='N'
as

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : msp_SelectQualityCasesByPolicy.sql
-- Desc    : Select Quality Case Checks for each Policy for the specified agent as seller or manager
-- Owner   : BT
-- Created : 30/08/2006
-- Amended : 09/10/2006 - MK - Amended Date logic as per Item 138
-- Amended : 20/11/2006 - BT - TPR245/246 - Move Seller filtering and replacement filtering from report into procedure so that it can be outer-joined with compliance categories
--                             TPR244 - Sort by compliance category sequence
--                             TPR249 - Perform distinct on case checks to remove duplicates caused by having multiple failing questions
-- Amended : 13/09/2007 - PR - Changes for SR8 - amend code around OriginatingSource
--
--########################################################################

if isnull(@AllowDelegates, 'N') = 'Y'
  set @UserId = (select dbo.msf_SQGetUserDelegatedFrom(@UserId))

declare @PermissionSummaryPeriod int
set @PermissionSummaryPeriod = case when @hierarchyTypeCode = 'CURRENT' then 1 else 6 end

--Ensure SecurityByPass is either Y or N, if Not either, default to N
IF @SecurityByPass NOT IN ('Y','N')
  SET @SecurityByPass='N'


IF @SecurityByPass='N'
BEGIN
  if dbo.msf_SQCheckPermissions (
      @UserId     
      ,@AgentCode       
      ,@KPILevel      
      ,@hierarchyTypeCode 
      ,@PermissionSummaryPeriod   ) = 'DENY' 

  BEGIN
    select 
      '' as [SellerAgentCode],
      '' as [SellerName],
      '' as [ClientNum],
      '' as [ClientName],
      '' as [ContractNum],
      '' as [PolicyRef],
      '' as [DateOfSale],
      '' as [ProductCode],
      '' as [Replacement],
      '' as [IsAReplacement],
      '' as [ReplacementType] ,
      '' as [TrackGroupId],
      '' as [ComplianceCategoryCode],
      '' as [CategoryOfBusiness],
      '' as [CategoryOfBusinessSequence],
      '' as [CaseCheckStatus],
      '' as [CaseCheckReferralReasonCode],
      '' as [CaseCheckReferralReasonDesc],
      '' as [CaseCheckInitialAssessmentMonthYear],
      '' as [CaseCheckInitialAssessmentDate],
      '' as [CaseCheckInitialFailureReasonCode],
      '' as [CaseCheckInitialFailureReasonDesc],
      '' as [CaseCheckFinalAssessmentDate],
      '' as [CaseCheckFinalFailureReasonCode],
      '' as [CaseCheckFinalFailureReasonDesc],
      '' as [CaseCheckInitialAssessment],
      '' as [CaseCheckFinalAssessment],
      '' as [QuestionText],
      '' as [QuestionStandardWording],
      '' as [QuestionFailureReasonCode],
      '' as [QuestionFailureReasonDesc],
      '' as [ASDAgentCode],
      '' as [ASDName],
      '' as [RSMAgentCode],
      '' as [RSMName],
      '' as [SQMAgentCode],
      '' as [SQMName],
      '' as [PSAgentCode],
      '' as [PSName]
    RETURN --Exit SP no need to continue
  END 
END

--Create the list of agents under the managers span of control OR insert the sellers agent code
SELECT [AgentCode] = [AgentCode]
INTO   #Agents
FROM   dbo.msf_SQGetAgentsInSpan(@AgentCode, @KPILevel, @HierarchyTypeCode, @PermissionSummaryPeriod, NULL)

--#Agents will possibly include the AgentCode of the User running the report. 
--This is only required if the user is running the AdviserKPI report in which case you only want them. 
--If the @Level is not AdviserKPI, the AgentCode must be removed.
if @KPILevel = 'AdviserKPI'
  delete from #Agents where AgentCode <> @AgentCode
else
  delete from #Agents where AgentCode = @AgentCode

--Apply Agent code filtering
if @SellerFilter <> '-1' delete from #Agents where AgentCode <> @SellerFilter

--Retrieve the list of policies and quality case checks
SELECT DISTINCT 
       ISNULL([SellerAgentCode], a.[CODE]) AS [SellerAgentCode]
      ,ISNULL([SellerName],RTRIM(a.[DESCN])) AS [SellerName]
      ,ISNULL([ClientNum],p.[CLIENT_NUM]) AS [ClientNum]
      ,ISNULL([ClientName], RTRIM(CASE WHEN c.[CLIENT_TYP] IN (1,4) THEN 
                  CASE WHEN c.[TITLE] IS NULL THEN '' ELSE c.[TITLE] + ' ' END 
                + CASE WHEN c.[FIRSTNAMES] IS NULL THEN '' ELSE c.[FIRSTNAMES] + ' ' END 
                + c.[NAME]
                ELSE c.[NAME] END)) AS [ClientName]
      ,ISNULL([ContractNum], p.[CONT_NUM]) AS [ContractNum]
      ,ISNULL(cc.[PolicyRef], p.[PolicyRef]) AS [PolicyRef]
      ,ISNULL([DateOfSale], 
      CASE WHEN cc.[ComplianceCategoryCode] = 'MCOB' and isnull(p.OriginatingSource,0) = 3 THEN p.[PROP_DATE] 
            WHEN cc.[ComplianceCategoryCode] = 'MCOB' and isnull(p.OriginatingSource,0) <> 3 THEN p.[CreateDate]
            ELSE p.[PROP_DATE] END) AS [DateOfSale]
      ,ISNULL(cc.[ProductCode], p.[ProductCode]) AS [ProductCode]
      ,ISNULL(cc.[Replacement], p.[Replacement]) AS [Replacement]
      ,ISNULL([IsAReplacement], CASE WHEN p.[Replacement] = 0 THEN 'No' 
            WHEN p.[Replacement] IN (1,2,3) THEN 'Yes' 
            END) AS [IsAReplacement]
      ,ISNULL([ReplacementType], CASE WHEN p.[Replacement] = 0 THEN '' 
            WHEN p.[Replacement] = 1 THEN 'A' 
            WHEN p.[Replacement] = 2 THEN 'B' 
            WHEN p.[Replacement] = 3 THEN 'C' 
            END) AS [ReplacementType]
      ,[TrackGroupId]
      ,ISNULL(cc.[ComplianceCategoryCode], cofb.[ComplianceCategoryCode]) AS [ComplianceCategoryCode]
      ,ISNULL(cc.[CategoryOfBusiness], cofb.[CategoryOfBusiness]) AS [CategoryOfBusiness]
      ,ISNULL(cc.[CategoryOfBusinessSequence], cofb.[CategoryOfBusinessSequence]) AS [CategoryOfBusinessSequence]
      ,[CaseCheckStatus]
      ,[CaseCheckReferralReasonCode]
      ,[CaseCheckReferralReasonDesc]
      ,[CaseCheckInitialAssessmentMonthYear]
      ,[CaseCheckInitialAssessmentDate]
      ,[CaseCheckInitialFailureReasonCode]
      ,[CaseCheckInitialFailureReasonDesc]
      ,[CaseCheckFinalAssessmentDate]
      ,[CaseCheckFinalFailureReasonCode]
      ,[CaseCheckFinalFailureReasonDesc]
      ,[CaseCheckInitialAssessment]
      ,[CaseCheckFinalAssessment]
      ,ISNULL([ASDAgentCode], '') AS [ASDAgentCode]
      ,ISNULL([ASDName], '') AS [ASDName]
      ,ISNULL([RSMAgentCode], '') AS [RSMAgentCode]
      ,ISNULL([RSMName], '') AS [RSMName]
      ,ISNULL([SQMAgentCode], '') AS [SQMAgentCode]
      ,ISNULL([SQMName], '') AS [SQMName]
      ,ISNULL([PSAgentCode], '') AS [PSAgentCode]
      ,ISNULL([PSName], '') AS [PSName]
FROM  [msv_CategoryOfBusiness] cofb 
      LEFT JOIN [mstt_Policies] p           
      ON p.[Regulation] = cofb.[ComplianceCategoryCode]
      AND p.[SalesQualityAdviserLevelCode] IN (SELECT [AgentCode] FROM #Agents)
      AND p.[Replacement] IN (1,2,3)
      -- Policy Sold Date must be within the specified number of months of the report month and the last day of the report month
      -- Commenting out under Item 138
      -- AND CASE WHEN p.[Regulation] = 'MCOB' THEN p.[START_DATE] ELSE p.[PROP_DATE] END 
      AND CASE WHEN p.[Regulation] = 'MCOB' and isnull(p.OriginatingSource,0) = 3 THEN p.[PROP_DATE] 
        WHEN p.[Regulation] = 'MCOB' and isnull(p.OriginatingSource,0) <> 3 THEN p.[CreateDate]
            ELSE p.[PROP_DATE] END
        BETWEEN DATEADD(mm,(@NumberOfMonths*-1)+1,@ReportMonth) AND DATEADD(dd,-1,DATEADD(mm,1,@ReportMonth))
      AND CASE WHEN p.[Regulation] = 'MCOB' and isnull(p.OriginatingSource,0) = 3 THEN p.[PROP_DATE] 
        WHEN p.[Regulation] = 'MCOB' and isnull(p.OriginatingSource,0) <> 3 THEN p.[CreateDate]
            ELSE p.[PROP_DATE] END >= '01 Oct 2006' /* HEY HEY HEY */

    LEFT JOIN [msv_AgentQualityCases] cc  ON p.[PolicyRef] = cc.[PolicyRef]
    LEFT JOIN [mstt_Agents] a             ON p.[SalesQualityAdviserLevelCode] = a.[CODE]
    LEFT JOIN [mstt_Clients] c            ON p.[CLIENT_NUM] = c.[CLIENT_NUM]
WHERE cofb.[ComplianceCategoryCode] IN ('COB', 'ICOB-PP')
ORDER BY [CategoryOfBusinessSequence], [DateOfSale] DESC

drop table #Agents
GO
