CREATE procedure [dbo].[msp_SelectQualityCasesFilterValues]
    @AgentCode            nvarchar(50)
   ,@KPILevel             nvarchar(50)
   ,@HierarchyTypeCode    nvarchar(50)
   ,@ReportMonth          datetime
   ,@NumberOfMonths       int
   ,@FilterName           nvarchar(50)
   ,@UserId               nvarchar(50)
   ,@AllowDelegates       char(1)

as

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2006 All rights reserved
--
-- Object  : procedure
-- Name    : msp_SelectQualityCasesFilterValues.sql
-- Desc    : Select a list of values for the specified field from the retrieved cases
-- Owner   : BT
-- Created : 28/07/2006
--
-- Amended : 15/08/2006  - BT  - Exclude NULL values from returned list of filter values
-- Amended : 15/08/2006  - BT  - Implement row-level security
-- Amended : 16/08/2006  - MK  - Add function to allow delegate access. That is, allow a user
--                               to impersonate the user to whom they have been given access.
-- Amended : 17/08/2006  - JL  - Added @AllowDelegates to EXEC msp_SelectQualityCases
-- Amended : 21/08/2006  - JL  - Added @SecurityByPass to proceddure call for msp_SelectQualityCases
--                 No Need to check security on lowest levels as already completed here. 
-- Amended : 21/08/2006  - JL  - Added and Order by IF Dates filter required
-- Amended : 22/08/2006  - BT  - Add new column CaseCheckFinalAssessment
-- Amended : 07/10/2009  - PR  - Increase size of column [QuestionStandardWording] in the temp table from 1000 
--                               to nvarchar(max)
--########################################################################

if isnull(@AllowDelegates, 'N') = 'Y'
  set @UserId = (select dbo.msf_SQGetUserDelegatedFrom(@UserId))
  
declare @PermissionSummaryPeriod int
set @PermissionSummaryPeriod = case when @hierarchyTypeCode = 'CURRENT' then 1 else 6 end

if dbo.msf_SQCheckPermissions (@UserId, @AgentCode, @KPILevel, @hierarchyTypeCode, @PermissionSummaryPeriod) = 'DENY' 

SELECT '*' AS [Value], '~ALL~' AS [Label]

else

begin

CREATE TABLE #Cases (
   [SellerAgentCode] nvarchar(50)
  ,[SellerName] nvarchar(255)
  ,[ClientNum] nvarchar(50)
  ,[ClientName] nvarchar(255)
  ,[ContractNum] nvarchar(50)
  ,[PolicyRef] nvarchar(50)
  ,[DateOfSale] datetime
  ,[ProductCode] nvarchar(50)
  ,[Replacement] nvarchar(50)
  ,[IsAReplacement] nvarchar(50)
  ,[ReplacementType] nvarchar(50)
  ,[TrackGroupId] nvarchar(50)
  ,[ComplianceCategoryCode] nvarchar(50)
  ,[CategoryOfBusiness] nvarchar(50)
  ,[CategoryOfBusinessSequence] int
  ,[CaseCheckStatus] nvarchar(50)
  ,[CaseCheckReferralReasonCode] nvarchar(50)
  ,[CaseCheckReferralReasonDesc] nvarchar(255)
  ,[CaseCheckInitialAssessmentMonthYear] nvarchar(50)
  ,[CaseCheckInitialAssessmentDate] datetime
  ,[CaseCheckInitialFailureReasonCode] nvarchar(50)
  ,[CaseCheckInitialFailureReasonDesc] nvarchar(255)
  ,[CaseCheckFinalAssessmentDate] datetime
  ,[CaseCheckFinalFailureReasonCode] nvarchar(50)
  ,[CaseCheckFinalFailureReasonDesc] nvarchar(255)
  ,[CaseCheckInitialAssessment] nvarchar(50)
  ,[CaseCheckFinalAssessment] nvarchar(50)
  ,[QuestionText] nvarchar(500)
  ,[QuestionStandardWording] nvarchar(max)    -- PR 7/10/2009 Change from nvarchar(1000) to ncharvar(max)
  ,[QuestionFailureReasonCode] nvarchar(50)
  ,[QuestionFailureReasonDesc] nvarchar(255)
  ,[ASDAgentCode] nvarchar(50)
  ,[ASDName] nvarchar(255)
  ,[RSMAgentCode] nvarchar(50)
  ,[RSMName] nvarchar(255)
  ,[SQMAgentCode] nvarchar(50)
  ,[SQMName] nvarchar(255)
  ,[PSAgentCode] nvarchar(50)
  ,[PSName] nvarchar(255)
)

INSERT INTO #Cases
EXEC msp_SelectQualityCases @AgentCode, @KPILevel, @HierarchyTypeCode, @ReportMonth, @NumberOfMonths, @UserId, @AllowDelegates, @SecurityByPass='Y'

IF @FilterName='CaseCheckInitialAssessmentMonthYear'
BEGIN
  EXEC ('SELECT DISTINCT ' + 
        @FilterName + ' as [Value], ' + 
        @FilterName + ' as [Label] 
      from #Cases 
      WHERE ' + @FilterName +
      ' IS NOT NULL UNION SELECT ''*'', ''~ALL~''
      ORDER BY 2 ASC')
END
ELSE
BEGIN
  EXEC ('SELECT DISTINCT ' + 
        @FilterName + ' as [Value], ' + 
        @FilterName + ' as [Label] 
      from #Cases 
      WHERE ' + @FilterName +
      ' IS NOT NULL UNION SELECT ''*'', ''~ALL~''')
END   

--EXEC ('SELECT DISTINCT ' + @FilterName + ' as [Value], ' + @FilterName + ' as [Label] from #Cases WHERE ' + @FilterName + ' IS NOT NULL UNION SELECT ''*'', ''~ALL~''')

DROP TABLE #Cases

end




GO
