CREATE procedure [dbo].[msp_SelectQualityComplaints]
    @AgentCode            nvarchar(50)
   ,@KPILevel             nvarchar(50)
   ,@HierarchyTypeCode    nvarchar(50)
   ,@ReportMonth          datetime
   ,@NumberOfMonths       int
   ,@UserId               nvarchar(50)
   ,@AllowDelegates       char(1)   

as

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : msp_SelectQualityComplaints.sql
-- Desc    : 
-- Owner   : BT
-- Created : 03/07/2006
--
-- Amended : 13/07/2006  - BT  - Remove Audience & UserId parameters
-- Amended : 19/07/2006  - KS  - Add date range for @Frequency parameter - uses AgentInformedDate  ** might need to change
-- Amended : 02/08/2006  - BT  - Use function to get agents in span
-- Amended : 07/08/2006  - BT  - Return null row if no complaints are found
-- Amended : 10/08/2006  - MK  - Remove @ReportMonth parameter from call to msf_SQGetAgentsInSpan
-- Amended : 11/08/2006  - BT  - Specify filter parameter in call to msf_SQGetAgentsInSpan
-- Amended : 11/08/2006  - MK  - Remove User's AgentCode from #Agents if @KPILevel <> 'AdviserKPI'
-- Amended : 14/08/2006  - MK  - Added further security, to ensure that the 
--                               user executing the report is allowed to see
--                               the agent that has been passed in to the proc.
-- Amended : 16/08/2006  - MK  - Add function to allow delegate access. That is, allow a user
--                               to impersonate the user to whom they have been given access.
-- Amended : 16/08/2006  - BT  - Fix issue where Adviser KPI report for PS/SQM/RSM included all advisers that report to them
-- Amended : 21/08/2006  - KS  - Added Adviser field to table
--       14/02/2007  - RH/OW - Tuned for performance as part of Agent KPI report production issue
--         - Fixes to affected procs/fns include explicit conversion of datatypes in query
--           expressions where parameter type is not matched to table data type
--           allowing Index seeks rather than scans
--         - Addition of indexes to required Quality tables
--         - Explicit alternative logic paths for queries where global parameter (eg Filter) is not supplied
--           avoiding table/index scans forced by unnecessary OR statememnts
--         - Use permissions caching wrapper around existing permissions/span checks

--
--########################################################################

if isnull(@AllowDelegates, 'N') = 'Y'
  set @UserId = (select dbo.msf_SQGetUserDelegatedFrom(@UserId))

declare @PermissionSummaryPeriod int
set @PermissionSummaryPeriod = case when @hierarchyTypeCode = 'CURRENT' then 1 else 6 end


declare @PermCheck nvarchar(50)
exec dbo.owp_SQCheckCachedPermissions @UserId, @AgentCode, @KPILevel, @HierarchyTypeCode, @PermissionSummaryPeriod, @PermCheck output

if @PermCheck = 'DENY'
--if dbo.msf_SQCheckPermissions (@UserId, @AgentCode, @KPILevel, @hierarchyTypeCode, @PermissionSummaryPeriod) = 'DENY' 
  

select 
null as [CaseId],
null as [ClientName],
null as [ProviderPolicyNumber],
null as [AgentCode],
null as [FSAProductType],
null as [AgentInformedDate],
null as [ComplianceCategoryCode],
null as [ComplaintReasonDesc]

else

begin

-- explicitly create #Agents table so we don't get collation issue with dev env
create table #Agents(AgentCode varchar(7) collate LATIN1_GENERAL_CI_AS)

--Create the list of agents under the managers span of control OR insert the sellers agent code
INSERT #Agents(AgentCode)
SELECT [AgentCode]
FROM   dbo.msf_SQGetAgentsInSpan(@AgentCode, @KPILevel, @HierarchyTypeCode, @NumberOfMonths, NULL)

--#Agents will possibly include the AgentCode of the User running the report. 
--This is only required if the user is running the AdviserKPI report in which case you only want them. 
--If the @Level is not AdviserKPI, the AgentCode must be removed.
if @KPILevel = 'AdviserKPI'
  delete from #Agents where AgentCode <> convert(varchar(7),@AgentCode)
else
  delete from #Agents where AgentCode = convert(varchar(7),@AgentCode)


--Retrieve the list of complaints
SELECT [CaseId] = c.[CaseId]
      ,[Adviser] = a.[Descn]
      ,[ClientName] = [ClientName]
      ,[ProviderPolicyNumber] = [ProviderPolicyNumber]
      ,[AgentCode] = [AgentCode]
      ,[FSAProductType] = [FSAProductType]
      ,[AgentInformedDate] = [AgentInformedDate]
      ,[ComplianceCategoryCode] = [ComplianceCategoryCode]
      ,[ComplaintReasonDesc] = [ComplaintReasonDesc]
INTO #Complaints
FROM mstt_Complaint c 
     INNER JOIN mstt_ComplaintReason cr ON cr.[CaseId] = c.[CaseId]
     LEFT OUTER JOIN mstt_agents a  ON c.[AgentCode] = a.[Code]
WHERE c.[AgentCode] in (select * from #Agents)
-- Complaint must be within the specified number of months of the report month and the last day of the report month
AND c.[AgentInformedDate] BETWEEN DATEADD(mm,(@NumberOfMonths*-1)+1,@ReportMonth) AND DATEADD(dd,-1,DATEADD(mm,1,@ReportMonth))


--If the complaints table is empty - return a null row
IF (SELECT COUNT(*) FROM #Complaints) >= 1
  BEGIN
    SELECT * FROM #Complaints
  END
ELSE
  BEGIN
    SELECT NULL AS [CaseId]
              ,NULL AS [Adviser]
        ,NULL AS [ClientName]
        ,NULL AS [ProviderPolicyNumber]
        ,NULL AS [AgentCode]
        ,NULL AS [FSAProductType]
        ,NULL AS [AgentInformedDate]
        ,NULL AS [ComplianceCategoryCode]
        ,NULL AS [ComplaintReasonDesc]
  END

DROP TABLE #Agents

DROP TABLE #Complaints

end




GO
