create procedure [dbo].[msp_SelectQualityDefaultSeller]
    @UserId   nvarchar(50)

as

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : msp_SelectQualityDefaultSeller.sql
-- Desc    : Select the specified User's agent code and any other info required 
--           to calculate the default seller
-- Owner   : BT
-- Created : 15/08/2006
-- Amended : 31/08/2006 - MK - Added hardcoded 'N' as AllowDelegates Parameter
--                             for msf_SQGetAgentCode
--
--########################################################################

declare @AgentCode nvarchar(50)
set @AgentCode = dbo.msf_SQGetAgentCode(@UserId, 'N')

SELECT [Code] AS [UserAgentCode]
      ,CAST(CASE WHEN [GivesAdvice]='Y' THEN 1 ELSE 0 END AS BIT) AS [GivesAdvice]
FROM   [mstt_agents]
WHERE  [Code] = @AgentCode


