create procedure [dbo].[msp_SelectQualityPracticeMembers]
    @AgentCode            nvarchar(50)
   ,@ReportMonth          datetime
   ,@UserId               nvarchar(50)
   ,@AllowDelegates       char(1)

as

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2006 All rights reserved
--
-- Object  : procedure
-- Name    : msp_SelectQualityPracticeMembers.sql
-- Desc    : Retrieve the list of members for the specified practice
-- Owner   : BT
-- Created : 24/07/2006
-- Amended : 17/08/2006  - BT  - Exclude hierarchy changes made after ReportMonth, add security & delegation
--
--########################################################################

if isnull(@AllowDelegates, 'N') = 'Y'
  set @UserId = (select dbo.msf_SQGetUserDelegatedFrom(@UserId))

if dbo.msf_SQCheckPermissions (@UserId,@AgentCode,'PRACTICE','CURRENT',1) = 'DENY' 

select null AS [PracticeCode]
      ,null AS [PracticeName]
      ,null AS [AdviserCode]
      ,null AS [AdviserName]
      ,null AS [PSCode]
      ,null AS [PSName]
      ,null AS [SQMCode]
      ,null AS [SQMName]
      ,null AS [RSMCode]
      ,null AS [RSMName]
      ,null AS [ASDCode]
      ,null AS [ASDName]
      
else

begin

select p.[Code] AS [PracticeCode]
      ,p.[Descn] AS [PracticeName]
      ,a.[Code] AS [AdviserCode]
      ,a.[Descn] AS [AdviserName]
      ,ps.[Code] AS [PSCode]
      ,ps.[Descn] AS [PSName]
      ,sqm.[Code] AS [SQMCode]
      ,sqm.[Descn] AS [SQMName]
      ,rsm.[Code] AS [RSMCode]
      ,rsm.[Descn] AS [RSMName]
      ,asd.[Code] AS [ASDCode]
      ,asd.[Descn] AS [ASDName]
from   [mstt_Agents] a
       INNER JOIN [mstt_AgentQualityHierarchy] h on h.[AgentCode] = a.[Code]
       LEFT JOIN [mstt_Agents] asd ON asd.[Code] = [SalesQualityASDLevelCode]
       LEFT JOIN [mstt_Agents] rsm ON rsm.[Code] = [SalesQualityRSMLevelCode]
       LEFT JOIN [mstt_Agents] sqm ON sqm.[Code] = [SalesQualitySQMLevelCode] AND [SalesQualityRSMLevelCode] IS NOT NULL
       LEFT JOIN [mstt_Agents] ps ON ps.[Code] = [SalesQualityPSLevelCode]
       LEFT JOIN [mstt_Agents] p ON p.[Code] = h.[PracticeCode]
where  h.[AgentHierarchyEndDate] = 
            (
            select max([AgentHierarchyEndDate]) 
            from   [mstt_AgentQualityHierarchy] h_max 
            where  h.[AgentCode] = h_max.[AgentCode]
            and    [AgentHierarchyStartDate] <= dateadd(d,-1,dateadd(m,1,@ReportMonth))
            )
and    h.PracticeCode = @AgentCode

end


GO
