CREATE procedure [dbo].[msp_SelectQualityProviderMix]
    @AgentCode       nvarchar(50),
    @Level           nvarchar(50),
    @UserId          nvarchar(50),
    @AllowDelegates  char(1)

as

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2006 All rights reserved
--
-- Object  : procedure
-- Name    : msp_SelectQualityProviderMix.sql
-- Desc    : Retrieve Provider Mix percentages for the selected agent and level
--           An Agent can have multiple levels e.g. an SQM has an adviser level
--           if they sell and an SQM level.
-- Owner   : BT
-- Created : 11/07/2006
--
-- Amended : 13/07/2006  - BT  - Remove Audience & UserId parameters
-- Amended : 21/07/2006  - BT  - Add Product Provider Name field
-- Amended : 08/08/2006  - BT  - Cast values as int and float
-- Amended : 14/08/2006  - MK  - Added further security, to ensure that the 
--                               user executing the report is allowed to see
--                               the agent that has been passed in to the proc.
-- Amended : 16/08/2006  - MK  - Add function to allow delegate access. That is, allow a user
--                               to impersonate the user to whom they have been given access.
-- Amended : 17/08/2006  - KS  - Added Order by to sort by Percentage
-- Amended : 11/09/2006  - MK  - Return a blank row if no cases are found.
--
--       14/02/2007  - RH/OW - Tuned for performance as part of Agent KPI report production issue
--         - Fixes to affected procs/fns include explicit conversion of datatypes in query
--           expressions where parameter type is not matched to table data type
--           allowing Index seeks rather than scans
--         - Addition of indexes to required Quality tables
--         - Explicit alternative logic paths for queries where global parameter (eg Filter) is not supplied
--           avoiding table/index scans forced by unnecessary OR statememnts
--         - Use permissions caching wrapper around existing permissions/span checks

--########################################################################

if isnull(@AllowDelegates, 'N') = 'Y'
  set @UserId = (select dbo.msf_SQGetUserDelegatedFrom(@UserId))

declare @PermCheck nvarchar(50)
exec dbo.owp_SQCheckCachedPermissions @UserId, @AgentCode, @Level, 'CURRENT', 1, @PermCheck output

if @PermCheck = 'DENY'
--if dbo.msf_SQCheckPermissions (@UserId,@AgentCode,@Level,'CURRENT',1) = 'DENY' 


  select 
  null as [AgentCode],
  null as [KPILevel],
  null as [ProductProviderCode],
  null as [ProductProviderName],
  null as [SubmittedPolicyQty],
  null as [OverallSubmittedPolicyQty],
  null as [SubmittedPolicyProviderMixPct],
  null as [IssuedPolicyQty],
  null as [OverallIssuedPolicyQty],
  null as [IssuedPolicyProviderMixPct]

else

  begin

    SELECT Overall.[AgentCode]
      ,Overall.[KPILevel]
      ,ByProd.[ReportingProductProviderCode] AS [ProductProviderCode]
      ,ByProd.[ReportingProductProviderName] AS [ProductProviderName]
      ,CAST(ByProd.[SubmittedPolicyQty] AS INT) AS [SubmittedPolicyQty]
      ,CAST(Overall.[SubmittedPolicyQty] AS INT) AS [OverallSubmittedPolicyQty]
      ,CAST(CASE WHEN Overall.[SubmittedPolicyQty] = 0 THEN 0 
            ELSE ByProd.[SubmittedPolicyQty]/Overall.[SubmittedPolicyQty] 
          END AS FLOAT) AS [SubmittedPolicyProviderMixPct]
      ,CAST(ByProd.[IssuedPolicyQty] AS INT) AS [IssuedPolicyQty]
      ,CAST(Overall.[IssuedPolicyQty] AS INT) AS [OverallIssuedPolicyQty]
      ,CAST(CASE WHEN Overall.[IssuedPolicyQty] = 0 THEN 0 
            ELSE ByProd.[IssuedPolicyQty]/Overall.[IssuedPolicyQty] 
          END AS FLOAT) AS [IssuedPolicyProviderMixPct]
    INTO #ProviderMix     
    FROM
    (
      --Group by Provider
      SELECT [AgentCode]
        ,[KPILevel]
        ,[ReportingProductProviderCode]
        ,[ReportingProductProviderName]
        ,SUM([SubmittedPolicyQty]) AS [SubmittedPolicyQty]
        ,SUM([IssuedPolicyQty]) AS [IssuedPolicyQty]
      FROM   mstt_AgentProductAggregation a INNER JOIN mstt_ProductProviders p ON a.[ProductProviderCode] = p.[ProductProviderCode]
      GROUP BY
        [AgentCode]
        ,[KPILevel]
        ,[ReportingProductProviderCode] 
        ,[ReportingProductProviderName]
    ) ByProd,
    (
      --Group by All Providers
      SELECT [AgentCode]
        ,[KPILevel]
        ,SUM([SubmittedPolicyQty]) AS [SubmittedPolicyQty]
        ,SUM([IssuedPolicyQty]) AS [IssuedPolicyQty]
      FROM   mstt_AgentProductAggregation
      GROUP BY 
        [AgentCode]
        ,[KPILevel]
    ) Overall
    WHERE Overall.[KPILevel] = ByProd.[KPILevel]
    AND Overall.[AgentCode] = ByProd.[AgentCode]
    AND Overall.[KPILevel] = convert(varchar(50),@Level)
    AND Overall.[AgentCode] = convert(varchar(50),@AgentCode)

    Order by
    CAST(CASE WHEN Overall.[IssuedPolicyQty] = 0 
        THEN 0 
        ELSE ByProd.[IssuedPolicyQty]/Overall.[IssuedPolicyQty] 
      END AS FLOAT)  desc

    if (select count(*) from #ProviderMix) = 0

      select 
        null as [AgentCode],
        null as [KPILevel],
        null as [ProductProviderCode],
        null as [ProductProviderName],
        null as [SubmittedPolicyQty],
        null as [OverallSubmittedPolicyQty],
        null as [SubmittedPolicyProviderMixPct],
        null as [IssuedPolicyQty],
        null as [OverallIssuedPolicyQty],
        null as [IssuedPolicyProviderMixPct]
      
    else

      select 
        [AgentCode],
        [KPILevel],
        [ProductProviderCode],
        [ProductProviderName],
        [SubmittedPolicyQty],
        [OverallSubmittedPolicyQty],
        [SubmittedPolicyProviderMixPct],
        [IssuedPolicyQty],
        [OverallIssuedPolicyQty],
        [IssuedPolicyProviderMixPct]
      from
        #ProviderMix
      Order by
        CAST(CASE WHEN OverallIssuedPolicyQty = 0 
            THEN 0 
            ELSE IssuedPolicyQty / OverallIssuedPolicyQty
          END AS FLOAT)  desc,
        ProductProviderCode

  end

GO
