CREATE PROCEDURE [dbo].[msp_SelectRecruitment] -- WITH RECOMPILE,ENCRYPTION
--  @Size nvarchar(50) /* Param List */
  @UserId nvarchar(50)
AS
/******************************************************************************
Copyright (C) Moore Stephens Consulting Limited 2005
Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>
*******************************************************************************/
-- drop table #mst_Recruitment2
-- go
-- 
-- declare @Size nvarchar(50)
-- set @Size = '%'
select
  'Company' as Company,
  AreaSalesManagerCode,
  AreaSalesManager,
  RegionalSalesManager,
  RegionalSalesManagerCode,
  FranchiseName,
  FranchiseCode,
  FranchiseSize,
  RecruitName,
  RecruitCode,
  RecruitType,
  RecruitCategory,
  PipeLineStageCode,
  PipeLineStageDescription,
  RecruitStatus,
  RecruitStatusDescription,
  StatusDate,
  PreviousRole,
  0 as PR_NumberRecruits,
  0 as PR_Active,
  convert(float,0) as PR_TargetTurnover,
  0 as PipeCounts,
  convert(float,0) as PipeProjectedAPE,
  0 as AppointedYTD,
  0 as AppointedYTDTurnover,
  0 as NPWYTD
into  #mst_Recruitment2
from
  mst_Recruitment r,
  msct_UAC_Recruits uac
where 
  r.recruitstatus <> 'APPS' and
  r.RecruitId = uac.AdviserId and
  uac.DomainLogin = @UserId
--exclude Appointed recruits as per BK's email "DON'T WANT THE APPOINTED PEOPLE LISTED (AS THIS IS A RECRUITMENT REPORT) BUT DO WANT TO KNOW THE TOTALS APPOINTED."
--  FranchiseSize like @Size
order by 
  Areasalesmanagercode,
  Regionalsalesmanagercode
CREATE INDEX  Regionalsalesmanagercode ON #mst_Recruitment2(Regionalsalesmanagercode)
CREATE INDEX  Areasalesmanagercode ON #mst_Recruitment2(Areasalesmanagercode)
CREATE INDEX  FranchiseName ON #mst_Recruitment2(FranchiseName)
/*** To update PipeProjectedAPE, PipeCounts at RecruitName level in mst_Recruitment2  ***/
declare
 PipeF cursor
for
select
  AreaSalesManager,
  RegionalSalesManager,
  FranchiseName,
  RecruitStatus,
  Recruitname,
  RecruitType
from
  #mst_Recruitment2
where
  --FranchiseSize like @Size and 
  RecruitStatus = 'PIPE'
order by 
  Recruitname
declare @FranchiseNamePipe  varchar(255),
  @Areasalesmanager varchar(255),
  @RegionalSalesManager varchar(255), 
  @RecruitStatus    varchar(255),
  @Recruitname    varchar(255),
  @RecruitTypeP   varchar(255)
open
  PipeF
fetch
  PipeF
into
  @areasalesmanager, 
  @RegionalSalesManager, 
  @FranchiseNamePipe,
  @RecruitStatus,
  @Recruitname,
  @RecruitTypeP
while (@@fetch_status = 0)
begin
  update 
   #mst_Recruitment2
  set
  PipeProjectedAPE = (select isnull(sum(TargetTurnover),0) 
      from mst_Recruitment R
      where --FranchiseSize  like @Size     and
      Recruitstatus        = 'PIPE'     and 
            FranchiseName        = TR.FranchiseName   and 
      AreaSalesManager     = TR.AreaSalesManager  and
      RegionalSalesManager = TR.RegionalSalesManager  and
      Recruitname          = TR.Recruitname   and
      Recruittype          = TR.RecruitType),
  PipeCounts  = (select isnull(sum(NumberRecruits),0) 
      from mst_Recruitment  R
      where --FranchiseSize like @Size      and
      Recruitstatus   = 'PIPE'      and 
            FranchiseName   = TR.FranchiseName    and 
      AreaSalesManager  = TR.AreaSalesManager   and
      RegionalSalesManager  = TR.RegionalSalesManager and
      Recruitname   = TR.Recruitname    and
      Recruittype   = TR.Recruittype)
 from 
  #mst_Recruitment2 TR
 where
  Recruitstatus        = 'PIPE'     and
  FranchiseName        = @FranchiseNamePipe and
  AreaSalesManager     = @AreaSalesManager  and
  RegionalSalesManager = @RegionalSalesManager  and
  Recruitname          = @Recruitname   and
  Recruittype          = @RecruitTypeP
 fetch
  PipeF
 into
  @areasalesmanager, 
  @RegionalSalesManager, 
  @FranchiseNamePipe,
  @RecruitStatus,
  @Recruitname,
  @RecruitTypeP
end
close PipeF
deallocate PipeF
/*** To update PreRecruits Counts,PreRecruits Active at Region Level in mst_Recruitment2  ***/
declare
  PreRecruits cursor
for
select Distinct
  AreaSalesManagerCode, 
  RegionalSalesManagerCode 
from
  #mst_Recruitment2
where
  --FranchiseSize like @Size and 
  RecruitStatus = 'PRO'
order by 
  AreaSalesManagerCode, 
  RegionalSalesManagerCode
declare @RegionalSalesManagerCode2  varchar(255),
  @AreaSalesManagerCode2    varchar(255)
open
  PreRecruits
fetch
  PreRecruits
into
  @AreaSalesManagerCode2, 
  @RegionalSalesManagerCode2
while (@@fetch_status = 0)
begin
 begin
declare
  PreRecruitsToUpdate cursor
for
select top 1
  FranchiseName,
  RecruitStatus,
  Recruitname,
  RecruitType
from
  #mst_Recruitment2
where
  --FranchiseSize     like @Size      and 
  AreaSalesManagerCode    = @AreaSalesManagerCode2  and
  RegionalSalesManagerCode  = @RegionalSalesManagerCode2  and 
  RecruitStatus     = 'PRO'
order by 
  FranchiseName,
  RecruitStatus,
  Recruitname,
  RecruitType
declare @FranchiseNamePRO varchar(255),
  @RecruitStatusPRO varchar(255),
  @RecruitnamePRO   varchar(255),
  @RecruitTypePRO   varchar(255)
open
  PreRecruitsToUpdate
fetch
  PreRecruitsToUpdate
into
  @FranchiseNamePRO,
  @RecruitStatusPRO,
  @RecruitnamePRO,
  @RecruitTypePRO
 while @@Fetch_Status = 0
  begin
    update
    #mst_Recruitment2
    set
    /* PR_NumberRecruits      = (select isnull(sum(NumberRecruits),0) from mst_Recruitment 
                      where FranchiseSize         like @Size and
                        RecruitStatus            = 'PRO'   and 
                              RegionalSalesManagerCode = @RegionalSalesManagerCode2 and 
                      (statusdate between convert(nvarchar(4),year(getdate()),112) + '01' + '01' and getdate())),
    */ --TPR 1177 remove Pre-recruits YTD column
    PR_Active         = (select isnull(sum(NumberRecruits),0) 
                from mst_Recruitment 
                where --FranchiseSize   like @Size      and
                RecruitStatus     = 'PRO'       and
                AreaSalesManagerCode    = @AreaSalesManagerCode2  and
                RegionalSalesManagerCode  = @RegionalSalesManagerCode2)
    where
    Recruitstatus     = 'PRO'       and
    FranchiseName     = @FranchiseNamePRO   and
    AreaSalesManagerCode    = @AreaSalesManagerCode2  and
    RegionalSalesManagerCode  = @RegionalSalesManagerCode2  and
    Recruitname     = @RecruitnamePro   and
    Recruittype     = @RecruitTypePro
    fetch
      PreRecruitsToUpdate
    into
      @FranchiseNamePRO,
      @RecruitStatusPRO,
      @RecruitnamePRO,
      @RecruitTypePRO
  end
 close PreRecruitsToUpdate
 deallocate PreRecruitsToUpdate
 end
 fetch
  PreRecruits
 into
   @AreaSalesManagerCode2, @RegionalSalesManagerCode2
end
close PreRecruits
deallocate PreRecruits
/*** To update PreRecruitsAPE at RecruitName Level in mst_Recruitment2  ***/
declare
  PreRecruits cursor
for
select
  AreaSalesManager,
  RegionalSalesManager,
  FranchiseName,
  RecruitStatus,
  Recruitname,
  RecruitType
from
  #mst_Recruitment2
where
  --FranchiseSize like @Size and 
  RecruitStatus = 'PRO'
order by 
  Recruitname
declare @FranchiseNamePR  varchar(255),
  @areasalesmanagerPR varchar(255),
  @RegionalSalesManagerPR varchar(255), 
  @RecruitStatusPR  varchar(255), 
  @RecruitnamePR    varchar(255),
  @RecruitType    varchar(255) --to remove duplicate recruitsname, using recruittype to uniquely identify them
open
  PreRecruits
fetch
  PreRecruits
into
  @areasalesmanagerPR, 
  @RegionalSalesManagerPR, 
  @FranchiseNamePR,
  @RecruitStatusPR,
  @RecruitnamePR,
  @RecruitType
while (@@fetch_status = 0)
begin
  update 
   #mst_Recruitment2
  set
    PR_TargetTurnover = (select isnull(sum(TargetTurnover),0) 
      from  mst_Recruitment R
      where --FranchiseSize   like @Size             and
        Recruitstatus   = 'PRO'                and 
              FranchiseName   = TR.FranchiseName     and 
        AreaSalesManager  = TR.AreaSalesManager  and
        RegionalSalesManager  = TR.RegionalSalesManager and
        Recruitname   = TR.Recruitname  and
        Recruittype   = TR.Recruittype)
 from 
  #mst_Recruitment2 TR
 where
  Recruitstatus   = 'PRO'       and
  FranchiseName   = @FranchiseNamePR    and
  AreaSalesManager  = @AreaSalesManagerPR   and
  RegionalSalesManager  = @RegionalSalesManagerPR and
  Recruitname   = @RecruitnamePR    and
  recruittype   = @RecruitType
 fetch
  PreRecruits
 into
  @areasalesmanagerPR, 
  @RegionalSalesManagerPR, 
  @FranchiseNamePR,
  @RecruitStatusPR,
  @RecruitnamePR,
  @RecruitType
end
close PreRecruits
deallocate PreRecruits
/*** To update AppointedYTD, NPWYTD  at Region Level in mst_Recruitment2  ***/
declare
 Appointed cursor
for
select 
 RegionalSalesManagerCode
from
 #mst_Recruitment2
--where
-- FranchiseSize like @Size
order by 
 RegionalSalesManagerCode
declare @RegionalSalesManagerCode3     varchar(255),
  @NewRegionalSalesManagerCode3  varchar(255)
open
 Appointed
fetch
 Appointed
into
 @RegionalSalesManagerCode3
select @NewRegionalSalesManagerCode3 = 0
while (@@fetch_status = 0)
begin
 if @NewRegionalSalesManagerCode3 <> @RegionalSalesManagerCode3
 begin
  update
   #mst_Recruitment2
  set
   /*
   AppointedYTD     =  ( select 
        count(distinct a.agentcode) 
      from
        msdt_adviser  a,
        msft_agents   ag,
        msdt_calendartime ct
      where
        a.regionalsalesmanagercode = @RegionalSalesManagerCode3 and
        a.agentcode       = ag.agentcode           and
        ag.dateappointedId      = ct.dateid                and
        ct.entrytypeid        = 4                  and
        (ct.datetime between 
        convert(nvarchar(4),year(getdate()),112) + '01' + '01' and getdate())
      ),
    AppointedYTD    = (select 
        count(distinct code) 
      from
        mstt_Agents
      where 
        Manager2code = @RegionalSalesManagerCode3 and
        AgentType in ('4','2')                    and --Sellers and Franchise
        GivesAdvice = 'Y'                         and 
        (case 
        when (Datestarted = '1 Jun 2005' and OscarDateStarted is not null) then OscarDateStarted 
        else Datestarted
        end ) between convert(nvarchar(4),year(getdate()),112) + '01' + '01' and getdate()),
    */           
  AppointedYTD    = ( select isnull(sum(NumberRecruits),0)
            from
              mst_Recruitment
            where
              Regionalsalesmanagercode = @RegionalSalesManagerCode3 and 
              --FranchiseSize   like @Size      and
              Recruitstatus   = 'APPS'      and 
              (statusdate between convert(nvarchar(4),year(getdate()),112) + '01' + '01' and getdate())
             )  ,
  AppointedYTDTurnover  = ( select isnull(sum(Turnover),0)
            from
              mst_Production p,
              mst_Recruitment r
            where
              r.RegionalSalesManagerCode = @RegionalSalesManagerCode3
              and r.RecruitCode = p.AgentCode
              and Recruitstatus = 'APPS'
              and (left(DateIssued, 4) = cast(year(getdate()) as varchar(4)))
              and year(r.StatusDate) = year(getdate()) 
             )  ,                        
  NPWYTD      = ( select isnull(sum(NumberRecruits),0)
            from
              mst_Recruitment
            where
              Regionalsalesmanagercode = @RegionalSalesManagerCode3 and 
              --FranchiseSize   like @Size      and
              Recruitstatus   = 'NPW'       and 
              (statusdate between convert(nvarchar(4),year(getdate()),112) + '01' + '01' and getdate())
             )
  where
   current of Appointed 
 end
 select @NewRegionalSalesManagerCode3 = @RegionalSalesManagerCode3
 fetch
  Appointed
 into
  @RegionalSalesManagerCode3
end
close Appointed
deallocate Appointed
--1178 - Recruitment Report change - blank out Stage column when dealing with Pre-Recruits / Prospects
--- if the Status = PRO and the Pipeline Stage = blank, please print Blank in the Stage column of the report rather than Unknown
Update 
 #mst_Recruitment2 
set
 PipelinestageDescription = ''
where
 Recruitstatus = 'PRO' and PipeLineStageCode is null
--TPR 1896 - Status column wording
Update
 #mst_Recruitment2
set
 RecruitStatusDescription = 'Prospect'
where
 RecruitStatus = 'PRO' or RecruitStatus = 'PROS'
select * 
from #mst_Recruitment2 
order by  Areasalesmanager, 
    regionalsalesmanager, 
    RecruitStatus, 
    FranchiseName

GO
