CREATE PROCEDURE [dbo].[msp_SelectRecruitmentLeague] -- WITH RECOMPILE,ENCRYPTION
  @OrderBy nvarchar(50),
    @Area nvarchar(50)
    --@FranchiseSize nvarchar(50)
    --@UserID nvarchar(50)
AS
/******************************************************************************
Copyright (C) Moore Stephens Consulting Limited 2005
Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>
*******************************************************************************/
declare @sql nvarchar(1000)
select @sql = case when @orderby = 'Appointed' then 
'select Area, Region, sum(Applicants) [Applicants], sum(Appointed) [Appointed], case when sum(applicants) > 5 then convert(float, sum(appointed)/sum(applicants)) else null end [Ratio] 
from
  mst_RecruitmentLeagueTable 
where
 Area like '+ ''''+ @Area + ''''  + 'group by area,region order by Appointed desc' 
when  @OrderBy = 'Applicants' then  
'select Area, Region, sum(Applicants) [Applicants], sum(Appointed) [Appointed], case when sum(applicants) > 5 then convert(float, sum(appointed)/sum(applicants)) else null end [Ratio] 
from
  mst_RecruitmentLeagueTable 
where
 Area like '+ ''''+ @Area + ''''  + 'group by area,region order by Applicants desc'  
when  @OrderBy = 'Ratio' then  
'select Area, Region, sum(Applicants) [Applicants], sum(Appointed) [Appointed], case when sum(applicants) > 5 then convert(float, sum(appointed)/sum(applicants)) else null end [Ratio] 
from
  mst_RecruitmentLeagueTable 
where
 Area like '+ ''''+ @Area + ''''  + 'group by area,region order by Ratio desc'  
 else  
 'select  Area, Region, sum(Applicants) [Applicants], sum(Appointed) [Appointed], case when sum(applicants) > 5 then convert(float, sum(appointed)/sum(applicants)) else null end [Ratio] from  mst_RecruitmentLeagueTable group by area,region order by Appointed desc'
end
--select @sql
exec (@sql)

GO
/****** Object:  StoredProcedure [dbo].[msp_SelectRegionalFailsData]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER OFF
GO
CREATE    Procedure [dbo].[msp_SelectRegionalFailsData]
 @ComplianceCategoryCode varchar(50),
 @SummaryPeriod int
AS

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2006 All rights reserved
--
-- Object  : procedure
-- Name    : msp_SelectRegionalFailsData.sql
-- Desc    : Selects the Regional Fails Data for Section 8.2
-- Owner   : JNHL
-- Created : 26/07/2006
--
-- Amended : 09/08/2006 Added KPILevel<>CORP 
--
--########################################################################


SET NOCOUNT ON 

  Declare @ReportMonth DateTime
  --Get the current Reporting month
  SELECT @ReportMonth=MAX(Reportmonth) 
  FROM mstt_AgentQualityAggregation
  WHERE KPILevel= 'ADVISERKPI'
  
  --Merge ASD/RSM Data Ready for return
  SELECT DISTINCT 
    AQA_ASD.SummaryPeriod, 
    AQH.SalesQualityASDLevelCode, 
    ASD.DESCN AS ASD_DESCN, 
      AQA_ASD.ComplianceCategoryCode AS ASD_ComplianceCategoryCode, 
    AQA_ASD.SAKPIPercent*100 AS ASD_SA, 
    AQA_ASD.CQKPIPercent*100 AS ASD_CQ, 
    AQA_ASD.Rejects AS ASD_Rejects, 
    AQH.SalesQualityRSMLevelCode, 
    RSM.DESCN AS RSM_DESCN, 
    AQA_RSM.ComplianceCategoryCode AS RSM_ComplianceCategoryCode, 
    AQA_RSM.SAKPIPercent*100 AS RSM_SA, 
    AQA_RSM.CQKPIPercent*100 AS RSM_CQ, 
    AQA_RSM.Rejects AS RSM_Rejects
  FROM        
    mstt_AgentQualityHierarchy AQH
  --Area Manager
    Left OUTER JOIN (SELECT Distinct AgentCode, 
                ComplianceCategoryCode, 
                SAKPIPercent, 
                CQKPIPercent, 
                FinalRiskRejectQty + 
                  FinalRandomRejectQty + 
                  FinalOtherRejectQty Rejects, 
                SummaryPeriod
              FROM mstt_AgentQualityAggregation 
              WHERE KPILevel = 'ASDKPI' --
                AND HierarchyTypeCode = 'KPI' 
                AND Summaryperiod = @SummaryPeriod 
                AND ReportMonth = @ReportMonth) AQA_ASD 
              ON AQH.SalesQualityASDLevelCode = AQA_ASD.AgentCode 
    INNER JOIN mstt_Agents ASD 
              ON AQH.SalesQualityASDLevelCode = ASD.CODE 
  --Regional Manager
    LEFT OUTER JOIN (SELECT Distinct AgentCode, 
              ComplianceCategoryCode, 
              SAKPIPercent, 
              CQKPIPercent, 
                FinalRiskRejectQty + 
                FinalRandomRejectQty + 
                FinalOtherRejectQty Rejects, 
              SummaryPeriod
            FROM mstt_AgentQualityAggregation
            WHERE KPILevel = 'RSMKPI' 
              AND HierarchyTypeCode = 'KPI' 
              AND Summaryperiod =@SummaryPeriod 
              AND ReportMonth = @ReportMonth) AQA_RSM 
              ON AQH.SalesQualityRSMLevelCode = AQA_RSM.AgentCode 
    INNER JOIN mstt_Agents RSM 
              ON AQH.SalesQualityRSMLevelCode = RSM.CODE
  WHERE (AQA_ASD.ComplianceCategoryCode = @ComplianceCategoryCode) 
      AND (AQA_RSM.ComplianceCategoryCode = @ComplianceCategoryCode)
      AND @ReportMonth BETWEEN AQH.AgentHierarchyStartDate 
                AND AQH.AgentHierarchyEndDate 
      And AQH.IsCurrent=1
  ORDER BY ASD.DESCN, RSM.DESCN


GO
/****** Object:  StoredProcedure [dbo].[msp_SelectReplacementAdvisers]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
