create procedure [dbo].[msp_SelectReplacementAdvisers]
    @AgentCode            nvarchar(50)
   ,@KPILevel             nvarchar(50)
   ,@HierarchyTypeCode    nvarchar(50)
   ,@ReportMonth          datetime
   ,@NumberOfMonths       int

as

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : msp_SelectReplacementAdvisers.sql
-- Desc    : Select Adviser list for Replacements report
-- Owner   : KS
-- Created : 14/08/2006
-- Amended : 22/08/2006  - BT  - Use Summary period instead of Number of months to get list of agents. Return Value & Label in results.
-- Amended : 22/08/2006  - BT  - Use msv_AgentQualityCases view instead of direct query
-- Amended : 09/10/2006  - MK  - Add Date Check to ensure we get nothing relating to pre-1 Oct (Item 138)
-- Amended : 20/11/2006  - BT  - TPR238/239 - Select advisers from results of msp_SelectQualityCasesByPolicy procedure to ensure that the lists match
--                               TPR245/246 - Return agent code instead of agent name as value field for use in filtering replacements.
--                               
--########################################################################

CREATE TABLE #Replacements (
   [SellerAgentCode] nvarchar(50)
  ,[SellerName] nvarchar(255)
  ,[ClientNum] nvarchar(50)
  ,[ClientName] nvarchar(255)
  ,[ContractNum] nvarchar(50)
  ,[PolicyRef] nvarchar(50)
  ,[DateOfSale] datetime
  ,[ProductCode] nvarchar(50)
  ,[Replacement] nvarchar(50)
  ,[IsAReplacement] nvarchar(50)
  ,[ReplacementType] nvarchar(50)
  ,[TrackGroupId] nvarchar(50)
  ,[ComplianceCategoryCode] nvarchar(50)
  ,[CategoryOfBusiness] nvarchar(50)
  ,[CategoryOfBusinessSequence] int
  ,[CaseCheckStatus] nvarchar(50)
  ,[CaseCheckReferralReasonCode] nvarchar(50)
  ,[CaseCheckReferralReasonDesc] nvarchar(255)
  ,[CaseCheckInitialAssessmentMonthYear] nvarchar(50)
  ,[CaseCheckInitialAssessmentDate] datetime
  ,[CaseCheckInitialFailureReasonCode] nvarchar(50)
  ,[CaseCheckInitialFailureReasonDesc] nvarchar(255)
  ,[CaseCheckFinalAssessmentDate] datetime
  ,[CaseCheckFinalFailureReasonCode] nvarchar(50)
  ,[CaseCheckFinalFailureReasonDesc] nvarchar(255)
  ,[CaseCheckInitialAssessment] nvarchar(50)
  ,[CaseCheckFinalAssessment] nvarchar(50)
  ,[ASDAgentCode] nvarchar(50)
  ,[ASDName] nvarchar(255)
  ,[RSMAgentCode] nvarchar(50)
  ,[RSMName] nvarchar(255)
  ,[SQMAgentCode] nvarchar(50)
  ,[SQMName] nvarchar(255)
  ,[PSAgentCode] nvarchar(50)
  ,[PSName] nvarchar(255)
)

INSERT INTO #Replacements
EXEC msp_SelectQualityCasesByPolicy @AgentCode, @KPILevel, @HierarchyTypeCode, @ReportMonth, @NumberOfMonths, '-1', '-1', 'Y', @SecurityByPass='Y'

--Retrieve the list of advisers with Replacements
SELECT DISTINCT 
       [SellerAgentCode] AS [Value]
      ,[SellerName] AS [Label]
FROM  #Replacements
WHERE [SellerAgentCode] IS NOT NULL
UNION 
SELECT -1, '~ALL~'
ORDER BY 2

DROP TABLE #Replacements


GO
