CREATE  PROCEDURE [dbo].[msp_SelectReportDates]
  @RunAsCorp as int = 0
AS

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2006 All rights reserved
--
-- Object  : procedure
-- Name    : msp_SelectReportDates
-- Desc    : Selects Various Dates in various Formats
-- Owner   : JNHL
-- Created : 04/08/2006
--
-- Amended : 09/08/2006 - JL - Added KPILevel<>CORP
-- Amended : 23/08/2006 - JL - Added Default Param, to filter CORP/Non corp
--                 - Requirements
-- Amended : 20/10/2006 - BT - Set ReportStartDate to be the minimum date with a floor of 
--                             6 months before the maximum date to cater for October data 
--                             re-align. (CR172)
-- Amended : 04/05/2007 - BT - Fix issue with ReportStartDate and Rolling6MonthStart to correctly
--                             reflect the 6 month time span.
--
--########################################################################

  If @RunAsCorp Not in (1,0)
    SET @RunAsCorp=0
    
  IF @RunAsCorp = 0
  BEGIN
    --Rolling Periods
    Select
      ReportMonth CurrentMonth,
      DATENAME(M,ReportMonth) ReportMonthName ,
      StartReportMonth ReportStartDate,
      DATEADD(D,-1,DATEADD(M,1,ReportMonth)) ReportEndDate,
      CAST(DATEPART(d,ReportMonth)AS VARCHAR) + ' '+ DATENAME(M,ReportMonth) ReportStart,
      CAST(DATEPART(d,DATEADD(d,-1,GETDATE()))AS VARCHAR) + ' '+ DATENAME(M,DATEADD(d,-1,GETDATE())) ReportEnd, 
      DATENAME(M,ReportMonth)+' '+DATENAME(YEAR,ReportMonth) ReportEpoch,
      DATEADD(M,-5,ReportMonth) Rolling6MonthStart,
      DATEADD(D,-1,ReportMonth) Rolling6MonthStop
    FROM
      (SELECT MAX(ReportMonth) ReportMonth 
        FROM mstt_AgentQualityAggregation
        WHERE KPILevel= 'ADVISERKPI') GetMonth,
      (SELECT MIN(ReportMonth) StartReportMonth 
        FROM mstt_AgentQualityAggregation
        WHERE KPILevel = 'ADVISERKPI'
        AND ReportMonth >= DATEADD(M,-5,(SELECT MAX(ReportMonth)
                          FROM mstt_AgentQualityAggregation
                          WHERE KPILevel = 'ADVISERKPI'))) GetMonth2
  END
  ELSE 
  BEGIN
    Select
      ReportMonth CurrentMonth,
      DATENAME(M,ReportMonth) ReportMonthName ,
      StartReportMonth ReportStartDate,
      DATEADD(D,-1,DATEADD(M,1,ReportMonth)) ReportEndDate,
      CAST(DATEPART(d,ReportMonth)AS VARCHAR) + ' '+ DATENAME(M,ReportMonth) ReportStart,
      CAST(DATEPART(d,DATEADD(d,-1,GETDATE()))AS VARCHAR) + ' '+ DATENAME(M,DATEADD(d,-1,GETDATE())) ReportEnd, 
      DATENAME(M,ReportMonth)+' '+DATENAME(YEAR,ReportMonth) ReportEpoch,
      DATEADD(M,-5,ReportMonth) Rolling6MonthStart,
      DATEADD(D,-1,ReportMonth) Rolling6MonthStop
    FROM
      (SELECT MAX(ReportMonth) ReportMonth 
        FROM mstt_AgentQualityAggregation
        WHERE KPILevel='CORP'
          AND SummaryPeriod=1) GetMonth,
      (SELECT MIN(ReportMonth) StartReportMonth 
        FROM mstt_AgentQualityAggregation
        WHERE KPILevel = 'CORP'
        AND SummaryPeriod = 1
        AND ReportMonth >= DATEADD(M,-5,(SELECT MAX(ReportMonth)
                          FROM mstt_AgentQualityAggregation
                          WHERE KPILevel = 'CORP'
                          AND SummaryPeriod = 1))) GetMonth2
  END 

GO
