CREATE PROCEDURE [dbo].[msp_SelectReportPeriods]
AS
--########################################################################
-- Copyright (c) MOORE STEPHENS, 2006 All rights reserved
--
-- Object  : procedure
-- Name    : msp_SelectReportDates
-- Desc    : Selects The Number of Periods Available
-- Owner   : JNHL
-- Created : 04/08/2006
--
-- Amended : 09/08/2006 Added KPILevel<>CORP 
--
--########################################################################


SELECT DISTINCT
  DATEDIFF(M,ReportMonth,CM.CurrentMonth)+1 ReportPeriod,
  DATEDIFF(M,ReportMonth,CM.CurrentMonth)+1 PreviousPeriods
FROM
  mstt_AgentQualityAggregation
  CROSS JOIN (SELECT MAX(ReportMonth) CurrentMonth
          FROM mstt_AgentQualityAggregation
          WHERE KPILevel= 'ADVISERKPI') CM
WHERE KPILevel= 'ADVISERKPI'
ORDER BY 1 DESC


GO
