CREATE   PROCEDURE [dbo].[msp_SelectRSMMonthlyAssessmentResults]
   @RSMAgent               VARCHAR(50),
   @ComplianceCategoryCode VARCHAR(20),
   @UserId                 VARCHAR(50),
   @AllowDelegates         char(1)
AS

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2006 All rights reserved
--
-- Object  : procedure
-- Name    : msp_SelectRSMMonthlyAssessmentResults
-- Desc    : Selects Data For the RSM Monthly Results
-- Owner   : JNHL
-- Created : 09/08/2006
--
-- Amended : 10/08/2006 - Removed the Union for blank data
-- Amended : 14/08/2006  - MK  - Added further security, to ensure that the 
--                               user executing the report is allowed to see
--                               the agent that has been passed in to the proc.
-- Amended : 16/08/2006  - MK  - Add function to allow delegate access. That is, allow a user
--                               to impersonate the user to whom they have been given access.
--########################################################################

  if isnull(@AllowDelegates, 'N') = 'Y'
    set @UserId = (select dbo.msf_SQGetUserDelegatedFrom(@UserId))


  if dbo.msf_SQCheckPermissions (@UserId, @RSMAgent, 'RSM', 'CURRENT', 1 ) = 'DENY' 


    select 
    null as ASDAgentCode,
    null as SQMAgentName,
    null as SQMSurname,
    null as SQMAgentCode,
    null as Status,
    null as RSMAgentName,
    null as RSMAgentCode, 
    null as Cases_Submitted,
    null as Cases_Assessed,
    null as SAFail,
    null as SAKPIPercent,
    null as CQFail,
    null as CQKPIPercent

  else

  begin

  --- SP PARAMETERS Variables Normally Passed in Query
  --DECLARE @RSMAgent VARCHAR(50) --current User Id
  --DECLARE @ComplianceCategoryCode VARCHAR(20)
  --- Variables required in 

  -------TESTING Parameters
  --SET @RSMAgent='1002128'
  --SET @ComplianceCategoryCode='COB'
  ------- 

  --Local Vars
  DECLARE @ReportMonth AS DATETIME
  DECLARE @ReportStart AS DATETIME 
  DECLARE @SummaryPeriod AS INT

  --Get the Current reporting Month
  SELECT @ReportMonth=MAX(ReportMonth) 
  FROM mstt_AgentQualityAggregation
  WHERE KPILevel= 'ADVISERKPI'

  --Default Summary Period=6 for 6 Month Rolling
  SET @SummaryPeriod=1

  --Select Data For Report
  SELECT  
      SQM.SalesQualityASDLevelCode ASDAgentCode
    , SQMAgent.Descn SQMAgentName
    , SQMAgent.[Name] SQMSurname
    , SQMAgent.Code SQMAgentCode
    , SQMAgent.CompetentStatus Status
    , RSMAgent.Descn RSMAgentName
    , RSMAgent.Code RSMAgentCode  
    , AQA.SubmittedRiskProposalQTY+AQA.SubmittedRandomProposalQTY+AQA.SubmittedOtherProposalQTY Cases_Submitted
    , AQA.InitialRiskAssessedQTY+AQA.InitialRandomAssessedQTY+AQA.InitialOtherAssessedQTY Cases_Assessed
    , AQA.InitialRiskSuitableAdviceQTY+AQA.InitialRandomSuitableAdviceQTY+InitialOtherSuitableAdviceQTY SAFail
    , SAKPIPercent 
    , AQA.InitialRiskCompletionQTY+AQA.InitialRandomCompletionQTY+InitialOtherCompletionQTY CQFail
    , CQKPIPercent
  FROM mstt_AgentQualityAggregation AQA
    INNER JOIN (SELECT DISTINCT 
            SalesQualityASDLevelCode
          , SalesQualityRSMLevelCode
          , SalesQualitySQMLevelCode
        FROM mstt_AgentQualityHierarchy 
        WHERE SalesQualityRSMLevelCode=@RSMAgent --OR @RSMAgent='%'
          AND IsCurrent=1) SQM ON AQA.AgentCode=SQM.SalesQualitySQMLevelCode
    LEFT OUTER JOIN mstt_Agents SQMAgent ON SQM.SalesQualitySQMLevelCode=SQMAgent.Code
    LEFT OUTER JOIN mstt_Agents RSMAgent ON SQM.SalesQualityRSMLevelCode=RSMAgent.Code
  WHERE AQA.ComplianceCategoryCode=@ComplianceCategoryCode
    AND SummaryPeriod=@SummaryPeriod
    AND ReportMonth=@Reportmonth
    AND AQA.KPILevel='SQMKPI'
    AND AQA.HierarchyTypeCode='KPI'
  ORDER BY 
    SQMSurname

  end
  

GO
