CREATE PROCEDURE [dbo].[msp_SelectSellerABCLeague] 

AS

/******************************************************************************

Created by Paul Robathan (August 2008)

1. Simple procedure to return this months Seller League table

*******************************************************************************/

begin


select 
  Code,
  Seller,
  AgentCategory as 'Seller Type', 
  FranchiseCode as 'Franchise Code',
  Franchise,
  AreaSalesManagerCode as 'Area Code',
  AreaSalesManager 'Area',
  Sum(ABCValue) as 'ABC Turnover'
from mstt_SellerABCLeagueTable_Current  
group by 
  Code,
  Seller, 
  AgentCategory, 
  FranchiseCode,
  Franchise,
  AreaSalesManagerCode,
  AreaSalesManager
order by [ABC Turnover] desc

end
