CREATE PROCEDURE [dbo].[msp_SelectSellerABCLeagueBreakdown]
    @Product nvarchar(50),
    @ProductSubGroup nvarchar(50),
    @ProductCategory nvarchar(50),
    @Area nvarchar(50),
    @Region nvarchar(50)
AS

/******************************************************************************

Created by Paul Robathan (Feb 2009)
Steve Berry requested that the ABC Leagues are made more granular so that both Enterprise
and Adviser Leagues have overall totals plus breakdown by Product Type.

Marcus Cossey asked that we
- only include Principals and Sellers i.e. AgentType 4 and 43
- only include Sellers if Franchise is in Franchise League table

Example Call
  exec msp_SelectSellerABCLeagueBreakdown '%','%','Protection', 'Steve Baker','Andy Miles Panel BQM L&SE L06'
  exec msp_SelectSellerABCLeagueBreakdown '%','%','%', '%','%'

*******************************************************************************/

begin

  create table #Total (AdviserCode varchar(50),Adviser varchar(50),Type varchar(50),FranchiseCode varchar(50), 
        Franchise varchar(255), 
        Area varchar(255), 
        Region varchar(255),
        Turnover float,
        Position int not null identity (1,1))
  create table #Prot (AdviserCode varchar(50),FranchiseCode varchar(50), 
        Turnover float)
  create table #GI (AdviserCode varchar(50),FranchiseCode varchar(50), 
        Turnover float)
  create table #Inv (AdviserCode varchar(50),FranchiseCode varchar(50), 
        Turnover float)
  create table #Pen (AdviserCode varchar(50),FranchiseCode varchar(50), 
        Turnover float)
  create table #Mort (AdviserCode varchar(50),FranchiseCode varchar(50), 
        Turnover float)

  insert into #Total (AdviserCode,Adviser,Type,FranchiseCode, Franchise, Area, Region, Turnover)
  select c.Code,Seller,c.AgentCategory,c.FranchiseCode, Franchise, AreaSalesManager, RegionalSalesManager, sum(ABCValue) as Turnover 
  from mstt_SellerABCLeagueTable_Current c
  inner join mstt_agents a on a.Code = c.Code
  where a.AgentType in (4,43) and
--  ProductCategoryName = case when @ProductCategory = '%' then ProductCategoryName else @ProductCategory end
--  and ProductSubGroupName = case when @ProductSubGroup = '%' then ProductSubGroupName else @ProductSubGroup end
--  and ProductName = case when @Product = '%' then ProductName else @Product end and
  AreaSalesManager = case when @Area = '%' then AreaSalesManager else @Area end
  and RegionalSalesManager = case when @Region = '%' then RegionalSalesManager else @Region end
  group by c.Code,Seller,c.AgentCategory,c.FranchiseCode, Franchise, AreaSalesManager, RegionalSalesManager
  order by sum(ABCValue) desc, Seller,Franchise

  insert into #Prot (AdviserCode,FranchiseCode, Turnover)
  select Code,FranchiseCode, sum(ABCValue) as Turnover 
  from mstt_SellerABCLeagueTable_Current
  where  ProductGroupName = 'Protection'
  and ProductCategoryName = case when @ProductCategory = '%' then ProductCategoryName else @ProductCategory end
  and ProductSubGroupName = case when @ProductSubGroup = '%' then ProductSubGroupName else @ProductSubGroup end
  and ProductName = case when @Product = '%' then ProductName else @Product end
  and AreaSalesManager = case when @Area = '%' then AreaSalesManager else @Area end
  and RegionalSalesManager = case when @Region = '%' then RegionalSalesManager else @Region end
  group by Code,FranchiseCode
  order by Code,FranchiseCode

  insert into #GI (AdviserCode,FranchiseCode, Turnover)
  select Code,FranchiseCode, sum(ABCValue) as Turnover 
  from mstt_SellerABCLeagueTable_Current
  where  ProductGroupName = 'GI'
  and ProductCategoryName = case when @ProductCategory = '%' then ProductCategoryName else @ProductCategory end
  and ProductSubGroupName = case when @ProductSubGroup = '%' then ProductSubGroupName else @ProductSubGroup end
  and ProductName = case when @Product = '%' then ProductName else @Product end
  and AreaSalesManager = case when @Area = '%' then AreaSalesManager else @Area end
  and RegionalSalesManager = case when @Region = '%' then RegionalSalesManager else @Region end
  group by Code,FranchiseCode
  order by Code,FranchiseCode

  insert into #Inv (AdviserCode,FranchiseCode, Turnover)
  select Code,FranchiseCode, sum(ABCValue) as Turnover 
  from mstt_SellerABCLeagueTable_Current
  where  ProductGroupName = 'Investment'
  and ProductCategoryName = case when @ProductCategory = '%' then ProductCategoryName else @ProductCategory end
  and ProductSubGroupName = case when @ProductSubGroup = '%' then ProductSubGroupName else @ProductSubGroup end
  and ProductName = case when @Product = '%' then ProductName else @Product end
  and AreaSalesManager = case when @Area = '%' then AreaSalesManager else @Area end
  and RegionalSalesManager = case when @Region = '%' then RegionalSalesManager else @Region end
  group by Code,FranchiseCode
  order by Code,FranchiseCode

  insert into #Pen (AdviserCode,FranchiseCode, Turnover)
  select Code,FranchiseCode, sum(ABCValue) as Turnover 
  from mstt_SellerABCLeagueTable_Current
  where  ProductGroupName = 'Pensions'
  and ProductCategoryName = case when @ProductCategory = '%' then ProductCategoryName else @ProductCategory end
  and ProductSubGroupName = case when @ProductSubGroup = '%' then ProductSubGroupName else @ProductSubGroup end
  and ProductName = case when @Product = '%' then ProductName else @Product end
  and AreaSalesManager = case when @Area = '%' then AreaSalesManager else @Area end
  and RegionalSalesManager = case when @Region = '%' then RegionalSalesManager else @Region end
  group by Code,FranchiseCode
  order by Code,FranchiseCode

  insert into #Mort (AdviserCode,FranchiseCode, Turnover)
  select Code,FranchiseCode, sum(ABCValue) as Turnover 
  from mstt_SellerABCLeagueTable_Current
  where  ProductGroupName = 'Mortgage'
  and ProductCategoryName = case when @ProductCategory = '%' then ProductCategoryName else @ProductCategory end
  and ProductSubGroupName = case when @ProductSubGroup = '%' then ProductSubGroupName else @ProductSubGroup end
  and ProductName = case when @Product = '%' then ProductName else @Product end
  and AreaSalesManager = case when @Area = '%' then AreaSalesManager else @Area end
  and RegionalSalesManager = case when @Region = '%' then RegionalSalesManager else @Region end
  group by Code,FranchiseCode
  order by Code,FranchiseCode

  select t.AdviserCode as 'Advisor Code',t.Adviser,t.Type as 'Adviser Type',t.FranchiseCode as 'Enterprise Code',t.Franchise as Enterprise,
      t.Area,t.Region,round(t.Turnover,0) as 'Overall', 
      isnull(round(p.Turnover,0),0) as 'Protection',isnull(round(pe.Turnover,0),0) as 'Pensions',isnull(round(i.Turnover,0),0) as 'Investments',
      isnull(round(m.Turnover,0),0) as 'Mortgages',isnull(round(g.Turnover,0),0) as 'GI'
  from #Total t
  left outer join #Prot p on p.FranchiseCode = t.FranchiseCode and p.AdviserCode = t.AdviserCode
  left outer join #Pen pe on pe.FranchiseCode = t.FranchiseCode and pe.AdviserCode = t.AdviserCode
  left outer join #Inv i on i.FranchiseCode = t.FranchiseCode and i.AdviserCode = t.AdviserCode
  left outer join #Mort m on m.FranchiseCode = t.FranchiseCode and m.AdviserCode = t.AdviserCode
  left outer join #GI g on g.FranchiseCode = t.FranchiseCode and g.AdviserCode = t.AdviserCode
  where exists (select null from mstt_FranchiseABCLeagueTable_Current f where f.Code = t.FranchiseCode)
  order by t.position 

  drop table #Total
  drop table #Prot
  drop table #Pen
  drop table #Inv
  drop table #Mort
  drop table #GI

end
GO
