CREATE PROCEDURE [dbo].[msp_SelectSellingCapacityBySize] -- WITH RECOMPILE,ENCRYPTION
  @Size nvarchar(50),
    @Level nvarchar(50),
    @UserId nvarchar(50),
    @Comparison nvarchar(50)
AS

/******************************************************************************

Copyright (C) Moore Stephens Consulting Limited 2005

Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
          
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>

*******************************************************************************/


select 
'Company' as Company,
Area,
Region,
SQM,
Franchise,
Adviser,
[Size],
sum(Active) [Active],
sum(case when Comparison <> 'Actual' and Comparison = @Comparison then Target else null end) [Target],
sum(AppThisMonth) [AppThisMonth],
sum(AppLast6) [AppLastMonth],
sum(AppLast12) [AppLast12],
sum(AppYTD) [AppYTD],
sum(TerminatedYTD) [TerminatedYTD]
from 
 mst_SellingCapacity sc,
 msct_UserAccessControlHistory uac
where 
     [size] like @Size
 and [Level] like @Level
 and Comparison = 'Actual'
 and sc.AdviserId = uac.AdviserId
 and uac.DomainLogin = @UserId
 and sc.TerminatedYTD is null
group by
Area,
Region,
SQM,
Franchise,
Adviser,
[Size]

union all 

--Select the Terminations Rows
select 
'Company' as Company,
Area,
Region,
'TargetHolder' as SQM,
'TargetHolder' as Franchise,
'TargetHolder' as Adviser,
'TargetHolder' as [Size],
sum(Active) [Active],
sum(case when Comparison <> 'Actual' and Comparison = @Comparison then Target else null end) [Target],
sum(AppThisMonth) [AppThisMonth],
sum(AppLast6) [AppLastMonth],
sum(AppLast12) [AppLast12],
sum(AppYTD) [AppYTD],
sum(TerminatedYTD) [TerminatedYTD]
from 
 mst_SellingCapacity sc,
 msct_UserAccessControlHistory uac
where 
     [size] like @Size
 and [Level] like @Level
 and Comparison = 'Actual'
 and sc.AdviserId = uac.AdviserId
 and uac.DomainLogin = @UserId
 and sc.TerminatedYTD is not null
group by
Area,
Region

union all 

select 
'Company' as Company,
case when @Comparison like 'Company%' then 'TargetHolder' else Area end as Area,
case when @Comparison like 'Company%' or @Comparison like 'Area%' then 'TargetHolder' else Region end as Region,
case when @Comparison like 'Company%' or @Comparison like 'Area%' then 'TargetHolder' else SQM end as SQM,
case when @Comparison like 'Company%' or @Comparison like 'Area%' or @Comparison like 'Region%' then 'TargetHolder' else Franchise end as Franchise,
case when @Comparison like 'Company%' or @Comparison like 'Area%' or @Comparison like 'Region%' or @Comparison like 'Franchise%' then 'TargetHolder' else Adviser end as Adviser,
case when @Comparison like 'Company%' or @Comparison like 'Area%' or @Comparison like 'Region%' or @Comparison like 'Franchise%' then 'TargetHolder' else [Size] end as [Size],
sum(Active) [Active],
sum(case when Comparison <> 'Actual' and Comparison = @Comparison then Target else null end) [Target],
sum(AppThisMonth) [AppThisMonth],
sum(AppLast6) [AppLastMonth],
sum(AppLast12) [AppLast12],
sum(AppYTD) [AppYTD],
sum(TerminatedYTD) [TerminatedYTD]
from 
 mst_SellingCapacity sc,
 msct_UserAccessControlHistory uac
where 
 Comparison <> 'Actual'
 and Comparison = @Comparison
 and [size] like @Size
 and [Level] like @Level
 and sc.AdviserId = uac.AdviserId
 and uac.DomainLogin = @UserId
group by
Area,
Region,
SQM,
Franchise,
Adviser,
[Size]
order by 
Area,
Region,
SQM,
Franchise,
Adviser


GO
