Create Procedure [dbo].[msp_SelectWeeklyCorporateReportDetail]
  @ReportType varchar(50),
  @KPILevel varchar(50),
  @ReportingMonth datetime
AS

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2006 All rights reserved
--
-- Object  : procedure
-- Name    : msp_SelectWeeklyCorporateReportDetail.sql
-- Desc    : Selects Weekly Corporate Data Submitted, Assessed, And Failed
-- Owner   : JNHL
-- Created : 26/07/2006
--
-- Amended : 11/08/2006  - JL - Added Sort Order to Data Set
--
--########################################################################

  --Get the Sort Order
  CREATE TABLE  #Tmp_SortOrder
    ( Value VARCHAR(50)
      ,Label VARCHAR(50)
      ,SortOrder INT)
  
  INSERT INTO #Tmp_SortOrder
  EXEC dbo.msp_SelectBusinessCategory


  SELECT     
    ReportMonth StartDate
    ,CASE @ReportType 
      WHEN 'Submitted' THEN 'How Many Cases Submitted?' 
      WHEN 'Assessed' THEN 'How Many Cases Assessed?' 
      WHEN 'Failed' THEN 'How Many Cases Failed' 
    END ReportTitle
    ,ComplianceCategoryCode
    ,isNull(CASE @ReportType 
          WHEN 'Submitted' THEN SubmittedRiskProposalQty 
          WHEN 'Assessed' THEN InitialRiskAssessedQty 
          WHEN 'Failed' THEN InitialRiskCompletionQTY+ InitialRiskSuitableAdviceQty 
        END, 0) AS Risk 
    ,isNull(CASE @ReportType 
          WHEN 'Submitted' THEN SubmittedRandomProposalQty 
          WHEN 'Assessed' THEN InitialRandomAssessedQty 
          WHEN 'Failed' THEN InitialRandomCompletionQTY + InitialRandomSuitableAdviceQty 
        END, 0) AS Random 
    ,isNull(CASE @ReportType 
          WHEN 'Submitted' THEN SubmittedOtherProposalQty 
          WHEN 'Assessed' THEN InitialOtherAssessedQty 
          WHEN 'Failed' THEN InitialOtherCompletionQTY + InitialOtherSuitableAdviceQty 
        END, 0) AS Other
    , SortOrder
  FROM         
    dbo.mstt_AgentQualityAggregation
    INNER JOIN #Tmp_SortOrder on Value=ComplianceCategoryCode
  WHERE     
    KPILevel = @KpiLevel 
    AND SummaryPeriod = 1 
    AND ReportMonth = @ReportingMonth
  UNION
  SELECT     
    ReportMonth StartDate 
    ,CASE @ReportType 
      WHEN 'Submitted' THEN 'How Many Cases Submitted?' 
      WHEN 'Assessed' THEN 'How Many Cases Assessed?' 
      WHEN 'Failed' THEN 'How Many Cases Failed' 
    END ReportTitle, 'ICOB (PP+GI)' 
    ,isNull(CASE @ReportType 
          WHEN 'Submitted' THEN SUM(SubmittedRiskProposalQty) 
          WHEN 'Assessed' THEN SUM(InitialRiskAssessedQty) 
          WHEN 'Failed' THEN SUM(InitialRiskCompletionQTY + InitialRiskSuitableAdviceQty) 
        END, 0) AS Risk 
    ,isNull(CASE @ReportType
          WHEN 'Submitted' THEN SUM(SubmittedRandomProposalQty) 
          WHEN 'Assessed' THEN SUM(InitialRandomAssessedQty) 
          WHEN 'Failed' THEN SUM(InitialRandomCompletionQTY + InitialRandomSuitableAdviceQty) 
        END, 0) AS Random 
    ,isNull(CASE @ReportType 
          WHEN 'Submitted' THEN SUM(SubmittedOtherProposalQty) 
          WHEN 'Assessed' THEN SUM(InitialOtherAssessedQty) 
          WHEN 'Failed' THEN SUM(InitialOtherCompletionQTY + InitialOtherSuitableAdviceQty) 
        END, 0) AS Other
    , 99 SortOrder
  FROM        
    dbo.mstt_AgentQualityAggregation
  WHERE     
    KPILevel = @KPILevel 
    AND SummaryPeriod = 1 
    AND ReportMonth = @ReportingMonth 
    AND ComplianceCategoryCode IN ('ICOB-GI', 'ICOB-PP')
  GROUP BY ReportMonth






GO
/****** Object:  StoredProcedure [dbo].[msp_SelectWeeklyCorporateReportPercentages]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE  Procedure [dbo].[msp_SelectWeeklyCorporateReportPercentages]
  @ReportType varchar(50),
  @KPILevel varchar(50),
  @ReportingMonth datetime
AS

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2006 All rights reserved
--
-- Object  : procedure
-- Name    : msp_SelectWeeklyCorporateReportPercentages.sql
-- Desc    : Selects Weekly Corporate KPI Data For Suitable Advice & Completion Queries
-- Owner   : JNHL
-- Created : 26/07/2006
--
-- Amended : 11/08/2006  - JL - Added Sort Order to Data Set
--
--########################################################################

  --Get the Sort Order
  CREATE TABLE  #Tmp_SortOrder
    ( Value VARCHAR(50)
      ,Label VARCHAR(50)
      ,SortOrder INT)
  
  INSERT INTO #Tmp_SortOrder
  EXEC dbo.msp_SelectBusinessCategory

  SELECT  
    ReportMonth StartDate
    ,CASE @ReportType 
      WHEN 'SuitableAdvice' THEN 'Suitable Advice Calculation' 
      WHEN 'QueryCalculation' THEN 'Completion Query Calculation' 
    END ReportTitle
    ,ComplianceCategoryCode
    ,isNull(CASE @ReportType 
          WHEN 'SuitableAdvice' THEN SAKPIPercent 
          WHEN 'QueryCalculation' THEN CQKPIPercent 
        END, 0) AS Percentage
    ,SortOrder
  FROM         
    dbo.mstt_AgentQualityAggregation
    INNER JOIN #Tmp_SortOrder on Value=ComplianceCategoryCode
  WHERE     
    KPILevel = @KPILevel 
    AND SummaryPeriod = '1' 
    AND ReportMonth = @ReportingMonth
  UNION SELECT     
    ReportMonth StartDate
        ,CASE @ReportType 
      WHEN 'SuitableAdvice' THEN 'Suitable Advice Calculation' 
      WHEN 'QueryCalculation' THEN 'Completion Query Calculation' 
    END ReportTitle
        ,'ICOB (PP+GI)' ComplianceCategoryCode 
    ,isNull(CASE @ReportType 
          WHEN 'SuitableAdvice' THEN SUM(SAKPIPercent) 
          WHEN 'QueryCalculation' THEN SUM(CQKPIPercent) 
    END, 0) AS Percentage
    ,99 SortOrder
  FROM         
    dbo.mstt_AgentQualityAggregation
  WHERE     
    KPILevel = @KPILevel 
    AND SummaryPeriod = '1' 
    AND ReportMonth = @ReportingMonth 
    AND ComplianceCategoryCode IN ('ICOB-GI', 'ICOB-PP')
  GROUP BY ReportMonth
  

GO
/****** Object:  StoredProcedure [dbo].[msp_SelectYTDProduction]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO




CREATE PROCEDURE [dbo].[msp_SelectYTDProduction] -- WITH RECOMPILE,ENCRYPTION
    @Measure nvarchar(50),
    @BusinessType nvarchar(50),
    @Status nvarchar(50),
    @Comparison nvarchar(50),
    @UserId nvarchar(50)
AS

/******************************************************************************

Copyright (C) Moore Stephens Consulting Limited 2005

Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
          
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>

*******************************************************************************/

-- declare
--     @Measure nvarchar(50),
--     @BusinessType nvarchar(50),
--     @Status nvarchar(50),
--     @Comparison nvarchar(50),
--     @UserId nvarchar(50)
-- 
-- set @Measure = 'Turnover'
-- set @BusinessType = 'Issued'
-- set @Status = 'Active' --'New Recruits (last 6 Months)' --there is no YTD values because when set to Active the datewritten is 000000
-- set @Comparison = 'Company'
-- set @UserId = 'bi\kstokes'

--declare @Actual nvarchar(100)
--set @Actual = 'Actual'

declare @id int

set @id = (select id from mst_YTDProduction_CacheHeader
    where Measure = @Measure
    and Comparison = @Comparison
    and BusinessType =  @BusinessType
    and Status = @Status)

declare @IsHeadOfficeUser int

set @IsHeadOfficeUser = 0

select @IsHeadOfficeUser = 1
from mst_HeadOfficeUsersForReports
where DomainLogin = @UserId

if @IsHeadOfficeUser = 1 

select
  Company,
  Area,
  Region,
  Franchise,
  AdviserId,
  Adviser,
  ProductGroup,
  ActiveStatus,
  YTD,
  PrevYE,
  PrevYTD,
  [Growth],
  [ProjYE],
  [YEGrowth]
from
 mst_YTDProduction_CacheDetail
where id = @id
order by 
 1,2,3,4,6,7   

else

select
  Company,
  Area,
  Region,
  Franchise,
  p.AdviserId,
  Adviser,
  ProductGroup,
  ActiveStatus,
  YTD,
  PrevYE,
  PrevYTD,
  [Growth],
  [ProjYE],
  [YEGrowth]
from
 mst_YTDProduction_CacheDetail p
  inner join msct_UserAccessControl uac
    on p.AdviserId = uac.AdviserId
where id = @id
and uac.DomainLogin = @UserId
order by 
 1,2,3,4,6,7   









GO
/****** Object:  StoredProcedure [dbo].[msp_SelectYTDProduction_NotFromCache]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[msp_SelectYTDProduction_NotFromCache] -- WITH RECOMPILE,ENCRYPTION
    @Measure nvarchar(50),
    @BusinessType nvarchar(50),
    @Status nvarchar(50),
    @Comparison nvarchar(50),
    @UserId nvarchar(50)
AS

/******************************************************************************

Copyright (C) Moore Stephens Consulting Limited 2005

Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
          
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>
--
-- Amended : 08/07/2009 - MPC: Replace *= ANSI JOINS as these not allowed in SQL Server 2005
--
*******************************************************************************/

-- declare
--     @Measure nvarchar(50),
--     @BusinessType nvarchar(50),
--     @Status nvarchar(50),
--     @Comparison nvarchar(50),
--     @UserId nvarchar(50)
-- 
-- set @Measure = 'Turnover'
-- set @BusinessType = 'Issued'
-- set @Status = 'Active' --'New Recruits (last 6 Months)' --there is no YTD values because when set to Active the datewritten is 000000
-- set @Comparison = 'Company'
-- set @UserId = 'bi\kstokes'

--declare @Actual nvarchar(100)
--set @Actual = 'Actual'


--Calculate weighting factor
declare @CurrentMonthLastYearWeightingFactor float
set @CurrentMonthLastYearWeightingFactor = 
  (select cast(day(getdate()-1) as Float) / 
    cast((DAY(DATEADD(d, -DAY(DATEADD(m,1,getdate()-1)),DATEADD(m,1,getdate()-1)))) as Float))


--create #mst_Production to get round compile error
select 
 Area as Company,
 Area,
 Region,
 Franchise,
 AdviserId,
 Adviser,
 ProductGroup,
 ActiveStatus,
 SalesMargin as [YTD],
 Turnover as [PrevYE],
 Turnover as [PrevYTD]  
into
 #mst_Production
from 
 mst_Production 
where 1=2




--create #mst_Production2 to get round compile error
select
 Area as Company,
 Area,
 Region,
 Franchise,
 AdviserId,
 Adviser,
 ProductGroup,
 ActiveStatus,
 SalesMargin as [YTD],
 Turnover as [PrevYE],
 Turnover as [PrevYTD]  
into
 #mst_Production2
from 
 mst_Production p
where 1=2





  insert into #mst_Production
  select 
  'Company',
  p.Area,
  p.Region,
  p.Franchise,
  p.AdviserId,
  p.Adviser,
  p.ProductGroup,
  p.ActiveStatus,
  sum(case @Measure 
    when 'Turnover' then ( case when 
          left(coalesce(p.DateWritten, p.DateIssued),4) = year(getdate())  and
          right(coalesce(p.DateWritten, p.DateIssued),2) >= '01' and 
          right(coalesce(p.DateWritten, p.DateIssued),2) <= month(getdate()) then p.Turnover else 0 end)
    when 'No. of Cases' then ( case when 
          left(coalesce(p.DateWritten, p.DateIssued),4) = year(getdate())  and
          right(coalesce(p.DateWritten, p.DateIssued),2) >= '01' and 
          right(coalesce(p.DateWritten, p.DateIssued),2) <= month(getdate()) then p.Cases else 0 end)
    when 'DA' then ( case when 
          left(coalesce(p.DateWritten, p.DateIssued),4) = year(getdate())  and
          right(coalesce(p.DateWritten, p.DateIssued),2) >= '01' and 
          right(coalesce(p.DateWritten, p.DateIssued),2) <= month(getdate()) then p.DA else 0 end)
          when 'NBI' then ( case when 
          left(coalesce(p.DateWritten, p.DateIssued),4) = year(getdate())  and
          right(coalesce(p.DateWritten, p.DateIssued),2) >= '01' and 
          right(coalesce(p.DateWritten, p.DateIssued),2) <= month(getdate()) then p.NBI else 0 end)
    when 'Sales Margin' then ( case when 
          left(coalesce(p.DateWritten, p.DateIssued),4) = year(getdate())  and
          right(coalesce(p.DateWritten, p.DateIssued),2) >= '01' and 
          right(coalesce(p.DateWritten, p.DateIssued),2) <= month(getdate()) then p.SalesMargin else 0 end)
    else 0 end) [YTD],
       
  0 as [PrevYE],
  0 as [PrevYTD]
        
     
  from 

   mst_Production p,
   msct_UserAccessControl uac

  where 

  p.Comparison = 'Actual' and
  p.AdviserId = uac.AdviserId and
  uac.DomainLogin = @UserId and
  p.BusinessType = @BusinessType and

  --Transaction Occurred this year (to date)
  (
  left(coalesce(p.DateWritten, p.DateIssued),4) = year(getdate())  and
  right(coalesce(p.DateWritten, p.DateIssued),2) >= '01' and 
        right(coalesce(p.DateWritten, p.DateIssued),2) <= month(getdate()) 
        
        or
        --Transaction occurred any time last year
        left(coalesce(p.DateWritten, p.DateIssued),4) = year(dateadd(yy,-1,getdate())) 
        )
  
  and
   (p.ActiveStatus = (case when @Status = '%' then p.ActiveStatus
                     when @Status in ('Active', 'New Recruits (Last 12 Months)') then '1'
                     when @Status = 'Terminated' then '2' end) 
    or
    p.ActiveStatus = (case when @Status = 'Terminated' then '3' else -100 end))
  
  and
  (convert(nvarchar(4),year(getdate()))) + '01'  >=
    case @Status
      when 'New Recruits (Last 12 Months)' then coalesce(p.DateWritten, p.DateIssued)
      else (convert(nvarchar(4),year(getdate()))) + '01'
          end
  
  group by
   p.Area,
   p.Region,
   p.Franchise,
   p.AdviserId,
   p.Adviser,
   p.ProductGroup,
   p.ActiveStatus

if @Comparison = 'Actual'

  begin
  
    update #mst_Production
    set [PrevYE] = (select case when @Measure = 'Turnover' then sum(p.Turnover)
                                when @Measure = 'No. of Cases' then sum(p.Cases)
                                when @Measure = 'DA' then sum(p.DA)
                                when @Measure = 'NBI' then sum(p.NBI)
                                when @Measure = 'Sales Margin' then sum(p.SalesMargin)
                                
                                else 0 end
                            from
                            mst_production p
                            where
              p.BusinessType = @BusinessType and
              p.Comparison = @Comparison and
                                coalesce(p.DateWritten, p.DateIssued) between
                                convert(nvarchar(4), year(dateadd(yy,-1,getdate())),112) + '01' and convert(nvarchar(6),year(dateadd(yy,-1,getdate())),112) + '12' and
                                     p.Area = hp.area and
                                     p.Region = hp.Region and
                                     p.Franchise = hp.Franchise and
                                     p.AdviserId = hp.adviserid and
                                     p.Adviser = hp.adviser and
                                     p.ProductGroup = hp.productgroup)
                     from
                       #mst_Production hp            
  
  
  end

else

 begin
  insert into #mst_Production
  select 
  'Company',
  case when @Comparison like 'Company%' then 'TargetHolder' else p.Area end as Area,
  case when @Comparison like 'Company%' or @Comparison like 'Area%' then 'TargetHolder' else p.Region end as Region,
  case when @Comparison like 'Company%' or @Comparison like 'Area%' or @Comparison like 'Region%' then 'TargetHolder' else p.Franchise end as Franchise,
  p.AdviserId,
  case when @Comparison like 'Company%' or @Comparison like 'Area%' or @Comparison like 'Region%' or @Comparison like 'Franchise%' then 'TargetHolder' else p.Adviser end as Adviser,
  p.ProductGroup,
  p.ActiveStatus,
  0 [YTD],
       
  case when @Measure = 'Turnover' then sum(p.Turnover)
       when @Measure = 'No. of Cases' then sum(p.Cases)
       when @Measure = 'DA' then sum(p.DA)
       when @Measure = 'NBI' then sum(p.NBI)
       when @Measure = 'Sales Margin' then sum(p.SalesMargin) end as [PrevYE],
  
  0 as [PrevYTD]
        
     
  from 

   mst_Production p,
   msct_UserAccessControl uac

  where 

  p.Comparison like @Comparison and
  p.AdviserId = uac.AdviserId and
  uac.DomainLogin = @UserId and
  p.BusinessType = @BusinessType and

  left(coalesce(p.DateWritten, p.DateIssued),4) = year(getdate())  and
  right(coalesce(p.DateWritten, p.DateIssued),2) >= '01' and 
        right(coalesce(p.DateWritten, p.DateIssued),2) <= '12' 

  
  group by
   p.Area,
   p.Region,
   p.Franchise,
   p.AdviserId,
   p.Adviser,
   p.ProductGroup,
   p.ActiveStatus

 end

If @Comparison = 'Actual'

  begin

    insert into #mst_Production2
select
 x.Type,
 x.Area,
 x.Region,
 x.Franchise,
 x.AdviserId,
 x.Adviser,
 x.ProductGroup,
 x.ActiveStatus,
 sum(x.[YTD]) [YTD],
 sum(x.[PrevYE]) [PrevYE],
 sum(x.[PrevYTD]) [PrevYTD]
from
(
    select
      'Company' Type,
      p.Area,
      p.Region,
      p.Franchise,
      p.AdviserId,
      p.Adviser,
      p.ProductGroup,
      p.ActiveStatus,
      convert(float,'0') as [YTD],
      convert(float,'0') as [PrevYE],
                    sum(case @Measure 
      when 'Turnover' then p.Turnover
      when 'No. of Cases' then p.Cases
      when 'DA' then p.DA
            when 'NBI' then p.NBI
      when 'Sales Margin' then p.SalesMargin
      else 0 end) as [PrevYTD]
  
    from 
     mst_Production p,
     msct_UserAccessControl uac
    where 
     p.AdviserId = uac.AdviserId and
     uac.DomainLogin = @UserId and
     --p.ActiveStatus in ('1','2','3') and   --removed filter so taht All does not exclude N/A and Pre-Appointed
    p.BusinessType = @BusinessType and
    
     (p.ActiveStatus = (case when @Status = '%' then p.ActiveStatus
                       when @Status in ('Active', 'New Recruits (Last 12 Months)') then '1'
                       when @Status = 'Terminated' then '2' end) 
      or
      p.ActiveStatus = (case when @Status = 'Terminated' then '3' else -100 end))
      and
    (convert(nvarchar(4),year(dateadd(mm,-12,getdate()))) + convert(nvarchar(2), month(dateadd(mm,-12,getdate()))) ) >=
                case @Status
                                 when 'New Recruits (Last 12 Months)' then coalesce(p.DateWritten, p.DateIssued)
                                 else (convert(nvarchar(4),year(dateadd(mm,-12,getdate()))) + convert(nvarchar(2), month(dateadd(mm,-12,getdate()))) )
                                end 
    and
    left(coalesce(p.DateWritten, p.DateIssued),4) = year(dateadd(yy,-1,getdate())) and
--    right(coalesce(p.DateWritten, p.DateIssued),2) >= '01' and 
          right(coalesce(p.DateWritten, p.DateIssued),2) < month(getdate())
          
          and
    p.Comparison like @Comparison
    group by
      p.Area,
      p.Region,
      p.Franchise,
      p.AdviserId,
      p.Adviser,
      p.ProductGroup,
      p.ActiveStatus


union all

select
      'Company',
      p.Area,
      p.Region,
      p.Franchise,
      p.AdviserId,
      p.Adviser,
      p.ProductGroup,
      p.ActiveStatus,
      convert(float,'0') as [YTD],
      convert(float,'0') as [PrevYE],
                    sum(case @Measure 
      when 'Turnover' then p.Turnover
      when 'No. of Cases' then p.Cases
      when 'DA' then p.DA
            when 'NBI' then p.NBI
      when 'Sales Margin' then p.SalesMargin
      else 0 end) * @CurrentMonthLastYearWeightingFactor as [PrevYTD]
  
    from 
     mst_Production p,
     msct_UserAccessControl uac
    where 
     p.AdviserId = uac.AdviserId and
     uac.DomainLogin = @UserId and
     --p.ActiveStatus in ('1','2','3') and   --removed filter so taht All does not exclude N/A and Pre-Appointed
    p.BusinessType = @BusinessType and
    
     (p.ActiveStatus = (case when @Status = '%' then p.ActiveStatus
                       when @Status in ('Active', 'New Recruits (Last 12 Months)') then '1'
                       when @Status = 'Terminated' then '2' end) 
      or
      p.ActiveStatus = (case when @Status = 'Terminated' then '3' else -100 end))
      and
    (convert(nvarchar(4),year(dateadd(mm,-12,getdate()))) + convert(nvarchar(2), month(dateadd(mm,-12,getdate()))) ) >=
                case @Status
                                 when 'New Recruits (Last 12 Months)' then coalesce(p.DateWritten, p.DateIssued)
                                 else (convert(nvarchar(4),year(dateadd(mm,-12,getdate()))) + convert(nvarchar(2), month(dateadd(mm,-12,getdate()))) )
                                end 
    and
    left(coalesce(p.DateWritten, p.DateIssued),4) = year(dateadd(yy,-1,getdate())) and
--    right(coalesce(p.DateWritten, p.DateIssued),2) >= '01' and 
          right(coalesce(p.DateWritten, p.DateIssued),2) = month(getdate())
          
          and
    p.Comparison like @Comparison
    group by
      p.Area,
      p.Region,
      p.Franchise,
      p.AdviserId,
      p.Adviser,
      p.ProductGroup,
      p.ActiveStatus
) x
group by
 x.Type,
 x.Area,
 x.Region,
 x.Franchise,
 x.AdviserId,
 x.Adviser,
 x.ProductGroup,
 x.ActiveStatus


  end         

else

  begin

    insert into #mst_Production
select
 x.Type,
 x.Area,
 x.Region,
 x.Franchise,
 x.AdviserId,
 x.Adviser,
 x.ProductGroup,
 x.ActiveStatus,
 sum(x.[YTD]) [YTD],
 sum(x.[PrevYE]) [PrevYE],
 sum(x.[PrevYTD]) [PrevYTD]
from
(
    select
    'Company' Type,
    case when @Comparison like 'Company%' then 'TargetHolder' else p.Area end as Area,
    case when @Comparison like 'Company%' or @Comparison like 'Area%' then 'TargetHolder' else p.Region end as Region,
    case when @Comparison like 'Company%' or @Comparison like 'Area%' or @Comparison like 'Region%' then 'TargetHolder' else p.Franchise end as Franchise,
    p.AdviserId,
    case when @Comparison like 'Company%' or @Comparison like 'Area%' or @Comparison like 'Region%' or @Comparison like 'Franchise%' then 'TargetHolder' else p.Adviser end as Adviser,
    p.ProductGroup,
    p.ActiveStatus,
    convert(float,'0') as [YTD],
    convert(float,'0') as [PrevYE],
    sum(case @Measure 
      when 'Turnover' then p.Turnover
      when 'No. of Cases' then p.Cases
      when 'DA' then p.DA
            when 'NBI' then p.NBI
      when 'Sales Margin' then p.SalesMargin
      else 0 end) [PrevYTD]
  
    from 
     mst_Production p,
     msct_UserAccessControl uac
    where 
    p.AdviserId = uac.AdviserId and
    uac.DomainLogin = @UserId and
    p.BusinessType = @BusinessType and
  
    left(coalesce(p.DateWritten, p.DateIssued),4) = year(getdate())  and
    --right(coalesce(p.DateWritten, p.DateIssued),2) >= '01' and 
          right(coalesce(p.DateWritten, p.DateIssued),2) < month(getdate()) 
          
          and
    p.Comparison like @Comparison
    group by
      p.Area,
      p.Region,
      p.Franchise,
      p.AdviserId,
      p.Adviser,
      p.ProductGroup,
      p.ActiveStatus      

union all

select
    'Company',
    case when @comparison like 'company%' then 'TargetHolder' else p.area end as area,
    case when @comparison like 'company%' or @comparison like 'area%' then 'TargetHolder' else p.region end as region,
    case when @comparison like 'company%' or @comparison like 'area%' or @comparison like 'region%' then 'TargetHolder' else p.franchise end as franchise,
    p.adviserid,
    case when @comparison like 'company%' or @comparison like 'area%' or @comparison like 'region%' or @comparison like 'franchise%' then 'TargetHolder' else p.adviser end as adviser,
    p.productgroup,
    p.activestatus,
    convert(float,'0') as [ytd],
    convert(float,'0') as [prevye],
    sum(case @measure 
      when 'turnover' then p.turnover
      when 'no. of cases' then p.cases
      when 'da' then p.da
            when 'nbi' then p.nbi
      when 'sales margin' then p.salesmargin
      else 0 end) * @currentmonthlastyearweightingfactor as [prevytd]
  
    from 
     mst_production p,
     msct_useraccesscontrol uac
    where 
    p.adviserid = uac.adviserid and
    uac.domainlogin = @userid and
    p.businesstype = @businesstype and
  
    left(coalesce(p.datewritten, p.dateissued),4) = year(getdate())  and
    --right(coalesce(p.datewritten, p.dateissued),2) >= '01' and 
          right(coalesce(p.datewritten, p.dateissued),2) = month(getdate()) 
          
          and
    p.comparison like @comparison
    group by
      p.area,
      p.region,
      p.franchise,
      p.adviserid,
      p.adviser,
      p.productgroup,
      p.activestatus
) x
group by
 x.Type,
 x.Area,
 x.Region,
 x.Franchise,
 x.AdviserId,
 x.Adviser,
 x.ProductGroup,
 x.ActiveStatus
--  

  end

-------------------------------

if @Comparison = 'Actual'

  begin
  
    select
      rtrim(a.Company) as Company,
      rtrim(a.Area) as Area,
      rtrim(a.Region) as Region,
      rtrim(a.Franchise) as Franchise,
      a.AdviserId,
      rtrim(a.Adviser) as Adviser,
      rtrim(a.ProductGroup) as ProductGroup,
      a.ActiveStatus,
      a.[YTD],
      a.[PrevYE] ,
      b.PrevYTD,
      (a.YTD-b.PrevYTD)/case when b.PrevYTD = 0 then 1 else b.PrevYTD end [Growth],
       a.YTD * (convert(float, 365)/convert(float, (datediff(dd, (convert(nvarchar(4),year(getdate()),112) + '01' + '01' ), getdate())))) [ProjYE],
      (a.YTD * (convert(float, 365)/convert(float, (datediff(dd, (convert(nvarchar(4),year(getdate()),112) + '01' + '01' ), getdate()))))-a.PrevYE)/case when a.PrevYE = 0 then 1 else a.PrevYE end [YEGrowth]
    from
      #mst_Production a               --MPC: 08/07/2009
      left outer join #mst_Production2 b        --MPC: 08/07/2009
        on  a.adviserid = b.adviserid and     --MPC: 08/07/2009
          a.Adviser = b.Adviser and       --MPC: 08/07/2009
          a.productgroup = b.productgroup     --MPC: 08/07/2009
    where
--      a.adviserid *= b.adviserid and          --MPC: 08/07/2009
--      a.Adviser *= b.Adviser and            --MPC: 08/07/2009
--      a.productgroup *= b.productgroup and      --MPC: 08/07/2009
      (a.[YTD] <> 0 or a.[PrevYE] <> 0 or a.[PrevYTD] <> 0)
    order by 1,2,3,4,6,7

  end

else

  begin
  
    select
      rtrim(a.Company) as Company,
      rtrim(a.Area) as Area,
      rtrim(a.Region) as Region,
      rtrim(a.Franchise) as Franchise,
      a.AdviserId,
      rtrim(a.Adviser) as Adviser,
      rtrim(a.ProductGroup) as ProductGroup,
      a.ActiveStatus,
      a.[YTD] as YTD,
      a.[PrevYE] as PrevYE,
      a.[PrevYTD] as PrevYTD,
      null as [Growth],
      (a.[YTD] * (convert(float, 365)/convert(float, (datediff(dd, (convert(nvarchar(4),year(getdate()),112) + '01' + '01' ), getdate()))))) [ProjYE],
      null as [YEGrowth]
    from
      #mst_Production a
--    group by 
--      a.Company,
--      a.Area,
--      a.Region,
--      a.Franchise,
--      a.AdviserId,
--      a.Adviser,
--      a.ProductGroup,
--      a.ActiveStatus
    --having 
    --  sum(a.[YTD]) <> 0
    --  or sum(a.[PrevYE]) <> 0
    --  or sum(a.[PrevYTD]) <> 0

    order by 1,2,3,4,6,7

  end
  
drop table #mst_Production
drop table #mst_Production2



 







GO
/****** Object:  StoredProcedure [dbo].[msp_SellerABCLeague]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[msp_SellerABCLeague] 
  /* Param List */
  @CalcLastMonthPositions nchar(1) = 'N'
AS


/******************************************************************************

PFA League Refresh
========================

Created by Paul Robathan June 2008

1. Create league table for Sellers (of type PFA only)
2. Records contain Franchise details for PFA
3. As Seller might have > 1 Franchise during year often there will be > 1
    records for the same seller because of this
4. No Franchise sizes are included
5. Turnover is determined by ABC Value and not APE
6. The Franchise ABC League table Last is the driver for which month
    the league is being created for

Amendment History
=================

Date		Author		Description
----------	------		-----------
15/08/2008	P Robathan	Only include Sellers at valid Franchises
20/10/2014	A Groves	SR341528. Handle non-numeric UIDs to protect the batch.
 
*******************************************************************************/

set dateformat dmy


--Get overrides and other info from CodesAndDescriptions spreadsheet.

-- AG 20/10/2014 Start

--Competent Status Overrides
--select distinct 
-- Null as SellerCode,
--  Null as CompetentStatus
--into #CompetentStatusOverride

select top 0 Code as SellerCode, CompetentStatus into #CompetentStatusOverride from mstt_Agents

-- AG 20/10/2014 End


--Seller Types
select distinct 
  Code as AgentType
into #SellerAgentType
from msit_MIWarehouseCodesAndDescriptions
where ColumnName = 'LG-AgtType'
and Description = 'Seller'

--Business Types
select distinct 
  Code as AgentType
into #BusinessAgentType
from msit_MIWarehouseCodesAndDescriptions
where ColumnName = 'LG-AgtType'
and Description = 'Business'


--Put other 'Competent' Agents into the #CompetentStatusOverride table
insert into #CompetentStatusOverride
select Code, CompetentStatus
from mstt_Agents a
where CompetentStatus = 1
and not exists (select 'x' from #CompetentStatusOverride c
        where a.Code = c.SellerCode)

--Get Current League Month - first commission start date after the value stored in LastMonth
declare @CurrentLeagueMonth datetime
set @CurrentLeagueMonth = (
  select min(PeriodStartDate)
  from msit_commissionstatementperiods
  where PeriodStartDate > (select top 1 LastMonth from mstt_sellerABCLeagueTable_last)
  )

--Get Current Year from commission statement period table :MPC 16/01/2008
declare @CurrentYear int
set @CurrentYear = (select Year from msit_commissionstatementperiods 
         where PeriodStartDate = @CurrentLeagueMonth)

--Determine current end-of-month date value from commission statement periods
declare @EndOfMonthDate datetime
set @EndOfMonthDate = (
  select PeriodEndDate
  from msit_commissionstatementperiods
  where PeriodStartDate = @CurrentLeagueMonth
  )

--Get Current Month from commission statement period table  :MPC 16/01/2008
declare @CurrentMonth datetime
set @CurrentMonth = (select Month from msit_commissionstatementperiods 
         where PeriodEndDate = @EndOfMonthDate)

--Determine first day-of-year date value from commission statement periods
declare @FirstDayThisYear datetime
set @FirstDayThisYear = (
  select min(PeriodStartDate)
  from msit_commissionstatementperiods
  where PeriodStartDate >= convert(datetime, convert(char(4),year(@CurrentLeagueMonth)) + '0101', 112)
  )


  
select agentcode,max(id) as ID,max(startdate) as StartDate
into #RSM_ValidASD
from msit_agenthierarchyhistory 
where participanttype = 2                   --ASD
and defaultvalue = 1                    --Ticked rows only
and @EndofMonthDate between startdate and isnull(enddate,'31 dec 9999')       --Hierarchy as at Run Date
and agentcode in (select distinct code from mstt_agentshistory where agenttype in (52,53))  --RSM/BQM
group by agentcode
order by agentcode

select agentcode,max(id) as ID,max(startdate) as StartDate
into #Franchise_ValidRSM
from msit_agenthierarchyhistory 
where participanttype = 4             --RSM
and defaultvalue = 1              --Ticked rows only
and @EndofMonthDate between startdate and isnull(enddate,'31 dec 9999') --Hierarchy as at Run Date
and agentcode in (select code from mstt_agents where agenttype in (select distinct AgentType from #SellerAgentType))  --Franchise Agent types in list of business types
group by agentcode
order by agentcode

select af.code as FranchiseCode,rtrim(ltrim(coalesce(af.CompetitionName, af.TradingName, af.DESCN))) as Franchise,
ar.code as RegionalSalesManagerCode,rtrim(ar.descn) as RegionalSalesManager,
aa.code as AreaSalesManagerCode,rtrim(aa.descn) as AreaSalesManager
into #HistoricalHierarchy
from mstt_agents af 
inner join #Franchise_ValidRSM t1 on af.code = t1.agentcode
inner join msit_agenthierarchyhistory RSM on rsm.id = t1.id
inner join mstt_agents ar on ar.code = rsm.detailagentcode
inner join #RSM_ValidASD t2 on ar.code = t2.agentcode
inner join msit_agenthierarchyhistory ASD on asd.id = t2.id
inner join mstt_agents aa on aa.code = asd.detailagentcode
where af.agenttype in (select distinct AgentType from #SellerAgentType)   --Franchise Agent types in list of business types
order by 1

/*
Insert Turnover values from msit_OpenworkAdviserListing (OAL)and mstt_ProductionAdjustments (ADJ)
into a temporary table. 

This section replaces the msft_Sales extract in the previous version. To be included the OAL and 
ADJ entries must match to the Product Hierarchy, have a valid RSM and fall within the 
Commission Period being processed.
*/
--Extract Openwork Adviser Listing movements

select
 oal.SellerCode as Code,
 ag.Firm as FranchiseCode,
 ag.AgentCategoryDescription as AgentCategory,
 p.ProductName,
 p.ProductSubGroupName,
 p.ProductGroupName,
 p.ProductCategoryName,
 sum(isnull(oal.ABCValue,0)) as Turnover,  
 rtrim(ltrim(coalesce(ag.CompetitionName, ag.TradingName, ag.DESCN))) as Seller, -- as per CR 66
 rtrim(ltrim(coalesce(agf.CompetitionName, agf.TradingName, agf.DESCN))) as Franchise, -- as per CR 66
 hh.AreaSalesManagerCode,
 rtrim(ltrim(hh.AreaSalesManager)) as AreaSalesManager,
 hh.RegionalSalesManagerCode,
 rtrim(ltrim(hh.RegionalSalesManager)) as RegionalSalesManager,
 left(p.ProductCode,8) as HierarchyProdCode,
 oal.Source,
 CAST(CONVERT(NVARCHAR, getdate(), 112) AS DATETIME) as Updated
 
into #CurrentLeagueTable
from msit_OpenworkAdviserListing oal
  inner join mstt_Agents ag on oal.SellerCode = ag.Code
  inner join mstt_Agents agf on ag.Firm = agf.Code
  inner join #HistoricalHierarchy hh on ag.Code = hh.FranchiseCode
  inner join msit_CommissionStatementPeriods csp on csp.Month = oal.Month
  inner join mstt_ProductHierarchy p 
        on  p.productcode = case when oal.source = 'OMS' then 'O_' + left(oal.prodtype,6) 
         when oal.source = 'Payshield' then 'PY_' + left(oal.prodtype,5) 
         when oal.source = 'Openwork 2005' and listposition not in (6,51,54,55) then 'NBI_' + left(oal.prodtype,4)
         when oal.source = 'Openwork 2005' and listposition = 6 and left(oal.prodtype,3) = 'MOR' then 'NBI_MOR'
         when oal.source = 'Openwork 2005' and listposition = 6 and left(oal.prodtype,3) <> 'MOR' then 'NBI_UKPL'
         when oal.source = 'Openwork 2005' and listposition = 54 then 'NBI_SCO'
         when oal.source = 'Openwork 2005' and listposition in (51,55) then 'NBI_STE'
         when oal.source = 'openwork 2006' and oal.prodtype = 'MORTGAGE' then 'NBI_MTG'
         when oal.source = 'openwork 2006' and oal.prodtype is null then oal.prodtype
         when oal.source = 'openwork 2006' and oal.prodtype <> 'MORTGAGE' then oal.prodtype 
        else oal.prodtype end
where
 --Seller Agent type is in list of Business Types
 ag.AgentType in (select distinct AgentType from #SellerAgentType)
 AND
 --Agent is Competent OR Agent is being merged into another
  ag.Code in (select distinct SellerCode from #CompetentStatusOverride where CompetentStatus = 1) 
 --AND
 -- Seller must be a PFA 
 --ag.AgentCategory = 'PFA'
AND
-- Franchise for Seller must be a valid Business Type 
(agf.AgentType in (select distinct AgentType from #BusinessAgentType) or agf.AgentType = '46')
 AND
 --Sale earlier then current Commission Month
  oal.Month <= @CurrentMonth
 AND
 --Sale linked to Commission Month made in Current Year
  csp.Year = @CurrentYear
 AND
 -- Select Payments with Turnover
 isnull(oal.ABCValue,0) <> 0
 AND
 --Product exists on Hierarchy and is required for League
  p.LeagueIncludeFlag = 'Y'
group by 
 oal.SellerCode,
 ag.Firm,
 ag.AgentCategoryDescription,
 p.ProductName,
 p.ProductSubGroupName,
 p.ProductGroupName,
 p.ProductCategoryName,
 rtrim(ltrim(coalesce(ag.CompetitionName, ag.TradingName, ag.DESCN))),
 rtrim(ltrim(coalesce(agf.CompetitionName, agf.TradingName, agf.DESCN))),
 hh.AreaSalesManagerCode,
 rtrim(ltrim(hh.AreaSalesManager)),
 hh.RegionalSalesManagerCode,
 rtrim(ltrim(hh.RegionalSalesManager)),
 p.ProductCode,
 oal.Source
/*
union all

-- Add All Production Adjustments 

select
 ag.Code,
 p.ProductName,
 p.ProductSubGroupName,
 p.ProductGroupName,
 p.ProductCategoryName,
 s.Turnover as Turnover,  
 rtrim(ltrim(coalesce(ag.CompetitionName, ag.TradingName, ag.DESCN))) as Seller, -- as per CR 66
 hh.AreaSalesManagerCode,
 rtrim(ltrim(hh.AreaSalesManager)) as AreaSalesManager,
 hh.RegionalSalesManagerCode,
 rtrim(ltrim(hh.RegionalSalesManager)) as RegionalSalesManager,
 left(ph.ProductCode,8) as HierarchyProdCode,
 'Adjustment' as Source,
 CAST(CONVERT(NVARCHAR, getdate(), 112) AS DATETIME) as Updated

from mstt_ProductionAdjustments s
  inner join mstt_Agents ag on s.AgentCode = ag.Code
  inner join #HistoricalHierarchy hh on ag.Code = hh.FranchiseCode
  inner join msdt_Products p on s.ProductId = p.ProductId
  inner join mstt_ProductHierarchy ph on ph.ProductCode = p.ProductCode
  inner join #MaxFranchiseSizeForYear m on ag.Code = m.Code
  inner join msdt_FranchiseSize fs on m.FranchiseSizeId = fs.FranchiseSizeId

where
 --Franchise Agent type is in list of Business Types
 ag.AgentType in (select distinct AgentType from #BusinessAgentType)
 AND
 --Franchise is Competent OR Franchise is being merged into another
(ag.Code in (select distinct FranchiseCode from #CompetentStatusOverride where CompetentStatus = 1
 AND
 -- Select Adjustments for Current Year (regardless of Date added) :MPC 16/01/2008
 s.[Year] = @CurrentYear
 AND
 -- Select Adjustments with Turnover
 isnull(s.Turnover,0) <> 0
 AND
 --Product exists on Hierarchy and is required for League
  ph.LeagueIncludeFlag = 'Y'

*/

--Truncate target table and insert values from #CurrentLeagueTable temporary table
--Production adjustments inserted into #CurrentLeagueTable are aggregated with main turnover values at this stage
truncate table mstt_SellerABCLeagueTable_Current

insert into mstt_SellerABCLeagueTable_Current
select 
 c.Code,
 c.AgentCategory,
 c.ProductName,
 c.ProductSubGroupName,
 c.ProductGroupName,
 c.ProductCategoryName,
 round(sum(c.Turnover),2) as ABCValue,  
 c.Seller, 
 c.FranchiseCode,
 c.Franchise,
 c.AreaSalesManagerCode,
 c.AreaSalesManager,
 c.RegionalSalesManagerCode,
 c.RegionalSalesManager,
 c.HierarchyProdCode,
 c.Source,
 c.Updated
from 
 #CurrentLeagueTable c
group by 
 c.Code,
 c.AgentCategory,
 c.ProductName,
 c.ProductSubGroupName,
 c.ProductGroupName,
 c.ProductCategoryName,
 c.Seller, 
 c.FranchiseCode,
 c.Franchise,
 c.AreaSalesManagerCode,
 c.AreaSalesManager,
 c.RegionalSalesManagerCode,
 c.RegionalSalesManager,
 c.HierarchyProdCode,
 c.Source, 
 c.Updated
--having round(sum(c.Turnover),2) <> 0

--Roll if parameter is set to 'Y' or the @EndOfMonthDate is the day prior to executing this procedure
if @CalcLastMonthPositions = 'Y' or @EndOfMonthDate = convert(datetime,convert(varchar(8),getdate()-1,112),112)

begin

  --Truncate Previous
  Truncate table mstt_SellerABCLeagueTable_Previous
  
  --Copy Last to Previous except at start of year
  --(as Commission Year of Last is earlier than CommissionYear 

  --declare @CurrentYear int set @CurrentYear = 2009

  declare @LastMonth datetime 
  set @LastMonth = (select max(lastmonth) from mstt_SellerABCLeagueTable_Last)
  
  declare @LastYear int
  set @LastYear = (select Year from msit_commissionstatementperiods 
           where PeriodStartDate = @LastMonth)

  -- Only populate Previous table if reloading data for the same commission year 
  if @LastYear = @CurrentYear
  begin

    insert into mstt_SellerABCLeagueTable_Previous
    select Code, AgentCategory,ProductName, ProductSubGroupName, ProductGroupName, 
    ProductCategoryName,  
    ABCValue, Seller, FranchiseCode, Franchise,
    AreaSalesManagerCode, AreaSalesManager, 
    RegionalSalesManagerCode, RegionalSalesManager, 
    HierarchyProductCode, Source, LastMonth
    from mstt_SellerABCLeagueTable_Last

  end

  --Truncate Last
  Truncate table mstt_SellerABCLeagueTable_Last
  
  --Copy Current to Last
  insert into mstt_SellerABCLeagueTable_Last
  select Code, AgentCategory,ProductName, ProductSubGroupName, ProductGroupName, 
  ProductCategoryName,  
  ABCValue, Seller, FranchiseCode, Franchise,
  AreaSalesManagerCode, AreaSalesManager, 
  RegionalSalesManagerCode, RegionalSalesManager, 
  HierarchyProductCode, Source, @CurrentLeagueMonth
  from mstt_SellerABCLeagueTable_Current

end

 
--Update names of Franchises on Last and Prev tables. This safeguards us against name changes. Without doing this, 
--both old and new names would appear, which is an error.
update l
set Seller = rtrim(ltrim(coalesce(ag.CompetitionName, ag.TradingName, ag.DESCN)))
from mstt_SellerABCLeagueTable_Last l
  inner join mstt_Agents ag on l.Code = ag.Code
update l
set Franchise = rtrim(ltrim(coalesce(ag.CompetitionName, ag.TradingName, ag.DESCN)))
from mstt_SellerABCLeagueTable_Last l
  inner join mstt_Agents ag on l.FranchiseCode = ag.Code
    
update p
set Seller = rtrim(ltrim(coalesce(ag.CompetitionName, ag.TradingName, ag.DESCN)))
from mstt_SellerABCLeagueTable_Previous p
  inner join mstt_Agents ag on p.Code = ag.Code
update p
set Franchise = rtrim(ltrim(coalesce(ag.CompetitionName, ag.TradingName, ag.DESCN)))
from mstt_SellerABCLeagueTable_Previous p
  inner join mstt_Agents ag on p.FranchiseCode = ag.Code

 
drop table #CurrentLeagueTable
drop table #HistoricalHierarchy
drop table #Franchise_ValidRSM
drop table #RSM_ValidASD
drop table #CompetentStatusOverride
drop table #SellerAgentType
drop table #BusinessAgentType

GO
/****** Object:  StoredProcedure [dbo].[msp_SellingCapacity]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [dbo].[msp_SellingCapacity] -- WITH RECOMPILE,ENCRYPTION
  /* Param List */
AS
/******************************************************************************

Copyright (C) Moore Stephens Consulting Limited 2005

AMENDMENTS
==========
23/07/2009  Mike Cawood   Replace mstt_AgentsHistory by mstt_Agents to avoid many
              to one relationship.

*******************************************************************************/

truncate table mst_SellingCapacity 

set dateformat dmy
 
--declare @SwiftAgentDateStarted  nvarchar(255)
declare @SwiftAgentDateStarted  datetime                          --MPC: 23/07/2009
set @SwiftAgentDateStarted  = (select convert(datetime,DefaultValue,103) as DefaultValue  --MPC: 23/07/2009
        from mstt_DefaultCodeValues 
        where CodeColumn = 'SwiftAgentDateStarted')   

declare @CurrentStatusDate datetime
set @CurrentStatusDate = (select max(StatusDate) 
      from msft_CapacityTerminationCounts 
      where reporttype='Capacity'
      and Comparison = 'Actual')
      
declare @FirstDayThisYear datetime
set @FirstDayThisYear = convert(datetime,cast(year(getdate()-1) as varchar(4))+'01'+'01', 103)      

--Get the Capacity rows
insert into mst_SellingCapacity (
 AdviserId,
 AgentCode,
 [Level],
 FranchiseSizeID,
 Active,
 Target,
 Comparison
)
select 
 AdviserId as AdviserId,
 AgentCode as AgentCode,
 [Level] as [Level],
 FranchiseSizeID as FranchiseSize,
 case when Comparison = 'Actual' then Val else null end as Active,
 case when Comparison = 'Actual' then null else Val end as Target,
 Comparison
from 
 msft_CapacityTerminationCounts
where 
 ReportType = 'Capacity'
 and StatusDate = @CurrentStatusDate

 
--Slot in a row for each applicable RSM/Level/Size combo, with the YTD Terminations for Advisers
insert into mst_SellingCapacity (
 AdviserId,
 AgentCode,
 FranchiseSizeId,
 [Level],
 TerminatedYTD,
 Comparison
)
select 
 adh.AdviserId,
 adh.AgentCode,
 nullif(ctc.FranchiseSizeId, -99),
 ctc.[Level],
 sum(ctc.Val),
 ctc.Comparison
from 
 msft_capacityterminationcounts ctc,
 msdt_AdviserHistory ah,
 msdt_AdviserDummiesHistory adh
where 
 ctc.AdviserId = ah.AdviserId
 and ah.RegionalSalesManagerCode+'_RSM_DUMMY_CODE' = adh.AgentCode
 and ctc.ReportType = 'Terminations'
 and ctc.Comparison = 'Actual'
 and ctc.Level = 'Adviser'
 and ctc.StatusDate between @FirstDayThisYear and @CurrentStatusDate
 and adh.IsCurrent = 1
group by
 adh.AdviserId,
 adh.AgentCode,
 ctc.FranchiseSizeId,
 ctc.[Level],
 ctc.Comparison
 
--Slot in a row for each applicable RSM/Level/Size combo, with the YTD Terminations for Franchises
insert into mst_SellingCapacity (
 AdviserId,
 AgentCode,
 FranchiseSizeId,
 [Level],
 TerminatedYTD,
 Comparison
)
select 
 adh_RSM.AdviserId,
 adh_RSM.AgentCode,
 nullif(ctc.FranchiseSizeId, -99),
 ctc.[Level],
 sum(ctc.Val),
 ctc.Comparison
from 
 msft_capacityterminationcounts ctc,
 msdt_AdviserDummiesHistory adh_Franchise,
 msdt_AdviserDummiesHistory adh_RSM
where 
 ctc.AdviserId = adh_Franchise.AdviserId
 and adh_Franchise.RegionalSalesManagerCode+'_RSM_DUMMY_CODE' = adh_RSM.AgentCode
 and ctc.ReportType = 'Terminations'
 and ctc.Comparison = 'Actual'
 and ctc.Level = 'Franchise'
 and ctc.StatusDate between @FirstDayThisYear and @CurrentStatusDate
 and adh_RSM.IsCurrent = 1
group by
 adh_RSM.AdviserId,
 adh_RSM.AgentCode,
 ctc.FranchiseSizeId,
 ctc.[Level],
 ctc.Comparison



update 
 mst_SellingCapacity
set
 Adviser = a.Adviser,
 Franchise = a.Franchise,
 SQM = isnull(a.SalesQualityManager, 'Yet to be allocated'),
 Region = a.RegionalSalesManager,
 Area = a.AreaSalesManager
 
from 
 msdt_adviserHistory a,
 mst_SellingCapacity s
where
 iscurrent = 1 and
 s.AdviserId = a.AdviserId
 
 
 --Update for Franchises and terminations (must go to the Adviser Dummies table)
 update 
 mst_SellingCapacity
set
 Adviser = a.Adviser,
 Franchise = a.Franchise,
 SQM = isnull(a.SalesQualityManager, 'Yet to be allocated'),
 Region = a.RegionalSalesManager,
 Area = a.AreaSalesManager

from 
 msdt_adviserDummiesHistory a,
 mst_SellingCapacity s
where
 IsCurrent = 1 and
 s.AdviserId = a.AdviserId
 
 


update
 mst_SellingCapacity 
set 
 DateStarted = (case when (a.Datestarted = @SwiftAgentDateStarted and a.OscarDateStarted is not null) then a.OscarDateStarted
                else a.Datestarted
                end ) ,
 DateTerminated = a.DateLeaving
 --Active = case when a.CompetentStatus = 1 then 1 else 0 end
from
-- mstt_AgentsHistory a       --MPC: 23/07/2009
   mstt_Agents a          --MPC: 23/07/2009
where 
 mst_SellingCapacity.agentcode = a.code
 
 
--Update for Franchises
 update
 mst_SellingCapacity 
set 
 DateStarted = (case when (a.Datestarted = @SwiftAgentDateStarted and a.OscarDateStarted is not null) then a.OscarDateStarted
                else a.Datestarted
                end ) ,
 DateTerminated = a.DateLeaving--,
 --Active = case when a.CompetentStatus = 1 then 1 else 0 end
from
-- mstt_AgentsHistory a,      --MPC: 23/07/2009
   mstt_Agents a,         --MPC: 23/07/2009
 msdt_AdviserDummiesHistory ad
where 
 mst_SellingCapacity.AgentCode = ad.AgentCode and
 ad.FranchiseCode = a.Code and
 mst_SellingCapacity.[Level] = 'Franchise'



update
 mst_SellingCapacity
set
 [Size] = f.FranchiseSizeType
from
 msdt_FranchiseSize f
where
 mst_SellingCapacity.franchisesizeid = f.franchisesizeid

 
update
 mst_SellingCapacity
set
 AppThisMonth = case when month(DateStarted) = month(getdate()) and year(DateStarted) = year(getdate()) then
                     1 else 0 end,
 AppLast6 = case when DateStarted >= dateadd(mm,-6,getdate()) then
                     1 else 0 end,
 AppLast12 = case when DateStarted >= dateadd(mm,-12,getdate()) then
                     1 else 0 end,
 AppYTD = case when DateStarted between @FirstDayThisYear and getdate()-1 then 
    1 else 0 end--, --Commenting out due to TerminationsYTD being set explicitly above.
-- TerminatedYTD = case when year(dateterminated) = year(getdate()) then
--                      1               
--                else 0
--                end

