CREATE procedure [dbo].[msp_SQMKPISummary]


as

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : msp_SQMKPISummary.sql
-- Desc    : 
-- Owner   : KS
-- Created : 28/06/2006
--
--
-- Amended : 08/07/2009 - MPC: Replace *= ANSI JOINS as these not allowed in SQL Server 2005
--
--########################################################################


select 
 SalesQualitySQMLevelCode as [SQMCode],
 cast('' as nvarchar(255)) as [SQMName],
 ComplianceCategoryCode as [COB],
 SummaryPeriod as [SummaryPeriod],
 SubmittedRiskProposalQty as [Cases Submitted],
 InitialRiskAssessedQty as [Cases Assessed],
 SAKPIPercent as [SuitableAdvicePercent],
 InitialOtherSuitableAdviceQty as [SuitableAdviceFails],
 CQKPIPercent as [CompletionQueriesPercent],
 InitialOtherCompletionQty as [CompletionQueriesFails],
 RejectKPIPercent as [Rejects],
 ReplacementKPIPercent as [Replacements],
 ComplaintQty as [Justified Complaints],
 cast('' as nvarchar(255)) as [Competence]
into
 #mst_SummaryReport
from 
 msv_AgentQualityAggregation
where 1=2



insert into  
 #mst_SummaryReport
select
 [SQMCode] = AgentCode,
 [SQMName] = b.Descn,
 [COB] = ComplianceCategoryCode,
 [SummaryPeriod] = SummaryPeriod,
 [Cases Submitted] = CasesSubmitted,
 [Cases Assessed] = CasesAssessed,
 [SuitableAdvicePercent] = SAKPIPercent,
 [SuitableAdviceFails] = SuitableAdviceFailures,
 [CompletionQueriesPercent] = CQKPIPercent,
 [CompletionQueriesFails] = CompletionFailures,
 [Rejects] = Rejects,
 [Replacements] = Replacements,
 [Justified Complaints] = ComplaintQty,
 [Competence] = ''
from
 msv_AgentQualityAggregation a              --MPC: 08/07/2009
 inner join mstt_Agents b on a.AgentCode = b.Code   --MPC: 08/07/2009
where
-- a.AgentCode *= b.Code and              --MPC: 08/07/2009
 a.reportmonth = (select max(reportmonth)
                         from mstt_AgentQualityAggregation) and
 a.summaryperiod = 1 and
 a.kpilevel = 'sqmkpi' and
 a.HierarchyTypeCode = 'KPI'  -- Span affecting KPI.  Change to Current for Current Span report



select 
 *
from
 #mst_SummaryReport
order by
 SQMCode


 

 
drop table #mst_SummaryReport




GO
