/****** Object:  StoredProcedure [dbo].[msp_TruncateTables]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER OFF
GO

create procedure [dbo].[msp_TruncateTables]
 @Client        varchar(50),
 @Module        varchar(50),
 @Type          varchar(50),
 @Area          varchar(50),
 @ProcedureName varchar(255) out,
 @Error         int          out
WITH RECOMPILE --, ENCRYPTION

as

--############################################################################
-- Copyright (c) MOORE STEPHENS CONSULTING LIMITED, 2004 All rights reserved 
-- 
-- Object     : Procedure
-- Name       : msp_TruncateTable.sql
-- Description: Truncate relevant tables
-- Owner      : Ermedin Selmanovic
-- Created    : 22/12/2004
-- 
--############################################################################
--
-- $Id: msp_TruncateTables.sql 1.1 2004/12/22 11:57:17Z dselmano Exp $
-- $Log: msp_TruncateTables.sql $
-- Revision 1.1  2004/12/22 11:57:17Z  dselmano
-- Initial revision
--
--############################################################################

declare 
 @Phase          varchar(50),
 @Process        varchar(100),
 @ErrorCode      int,
 @ErrorCount     int,
 @StopProcessing bit

set @ErrorCount     = 0
set @StopProcessing = 0 

set @ProcedureName  = object_name(@@procid)
set @Process        = @ProcedureName
set @Phase          = 'START'

exec msp_ProcessLog @Phase, @Process, null, @Module, @Client

declare
 Tables cursor
for
select
 [Database],
 [Name],
 [ArchiveName]
from
 mst_DataImportConfiguration
where
 [Client] = @Client and
 [Module] = @Module and
 [Type]   = @Type   and
 [Active] = 1
order by
 [Name]
for read only

declare 
 @Database    varchar(50),
 @Name        varchar(50),
 @ArchiveName varchar(50),
 @String         varchar(4000),
 @FullName    varchar(255)

open
 Tables
fetch
 Tables
into
 @Database,
 @Name, 
 @ArchiveName

while (@@fetch_status = 0)
begin
 if @Area = 'IMPORT' or @Area = 'ALL'
 begin
 
  set @FullName = @Database + '..' + @Name
 
  if object_id(@FullName) is NOT NULL
   begin
   
    set @Phase   = 'START'
    set @Process = 'Truncate Import Table ' + @Name
    exec msp_ProcessLog @Phase, @Process, null, @Module, @Client
   
    set @String = 'truncate table ' + @Name
    
    exec (@String)
    
    set @Error = @@Error
    if @Error <> 0
     begin
      set @ErrorCount = @ErrorCount + 1
            
      set @Phase          = 'ERROR'
      set @ErrorCode      = 40
      set @Process        = @Name + ': ' + (select [Description] from mst_ErrorCodes ec where ec.ErrorCode = @ErrorCode)
      set @StopProcessing = (select StopProcessing from mst_ErrorCodes ec where ec.ErrorCode = @ErrorCode) 
      
      exec msp_ProcessLog @Phase, @Process, null, @Module, @Client
      
     end
    else
     begin   
      set @Phase = 'END'
      exec msp_ProcessLog @Phase, @Process, null, @Module, @Client
     end
    end
  else
   begin
    set @ErrorCount = @ErrorCount + 1
    
    set @Phase          = 'ERROR'
    set @ErrorCode      = 5
    set @Process        = @Name + ': ' + (select [Description] from mst_ErrorCodes ec where ec.ErrorCode = @ErrorCode)
    set @StopProcessing = (select StopProcessing from mst_ErrorCodes ec where ec.ErrorCode = @ErrorCode) 
    
    exec msp_ProcessLog @Phase, @Process, null, @Module, @Client
   end
 end
 if @Area = 'ARCHIVE' or @Area = 'ALL'
 begin
 
  set @FullName = @Database + '..' + @ArchiveName
 
  if object_id(@FullName) is NOT NULL
   begin
   
    set @Phase   = 'START'
    set @Process = 'Truncate Post Table ' + @ArchiveName
    exec msp_ProcessLog @Phase, @Process, null, @Module, @Client
   
    set @String = 'truncate table ' + @ArchiveName
   
    exec (@String)

    set @Error = @@Error
    if @Error <> 0
     begin
      set @ErrorCount     = @ErrorCount + 1
           
      set @Phase          = 'ERROR'
      set @ErrorCode      = 40
      set @Process        = @ArchiveName + ': ' + (select [Description] from mst_ErrorCodes ec where ec.ErrorCode = @ErrorCode)
      set @StopProcessing = (select StopProcessing from mst_ErrorCodes ec where ec.ErrorCode = @ErrorCode) 
      
      exec msp_ProcessLog @Phase, @Process, null, @Module, @Client
       
     end
    else
     begin   
      set @Phase = 'END'
      exec msp_ProcessLog @Phase, @Process, null, @Module, @Client
     end
   end
  else
   begin
    set @ErrorCount     = @ErrorCount + 1
 
    set @Phase          = 'ERROR'
    set @ErrorCode      = 5
    set @Process        = @ArchiveName + ': ' + (select [Description] from mst_ErrorCodes ec where ec.ErrorCode = @ErrorCode)
    set @StopProcessing = (select StopProcessing from mst_ErrorCodes ec where ec.ErrorCode = @ErrorCode) 
 
    exec msp_ProcessLog @Phase, @Process, null, @Module, @Client
 
  end   
 end
 
 fetch
  Tables
 into
  @Database,
  @Name, 
  @ArchiveName

end

close Tables
deallocate Tables

if @ErrorCount > 0
 begin
  set @Phase          = 'ERROR'
  set @ErrorCode      = 1000
  set @Process        = @ProcedureName + ': ' + (select [Description] from mst_ErrorCodes ec where ec.ErrorCode = @ErrorCode)
  set @StopProcessing = (select StopProcessing from mst_ErrorCodes ec where ec.ErrorCode = @ErrorCode) 
 
  exec msp_ProcessLog @Phase, @Process, null, @Module, @Client

  raiserror (@Process, 16, 1)
 end
 
--MK: Added this so as to drop the indexes prior to populating the tables
 
set @Phase   = 'START'
set @Process = 'Dropping Indexes'
exec msp_ProcessLog @Phase, @Process, null, @Module, @Client

if @Module = 'Swift' 
begin
   set @Process = 'Calling mscp_DropPKFromImportTables'
   exec msp_ProcessLog @Phase, @Process, null, @Module, @Client
   exec mscp_DropPKFromImportTables
end
else
begin
  if @Module = 'OMS' 
  begin
    set @Process = 'Calling omscp_DropPKFromImportTables'
    exec msp_ProcessLog @Phase, @Process, null, @Module, @Client
      exec omscp_DropPKFromImportTables
  end
  else
  begin
    set @Process = 'Calling opmscp_DropPKFromImportTables'
    exec msp_ProcessLog @Phase, @Process, null, @Module, @Client
      exec opmscp_DropPKFromImportTables
  end
end

set @Phase   = 'END'
set @Process = 'Dropping Indexes'
exec msp_ProcessLog @Phase, @Process, null, @Module, @Client

set @Phase   = 'END'
set @Process = @ProcedureName
exec msp_ProcessLog @Phase, @Process, null, @Module, @Client


GO
