/****** Object:  StoredProcedure [dbo].[msp_YTDProduction_CacheWarmer]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[msp_YTDProduction_CacheWarmer] -- WITH RECOMPILE,ENCRYPTION
  @id int,
  @Measure nvarchar(50),
  @BusinessType nvarchar(50),
  @Status nvarchar(50),
  @Comparison nvarchar(50),
  @UserId nvarchar(50),
  @Debug varchar(1)

with Recompile

AS

/******************************************************************************

Copyright (C) Moore Stephens Consulting Limited 2005

Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
          
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
  Date    Author    Description
  ----------  --------  ---------------------------------------------------------------
  28/11/2008  A Groves  This proc fails with "divide by zero" on 1st January.  Module
              amended to use @ProcessDate instead of getdate() to facilitate
              testing the fix.  Case statements added to deal with the divide
              by zero.
  12/02/2009  A Groves  Proc running very slowly so msp_ProcessLog calls added to locate
              problem area.
  13/02/2009  A Groves  Cached query plan found to cause performance problem.  This proc has had the
              "with recompile" option added which causes the query plan to
              be derived each time - but in consequence - a better performing
              plan is used.  It looks like "recompile" has been specified
              in the past - but then commented out.
  17/02/2009  A Groves  Performance problem persisting so SET ARITHABORT ON.
  25/02/2009  A Groves  Turned INTs into NVARCHARs to improve query performance.
  03/03/2009  A Groves  Re-coded the WHERE clause for query '03 Insert Into Temp Table-1' to remove
              coalesce and simplify the expression to improve performance.
  08/07/2009  M Cawood  Replace *= ANSI JOINS as these not allowed in SQL Server 2005
*******************************************************************************/

--     @Measure nvarchar(50),
--     @BusinessType nvarchar(50),
--     @Status nvarchar(50),
--     @Comparison nvarchar(50),
--     @UserId nvarchar(50)
-- 
-- set @Measure = 'Turnover'
-- set @BusinessType = 'Issued'
-- set @Status = 'Active' --'New Recruits (last 6 Months)' --there is no YTD values because when set to Active the datewritten is 000000
-- set @Comparison = 'Company'
-- set @UserId = 'bi\kstokes'

--declare @Actual nvarchar(100)
--set @Actual = 'Actual'

declare @PhaseStart   varchar(50),
  @PhaseEnd   varchar(50),
  @Client     varchar(50),
  @Module     varchar(50),
  @Process    varchar(100),
  @ProcessDate    datetime,
  @CurrentYear    nvarchar(50), -- AG 25/02/2009
  @CurrentMonth   nvarchar(50), -- AG 25/02/2009
  @LastYear   nvarchar(50)  -- AG 25/02/2009

set @PhaseStart     = 'START'
set @PhaseEnd       = 'END'
set @Module         = 'CacheWarmer:' + @Measure + '|' + @BusinessType + '|' + @Status + '|' + @Comparison
set @Client         = 'Openwork'

if @debug = 'Y'
begin
  set @Process      = '01 Calc Weighting & Create Temp Table'
  exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client
end

set @ProcessDate = (select ProcessDate from mst_ImportControl where Type = 'Openwork' and Module = 'Swift') -- AG 28/11/2008

set @CurrentYear  = convert(nvarchar(50),year(@ProcessDate))      -- AG 25/02/2009
set @CurrentMonth = substring(convert(nvarchar(3),month(@ProcessDate)+100),2,2) -- AG 25/02/2009
set @LastYear   = convert(nvarchar(50),year(dateadd(yy,-1,@ProcessDate))) -- AG 25/02/2009

--Calculate weighting factor
declare @CurrentMonthLastYearWeightingFactor float
set @CurrentMonthLastYearWeightingFactor = 
  (select cast(day(@ProcessDate-1) as Float) / 
    cast((DAY(DATEADD(d, -DAY(DATEADD(m,1,@ProcessDate-1)),DATEADD(m,1,@ProcessDate-1)))) as Float))


--create #mst_Production to get round compile error
select 
 Area as Company,
 Area,
 Region,
 Franchise,
 AdviserId,
 Adviser,
 ProductGroup,
 ActiveStatus,
 SalesMargin as [YTD],
 Turnover as [PrevYE],
 Turnover as [PrevYTD]  
into
 #mst_Production
from 
 mst_Production 
where 1=2


if @debug = 'Y'
begin
  set @Process      = '02 Select Into Temp Table'
  exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client
end


--create #mst_Production2 to get round compile error
select
 Area as Company,
 Area,
 Region,
 Franchise,
 AdviserId,
 Adviser,
 ProductGroup,
 ActiveStatus,
 SalesMargin as [YTD],
 Turnover as [PrevYE],
 Turnover as [PrevYTD]  
into
 #mst_Production2
from 
 mst_Production p
where 1=2


if @debug = 'Y'
begin
  set @Process      = '03 Insert Into Temp Table-1'
  exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client
end
  -- AG 25/02/2009 Start
  
  insert into #mst_Production
  select 
  'Company',
  p.Area,
  p.Region,
  p.Franchise,
  p.AdviserId,
  p.Adviser,
  p.ProductGroup,
  p.ActiveStatus,
  sum(case @Measure 
    when 'Turnover' then ( case when 
          left(coalesce(p.DateWritten, p.DateIssued),4) = @CurrentYear  and
          right(coalesce(p.DateWritten, p.DateIssued),2) >= '01' and 
          right(coalesce(p.DateWritten, p.DateIssued),2) <= @CurrentMonth then p.Turnover else 0 end)
    when 'No. of Cases' then ( case when 
          left(coalesce(p.DateWritten, p.DateIssued),4) = @CurrentYear  and
          right(coalesce(p.DateWritten, p.DateIssued),2) >= '01' and 
          right(coalesce(p.DateWritten, p.DateIssued),2) <= @CurrentMonth then p.Cases else 0 end)
    when 'DA' then ( case when 
          left(coalesce(p.DateWritten, p.DateIssued),4) = @CurrentYear  and
          right(coalesce(p.DateWritten, p.DateIssued),2) >= '01' and 
          right(coalesce(p.DateWritten, p.DateIssued),2) <= @CurrentMonth then p.DA else 0 end)
          when 'NBI' then ( case when 
          left(coalesce(p.DateWritten, p.DateIssued),4) = @CurrentYear  and
          right(coalesce(p.DateWritten, p.DateIssued),2) >= '01' and 
          right(coalesce(p.DateWritten, p.DateIssued),2) <= @CurrentMonth then p.NBI else 0 end)
    when 'Sales Margin' then ( case when 
          left(coalesce(p.DateWritten, p.DateIssued),4) = @CurrentYear  and
          right(coalesce(p.DateWritten, p.DateIssued),2) >= '01' and 
          right(coalesce(p.DateWritten, p.DateIssued),2) <= @CurrentMonth then p.SalesMargin else 0 end)
    else 0 end) [YTD],
       
  0 as [PrevYE],
  0 as [PrevYTD]
        
  -- AG 03/03/2009 Start   

  from 

   mst_Production p
   inner join msct_UserAccessControl uac on p.AdviserId = uac.AdviserId

  where 

  p.Comparison = 'Actual' and
  uac.DomainLogin = @UserId and
  p.BusinessType = @BusinessType and

  --Transaction Occurred this year (to date) or any time last year unless new recruit
  (
  (p.DateWritten between @LastYear + '01' and @CurrentYear + @CurrentMonth)
    or  
  (p.DateIssued between @LastYear + '01' and @CurrentYear + @CurrentMonth)
    or
  (@Status = 'New Recruits (Last 12 Months)' and
  (p.DateWritten <= @CurrentYear + '01'
    or
   p.DateIssued <= @CurrentYear + '01'))
  )
  and
   (p.ActiveStatus = (case when @Status = '%' then p.ActiveStatus
                     when @Status in ('Active', 'New Recruits (Last 12 Months)') then '1'
                     when @Status = 'Terminated' then '2' end) 
    or
    p.ActiveStatus = (case when @Status = 'Terminated' then '3' else -100 end))

  -- AG 03/03/2009 End

  group by
   p.Area,
   p.Region,
   p.Franchise,
   p.AdviserId,
   p.Adviser,
   p.ProductGroup,
   p.ActiveStatus

  -- AG 25/02/2009 End

if @Comparison = 'Actual'

  begin
  
    if @debug = 'Y'
    begin
      set @Process      = '04a Update Temp Table - Actual'
      exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client
    end

    update #mst_Production
    set [PrevYE] = (select case when @Measure = 'Turnover' then sum(p.Turnover)
                                when @Measure = 'No. of Cases' then sum(p.Cases)
                                when @Measure = 'DA' then sum(p.DA)
                                when @Measure = 'NBI' then sum(p.NBI)
                                when @Measure = 'Sales Margin' then sum(p.SalesMargin)
                                
                                else 0 end
                            from
                            mst_production p
                            where
              p.BusinessType = @BusinessType and
              p.Comparison = @Comparison and
                                coalesce(p.DateWritten, p.DateIssued) between
                                convert(nvarchar(4), year(dateadd(yy,-1,@ProcessDate)),112) + '01' and convert(nvarchar(6),year(dateadd(yy,-1,@ProcessDate)),112) + '12' and
                                     p.Area = hp.area and
                                     p.Region = hp.Region and
                                     p.Franchise = hp.Franchise and
                                     p.AdviserId = hp.adviserid and
                                     p.Adviser = hp.adviser and
                                     p.ProductGroup = hp.productgroup)
                     from
                       #mst_Production hp            
  
  
  end

else

 begin

  if @debug = 'Y'
  begin
    set @Process      = '04b Insert Into Temp Table - Company'
    exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client
  end

  insert into #mst_Production
  select 
  'Company',
  case when @Comparison like 'Company%' then 'TargetHolder' else p.Area end as Area,
  case when @Comparison like 'Company%' or @Comparison like 'Area%' then 'TargetHolder' else p.Region end as Region,
  case when @Comparison like 'Company%' or @Comparison like 'Area%' or @Comparison like 'Region%' then 'TargetHolder' else p.Franchise end as Franchise,
  p.AdviserId,
  case when @Comparison like 'Company%' or @Comparison like 'Area%' or @Comparison like 'Region%' or @Comparison like 'Franchise%' then 'TargetHolder' else p.Adviser end as Adviser,
  p.ProductGroup,
  p.ActiveStatus,
  0 [YTD],
       
  case when @Measure = 'Turnover' then sum(p.Turnover)
       when @Measure = 'No. of Cases' then sum(p.Cases)
       when @Measure = 'DA' then sum(p.DA)
       when @Measure = 'NBI' then sum(p.NBI)
       when @Measure = 'Sales Margin' then sum(p.SalesMargin) end as [PrevYE],
  
  0 as [PrevYTD]
        
     
  from 

   mst_Production p,
   msct_UserAccessControl uac

  where 

  p.Comparison like @Comparison and
  p.AdviserId = uac.AdviserId and
  uac.DomainLogin = @UserId and
  p.BusinessType = @BusinessType and

  left(coalesce(p.DateWritten, p.DateIssued),4) = year(@ProcessDate)  and
  right(coalesce(p.DateWritten, p.DateIssued),2) >= '01' and 
        right(coalesce(p.DateWritten, p.DateIssued),2) <= '12' 

  
  group by
   p.Area,
   p.Region,
   p.Franchise,
   p.AdviserId,
   p.Adviser,
   p.ProductGroup,
   p.ActiveStatus

 end


If @Comparison = 'Actual'

begin

if @debug = 'Y'
begin
  set @Process      = '05a Insert Into Temp Table - Actual'
  exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client
end

insert into #mst_Production2
select
 x.Type,
 x.Area,
 x.Region,
 x.Franchise,
 x.AdviserId,
 x.Adviser,
 x.ProductGroup,
 x.ActiveStatus,
 sum(x.[YTD]) [YTD],
 sum(x.[PrevYE]) [PrevYE],
 sum(x.[PrevYTD]) [PrevYTD]
from
(
    select
      'Company' Type,
      p.Area,
      p.Region,
      p.Franchise,
      p.AdviserId,
      p.Adviser,
      p.ProductGroup,
      p.ActiveStatus,
      convert(float,'0') as [YTD],
      convert(float,'0') as [PrevYE],
                    sum(case @Measure 
      when 'Turnover' then p.Turnover
      when 'No. of Cases' then p.Cases
      when 'DA' then p.DA
            when 'NBI' then p.NBI
      when 'Sales Margin' then p.SalesMargin
      else 0 end) as [PrevYTD]
  
    from 
     mst_Production p,
     msct_UserAccessControl uac
    where 
     p.AdviserId = uac.AdviserId and
     uac.DomainLogin = @UserId and
     --p.ActiveStatus in ('1','2','3') and   --removed filter so taht All does not exclude N/A and Pre-Appointed
    p.BusinessType = @BusinessType and
    
     (p.ActiveStatus = (case when @Status = '%' then p.ActiveStatus
                       when @Status in ('Active', 'New Recruits (Last 12 Months)') then '1'
                       when @Status = 'Terminated' then '2' end) 
      or
      p.ActiveStatus = (case when @Status = 'Terminated' then '3' else -100 end))
      and
    (convert(nvarchar(4),year(dateadd(mm,-12,@ProcessDate))) + convert(nvarchar(2), month(dateadd(mm,-12,@ProcessDate))) ) >=
                case @Status

                                 when 'New Recruits (Last 12 Months)' then coalesce(p.DateWritten, p.DateIssued)
                                 else (convert(nvarchar(4),year(dateadd(mm,-12,@ProcessDate))) + convert(nvarchar(2), month(dateadd(mm,-12,@ProcessDate))) )
                                end 
    and
    left(coalesce(p.DateWritten, p.DateIssued),4) = year(dateadd(yy,-1,@ProcessDate)) and
--    right(coalesce(p.DateWritten, p.DateIssued),2) >= '01' and 
          right(coalesce(p.DateWritten, p.DateIssued),2) < month(@ProcessDate)
          
          and
    p.Comparison like @Comparison
    group by
      p.Area,
      p.Region,
      p.Franchise,
      p.AdviserId,
      p.Adviser,
      p.ProductGroup,
      p.ActiveStatus


union all

select
      'Company',
      p.Area,
      p.Region,
      p.Franchise,
      p.AdviserId,
      p.Adviser,
      p.ProductGroup,
      p.ActiveStatus,
      convert(float,'0') as [YTD],
      convert(float,'0') as [PrevYE],
                    sum(case @Measure 
      when 'Turnover' then p.Turnover
      when 'No. of Cases' then p.Cases
      when 'DA' then p.DA
            when 'NBI' then p.NBI
      when 'Sales Margin' then p.SalesMargin
      else 0 end) * @CurrentMonthLastYearWeightingFactor as [PrevYTD]
  
    from 
     mst_Production p,
     msct_UserAccessControl uac
    where 
     p.AdviserId = uac.AdviserId and
     uac.DomainLogin = @UserId and
     --p.ActiveStatus in ('1','2','3') and   --removed filter so taht All does not exclude N/A and Pre-Appointed
    p.BusinessType = @BusinessType and
    
     (p.ActiveStatus = (case when @Status = '%' then p.ActiveStatus
                       when @Status in ('Active', 'New Recruits (Last 12 Months)') then '1'
                       when @Status = 'Terminated' then '2' end) 
      or
      p.ActiveStatus = (case when @Status = 'Terminated' then '3' else -100 end))
      and
    (convert(nvarchar(4),year(dateadd(mm,-12,@ProcessDate))) + convert(nvarchar(2), month(dateadd(mm,-12,@ProcessDate))) ) >=
                case @Status
                                 when 'New Recruits (Last 12 Months)' then coalesce(p.DateWritten, p.DateIssued)
                                 else (convert(nvarchar(4),year(dateadd(mm,-12,@ProcessDate))) + convert(nvarchar(2), month(dateadd(mm,-12,@ProcessDate))) )
                                end 
    and
    left(coalesce(p.DateWritten, p.DateIssued),4) = year(dateadd(yy,-1,@ProcessDate)) and
--    right(coalesce(p.DateWritten, p.DateIssued),2) >= '01' and 
          right(coalesce(p.DateWritten, p.DateIssued),2) = month(@ProcessDate)
          
          and
    p.Comparison like @Comparison
    group by
      p.Area,
      p.Region,
      p.Franchise,
      p.AdviserId,
      p.Adviser,
      p.ProductGroup,
      p.ActiveStatus
) x
group by
 x.Type,
 x.Area,
 x.Region,
 x.Franchise,
 x.AdviserId,
 x.Adviser,
 x.ProductGroup,
 x.ActiveStatus


end         

else

begin

if @debug = 'Y'
begin
  set @Process      = '05b Insert Into Temp Table - Company'
  exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client
end

insert into #mst_Production
select
 x.Type,
 x.Area,
 x.Region,
 x.Franchise,
 x.AdviserId,
 x.Adviser,
 x.ProductGroup,
 x.ActiveStatus,
 sum(x.[YTD]) [YTD],
 sum(x.[PrevYE]) [PrevYE],
 sum(x.[PrevYTD]) [PrevYTD]
from
(
    select
    'Company' Type,
    case when @Comparison like 'Company%' then 'TargetHolder' else p.Area end as Area,
    case when @Comparison like 'Company%' or @Comparison like 'Area%' then 'TargetHolder' else p.Region end as Region,
    case when @Comparison like 'Company%' or @Comparison like 'Area%' or @Comparison like 'Region%' then 'TargetHolder' else p.Franchise end as Franchise,

    p.AdviserId,
    case when @Comparison like 'Company%' or @Comparison like 'Area%' or @Comparison like 'Region%' or @Comparison like 'Franchise%' then 'TargetHolder' else p.Adviser end as Adviser,
    p.ProductGroup,
    p.ActiveStatus,
    convert(float,'0') as [YTD],
    convert(float,'0') as [PrevYE],
    sum(case @Measure 
      when 'Turnover' then p.Turnover
      when 'No. of Cases' then p.Cases
      when 'DA' then p.DA
            when 'NBI' then p.NBI
      when 'Sales Margin' then p.SalesMargin
      else 0 end) [PrevYTD]
  
    from 
     mst_Production p,
     msct_UserAccessControl uac
    where 
    p.AdviserId = uac.AdviserId and
    uac.DomainLogin = @UserId and
    p.BusinessType = @BusinessType and
  
    left(coalesce(p.DateWritten, p.DateIssued),4) = year(@ProcessDate)  and
    --right(coalesce(p.DateWritten, p.DateIssued),2) >= '01' and 
          right(coalesce(p.DateWritten, p.DateIssued),2) < month(@ProcessDate) 
          
          and
    p.Comparison like @Comparison
    group by
      p.Area,
      p.Region,
      p.Franchise,
      p.AdviserId,
      p.Adviser,
      p.ProductGroup,
      p.ActiveStatus      

union all

select
    'Company',
    case when @comparison like 'company%' then 'TargetHolder' else p.area end as area,
    case when @comparison like 'company%' or @comparison like 'area%' then 'TargetHolder' else p.region end as region,
    case when @comparison like 'company%' or @comparison like 'area%' or @comparison like 'region%' then 'TargetHolder' else p.franchise end as franchise,
    p.adviserid,
    case when @comparison like 'company%' or @comparison like 'area%' or @comparison like 'region%' or @comparison like 'franchise%' then 'TargetHolder' else p.adviser end as adviser,
    p.productgroup,
    p.activestatus,
    convert(float,'0') as [ytd],
    convert(float,'0') as [prevye],
    sum(case @measure 
      when 'turnover' then p.turnover
      when 'no. of cases' then p.cases
      when 'da' then p.da
            when 'nbi' then p.nbi
      when 'sales margin' then p.salesmargin
      else 0 end) * @currentmonthlastyearweightingfactor as [prevytd]
  
    from 
     mst_production p,
     msct_useraccesscontrol uac
    where 
    p.adviserid = uac.adviserid and
    uac.domainlogin = @userid and
    p.businesstype = @businesstype and
  
    left(coalesce(p.datewritten, p.dateissued),4) = year(@ProcessDate)  and
    --right(coalesce(p.datewritten, p.dateissued),2) >= '01' and 
          right(coalesce(p.datewritten, p.dateissued),2) = month(@ProcessDate) 
          
          and
    p.comparison like @comparison
    group by
      p.area,
      p.region,
      p.franchise,
      p.adviserid,
      p.adviser,
      p.productgroup,
      p.activestatus
) x
group by
 x.Type,
 x.Area,
 x.Region,
 x.Franchise,
 x.AdviserId,
 x.Adviser,
 x.ProductGroup,
 x.ActiveStatus
--  

end

-------------------------------

if @debug = 'Y'
begin
  set @Process      = '06 Create Indexes'
  exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client
end

create clustered index rt1 on #mst_Production(AdviserID,Adviser,ProductGroup)
create clustered index rt1 on #mst_Production2(AdviserID,Adviser,ProductGroup)

if @Comparison = 'Actual'

  begin

    if @debug = 'Y'
    begin
      set @Process      = '07a Insert Into CacheDetail - Actual'
      exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client
    end

    insert into mst_YTDProduction_CacheDetail
    select
      @id,
      rtrim(a.Company) as Company,
      rtrim(a.Area) as Area,
      rtrim(a.Region) as Region,
      rtrim(a.Franchise) as Franchise,
      a.AdviserId,
      rtrim(a.Adviser) as Adviser,
      rtrim(a.ProductGroup) as ProductGroup,
      a.ActiveStatus,
      a.[YTD],
      a.[PrevYE] ,
      b.PrevYTD,
      --Set ceiling growth value at 9999.9999 - That is 999,999.99%
      case when (a.YTD-b.PrevYTD)/case when b.PrevYTD = 0 then 1 else b.PrevYTD end > 9999.9999 then 9999.9999 
           else (a.YTD-b.PrevYTD)/case when b.PrevYTD = 0 then 1 else b.PrevYTD end 
      end [Growth],
      case convert(float, (datediff(dd, (convert(nvarchar(4),year(@ProcessDate),112) + '01' + '01' ), @ProcessDate)))
        when 0.0 then 0.00
        else a.YTD * (convert(float, 365)/convert(float, (datediff(dd, (convert(nvarchar(4),year(@ProcessDate),112) + '01' + '01' ), @ProcessDate)))) 
      end [ProjYE], -- AG 28/11/2008
      --Set ceiling growth value at 9999.9999 - That is 999,999.99%
      case convert(float, (datediff(dd, (convert(nvarchar(4),year(@ProcessDate),112) + '01' + '01' ), @ProcessDate)))
        when 0.0 then 0.00
        else case when (a.YTD * (convert(float, 365)/convert(float, (datediff(dd, (convert(nvarchar(4),year(@ProcessDate),112) + '01' + '01' ), @ProcessDate))))-a.PrevYE)/case when a.PrevYE = 0 then 1 else a.PrevYE end > 9999.9999 then 9999.9999
                else (a.YTD * (convert(float, 365)/convert(float, (datediff(dd, (convert(nvarchar(4),year(@ProcessDate),112) + '01' + '01' ), @ProcessDate))))-a.PrevYE)/case when a.PrevYE = 0 then 1 else a.PrevYE end
        end
      end [YEGrowth]  -- AG 28/11/2008
    from
      #mst_Production a             --MPC: 08/07/2009
      left outer join #mst_Production2 b      --MPC: 08/07/2009
        on  a.adviserid = b.adviserid and   --MPC: 08/07/2009
          a.Adviser = b.Adviser and     --MPC: 08/07/2009
          a.productgroup = b.productgroup   --MPC: 08/07/2009
    where
--      a.adviserid *= b.adviserid and        --MPC: 08/07/2009
--      a.Adviser *= b.Adviser and          --MPC: 08/07/2009
--      a.productgroup *= b.productgroup and    --MPC: 08/07/2009
      (a.[YTD] <> 0 or a.[PrevYE] <> 0 or a.[PrevYTD] <> 0)

  end

else

  begin

    if @debug = 'Y'
    begin
      set @Process      = '07b Insert Into CacheDetail - Company'
      exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client
    end

    insert into mst_YTDProduction_CacheDetail
    select
      @id,
      rtrim(a.Company) as Company,
      rtrim(a.Area) as Area,
      rtrim(a.Region) as Region,
      rtrim(a.Franchise) as Franchise,
      a.AdviserId,
      rtrim(a.Adviser) as Adviser,
      rtrim(a.ProductGroup) as ProductGroup,
      a.ActiveStatus,
      a.[YTD] as YTD,
      a.[PrevYE] as PrevYE,
      a.[PrevYTD] as PrevYTD,
      null as [Growth],
      case convert(float, (datediff(dd, (convert(nvarchar(4),year(@ProcessDate),112) + '01' + '01' ), @ProcessDate)))
        when 0.0 then 0.00
        else (a.[YTD] * (convert(float, 365)/convert(float, (datediff(dd, (convert(nvarchar(4),year(@ProcessDate),112) + '01' + '01' ), @ProcessDate))))) 
      end [ProjYE], -- AG 28/11/2008
      null as [YEGrowth]
    from
      #mst_Production a
--    group by 
--      a.Company,
--      a.Area,
--      a.Region,
--      a.Franchise,
--      a.AdviserId,
--      a.Adviser,
--      a.ProductGroup,
--      a.ActiveStatus
    --having 
    --  sum(a.[YTD]) <> 0
    --  or sum(a.[PrevYE]) <> 0
    --  or sum(a.[PrevYTD]) <> 0


  end

if @debug = 'Y'
begin
  set @Process      = '08 Drop Temp Tables'
  exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client
end

drop table #mst_Production
drop table #mst_Production2




