/****** Object:  StoredProcedure [dbo].[msp_YTDProduction_PopulateCache]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS OFF
GO
SET QUOTED_IDENTIFIER OFF
GO
/******************************************************************************

Copyright (C) Moore Stephens Consulting Limited 2005

Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
          
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
  Date    Author    Description
  ----------  --------  ---------------------------------------------------------------
  12/02/2009  A Groves  Proc running very slowly so Debug parameter added to the call
              to "msp_YTDProduction_CacheWarmer".  This proc may be run
              as follows:
                exec msp_YTDProduction_PopulateCache
                  or
                exec msp_YTDProduction_PopulateCache 'Y'
              If 'Y' parameter is passed, then it causes a large number of
              diagnostic rows to be written to table mst_ProcessLog.
*******************************************************************************/

CREATE procedure [dbo].[msp_YTDProduction_PopulateCache] @Debug varchar(1) = 'N'

as 

begin

truncate table mst_YTDProduction_CacheHeader
truncate table mst_YTDProduction_CacheDetail

insert into mst_YTDProduction_CacheHeader
select *
from (  select 'Written' as BusinessType
  union select 'Issued') BusinessType
cross join 
  (select 'Turnover' as Measure
  union select 'DA'
  union select 'No. of Cases'
  union select 'NBI'
  union select 'Sales Margin') Measure
cross join
  (select 'Company' as Comparison
  union select 'Actual') Comparison
cross join
  (select '%' as Status
  union select 'Active') Status


declare Executions cursor for
select id, BusinessType, Measure, Comparison, Status
from mst_YTDProduction_CacheHeader
order by id

declare @id int
declare @BusinessType varchar(20)
declare @Measure varchar(20)
declare @Comparison varchar(20)
declare @Status varchar(20)

drop INDEX [dbo].[mst_YTDProduction_CacheDetail].[IX_mst_YTDProduction_CacheDetail]


open Executions
fetch next from Executions into @id, @BusinessType, @Measure, @Comparison, @Status

while @@Fetch_Status = 0

begin

insert into mst_YTDProduction_CacheDetail
exec msp_YTDProduction_CacheWarmer
    @id,
    @Measure,
    @BusinessType,
    @Status,
    @Comparison,
    'openwork\mitest11',
  @Debug

fetch next from Executions into @id, @BusinessType, @Measure, @Comparison, @Status

end

close Executions
deallocate Executions

 CREATE  CLUSTERED  INDEX [IX_mst_YTDProduction_CacheDetail] ON [dbo].[mst_YTDProduction_CacheDetail]([id], [AdviserId]) ON [PRIMARY]


end


GO
