CREATE procedure [dbo].[msp_ZANAdviserListing]
with recompile
as

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : msp_ZANAdviserListing.sql
-- Owner   : MWA
-- Created : 20/07/2006
--
--########################################################################

-- WI260 Mike Cawood 23/03/2007

-- Ticket 220: Mike Cawood 06/08/2007
-- Recode APE, AgentSplit, Sacrifice derivations using RemarksDataN fields

-- Mike Cawood 

Declare @LoadMidMonth DateTime
Declare @LoadEndMonth DateTime
Declare @BaseMidMonth DateTime
Declare @BaseEndMonth DateTime

Select @LoadMidMonth = (Select isnull (max(Month),'01/01/1901') from msit_ZANAdviserListing
where ListPosition = 55)

Select @LoadEndMonth = (Select isnull (max(Month),'01/01/1901') from msit_ZANAdviserListing
where ListPosition <> 55)

Select @BaseMidMonth = (Select isnull (max(Month),'01/01/1901') from msit_FeesZANCurrentListing
where ListPosition = 55)

Select @BaseEndMonth = (Select isnull (max(Month),'01/01/1901') from msit_FeesZANCurrentListing
where ListPosition <> 55)

  exec msp_ProcessLog 'ZAL', 'Variables Filled', null, 'ZAL', 'Openwork'

If @BaseMidMonth > @LoadMidMonth
or @BaseEndMonth > @LoadEndMonth

Begin

-- CREATE A TEMP TABLE OF THE MSIT_FEESNONSWIFTFEELISTING TABLE TO HOLD THE ENHANCEMENTRATE LOGIC
select
 Id,
 EnhancementRate = case
                    when ListPosition = 100 then isnull(EnhancementRate, 0.0)
                    when ListPosition < 6 and (isnull(UpLiftIT,0.0) + isnull(UpLiftAccr,0.0)) <> 0 then round(((UpLiftRate + 1) * 100), 2)
                    when ListPosition < 6 and (isnull(UpLiftIT,0.0) + isnull(UpLiftAccr,0.0))  = 0 then 100
                    else 0.0
                   end,
s.SwiftFranchise, 
s.SwiftSeller,
s.SellerPrefix,
s.SellerSerial,
s.SellerSuffix,
s.SellerName,
s.Client,
s.ClientForename,
s.ClientSurname,
s.BACSDate,
s.Policy,
s.ProductCode,
s.DeclarationDate,
s.StartDate,
s.[Month],
s.Frequency,
s.Premium,
s.Value1,
s.Value4,
s.TotalFees,
s.CommRateTrue,
s.CommRateStd,
s.InitialPeriod,
s.PayBasis,
s.Value5,
s.Value6,
s.RemarkCode1,                  
s.RemarkCode2,
s.RemarkCode3,
s.RemarkCode4,
s.RemarkCode5,
s.RemarkCode6,
s.RemarksData1,
s.RemarksData2,
s.RemarksData3,
s.RemarksData4,
s.RemarksData5,
s.RemarksData6,
s.BIRemarks,
s.RemarksString,    -- WI260
s.ListPosition,
s.Value2,
s.Value3,
s.UpLiftAccr,
s.EnhancementAccr,
s.StillLeftToAccrue,
s.UpLiftIT,
s.ITAdvance,
s.ITAccrued,
s.ITLiability,
s.FranchisePrefix,
s.FranchiseSerial,
s.FranchiseSuffix,
s.DateLoaded
into
 #EnhancementRate
from
 msit_FeesNonSWIFTFeeListing s
where
 (s.OpenworkInd       is NULL   or
  s.OpenworkInd       <> 'Y')   and
 s.ListPosition   not in (7,8)
 and ((Month > @LoadMidMonth
 and ListPosition = 55)
 or (Month > @LoadEndMonth
 and ListPosition in (0,1,2,3,6,51,54,100)))

  exec msp_ProcessLog 'ZAL', 'Select Into 1', null, 'ZAL', 'Openwork'

create index er1 on #EnhancementRate (SwiftFranchise)

  exec msp_ProcessLog 'ZAL', 'er1', null, 'ZAL', 'Openwork'


select
 BusinessCode     = er.SwiftFranchise,
 BusinessName     = coalesce(a.TradingName, a.DESCN),
 SellerCode       = er.SwiftSeller,
 SellerName       = case
                     when isnull(er.SellerPrefix, '') + isnull(er.SellerSerial, '') + isnull(er.SellerSuffix, '') is NULL then cast(rtrim(ltrim(er.SellerName)) as varchar(50))
                     else cast(rtrim(ltrim(er.SellerName)) as varchar(50)) + ' - ' + isnull(er.SellerPrefix, '') + isnull(er.SellerSerial, '') + isnull(er.SellerSuffix, '')
                    end,
 SellerForename    = case
                     when er.SwiftSeller is not null and a.FirstNames is not null and charindex(' ', a.FirstNames) = 0 then a.FirstNames 
                     when er.SwiftSeller is not null and a.FirstNames is not null and charindex(' ', a.FirstNames) > 0 then rtrim(substring(a.FirstNames, 1, charindex(' ', a.FirstNames)))
                     when charindex(' ', ltrim(er.SellerName)) = 0 then ltrim(er.SellerName)
                     else rtrim(substring(ltrim(er.SellerName), 1, charindex(' ', ltrim(er.SellerName))))
                    end,
 SellerSurname    = case
                     when er.SwiftSeller is not null and a.[Name] is not null then a.[Name]
                     when charindex(' ', reverse(rtrim(er.SellerName))) = 0 then er.SellerName
                     else reverse(rtrim(substring(reverse(rtrim(er.SellerName)), 1, charindex(' ', reverse(rtrim(er.SellerName))))))
                    end,
 Client           = er.Client,
 ClientForename    = case
                     when charindex(' ', er.ClientForename) = 0 then er.ClientForename
                     else rtrim(substring(er.ClientForename, 1, charindex(' ', er.ClientForename)))
                    end,
 ClientSurname    = er.ClientSurname,
 BACSDate         = er.BACSDate,
 Policy           = er.Policy,
 --ProdType         = isnull((select 
 --                            substring(lp.SWIFTProdType,1,8)
 --                          from
 --                            msit_LegacyProducts lp
 --                           where
 --                            er.ProductCode           = lp.LegacyProdCode and
 --                            er.DeclarationDate between lp.StartDate      and lp.EndDate), er.ProductCode),
 ProdType         = cast(null as varchar(8)),
 StartDate        = er.StartDate,
 PaymentDate      = er.[Month],
 Frequency        = case
                     when er.Frequency in ('A','M','S','R') then er.Frequency
                     else NULL
                    end,
 Premium          = case
      -- RH 23 Jan 2007 CR230 Fix Scot Eq Monthly Premium Value
      when er.ListPosition = 54 then er.Premium
                      when er.Frequency = 'M' then er.Premium / 12
                      else er.Premium
                    end,
-- Doing this calculation here, as all elements are available, rather than requiring its own update (commented out below)
 APE              =   -- RH 23 Jan 2007 CR230 Fix Scot Eq Monthly Premium Value
      -- WI260 Cater for negative APE
        case
                     when (isnull(er.Value1, 0.0) <> 0 or isnull(er.Value4, 0.0) <> 0 or isnull(er.TotalFees, 0.0) <> 0) and er.Frequency     in ('M', 'A', 'R') then er.Premium / 100
                     when (isnull(er.Value1, 0.0) <> 0 or isnull(er.Value4, 0.0) <> 0 or isnull(er.TotalFees, 0.0) <> 0) and er.Frequency not in ('M', 'A', 'R') then er.Premium / 1000 -- Single Premium / 10
                     else 0.0
                    end 
        * 
        -- Sign --WI260
        case
      when (isnull(er.Value1, 0.0) < 0 or isnull(er.Value4, 0.0) < 0 or isnull(er.TotalFees, 0.0) < 0) then -1
      else 1
        end
        * 
        -- multiplier for ScotEq monthly - all other options remain the same
        case
      when er.ListPosition = 54 and er.Frequency = 'M' then 12
      else 1
        end
        *
                    case  -- AgentSplit
                     when er.RemarkCode1 in ('012','805','905') 
      then isnull(cast(convert(float,replace(er.RemarksData1, '%', '')) as decimal(15,2)),100.0)
--      then replace(er.RemarksData1, '%', '')
                     when er.RemarkCode2 in ('012','805','905') 
      then isnull(cast(convert(float,replace(er.RemarksData2, '%', '')) as decimal(15,2)),100.0)
--      then replace(er.RemarksData2, '%', '')
                     when er.RemarkCode3 in ('012','805','905') 
      then isnull(cast(convert(float,replace(er.RemarksData3, '%', '')) as decimal(15,2)),100.0)
--      then replace(er.RemarksData3, '%', '')
                     when er.RemarkCode4 in ('012','805','905') 
      then isnull(cast(convert(float,replace(er.RemarksData4, '%', '')) as decimal(15,2)),100.0)
--      then replace(er.RemarksData4, '%', '')
                     when er.RemarkCode5 in ('012','805','905') 
      then isnull(cast(convert(float,replace(er.RemarksData5, '%', '')) as decimal(15,2)),100.0)
--      then replace(er.RemarksData5, '%', '')
                     when er.RemarkCode6 in ('012','805','905')
      then isnull(cast(convert(float,replace(er.RemarksData6, '%', '')) as decimal(15,2)),100.0) 
--      then replace(er.RemarksData6, '%', '')
                     else 100.0
--           else '100.0'
                    end,                    
 CommRate         = case
                     when isnull(er.CommRateTrue, 0.0) <> 0.0 then er.CommRateTrue
                     else er.CommRateStd
                    end,
 InitialPeriod    = InitialPeriod,
 PayBasis         = case
                     when er.PayBasis = 'I' then 'IT'
                     when er.PayBasis = 'A' then 'Accr'
                     else case
                           when abs(isnull(er.Value4, 0.0) + isnull(er.Value5, 0.0) + isnull(er.Value6, 0.0)) > 0 then 'IT'
                           else 'Accr'
                          end
                    end,
 Sacrifice        = case
                     when er.RemarkCode1 in ('016','091','092','802') and substring(er.RemarksData1,2,9) is not NULL
      then isnull(cast(convert(float,rtrim(substring(er.RemarksData1,2,9))) as decimal(15,2)),0.0)
                     when er.RemarkCode2 in ('016','091','092','802') and substring(er.RemarksData2,2,9) is not NULL
      then isnull(cast(convert(float,rtrim(substring(er.RemarksData2,2,9))) as decimal(15,2)),0.0)
                     when er.RemarkCode3 in ('016','091','092','802') and substring(er.RemarksData3,2,9) is not NULL
      then isnull(cast(convert(float,rtrim(substring(er.RemarksData3,2,9))) as decimal(15,2)),0.0)
                     when er.RemarkCode4 in ('016','091','092','802') and substring(er.RemarksData4,2,9) is not NULL
      then isnull(cast(convert(float,rtrim(substring(er.RemarksData4,2,9))) as decimal(15,2)),0.0)
                     when er.RemarkCode5 in ('016','091','092','802') and substring(er.RemarksData5,2,9) is not NULL
      then isnull(cast(convert(float,rtrim(substring(er.RemarksData5,2,9))) as decimal(15,2)),0.0)
                     when er.RemarkCode6 in ('016','091','092','802') and substring(er.RemarksData6,2,9) is not NULL
      then isnull(cast(convert(float,rtrim(substring(er.RemarksData6,2,9))) as decimal(15,2)),0.0)
                     else 0.0
--                     when er.RemarkCode1 in ('016','091','092','802') then replace(er.RemarksData1, '$', '')
--                     when er.RemarkCode2 in ('016','091','092','802') then replace(er.RemarksData2, '$', '')
--                     when er.RemarkCode3 in ('016','091','092','802') then replace(er.RemarksData3, '$', '')
--                     when er.RemarkCode4 in ('016','091','092','802') then replace(er.RemarksData4, '$', '')
--                     when er.RemarkCode5 in ('016','091','092','802') then replace(er.RemarksData5, '$', '')
--                     when er.RemarkCode6 in ('016','091','092','802') then replace(er.RemarksData6, '$', '')
--                     else '0.0'
                    end,
 AgentSplit       = case
                     when er.RemarkCode1 in ('012','805','905') 
      then isnull(cast(convert(float,replace(er.RemarksData1, '%', '')) as decimal(15,2)),100.0)
--      then replace(er.RemarksData1, '%', '')
                     when er.RemarkCode2 in ('012','805','905') 
      then isnull(cast(convert(float,replace(er.RemarksData2, '%', '')) as decimal(15,2)),100.0)
--      then replace(er.RemarksData2, '%', '')
                     when er.RemarkCode3 in ('012','805','905') 
      then isnull(cast(convert(float,replace(er.RemarksData3, '%', '')) as decimal(15,2)),100.0)
--      then replace(er.RemarksData3, '%', '')
                     when er.RemarkCode4 in ('012','805','905') 
      then isnull(cast(convert(float,replace(er.RemarksData4, '%', '')) as decimal(15,2)),100.0)
--      then replace(er.RemarksData4, '%', '')
                     when er.RemarkCode5 in ('012','805','905') 
      then isnull(cast(convert(float,replace(er.RemarksData5, '%', '')) as decimal(15,2)),100.0)
--      then replace(er.RemarksData5, '%', '')
                     when er.RemarkCode6 in ('012','805','905')
      then isnull(cast(convert(float,replace(er.RemarksData6, '%', '')) as decimal(15,2)),100.0) 
--      then replace(er.RemarksData6, '%', '')
                     else 100.0
--                     else '100.0'
                    end,
 FeeType          = -- 'IC',
        -- RH 23 Jan 2007 CR224 Fix Fee Type Descriptions
      case
        when er.ListPosition in (51,55) 
          and isnull(er.Premium,0) = 0        -- WI260
          and er.RemarksString like '%trai%'      -- WI260
          and er.RemarksString not like '%no tra%' then 'TF'  -- WI260        
        when er.RemarkCode1 in (73, 86, 94, 162) then 'IC'
        when er.RemarkCode2 in (73, 86, 94, 162) then 'IC'
        when er.RemarkCode3 in (73, 86, 94, 162) then 'IC'
        when er.RemarkCode4 in (73, 86, 94, 162) then 'IC'
        when er.RemarkCode5 in (73, 86, 94, 162) then 'IC'
        when er.RemarkCode6 in (73, 86, 94, 162) then 'IC'
        when er.RemarkCode1 in (74, 87, 99, 100, 112, 155, 156, 157, 159, 185, 813, 908) then 'Fee'
        when er.RemarkCode2 in (74, 87, 99, 100, 112, 155, 156, 157, 159, 185, 813, 908) then 'Fee'
        when er.RemarkCode3 in (74, 87, 99, 100, 112, 155, 156, 157, 159, 185, 813, 908) then 'Fee'
        when er.RemarkCode4 in (74, 87, 99, 100, 112, 155, 156, 157, 159, 185, 813, 908) then 'Fee'
        when er.RemarkCode5 in (74, 87, 99, 100, 112, 155, 156, 157, 159, 185, 813, 908) then 'Fee'
        when er.RemarkCode6 in (74, 87, 99, 100, 112, 155, 156, 157, 159, 185, 813, 908) then 'Fee'
        when er.RemarkCode1 in (75, 167) then 'RC'
        when er.RemarkCode2 in (75, 167) then 'RC'
        when er.RemarkCode3 in (75, 167) then 'RC'
        when er.RemarkCode4 in (75, 167) then 'RC'
        when er.RemarkCode5 in (75, 167) then 'RC'
        when er.RemarkCode6 in (75, 167) then 'RC'
        when er.RemarkCode1 in (111, 170) then 'AF'
        when er.RemarkCode2 in (111, 170) then 'AF'
        when er.RemarkCode3 in (111, 170) then 'AF'
        when er.RemarkCode4 in (111, 170) then 'AF'
        when er.RemarkCode5 in (111, 170) then 'AF'
        when er.RemarkCode6 in (111, 170) then 'AF'
        when er.RemarkCode1 = 154 then 'PR'
        when er.RemarkCode2 = 154 then 'PR'
        when er.RemarkCode3 = 154 then 'PR'
        when er.RemarkCode4 = 154 then 'PR'
        when er.RemarkCode5 = 154 then 'PR'
        when er.RemarkCode6 = 154 then 'PR'
        when er.RemarkCode1 in (163, 166, 173, 174, 184) then 'TF'
        when er.RemarkCode2 in (163, 166, 173, 174, 184) then 'TF'
        when er.RemarkCode3 in (163, 166, 173, 174, 184) then 'TF'
        when er.RemarkCode4 in (163, 166, 173, 174, 184) then 'TF'
        when er.RemarkCode5 in (163, 166, 173, 174, 184) then 'TF'
        when er.RemarkCode6 in (163, 166, 173, 174, 184) then 'TF'
        when er.RemarkCode1 = 175 then 'LF'
        when er.RemarkCode2 = 175 then 'LF'
        when er.RemarkCode3 = 175 then 'LF'
        when er.RemarkCode4 = 175 then 'LF'
        when er.RemarkCode5 = 175 then 'LF'
        when er.RemarkCode6 = 175 then 'LF'
        else 'IC'
      end,
 Remarks          = er.BIRemarks,
 Provider         = case
                     when er.ListPosition = 6 and er.ProductCode  = 'MOR' then 'MORTGAGE'
                     when er.ListPosition = 6 and er.ProductCode <> 'MOR' then 'GI'
                     when er.ListPosition = 54                           then 'SCOT EQ'
                     when er.ListPosition in (51,55)                     then 'STERLING'
                     else 'ZURICH'
                    end,
 ProviderCode     = case
                     when er.ListPosition = 6 and er.ProductCode  = 'MOR' then 'MORTGAGE'
                     when er.ListPosition = 6 and er.ProductCode <> 'MOR' then 'GI'
                     when er.ListPosition = 54                           then 'SCOT EQ'
                     when er.ListPosition in (51,55)                     then 'STERLING'
                     else 'ZURICH'
                    end,
 SourceID            = er.[Id],
 ListPosition        = er.ListPosition,
 [Month]             = er.[Month],
 Source              = 'ZAN',
 TotDue_Base         = isnull(er.Value1, 0.0),
 Accrued_Base        = isnull(er.Value2, 0.0),
 StillToAccr_Base    = isnull(er.Value3, 0.0),
 ITAdvanced_Base     = isnull(er.Value4, 0.0),
 ITAccrued_Base      = isnull(er.Value5, 0.0),
 ITOutLiability_Base = isnull(er.Value6, 0.0),
 EnhancementRate     = isnull(er.EnhancementRate,0.0),
 TotDue_Enhd         = isnull(er.Value1, 0.0) * isnull(er.EnhancementRate,0.0) / 100,
 Accrued_Enhd        = case
                        when er.ListPosition < 6 then isnull(er.Value2,0.0) + isnull(er.UpLiftAccr,0.0)
                        when er.ListPosition > 6 and isnull(er.EnhancementAccr,0.0) <> 0 then er.EnhancementAccr
                        else isnull(er.Value2,0.0) * isnull(er.EnhancementRate,0.0) / 100
                       end,
 StillToAccr_Enhd    = case
                        when isnull(StillLeftToAccrue,0.0) <> 0 then StillLeftToAccrue
                        else isnull(er.Value3,0.0) * isnull(er.EnhancementRate,0.0) / 100
                       end,
 ITAdvanced_Enhd     = case
                        when er.ListPosition < 6 then isnull(Value4,0.0) + isnull(UpLiftIT,0.0)
                        when er.ListPosition > 6 and isnull(ITAdvance,0.0) <> 0 then ITAdvance
                        else isnull(Value4,0.0) * isnull(er.EnhancementRate,0.0) / 100
                       end,
 ITAccrued_Enhd      = case
                        when isnull(er.ITAccrued, 0.0) <> 0 then er.ITAccrued
                        else isnull(er.Value5, 0.0) * isnull(er.EnhancementRate,0.0) / 100
                       end,
 ITOutLiability_Enhd = case
                        when isnull(er.ITLiability, 0.0) <> 0 then er.ITLiability
                        else isnull(er.Value6, 0.0) * isnull(er.EnhancementRate,0.0) / 100
                       end,
 TotalPayment        = case
                        when er.ListPosition in (51,54,55) then isnull(er.TotalFees, 0.0)
                        else NULL
                       end,
 BusinessECode       = er.FranchisePrefix + er.FranchiseSerial + er.FranchiseSuffix,
 SellerECode         = er.SellerPrefix    + er.SellerSerial    + er.SellerSuffix,
 CreateDate      = DateLoaded,
  er.ProductCode,
 er.DeclarationDate
into
 #msit_ZANAdviserListing
from
 --msit_FeesNonSWIFTFeeListing s,
 mstt_Agents                 a,
 #EnhancementRate            er
where
 er.SwiftFranchise      = a.Code-- and
 --er.Id                  = er.Id  and
-- (er.OpenworkInd       is NULL   or
 -- er.OpenworkInd       <> 'Y')   and
-- er.ListPosition   not in (7,8)
-- and ((Month >= @LoadMidMonth
-- and ListPosition = 55)
-- or (Month >= @LoadEndMonth
-- and ListPosition in (0,1,2,3,6,51,54,100))) 

  exec msp_ProcessLog 'ZAL', 'Select Into 2', null, 'ZAL', 'Openwork'
 
 
create index ix_msit_zal1 on #msit_ZANAdviserListing (Month, ListPosition, Source)
 exec msp_ProcessLog 'ZAL', 'ix_msit_zal1', null, 'ZAL', 'Openwork'
 
create index ix_msit_zal2 on #msit_ZANAdviserListing (BusinessCode)
 exec msp_ProcessLog 'ZAL', 'ix_msit_zal2', null, 'ZAL', 'Openwork'
  
create index ix_msit_zal3 on #msit_ZANAdviserListing (BACSDate)
 exec msp_ProcessLog 'ZAL', 'ix_msit_zal3', null, 'ZAL', 'Openwork'
 
create index ix_msit_zal4 on #msit_ZANAdviserListing (Provider)
 exec msp_ProcessLog 'ZAL', 'ix_msit_zal4', null, 'ZAL', 'Openwork'

drop table #EnhancementRate
  
--UPDATE ProdType column. We do this update instead of the nested select in the insert above
--to assist performance.
update
 zal
set
 ProdType  = substring(lp.SWIFTProdType,1,8)
from
 #msit_ZANAdviserListing zal,
 msit_LegacyProducts lp
where
 zal.ProductCode           = lp.LegacyProdCode and
 zal.DeclarationDate between lp.StartDate      and lp.EndDate
 
 exec msp_ProcessLog 'ZAL', 'Update 1', null, 'ZAL', 'Openwork'  

-- UPDATE THE APE FIELD BASE ON THE VALUE CONTAINED WITHIN AGENT SPLIT
--update
-- #msit_ZANAdviserListing
--set
-- APE = APE * AgentSplit
--where ((Month >= @LoadMidMonth
-- and ListPosition = 55)
-- or (Month >= @LoadEndMonth
-- and ListPosition in (0,1,2,3,6,51,54,100))) 

--  exec msp_ProcessLog 'ZAL', 'Update 1', null, 'ZAL', 'Openwork'

-- UPDATE PROVIDER WITH THE PROVIDER NAME USING THE CODE DETERMINED IN THE PREVIOUS INSERT STATEMENT
update
 #msit_ZANAdviserListing
set
 Provider = pp.CommRepProductProviderName
from
 mstt_ProductProviders pp
where
 #msit_ZANAdviserListing.Provider = pp.CommRepProductProviderCode
--and ((Month >= @LoadMidMonth
-- and ListPosition = 55)
-- or (Month >= @LoadEndMonth
-- and ListPosition in (0,1,2,3,6,51,54,100))) 

  exec msp_ProcessLog 'ZAL', 'Update 2', null, 'ZAL', 'Openwork'

-- UPDATE TOTALPAYMENT FIELD
--update
-- msit_ZANAdviserListing
--set
-- TotalPayment = Accrued_Enhd + ITAdvanced_Enhd
--where
-- TotalPayment is NULL
-- and ((Month >= @LoadMidMonth
-- and ListPosition = 55)
-- or (Month >= @LoadEndMonth
-- and ListPosition in (0,1,2,3,6,51,54,100))) 

-- exec msp_ProcessLog 'ZAL', 'Update 3', null, 'ZAL', 'Openwork'

update
 #msit_ZANAdviserListing
set
 Premium             = round(Premium,2),
 APE                 = round(APE,2),
 CommRate            = round(CommRate,2),
 Sacrifice           = round(Sacrifice,2),
 AgentSplit          = round(AgentSplit,2),
 TotDue_Base         = round(TotDue_Base,2),
 Accrued_Base        = round(Accrued_Base,2),
 StillToAccr_Base    = round(StillToAccr_Base,2),
 ITAdvanced_Base     = round(ITAdvanced_Base,2),

 ITAccrued_Base      = round(ITAccrued_Base,2),
 ITOutLiability_Base = round(ITOutLiability_Base,2),
 EnhancementRate     = round(EnhancementRate,2),
 TotDue_Enhd         = round(TotDue_Enhd,2),
 Accrued_Enhd        = round(Accrued_Enhd,2),
 StillToAccr_Enhd    = round(StillToAccr_Enhd,2),
 ITAdvanced_Enhd     = round(ITAdvanced_Enhd,2),
 ITAccrued_Enhd      = round(ITAccrued_Enhd,2),
 ITOutLiability_Enhd = round(ITOutLiability_Enhd,2),
 TotalPayment        = round(isnull(TotalPayment, (Accrued_Enhd + ITAdvanced_Enhd)),2),
 ProdType            = isnull(ProdType, ProductCode)
--
-- where ((Month >= @LoadMidMonth
-- and ListPosition = 55)
-- or (Month >= @LoadEndMonth
-- and ListPosition in (0,1,2,3,6,51,54,100))) 

  exec msp_ProcessLog 'ZAL', 'Update 3 (Done)', null, 'ZAL', 'Openwork'
  
 --insert the rows into the table
insert into msit_ZANAdviserListing
select 
BusinessCode, BusinessName, SellerCode, SellerName, SellerForename, SellerSurname, Client, 
ClientForename, ClientSurname, BACSDate, Policy, ProdType, StartDate, PaymentDate, Frequency, 
Premium, APE, CommRate, InitialPeriod, PayBasis, Sacrifice, AgentSplit, FeeType, Remarks, 
Provider, ProviderCode, SourceID, ListPosition, Month, Source, TotDue_Base, Accrued_Base, 
StillToAccr_Base, ITAdvanced_Base, ITAccrued_Base, ITOutLiability_Base, EnhancementRate, 
TotDue_Enhd, Accrued_Enhd, StillToAccr_Enhd, ITAdvanced_Enhd, ITAccrued_Enhd, ITOutLiability_Enhd, 
TotalPayment, BusinessECode, SellerECode, CreateDate
from #msit_ZANAdviserListing

 exec msp_ProcessLog 'ZAL', 'Insert', null, 'ZAL', 'Openwork'

drop table #msit_ZANAdviserListing
  
end


GO
/****** Object:  StoredProcedure [dbo].[msp_ZANAdviserListing_Reload]    Script Date: 7/3/2026 3:44:25 PM ******/
