create procedure [dbo].[mspr_BankAccountSummary]
 @FranchiseCode nvarchar(20),
 @Month        datetime,
 @UserId    NVARCHAR(20)
as
--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : mspr_NSOrder.sql
-- Owner   : MWA
-- Created : 25/07/2006
--
--########################################################################

-- Select Openwork 2005 (Pre-Swift) entries
select
 BusinessCode   = BusinessCode,
 BusinessName   = BusinessName,
 BusinessECode  = BusinessECode,
 [Month]        = [Month],
 Source         = 'Openwork',
 Amount         = sum(Amount),
 OpeningBalance = case when TotalType = 0 then sum(Amount)
                       else 0.0
                  end,
 Debit          = case when TotalType = 1 then sum(Amount)
                       else 0.0
                  end,
 Credit         = case when TotalType = 2 then sum(Amount)
                       else 0.0
                  end,
 Payment        = case when TotalType = 3 then sum(Amount)
                       else 0.0
                  end,
 ClosingBalance = case when TotalType = 9 then sum(Amount)
                       else 0.0
                  end,
 TotalType      = TotalType,
 SWIFTCount     = 0,
 PreSWIFTCount  = Count(*),
 ZANCount       = 0
from
 msit_OpenworkBankDetails
where
 BusinessCode = @FranchiseCode and
 [Month] = @Month              and
 Source  = 'Openwork 2005'
group by
 BusinessCode,
 BusinessName,
 BusinessECode,
 [Month],
 Source,
 TotalType

union all

-- Select Openwork 2006 (Swift) entries
select
 BusinessCode   = BusinessCode,
 BusinessName   = BusinessName,
 BusinessECode  = BusinessECode,
 [Month]        = [Month],
 Source         = 'Openwork',
 Amount         = sum(Amount),
 OpeningBalance = case when TotalType = 0 then sum(Amount)
                       else 0.0
                  end,
 Debit          = case when TotalType = 1 then sum(Amount)
                       else 0.0
                  end,
 Credit         = case when TotalType = 2 then sum(Amount)
                       else 0.0
                  end,
 Payment        = case when TotalType = 3 then sum(Amount)
                       else 0.0
                  end,
 ClosingBalance = case when TotalType = 9 then sum(Amount)
                       else 0.0
                  end,
 TotalType      = TotalType,
 SWIFTCount     = Count(*),
 PreSWIFTCount  = 0,
 ZANCount       = 0
from
 msit_OpenworkBankDetails
where
 BusinessCode = @FranchiseCode and
 [Month] = @Month              and
 Source  = 'Openwork 2006'
group by
 BusinessCode,
 BusinessName,
 BusinessECode,
 [Month],
 Source,
 TotalType

union all

-- select ZAN entries
select
 BusinessCode   = BusinessCode,
 BusinessName   = BusinessName,
 BusinessECode  = BusinessECode,
 [Month]        = [Month],
 Source         = Source,
 Amount         = sum(Amount),
 OpeningBalance = case when TotalType = 0 then sum(Amount)
                       else 0.0
                  end,
 Debit          = case when TotalType = 1 then sum(Amount)
                       else 0.0
                  end,
 Credit         = case when TotalType = 2 then sum(Amount)
                       else 0.0
                  end,
 Payment        = case when TotalType = 3 then sum(Amount)
                       else 0.0
                  end,
 ClosingBalance = case when TotalType = 9 then sum(Amount)
                       else 0.0
                  end,
 TotalType      = TotalType,
 SWIFTCount     = 0,
 PreSWIFTCount  = 0,
 ZANCount       = Count(*)
from
 msit_ZANBankDetails
where
 BusinessCode = @FranchiseCode and
 [Month] = @Month
group by
 BusinessCode,
 BusinessName,
 BusinessECode,
 [Month],
 Source,
 TotalType


GO
