create procedure [dbo].[mspr_BankAccountSummaryFranchiseList]
 @UserId nvarchar(255),
 @Order  nvarchar(1)
as
--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : mspr_NSOrder.sql
-- Owner   : MWA
-- Created : 25/07/2006
--
--########################################################################

declare @FranchiseList table (FranchiseCode nvarchar(10))

insert into
 @FranchiseList
select distinct 
 a.FranchiseCode
from  
 msdt_Adviser a inner join msct_UserAccessControl uac 
    on a.AdviserID = uac.AdviserID
where
 uac.DomainLogin = @UserId


declare @BusinessList table (BusinessCode nvarchar(10), BusinessName nvarchar(255),Source NVARCHAR(50))


insert into
 @BusinessList
select distinct
 o.BusinessCode,
 o.BusinessName,
 o.Source
from
 msit_OpenworkBankDetails o,
 @FranchiseList           fr
where
 o.BusinessCode collate Database_Default = fr.FranchiseCode
union all
select distinct
 z.BusinessCode,
 z.BusinessName,
 z.Source
from
 msit_ZANBankDetails z,
 @FranchiseList      fr
where
 z.BusinessCode collate Database_Default = fr.FranchiseCode
Union All
select distinct
 o.BusinessCode,
 o.BusinessName,
 o.Source
from
 mstt_StatementsFranchiseList o,
 @FranchiseList           fr
where
 o.BusinessCode collate Database_Default = fr.FranchiseCode
order by 1


select distinct
 Value = BusinessCode,
 Label = case when @Order = '1' then BusinessCode + ' - ' + rtrim(BusinessName)
              else rtrim(BusinessName) + ' - ' + BusinessCode 
         end,
 Source = '%'
from
 @BusinessList
order by
 2 asc




