 left(a.[CommFeeType],10) [FeeType],
 a.[CommReason] [Reason],
 a.[BACSDate],
 a.[PaymentStatus] [Status],
 a.[EXIssued],
 a.[EXAccrued],
 a.[EXStillToAccrue],
 a.[EXIndemnity],
 a.[INIssued],
 a.[INAccrued],
