CREATE procedure [dbo].[mspr_CurrentPeriodDownload]
 @FranchiseCode nvarchar(20)
as
--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : mspr_CurrentPeriodDownload.sql
-- Owner   : MWA
-- Created : 25/07/2006
--
--       14/02/2007  - RH/OW - Tuned for performance as part of Agent KPI report production issue
--         - Fixes to affected procs/fns include explicit conversion of datatypes in query
--           expressions where parameter type is not matched to table data type
--           allowing Index seeks rather than scans
--         - Addition of indexes to required Quality tables
--         - Explicit alternative logic paths for queries where global parameter (eg Filter) is not supplied
--           avoiding table/index scans forced by unnecessary OR statememnts
--########################################################################

declare 
 @CurrentPeriod datetime

select
 CurrentPeriod = case when max([Month]) not in (select distinct [Month] from msit_OpenworkAdviserListing where BusinessCode = convert(varchar(7),@FranchiseCode)) 
                      then (select max([Month]) from msit_OpenworkAdviserListing where BusinessCode = convert(varchar(7),@FranchiseCode))
                      else max([Month])
                 end
from 
 msit_CommissionStatementPeriods
where
 PeriodEndDate <= getdate()

GO
