CREATE procedure [dbo].[mspr_DefComSta]
@UserId nvarchar(255)
with recompile
as

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : mspr_DefComSta.sql
-- Owner   : CTT
-- Created : 26/10/2005
--
--
-- Amended : 08/07/2009 - MPC: Replace *= ANSI JOINS as these not allowed in SQL Server 2005
--
--########################################################################

set dateformat dmy

SELECT DISTINCT a.FranchiseCode
into
 #Franchise
FROM  msdt_Adviser a 
  INNER JOIN msct_UserAccessControl uac 
    ON a.AdviserID = uac.AdviserID
WHERE uac.DomainLogin = @UserId


select
 'Charges' [ReportingClassDesc]
into
 #Category
union
select
 'General Insurance'
union
select
 'Manual Adjustments'
union
select
 'Mortgages'
union
select
 'Other Providers'
union
select
 'Scottish Equitable'
union
select
 'Sterling'
union
select
 'Zurich'
--union
--select
-- 'Zurich Renewals'
union
select
 'Payments To Bank'

select
 CS.ReportingClassDesc [Category],
 sum(case when CS.DebitCredit = 'D' then ABS(CS.Amount)  else '0' end) [Debit],
 sum(case when CS.DebitCredit = 'C' then CS.Amount else '0' end) [Credit]
into
 #DefComSta
from
 msit_CommissionStatement CS,
 mst_BACSDate BD,
 #Franchise FR
where
 CS.BusinessCode = BD.FranchiseCode and
 CS.BACSDate = BD.LastBACSDate and
 CS.BusinessCode = FR.FranchiseCode
group by
 CS.ReportingClassDesc

select
 case when CA.ReportingClassDesc = 'Payments To Bank' then 'zzPayments To Bank' else CA.ReportingClassDesc end [Category],
 DC.Debit,
 DC.Credit
from
 #Category CA                 --MPC: 08/07/2009
 left outer join #DefComSta DC          --MPC: 08/07/2009
  on CA.ReportingClassDesc = DC.Category    --MPC: 08/07/2009
--where                     --MPC: 08/07/2009
-- CA.ReportingClassDesc *= DC.Category     --MPC: 08/07/2009
order by
 1 
 
drop table #Category
drop table #DefComSta



GO
