create procedure [dbo].[mspr_DefComStaAdv]
@UserId nvarchar(255)
with recompile
as

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : mspr_DefComStaAdv.sql
-- Owner   : CTT
-- Created : 26/10/2005
--
--########################################################################

set dateformat dmy

SELECT DISTINCT a.FranchiseCode
into
 #Franchise
FROM  msdt_Adviser a 
  INNER JOIN msct_UserAccessControl uac 
    ON a.AdviserID = uac.AdviserID
WHERE uac.DomainLogin = @UserId

select
 rtrim(CS.[FranchiseName]) [FranchiseName],
 CS.[CommProviderDesc],
 CS.[AgentCode],
 rtrim(CS.[SellerName]) [SellerName],
 convert(nvarchar(10),CS.[PaymentDate],3) [Payment_Date],
 convert(nvarchar(10),CS.[BACSDate],3) [BACS_Date],
 rtrim(upper(left(CS.[ClientSurname],1))+ lower(substring(CS.[ClientSurname],2,19)) + ' ' + upper(left(CS.[ClientForenames],1))) [ClientName],
 CS.[ExtPolicyNumber] [PolicyNumber],
 CS.[ProductCode] [Product],
 convert(nvarchar(10),CS.[StartDate],3) [StartDate],
 left(CS.[FrequencyDesc],1) [Frequency],
 CS.[Premium] [Premium],
 case when convert(nvarchar,CS.[CommissionRate]) = '0' then '' else convert(nvarchar,CS.[CommissionRate]) end [CommissionRate],
 case when convert(nvarchar,CS.[InitialPeriod]) = '0' then '' else convert(nvarchar,CS.[InitialPeriod]) end [InitialPeriod],
 CS.[FranchiseUpliftRate] [EnhancedRate],
 left(CS.[PayBasisDesc],10) [PaymentBasisCommission],
 case when convert(nvarchar,CS.[CommSacrificeAmt]) = '0' then '' else convert(nvarchar,CS.[CommSacrificeAmt]) end [CommSacrificeAmt],
 CS.[AgentSplit],
 left(CS.[CommFeeType],10) [FeeType],
 left(CS.[CommReason],10) [Reason],
 CS.[BACSDate],
 CS.[PaymentStatus] [Status],
 CS.[EXIssued],
 CS.[EXAccrued],
 case when CS.[EXStillToAccrue] < 0 then 0 else CS.[EXStillToAccrue] end [EXStillToAccrue],
 CS.[EXIndemnity],
 CS.[INIssued],
 CS.[INAccrued],
 case when CS.[INStillToAccrue] < 0 then 0 else CS.[INStillToAccrue] end [INStillToAccrue],
 CS.[INIndemnity],
 CS.[INAccrued] + CS.[INIndemnity] [TotalPayment],
 CS.[DistributorRef]
from
 msit_CommissionStatement CS,
 mst_BACSDate BD,
 #Franchise FR
where
 CS.BusinessCode = BD.FranchiseCode and
 CS.BACSDate = BD.LastBACSDate and
 CS.ReportingClassCode = '1' and
 CS.BusinessCode = FR.FranchiseCode
order by
 rtrim(CS.[SellerName]),
 CS.[CommProviderDesc],
 rtrim(upper(left(CS.[ClientSurname],1))+ lower(substring(CS.[ClientSurname],2,19)) + ' ' + upper(left(CS.[ClientForenames],1))),
 CS.[ExtPolicyNumber],
 CS.[ExpectationId],
 CS.[BACSDate],
 CS.[PaymentDate] 


GO
