create procedure [dbo].[mspr_DefComStaAdvDownLoadEnq]
@Franchise nvarchar(255)
with recompile
as

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : mspr_DefComStaAdvDownLoadEnq.sql
-- Owner   : CTT
-- Created : 30/05/2006
--
--########################################################################

set dateformat dmy

select
 rtrim(CS.[FranchiseName]) [FranchiseName],
 CS.[CommProviderDesc],
 CS.[AgentCode],
 rtrim(AG.[Name]) [AdviserSurname],
 [AdviserForename] = case when charindex(' ',FirstNames) >0 then left(FirstNames, charindex(' ',FirstNames))
 else rtrim(AG.[FirstNames]) end,
 convert(nvarchar(12),CS.[PaymentDate],103) [Payment_Date],
 convert(nvarchar(12),CS.[BACSDate],103) [BACS_Date],
 rtrim(upper(left(CS.[ClientSurname],1))+ lower(substring(CS.[ClientSurname],2,19))) [Client Surname],
 rtrim(CS.[ClientForenames]) [ClientForename],
 CS.[ExtPolicyNumber] [PolicyNumber],
 PO.[PolicyRef],
 CS.[ProductCode] [Product],
 convert(nvarchar(12),CS.[StartDate],103) [StartDate],
 left(CS.[FrequencyDesc],1) [Frequency],
 CS.[Premium] [Premium],
 case when convert(nvarchar,CS.[CommissionRate]) = '0' then 0 else CS.[CommissionRate] END [CommissionRate],
 case when convert(nvarchar,CS.[InitialPeriod]) = '0' then 0 else CS.[InitialPeriod] end [InitialPeriod],
 isnull(CS.[FranchiseUpliftRate],0) [EnhancedRate],
 left(CS.[PayBasisDesc],10) [PaymentBasisCommission],
 case when isnull(convert(nvarchar,CS.[CommSacrificeAmt]),'0') = '0' then convert(decimal(8,2),'0.00') else convert(decimal(8,2),CS.[CommSacrificeAmt]) end [CommSacrificeAmt],
 isnull(CS.[AgentSplit],0) [AgentSplit],
 left(CS.[CommFeeType],10) [FeeType],
 left(CS.[CommReason],10) [Reason],
 CS.[BACSDate],
 CS.[PaymentStatus] [Status],
 isnull(convert(decimal(8,2),CS.[EXIssued]),0) [EXIssued],
 isnull(convert(decimal(8,2),CS.[EXAccrued]),0) [EXAccrued],
 convert(decimal(8,2),case when CS.[EXStillToAccrue] < 0 then 0 else CS.[EXStillToAccrue] end) [EXStillToAccrue],
 isnull(convert(decimal(8,2),CS.[EXIndemnity]),0)[EXIndemnity],
 isnull(convert(decimal(8,2),CS.[INIssued]),0)[INIssued],
 isnull(convert(decimal(8,2),CS.[INAccrued]),0)[INAccrued],
 convert(decimal(8,2),case when CS.[INStillToAccrue] < 0 then 0 else CS.[INStillToAccrue] end) [INStillToAccrue],
 isnull(convert(decimal(8,2),CS.[INIndemnity]),0)[INIndemnity],
 isnull(convert(decimal(8,2),CS.[INAccrued] + CS.[INIndemnity]),0) [TotalPayment],
 'Swift' [DataSource],
 CS.[DistributorRef]
from
 msit_CommissionStatement CS,
 mst_BACSDate BD,
 mstt_Agents AG,
 mstt_Policies PO
where
 CS.BusinessCode = BD.FranchiseCode and
 CS.BACSDate = BD.LastBACSDate and
 CS.AgentCode = AG.Code and
 CS.PolicyID = PO.Pol_num and
 CS.ReportingClassCode = '1' and
 CS.BusinessCode = @Franchise
order by
 rtrim(AG.[FirstNames]),
 rtrim(AG.[Name]),
 CS.[CommProviderDesc],
 rtrim(CS.[ClientSurname]),
 rtrim(CS.[ClientForenames]),
 CS.[ExtPolicyNumber],
 CS.[ExpectationId],
 CS.[BACSDate],
 CS.[PaymentDate]


GO
