create procedure [dbo].[mspr_DefComStaRepOpt]
@UserId nvarchar(255)
as

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : mspr_DefComStaRepOpt.sql
-- Owner   : CTT
-- Created : 02/12/2005
--
--########################################################################

set dateformat dmy

SELECT DISTINCT a.FranchiseCode
into
 #Franchise
FROM  msdt_Adviser a 
  INNER JOIN msct_UserAccessControl uac 
    ON a.AdviserID = uac.AdviserID
WHERE uac.DomainLogin = @UserId

select distinct
 case 
 when CS.ReportingClassDesc not in ('Charges','Manual Adjustments','Payments To Bank') then
 'Provider Listing' else CS.ReportingClassDesc end [Name],
  case 
 when CS.ReportingClassDesc not in ('Charges','Manual Adjustments','Payments To Bank') then
 '150' else '100' end [Zoom]
from
 msit_CommissionStatement CS,
 mst_BACSDate BD,
 #Franchise FR
where
 CS.BusinessCode = BD.FranchiseCode and
 CS.BACSDate = BD.LastBACSDate and
 CS.BusinessCode = FR.FranchiseCode
union
select distinct
 case 
 when CS.ReportingClassDesc not in ('Charges','Manual Adjustments','Payments To Bank') then
 'Adviser Listing' else CS.ReportingClassDesc end,
 case 
 when CS.ReportingClassDesc not in ('Charges','Manual Adjustments','Payments To Bank') then
 '150' else '100' end
from
 msit_CommissionStatement CS,
 mst_BACSDate BD,
 #Franchise FR
where
 CS.BusinessCode = BD.FranchiseCode and
 CS.BACSDate = BD.LastBACSDate and
 CS.BusinessCode = FR.FranchiseCode
 
drop table 
#Franchise


GO
