--
-- Object  : procedure
-- Name    : mspr_DefComStaRepTyp.sql
-- Owner   : CTT
-- Created : 26/10/2005
--
--########################################################################

set dateformat dmy


SELECT DISTINCT a.FranchiseCode
into
 #Franchise
FROM  msdt_Adviser a 
  INNER JOIN msct_UserAccessControl uac 
    ON a.AdviserID = uac.AdviserID
WHERE uac.DomainLogin = @UserId

select distinct
 case 
 when CS.ReportingClassDesc not in ('Charges','Manual Adjustments','Payments To Bank') then
 'Provider Listing' else CS.ReportingClassDesc end [RepName]
into #DefComStaRepOpt
from
 msit_CommissionStatement CS,
 mst_BACSDate BD,
 #Franchise FR
where
 CS.BusinessCode = BD.FranchiseCode and
 CS.BACSDate = BD.LastBACSDate and
 CS.BusinessCode = FR.FranchiseCode
union
select distinct
 case 
 when CS.ReportingClassDesc not in ('Charges','Manual Adjustments','Payments To Bank') then
 'Adviser Listing' else CS.ReportingClassDesc end
from
 msit_CommissionStatement CS,
 mst_BACSDate BD,
 #Franchise FR
where
 CS.BusinessCode = BD.FranchiseCode and
 CS.BACSDate = BD.LastBACSDate and
 CS.BusinessCode = FR.FranchiseCode
 
select distinct
a.[Name],
a.[View],
a.[ReportId]
from
mst_DefComStaRepOpt a,
#DefComStaRepOpt RO
where
a.[Name] = RO.[RepName] and
substring(a.[ReportId],46,3) = 'Def'
ORDER BY a.[View] DESC
drop table #DefComStaRepOpt
