CREATE PROCEDURE [dbo].[mspr_DeriveUpLiftFactors]

AS


DECLARE @TempAgentTable TABLE
(
MAIN_SERIAL nvarchar (5) COLLATE latin1_General_CI_AS PRIMARY KEY,
UPLIFT_RATE float (8)
)

INSERT INTO @TempAgentTable
SELECT msit_AgentInfo.MAIN_SERIAL,msit_AgentInfo.UPLIFT_RATE
FROM msit_AgentInfo
WHERE msit_AgentInfo.UPLIFT_APPLIES = 'Y'



UPDATE msit_NSLaboris
SET msit_NSLaboris.UpliftRate = (a.UPLIFT_RATE - (1)),
msit_NSLaboris.UpliftAccr = CASE msit_NSLaboris.ProdCred WHEN  1 THEN ((a.UPLIFT_RATE - (1)) * ((msit_NSLaboris.Value2))) END,
msit_NSLaboris.UpliftIT = CASE msit_NSLaboris.ProdCred WHEN  1 THEN ((a.UPLIFT_RATE - (1)) * ((msit_NSLaboris.Value4))) END
FROM @TempAgentTable a
WHERE msit_NSLaboris.FranchiseSerial = a.MAIN_SERIAL

GO
