msit_NSLaboris_Reload.UpliftAccr = CASE msit_NSLaboris_Reload.ProdCred WHEN  1 THEN ((a.UPLIFT_RATE - (1)) * (msit_NSLaboris_Reload.Value2)) END,
msit_NSLaboris_Reload.UpliftIT = CASE msit_NSLaboris_Reload.ProdCred WHEN  1 THEN ((a.UPLIFT_RATE - (1)) * (msit_NSLaboris_Reload.Value4)) END
FROM @TempAgentTable a
WHERE msit_NSLaboris_Reload.FranchiseSerial = a.MAIN_SERIAL

