CREATE procedure [dbo].[mspr_EnqComSta]
@FranchiseCode nvarchar(15),
@SellerName nvarchar(225),
@Period nvarchar(15),
@Period1 datetime,
@Period2 datetime
with recompile
as

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : mspr_EnqComSta.sql
-- Owner   : CTT
-- Created : 26/10/2005
--
--
-- Amended : 07/07/2009 - MPC: Replace *= ANSI JOINS as these not allowed in SQL Server 2005
--
--########################################################################

set dateformat dmy

select
 'Charges' [ReportingClassDesc]
into
 #Category2
union
select
 'General Insurance'
union
select
 'Manual Adjustments'
union
select
 'Mortgages'
union
select
 'Other Providers'
union
select
 'Scottish Equitable'
union
select
 'Sterling'
union
select
 'Zurich'
--union
--select
-- 'Zurich Renewals'
union
select
 'Payments To Bank'

------------------- 

select
 CS.ReportingClassDesc [Category],
 sum(case when CS.DebitCredit = 'D' then ABS(CS.Amount) else '0' end) [Debit],
 sum(case when CS.DebitCredit = 'C' then CS.Amount else '0' end) [Credit]
into #EnqComSta
from
 msit_CommissionStatement CS
where
 CS.BusinessCode = @FranchiseCode and
 rtrim(CS.AgentCode) like right(@SellerName,7) and
 case
 when @Period = 'BACS' then CS.BACSDate
 else CS.PaymentDate
 end between @Period1 and @Period2
group by
 CS.ReportingClassDesc

-----------------------

select
 min(BACSDate) Date
into
 #OBDate
from
 msit_CommissionStatement
where
 BusinessCode = @FranchiseCode and
 convert(datetime,@Period1,102) <= BACSDate

select
 'NO OBD' [Type],
 ' Opening Balance' [Description],
 sum(case when CS.DebitCredit = 'D' then CS.Amount * (-1) else '0' end) [Debit],
 sum(case when CS.DebitCredit = 'C' then CS.Amount else '0' end) [Credit]
into
 #OBDate2
from
 msit_CommissionStatement CS
where
 CS.BusinessCode = @FranchiseCode and
 rtrim(CS.AgentCode) like right(@SellerName,7) and
 CS.PaymentDate < @Period1 and
 CS.BACSDate = '1901-01-01'
union
select
 'HAS OBD' Type,
 ' Opening Balance',
 sum(case when CS.DebitCredit = 'D' then CS.Amount * (-1) else '0' end) [Debit],
 sum(case when CS.DebitCredit = 'C' then CS.Amount else '0' end) [Credit]
from
 msit_CommissionStatement CS,
 #OBDate OBD
where
 CS.BusinessCode = @FranchiseCode and
 rtrim(CS.AgentCode) like right(@SellerName,7) and
 CS.PaymentDate < @Period1 and
 CS.BACSDate = OBD.Date
order by
 1

--------------------------

select
 case when CA.ReportingClassDesc = 'Payments To Bank' then 'zzPayments To Bank' else CA.ReportingClassDesc end [Category],
 DC.Debit,
 DC.Credit
from
 #Category2 CA                  --MPC: 07/07/2009
 left outer join #EnqComSta DC          --MPC: 07/07/2009
  on CA.ReportingClassDesc = DC.Category    --MPC: 07/07/2009
-- where                    --MPC: 07/07/2009
-- CA.ReportingClassDesc *= DC.Category     --MPC: 07/07/2009
union
select
 OBD2.Description,
 case when OBD2.Debit - OBD2.Credit >= 0 then OBD2.Debit - OBD2.Credit else '' end Debit,
 case when OBD2.Credit - OBD2.Debit > 0 then OBD2.Credit - OBD2.Debit else '' end Credit
from
 #OBDate2 OBD2,
 #OBdate OBD
where
 case when OBD.[Date] >= '2006-01-01' then 'HAS OBD' else 'NO OBD' end = OBD2.Type

drop table #OBDate2
drop table #OBDate
drop table #Category2
drop table #EnqComSta



GO
