create procedure [dbo].[mspr_EnqComStaFra]
@UserId nvarchar(255),
@Order nvarchar(1)
as
--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : mspr_EnqComStaFra.sql
-- Owner   : CTT
-- Created : 26/10/2005
--
--########################################################################
set dateformat dmy
SELECT DISTINCT a.FranchiseCode
into
 #Franchise
FROM  msdt_Adviser a 
  INNER JOIN msct_UserAccessControl uac 
    ON a.AdviserID = uac.AdviserID
WHERE uac.DomainLogin = @UserId
select distinct
 CS.BusinessCode [Value],
 case when @Order = '1' then CS.BusinessCode + ' - ' + rtrim(CS.FranchiseName)
      else rtrim(CS.FranchiseName) + ' - ' + CS.BusinessCode end [Label]
from
 msit_CommissionStatement CS,
 #Franchise FR
where
 CS.BusinessCode = FR.FranchiseCode
order by
 2 asc

