create procedure [dbo].[mspr_EnqComStaRepOpt]
@FranchiseCode nvarchar(15),
@SellerName nvarchar(255),
@Period nvarchar(15),
@Period1 datetime,
@Period2 datetime

as

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : mspr_EnqComStaRepOpt.sql
-- Owner   : CTT
-- Created : 03/11/2005
--
--########################################################################

select distinct
 case 
 when CS.ReportingClassDesc not in ('Charges','Manual Adjustments','Payments To Bank') then
 'Adviser Listing' else CS.ReportingClassDesc end [Name],
 case 
 when CS.ReportingClassDesc not in ('Charges','Manual Adjustments','Payments To Bank') then
 '150' else '100' end [Zoom]
from
 msit_CommissionStatement CS
where
 CS.BusinessCode = @FranchiseCode and
 rtrim(CS.AgentCode) like right(@SellerName,7) and
 case
 when @Period = 'BACS' then CS.BACSDate
 else CS.PaymentDate
 end between @Period1 and @Period2 and
 len(CS.ReportingClassDesc) <> '0'
union
select distinct
 case 
 when CS.ReportingClassDesc not in ('Charges','Manual Adjustments','Payments To Bank') then
 'Provider Listing' else CS.ReportingClassDesc end,
 case 
 when CS.ReportingClassDesc not in ('Charges','Manual Adjustments','Payments To Bank') then
 '150' else '100' end
from
 msit_CommissionStatement CS
where
 CS.BusinessCode = @FranchiseCode and
 rtrim(CS.AgentCode) like right(@SellerName,7) and
 case
 when @Period = 'BACS' then CS.BACSDate
 else CS.PaymentDate
 end between @Period1 and @Period2 and
 len(CS.ReportingClassDesc) <> '0'
 

GO
/****** Object:  StoredProcedure [dbo].[mspr_EnqComStaRepTyp]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

create procedure [dbo].[mspr_EnqComStaRepTyp]
@FranchiseCode nvarchar(15),
@SellerName nvarchar(255),
@Period nvarchar(15),
@Period1 datetime,
@Period2 datetime
with recompile
as

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : mspr_EnqComStaRepTyp.sql
-- Owner   : CTT
-- Created : 03/11/2005
--
--########################################################################

set dateformat dmy

select distinct
 case 
 when CS.ReportingClassDesc not in ('Charges','Manual Adjustments','Payments To Bank') then
 'Adviser Listing' else CS.ReportingClassDesc end [Name]
into
 #EnqComStaRepTyp
from
 msit_CommissionStatement CS
where
 CS.BusinessCode = @FranchiseCode and
 rtrim(CS.AgentCode) like right(@SellerName,7) and
 case
 when @Period = 'BACS' then CS.BACSDate
 else CS.PaymentDate
 end between @Period1 and @Period2
union
select distinct
 case 
 when CS.ReportingClassDesc not in ('Charges','Manual Adjustments','Payments To Bank') then
 'Provider Listing' else CS.ReportingClassDesc end
from
 msit_CommissionStatement CS
where
 CS.BusinessCode = @FranchiseCode and
 rtrim(CS.AgentCode) like right(@SellerName,7) and
 case
 when @Period = 'BACS' then CS.BACSDate
 else CS.PaymentDate
 end between @Period1 and @Period2
 
 select distinct
a.[Name],
a.[View],
a.[ReportId]
from
mst_DefComStaRepOpt a,
#EnqComStaRepTyp RO
where
a.[Name] = RO.[Name] and
substring(a.[ReportId],46,3) = 'Enq'
ORDER BY a.[View] DESC
drop table #EnqComStaRepTyp
 

GO
