Date		Who			Description				
----		---			-----------			
14/03/2018	A Groves	SR503642/CH20916. Previously "Client" was being set to NULL where the
						client's firstname/initials are null. ISNULL has been added so the 
						surname will always be retained in this scenario.
************************************************************************************************/

CREATE PROCEDURE [dbo].[mspr_FeeListings_Main_Scot_Eq_To_Laboris]
	@Client		varchar(50),
	@Module		Varchar(50)
AS

set nocount on

declare		@PhaseStart								varchar(50),
			@PhaseEnd								varchar(50),
			@PhaseLog								varchar(50),
			@PhaseError								varchar(50),
			@Message								varchar(100),
			@ProcName								varchar(100),
			@RowCount								int,
			@DateLoaded								datetime = getdate()
			
/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @ProcName			= object_name(@@procid)
set @PhaseStart			= 'START'
set @PhaseEnd   		= 'END'
set @PhaseLog			= 'LOG'
set @PhaseError			= 'ERROR'

exec msp_ProcessLog @PhaseStart, @ProcName, null, @Module, @Client

/****************************************************************************

	Insert table data

****************************************************************************/

--Note: Table dbo.msit_NSLaboris is truncated by the SSIS script because there 
--are three procs that populate the table.

insert into dbo.msit_NSLaboris
(
	SWIFTFranchise,
	SWIFTSeller,
	OpenworkInd,
	SellerPrefix,
	SellerSerial,
	SellerSuffix,
	SellerID,
	SellerName,
	FranchisePrefix,
	FranchiseSerial,
	FranchiseSuffix,
	FranchiseID,
	ClientForename,
	ClientSurname,
	Client,
	ApplicationDate,
	DeclarationDate,
	StartDate,
	RunDate,
	OrigBranch,
	PolicySerial,
	Member,
	ProductCode,
	Policy,
	Provider,
	SequenceNo,
	SliceNo,
	AgentSplit,
	Premium,
	Frequency,
	IncreaseInd,
	FlexInd,
	InitialPeriod,
	CommRateStd,
	CommRateTrue,
	NPWInd,
	ITInd,
	CommType,
	CommBasis,
	CommBasisDesc,
	EnhancementRate,
	EnhancementAccr,
	StillLeftToAccrue,
	ITAdvance,
	ITAccrued,
	ITLiability,
	UpliftFeeAccr,
	UpliftFeeIT,
	Value1,
	Value2,
	Value3,
	Value4,
	Value5,
	Value6,
	RemarksString,
	ProdFactor,
	ProdCred,
	PayBasis,
	TotalFees,
	IssuedInd,
	CommEnh,
	TotBaseCommStd,
	TotBaseCommTrue,
	CommNotEnhanced,
	UpliftRate,
	UpliftAccr,
	UpliftIT,
	FileID,
	ListPosition,
	DateLoaded,
	Month,
	Source,
	RemarkCode1,
	RemarksData1,
	RemarkCode2,
	RemarksData2,
	RemarkCode3,
	RemarksData3,
	RemarkCode4,
	RemarksData4,
	RemarkCode5,
	RemarksData5,
	RemarkCode6,
	RemarksData6,
	--BACSDate,		This column is populated by a default setting on the table.
	BIRemarks
)
select 	null as SWIFTFranchise,
		null as SWIFTSeller,
		'Y' as OpenworkInd,
		SELLER_PREFIX as SellerPrefix,
		SELLER_SERIAL as SellerSerial,
		SELLER_SUFFIX as SellerSuffix,
		SELLER_ID as SellerID,
		null as SellerName,
		HOST_PREFIX as FranchisePrefix,
		HOST_SERIAL as FranchiseSerial,
		HOST_SUFFIX as FranchiseSuffix,
		HOST_ID as FranchiseID,
		CLIENT_FORENAME as ClientForename,
		CLIENT_SURNAME as ClientSurname,
		isnull(CLIENT_SURNAME,'') + ' ' + isnull(CLIENT_FORENAME,'') as Client,	--AG 14/03/2018
		null as ApplicationDate,
		DEC_DATE as DeclarationDate,
		COMM_DATE as StartDate,
		RUN_DATE as RunDate,
		null as OrigBranch,
		left(POLICY_NO,6) as PolicySerial,	--The old DTS script only took the first 6 characters, so this gives the same behaviour.
		null as Member,
		PRODUCT_CODE as ProductCode,
		POLICY_NO as Policy,
		PRODUCT_PROVIDER as Provider,
		SEQUENCE_NO as SequenceNo,
		NULL as SliceNo,
		AGT_SPLIT as AgentSplit,
		isnull(SINGLE_CONT,0.0) + isnull(REGULAR_CONT,0.0) as Premium,
		FREQ as Frequency,
		null as IncreaseInd,
		case when FLEX > 0 then 'Y' else 'N' end as FlexInd,
		null as InitialPeriod,
		isnull(BASE_RATE_SINGLE,0.0) + isnull(BASE_RATE_REG,0.0) as CommRateStd,
		case when FLEX > (isnull(BASE_RATE_SINGLE,0.0) + isnull(BASE_RATE_REG,0.0))
			then isnull(BASE_RATE_SINGLE,0.0) + isnull(BASE_RATE_REG,0.0) - isnull(FLEX,0.0)
			else 0
		end as CommRateTrue,
		null as NPWInd,
		null as ITInd,
		TYPE as CommType,
		BENEFIT_ID as CommBasis,
		BENEFIT_ID_DESC as CommBasisDesc,
		ENHANCEMENT_FACTOR * 100.0 as EnhancementRate,
		COMM_ENHANCED as EnhancementAccr,
		null as StillLeftToAccrue,
		null as ITAdvance,
		null as ITAccrued,
		null as ITLiability,
		null as UpliftFeeAccr,
		null as UpliftFeeIT,
		null as Value1,
		null as Value2,
		null as Value3,
		null as Value4,
		null as Value5,
		null as Value6,
		REMARKS as RemarksString,
		null as ProdFactor,
		null as ProdCred,
		left(PAY_BASIS,1) as PayBasis,	--The old DTS script only took the first character, so this gives the same behaviour.
										--"A"=Accrual; "I"=Indemnity Terms; "O"=Other
		TOT_FEES as TotalFees,
		FIRST_PAY_MKR as IssuedInd,
		ENHANCED_COMM as CommEnh,
		TOT_BASE_COMM_STD as TotBaseCommStd,
		TOT_BASE_COMM_TRUE as TotBaseCommTrue,
		COMM_NOT_ENHANCED as CommNotEnhanced,
		null as UpliftRate,
		null as UpliftAccr,
		null as UpliftIT,
		FILE_ID as FileID,
		case when FILE_ID in (2,3) then 55 else 50 + FILE_ID end as ListPosition,
		@DateLoaded	as DateLoaded,
		Period as Month,
		'ScottEq' as Source,
		null as RemarkCode1,
		null as RemarksData1,
		null as RemarkCode2,
		null as RemarksData2,
		null as RemarkCode3,
		null as RemarksData3,
		null as RemarkCode4,
		null as RemarksData4,
		null as RemarkCode5,
		null as RemarksData5,
		null as RemarkCode6,
		null as RemarksData6,
		--null as BACSDate,		This column is populated by a default setting on the table.
		null as BIRemarks
from	msit_FeeListings_Main_Scott_Eq


/****************************************************************************

			E N D															

****************************************************************************/

exec msp_ProcessLog @PhaseEnd, @ProcName, null, @Module, @Client

GO
