14/03/2018	A Groves	SR503642/CH20916. Previously "Client" was being set to NULL where the
						client's firstname/initials are null. ISNULL has been added so the 
						surname will always be retained in this scenario.
************************************************************************************************/

CREATE PROCEDURE [dbo].[mspr_FeeListings_Main_To_Laboris]
	@Client		varchar(50),
	@Module		Varchar(50)
AS

set nocount on

declare		@PhaseStart								varchar(50),
			@PhaseEnd								varchar(50),
			@PhaseLog								varchar(50),
			@PhaseError								varchar(50),
			@Message								varchar(100),
			@ProcName								varchar(100),
			@RowCount								int,
			@DateLoaded								datetime = getdate()
			
/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @ProcName			= object_name(@@procid)
set @PhaseStart			= 'START'
set @PhaseEnd   		= 'END'
set @PhaseLog			= 'LOG'
set @PhaseError			= 'ERROR'

exec msp_ProcessLog @PhaseStart, @ProcName, null, @Module, @Client

/****************************************************************************

	Insert table data

****************************************************************************/

--Note: Table dbo.msit_NSLaboris is truncated by the SSIS script because there 
--are three procs that populate the table.

insert into dbo.msit_NSLaboris
(
	SWIFTFranchise,
	SWIFTSeller,
	OpenworkInd,
	SellerPrefix,
	SellerSerial,
	SellerSuffix,
	SellerID,
	SellerName,
	FranchisePrefix,
	FranchiseSerial,
	FranchiseSuffix,
	FranchiseID,
	ClientForename,
	ClientSurname,
	Client,
	ApplicationDate,
	DeclarationDate,
	StartDate,
	RunDate,
	OrigBranch,
	PolicySerial,
	Member,
	ProductCode,
	Policy,
	Provider,
	SequenceNo,
	SliceNo,
	AgentSplit,
	Premium,
	Frequency,
	IncreaseInd,
	FlexInd,
	InitialPeriod,
	CommRateStd,
	CommRateTrue,
	NPWInd,
	ITInd,
	CommType,
	CommBasis,
	CommBasisDesc,
	EnhancementRate,
	EnhancementAccr,
	StillLeftToAccrue,
	ITAdvance,
	ITAccrued,
	ITLiability,
	UpliftFeeAccr,
	UpliftFeeIT,
	Value1,
	Value2,
	Value3,
	Value4,
	Value5,
	Value6,
	RemarksString,
	ProdFactor,
	ProdCred,
	PayBasis,
	TotalFees,
	IssuedInd,
	CommEnh,
	TotBaseCommStd,
	TotBaseCommTrue,
	CommNotEnhanced,
	UpliftRate,
	UpliftAccr,
	UpliftIT,
	FileID,
	ListPosition,
