	RemarkCode5,
	RemarksData5,
	RemarkCode6,
	RemarksData6,
	--BACSDate,		This column is populated by a default setting on the table.
	BIRemarks
)
select 	null as SWIFTFranchise,
		null as SWIFTSeller,
		case
			when LIST_POSITION_IND = 6 then 'Y'
			when Openwork_Ind = '' then 'N'
			else Openwork_Ind
		end as OpenworkInd,
		null as SellerPrefix,
		SELLER_SERIAL as SellerSerial,
		null as SellerSuffix,
		null as SellerID,
		null as SellerName,
		MAIN_PREFIX as FranchisePrefix,
		MAIN_SERIAL as FranchiseSerial,
		MAIN_SUFFIX as FranchiseSuffix,
		null as FranchiseID,
		CLIENT_FORENAME as ClientForename,
		CLIENT_SURNAME as ClientSurname,
		isnull(CLIENT_SURNAME,'') + ' ' + isnull(CLIENT_FORENAME,'') as Client,	--AG 14/03/2018
		APPL_DATE as ApplicationDate,
		DEC_DATE as DeclarationDate,
		START_DATE as StartDate,
		null as RunDate,
		ORIGINAL_BRANCH as OrigBranch,
		SERIAL as PolicySerial,
		MEMBER as Member,
		PRODUCT_CODE as ProductCode,
		case when MEMBER = '   '
		then 
			case when ORIGINAL_BRANCH = '   '
				then SERIAL + '-' + PRODUCT_CODE
				else SERIAL + '-' + ORIGINAL_BRANCH + '-' + PRODUCT_CODE
			end			 
		else 
			case when ORIGINAL_BRANCH = '   '
				then SERIAL + '/' + MEMBER
				else SERIAL + '-' + ORIGINAL_BRANCH + '/' + MEMBER
			end
		end as Policy,
		null as Provider,
		SEQUENCE_NO as SequenceNo,
		SLICE_NO as SliceNo,
		SPLIT_PROPN as AgentSplit,
		YEARLY_PREMIUM as Premium,
		FREQUENCY as Frequency,
		Increase_Ind as IncreaseInd,
		DEAL_IND as FlexInd,
		INITIAL_PERIOD as InitialPeriod,
		case when COMM_RATE_STD > 0
			then COMM_RATE_STD
			else COMM_RATE_TRUE
		end as CommRateStd,
		COMM_RATE_TRUE as CommRateTrue,
		NPW_IND as NPWInd,
		INDEMN_TERMS_IND as ITInd,
		COMMISSION_TYPE as CommType,
		null as CommBasis,
		null as CommBasisDesc,
		AGNT_ENHT_RATE * 100.0 as EnhancementRate,
		ENHT_ACCRUEL as EnhancementAccr,
		ENHT_STILL_TO_ACCRUE as StillLeftToAccrue,
		ENHT_IT_ADVANCE as ITAdvance,
		ENHT_IT_ACCRUED as ITAccrued,
		ENHT_IT_LIABILITY as ITLiability,
		UPLIFT_FEE_ACCRUED as UpliftFeeAccr,
		UPLIFT_FEE_IT as UpliftFeeIT,
		VALUE_1 as Value1,
		VALUE_2 as Value2,
		VALUE_3 as Value3,
		VALUE_4 as Value4,
		VALUE_5 as Value5,
		VALUE_6 as Value6,
		REMARK_STRING as RemarksString,
		PROD_FACTOR as ProdFactor,
		PROD_CRED_FACTOR as ProdCred,
		null as PayBasis,
		null as TotalFees,
		null as IssuedInd,
		null as CommEnh,
		null as TotBaseCommStd,
		null as TotBaseCommTrue,
		null as CommNotEnhanced,
		null as UpliftRate,
		null as UpliftAccr,
		null as UpliftIT,
		PAGE_TYPE as FileID,
		LIST_POSITION_IND as ListPosition,
		@DateLoaded	as DateLoaded,
		Period as Month,
		'Main' as Source,
		case when isnumeric(REMARKS_CODE_1) = 1 then REMARKS_CODE_1 end as RemarkCode1,
		REMARKS_DATA_1 as RemarksData1,
		case when isnumeric(REMARKS_CODE_2) = 1 then REMARKS_CODE_2 end as RemarkCode2,
