/************************************************************************************************
  	 Program:  	mspr_FeeListings_Main_To_Laboris					
	  Author:	A Groves
Date created:	13/10/2017

		Type:	SR464996/CH16204. This change was to migrate the Legacy Month End process from 
				DTS to SSIS. The relevant scripts are:
				DTS:	Zurich_Openwork_FeesMonthly_Import
				SSIS:	LegacyMonthEndFeeImport.dtsx
				The DTS scripts did a lot more work in terms of mapped table-to-table uploads and
				running stored procs after the flat files were loaded. The uploads and stored proc
				executions were kept out of the SSIS script (to keep it simple) and were instead
				placed in the SQL Agent Job. Where mapped table-to-table uploads occurred, these
				were re-written in stored procs. This proc is one such example. 
		
		
 Description:   This proc populates table "msit_NSLaboris" from table "msit_FeeListings_Main".
				
				It is called as follows:

					exec mspr_FeeListings_Main_To_Laboris 'Openwork', 'NSMonthly'
									
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			

************************************************************************************************/

CREATE PROCEDURE [dbo].[mspr_FeeListings_Main_To_Laboris_Backup20180320AG]
	@Client		varchar(50),
	@Module		Varchar(50)
AS

set nocount on

declare		@PhaseStart								varchar(50),
			@PhaseEnd								varchar(50),
			@PhaseLog								varchar(50),
			@PhaseError								varchar(50),
			@Message								varchar(100),
			@ProcName								varchar(100),
			@RowCount								int,
			@DateLoaded								datetime = getdate()
			
/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @ProcName			= object_name(@@procid)
set @PhaseStart			= 'START'
set @PhaseEnd   		= 'END'
set @PhaseLog			= 'LOG'
set @PhaseError			= 'ERROR'

exec msp_ProcessLog @PhaseStart, @ProcName, null, @Module, @Client

/****************************************************************************

	Insert table data

****************************************************************************/

--Note: Table dbo.msit_NSLaboris is truncated by the SSIS script because there 
--are three procs that populate the table.

insert into dbo.msit_NSLaboris
(
	SWIFTFranchise,
	SWIFTSeller,
	OpenworkInd,
	SellerPrefix,
	SellerSerial,
	SellerSuffix,
	SellerID,
	SellerName,
	FranchisePrefix,
	FranchiseSerial,
	FranchiseSuffix,
	FranchiseID,
	ClientForename,
	ClientSurname,
	Client,
	ApplicationDate,
	DeclarationDate,
	StartDate,
	RunDate,
	OrigBranch,
	PolicySerial,
	Member,
	ProductCode,
	Policy,
	Provider,
	SequenceNo,
	SliceNo,
	AgentSplit,
	Premium,
	Frequency,
	IncreaseInd,
	FlexInd,
	InitialPeriod,
	CommRateStd,
	CommRateTrue,
	NPWInd,
	ITInd,
	CommType,
	CommBasis,
	CommBasisDesc,
	EnhancementRate,
	EnhancementAccr,
	StillLeftToAccrue,
	ITAdvance,
	ITAccrued,
	ITLiability,
	UpliftFeeAccr,
	UpliftFeeIT,
	Value1,
	Value2,
	Value3,
	Value4,
	Value5,
	Value6,
	RemarksString,
	ProdFactor,
	ProdCred,
	PayBasis,
	TotalFees,
	IssuedInd,
	CommEnh,
	TotBaseCommStd,
	TotBaseCommTrue,
	CommNotEnhanced,
	UpliftRate,
	UpliftAccr,
	UpliftIT,
	FileID,
	ListPosition,
	DateLoaded,
	Month,
	Source,
	RemarkCode1,
	RemarksData1,
	RemarkCode2,
	RemarksData2,
	RemarkCode3,
	RemarksData3,
	RemarkCode4,
	RemarksData4,
	RemarkCode5,
	RemarksData5,
	RemarkCode6,
	RemarksData6,
	--BACSDate,		This column is populated by a default setting on the table.
	BIRemarks
)
select 	null as SWIFTFranchise,
		null as SWIFTSeller,
		case
			when LIST_POSITION_IND = 6 then 'Y'
			when Openwork_Ind = '' then 'N'
			else Openwork_Ind
		end as OpenworkInd,
		null as SellerPrefix,
		SELLER_SERIAL as SellerSerial,
		null as SellerSuffix,
		null as SellerID,
		null as SellerName,
		MAIN_PREFIX as FranchisePrefix,
		MAIN_SERIAL as FranchiseSerial,
		MAIN_SUFFIX as FranchiseSuffix,
		null as FranchiseID,
		CLIENT_FORENAME as ClientForename,
		CLIENT_SURNAME as ClientSurname,
		CLIENT_SURNAME + ' ' + CLIENT_FORENAME as Client,
		APPL_DATE as ApplicationDate,
		DEC_DATE as DeclarationDate,
		START_DATE as StartDate,
		null as RunDate,
		ORIGINAL_BRANCH as OrigBranch,
		SERIAL as PolicySerial,
		MEMBER as Member,
		PRODUCT_CODE as ProductCode,
		case when MEMBER = '   '
		then 
			case when ORIGINAL_BRANCH = '   '
				then SERIAL + '-' + PRODUCT_CODE
				else SERIAL + '-' + ORIGINAL_BRANCH + '-' + PRODUCT_CODE
			end			 
		else 
			case when ORIGINAL_BRANCH = '   '
				then SERIAL + '/' + MEMBER
				else SERIAL + '-' + ORIGINAL_BRANCH + '/' + MEMBER
			end
		end as Policy,
		null as Provider,
		SEQUENCE_NO as SequenceNo,
		SLICE_NO as SliceNo,
		SPLIT_PROPN as AgentSplit,
		YEARLY_PREMIUM as Premium,
		FREQUENCY as Frequency,
		Increase_Ind as IncreaseInd,
		DEAL_IND as FlexInd,
		INITIAL_PERIOD as InitialPeriod,
		case when COMM_RATE_STD > 0
			then COMM_RATE_STD
			else COMM_RATE_TRUE
		end as CommRateStd,
		COMM_RATE_TRUE as CommRateTrue,
		NPW_IND as NPWInd,
		INDEMN_TERMS_IND as ITInd,
		COMMISSION_TYPE as CommType,
		null as CommBasis,
		null as CommBasisDesc,
		AGNT_ENHT_RATE * 100.0 as EnhancementRate,
		ENHT_ACCRUEL as EnhancementAccr,
		ENHT_STILL_TO_ACCRUE as StillLeftToAccrue,
		ENHT_IT_ADVANCE as ITAdvance,
		ENHT_IT_ACCRUED as ITAccrued,
		ENHT_IT_LIABILITY as ITLiability,
		UPLIFT_FEE_ACCRUED as UpliftFeeAccr,
		UPLIFT_FEE_IT as UpliftFeeIT,
		VALUE_1 as Value1,
		VALUE_2 as Value2,
		VALUE_3 as Value3,
		VALUE_4 as Value4,
		VALUE_5 as Value5,
		VALUE_6 as Value6,
		REMARK_STRING as RemarksString,
		PROD_FACTOR as ProdFactor,
		PROD_CRED_FACTOR as ProdCred,
		null as PayBasis,
		null as TotalFees,
		null as IssuedInd,
		null as CommEnh,
		null as TotBaseCommStd,
		null as TotBaseCommTrue,
		null as CommNotEnhanced,
		null as UpliftRate,
		null as UpliftAccr,
		null as UpliftIT,
		PAGE_TYPE as FileID,
		LIST_POSITION_IND as ListPosition,
		@DateLoaded	as DateLoaded,
		Period as Month,
		'Main' as Source,
		case when isnumeric(REMARKS_CODE_1) = 1 then REMARKS_CODE_1 end as RemarkCode1,
		REMARKS_DATA_1 as RemarksData1,
		case when isnumeric(REMARKS_CODE_2) = 1 then REMARKS_CODE_2 end as RemarkCode2,
		REMARKS_DATA_2 as RemarksData2,
		case when isnumeric(REMARKS_CODE_3) = 1 then REMARKS_CODE_3 end as RemarkCode3,
		REMARKS_DATA_3 as RemarksData3,
		case when isnumeric(REMARKS_CODE_4) = 1 then REMARKS_CODE_4 end as RemarkCode4,
		REMARKS_DATA_4 as RemarksData4,
		case when isnumeric(REMARKS_CODE_5) = 1 then REMARKS_CODE_5 end as RemarkCode5,
		REMARKS_DATA_5 as RemarksData5,
		case when isnumeric(REMARKS_CODE_6) = 1 then REMARKS_CODE_6 end as RemarkCode6,
		REMARKS_DATA_6 as RemarksData6,
		--null as BACSDate,		This column is populated by a default setting on the table.
		null as BIRemarks
from	dbo.msit_FeeListings_Main


