create procedure [dbo].[mspr_FranchiseListDef]
 @UserId nvarchar(255),
 @Order  nvarchar(1)
as
--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : mspr_NSOrder.sql
-- Owner   : MWA
-- Created : 25/07/2006
--
--########################################################################

select distinct 
 a.FranchiseCode
into
 #Franchise
from  
 msdt_Adviser a inner join msct_UserAccessControl uac 
    on a.AdviserID = uac.AdviserID
where
 uac.DomainLogin = @UserId

-- Check to see if the user has data in the msit_OpenworkAdviserListing table
declare @Error int
set
 @Error = case when (select distinct 0 from #Franchise where FranchiseCode in (select distinct BusinessCode from msit_OpenworkAdviserListing)) = 0 then 0
               else 1
          end

if(@Error = 1)
begin
 RAISERROR ('Openwork Adviser Listing is not available for this user, no data exists.',16, 1)
end
else
begin

select distinct
 Value = oal.BusinessCode,
 Label = case when @Order = '1' then oal.BusinessCode + ' - ' + rtrim(oal.BusinessName)
              else rtrim(oal.BusinessName) + ' - ' + oal.BusinessCode 
         end
from
 msit_OpenworkAdviserListing oal,
 #Franchise fr
where
 oal.BusinessCode = fr.FranchiseCode
order by
 2 asc

end


GO
