SET QUOTED_IDENTIFIER OFF
GO

CREATE procedure [dbo].[mspr_NBIEquity]
with recompile
as

set NoCount on
select ProductCode,substring(productcode,5,8) as Prod,ProductGroupName as GroupName,ProductGroupCode
into #NBIProducts
from mstt_producthierarchy
where productcode like 'NBI_%'
order by productcode

set NoCount on
SELECT  
SwiftFranchise as Business,coalesce(ag.tradingname,ag.descn) as BusinessName,SWIFTSeller as SellerUID,
SellerName,ListPosition,Month,
case MONTH(Month) when 1 then 'JAN' when 2 then 'FEB' when 3 then 'MAR' when 4 then 'APR'
when 5 then 'MAY' when 6 then 'JUN' when 7 then 'JUL' when 8 then 'AUG'
when 9 then 'SEP' when 10 then 'OCT' when 11 then 'NOV' when 12 then 'DEC' end as Period,
case when OpenworkInd is Null then 'N' else OpenworkInd end as Openwork,
case when Listposition = 6 and fl.ProductCode = 'MOR' then 'Mortgage'
when ListPosition = 6 and (fl.ProductCode <> 'MOR' or fl.ProductCode is null) then 'GI'
when Listposition = 54 then 'Pension' when Listposition in (51,55) then 'Investment'
when listposition in (0,1,2,3,100) and t1.groupname is not null then t1.groupname
else fl.ProductCode end as ProductGroup,
case when listposition in (51,55) then 'Sterling' when listposition = 54 then 'Scot Eq'
when listposition = 6 then 'Third Party' else 'Zurich' end as Source,(1+UpliftRate) as UpliftRate,
Value1 as NBIAccrual,Value4 as NBIIT,case when listposition = 6 then Value2 else TotalFees end as NBIFees
into #NBICases
FROM    dbo.msit_FeesNonSWIFTFeeListing fl
left outer join mstt_agents ag on ag.code = fl.swiftfranchise
left outer join #nbiProducts t1 on t1.prod = fl.productcode
WHERE ListPosition not IN (7,8) 
AND Month > '2006/01/01'
AND (Value1 <> 0 or Value2 <> 0 or Value4 <> 0 or TotalFees <> 0)
and SwiftFranchise is not null
ORDER BY SwiftFranchise,SellerName,OpenworkInd,7,Listposition,Month

Select Business,BusinessName,SellerUID,SellerName,ProductGroup,Openwork,
Sum(NBIAccrual) as PreUpliftNBIAccrual, Sum(NBIIT) as PreUpliftNBIIT,
Round(Sum(NBIAccrual*UpliftRate),2) as PostUpliftNBIAccrual, 
Round(Sum(NBIIT*UpliftRate),2) as PostUpliftNBIIT,
Round(sum(case when listposition = 6 then (UpliftRate*NBIFees) else NBIFees end),2) as NBIFees,
Count(*) as Count
from #nbicases
where (NBIAccrual <> 0 and NBIAccrual is not null) or (NBIIT <> 0 and NBIIT is not null) 
or (NBIFees <> 0 and NBIFees is not null)
GROUP BY Business,BusinessName,SellerUID,SellerName,ProductGroup,Openwork
ORDER BY Business,SellerName,ProductGroup,Openwork
GO
