CREATE PROCEDURE [dbo].[mspr_NonSWIFTFranchiseCodes]
@LoginName NVARCHAR(50),
@OpenworkInd nvarchar(5) = NULL,
@ListPosition1 INT = NULL, 
@ListPosition2 INT = NULL, 
@ListPosition3 INT = NULL,
@ListPosition4 INT = NULL,
@ListPosition5 INT = NULL,
@ListPosition6 INT = NULL,
@ListPosition7 INT = NULL,
@ListPosition8 INT = NULL,
@ListPosition9 INT = NULL,
@ListPosition10 INT = NULL
as




exec msp_ProcessLog 'Start', 'mspr_NonSWIFTFranchiseCodes', null, null, 'Openwork'
        
DECLARE @Franchises TABLE(Code varchar(7)COLLATE latin1_General_CI_AS)

INSERT INTO @Franchises
SELECT  DISTINCT a.FranchiseCode
FROM  msdt_Adviser a 
  INNER JOIN msct_UserAccessControl uac 
    ON a.AdviserID = uac.AdviserID
WHERE @LoginName = uac.DomainLogin

select 
TradingName AS Label,
CODE AS Value,
DateStarted,
AgentCode,
[Month],
Seller,
SellerID
from
msct_Feesnonswiftaccesscontrol
WHERE CODE IN (SELECT Code FROM @Franchises) AND
ISNULL(OpenworkInd,'N') = @OpenworkInd AND
(
  ListPosition=@ListPosition1 OR
  ListPosition=@ListPosition2 OR
  ListPosition=@ListPosition3 OR
  ListPosition=@ListPosition4 OR
  ListPosition=@ListPosition5 OR
  ListPosition=@ListPosition6 OR
  ListPosition=@ListPosition7 OR
  ListPosition=@ListPosition8 OR
  ListPosition=@ListPosition9 OR
  ListPosition=@ListPosition10
)

ORDER BY Label,[Month] DESC ,SellerID

exec msp_ProcessLog 'End', 'mspr_NonSWIFTFranchiseCodes', null, null, 'Openwork'


GO
