create procedure [dbo].[mspr_NSDateEnquiry]
@OpeningBalanceDate datetime,
@OpenworkInd   nvarchar(1),
@FranchiseCode nvarchar(15)
as
--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : mspr_NSDateEnq.sql
-- Owner   : CTT
-- Created : 26/10/2005
--
--########################################################################
declare @Opening nvarchar(10)
declare @Closing nvarchar(10)
select
 @Opening = convert(nvarchar(10),a.[LedgerDate],103)
from
 mst_NSStatement a
where
 a.[SortCode] = '0' and
 a.[OpenworkInd] = @OpenworkInd and
 a.[FranchiseCode] = @FranchiseCode and
 a.[Month] = @OpeningBalanceDate
select
 @Closing = convert(nvarchar(10),a.[LedgerDate],103)
from
 mst_NSStatement a
where
 a.[SortCode] = '2' and
 a.[OpenworkInd] = @OpenworkInd and
 a.[FranchiseCode] = @FranchiseCode and
 a.[Month] = @OpeningBalanceDate
select
 @Opening + ' to ' + @Closing [Label]


GO
