create procedure [dbo].[mspr_NSFranchiseDetails]
@FranchiseCode nvarchar(10)

as

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : mspr_NSFranchiseDetails.sql
-- Owner   : BI\ghope
-- Created : 10/01/2005
--
--########################################################################
exec msp_ProcessLog 'Start', 'mspr_NSFranchiseDetails', null, null, 'Openwork'

Select Top 1 
CASE WHEN mstt_Agents.TradingName IS NULL THEN RTRIM(mstt_Agents.DESCN) + SPACE(5) +'(' + mstt_Agents.CODE + ')' ELSE RTRIM(mstt_Agents.TradingName) + SPACE(5) +'(' + mstt_Agents.CODE + ')' END AS FranchiseName,
CASE WHEN mstt_Agents.OSCARDateStarted IS NULL THEN GETDATE()ELSE mstt_Agents.OSCARDateStarted END AS DateStarted,
CASE WHEN mstt_Agents.OSCARAgentSerial IS NULL THEN 'No Oscar Code Available' ELSE mstt_Agents.OSCARAgentPrefix +  mstt_Agents.OSCARAgentSerial + mstt_Agents.OSCARAgentSuffix END AS AgentCode
from
mstt_Agents 
Where mstt_Agents.CODE = @FranchiseCode 

--If CR66 is changed to apply to commission + feelistings  -  Comment code above, and uncomment code below
--Also make change to mspr_NonSwiftFranchiseCodes
/*
Select Top 1 
CASE WHEN mstt_Agents.CompetitionName IS NULL THEN CASE WHEN mstt_Agents.TradingName IS NULL THEN RTRIM(mstt_Agents.DESCN) + SPACE(5) +'(' + mstt_Agents.CODE + ')' ELSE RTRIM(mstt_Agents.TradingName) + SPACE(5) +'(' + mstt_Agents.CODE + ')' END  ELSE RTRIM(mstt_Agents.CompetitionName) + SPACE(5) +'(' + mstt_Agents.CODE + ')' END AS FranchiseName,
mstt_Agents.OSCARDateStarted AS DateStarted,
mstt_Agents.OSCARAgentPrefix +  mstt_Agents.OSCARAgentSerial + mstt_Agents.OSCARAgentSuffix AS AgentCode
from
mstt_Agents 
Where mstt_Agents.CODE = @FranchiseCode 
*/
exec msp_ProcessLog 'End', 'mspr_NSFranchiseDetails', null, null, 'Openwork'


GO
