create procedure [dbo].[mspr_NSFranchiseView]
@OpenworkInd nvarchar(1),
@UserId nvarchar(255),
@Order nvarchar(1)
as
--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : mspr_NSFranchiseView.sql
-- Owner   : CTT
-- Created : 26/10/2005
--
--########################################################################
SELECT DISTINCT a.FranchiseCode
into
 #Franchise
FROM  msdt_Adviser a 
  INNER JOIN msct_UserAccessControl uac 
    ON a.AdviserID = uac.AdviserID
WHERE uac.DomainLogin = @UserID
select
 FR.FranchiseCode [Value],
 case when @Order = '1' then FR.FranchiseCode + ' - ' + rtrim(isnull(AG.TradingName,AG.Descn))
      else rtrim(isnull(AG.TradingName,AG.Descn)) + ' - ' + FR.FranchiseCode end [Label]
from
 #Franchise FR,
 mstt_Agents AG
where
 FR.FranchiseCode = AG.Code
order by
2 asc     


GO
