CREATE PROCEDURE [dbo].[mspr_NSGetPeriodMonth] 
@FranchiseCode nvarchar(15),
@OpenworkInd nvarchar(5) = NULL,
@ListPosition1 INT = NULL, 
@ListPosition2 INT = NULL, 
@ListPosition3 INT = NULL,
@ListPosition4 INT = NULL,
@ListPosition5 INT = NULL,
@ListPosition6 INT = NULL,
@ListPosition7 INT = NULL,
@ListPosition8 INT = NULL,
@ListPosition9 INT = NULL,
@ListPosition10 INT = NULL
AS
/******************************************************************************
Copyright (C) Moore Stephens Consulting Limited 2005
Summary : %Summary%
Author  : ghope
Created : 23 November 2005
*******************************************************************************/
SELECT DISTINCT [Month] AS Value,convert(nvarchar(10),[Month],103) AS Label
FROM
  msit_FeesNonSWIFTFeeListing WITH (INDEX = IX_msit_FeesNonSWIFTFeeListing_8)
where
SWIFTFranchise = @FranchiseCode AND  (ISNULL(@OpenworkInd,'N') = ISNULL(OpenworkInd,'N')) AND
(
  msit_FeesNonSWIFTFeeListing.ListPosition=ISNULL(@ListPosition1,msit_FeesNonSWIFTFeeListing.ListPosition) OR 
  msit_FeesNonSWIFTFeeListing.ListPosition=@ListPosition2 OR 
  msit_FeesNonSWIFTFeeListing.ListPosition=@ListPosition3 OR 
  msit_FeesNonSWIFTFeeListing.ListPosition=@ListPosition4 OR 
  msit_FeesNonSWIFTFeeListing.ListPosition=@ListPosition5 OR 
  msit_FeesNonSWIFTFeeListing.ListPosition=@ListPosition6 OR
  msit_FeesNonSWIFTFeeListing.ListPosition=@ListPosition7 OR
  msit_FeesNonSWIFTFeeListing.ListPosition=@ListPosition8 OR
  msit_FeesNonSWIFTFeeListing.ListPosition=@ListPosition9 OR
  msit_FeesNonSWIFTFeeListing.ListPosition=@ListPosition10
)
ORDER BY [Month] DESC 


GO
