CREATE PROCEDURE [dbo].[mspr_NSGetSellerName]


@Adviser nvarchar(15)

AS

exec msp_ProcessLog 'Start', 'mspr_NSGetSellerName', null, null, 'Openwork'

DECLARE @Seller NVARCHAR(50)


IF @Adviser = 'All'
BEGIN
SELECT @Adviser = NULL
SELECT @Seller = 'All'
END
ELSE IF @Adviser IS NULL
BEGIN
SELECT @Seller = 'All' 
END
ELSE
BEGIN
SELECT @Seller = (SELECT TOP 1 RTRIM(SellerName) + ' (' + SellerPrefix+SellerSerial+SellerSuffix + ')' 
 FROM msit_FeesNonSWIFTFeeListing WHERE SellerID = @Adviser)
END


SELECT @Seller  AS Seller

exec msp_ProcessLog 'End', 'mspr_NSGetSellerName', null, null, 'Openwork'

GO
