CREATE PROCEDURE [dbo].[mspr_NSImportValidationAgentInfo] 
AS
IF ((SELECT COUNT(DISTINCT Curr_Mth) FROM msit_AgentInfo) > 1)
BEGIN
  TRUNCATE TABLE msit_AgentInfo
