/******************************************************************************

Copyright (C) Moore Stephens Consulting Limited 2005

Summary : Checks that the Mth Var values are correct before data import
Author  : ghope
Created : 03/01/2006

*******************************************************************************/

CREATE PROCEDURE [dbo].[mspr_NSImportValidationMidMonthly] 
AS
IF ((SELECT COUNT(*) FROM msit_FeeListings_Main_Sterling) = 0) AND ((SELECT COUNT(*) FROM msit_FeeListings_Main_Scott_Eq) = 0) 
BEGIN
  exec master.dbo.xp_logevent 55555, 'Data validation failed on MidMonthly import because no data was located in the staging table', ERROR
  RAISERROR ('There is no data in the staging tables',16, 1)
END
IF EXISTS (SELECT TOP 1 * FROM msit_FeesNonSWIFTFeeListing WHERE msit_FeesNonSWIFTFeeListing.ListPosition = 55 AND (msit_FeesNonSWIFTFeeListing.[Month] IN (SELECT MAX (Period) FROM msit_FeeListings_Main_Sterling)))
BEGIN
  exec master.dbo.xp_logevent 55555, 'Data validation failed on MidMonthly import because the curr_mth value already exists in the msit_FeesNonSWIFTFeeListing table for MidMonthly list positions (55)', ERROR
  RAISERROR ('Curr_Mth value already exists in the msit_FeesNonSWIFTFeeListing table for MidMonthly list positions (55)',16, 1)
END

IF (SELECT COUNT(*) FROM msit_AgentInfo) = 0
BEGIN
  exec master.dbo.xp_logevent 55555, 'Data validation failed on MidMonthly import because the agent_info table is empty.', ERROR
  RAISERROR ('Data validation failed on MidMonthly import because the agent_info table is empty.',16, 1)
END

DECLARE @AgentInfoMth smalldatetime
DECLARE @MMSterlingMth smalldatetime
SELECT @AgentInfoMth = (SELECT TOP 1 Curr_Mth FROM msit_AgentInfo)
SELECT @MMSterlingMth = (SELECT TOP 1 Period FROM msit_FeeListings_Main_Sterling)

IF NOT @AgentInfoMth = DATEADD(month,-1,@MMSterlingMth)
BEGIN
  exec master.dbo.xp_logevent 55555, 'Data validation failed on MidMonthly import because the curr_mth in the import tbale does not match the curr_mth value in the Agent Info Table', ERROR
  RAISERROR ('Data validation failed on MidMonthly import because the curr_mth in the import tbale does not match the curr_mth value in the Agent Info Table',16, 1)
END





GO
