/******************************************************************************

Copyright (C) Moore Stephens Consulting Limited 2005

Summary	: Checks that the Mth Var values are correct before data import
Author	: ghope
Created	: 03/01/2006

Amendment History
=================
Date		Author		Description
----		------		-----------
06/11/2013	A Groves	Added progress logging calls to msp_ProcessLog.

*******************************************************************************/

CREATE PROCEDURE [dbo].[mspr_NSImportValidationMonthly] 
AS

exec msp_ProcessLog 'START', 'mspr_NSImportValidationMonthly', null, 'ImportMonthly', 'Openwork'

IF ((SELECT COUNT(*) FROM msit_FeeListings_Main_Sterling) = 0) AND ((SELECT COUNT(*) FROM msit_FeeListings_Main_Scott_Eq) = 0) AND ((SELECT COUNT(*) FROM msit_FeeListings_Main) = 0)
BEGIN
	exec master.dbo.xp_logevent 55555, 'Data validation failed on Monthly import because no data was located in the staging table', ERROR
	RAISERROR ('There is no data in the staging tables',16, 1)
END
IF EXISTS (SELECT TOP 1 * FROM msit_FeesNonSWIFTFeeListing WHERE (msit_FeesNonSWIFTFeeListing.[Month] IN (SELECT DISTINCT Period FROM msit_FeeListings_Main WHERE NOT msit_FeeListings_Main.List_Position_Ind = '55'))  
	AND NOT msit_FeesNonSWIFTFeeListing.ListPosition = 55 AND NOT msit_FeesNonSWIFTFeeListing.ListPosition = 60)  
BEGIN
	exec master.dbo.xp_logevent 55555, 'Data validation failed on Monthly import because the curr_mth value already exists in the msit_FeesNonSWIFTFeeListing table for NONE MidMonth/Renewals list positions (55/60)', ERROR
	RAISERROR ('Curr_Mth value already exists in the msit_FeesNonSWIFTFeeListing table for NONE MidMonth/Renewals list positions (55/60)',16, 1)
END
IF EXISTS (SELECT TOP 1 * FROM msit_FeesNonSWIFTFeeListing WHERE (msit_FeesNonSWIFTFeeListing.[Month] IN (SELECT DISTINCT Period FROM msit_FeeListings_Main_Scott_Eq))  
	AND msit_FeesNonSWIFTFeeListing.ListPosition = 54)  
BEGIN
	exec master.dbo.xp_logevent 55555, 'Data validation failed on Monthly import because the curr_mth value for the Scott Eq data already exists in the msit_FeesNonSWIFTFeeListing table for Scott Eq  list positions (54)', ERROR
	RAISERROR ('Curr_Mth value for Scott Eq already exists in the msit_FeesNonSWIFTFeeListing table for Scott Eq list positions (54)',16, 1)
END
IF EXISTS (SELECT TOP 1 * FROM msit_FeesNonSWIFTFeeListing WHERE msit_FeesNonSWIFTFeeListing.ListPosition = 51 AND (msit_FeesNonSWIFTFeeListing.[Month] IN (SELECT MAX(Period) FROM msit_FeeListings_Main_Sterling)))
BEGIN
	exec master.dbo.xp_logevent 55555, 'Data validation failed on Monthly import because the  curr_mth value for the Sterling data already exists in the msit_FeesNonSWIFTFeeListing table for Sterling  list positions (51)', ERROR
	RAISERROR ('Curr_Mth value for the highest Sterling period already exists within msit_FeesNonSWIFTFeeListing table for Sterling list positions (51)',16, 1)
END

IF (SELECT COUNT(*) FROM msit_AgentInfo) = 0
BEGIN
	exec master.dbo.xp_logevent 55555, 'Data validation failed on MidMonthly import because the agent_info table is empty.', ERROR
	RAISERROR ('Data validation failed on MidMonthly import because the agent_info table is empty.',16, 1)
END

DECLARE @AgentInfoMth smalldatetime
DECLARE @SterlingMth smalldatetime
DECLARE @MainMth smalldatetime
DECLARE @ScottEqMth smalldatetime
SELECT @AgentInfoMth = (SELECT TOP 1 Curr_Mth FROM msit_AgentInfo)
SELECT @SterlingMth = (SELECT TOP 1 period FROM msit_FeeListings_Main_Sterling)
SELECT @MainMth = (SELECT TOP 1 period FROM msit_FeeListings_Main)
SELECT @ScottEqMth = (SELECT TOP 1 period FROM msit_FeeListings_Main_Scott_Eq)

IF ((NOT @AgentInfoMth = @SterlingMth)OR(NOT @SterlingMth=@MainMth)OR(NOT @MainMth=@ScottEqMth))
BEGIN
	exec master.dbo.xp_logevent 55555, 'Data validation failed on monthly import because the curr_mth value is not consistant between Agent Info and Monthly import tables', ERROR
	RAISERROR ('Data validation failed on monthly import because the curr_mth value is not consistant between Agent Info and Monthly import tables',16, 1)
END

exec msp_ProcessLog 'END', 'mspr_NSImportValidationMonthly', null, 'ImportMonthly', 'Openwork'

GO
