IF EXISTS (SELECT TOP 1 * FROM msit_FeesNonSWIFTFeeListing_Reload WHERE (msit_FeesNonSWIFTFeeListing_Reload.[Month] IN (SELECT DISTINCT Period FROM msit_FeeListings_Main_Scott_Eq_Reload))  
  AND msit_FeesNonSWIFTFeeListing_Reload.ListPosition = 54)  
BEGIN
  exec master.dbo.xp_logevent 55555, 'Data validation failed on Monthly import because the curr_mth value for the Scott Eq data already exists in the msit_FeesNonSWIFTFeeListing_Reload table for Scott Eq  list positions (54)', ERROR
  RAISERROR ('Curr_Mth value for Scott Eq already exists in the msit_FeesNonSWIFTFeeListing_Reload table for Scott Eq list positions (54)',16, 1)
END
IF EXISTS (SELECT TOP 1 * FROM msit_FeesNonSWIFTFeeListing_Reload WHERE msit_FeesNonSWIFTFeeListing_Reload.ListPosition = 51 AND (msit_FeesNonSWIFTFeeListing_Reload.[Month] IN (SELECT MAX(Period) FROM msit_FeeListings_Main_Sterling_Reload)))
BEGIN
  exec master.dbo.xp_logevent 55555, 'Data validation failed on Monthly import because the  curr_mth value for the Sterling data already exists in the msit_FeesNonSWIFTFeeListing_Reload table for Sterling  list positions (51)', ERROR
  RAISERROR ('Curr_Mth value for the highest Sterling period already exists within msit_FeesNonSWIFTFeeListing_Reload table for Sterling list positions (51)',16, 1)
END

IF (SELECT COUNT(*) FROM msit_AgentInfo_Reload) = 0
