SELECT @AgentInfoMth = (SELECT TOP 1 Curr_Mth FROM msit_AgentInfo_Reload)
SELECT @SterlingMth = (SELECT TOP 1 period FROM msit_FeeListings_Main_Sterling_Reload)
SELECT @MainMth = (SELECT TOP 1 period FROM msit_FeeListings_Main_Reload)
SELECT @ScottEqMth = (SELECT TOP 1 period FROM msit_FeeListings_Main_Scott_Eq_Reload)

IF ((NOT @AgentInfoMth = @SterlingMth)OR(NOT @SterlingMth=@MainMth)OR(NOT @MainMth=@ScottEqMth))
BEGIN
  exec master.dbo.xp_logevent 55555, 'Data validation failed on monthly import because the curr_mth value is not consistant between Agent Info and Monthly import tables', ERROR
  RAISERROR ('Data validation failed on monthly import because the curr_mth value is not consistant between Agent Info and Monthly import tables',16, 1)
