CREATE PROCEDURE [dbo].[mspr_NSMidMonthSummary]

@OpenworkInd   nvarchar(5) = NULL,
@FranchiseCode nvarchar(15),
@Period smalldatetime,
@Adviser nvarchar(15),
@UserId NVARCHAR(50)
AS

exec msp_ProcessLog 'Start', 'mspr_NSMidMonthSummary', null, null, 'Openwork'

exec mscp_CheckUserVerseFranchiseCode @UserId, @FranchiseCode

DECLARE @Seller NVARCHAR(50)
DECLARE @MidMonthSum FLOAT
DECLARE @MidMonthCount INT

IF((SELECT TOP 1 Month FROM msit_FeesPreSwiftCurrentListing  WHERE ListPosition = 55) = @Period)
BEGIN
  IF(@OpenworkInd = 'Y')
    BEGIN
      IF @Adviser = 'All'
  BEGIN
  
    SELECT @Seller = 'All'
  
    --Don't bother selecting into a temp table as this the temp select will take just as long
    SELECT @MidMonthSum = SUM(TotalFees) , 
      @MidMonthCount = Count(*)  
    From msit_FeesPreSwiftCurrentListing 
    WHERE ListPosition = 55 AND (SWIFTFranchise = @FranchiseCode) 
  END
  ELSE
  BEGIN
    SELECT *
    INTO #SingleCurrentSeller
    FROM msit_FeesPreSwiftCurrentListing
    WHERE SWIFTFranchise = @FranchiseCode
    AND ListPosition = 55
    AND SellerID = @Adviser
    
    SELECT @MidMonthSum = SUM(TotalFees) , 
      @MidMonthCount = Count(*)  
    From #SingleCurrentSeller 
    WHERE ListPosition = 55 AND (SWIFTFranchise = @FranchiseCode) 
    AND SellerID = @Adviser
  
    SELECT @Seller = (SELECT TOP 1 RTRIM( RTRIM(SellerName)) + ' (' + SellerPrefix+SellerSerial+SellerSuffix + ')' FROM #SingleCurrentSeller) 
  END
    END
  ELSE
    BEGIN
      IF @Adviser = 'All'
  BEGIN
  
    SELECT @Seller = 'All'
  
    --Don't bother selecting into a temp table as this the temp select will take just as long
    SELECT @MidMonthSum = SUM(TotalFees) , 
      @MidMonthCount = Count(*)  
    From msit_FeesZanCurrentListing 
    WHERE ListPosition = 55 AND (SWIFTFranchise = @FranchiseCode) 
  END
  ELSE
  BEGIN
    SELECT *
    INTO #SingleZanCurrentSeller
    FROM msit_FeesZanCurrentListing 
    WHERE SWIFTFranchise = @FranchiseCode
    AND ListPosition = 55
    AND SellerID = @Adviser
    
    SELECT @MidMonthSum = SUM(TotalFees) , 
      @MidMonthCount = Count(*)  
    From #SingleZanCurrentSeller 
    WHERE ListPosition = 55 AND (SWIFTFranchise = @FranchiseCode) 
    AND SellerID = @Adviser
  
    SELECT @Seller = (SELECT TOP 1 RTRIM( RTRIM(SellerName)) + ' (' + SellerPrefix+SellerSerial+SellerSuffix + ')' FROM #SingleZavCurrentSeller) 
  END
    END
END
ELSE
BEGIN
  IF @Adviser = 'All'
  BEGIN
  
    SELECT @Seller = 'All'
  
    --Don't bother selecting into a temp table as this the temp select will take just as long
    SELECT @MidMonthSum = SUM(TotalFees) , 
      @MidMonthCount = Count(*)  
    From msit_FeesNonSWIFTFeeListing 
    WHERE ListPosition = 55 AND (SWIFTFranchise = @FranchiseCode) 
    AND (ISNULL(@OpenworkInd,'N') = ISNULL(OpenworkInd,'N'))
    AND [Month] = @Period
  END
  ELSE
  BEGIN
    SELECT *
    INTO #SingleSeller
    FROM msit_FeesNonSWIFTFeeListing
    WHERE [Month] = @Period
    AND SWIFTFranchise = @FranchiseCode
    AND ISNULL(@OpenworkInd,'N') = ISNULL(OpenworkInd,'N')
    AND ListPosition = 55
    AND SellerID = @Adviser
    
    SELECT @MidMonthSum = SUM(TotalFees) , 
      @MidMonthCount = Count(*)  
    From #SingleSeller 
    WHERE ListPosition = 55 AND (SWIFTFranchise = @FranchiseCode) 
    AND (ISNULL(@OpenworkInd,'N') = ISNULL(OpenworkInd,'N'))
    AND [Month] = @Period
    AND SellerID = @Adviser
  
    SELECT @Seller = (SELECT TOP 1 RTRIM( RTRIM(SellerName)) + ' (' + SellerPrefix+SellerSerial+SellerSuffix + ')' FROM #SingleSeller) 
  END
END


SELECT 
ISNULL(@MidMonthSum,0.0) AS MidMonthSum,
@MidMonthCount AS MidMonthCount,
ISNULL(@Seller,'') AS Seller

exec msp_ProcessLog 'End', 'mspr_NSMidMonthSummary', null, null, 'Openwork'

GO
/****** Object:  StoredProcedure [dbo].[mspr_NSNewFeeZANFeeZurichOtherFee]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[mspr_NSNewFeeZANFeeZurichOtherFee]

@OpenworkInd   nvarchar(5) = NULL,
@FranchiseCode nvarchar(15) = NULL,
@Period smalldatetime,
@Adviser nvarchar(15),
@UserId NVARCHAR(50)


AS

exec msp_ProcessLog 'Start', 'mspr_NSNewFeeZanFeeZurichOtherFee', null, null, 'Openwork'

exec mscp_CheckUserVerseFranchiseCode @UserId, @FranchiseCode


DECLARE @Mortgages int
  

IF @Adviser = 'All'
BEGIN
SELECT @Adviser = NULL
END


IF((SELECT TOP 1 Month FROM msit_FeesPreSwiftCurrentListing  WHERE NOT ListPosition = 55) = @Period)
  BEGIN 
    IF(@OpenworkInd = 'Y')
    BEGIN
      SELECT @Mortgages = (SELECT count(*) 
            FROM          msit_FeesPreSwiftCurrentListing
            WHERE(SWIFTFranchise = ISNULL(@FranchiseCode, SWIFTFranchise)) AND SellerID = ISNULL(@Adviser, SellerID) AND ListPosition=6
            )
  
      SELECT      CASE WHEN @Adviser = 'All' THEN 'All' ELSE  RTRIM(SellerName) + ' (' + SellerPrefix+SellerSerial+SellerSuffix + ')' END AS Seller,   
          EnhancementRate AS EnhancedRate,
          EnhancementAccr AS EnhancedAccruedThisMth,
          StillLeftToAccrue AS EnhancedStillToAccrue,
          ITAdvance AS EnhancedITAdvanceThisMth,
          ITAccrued AS EnhancedITAccruedThisMth,
          Value1 AS NotEnhancedIssuedThisMth,
          Value2 AS NotEnhancedAccruedThisMth,
          Value3 AS NotEnhancedStillToAccrue,
          Value4 AS NotEnhancedITAdvancedThisMth,
          Value5 AS NotEnhancedITAccruedThisMth,  
          Value6 AS NotEnhancedOutstandingLiability,
          Client AS Client, 
          StartDate AS StartDate, 
          DateLoaded AS RunDate, 
          Policy AS Policy, 
          Premium AS AnnualPremium, 
          Frequency AS Frequency, 
              InitialPeriod AS InitialPeriod,
              CASE WHEN CommRateTrue > 0 THEN CommRateTrue ELSE CommRateStd END AS IFRate,
              RemarksString AS Remarks, 
              UpliftAccr AS UpliftAccr, 
              UpliftIT AS UpliftIT, 
              ListPosition AS ListPosition,
              @Mortgages AS Maortgages
                            
      FROM          msit_FeesPreSwiftCurrentListing
      WHERE 
        ListPosition IN (0,1,2,3,6)
        AND (SWIFTFranchise = ISNULL(@FranchiseCode, SWIFTFranchise)) AND SellerID = ISNULL(@Adviser, SellerID)
    END
    ELSE
    BEGIN
    SELECT @Mortgages = (SELECT count(*) 
          FROM           msit_FeesZanCurrentListing
          WHERE(SWIFTFranchise = ISNULL(@FranchiseCode, SWIFTFranchise)) AND SellerID = ISNULL(@Adviser, SellerID) AND ListPosition=6
          )

    SELECT      CASE WHEN @Adviser = 'All' THEN 'All' ELSE  RTRIM(SellerName) + ' (' + SellerPrefix+SellerSerial+SellerSuffix + ')' END AS Seller,   
        EnhancementRate AS EnhancedRate,
        EnhancementAccr AS EnhancedAccruedThisMth,
        StillLeftToAccrue AS EnhancedStillToAccrue,
        ITAdvance AS EnhancedITAdvanceThisMth,
        ITAccrued AS EnhancedITAccruedThisMth,
        Value1 AS NotEnhancedIssuedThisMth,
        Value2 AS NotEnhancedAccruedThisMth,
        Value3 AS NotEnhancedStillToAccrue,
        Value4 AS NotEnhancedITAdvancedThisMth,
        Value5 AS NotEnhancedITAccruedThisMth,  
        Value6 AS NotEnhancedOutstandingLiability,
        Client AS Client, 
        StartDate AS StartDate, 
        DateLoaded AS RunDate, 
        Policy AS Policy, 
        Premium AS AnnualPremium, 
        Frequency AS Frequency, 
            InitialPeriod AS InitialPeriod,
            CASE WHEN CommRateTrue > 0 THEN CommRateTrue ELSE CommRateStd END AS IFRate,
            RemarksString AS Remarks, 
            UpliftAccr AS UpliftAccr, 
            UpliftIT AS UpliftIT, 
            ListPosition AS ListPosition,
            @Mortgages AS Maortgages
                          
    FROM           msit_FeesZanCurrentListing
    WHERE 
      ListPosition IN (0,1,2,3,6)
      AND (SWIFTFranchise = ISNULL(@FranchiseCode, SWIFTFranchise)) AND SellerID = ISNULL(@Adviser, SellerID)
    END
  END
  ELSE
  BEGIN

    SELECT @Mortgages = (SELECT count(*) 
          FROM         msit_FeesNonSWIFTFeeListing
          WHERE(SWIFTFranchise = ISNULL(@FranchiseCode, SWIFTFranchise)) AND (ISNULL(@OpenworkInd,'N') = ISNULL(OpenworkInd,'N'))
            AND [Month] = @Period AND SellerID = ISNULL(@Adviser, SellerID) AND ListPosition=6
          )

    SELECT      CASE WHEN @Adviser = 'All' THEN 'All' ELSE  RTRIM(SellerName) + ' (' + SellerPrefix+SellerSerial+SellerSuffix + ')' END AS Seller,   
        EnhancementRate AS EnhancedRate,
        EnhancementAccr AS EnhancedAccruedThisMth,
        StillLeftToAccrue AS EnhancedStillToAccrue,
        ITAdvance AS EnhancedITAdvanceThisMth,
        ITAccrued AS EnhancedITAccruedThisMth,
        Value1 AS NotEnhancedIssuedThisMth,
        Value2 AS NotEnhancedAccruedThisMth,
        Value3 AS NotEnhancedStillToAccrue,
        Value4 AS NotEnhancedITAdvancedThisMth,
        Value5 AS NotEnhancedITAccruedThisMth,  
        Value6 AS NotEnhancedOutstandingLiability,
        Client AS Client, 
        StartDate AS StartDate, 
        DateLoaded AS RunDate, 
        Policy AS Policy, 
        Premium AS AnnualPremium, 
        Frequency AS Frequency, 
            InitialPeriod AS InitialPeriod,
            CASE WHEN CommRateTrue > 0 THEN CommRateTrue ELSE CommRateStd END AS IFRate,
            RemarksString AS Remarks, 
            UpliftAccr AS UpliftAccr, 
            UpliftIT AS UpliftIT, 
            ListPosition AS ListPosition,
            @Mortgages AS Maortgages
                          
    FROM         msit_FeesNonSWIFTFeeListing
    WHERE
    (
      ListPosition IN (0,1,2,3,6)
      )
      AND (SWIFTFranchise = ISNULL(@FranchiseCode, SWIFTFranchise)) AND (ISNULL(@OpenworkInd,'N') = ISNULL(OpenworkInd,'N'))
      AND [Month] = @Period AND SellerID = ISNULL(@Adviser, SellerID)
    END

exec msp_ProcessLog 'End', 'mspr_NSNewFeeZanFeeZurichOtherFee', null, null, 'Openwork'

GO
