CREATE procedure [dbo].[mspr_NSOBDateEnquiry]
@OpenworkInd nvarchar(5),
@FranchiseCode nvarchar(15)
as


--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : mspr_NSOBDateEnquiry.sql
-- Owner   : CTT
-- Created : 08/11/2005
--
-- Amended : 07/07/2009 - MPC: Replace =* ANSI JOIN as these not allowed in SQL Server 2005
--
--########################################################################

select distinct
 a.Month [Value],
 isnull(convert(nvarchar(12),'01/' + substring(convert(nvarchar(6),dateadd(mm,1,a.Month),112),5,2) + '/' +
 convert(nvarchar(4),dateadd(mm,1,a.Month),112)),'No Statement') [Label],
 ag.Code
from
 mst_NSStatement a            --MPC: 07/07/2009
 inner join mstt_Agents ag        --MPC: 07/07/2009
  on a.[FranchiseCode] = ag.code    --MPC: 07/07/2009
where
-- a.[FranchiseCode] =* ag.code and   --MPC: 07/07/2009
 a.[OpenworkInd] = @OpenworkInd and
 ag.[Code] = @FranchiseCode and
 a.SortCode = '0'
order by
 a.Month desc
    


