/****** Object:  StoredProcedure [dbo].[mspr_NSPreSWIFTSummary]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[mspr_NSPreSWIFTSummary]

@OpenworkInd   nvarchar(5) = NULL,
@FranchiseCode nvarchar(15),
@Period smalldatetime,
@Adviser nvarchar(15),
@UserId NVARCHAR(50)
AS

exec msp_ProcessLog 'Start', 'mspr_NSPreSwiftSummary', null, null, 'Openwork'

exec mscp_CheckUserVerseFranchiseCode @UserId, @FranchiseCode


DECLARE @ZurichProtectionSum FLOAT
DECLARE @ZurichOtherSum FLOAT
DECLARE @SterlingSum FLOAT
DECLARE @MidMonthSum FLOAT
DECLARE @ScottEqSum FLOAT
DECLARE @MortageSum FLOAT
DECLARE @RenewalsSum FLOAT
DECLARE @ZurichProtectionCount INT
DECLARE @ZurichOtherCount INT
DECLARE @SterlingCount INT
DECLARE @MidMonthCount INT
DECLARE @ScottEqCount INT
DECLARE @MortageCount INT
DECLARE @RenewalsCount INT
DECLARE @Seller nvarchar(100)

IF @Adviser = 'All'
BEGIN
  SELECT @Seller = 'All'
END

--Is the requested month in the current month table
IF((SELECT TOP 1 Month FROM msit_FeesPreSwiftCurrentListing WHERE NOT ListPosition = 55) = @Period)
  BEGIN
    IF @Adviser = 'All'
    BEGIN
    
      select *
      into #CurrentAllSellers
      from msit_FeesPreSwiftCurrentListing
      WHERE SWIFTFranchise = @FranchiseCode
    
      SELECT @Seller = 'All'
    
      SELECT @ZurichProtectionSum = ISNULL(SUM(ITAdvance),0) + ISNULL(SUM(EnhancementAccr),0),
        @ZurichProtectionCount =  COUNT(*)
      From #CurrentAllSellers 
      WHERE ListPosition = 100 
    
    
      SELECT @SterlingSum  = SUM(TotalFees),
        @SterlingCount = Count(*) 
      From #CurrentAllSellers 
      WHERE ListPosition = 51 
    
    
      SELECT @ScottEqSum = SUM(TotalFees), 
        @ScottEqCount = Count(*)
      From #CurrentAllSellers 
      WHERE ListPosition = 54 
    
    
      SELECT @MortageSum  = SUM(Value2) ,
        @MortageCount  = COUNT(*) 
      From #CurrentAllSellers 
      WHERE ListPosition = 6 
    
    
      SELECT @ZurichOtherSum = ISNULL(SUM(Value4),0) + ISNULL(SUM(Value2),0) + ISNULL(SUM(UpliftIT),0) + ISNULL(SUM(UpliftAccr),0) ,
        @ZurichOtherCount = COUNT(*) 
      From #CurrentAllSellers 
      WHERE (ListPosition = 0 OR  ListPosition = 1 OR ListPosition = 2 OR ListPosition = 3) 
    END
    ELSE 
    BEGIN 
      select *
      into #CurrentSingleSeller
      from msit_FeesPreSwiftCurrentListing
      where SWIFTFranchise = @FranchiseCode
      AND SellerID = @Adviser
      
    SELECT @ZurichProtectionSum = ISNULL(SUM(ITAdvance),0) + ISNULL(SUM(EnhancementAccr),0),
        @ZurichProtectionCount =  COUNT(*)
      From #CurrentSingleSeller 
      WHERE ListPosition = 100 
    
      SELECT @SterlingSum  = SUM(TotalFees),
        @SterlingCount = Count(*) 
      From #CurrentSingleSeller 
      WHERE ListPosition = 51 
    
    
      SELECT @ScottEqSum = SUM(TotalFees), 
        @ScottEqCount = Count(*)
      From #CurrentSingleSeller 
      WHERE ListPosition = 54
    
    
      SELECT @MortageSum  = SUM(Value2) ,
        @MortageCount  = COUNT(*) 
      From #CurrentSingleSeller 
      WHERE ListPosition = 6
    
    
      SELECT @ZurichOtherSum = ISNULL(SUM(Value4),0) + ISNULL(SUM(Value2),0) + ISNULL(SUM(UpliftIT),0) + ISNULL(SUM(UpliftAccr),0) ,
        @ZurichOtherCount = COUNT(*) 
      From #CurrentSingleSeller 
      WHERE (ListPosition = 0 OR  ListPosition = 1 OR ListPosition = 2 OR ListPosition = 3)
        
      SELECT @Seller = (SELECT TOP 1 RTRIM( RTRIM(SellerName)) + ' (' + SellerPrefix+SellerSerial+SellerSuffix + ')' FROM #CurrentSingleSeller) 
    END 
  END
ELSE
  BEGIN
    IF @Adviser = 'All'
    BEGIN
    
      select *
      into #AllSellers
      from msit_FeesNonSWIFTFeeListing
      where [Month] = @Period
      and SWIFTFranchise = @FranchiseCode
      and ISNULL(@OpenworkInd,'N') = ISNULL(OpenworkInd,'N')
    
      SELECT @Seller = 'All'
    
      SELECT @ZurichProtectionSum = ISNULL(SUM(ITAdvance),0) + ISNULL(SUM(EnhancementAccr),0),
        @ZurichProtectionCount =  COUNT(*)
      From #AllSellers 
      WHERE ListPosition = 100 
    
    
      SELECT @SterlingSum  = SUM(TotalFees),
        @SterlingCount = Count(*) 
      From #AllSellers 
      WHERE ListPosition = 51 
    
    
      SELECT @ScottEqSum = SUM(TotalFees), 
        @ScottEqCount = Count(*)
      From #AllSellers 
      WHERE ListPosition = 54 
    
    
      SELECT @MortageSum  = SUM(Value2) ,
        @MortageCount  = COUNT(*) 
      From #AllSellers 
      WHERE ListPosition = 6 
    
    
      SELECT @ZurichOtherSum = ISNULL(SUM(Value4),0) + ISNULL(SUM(Value2),0) + ISNULL(SUM(UpliftIT),0) + ISNULL(SUM(UpliftAccr),0) ,
        @ZurichOtherCount = COUNT(*) 
      From #AllSellers 
      WHERE (ListPosition = 0 OR  ListPosition = 1 OR ListPosition = 2 OR ListPosition = 3) 
    END
    ELSE 
    BEGIN 
      select *
      into #SingleSeller
      from msit_FeesNonSWIFTFeeListing
      where [Month] = @Period
      and SWIFTFranchise = @FranchiseCode
      and ISNULL(@OpenworkInd,'N') = ISNULL(OpenworkInd,'N')
      AND SellerID = @Adviser
      
    SELECT @ZurichProtectionSum = ISNULL(SUM(ITAdvance),0) + ISNULL(SUM(EnhancementAccr),0),
        @ZurichProtectionCount =  COUNT(*)
      From #SingleSeller 
      WHERE ListPosition = 100 
    
      SELECT @SterlingSum  = SUM(TotalFees),
        @SterlingCount = Count(*) 
      From #SingleSeller 
      WHERE ListPosition = 51 
    
    
      SELECT @ScottEqSum = SUM(TotalFees), 
        @ScottEqCount = Count(*)
      From #SingleSeller 
      WHERE ListPosition = 54
    
    
      SELECT @MortageSum  = SUM(Value2) ,
        @MortageCount  = COUNT(*) 
      From #SingleSeller 
      WHERE ListPosition = 6
    
    
      SELECT @ZurichOtherSum = ISNULL(SUM(Value4),0) + ISNULL(SUM(Value2),0) + ISNULL(SUM(UpliftIT),0) + ISNULL(SUM(UpliftAccr),0) ,
        @ZurichOtherCount = COUNT(*) 
      From #SingleSeller 
      WHERE (ListPosition = 0 OR  ListPosition = 1 OR ListPosition = 2 OR ListPosition = 3)
        
      SELECT @Seller = (SELECT TOP 1 RTRIM( RTRIM(SellerName)) + ' (' + SellerPrefix+SellerSerial+SellerSuffix + ')' FROM #SingleSeller) 
    END 
  END


SELECT 
ISNULL(@ZurichProtectionSum,0.0) AS ZurichProtectionSum,
ISNULL(@ZurichOtherSum,0.0) AS ZurichOtherSum,
ISNULL(@SterlingSum,0.0) AS SterlingSum,
ISNULL(@MidMonthSum,0.0) AS MidMonthSum,
ISNULL(@ScottEqSum,0.0) AS ScottEqSum,
ISNULL(@MortageSum,0.0) AS MortageSum,
ISNULL(@RenewalsSum,0.0) AS RenewalsSum,
@ZurichProtectionCount AS ZurichProtectionCount,
@ZurichOtherCount AS ZurichOtherCount,
@SterlingCount AS SterlingCount,
@MidMonthCount AS MidMonthCount,
@ScottEqCount AS ScottEqCount,
@MortageCount AS MortageCount,
@RenewalsCount AS RenewalsCount,
@Seller AS Seller

exec msp_ProcessLog 'End', 'mspr_NSPreSwiftSummary', null, null, 'Openwork'


GO
/****** Object:  StoredProcedure [dbo].[mspr_NSRemarksUpdate]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS OFF
GO
SET QUOTED_IDENTIFIER OFF
GO
CREATE Procedure [dbo].[mspr_NSRemarksUpdate]
AS

-- Amended : 07/07/2009 - MPC
-- Replaced *= ANSI JOINS as these not allowed in SQL Server 2005

-- ADD THE REMARKS INFORMATION To the working table
declare
 Remarks cursor
for
select
 [Id],
 RemarkCode1,
 RemarkCode2,
 RemarkCode3,
 RemarkCode4,
 RemarkCode5,
 RemarkCode6
from
 msit_NSLaboris
where
 (RemarkCode1 in (select RemarkCode from msit_NonSwiftCommRemarks) or
  RemarkCode2 in (select RemarkCode from msit_NonSwiftCommRemarks) or
  RemarkCode3 in (select RemarkCode from msit_NonSwiftCommRemarks) or
  RemarkCode4 in (select RemarkCode from msit_NonSwiftCommRemarks) or
  RemarkCode5 in (select RemarkCode from msit_NonSwiftCommRemarks) or
  RemarkCode6 in (select RemarkCode from msit_NonSwiftCommRemarks))
order by
 [Id]
for read only

declare @SourceId    int,
        @RemarkCode1 varchar(10),
        @RemarkCode2 varchar(10),
        @RemarkCode3 varchar(10),
        @RemarkCode4 varchar(10),
        @RemarkCode5 varchar(10),
        @RemarkCode6 varchar(10),
        @Priority    int,
        @Remarks     varchar(150)

declare @Table       table (SourceId int, Remarks varchar(150))

open
 Remarks
fetch
 Remarks
into
 @SourceId,
 @RemarkCode1,
 @RemarkCode2,
 @RemarkCode3,
 @RemarkCode4,
 @RemarkCode5,
 @RemarkCode6

while @@fetch_status = 0
begin
 set @Priority = 1
 set @Remarks  = ''

 while @Priority <= 5
 begin
  select @Remarks = @Remarks +
   isnull(rtrim(n1.RemarkText) + case when isnull(n1.RemarkInsert,'') = 'Y' then ' ' + rtrim(f.RemarksData1) + ', ' else ', ' end, '') +
   isnull(rtrim(n2.RemarkText) + case when isnull(n2.RemarkInsert,'') = 'Y' then ' ' + rtrim(f.RemarksData2) + ', ' else ', ' end, '') +
   isnull(rtrim(n3.RemarkText) + case when isnull(n3.RemarkInsert,'') = 'Y' then ' ' + rtrim(f.RemarksData3) + ', ' else ', ' end, '') +
   isnull(rtrim(n4.RemarkText) + case when isnull(n4.RemarkInsert,'') = 'Y' then ' ' + rtrim(f.RemarksData4) + ', ' else ', ' end, '') +
   isnull(rtrim(n5.RemarkText) + case when isnull(n5.RemarkInsert,'') = 'Y' then ' ' + rtrim(f.RemarksData5) + ', ' else ', ' end, '') +
   isnull(rtrim(n6.RemarkText) + case when isnull(n6.RemarkInsert,'') = 'Y' then ' ' + rtrim(f.RemarksData6) + ', ' else ', ' end, '')
  from
--MPC: 07/07/2009 Code Removed - START
   msit_NSLaboris f
   left outer join msit_NonSwiftCommRemarks  n1
  on  f.RemarkCode1     = n1.RemarkCode and
    n1.RemarkPriority = @Priority 
   left outer join msit_NonSwiftCommRemarks    n2
  on  f.RemarkCode2     = n2.RemarkCode and
    n2.RemarkPriority = @Priority 
   left outer join msit_NonSwiftCommRemarks    n3
  on  f.RemarkCode3     = n3.RemarkCode and
    n3.RemarkPriority = @Priority 
   left outer join msit_NonSwiftCommRemarks    n4
  on  f.RemarkCode4     = n4.RemarkCode and
    n4.RemarkPriority = @Priority 
   left outer join msit_NonSwiftCommRemarks    n5
  on  f.RemarkCode5     = n5.RemarkCode and
    n5.RemarkPriority = @Priority 
   left outer join msit_NonSwiftCommRemarks    n6
  on  f.RemarkCode6     = n6.RemarkCode and
    n6.RemarkPriority = @Priority 
  where
   f.[Id] = @SourceId 
--MPC: 07/07/2009 Code Changed - END
/* 
--MPC: 07/07/2009 Code Removed - START
   f.[Id]             = @SourceId     and
   f.RemarkCode1     *= n1.RemarkCode and
   n1.RemarkPriority  = @Priority     and
   f.RemarkCode2     *= n2.RemarkCode and
   n2.RemarkPriority  = @Priority     and
   f.RemarkCode3     *= n3.RemarkCode and
   n3.RemarkPriority  = @Priority     and
   f.RemarkCode4     *= n4.RemarkCode and
   n4.RemarkPriority  = @Priority     and
   f.RemarkCode5     *= n5.RemarkCode and
   n5.RemarkPriority  = @Priority     and
   f.RemarkCode6     *= n6.RemarkCode and
   n6.RemarkPriority  = @Priority
--MPC: 07/07/2009 Code Removed - END
*/

  set @Priority = @Priority + 1
 end

 set @Remarks = case when right(@Remarks,2) = ', ' then substring(@Remarks, 1, len(@Remarks)-1) else @Remarks end

 insert into @Table select @SourceId, @Remarks

 fetch
  Remarks
 into
  @SourceId,
  @RemarkCode1,
  @RemarkCode2,
  @RemarkCode3,
  @RemarkCode4,
  @RemarkCode5,
  @RemarkCode6
end

close Remarks
deallocate Remarks

update
 msit_NSLaboris
set
 BIRemarks = t.Remarks
from
 @Table t
where
 msit_NSLaboris.[ID] = t.SourceId



GO
