/****** Object:  StoredProcedure [dbo].[mspr_NSRenewalsSummary]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[mspr_NSRenewalsSummary]

@OpenworkInd   nvarchar(5) = NULL,
@FranchiseCode nvarchar(15),
@Period smalldatetime,
@Adviser nvarchar(15),
@UserId NVARCHAR(50)
AS

exec msp_ProcessLog 'Start', 'mspr_NSRenewalsSummary', null, null, 'Openwork'

exec mscp_CheckUserVerseFranchiseCode @UserId, @FranchiseCode

DECLARE @Seller NVARCHAR(50)
DECLARE @RenewalsSum FLOAT
DECLARE @RenewalsCount INT

IF @Adviser = 'All'
BEGIN

  SELECT @Seller = 'All'

  SELECT *
  INTO #AllSellers
  FROM msit_FeesNonSWIFTRenewalListing
  WHERE [Month] = @Period
  AND SWIFTFranchise = @FranchiseCode
  AND ISNULL(@OpenworkInd,'N') = ISNULL(OpenworkInd,'N')

  SELECT @RenewalsSum = ISNULL(SUM(#AllSellers.Value1*ISNULL(dbo.msit_AgentInfo.RC_RIGHTS_M1,1)),0) + ISNULL(SUM(#AllSellers.Value2*ISNULL(dbo.msit_AgentInfo.RC_RIGHTS_M2,1)),0) + ISNULL(SUM(#AllSellers.Value3*ISNULL(dbo.msit_AgentInfo.RC_RIGHTS_M3,1)),0),
    @RenewalsCount = COUNT(*)
  FROM  dbo.#AllSellers 
    LEFT OUTER JOIN dbo.msit_AgentInfo 
      ON dbo.msit_AgentInfo.MAIN_SERIAL = dbo.#AllSellers.FranchiseSerial 
END
ELSE
BEGIN
  SELECT *
  INTO #SingleSeller
  FROM msit_FeesNonSWIFTRenewalListing
  WHERE [Month] = @Period
  AND SWIFTFranchise = @FranchiseCode
  AND ISNULL(@OpenworkInd,'N') = ISNULL(OpenworkInd,'N')
  AND SellerID = @Adviser
  
  SELECT @RenewalsSum = ISNULL(SUM(#SingleSeller.Value1*ISNULL(dbo.msit_AgentInfo.RC_RIGHTS_M1,1)),0) + ISNULL(SUM(#SingleSeller.Value2*ISNULL(dbo.msit_AgentInfo.RC_RIGHTS_M2,1)),0) + ISNULL(SUM(#SingleSeller.Value3*ISNULL(dbo.msit_AgentInfo.RC_RIGHTS_M3,1)),0),
    @RenewalsCount = COUNT(*)
  FROM  dbo.#SingleSeller
    LEFT OUTER JOIN dbo.msit_AgentInfo 
      ON dbo.msit_AgentInfo.MAIN_SERIAL = dbo.#SingleSeller.FranchiseSerial 

  SELECT @Seller = (SELECT TOP 1 RTRIM(SellerName) + ' (' + SellerPrefix+SellerSerial+SellerSuffix + ')' FROM #SingleSeller) 
END
  
SELECT 
ISNULL(@RenewalsSum,0.0) AS RenewalsSum,
@RenewalsCount AS RenewalCount,
ISNULL(@Seller,'') AS Seller

exec msp_ProcessLog 'End', 'mspr_NSRenewalsSummary', null, null, 'Openwork'


GO
/****** Object:  StoredProcedure [dbo].[mspr_NSResetScotEqAdjustmentABC]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/*******************************************************************************************
     Program:	mspr_NSResetScotEqAdjustmentABC         
      Author:	A Groves
Date created:	03/12/2012
                      
Description:	This proc is designed to run as the last step of job "Openwork Import Monthly".
				Its purpose is to reset the ABC value on Scot Eq adjustments that have just
				been loaded by this job. This will make the non-Swift Scot Eq adjustments 
				consistent with the Swift Scot Eq adjustments with regard to the ABC reward
				calculated.

				This proc is called as follows:

					exec mspr_NSResetScotEqAdjustmentABC 'Openwork', 'NSMonthly', 1
          
				Use this SQL to find the fixing candidate rows:

					select * from msit_Openworkadviserlisting
					where source = 'openwork 2005'
					--and businesscode = '1001157'
					--and policy = '5512580'
					and providercode = 'scot eq'
					and feetype = 'ic'
					and paybasis = 'accr'
					and premium = 0
					and totalpayment <> 0

  Amendment History               
  -----------------               
                      
  Date			Who			Description       
  ----			---			-----------     
06/03/2014		A Groves	SR271363. Include ELITE points reset and amend to reset negative
							adjustments as well as positive adjustments.
*******************************************************************************************/
CREATE PROCEDURE [dbo].[mspr_NSResetScotEqAdjustmentABC] 
	@Client				varchar(50),
	@Module				varchar(50),
	@CurrentMonthOnly	bit = 1 
AS

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@Process					varchar(100),
		@Message					varchar(100),
		@LatestMonth				datetime,
		@OldestMonth				datetime,
		@RowCount					int

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart		= 'START'
set @PhaseEnd   	= 'END'
set @Process		= object_name(@@procid)

select	@LatestMonth	= max(Month),
		@OldestMonth	= min(Month)
from	msit_Openworkadviserlisting
where	Source = 'Openwork 2005'

/****************************************************************************

	Log start																
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	The data fix																
																		
****************************************************************************/

update OAL
	Set InitialPeriod		= 0,
		CommRate			= 0,
		TotDue_Enhd			= TotalPayment,
		Accrued_Enhd		= TotalPayment,
		StillToAccr_Enhd	= 0,
		TotDue_Base			= TotalPayment/case when isnull(EnhancementRate,100) <= 100 then 1.00 else EnhancementRate/100 end,
		Accrued_Base		= TotalPayment/case when isnull(EnhancementRate,100) <= 100 then 1.00 else EnhancementRate/100 end,
		StillToAccr_Base	= 0,
		ABCValue			= 0,
		ELITE_Points		= 0		-- AG 06/03/2014.
from	msit_OpenworkAdviserListing OAL with (index(IX_OpenworkAdviserListing_Month))	-- Full table scan occurs without this hint
where	Month between case when @CurrentMonthOnly = 1 then @LatestMonth else @OldestMonth end and @LatestMonth
and		Source = 'OPENWORK 2005'
and		ProviderCode = 'SCOT EQ'
and		FeeType = 'IC'
and		PayBasis = 'ACCR'
--and		ABCValue > 0	AG 06/03/2014. Removed to enable this proc to be re-runnable and should always have selected -ves too. 
and		Premium = 0
and		TotalPayment <> 0	-- AG 06/03/2014. Changed from TotalPayment > 0 as it should deal with negatives too.

set @RowCount = @@rowcount

set @Message = 'Oldest Month = ' + convert(varchar(10),@OldestMonth,103) + 
				'; Latest Month = ' + convert(varchar(10),@LatestMonth,103) +
				'; @CurrentMonthOnly = ' + convert(varchar(1),@CurrentMonthOnly)

exec msp_ProcessLog @PhaseEnd, @Message, null, @Module, @Client

/****************************************************************************

			E N D															

****************************************************************************/

set @Process = @Process + '. Number of rows = ' + convert(varchar(20),@RowCount)

exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

GO
/****** Object:  StoredProcedure [dbo].[mspr_NSSellerSerial]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [dbo].[mspr_NSSellerSerial]
@LP1 int = NULL,
@LP2 int = NULL,
@LP3 int = NULL,
@LP4 int = NULL,
@LP5 int = NULL,
@LP6 int = NULL,
@LP7 int = NULL
AS
SELECT 'All' AS Seller, NULL AS SellerSerial
UNION(
SELECT     SellerPrefix + SellerSerial + SellerSuffix + '(' + SwiftSeller + ')' AS Seller, SellerSerial AS SellerSerial
FROM         msit_FeesNonSWIFTFeeListing
WHERE
(
  ListPosition=@LP1 OR 
  ListPosition=@LP2 OR 
  ListPosition=@LP3 OR 
  ListPosition=@LP4 OR 
  ListPosition=@LP5 OR 
  ListPosition=@LP6  OR
  ListPosition=@LP7
)AND NOT SellerSerial IS NULL)
ORDER BY SellerSerial


GO
/****** Object:  StoredProcedure [dbo].[mspr_NSStatementEnquiry]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

create procedure [dbo].[mspr_NSStatementEnquiry]
@OpeningBalanceDate datetime,
@OpenworkInd   nvarchar(5),
@FranchiseCode nvarchar(15)
as
--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : mspr_NSStatementEnquiry.sql
-- Owner   : CTT
-- Created : 08/11/2005
--
--########################################################################
select
 a.[SortCode],
 a.[SortSeq],
 a.[LedgerDate],
 convert(nvarchar(10),a.[LedgerDate],103) [LedgerDate2],
 a.[LedgerDescription],
 case when a.[LedgerValue] < 0 then a.[LedgerValue] * -1 else '0' end [Debit],
 case when a.[LedgerValue] >= 0 then a.[LedgerValue] else '0' end [Credit]
from
 mst_NSStatement a
where
 a.[Month] = @OpeningBalanceDate and
 a.[OpenworkInd] = @OpenworkInd and
 a.[FranchiseCode] like @FranchiseCode
union all
select
 '1',
 '9999999',
 '2099-12-31',
 'Temp',
 '',
 sum(case when a.[LedgerValue] < 0 then a.[LedgerValue] * -1 else '0' end) [Debit],
 sum(case when a.[LedgerValue] >= 0 then a.[LedgerValue] else '0' end) [Credit]
from
 mst_NSStatement a
where
 a.[Month] = @OpeningBalanceDate and
 a.[OpenworkInd] = @OpenworkInd and
 a.[FranchiseCode] like @FranchiseCode and
 a.[SortCode] <> '2'
order by
 1,2


GO
/****** Object:  StoredProcedure [dbo].[mspr_NSStatementView]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

create procedure [dbo].[mspr_NSStatementView]
@OpenworkInd   nvarchar(5),
@UserId nvarchar(255)
as
--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : mspr_NSStatementView.sql
-- Owner   : CTT
-- Created : 26/10/2005
--
--########################################################################
SELECT DISTINCT a.FranchiseCode
into
 #Franchise
FROM  msdt_Adviser a 
  INNER JOIN msct_UserAccessControl uac 
    ON a.AdviserID = uac.AdviserID
WHERE uac.DomainLogin = @UserId
select
 a.[SortCode],
 a.[SortSeq],
 a.[LedgerDate],
 convert(nvarchar(10),a.[LedgerDate],103) [LedgerDate2],
 a.[LedgerDescription],
 case when a.[LedgerValue] < 0 then a.[LedgerValue] * -1 else '0' end [Debit],
 case when a.[LedgerValue] >= 0 then a.[LedgerValue] else '0' end [Credit]
from
 mst_NSStatement a,
(
select
 a.[FranchiseCode],
 max(a.[Month]) [month]
from
 mst_NSStatement a,
 #Franchise b
where
 a.OpenworkInd = @OpenworkInd and
 a.FranchiseCode = b.FranchiseCode and
 SortCode = '0'
group by
 a.[FranchiseCode]
) b,
 #Franchise c
where
 a.[FranchiseCode] = b.[FranchiseCode] and
 a.[Month] = b.[Month] and
 a.[OpenworkInd] = @OpenworkInd and
 a.FranchiseCode = c.FranchiseCode
union all
select
 '1',
 '9999999',
 '2099-12-31',
 'Temp',
 '',
 sum(case when a.[LedgerValue] < 0 then a.[LedgerValue] * -1 else '0' end) [Debit],
 sum(case when a.[LedgerValue] >= 0 then a.[LedgerValue] else '0' end) [Credit]
from
 mst_NSStatement a,
(
select
 a.[FranchiseCode],
 max(a.[Month]) [Month]
from
 mst_NSStatement a
where
 SortCode = '0'
group by
 a.[FranchiseCode]
) b,
 #Franchise c
where
 a.[FranchiseCode] = b.[FranchiseCode] and
 a.[Month] = b.[Month] and
 a.[OpenworkInd] = @OpenworkInd and
 a.FranchiseCode = c.FranchiseCode and
 a.[SortCode] <> '2'
order by
 1,2


GO
/****** Object:  StoredProcedure [dbo].[mspr_NSSterlingScottEqFeeListing]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[mspr_NSSterlingScottEqFeeListing]

@OpenworkInd   nvarchar(5) = NULL,
@FranchiseCode nvarchar(15),
@Period smalldatetime,
@ScottEq bit,
@MidMonth bit,
@Source nvarchar(10) = NULL,
@ListPosition int = NULL,
@Adviser nvarchar(15),
@UserId NVARCHAR(50)
AS

exec msp_ProcessLog 'Start', 'mspr_NSSterlingScottEqFeeListing', null, null, 'Openwork'

exec mscp_CheckUserVerseFranchiseCode @UserId, @FranchiseCode


IF @Adviser = 'All'
BEGIN
SELECT @Adviser = NULL
END

IF (@ScottEq = 0)
BEGIN
  --SELECT @Source = 'Sterling'
  SELECT @ListPosition = 51
END
ELSE
BEGIN
  --SELECT @Source = 'Scott'
  SELECT @ListPosition = 54
END
IF(@MidMonth = 1)
BEGIN
  --SELECT @Source = 'Mid Month'
  SELECT @ListPosition = 55
END

--if not midmonth and current
IF(((SELECT TOP 1 Month FROM msit_FeesPreSwiftCurrentListing WHERE NOT ListPosition = 55) = @Period) AND @MidMonth = 0 )
  BEGIN
  --if owk
  IF(@OpenworkInd = 'Y')
    BEGIN
      SELECT  CASE WHEN @Adviser = 'All' THEN 'All' ELSE  RTRIM(SellerName) + ' (' + SellerPrefix+SellerSerial+SellerSuffix + ')' END AS Seller,
        Client AS Client, 
        StartDate AS StartDate,
        Policy AS Policy, 
        Premium AS Contribution, 
        Frequency AS Frequency, 
        RemarksString AS Remarks, 
              PayBasis AS PaymentBasis, 
        TotalFees AS TotalFeesThisMonth,
        DateLoaded AS RunDate
      FROM        msit_FeesPreSwiftCurrentListing
      WHERE
        ListPosition=@ListPosition
        AND (SWIFTFranchise = @FranchiseCode) AND SellerID = ISNULL(@Adviser,SellerID)
    END
  --if zan
  ELSE
    BEGIN
      SELECT  CASE WHEN @Adviser = 'All' THEN 'All' ELSE  RTRIM(SellerName) + ' (' + SellerPrefix+SellerSerial+SellerSuffix + ')' END AS Seller,
        Client AS Client, 
        StartDate AS StartDate,
        Policy AS Policy, 
        Premium AS Contribution, 
        Frequency AS Frequency, 
        RemarksString AS Remarks, 
              PayBasis AS PaymentBasis, 
        TotalFees AS TotalFeesThisMonth,
        DateLoaded AS RunDate
      FROM        msit_FeesZanCurrentListing
      WHERE
        ListPosition=@ListPosition
        AND (SWIFTFranchise = @FranchiseCode) AND SellerID = ISNULL(@Adviser,SellerID)
    END
  END
--if midmonth and current
ELSE
IF(((SELECT TOP 1 Month FROM msit_FeesPreSwiftCurrentListing WHERE ListPosition = 55) = @Period) AND @MidMonth = 1 )
  BEGIN
    IF(@OpenworkInd = 'Y')
    BEGIN
      SELECT  CASE WHEN @Adviser = 'All' THEN 'All' ELSE  RTRIM(SellerName) + ' (' + SellerPrefix+SellerSerial+SellerSuffix + ')' END AS Seller,
        Client AS Client, 
        StartDate AS StartDate,
        Policy AS Policy, 
        Premium AS Contribution, 
        Frequency AS Frequency, 
        RemarksString AS Remarks, 
              PayBasis AS PaymentBasis, 
        TotalFees AS TotalFeesThisMonth,
        DateLoaded AS RunDate
      FROM        msit_FeesPreSwiftCurrentListing
      WHERE
        ListPosition=@ListPosition
        AND (SWIFTFranchise = @FranchiseCode) AND SellerID = ISNULL(@Adviser,SellerID)
    END
  --if zan
  ELSE
    BEGIN
      SELECT  CASE WHEN @Adviser = 'All' THEN 'All' ELSE  RTRIM(SellerName) + ' (' + SellerPrefix+SellerSerial+SellerSuffix + ')' END AS Seller,
        Client AS Client, 
        StartDate AS StartDate,
        Policy AS Policy, 
        Premium AS Contribution, 
        Frequency AS Frequency, 
        RemarksString AS Remarks, 
              PayBasis AS PaymentBasis, 
        TotalFees AS TotalFeesThisMonth,
        DateLoaded AS RunDate
      FROM        msit_FeesZanCurrentListing
      WHERE
        ListPosition=@ListPosition
        AND (SWIFTFranchise = @FranchiseCode) AND SellerID = ISNULL(@Adviser,SellerID)
    END
  END

--else normal processing
ELSE
BEGIN
SELECT  CASE WHEN @Adviser = 'All' THEN 'All' ELSE  RTRIM(SellerName) + ' (' + SellerPrefix+SellerSerial+SellerSuffix + ')' END AS Seller,
    Client AS Client, 
    StartDate AS StartDate,
    Policy AS Policy, 
    Premium AS Contribution, 
    Frequency AS Frequency, 
    RemarksString AS Remarks, 
        PayBasis AS PaymentBasis, 
    TotalFees AS TotalFeesThisMonth,
    DateLoaded AS RunDate
FROM        msit_FeesNonSWIFTFeeListing
WHERE
  ListPosition=@ListPosition
  AND (SWIFTFranchise = @FranchiseCode) AND (ISNULL(@OpenworkInd,'N') = ISNULL(OpenworkInd,'N'))
  AND [Month] = @Period AND SellerID = ISNULL(@Adviser,SellerID)
END
exec msp_ProcessLog 'Start', 'mspr_NSSterlingScottEqFeeListing', null, null, 'Openwork'


GO
/****** Object:  StoredProcedure [dbo].[mspr_NSZANSummary]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[mspr_NSZANSummary]

@OpenworkInd   nvarchar(5) = NULL,
@FranchiseCode nvarchar(15),
@Period smalldatetime,
@Adviser nvarchar(15),
@UserId NVARCHAR(50)
AS

exec msp_ProcessLog 'Start', 'mspr_NSZANSummary', null, null, 'Openwork'

exec mscp_CheckUserVerseFranchiseCode @UserId, @FranchiseCode

DECLARE @FeeListingSum FLOAT
DECLARE @SterlingSum FLOAT
DECLARE @MidMonthSum FLOAT
DECLARE @NewFeeSum FLOAT
DECLARE @RenewalsSum FLOAT
DECLARE @FeeListingCount INT
DECLARE @SterlingCount INT
DECLARE @MidMonthCount INT
DECLARE @NewFeeCount INT
DECLARE @RenewalCount INT
DECLARE @Seller nvarchar(100)


--Is the requested month in the current month table
IF((SELECT TOP 1 Month FROM msit_FeesPreSwiftCurrentListing WHERE NOT ListPosition = 55) = @Period)
  BEGIN
    IF @Adviser = 'All'
    BEGIN
    SELECT *
      INTO #AllCurrentSellers
      FROM msit_FeesZanCurrentListing
      WHERE SWIFTFranchise = @FranchiseCode
    
    SELECT @Seller = 'All'
    
    
    SELECT @FeeListingSum =  ISNULL(SUM(Value4),0) + ISNULL(SUM(Value2),0) + ISNULL(SUM(UpliftIT),0)+ ISNULL(SUM(UpliftAccr),0),
         @FeeListingCount = COUNT(*)
    From #AllCurrentSellers 
    WHERE  (ListPosition = 0 OR ListPosition = 1 OR ListPosition = 2 OR ListPosition = 3 OR ListPosition = 5)
      
    
    SELECT @SterlingSum =  SUM(TotalFees),
         @SterlingCount = COUNT(*)
    From #AllCurrentSellers 
    WHERE  ListPosition = 51
    
    
    SELECT @NewFeeSum = ISNULL(SUM(ITAdvance),0) + ISNULL(SUM(EnhancementAccr),0),
        @NewFeeCount = COUNT(*)
    From #AllCurrentSellers
    WHERE ListPosition = 100

    END
    ELSE
    BEGIN
    SELECT *
      INTO #SingleCurrentSeller
      FROM msit_FeesZanCurrentListing
      WHERE SWIFTFranchise = @FranchiseCode
      AND SellerID = @Adviser
    
    SELECT @FeeListingSum =  ISNULL(SUM(Value4),0) + ISNULL(SUM(Value2),0) + ISNULL(SUM(UpliftIT),0)+ ISNULL(SUM(UpliftAccr),0),
         @FeeListingCount = COUNT(*)
    From  #SingleCurrentSeller 
    WHERE  (ListPosition = 0 OR ListPosition = 1 OR ListPosition = 2 OR ListPosition = 3 OR ListPosition = 5)
      
    
    SELECT @SterlingSum =  SUM(TotalFees),
         @SterlingCount = COUNT(*)
    From #SingleCurrentSeller 
    WHERE  ListPosition = 51
    
    
    SELECT @NewFeeSum = ISNULL(SUM(ITAdvance),0) + ISNULL(SUM(EnhancementAccr),0),
        @NewFeeCount = COUNT(*)
    From #SingleCurrentSeller
    WHERE ListPosition = 100
    
    
    SELECT @Seller = (SELECT TOP 1 RTRIM( RTRIM(SellerName)) + ' (' + SellerPrefix+SellerSerial+SellerSuffix + ')' FROM #SingleCurrentSeller) 
    END
  END
  ELSE
  BEGIN
    IF @Adviser = 'All'
    BEGIN
    SELECT *
      INTO #AllSellers
      FROM msit_FeesNonSWIFTFeeListing
      WHERE [Month] = @Period
      AND SWIFTFranchise = @FranchiseCode
      AND ISNULL(@OpenworkInd,'N') = ISNULL(OpenworkInd,'N')
    
    SELECT @Seller = 'All'
    
    
    SELECT @FeeListingSum =  ISNULL(SUM(Value4),0) + ISNULL(SUM(Value2),0) + ISNULL(SUM(UpliftIT),0)+ ISNULL(SUM(UpliftAccr),0),
         @FeeListingCount = COUNT(*)
    From #AllSellers 
    WHERE  (ListPosition = 0 OR ListPosition = 1 OR ListPosition = 2 OR ListPosition = 3 OR ListPosition = 5)
      
    
    SELECT @SterlingSum =  SUM(TotalFees),
         @SterlingCount = COUNT(*)
    From #AllSellers 
    WHERE  ListPosition = 51
    
    
    SELECT @NewFeeSum = ISNULL(SUM(ITAdvance),0) + ISNULL(SUM(EnhancementAccr),0),
        @NewFeeCount = COUNT(*)
    From #AllSellers
    WHERE ListPosition = 100

    END
    ELSE
    BEGIN
    SELECT *
      INTO #SingleSeller
      FROM msit_FeesNonSWIFTFeeListing
      WHERE [Month] = @Period
      AND SWIFTFranchise = @FranchiseCode
      AND ISNULL(@OpenworkInd,'N') = ISNULL(OpenworkInd,'N')
      AND SellerID = @Adviser
    
    SELECT @FeeListingSum =  ISNULL(SUM(Value4),0) + ISNULL(SUM(Value2),0) + ISNULL(SUM(UpliftIT),0)+ ISNULL(SUM(UpliftAccr),0),
         @FeeListingCount = COUNT(*)
    From  #SingleSeller 
    WHERE  (ListPosition = 0 OR ListPosition = 1 OR ListPosition = 2 OR ListPosition = 3 OR ListPosition = 5)
      
    
    SELECT @SterlingSum =  SUM(TotalFees),
         @SterlingCount = COUNT(*)
    From #SingleSeller 
    WHERE  ListPosition = 51
    
    
    SELECT @NewFeeSum = ISNULL(SUM(ITAdvance),0) + ISNULL(SUM(EnhancementAccr),0),
        @NewFeeCount = COUNT(*)
    From #SingleSeller
    WHERE ListPosition = 100
    
    
    SELECT @Seller = (SELECT TOP 1 RTRIM( RTRIM(SellerName)) + ' (' + SellerPrefix+SellerSerial+SellerSuffix + ')' FROM #SingleSeller) 
    END
  END

SELECT 
ISNULL(@FeeListingSum,0.0) AS FeeListingSum,
ISNULL(@SterlingSum,0.0) AS SterlingSum,
ISNULL(@MidMonthSum,0.0) AS MidMonthSum,
ISNULL(@NewFeeSum,0.0) AS NewFeeSum,
ISNULL(@RenewalsSum,0.0) AS RenewalsSum,
@FeeListingCount AS FeeListingCount,
@SterlingCount AS SterlingCount,
@MidMonthCount AS MidMonthCount,
@NewFeeCount AS NewFeeCount,
@RenewalCount AS RenewalCount,
ISNULL(@Seller,'') AS Seller

exec msp_ProcessLog 'End', 'mspr_NSZanSummary', null, null, 'Openwork'

GO
