create procedure [dbo].[mspr_OpenworkBankAccountStatement]
 @FranchiseCode nvarchar(20),
 @Month         datetime,
 @Source        nvarchar(20),
 @UserId    NVARCHAR(20)
as
--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : mspr_NSOrder.sql
-- Owner   : MWA
-- Created : 25/07/2006
--
--########################################################################

if(@Source = 'OWK')
  SELECT @Source= '%'

select
 BusinessCode    = BusinessCode,
 BusinessName    = BusinessName,
 BusinessECode   = BusinessECode,
 [Month]         = [Month],
Source = Source,
 Debits          = case when Amount < 0 then Amount
                        else 0
                   end,
 Credits         = case when Amount > 0 then Amount
                        else 0
                   end,
 TotalAmount     = Amount,
 TransactionDate = TransactionDate,
 PaymentType     = PaymentType,
 TransactionType = TransactionType,
 Description     = Description,
 Notes           = Notes,
 Sequence        = Sequence,
 TotalType       = TotalType,
 SortCode        = SortCode
from
 msit_OpenworkBankDetails
where
 BusinessCode = @FranchiseCode and
 [Month]      = @Month         and
 (Source = @Source or @Source = '%')
 order by
 SortCode,
 Source,
 TransactionDate,
 Sequence,
 TotalType,
 PaymentType
 




