create procedure [dbo].[mspr_OpenworkBankAccountStatementFranchiseList]
 @UserId nvarchar(255),
 @Order  nvarchar(1)
as
--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : mspr_NSOrder.sql
-- Owner   : MWA
-- Created : 25/07/2006
--
--########################################################################

select distinct 
 a.FranchiseCode
into
 #Franchise
from  
 msdt_Adviser a inner join msct_UserAccessControl uac 
    on a.AdviserID = uac.AdviserID
where
 uac.DomainLogin = @UserId

select distinct
 Value = o.BusinessCode,
 Label = case when @Order = '1' then o.BusinessCode + ' - ' + rtrim(o.BusinessName)
              else rtrim(o.BusinessName) + ' - ' + o.BusinessCode 
         end
from
 msit_OpenworkBankDetails o,
 #Franchise fr
where
 o.BusinessCode = fr.FranchiseCode
order by
 2 asc


