create procedure [dbo].[mspr_OpenworkBankAccountStatementSourceList]
 @FranchiseCode nvarchar(20),
 @Month         datetime
as
--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : mspr_NSOrder.sql
-- Owner   : MWA
-- Created : 25/07/2006
--
--########################################################################

declare
 @StartDate     datetime,
 @EndDate       datetime

select
 @StartDate = PeriodStartDate,
 @EndDate   = PeriodEndDate
from
 msit_CommissionStatementPeriods
where
 [Month] = @Month

select distinct
 Value = Source,
 Label = Source,
 OrderValue = 1
