CREATE Procedure [dbo].[mspr_OpenworkFranchiseListWeb]
@FranchiseCode VARCHAR(10)
AS

IF(NOT EXISTS (SELECT
TOP 1 rtrim(BusinessName) + ' - ' + BusinessCode AS FranchiseName
FROM   
 msit_OpenworkAdviserListing
WHERE BusinessCode = @FranchiseCode))
BEGIN
  RAISERROR ('This franchise has no data for this period.',16, 1)
END
ELSE
BEGIN
SELECT
TOP 1 rtrim(BusinessName) + ' - ' + BusinessCode AS FranchiseName
FROM   
 msit_OpenworkAdviserListing
WHERE BusinessCode = @FranchiseCode
END

