CREATE procedure [dbo].[mspr_PaymentStatus]
 @Month datetime
as
--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : mspr_NSOrder.sql
-- Owner   : MWA
-- Created : 25/07/2006
--
--########################################################################


select
 PaymentStatus = case when CAST(CONVERT(NVARCHAR,PeriodEndDate,112) AS
DATETIME) < CAST(CONVERT(NVARCHAR,getdate(),112) AS DATETIME) then '(Paid)'
                      else '(Awaiting Payment)'
                 end
from
 msit_CommissionStatementPeriods

where
 [Month] = @Month



