create procedure [dbo].[mspr_PeriodData]
 @Month datetime
as
--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : mspr_NSOrder.sql
-- Owner   : MWA
-- Created : 25/07/2006
--
--########################################################################

-- CODE TO SET THE PERIOD TO CURRENT DATE IF THE END PERIOD IF GREATER THAN CURRENT DATE
declare
 @EndDate datetime

select
 @EndDate = case when getdate() > PeriodEndDate then PeriodEndDate
                 else getdate()
            end
from
 msit_CommissionStatementPeriods
where
 [Month] = @Month

select
 Period   = convert(nvarchar(10), PeriodStartDate, 103) + ' to ' + convert(nvarchar(10), PeriodEndDate, 103),
 AsAtDate = convert(nvarchar(10), @EndDate, 103)
from 
 msit_CommissionStatementPeriods
where
 [Month] = @Month


