select
 Value      = [Month],
 Label      = convert(char(20), MonthName) + '' + 'Dates From: ' + convert(varchar(11),PeriodStartDate) + ' - ' + convert(varchar(11),PeriodEndDate),
 PrintLabel = MonthName,
 Start      = convert(varchar(10),PeriodStartDate,103),
 EndDate    = convert(varchar(10),PeriodEndDate,103)
from 
