/************************************************************************************************
  	 Program:  	mspr_Renewals_Laboris_To_NonSWIFTRenewalListing					
	  Author:	A Groves
Date created:	30/10/2017

Subject Area:	Legacy Month End
Subject Unit:	Quarterly Renewals

		Type:	SR464996/CH16204. This change was to migrate the Legacy Month End process from 
				DTS to SSIS. In particular, this proc relates to the quarterly renewals.
				The relevant scripts are:
				DTS:	Zurich_Openwork_FeesRenewals_Import
				SSIS:	LegacyMonthEndRenewalImport.dtsx
				The DTS scripts did a lot more work in terms of mapped table-to-table uploads and
				running stored procs after the flat files were loaded. The uploads and stored proc
				executions were kept out of the SSIS script (to keep it simple) and were instead
				placed in the SQL Agent Job. Where mapped table-to-table uploads occurred, these
				were re-written in stored procs. This proc is one such example. 
		
		
 Description:   This proc populates table "msit_NSLaboris" from table "msit_FeesNonSWIFTRenewalListing".
				
				It is called as follows:

					exec mspr_Renewals_Laboris_To_NonSWIFTRenewalListing 'Openwork', 'NSQuarterly'
									
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			

************************************************************************************************/

CREATE PROCEDURE [dbo].[mspr_Renewals_Laboris_To_NonSWIFTRenewalListing]
	@Client		varchar(50),
	@Module		Varchar(50)
AS

set nocount on

declare		@PhaseStart								varchar(50),
			@PhaseEnd								varchar(50),
			@PhaseLog								varchar(50),
			@PhaseError								varchar(50),
			@Message								varchar(100),
			@ProcName								varchar(100)
			
/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @ProcName			= object_name(@@procid)
set @PhaseStart			= 'START'
set @PhaseEnd   		= 'END'
set @PhaseLog			= 'LOG'
set @PhaseError			= 'ERROR'

exec msp_ProcessLog @PhaseStart, @ProcName, null, @Module, @Client

/****************************************************************************

	Insert table data

****************************************************************************/

insert into dbo.msit_FeesNonSWIFTRenewalListing
(
	SWIFTFranchise,
	SWIFTSeller,
	OpenworkInd,
	SellerPrefix,
	SellerSerial,
	SellerSuffix,
	SellerID,
	SellerName,
	FranchisePrefix,
	FranchiseSerial,
	FranchiseSuffix,
	FranchiseID,
	Client,
	StartDate,
	RunDate,
	Policy,
	AgentSplit,
	Premium,
	Frequency,
	CommRateStd,
	CommRateTrue,
	UpliftFeeAccr,
	UpliftFeeIT,
	Value1,
	Value2,
	Value3,
	RemarksString,
	ListPosition,
	DateLoaded,
	Month,
	Source
)
select	SWIFTFranchise,
		SWIFTSeller,
		OpenworkInd,
		SellerPrefix,
		SellerSerial,
		SellerSuffix,
		SellerID,
		SellerName,
		FranchisePrefix,
		FranchiseSerial,
		FranchiseSuffix,
		FranchiseID,
		Client,
		StartDate,
		RunDate,
		Policy,
		AgentSplit,
		Premium,
		Frequency,
		CommRateStd,
		CommRateTrue,
		UpliftFeeAccr,
		UpliftFeeIT,
		Value1,
		Value2,
		Value3,
		RemarksString,
		ListPosition,
		DateLoaded,
		Month,
		Source
from	dbo.msit_NSLaboris

/****************************************************************************

			E N D															

****************************************************************************/

exec msp_ProcessLog @PhaseEnd, @ProcName, null, @Module, @Client

GO
