				executions were kept out of the SSIS script (to keep it simple) and were instead
				placed in the SQL Agent Job. Where mapped table-to-table uploads occurred, these
				were re-written in stored procs. This proc is one such example. 
		
		
 Description:   This proc populates table "msit_NSLaboris" from table "msit_Fees_RenewalsListing".
				
				It is called as follows:

					exec mspr_Renewals_RenewalsListing_To_Laboris 'Openwork', 'NSQuarterly'
									
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			

************************************************************************************************/

CREATE PROCEDURE [dbo].[mspr_Renewals_RenewalsListing_To_Laboris]
	@Client		varchar(50),
	@Module		Varchar(50)
AS

set nocount on

declare		@PhaseStart								varchar(50),
			@PhaseEnd								varchar(50),
			@PhaseLog								varchar(50),
			@PhaseError								varchar(50),
			@Message								varchar(100),
			@ProcName								varchar(100),
			@RowCount								int,
			@DateLoaded								datetime = getdate()
			
/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @ProcName			= object_name(@@procid)
set @PhaseStart			= 'START'
set @PhaseEnd   		= 'END'
set @PhaseLog			= 'LOG'
set @PhaseError			= 'ERROR'

exec msp_ProcessLog @PhaseStart, @ProcName, null, @Module, @Client

/****************************************************************************

	Insert table data

****************************************************************************/

--Note: Table dbo.msit_NSLaboris is truncated by the SSIS script. 

insert into dbo.msit_NSLaboris
(
	SWIFTFranchise,
	SWIFTSeller,
	OpenworkInd,
	SellerPrefix,
	SellerSerial,
	SellerSuffix,
	SellerID,
	SellerName,
	FranchisePrefix,
	FranchiseSerial,
	FranchiseSuffix,
	FranchiseID,
	ClientForename,
	ClientSurname,
	Client,
	ApplicationDate,
	DeclarationDate,
	StartDate,
	RunDate,
	OrigBranch,
	PolicySerial,
	Member,
	ProductCode,
	Policy,
	Provider,
	SequenceNo,
	SliceNo,
	AgentSplit,
	Premium,
	Frequency,
	IncreaseInd,
	FlexInd,
	InitialPeriod,
	CommRateStd,
	CommRateTrue,
	NPWInd,
	ITInd,
	CommType,
	CommBasis,
	CommBasisDesc,
	EnhancementRate,
	EnhancementAccr,
	StillLeftToAccrue,
	ITAdvance,
	ITAccrued,
	ITLiability,
	UpliftFeeAccr,
	UpliftFeeIT,
	Value1,
	Value2,
	Value3,
	Value4,
	Value5,
	Value6,
	RemarksString,
	ProdFactor,
	ProdCred,
	PayBasis,
	TotalFees,
	IssuedInd,
	CommEnh,
	TotBaseCommStd,
	TotBaseCommTrue,
	CommNotEnhanced,
	UpliftRate,
	UpliftAccr,
	UpliftIT,
	FileID,
	ListPosition,
	DateLoaded,
	Month,
	Source,
	RemarkCode1,
	RemarksData1,
	RemarkCode2,
	RemarksData2,
	RemarkCode3,
	RemarksData3,
	RemarkCode4,
	RemarksData4,
	RemarkCode5,
	RemarksData5,
	RemarkCode6,
	RemarksData6,
	--BACSDate,		This column is populated by a default setting on the table.
	BIRemarks
)
select 	null as SWIFTFranchise,
		null as SWIFTSeller,
		case when OW_IND = ''	--This coding gives the same results as the DTS script, although the use of ISNULL may have given better results.
			then 'N'
			else OW_IND
		end as OpenworkInd,
		null as SellerPrefix,
		SELLER_SERIAL as SellerSerial,
		null as SellerSuffix,
		null as SellerID,
		null as SellerName,
		MAIN_PREFIX as FranchisePrefix,
		MAIN_SERIAL as FranchiseSerial,
		MAIN_SUFFIX as FranchiseSuffix,
		null as FranchiseID,
		CLIENT_FORENAME as ClientForename,
		CLIENT_SURNAME as ClientSurname,
		CLIENT_SURNAME + ' ' + CLIENT_FORENAME as Client,
		null as ApplicationDate,
		null as DeclarationDate,
		START_DATE as StartDate,
		null as RunDate,
		ORIGINAL_BRANCH as OrigBranch,
		SERIAL as PolicySerial,
		MEMBER as Member,
		PRODUCT_CODE as ProductCode,
		case when MEMBER = '   '
		then 
			case when ORIGINAL_BRANCH = '   '
				then SERIAL + '-' + PRODUCT_CODE
				else SERIAL + '-' + ORIGINAL_BRANCH + '-' + PRODUCT_CODE
			end			 
		else 
			case when ORIGINAL_BRANCH = '   '
				then SERIAL + '/' + MEMBER
				else SERIAL + '-' + ORIGINAL_BRANCH + '/' + MEMBER
			end
		end as Policy,
		null as Provider,
		SEQUENCE_NO as SequenceNo,
		SLICE_NO as SliceNo,
		SPLIT_PROPN as AgentSplit,
		YEARLY_PREMIUM as Premium,
		FREQUENCY as Frequency,
		null as IncreaseInd,
		DEAL_IND as FlexInd,
		INITIAL_PERIOD as InitialPeriod,
		case when COMM_RATE_STD > 0
			then COMM_RATE_STD
			else COMM_RATE_TRUE
		end as CommRateStd,
		COMM_RATE_TRUE as CommRateTrue,
		NPW_IND as NPWInd,
		INDEMN_TERMS_IND as ITInd,
		COMMISSION_TYPE as CommType,
		null as CommBasis,
		null as CommBasisDesc,
		null as EnhancementRate,
		null as EnhancementAccr,
		null as StillLeftToAccrue,
		null as ITAdvance,
		null as ITAccrued,
		null as ITLiability,
		null as UpliftFeeAccr,
		null as UpliftFeeIT,
		VALUE_1 as Value1,
		VALUE_2 as Value2,
		VALUE_3 as Value3,
		VALUE_4 as Value4,
		VALUE_5 as Value5,
		VALUE_6 as Value6,
		REMARK_STRING as RemarksString,
		PROD_FACTOR as ProdFactor,
		PROD_CRED_FACTOR as ProdCred,
		null as PayBasis,
		null as TotalFees,
		null as IssuedInd,
		null as CommEnh,
		null as TotBaseCommStd,
		null as TotBaseCommTrue,
		null as CommNotEnhanced,
		null as UpliftRate,
		null as UpliftAccr,
		null as UpliftIT,
		PAGE_TYPE as FileID,
		60 as ListPosition,
		@DateLoaded	as DateLoaded,
		Period as Month,
		'Renewals' as Source,
		null as RemarkCode1,
		null as RemarksData1,
		null as RemarkCode2,
		null as RemarksData2,
		null as RemarkCode3,
		null as RemarksData3,
		null as RemarkCode4,
		null as RemarksData4,
		null as RemarkCode5,
		null as RemarksData5,
		null as RemarkCode6,
		null as RemarksData6,
		--null as BACSDate,		This column is populated by a default setting on the table.
		null as BIRemarks
from	dbo.msit_Fees_RenewalsListing


/****************************************************************************

			E N D															

****************************************************************************/

exec msp_ProcessLog @PhaseEnd, @ProcName, null, @Module, @Client

GO
