CREATE PROCEDURE [dbo].[mspr_SetUpFranchiseIDs]
AS
/******************************************************************************
Summary	: Add process events to Log Table (ProcessLog)
Author	: ghope
Created	: 18/11/2005

Amended 
Nov 2007 - to use new xref table

09/08/2012	SR173849 Mike Cawood		
			a) Convert Join to SQL2005 standards
			b) Insert entries with NULL FranchiseID onto new table
				msit_FeesNonSwiftFeeListing_NotLoaded

*******************************************************************************/

UPDATE msit_NSLaboris 
SET msit_NSLaboris.FranchiseID = o.OSCAR_ID,
	msit_NSLaboris.SWIFTFranchise = o.AgentCode
FROM msit_NSLaboris L												--SR173849(a): MPC 09/08/2012
inner join Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref o		--SR173849(a): MPC 09/08/2012
	ON L.FranchiseSerial = o.OSCAR_Serial AND o.AgentLevel = 'B'	--SR173849(a): MPC 09/08/2012

--SR173849(b): MPC 09/08/2012: START 
INSERT into msit_FeesNonSWIFTFeeListing_NotLoaded
	  (SWIFTFranchise,SWIFTSeller,OpenworkInd,SellerPrefix,SellerSerial,SellerSuffix,SellerID,SellerName,FranchisePrefix,FranchiseSerial,FranchiseSuffix,FranchiseID,ClientForename,ClientSurname,Client,ApplicationDate,DeclarationDate,StartDate,RunDate,OrigBranch,PolicySerial,Member,ProductCode,Policy,Provider,SequenceNo,SliceNo,AgentSplit,Premium,Frequency,IncreaseInd,FlexInd,InitialPeriod,CommRateStd,CommRateTrue,NPWInd,ITInd,CommType,CommBasis,CommBasisDesc,EnhancementRate,EnhancementAccr,StillLeftToAccrue,ITAdvance,ITAccrued,ITLiability,UpliftFeeAccr,UpliftFeeIT,Value1,Value2,Value3,Value4,Value5,Value6,RemarksString,ProdFactor,ProdCred,PayBasis,TotalFees,IssuedInd,CommEnh,TotBaseCommStd,TotBaseCommTrue,CommNotEnhanced,UpliftRate,UpliftAccr,UpliftIT,FileID,ListPosition,DateLoaded,Month,Source,RemarkCode1,RemarksData1,RemarkCode2,RemarksData2,RemarkCode3,RemarksData3,RemarkCode4,RemarksData4,RemarkCode5,RemarksData5,RemarkCode6,RemarksData6,BACSDate,BIRemarks)
Select SWIFTFranchise,SWIFTSeller,OpenworkInd,SellerPrefix,SellerSerial,SellerSuffix,SellerID,SellerName,FranchisePrefix,FranchiseSerial,FranchiseSuffix,FranchiseID,ClientForename,ClientSurname,Client,ApplicationDate,DeclarationDate,StartDate,RunDate,OrigBranch,PolicySerial,Member,ProductCode,Policy,Provider,SequenceNo,SliceNo,AgentSplit,Premium,Frequency,IncreaseInd,FlexInd,InitialPeriod,CommRateStd,CommRateTrue,NPWInd,ITInd,CommType,CommBasis,CommBasisDesc,EnhancementRate,EnhancementAccr,StillLeftToAccrue,ITAdvance,ITAccrued,ITLiability,UpliftFeeAccr,UpliftFeeIT,Value1,Value2,Value3,Value4,Value5,Value6,RemarksString,ProdFactor,ProdCred,PayBasis,TotalFees,IssuedInd,CommEnh,TotBaseCommStd,TotBaseCommTrue,CommNotEnhanced,UpliftRate,UpliftAccr,UpliftIT,FileID,ListPosition,DateLoaded,Month,Source,RemarkCode1,RemarksData1,RemarkCode2,RemarksData2,RemarkCode3,RemarksData3,RemarkCode4,RemarksData4,RemarkCode5,RemarksData5,RemarkCode6,RemarksData6,BACSDate,BIRemarks
FROM msit_NSLaboris WHERE msit_NSLaboris.FranchiseID IS NULL
--SR173849(b): MPC 09/08/2012: END 

DELETE FROM msit_NSLaboris WHERE msit_NSLaboris.FranchiseID IS NULL;
GO
