GO
SET QUOTED_IDENTIFIER ON
GO

create procedure [dbo].[mspr_SourceList]
 @FranchiseCode nvarchar(20),
 @Month         datetime
as
--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : mspr_NSOrder.sql
-- Owner   : MWA
-- Created : 25/07/2006
--
--########################################################################

declare
 @StartDate     datetime,
 @EndDate       datetime

select
 @StartDate = PeriodStartDate,
 @EndDate   = PeriodEndDate
from
 msit_CommissionStatementPeriods
where
 [Month] = @Month

select distinct
 Value = Source,
 Label = Source,
 OrderValue = 1
from
 msit_OpenworkAdviserListing
where
 BusinessCode = @FranchiseCode   and
 [Month]      between @StartDate and @EndDate
union
select
 Value      = '%',
 Label      = 'All',
 OrderValue = 0 
order by
3, 2 asc


GO
/****** Object:  StoredProcedure [dbo].[mspr_TestNonSWIFTFranchiseCodes]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[mspr_TestNonSWIFTFranchiseCodes]
@LoginName NVARCHAR(50),
@OpenworkInd nvarchar(5) = NULL,
@ListPosition1 INT = NULL, 
@ListPosition2 INT = NULL, 
@ListPosition3 INT = NULL,
@ListPosition4 INT = NULL,
@ListPosition5 INT = NULL,
@ListPosition6 INT = NULL,
@ListPosition7 INT = NULL,
@ListPosition8 INT = NULL,
@ListPosition9 INT = NULL,
@ListPosition10 INT = NULL
as
DECLARE @Franchises TABLE(Code nvarchar(255)COLLATE latin1_General_CI_AS)
INSERT INTO @Franchises
SELECT  DISTINCT a.FranchiseCode
FROM  msdt_Adviser a 
  INNER JOIN msct_UserAccessControl uac 
    ON a.AdviserID = uac.AdviserID
--WHERE  @LoginName LIKE  '%'+uac.DomainLogin 
WHERE  @LoginName = uac.DomainLogin
select distinct (mstt_Agents.Code) AS Value,
CASE WHEN mstt_Agents.TradingName IS NULL THEN RTRIM(mstt_Agents.DESCN) ELSE RTRIM(mstt_Agents.TradingName) END   AS Label,
mstt_Agents.OSCARDateStarted AS DateStarted,
mstt_Agents.OSCARAgentPrefix +  mstt_Agents.OSCARAgentSerial + mstt_Agents.OSCARAgentSuffix AS AgentCode,
sf.[Month],
sf.SellerPrefix + sf.SellerSerial + SellerSuffix + '-' + SellerName As Seller,
sf.SellerID AS SellerID
from
mstt_Agents 
LEFT OUTER JOIN @Franchises f ON mstt_Agents.Code = f.Code
LEFT OUTER JOIN msit_FeesNonSWIFTFeeListing sf WITH (INDEX = IX_msit_FeesNonSWIFTFeeListing_6)  
ON mstt_Agents.Code = sf.SwiftFranchise
--select distinct 
--CASE WHEN mstt_Agents.TradingName IS NULL THEN RTRIM(mstt_Agents.DESCN) + SPACE(5) +'(' + mstt_Agents.CODE + ')' ELSE RTRIM(mstt_Agents.TradingName) + SPACE(5) +'(' + mstt_Agents.CODE + ')' END   AS Label,
--mstt_Agents.CODE AS Value,
--mstt_Agents.OSCARDateStarted AS DateStarted,
--mstt_Agents.OSCARAgentPrefix +  mstt_Agents.OSCARAgentSerial + mstt_Agents.OSCARAgentSuffix AS AgentCode
--from
--mstt_Agents 
--LEFT OUTER JOIN @Franchises f ON mstt_Agents.Code = f.Code
--LEFT OUTER JOIN msit_FeesNonSWIFTFeeListing sf WITH (INDEX = IX_msit_FeesNonSWIFTFeeListing_8)  ON mstt_Agents.Code = sf.SwiftFranchise
WHERE (mstt_Agents.CODE IN
(
  f.Code
))
AND
(
(
  sf.ListPosition=@ListPosition1 OR
  sf.ListPosition=@ListPosition2 OR
  sf.ListPosition=@ListPosition3 OR
  sf.ListPosition=@ListPosition4 OR
  sf.ListPosition=@ListPosition5 OR
  sf.ListPosition=@ListPosition6 OR
  sf.ListPosition=@ListPosition7 OR
  sf.ListPosition=@ListPosition8 OR
  sf.ListPosition=@ListPosition9 OR
  sf.ListPosition=@ListPosition10
)
AND ISNULL(sf.OpenworkInd,'N') = @OpenworkInd AND NOT sf.[Month] IS NULL
)
ORDER BY Label,sf.[Month] DESC ,SellerID

GO
