/****** Object:  StoredProcedure [dbo].[mspr_UpdateSellerDetails]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/****************************************************************************************

Copyright (C) Moore Stephens Consulting Limited 2005

Summary : Add process events to Log Table (ProcessLog)
Author  : ghope
Created : 18/11/2005

AMENDMENT HISTORY
=================

Date		Author		Description
----		------		-----------
03/03/2015	A Groves	SR366515 - Correct the derivation of the Seller ECode
						Suffix which has always been incorrect. Issue identified
						by Brian Goldich whose ECode showed as E75853M but should
						have been E75853F.
						Also introduced logging to mst_ProcessLog to help track
						progress.
*****************************************************************************************/


CREATE PROCEDURE [dbo].[mspr_UpdateSellerDetails]

AS


exec msp_ProcessLog 'START', 'mspr_UpdateSellerDetails', null, 'ImportMonthly', 'Openwork'	-- AG 03/03/2015


UPDATE msit_NSLaboris
SET msit_NSLaboris.SellerID = x.OSCAR_ID,
  msit_NSLaboris.SellerPrefix = x.OSCAR_Prefix,
  msit_NSLaboris.SellerSuffix = x.OSCAR_Suffix,
  msit_NSLaboris.SWIFTSeller = x.AgentCode
FROM Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref x
WHERE msit_NSLaboris.SellerSerial = x.OSCAR_Serial AND x.AgentLevel = 'S' and msit_NSLaboris.FranchiseSerial = x.Business_OSCAR_SERIAL 


UPDATE msit_NSLaboris
SET msit_NSLaboris.SellerName = mstt_Agents.DESCN
FROM mstt_Agents
WHERE (msit_NSLaboris.SWIFTSeller = mstt_Agents.CODE ) AND SellerName IS NULL


UPDATE msit_NSLaboris
SET msit_NSLaboris.SellerID = msit_AgentInfo.Agent_ID,
  msit_NSLaboris.SellerPrefix =msit_AgentInfo.MAIN_PREFIX,
  msit_NSLaboris.SellerSuffix = msit_AgentInfo.MAIN_SUFFIX,
  msit_NSLaboris.SellerName = msit_AgentInfo.FULLNAME
FROM msit_AgentInfo
WHERE(msit_NSLaboris.SellerSerial = msit_AgentInfo.MAIN_SERIAL) AND  (msit_NSLaboris.SellerName IS NULL) 


DECLARE @TempAgentTable TABLE
(
SellerSerial nvarchar(255) COLLATE latin1_General_CI_AS,
AgentID float(8),
SellerPrefix nvarchar (10),
SellerSuffix nvarchar(10),
FullName nvarchar(255)
)

INSERT INTO @TempAgentTable
-- AG 03/03/2015 Start
SELECT		dbo.msit_ContractDetails.AGENT_SERIAL, 
			dbo.msit_AgentInfo.Agent_ID, 
			case when dbo.msit_ContractDetails.AGENT_SERIAL is not null
				then dbo.msit_ContractDetails.AGENT_PREFIX
				else dbo.msit_AgentInfo.MAIN_PREFIX
			end, 
			case when dbo.msit_ContractDetails.AGENT_SERIAL is not null
				then dbo.msit_ContractDetails.AGENT_SUFFIX
				else dbo.msit_AgentInfo.MAIN_SUFFIX
			end, 
			dbo.msit_AgentInfo.FULLNAME
--SELECT    dbo.msit_ContractDetails.AGENT_SERIAL, dbo.msit_AgentInfo.Agent_ID, dbo.msit_AgentInfo.MAIN_PREFIX, dbo.msit_AgentInfo.MAIN_SUFFIX, dbo.msit_AgentInfo.FULLNAME
-- AG 03/03/2015 End
FROM         dbo.msit_AgentInfo LEFT OUTER JOIN
                      dbo.msit_ContractDetails ON dbo.msit_AgentInfo.AGENT_ID = dbo.msit_ContractDetails.AGENT_ID


UPDATE msit_NSLaboris
SET msit_NSLaboris.SellerID =a.AgentID,
  msit_NSLaboris.SellerPrefix = a.SellerPrefix,
  msit_NSLaboris.SellerSuffix = a.SellerSuffix,
  msit_NSLaboris.SellerName =a.FullName
FROM @TempAgentTable a
WHERE (msit_NSLaboris.SellerSerial = a.SellerSERIAL) AND (msit_NSLaboris.SellerName IS NULL)


UPDATE msit_NSLaboris
SET msit_NSLaboris.SellerName = CASE msit_NSLaboris.SellerSerial WHEN a.SellerSerial THEN 'Seller Not Identified' + '(' + a.SellerPrefix + msit_NSLaboris.SellerSerial + a.SellerSuffix + ')'
ELSE  'Seller Not Identified' + '(' + msit_NSLaboris.SellerSerial+ ')' END
FROM @TempAgentTable a
WHERE   (msit_NSLaboris.SellerSerial = a.SellerSerial)  and (msit_NSLaboris.SellerName IS NULL)


exec msp_ProcessLog 'END', 'mspr_UpdateSellerDetails', null, 'ImportMonthly', 'Openwork'	-- AG 03/03/2015
GO
