CREATE PROCEDURE [dbo].[mspr_UpdateSellerDetails_Reload]

AS



UPDATE msit_NSLaboris_Reload
SET msit_NSLaboris_Reload.SellerID = x.OSCAR_ID,
  msit_NSLaboris_Reload.SellerPrefix = x.OSCAR_Prefix,
  msit_NSLaboris_Reload.SellerSuffix = x.OSCAR_Suffix,
  msit_NSLaboris_Reload.SWIFTSeller = x.AgentCode
FROM Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref x
WHERE msit_NSLaboris_Reload.SellerSerial = x.OSCAR_Serial AND x.AgentLevel = 'S' and msit_NSLaboris_Reload.FranchiseSerial = x.Business_OSCAR_SERIAL 


UPDATE msit_NSLaboris_Reload
SET msit_NSLaboris_Reload.SellerName = mstt_Agents.DESCN
FROM mstt_Agents
WHERE (msit_NSLaboris_Reload.SWIFTSeller = mstt_Agents.CODE ) AND SellerName IS NULL


UPDATE msit_NSLaboris_Reload
SET msit_NSLaboris_Reload.SellerID = a.Agent_ID,
  msit_NSLaboris_Reload.SellerPrefix = a.MAIN_PREFIX,
  msit_NSLaboris_Reload.SellerSuffix = a.MAIN_SUFFIX,
  msit_NSLaboris_Reload.SellerName = a.FULLNAME
FROM msit_AgentInfo_Reload a
WHERE(msit_NSLaboris_Reload.SellerSerial = a.MAIN_SERIAL) AND  (msit_NSLaboris_Reload.SellerName IS NULL) 



DECLARE @TempAgentTable TABLE
(
SellerSerial nvarchar(255) COLLATE latin1_General_CI_AS,
AgentID float(8),
SellerPrefix nvarchar (10),
SellerSuffix nvarchar(10),
FullName nvarchar(255)
)

INSERT INTO @TempAgentTable
SELECT     c.AGENT_SERIAL, a.Agent_ID, a.MAIN_PREFIX, a.MAIN_SUFFIX, a.FULLNAME
FROM         dbo.msit_AgentInfo_Reload a LEFT OUTER JOIN
                      dbo.msit_ContractDetails c ON a.AGENT_ID = c.AGENT_ID


UPDATE msit_NSLaboris_Reload
SET msit_NSLaboris_Reload.SellerID = a.AgentID,
  msit_NSLaboris_Reload.SellerPrefix = a.SellerPrefix,
  msit_NSLaboris_Reload.SellerSuffix = a.SellerSuffix,
  msit_NSLaboris_Reload.SellerName = a.FullName
FROM @TempAgentTable a
WHERE (msit_NSLaboris_Reload.SellerSerial = a.SellerSERIAL) AND (msit_NSLaboris_Reload.SellerName IS NULL)


UPDATE msit_NSLaboris_Reload
SET msit_NSLaboris_Reload.SellerName = CASE msit_NSLaboris_Reload.SellerSerial WHEN a.SellerSerial THEN 'Seller Not Identified' + '(' + a.SellerPrefix + msit_NSLaboris_Reload.SellerSerial + a.SellerSuffix + ')'
ELSE  'Seller Not Identified' + '(' + msit_NSLaboris_Reload.SellerSerial+ ')' END
FROM @TempAgentTable a
WHERE   (msit_NSLaboris_Reload.SellerSerial = a.SellerSerial)  and (msit_NSLaboris_Reload.SellerName IS NULL)

GO
