CREATE procedure [dbo].[mspr_UserDataCheck]
 @UserId  nvarchar(255),
 @Source  nvarchar(1),
 @Output bit OUTPUT
as
--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : mspr_NSOrder.sql
-- Owner   : MWA
-- Created : 25/07/2006
--
--       14/02/2007  - RH/OW - Tuned for performance as part of Agent KPI report production issue
--         - Fixes to affected procs/fns include explicit conversion of datatypes in query
--           expressions where parameter type is not matched to table data type
--           allowing Index seeks rather than scans
--         - Addition of indexes to required Quality tables
--         - Explicit alternative logic paths for queries where global parameter (eg Filter) is not supplied
--           avoiding table/index scans forced by unnecessary OR statememnts
--########################################################################

select distinct 
 a.FranchiseCode
into
 #Franchise
from  
 msdt_Adviser a inner join msct_UserAccessControl uac 
    on a.AdviserID = uac.AdviserID
where
 uac.DomainLogin = convert(varchar(255),@UserId)

Select @Output = 1

if (@Source = 'O' OR @Source = 'P')
begin

 if not exists (select NULL from #Franchise f where exists (select NULL from msit_OpenworkAdviserListing where f.FranchiseCode = BusinessCode))
 begin
   Select @Output = 0
 end

end
else
begin

 if not exists (select NULL from #Franchise f where exists (select NULL from msit_ZANAdviserListing where f.FranchiseCode = BusinessCode))
 begin
     Select @Output = 0
 end

end

