select distinct 
 a.FranchiseCode
into
 #Franchise
from  
 msdt_Adviser a inner join msct_UserAccessControl uac 
    on a.AdviserID = uac.AdviserID
where
 uac.DomainLogin = @UserId

-- Check to see if the user has data in the msit_ZANAdviserListing table
declare @Error int
set
 @Error = case when (select distinct 0 from #Franchise where FranchiseCode in (select distinct BusinessCode from msit_ZANAdviserListing)) = 0 then 0
               else 1
          end

if(@Error = 1)
begin
 RAISERROR ('ZAN Adviser Listing is not available for this user, no data exists.',16, 1)
end
else
begin


if (select count(FranchiseCode) from #Franchise) = 1
begin
 select distinct
  Value = zal.BusinessCode,
  Label = case when @Order = '1' then zal.BusinessCode + ' - ' + rtrim(zal.BusinessName)
               else rtrim(zal.BusinessName) + ' - ' + zal.BusinessCode 
          end
 from
  msit_ZANAdviserListing zal,
  #Franchise fr
 where
  zal.BusinessCode = fr.FranchiseCode
end
else
 begin
  select 
   Value = 'Select'
 end

end


